var DICT = {"ABODE":{"p":"/əˈbəʊd/","s":"v./n.","e":"[v.] To endure without yielding; to withstand; await defiantly; to encounter; to persevere.\n[v.] To bear patiently; to tolerate; to put up with; stand.\n[v.] To pay for; to stand the consequences of; to answer for; to suffer for; to atone for.\n[n.] Act of waiting; delay.\n[n.] Stay or continuance in a place; sojourn.\n[n.] A residence, dwelling or habitation.","ex":"The old oak tree abides the wind endlessly."},"ABHOR":{"p":"/əbˈhɔː(ɹ)/","s":"v.","e":"[v.] To regard with horror or detestation; to shrink back with shuddering from; to feel excessive repugnance toward; to detest to extremity; to loathe.\n[v.] To fill with horror or disgust.\n[v.] To turn aside or avoid; to keep away from; to reject.","ex":"I absolutely abhor being stuck in traffic jams"},"ACCOUNT":{"p":"/ə.ˈkaʊnt/","s":"n.","e":"[n.] A registry of pecuniary transactions; a written or printed statement of business dealings or debts and credits, and also of other things subjected to a reckoning or review.\n[n.] A sum of money deposited at a bank and subject to withdrawal.\n[n.] A statement in general of reasons, causes, grounds, etc., explanatory of some event; a reason of an action to be done.","ex":"to keep one's account at the bank."},"ABATE":{"p":"/əˈbeɪt/","s":"n./v.","e":"[n.] Abatement.\n[v.] (obsolete outside law) To put an end to; to cause to cease.\n[v.] To become null and void.\n[v.] To nullify; make void.","ex":"to abate a nuisance"},"ABBOT":{"p":"/ˈæb.ət/","s":"n.","e":"[n.] The superior or head of an abbey or monastery.\n[n.] The pastor and/or administrator of an order, including minor and major orders starting with the minor order of porter.\n[n.] A layman who received the abbey's revenues, after the closing of the monasteries.","ex":"The newly appointed abbot decided to take a tour of the abbey with the cardinal's emissary."},"ACORN":{"p":"/ˈeɪ.kɔːn/","s":"n.","e":"[n.] The fruit of the oak, being an oval nut growing in a woody cup or cupule.\n[n.] A cone-shaped piece of wood on the point of the spindle above the vane, on the mast-head.\n[n.] See acorn-shell.","ex":""},"ABLE":{"p":"/ˈeɪ.bl̩/","s":"adj.","e":"[adj.] Easy to use.\n[adj.] Suitable; competent.\n[adj.] Liable to.","ex":""},"ABYSS":{"p":"/əˈbɪs/","s":"n.","e":"[n.] Hell; the bottomless pit; primeval chaos; a confined subterranean ocean.\n[n.] (frequently figurative) A bottomless or unfathomed depth, gulf, or chasm; hence, any deep, immeasurable; any void space.\n[n.] Anything infinite, immeasurable, or profound.","ex":""},"ACRID":{"p":"/ˈæk.ɹɪd/","s":"adj.","e":"[adj.] Sharp and harsh, or bitter and not to the taste.\n[adj.] Causing heat and irritation.\n[adj.] Caustic; bitter; bitterly irritating.","ex":"Sodium polyacrylate is an acrid salt."},"ABORT":{"p":"/əˈbɔːt/","s":"n.","e":"[n.] A miscarriage; an untimely birth; an abortion.\n[n.] The product of a miscarriage; an aborted offspring; an abortion.\n[n.] An early termination of a mission, action, or procedure in relation to missiles or spacecraft; the craft making such a mission.","ex":"We've had aborts on three of our last seven launches."},"ABOUT":{"p":"/əˈbɛʊt/","s":"adj./adv./prep.","e":"[adj.] Moving around; astir.\n[adj.] In existence; being in evidence; apparent.\n[adj.] Near; in the vicinity or neighbourhood.\n[adv.] On all sides; around.\n[adv.] Here and there; around; in one place and another; up and down.\n[adv.] From one place or position to another in succession; indicating repeated movement or activity.","ex":"After my bout with Guillan-Barre Syndrome, it took me 6 months to be up and about again."},"ABACK":{"p":"/əˈbæk/","s":"adv.","e":"[adv.] Towards the back or rear; backwards.\n[adv.] In the rear; a distance behind.\n[adv.] By surprise; startled; dumbfounded. (see usage)","ex":""},"ABBEY":{"p":"/ˈæb.i/","s":"n.","e":"[n.] The office or dominion of an abbot or abbess.\n[n.] A monastery or society of people, secluded from the world and devoted to religion and celibacy, which is headed by an abbot or abbess; also, the monastic building or buildings.\n[n.] The church of a monastery.","ex":""},"ACCEPT":{"p":"/ækˈsɛpt/","s":"v./adj.","e":"[v.] To receive, especially with a consent, with favour, or with approval.\n[v.] To admit to a place or a group.\n[v.] To regard as proper, usual, true, or to believe in.\n[adj.] Accepted.","ex":"The Boy Scouts were going to accept him as a member."},"ABIDE":{"p":"/əˈbaɪd/","s":"v.","e":"[v.] To endure without yielding; to withstand; await defiantly; to encounter; to persevere.\n[v.] To bear patiently; to tolerate; to put up with; stand.\n[v.] To pay for; to stand the consequences of; to answer for; to suffer for; to atone for.","ex":"The old oak tree abides the wind endlessly."},"ABASE":{"p":"/əˈbeɪs/","s":"v.","e":"[v.] To lower, as in condition in life, office, rank, etc., so as to cause pain or hurt feelings; to degrade, to depress, to humble, to humiliate.\n[v.] To lower physically; to depress; to cast or throw down; to stoop.\n[v.] To lower in value, in particular by altering the content of alloys in coins; to debase.","ex":"to abase the eye"},"ACCUSED":{"p":"/ə.ˈkjuzd/","s":"v./n./adj.","e":"[v.] To find fault with, blame, censure\n[v.] (followed by \"of\") to charge with having committed a crime or offence\n[v.] To make an accusation against someone\n[n.] The person charged with an offense; the defendant in a criminal case.\n[adj.] Having been accused; being the target of accusations.","ex":"For the U.S. President to be impeached, he must be accused of a high crime or misdemeanor."},"ACROSS":{"p":"/əˈkɹɑs/","s":"n./adv./prep.","e":"[n.] (crosswords, often in combination) A word that runs horizontally in the completed puzzle grid or its associated clue.\n[adv.] From one side to the other.\n[adv.] On the other side.\n[adv.] In a particular direction.\n[prep.] To, toward or from the far side of (something that lies between two points of interest).\n[prep.] On the opposite side of (something that lies between two points of interest).","ex":"I solved all of the acrosses, but then got stuck on 3 down."},"ABILITY":{"p":"/əˈ.bɪl.ɪ.ti/","s":"n.","e":"[n.] Suitableness.\n[n.] The quality or state of being able; capacity to do or of doing something; having the necessary power.\n[n.] The legal wherewithal to act.","ex":"This phone has the ability to have its software upgraded wirelessly."},"ACQUIRE":{"p":"/əˈkwaɪə/","s":"v.","e":"[v.] To get.\n[v.] To gain, usually by one's own exertions; to get as one's own\n[v.] To contract.","ex":"He acquired a title."},"ACHIEVE":{"p":"/əˈtʃiːv/","s":"v.","e":"[v.] To succeed in something, now especially in academic performance.\n[v.] To carry out successfully; to accomplish.\n[v.] To conclude, finish, especially successfully.","ex":""},"ABUSE":{"p":"/əˈbjuːs/","s":"n.","e":"[n.] Improper treatment or usage; application to a wrong or bad purpose; an unjust, corrupt or wrongful practice or custom.\n[n.] Misuse; improper use; perversion.\n[n.] A delusion; an imposture; misrepresentation; deception.","ex":"All abuse, whether physical, verbal, psychological or sexual, is bad."},"ABLED":{"p":"/ˈeɪ.bl̩d/","s":"adj.","e":"[adj.] (in combination) Having a range of physical powers as specified.","ex":""},"ACADEMY":{"p":"/əˈkæd.ə.mi/","s":"n.","e":"[n.] (usually capitalized) The garden where Plato taught.\n[n.] (usually capitalized) Plato's philosophical system based on skepticism; Plato's followers.\n[n.] An institution for the study of higher learning; a college or a university; typically a private school.","ex":""},"ACTION":{"p":"/ˈæk.ʃən/","s":"n./v./int.","e":"[n.] Something done so as to accomplish a purpose.\n[n.] A way of motion or functioning.\n[n.] Fast-paced activity.\n[v.] To act on a request etc, in order to put it into effect.\n[v.] To initiate a legal action against someone.\n[int.] Demanding or signifying the start of something, usually an act or scene of a theatric performance.","ex":"Knead bread with a rocking action."},"ACTUAL":{"p":"/ˈak(t)ʃj(ʊ)əl/","s":"n./adj.","e":"[n.] An actual, real one; notably:\n[adj.] Relating to a person's acts or deeds; active, practical\n[adj.] Existing in reality, not just potentially; really acted or acting; occurring in fact.\n[adj.] In action at the time being; now existing; current.","ex":"The actual government expenses dramatically exceed the budget."},"ADMIT":{"p":"/ədˈmɪt/","s":"v.","e":"[v.] To allow to enter; to grant entrance (to), whether into a place, into the mind, or into consideration\n[v.] To allow (someone) to enter a profession or to enjoy a privilege; to recognize as qualified for a franchise.\n[v.] To concede as true; to acknowledge or assent to, as an allegation which it is impossible to deny","ex":"A ticket admits one into a playhouse."},"ACTIVE":{"p":"/ˈæk.tɪv/","s":"n./adj.","e":"[n.] A person or thing that is acting or capable of acting.\n[n.] Any component that is not passive. See Passivity (engineering).\n[adj.] Having the power or quality of acting; causing change; communicating action or motion; acting;—opposed to passive, that receives.\n[adj.] Quick in physical movement; of an agile and vigorous body; nimble.\n[adj.] In action; actually proceeding; working; in force","ex":"certain active principles"},"ACTOR":{"p":"/ˈæk.tə/","s":"n.","e":"[n.] A person who performs, plays a part in a theatrical play or film.\n[n.] One who acts; a doer.\n[n.] One who takes part in a situation.","ex":""},"ADOPT":{"p":"/əˈdɒpt/","s":"v.","e":"[v.] To take by choice into relationship (a child, heir, friend, citizen, etc.)\n[v.] To take or receive as one's own what is not so naturally.\n[v.] To select and take or approve.","ex":"He adopted a new look in order to fit in with his new workmates."},"ADULT":{"p":"/əˈdʌlt/","s":"n./v./adj.","e":"[n.] A fully grown human or animal.\n[n.] A person who has reached the legal age of majority.\n[v.] To (cause to) be or become an adult.\n[v.] To behave like an adult.\n[adj.] Fully grown.\n[adj.] Intended for or restricted to adults rather than children.","ex":"an adult human, animal, or plant"},"ADVISER":{"p":"/ædˈvaɪz.ɚ/","s":"n.","e":"[n.] One who advises","ex":""},"ADEPT":{"p":"/əˈdɛpt/","s":"n./adj.","e":"[n.] One fully skilled or well versed in anything; a proficient\n[adj.] Well skilled; completely versed; thoroughly proficient","ex":"adepts in philosophy"},"ADAGE":{"p":"/ˈæ.dɪdʒ/","s":"n.","e":"[n.] An old saying which has obtained credit by long use\n[n.] An old saying which has been overused or considered a cliché; a trite maxim","ex":""},"ACUTE":{"p":"/əˈkjuːt/","s":"n./v./adj.","e":"[n.] A person who has the acute form of a disorder, such as schizophrenia.\n[n.] An accent or tone higher than others.\n[n.] An acute accent (´).\n[v.] To give an acute sound to.\n[v.] To make acute; to sharpen, to whet.\n[adj.] Brief, quick, short.","ex":"The word ‘cafe’ often has an acute over the ‘e’."},"ADAPT":{"p":"/əˈdæpt/","s":"v./adj.","e":"[v.] To make suitable; to make to correspond; to fit or suit\n[v.] To fit by alteration; to modify or remodel for a different purpose; to adjust\n[v.] To make by altering or fitting something else; to produce by change of form or character\n[adj.] Adapted; fit; suited; suitable.","ex":"to adapt a story for the stage"},"ADDRESS":{"p":"/æˈdɹɛs/","s":"n./v.","e":"[n.] Direction.\n[n.] Preparation.\n[v.] To prepare oneself.\n[v.] To direct speech.\n[v.] To aim; to direct.","ex":""},"ADIEU":{"p":"/əˈdjuː/","s":"n./int.","e":"[n.] A farewell, a goodbye; especially a fond farewell, or a lasting or permanent farewell.\n[int.] Said to wish a final farewell; goodbye.","ex":"We bid our final adieus to our family, then boarded the ship, bound for America."},"ADMIN":{"p":"/ədˈmɪn/","s":"n./v.","e":"[n.] Administration, or administrative work.\n[n.] A systems administrator; one who maintains a computer system or network.\n[n.] A user of a discussion forum, web site, etc. with privileges allowing them to control or restrict the activity of other uses.\n[v.] To serve as an administrator for or of.","ex":"There's a lot of admin involved in the birth of a child."},"ADOBE":{"p":"/əˈdəʊ.bi/","s":"n.","e":"[n.] An unburnt brick dried in the sun.\n[n.] The earth from which such bricks are made.\n[n.] A house made of adobe brick.","ex":"Many people in Texas and New Mexico live in adobe houses."},"ADORE":{"p":"/əˈdɔː/","s":"v.","e":"[v.] To worship.\n[v.] To love with one's entire heart and soul; regard with deep respect and affection.\n[v.] To be very fond of.","ex":"It is obvious to everyone that Gerry adores Heather."},"ADORN":{"p":"/əˈdɔː(ɹ)n/","s":"n./v./adj.","e":"[n.] Adornment\n[v.] To make more beautiful and attractive; to decorate.\n[adj.] Adorned; ornate","ex":"a character adorned with every Christian grace"},"AFOOT":{"p":"/əˈfʊt/","s":"adj./adv.","e":"[adj.] (predicative) That is on foot, in motion, in action, in progress.\n[adv.] On foot. (means of locomotion, walking)\n[adv.] On foot. (support of the body, standing)\n[adv.] In motion; in action; astir; stirring; in progress.","ex":""},"AFFIX":{"p":"","s":"n./v.","e":"[n.] That which is affixed; an appendage.\n[n.] A bound morpheme added to the word’s stem's end.\n[n.] (broadly) A bound morpheme added to a word’s stem; a prefix, suffix etc.\n[v.] To attach.\n[v.] To subjoin, annex, or add at the close or end; to append to.\n[v.] To fix or fasten figuratively; with on or upon.","ex":"to affix a stigma to a person"},"AFIRE":{"p":"/əˈfaɪə(ɹ)/","s":"adj./adv.","e":"[adj.] On fire (often metaphorically).\n[adv.] On fire (often metaphorically).","ex":""},"ADAPTER":{"p":"/əˈdaptə/","s":"n.","e":"[n.] One who is capable of adapting to differing situations.\n[n.] One who adapts a thing, e.g. a play.\n[n.] A device or application used to achieve operative compatibility between devices that otherwise are incompatible.","ex":"He was an able adapter, and could easily adjust to the differences when the company changed ownership."},"AFOUL":{"p":"/əˈfaʊl/","s":"adv.","e":"[adv.] (principally nautical) In a state of collision or entanglement.\n[adv.] (with of) In a state of entanglement or conflict (with).","ex":"The ships’ lines and sails were all afoul."},"AFTER":{"p":"/ˈæf.tə(ɹ)/","s":"adj./adv./prep./conj.","e":"[adj.] Later; second (of two); next, following, subsequent\n[adj.] (where the frame of reference is within the ship) At or towards the stern of a ship.\n[adv.] Behind; later in time; following.\n[prep.] Subsequently to; following in time; later than.\n[prep.] Behind.\n[prep.] In pursuit of, seeking.","ex":"The after gun is abaft the forward gun."},"AGAIN":{"p":"/əˈɡeɪn/","s":"adv./prep.","e":"[adv.] Another time; once more.\n[adv.] Over and above a factor of one.\n[adv.] Used metalinguistically, with the repetition being in the discussion, or in the linguistic or pragmatic context of the discussion, rather than in the subject of discussion.\n[prep.] (obsolete or dialectal) Against.","ex":"Great, thanks again!"},"AGAINST":{"p":"/əˈɡeɪnst/","s":"prep./conj.","e":"[prep.] In a contrary direction to.\n[prep.] In physical opposition to; in collision with.\n[prep.] In physical contact with, so as to abut or be supported by.\n[conj.] By the time that (something happened); before.","ex":"It is hard work to swim against the current."},"AGILE":{"p":"/ˈæd͡ʒ.aɪl/","s":"adj.","e":"[adj.] Having the faculty of quick motion in the limbs; apt or ready to move\n[adj.] Characterised by quick motion\n[adj.] Of or relating to agile software development, a technique for iterative and incremental development of software involving collaboration between teams.","ex":"an agile creature"},"AGAPE":{"p":"/əˈɡeɪp/","s":"adj./adv.","e":"[adj.] In a state of astonishment, wonder, expectation, or eager attention; as with mouth hanging open.\n[adj.] Wide open.\n[adv.] In a state of astonishment, wonder, expectation, or eager attention.\n[adv.] Open wide.","ex":""},"ALGAE":{"p":"/æl.ɡɪ/","s":"n.","e":"[n.] Any of many aquatic photosynthetic organisms, including the seaweeds, whose size ranges from a single cell to giant kelps and whose biochemistry and forms are very diverse, some being eukaryotic.\n[n.] Algal organisms viewed collectively or as a mass; algal growth.\n[n.] A particular kind of algae.","ex":""},"AGONY":{"p":"/ˈæ.ɡə.niː/","s":"n.","e":"[n.] Extreme pain.\n[n.] The sufferings of Jesus Christ in the garden of Gethsemane.\n[n.] Violent contest or striving.","ex":""},"AGENT":{"p":"/ˈeɪ.dʒənt/","s":"n.","e":"[n.] One who exerts power, or has the power to act\n[n.] One who acts for, or in the place of, another (the principal), by authority from him/her; someone entrusted to do the business of another\n[n.] A person who looks for work for another person","ex":""},"AGATE":{"p":"/ˈæ.ɡət/","s":"n.","e":"[n.] A semi-pellucid, uncrystallized variety of quartz, presenting various tints in the same specimen, with colors delicately arranged in stripes or bands, or blended in clouds.\n[n.] The size of type between pearl and nonpareil, standardized as 5 1/2-point.\n[n.] One fourteenth of an inch","ex":""},"ALARM":{"p":"/əˈlɑːm/","s":"n./v.","e":"[n.] A summons to arms, as on the approach of an enemy.\n[n.] Any sound or information intended to give notice of approaching danger; a warning sound to arouse attention; a warning of danger.\n[n.] A sudden attack; disturbance.\n[v.] To call to arms for defense\n[v.] To give (someone) notice of approaching danger\n[v.] To rouse to vigilance and action; to put on the alert.","ex":""},"AGING":{"p":"/ˈeɪ.dʒɪŋ/","s":"v./n./adj.","e":"[v.] To cause to grow old; to impart the characteristics of age to.\n[v.] To postpone an action that would extinguish something, as a debt.\n[v.] To categorize by age.\n[n.] The process of becoming older or more mature.\n[n.] The deliberate process of making something (such as an antique) appear (or, in science fiction, become) older than it is.\n[n.] Becoming senescent; accumulating damage to macromolecules, cells, tissues and organs with the passage of time; progressing loss of health, mobility, vibrancy and body functionality, resulting in biological death.","ex":"Grief ages us."},"AHEAD":{"p":"/əˈhɛd/","s":"adv.","e":"[adv.] In or to the front; in advance; onward.\n[adv.] In the direction one is facing or moving.\n[adv.] In or for the future.","ex":"Just ahead you can see the cliffs."},"AGLOW":{"p":"/əˈɡloʊ/","s":"adj.","e":"[adj.] (sometimes figurative) glowing; radiant","ex":""},"AGREE":{"p":"/əˈɡɹi/","s":"v.","e":"[v.] To harmonize in opinion, statement, or action; to be in unison or concord; to be or become united or consistent; to concur.\n[v.] To yield assent; to accede;—followed by to.\n[v.] To yield assent to; to approve.","ex":"all parties agree in the expediency of the law."},"AISLE":{"p":"/aɪ̯l/","s":"n.","e":"[n.] A wing of a building, notably in a church separated from the nave proper by piers.\n[n.] A clear path through rows of seating.\n[n.] A clear corridor in a supermarket with shelves on both sides containing goods for sale.","ex":""},"ALIEN":{"p":"/ˈeɪ.li.ən/","s":"n./v./adj.","e":"[n.] Any life form of extraterrestrial or extradimensional origin.\n[n.] A person, animal, plant, or other thing which is from outside the family, group, organization, or territory under consideration.\n[n.] A foreigner residing in a country.\n[v.] To estrange; to alienate.\n[v.] To transfer the ownership of something.\n[adj.] Not belonging to the same country, land, or government, or to the citizens or subjects thereof; foreign.","ex":"alien subjects, enemies, property, or shores"},"AGOGO":{"p":"","s":"n.","e":"[n.] An agogo bell, a bell used in Yoruba and Brazilian music and typically played in pairs","ex":""},"AIDED":{"p":"/ˈeɪ.dɪd/","s":"v.","e":"[v.] To provide support to; to further the progress of; to help; to assist.\n[v.] To climb with the use of aids such as pitons.","ex":""},"ALIGN":{"p":"/æˈlaɪn/","s":"v.","e":"[v.] To form a line; to fall into line.\n[v.] To adjust or form to a line; to range or form in line; to bring into line.\n[v.] To store (data) in a way that is consistent with the memory architecture, i.e. by beginning each item at an offset equal to some multiple of the word size.","ex":""},"ALIKE":{"p":"/əˈlaɪk/","s":"adj./adv.","e":"[adj.] Having resemblance or similitude; similar; without difference.\n[adv.] In the same manner, form, or degree; in common; equally.","ex":"The twins were alike."},"ALBUM":{"p":"/ˈælbəm/","s":"n.","e":"[n.] A book specially designed to keep photographs, stamps, or autographs.\n[n.] A collection, especially of literary items\n[n.] A phonograph record that is composed of several tracks","ex":""},"ALERT":{"p":"/əˈlɜːt/","s":"n./adj.","e":"[n.] An alarm.\n[n.] A notification of higher importance than an advisory.\n[n.] A state of readiness for potential combat.\n[adj.] Attentive; awake; on guard.\n[adj.] Brisk; nimble; moving with celerity.","ex":"an airborne alert; ground alert"},"ALIBI":{"p":"/ˈæl.ə.baɪ/","s":"n./v.","e":"[n.] The plea or mode of defense under which a person on trial for a crime proves or attempts to prove being in another place when the alleged act was committed\n[v.] To provide an alibi for.\n[v.] To provide an excuse for.","ex":"to prove an alibi"},"ALIVE":{"p":"/əˈlaɪv/","s":"adj.","e":"[adj.] Having life; living; not dead\n[adj.] In a state of action; in force or operation; existent\n[adj.] Busy with activity of many living beings; swarming; thronged; busy.\n[adj.] (only used attributively) Having life; that is alive.\n[adj.] Being in existence; actual\n[adj.] Having active properties; being energized.","ex":"As long as the plant is alive, he will continue to water it."},"ALLAY":{"p":"/əˈleɪ/","s":"n./v.","e":"[n.] Alleviation; abatement; check.\n[n.] An alloy.\n[v.] To make quiet or put at rest; to pacify or appease; to quell; to calm.\n[v.] To alleviate; to abate; to mitigate.\n[v.] To subside, abate, become peaceful.","ex":"to allay popular excitement"},"ALLEY":{"p":"/ˈæ.li/","s":"n.","e":"[n.] A narrow street or passageway, especially one through the middle of a block giving access to the rear of lots or buildings.\n[n.] The area between the outfielders.\n[n.] An establishment where bowling is played.","ex":"The parking lot to my friend's apartment building is in the alley."},"ALLOT":{"p":"/əˈlɒt/","s":"v.","e":"[v.] To distribute or apportion by (or as if by) lot.\n[v.] To assign or designate as a task or for a purpose.","ex":""},"ALLOW":{"p":"/əˈlaʊ/","s":"v.","e":"[v.] To grant, give, admit, accord, afford, or yield; to let one have.\n[v.] To acknowledge; to accept as true; to concede; to accede to an opinion.\n[v.] To grant (something) as a deduction or an addition; especially to abate or deduct.","ex":"to allow a servant his liberty;  to allow a free passage;  to allow one day for rest"},"ALLOY":{"p":"","s":"n.","e":"[n.] A metal that is a combination of two or more elements, at least one of which is a metal.\n[n.] A metal of lesser value, mixed with a metal of greater value.\n[n.] An admixture; something added which stains, taints etc.","ex":"gold without alloy"},"ALOHA":{"p":"/əˈləʊ.(h)ə/","s":"n./int.","e":"[n.] Good wishes, love.\n[n.] An utterance of aloha (see Interjection, below).\n[int.] Expressing good wishes when greeting or parting from someone; hello; goodbye.","ex":""},"ALONG":{"p":"/əˈlɑŋ/","s":"adv./prep.","e":"[adv.] In company; together.\n[adv.] Onward, forward, with progressive action.\n[prep.] By the length of; in a line with the length of; lengthwise next to.\n[prep.] In a line with, with a progressive motion on; onward on; forward on.","ex":"John played the piano and everyone sang along."},"ALMOST":{"p":"/ɔːl.ˈməʊst/","s":"n./adv.","e":"[n.] Something or someone that doesn't quite make it.\n[adv.] Very close to, not quite.","ex":"In all the submissions, they found four papers that were clearly worth publishing and another dozen almosts."},"ALPHA":{"p":"/ˈælfə/","s":"n./adj.","e":"[n.] The name of the first letter of the Greek alphabet (Α,  α), followed by beta. In the Latin alphabet it is the predecessor to A.\n[n.] Latin alpha\n[n.] The name of the symbols Α and α used in science and mathematics, often interchangeable with the symbols when used as a prefix.\n[adj.] Designates the first in an order of precedence.\n[adj.] (of person, object or action) exhibiting characteristics of the alpha male/female archetype.\n[adj.] Designates some bright star, usually the brightest star, of a constellation.","ex":"I will attempt to make an alpha particle (\"α-particle\") with the Large Hadron Collider."},"AMASS":{"p":"/əˈmæs/","s":"n./v.","e":"[n.] A large number of things collected or piled together.\n[n.] The act of amassing.\n[v.] To collect into a mass or heap.\n[v.] To gather a great quantity of; to accumulate.","ex":"to amass a treasure or a fortune"},"ALOFT":{"p":"/əˈlɑft/","s":"adv.","e":"[adv.] At, to, or in the air or sky.\n[adv.] Above, overhead, in a high place; up.\n[adv.] In the top, at the masthead, or on the higher yards or rigging.","ex":"high winds aloft"},"ALONE":{"p":"/əˈləʊn/","s":"adj./adv.","e":"[adj.] By oneself, solitary.\n[adj.] Apart from, or exclusive of, others.\n[adj.] Considered separately.\n[adv.] By oneself; apart from, or exclusive of, others; solo.\n[adv.] Without outside help.\n[adv.] Exclusively.","ex":"I can't ask for help because I am alone."},"AMAZE":{"p":"/əˈmeɪz/","s":"n./v.","e":"[n.] Amazement, astonishment.\n[v.] To fill with wonder and surprise; to astonish, astound, surprise or perplex.\n[v.] To undergo amazement; to be astounded.\n[v.] To stupefy; to knock unconscious.","ex":"He was amazed when he found that the girl was a robot."},"ALOOF":{"p":"/əˈluːf/","s":"adj./adv./prep.","e":"[adj.] Reserved and remote; either physically or emotionally distant; standoffish.\n[adv.] At or from a distance, but within view, or at a small distance; apart; away.\n[adv.] Without sympathy; unfavorably.\n[prep.] Away from; clear of.","ex":""},"ALOUD":{"p":"/əˈlaʊd/","s":"adj./adv.","e":"[adj.] Spoken out loud.\n[adv.] With a loud voice, or great noise; loudly; audibly.\n[adv.] Audibly, as opposed to silently/quietly.","ex":"Try speaking aloud rather than whispering."},"ALTAR":{"p":"/ˈɑl.tɚ/","s":"n.","e":"[n.] A table or similar flat-topped structure used for religious rites.\n[n.] A raised area around an altar in a church; the sanctuary.\n[n.] Anything that is worshipped or sacrificed to.","ex":""},"ALREADY":{"p":"/ɑlˈɹɛdi/","s":"adv.","e":"[adv.] Prior to some specified time, either past, present, or future; by this time; previously.\n[adv.] So soon.","ex":"Are you quitting already?"},"ALTER":{"p":"/ˈɑl.tɚ/","s":"v.","e":"[v.] To change the form or structure of.\n[v.] To become different.\n[v.] To tailor clothes to make them fit.","ex":""},"ALSO":{"p":"/ˈɔːl.səʊ/","s":"adv.","e":"[adv.] (focus) In addition; besides; as well; further; too.\n[adv.] To the same degree or extent; so, as.","ex":"They had porridge for breakfast, and also toast."},"AMISS":{"p":"/əˈmɪs/","s":"n./adj./adv.","e":"[n.] Fault; wrong; an evil act, a bad deed.\n[adj.] Wrong; faulty; out of order; improper or otherwise incorrect.\n[adv.] Wrongly.\n[adv.] Mistakenly.\n[adv.] Astray.","ex":"He suspected something was amiss."},"AMAZING":{"p":"/əˈmeɪzɪŋ/","s":"v./adj.","e":"[v.] To fill with wonder and surprise; to astonish, astound, surprise or perplex.\n[v.] To undergo amazement; to be astounded.\n[v.] To stupefy; to knock unconscious.\n[adj.] Causing wonder and amazement; very surprising.\n[adj.] Possessing uniquely wonderful qualities.\n[adj.] Very good.","ex":"He was amazed when he found that the girl was a robot."},"AMBER":{"p":"/ˈam.bə/","s":"n./v./adj.","e":"[n.] Ambergris, the waxy product of the sperm whale.\n[n.] A hard, generally yellow to brown translucent fossil resin, used for jewellery. One variety, blue amber, appears blue rather than yellow under direct sunlight.\n[n.] A yellow-orange colour.\n[v.] To perfume or flavour with ambergris.\n[v.] To preserve in amber.\n[v.] To cause to take on the yellow colour of amber.","ex":"ambered wine, an ambered room"},"AMBLE":{"p":"/ˈæm.bəl/","s":"n./v.","e":"[n.] An unhurried leisurely walk or stroll.\n[n.] An easy gait, especially that of a horse.\n[v.] To stroll or walk slowly and leisurely.\n[v.] Of a quadruped: to move along by using both legs on one side, and then the other.","ex":""},"AMEND":{"p":"/əˈmɛnd/","s":"n./v.","e":"[n.] (usually in the plural) An act of righting a wrong; compensation.\n[v.] To make better; improve.\n[v.] To become better.\n[v.] To heal (someone sick); to cure (a disease etc.).","ex":""},"AMOUNT":{"p":"/əˈmaʊnt/","s":"n./v.","e":"[n.] The total, aggregate or sum of material (not applicable to discrete numbers or units or items in standard English).\n[n.] A quantity or volume.\n[n.] (sometimes proscribed) The number (the sum) of elements in a set.\n[v.] (followed by to) To total or evaluate.\n[v.] (followed by to) To be the same as or equivalent to.\n[v.] To go up; to ascend.","ex":"The amount of atmospheric pollution threatens a health crisis."},"AMONG":{"p":"/əˈmɒŋ/","s":"prep.","e":"[prep.] Denotes a mingling or intermixing with distinct or separable objects. (See Usage Note at amidst.)\n[prep.] Denotes a belonging of a person or a thing to a group.\n[prep.] Denotes a sharing of a common feature in a group.","ex":"How can you speak with authority about their customs when you have never lived among them?"},"ANGER":{"p":"/ˈæŋɡə(ɹ)/","s":"n./v.","e":"[n.] A strong feeling of displeasure, hostility or antagonism towards someone or something, usually combined with an urge to harm.\n[n.] Pain or stinging.\n[v.] To cause such a feeling of antagonism in.\n[v.] To become angry.","ex":"You need to control your anger."},"AMPLE":{"p":"/ˈæm.pəl/","s":"adj.","e":"[adj.] Large; great in size, extent, capacity, or bulk; for example spacious, roomy or widely extended.\n[adj.] Fully sufficient; abundant; plenty\n[adj.] Not contracted or brief; not concise; extended; diffusive","ex":"an ample house"},"ANCIENT":{"p":"/ˈeɪn.ʃənt/","s":"n./adj.","e":"[n.] A person who is very old.\n[n.] A person who lived in ancient times.\n[n.] One of the senior members of the Inns of Court or of Chancery.\n[adj.] Having lasted from a remote period; having been of long duration; of great age, very old.\n[adj.] Existent or occurring in time long past, usually in remote ages; belonging to or associated with antiquity; old, as opposed to modern.\n[adj.] (history) Relating to antiquity as a primarily European historical period; the time before the Middle Ages.","ex":"an ancient city  an ancient forest"},"AMPLY":{"p":"/ˈæmp.li/","s":"adv.","e":"[adv.] In an ample manner.","ex":""},"ANGLE":{"p":"/ˈæŋ.ɡəl/","s":"n./v.","e":"[n.] A figure formed by two rays which start from a common point (a plane angle) or by three planes that intersect (a solid angle).\n[n.] The measure of such a figure. In the case of a plane angle, this is the ratio (or proportional to the ratio) of the arc length to the radius of a section of a circle cut by the two rays, centered at their common point. In the case of a solid angle, this is the ratio of the surface area to the square of the radius of the section of a sphere.\n[n.] A corner where two walls intersect.\n[v.] (often in the passive) To place (something) at an angle.\n[v.] To change direction rapidly.\n[v.] To present or argue something in a particular way or from a particular viewpoint.","ex":"the angle between lines A and B"},"AMITY":{"p":"/ˈæ.mɪ.ti/","s":"n.","e":"[n.] Friendship. The cooperative and supportive relationship between people, or animals. In this sense, the term connotes a relationship which involves mutual knowledge, esteem, affection, and respect along with a degree of rendering service to friends in times of need or crisis.\n[n.] Mutual understanding and a peaceful relationship, especially between nations; peace; accord.","ex":""},"AMUSE":{"p":"/əˈmjuːz/","s":"v.","e":"[v.] To entertain or occupy in a pleasant manner; to stir with pleasing emotions.\n[v.] To cause laughter or amusement; to be funny.\n[v.] To keep in expectation; to beguile; to delude.","ex":"I watch these movies because they amuse me."},"ANKLE":{"p":"/ˈæŋ.kəl/","s":"n./v.","e":"[n.] The skeletal joint which connects the foot with the leg; the uppermost portion of the foot and lowermost portion of the leg, which contain this skeletal joint.\n[v.] To walk.\n[v.] To cyclically angle the foot at the ankle while pedaling, to maximize the amount of work applied to the pedal during each revolution.","ex":""},"ANNUAL":{"p":"/ˈæn.ju.əl/","s":"n./adj.","e":"[n.] An annual publication; a book, periodical, journal, report, comic book, yearbook, etc., which is published serially once a year, which may or may not be in addition to regular weekly or monthly publication.\n[n.] An annual plant; a plant with a life span of just one growing season; a plant which naturally germinates, flowers and dies in one year. Compare biennial, perennial.\n[n.] A medical checkup taking place once a year.\n[adj.] Happening once every year.\n[adj.] Of, for, or relating to a whole year, often as a recurring cycle; determined or reckoned by the year; accumulating in the course of a year; performed, executed, or completed over the course of a year. See also circannual.\n[adj.] (of a plant) Having a life cycle that is completed in only one growing season; e.g. beans, corn, marigold. See Annual plant in Wikipedia. Compare biennial, perennial.","ex":"I read the magazine, but I usually don't purchase the annuals."},"ANGRY":{"p":"/ˈæŋ.ɡɹi/","s":"adj.","e":"[adj.] Displaying or feeling anger.\n[adj.] (said about a wound or a rash) Inflamed and painful.\n[adj.] (said about the elements, like the sky or the sea) Dark and stormy, menacing.","ex":"An angry mob started looting the warehouse."},"ANGST":{"p":"/æŋ(k)st/","s":"n./v.","e":"[n.] Emotional turmoil; painful sadness.\n[n.] A feeling of acute but vague anxiety or apprehension often accompanied by depression, especially philosophical anxiety.\n[v.] To suffer angst; to fret.","ex":""},"ANIME":{"p":"/ˈæn.ɪ.meɪ/","s":"n.","e":"[n.] An artistic style originating in, and associated with, Japanese animation, and that has also been adopted by a comparatively low number of animated works from other countries.\n[n.] An animated work that originated in Japan, regardless of the artistic style.\n[n.] An animated work, regardless of the country of origin.","ex":"I can draw an anime version of you, if you want."},"ANNUL":{"p":"/əˈnʌl/","s":"v.","e":"[v.] To formally revoke the validity of.\n[v.] To dissolve (a marital union) on the grounds that it is not valid.","ex":""},"ANXIETY":{"p":"/ˌæŋ(ɡ)ˈzaɪ.ə.ti/","s":"n.","e":"[n.] An unpleasant state of mental uneasiness, nervousness, apprehension and obsession or concern about some uncertain event.\n[n.] An uneasy or distressing desire (for something).\n[n.] A state of restlessness and agitation, often accompanied by a distressing sense of oppression or tightness in the stomach.","ex":""},"APING":{"p":"/ˈeɪ.pɪŋ/","s":"v./n.","e":"[v.] To behave like an ape.\n[v.] To imitate or mimic, particularly to imitate poorly.\n[n.] Foolish imitation or mimicry.","ex":""},"APNEA":{"p":"","s":"n.","e":"[n.] The cessation of breathing.","ex":""},"APPLY":{"p":"/əˈplaɪ/","s":"v.","e":"[v.] To lay or place; to put (one thing to another)\n[v.] To put to use; to use or employ for a particular purpose, or in a particular case\n[v.] To make use of, declare, or pronounce, as suitable, fitting, or relative","ex":"to apply cream to a rash"},"APRON":{"p":"/ˈeɪ.pɹən/","s":"n./v.","e":"[n.] An article of clothing worn over the front of the torso and/or legs for protection from spills; also historically worn by Freemasons and as part of women's fashion.\n[n.] The short cassock ordinarily worn by English bishops.\n[n.] A hard surface bordering a structure or area.\n[v.] To cover with, or as if with, an apron.","ex":""},"ARSON":{"p":"/ˈɑːsən/","s":"n./v.","e":"[n.] The crime of deliberately starting a fire with intent to cause damage.\n[v.] To illegally set fire to; to burn down in a criminal manner","ex":""},"AROSE":{"p":"/əˈɹoʊz/","s":"v.","e":"[v.] To come up from a lower to a higher position.\n[v.] To come up from one's bed or place of repose; to get up.\n[v.] To spring up; to come into action, being, or notice; to become operative, sensible, or visible; to begin to act a part; to present itself.","ex":"to arise from a kneeling posture"},"AREA":{"p":"/ˈɛə̯ɹɪə̯/","s":"n.","e":"[n.] A measure of the extent of a surface; it is measured in square units.\n[n.] A particular geographic region.\n[n.] Any particular extent of surface, especially an empty or unused extent.","ex":"The photo is a little dark in that area."},"AROUND":{"p":"/əˈɹaʊnd/","s":"adj./adv./prep.","e":"[adj.] (with the verb \"to be\") Present in the vicinity.\n[adj.] (with the verb \"to be\") Alive; existing.\n[adv.] So as to form a circle or trace a circular path, or approximation thereof.\n[adv.] So as to surround or be near.\n[adv.] Nearly; approximately; about.\n[prep.] Defining a circle or closed curve containing a thing.","ex":"Is Clare around today?"},"ARROW":{"p":"/ˈæɹ.əʊ/","s":"n./v.","e":"[n.] A projectile consisting of a shaft, a point and a tail with stabilizing fins that is shot from a bow.\n[n.] A sign or symbol used to indicate a direction (e.g. →).\n[n.] A directed edge.\n[v.] To move swiftly and directly (like an arrow)\n[v.] To let fly swiftly and directly\n[v.] (of a sugar cane plant) To develop an inflorescence.","ex":""},"ASCOT":{"p":"","s":"n.","e":"[n.] Ascot tie","ex":""},"AUGUR":{"p":"/ˈɔː.ɡə/","s":"n./v.","e":"[n.] A diviner who foretells events by the behaviour of birds or other animals, or by signs derived from celestial phenomena, or unusual occurrences.\n[n.] An official who interpreted omens before the start of public events.\n[v.] To foretell events; to exhibit signs of future events.\n[v.] To anticipate, to foretell, or to indicate a favorable or an unfavorable issue.","ex":"to augur well or ill"},"ASSUME":{"p":"/əˈsuːm/","s":"v.","e":"[v.] To authenticate by means of belief; to surmise; to suppose to be true, especially without proof\n[v.] To take on a position, duty or form\n[v.] To adopt a feigned quality or manner; to claim without right; to arrogate","ex":"We assume that, as her parents were dentists, she knows quite a bit about dentistry."},"AUCTION":{"p":"/ˈɒkʃən/","s":"n./v.","e":"[n.] A public event where goods or property are sold to the highest bidder.\n[n.] The first stage of a deal, in which players bid to determine the final contract.\n[v.] To sell at an auction.","ex":""},"ATTEMPT":{"p":"/əˈtɛmpt/","s":"n./v.","e":"[n.] The action of trying at something.\n[n.] An assault or attack, especially an assassination attempt.\n[v.] To try.\n[v.] To try to move, by entreaty, by afflictions, or by temptations; to tempt.\n[v.] To try to win, subdue, or overcome.","ex":"It was worth the attempt."},"AVAIL":{"p":"/əˈveɪl/","s":"n./v.","e":"[n.] Effect in achieving a goal or aim; purpose, use (now usually in negative constructions).\n[n.] Proceeds; profits from business transactions.\n[n.] An advertising slot or package.\n[v.] To turn to the advantage of.\n[v.] To be of service to.\n[v.] To promote; to assist.","ex":"I tried fixing it, to no avail.  Labor, without economy, is of little avail."},"AWARE":{"p":"/əˈweːɹ/","s":"adj.","e":"[adj.] Vigilant or on one's guard against danger or difficulty.\n[adj.] Conscious or having knowledge of something.","ex":"Stay aware! Don't let your guard down."},"BACON":{"p":"/ˈbeɪ.kən/","s":"n.","e":"[n.] Cured meat from the sides, belly or back of a pig.\n[n.] Thin slices of the above in long strips.\n[n.] The police or spies.","ex":"Run! It's the bacon!"},"CASTE":{"p":"/kɑːst/","s":"n.","e":"[n.] Any of the hereditary social classes and subclasses of South Asian societies.\n[n.] A separate and fixed order or class of persons in society who chiefly associate with each other.\n[n.] A class of polymorphous eusocial insects of a particular size and function within a colony.","ex":""},"CAUSE":{"p":"/kɔːz/","s":"n./v.","e":"[n.] (often with of, typically of adverse results) The source of, or reason for, an event or action; that which produces or effects a result.\n[n.] (especially with for and a bare noun) Sufficient reason for a state, as of emotion.\n[n.] A goal, aim or principle, especially one which transcends purely selfish ends.\n[v.] To set off an event or action.\n[v.] (ditransitive) To actively produce as a result, by means of force or authority.\n[v.] To assign or show cause; to give a reason; to make excuse.","ex":"They identified a burst pipe as the cause of the flooding."},"CELLO":{"p":"/ˈtʃɛləʊ/","s":"n.","e":"[n.] A large stringed instrument of the violin family with four strings, tuned from lowest to highest C-G-D-A, and played with a bow, also possessing an endpin to support the instrument's weight.","ex":""},"CECUM":{"p":"","s":"n.","e":"[n.] A blind pouch connected to the large intestine between the ileum and the colon.","ex":""},"CHAMP":{"p":"/t͡ʃæmp/","s":"n.","e":"[n.] Buddy, sport, mate (as a term of address)\n[n.] An ongoing winner in a game or contest.\n[n.] Someone who is chosen to represent a group of people in a contest.\n[n.] Someone who fights for a cause or status.","ex":"Whatcha doing, champ?"},"CHALK":{"p":"/t͡ʃɔːk/","s":"n./v.","e":"[n.] A soft, white, powdery limestone.\n[n.] A piece of chalk, or nowadays processed compressed gypsum, that is used for drawing and for writing on a blackboard.\n[n.] Tailor's chalk.\n[v.] To apply chalk to anything, such as the tip of a billiard cue.\n[v.] To record something, as on a blackboard, using chalk.\n[v.] To use powdered chalk to mark the lines on a playing field.","ex":""},"CHANT":{"p":"/tʃænt/","s":"n./v.","e":"[n.] Type of singing done generally without instruments and harmony.\n[n.] A short and simple melody, divided into two parts by double bars, to which unmetrical psalms, etc., are sung or recited. It is the most ancient form of choral music.\n[n.] Twang; manner of speaking; a canting tone.\n[v.] To sing, especially without instruments, and as applied to monophonic and pre-modern music.\n[v.] To sing or intone sacred text.\n[v.] To utter or repeat in a strongly rhythmical manner, especially as a group.","ex":"The football fans chanted insults at the referee."},"CHART":{"p":"/tʃɑːt/","s":"n./v.","e":"[n.] A map.\n[n.] A systematic non-narrative presentation of data.\n[n.] A written deed; a charter.\n[v.] To draw a chart or map of.\n[v.] To draw or figure out (a route or plan).\n[v.] To record systematically.","ex":"Let's chart how we're going to get from here to there."},"CHASE":{"p":"/tʃeɪs/","s":"n./v.","e":"[n.] The act of one who chases another; a pursuit.\n[n.] A hunt.\n[n.] A children's game where one player chases another.\n[v.] To pursue.\n[v.] To consume another beverage immediately after drinking hard liquor, typically something better tasting or less harsh such as soda or beer; to use a drink as a chaser\n[v.] To attempt to win by scoring the required number of runs in the final innings.","ex":"I need something to chase this shot with."},"CHARITY":{"p":"/ˈtʃæɹɪti/","s":"n.","e":"[n.] An organization, the objective of which is to carry out a charitable purpose.\n[n.] The goods or money given to those in need.\n[n.] Benevolence to others less fortunate than ourselves; the providing of goods or money to those in need.","ex":""},"CHEER":{"p":"/t͡ʃɪə(ɹ)/","s":"n./v.","e":"[n.] A cheerful attitude; happiness; a good, happy, or positive mood.\n[n.] That which promotes good spirits or cheerfulness; provisions prepared for a feast; entertainment.\n[n.] A cry expressing joy, approval or support such as \"hurray\".\n[v.] To gladden; to make cheerful; often with up.\n[v.] To infuse life, courage, animation, or hope, into; to inspirit; to solace or comfort.\n[v.] To applaud or encourage with cheers or shouts.","ex":"a table loaded with good cheer"},"CHEEK":{"p":"/tʃiːk/","s":"n./v.","e":"[n.] The soft skin on each side of the face, below the eyes; the outer surface of the sides of the oral cavity.\n[n.] (usually in the plural) The lower part of the buttocks that is often exposed beneath very brief underwear, swimwear, or extremely short shorts.\n[n.] Impudence.\n[v.] To be impudent towards.\n[v.] To pull a horse's head back toward the saddle using the cheek strap of the bridle.","ex":"You’ve got some cheek, asking me for money!"},"CHIDE":{"p":"/tʃaɪd/","s":"v.","e":"[v.] To admonish in blame; to reproach angrily.\n[v.] To utter words of disapprobation and displeasure; to find fault; to contend angrily.\n[v.] To make a clamorous noise; to chafe.","ex":""},"CHAPTER":{"p":"/ˈt͡ʃæptə/","s":"n./v.","e":"[n.] (authorship) One of the main sections into which the text of a book is divided.\n[n.] A section of a social or religious body.\n[n.] A sequence (of events), especially when presumed related and likely to continue.\n[v.] To divide into chapters.\n[v.] To put into a chapter.\n[v.] (with \"out\") To use administrative procedure to remove someone.","ex":"Detective novel writers try to keep up the suspense until the last chapter."},"CHARD":{"p":"/tʃɑːd/","s":"n.","e":"[n.] An edible leafy vegetable, Beta vulgaris subsp. cicla, with a slightly bitter taste.\n[n.] Artichoke leaves and shoots, blanched to eat.","ex":""},"CHICK":{"p":"/t͡ʃɪk/","s":"n./v.","e":"[n.] A young bird.\n[n.] A young chicken.\n[n.] (term of endearment) A young child.\n[v.] To sprout, as seed does in the ground; to vegetate.","ex":""},"CHESS":{"p":"/t͡ʃɛs/","s":"n.","e":"[n.] A board game for two players with each beginning with sixteen chess pieces moving according to fixed rules across a chessboard with the objective to checkmate the opposing king.","ex":""},"CHILL":{"p":"/tʃɪl/","s":"n./v./adj.","e":"[n.] A moderate, but uncomfortable and penetrating coldness.\n[n.] A sudden penetrating sense of cold, especially one that causes a brief trembling nerve response through the body; the trembling response itself; often associated with illness: fevers and chills, or susceptibility to illness.\n[n.] An uncomfortable and numbing sense of fear, dread, anxiety, or alarm, often one that is sudden and usually accompanied by a trembling nerve response resembling the body's response to biting cold.\n[v.] To lower the temperature of something; to cool\n[v.] To become cold\n[v.] To harden a metal surface by sudden cooling","ex":"There was a chill in the air."},"CHIME":{"p":"/ˈtʃaɪm/","s":"n./v.","e":"[n.] A musical instrument producing a sound when struck, similar to a bell (e.g. a tubular metal bar) or actually a bell. Often used in the plural to refer to the set: the chimes.\n[n.] An individual ringing component of such a set.\n[n.] A small bell or other ringing or tone-making device as a component of some other device.\n[v.] To make the sound of a chime.\n[v.] To cause to sound in harmony; to play a tune, as upon a set of bells; to move or strike in harmony.\n[v.] To utter harmoniously; to recite rhythmically.","ex":"Hugo was a chime player in the school orchestra."},"CHILI":{"p":"/ˈt͡ʃɪli/","s":"n.","e":"[n.] The pungent, spicy fresh or dried fruit of any of several cultivated varieties of capsicum peppers, used in cooking.\n[n.] Powdered chili pepper, used as a spice or flavouring in cooking.\n[n.] (Indian Chinese cuisine) a spicy stew of chicken or paneer, capsicum and onion, eaten as an appetizer.","ex":""},"CHOOSE":{"p":"/t͡ʃuːz/","s":"v./conj.","e":"[v.] To pick; to make the choice of; to select.\n[v.] To elect.\n[v.] To decide to act in a certain way.\n[conj.] The binomial coefficient of the previous and following number.","ex":"I chose a nice ripe apple from the fruit bowl."},"CHOKE":{"p":"/t͡ʃəʊk/","s":"n./v.","e":"[n.] A control on a carburetor to adjust the air/fuel mixture when the engine is cold.\n[n.] In wrestling, karate (etc.), a type of hold that can result in strangulation.\n[n.] A constriction at the muzzle end of a shotgun barrel which affects the spread of the shot.\n[v.] To be unable to breathe because of obstruction of the windpipe (for instance food or other objects that go down the wrong way, or fumes or particles in the air that cause the throat to constrict).\n[v.] To prevent (someone) from breathing or talking by strangling or filling the windpipe.\n[v.] To obstruct (a passage, etc.) by filling it up or clogging it.","ex":"Ever since he choked on a bone, he has refused to eat fish."},"CHINA":{"p":"/tʃʌɪnə/","s":"n.","e":"[n.] The plant Smilax china, a liana of much of eastern Asia.\n[n.] A plant or flower of the repeat-blooming Chinese rose species Rosa chinensis.\n[n.] A plant or flower of one of the class of hybrids developed from Rosa chinensis.\n[n.] Synonym of elderflower rose, Rosa cymosa.\n[n.] Hibiscus rosa-sinensis, native to east Asia.\n[n.] Chinaware: porcelain tableware.","ex":"He set the table with china, cloth napkins, and crystal stemware."},"CHORD":{"p":"/kɔː(ɹ)d/","s":"n./v.","e":"[n.] A harmonic set of three or more notes that is heard as if sounding simultaneously.\n[n.] A straight line between two points of a curve.\n[n.] A horizontal member of a truss.\n[v.] To write chords for.\n[v.] To accord; to harmonize together.\n[v.] To provide with musical chords or strings; to string; to tune.","ex":"This note chords with that one."},"CHIRP":{"p":"/tʃɜː(ɹ)p/","s":"n./v.","e":"[n.] A short, sharp or high note or noise, as of a bird or insect.\n[n.] (radar, sonar, radio telescopy etc.) A pulse of signal whose frequency sweeps through a band of frequencies for the duration of the pulse.\n[v.] To make a short, sharp, cheerful note, as of small birds or crickets\n[v.] To speak in a high-pitched staccato\n[v.] (radar, sonar, radio telescopy etc.) To modify (a pulse of signal) so that it sweeps through a band of frequencies throughout its duration.","ex":""},"CHOICE":{"p":"/tʃɔɪs/","s":"n./adj.","e":"[n.] An option; a decision; an opportunity to choose or select something.\n[n.] The power to choose.\n[n.] One selection or preference; that which is chosen or decided; the outcome of a decision.\n[adj.] Especially good or preferred.\n[adj.] Careful in choosing; discriminating.","ex":"Do I have a choice of what color to paint it?"},"CHOIR":{"p":"/kwaɪə(ɹ)/","s":"n./v.","e":"[n.] Singing group; group of people who sing together; company of people who are trained to sing together.\n[n.] The part of a church where the choir assembles for song.\n[n.] (Christian angelology) One of the nine ranks or orders of angels.\n[v.] To sing in concert.","ex":"The church choir practices Thursday nights."},"CHURCH":{"p":"/t͡ʃɜːt͡ʃ/","s":"n./v.","e":"[n.] A Christian house of worship; a building where Christian religious services take place.\n[n.] Christians collectively seen as a single spiritual community; Christianity.\n[n.] A local group of people who follow the same Christian religious beliefs, local or general.\n[v.] To conduct a religious service for (a woman after childbirth, or a newly married couple).\n[v.] To educate someone religiously, as in in a church.","ex":"There is a lovely little church in the valley."},"CHOSE":{"p":"/tʃəʊz/","s":"v.","e":"[v.] To pick; to make the choice of; to select.\n[v.] To elect.\n[v.] To decide to act in a certain way.","ex":"I chose a nice ripe apple from the fruit bowl."},"CHUMP":{"p":"/tʃʌmp/","s":"v./n.","e":"[v.] To bite or chew loudly or heavily.\n[v.] (Perl) To remove the final character from (a text string) if it is a newline (or, less commonly, some other programmer-specified character).\n[n.] An incompetent person, a blockhead; a loser.\n[n.] A gullible person; a sucker; someone easily taken advantage of; someone lacking common sense.\n[n.] The thick end, especially of a piece of wood or of a joint of meat.","ex":"The dog chomped on the treat and swallowed it in one gulp."},"CIGAR":{"p":"/sɪˈɡɑː(ɹ)/","s":"n.","e":"[n.] Tobacco rolled and wrapped with an outer covering of tobacco leaves, intended to be smoked.\n[n.] Penis","ex":""},"CHUCK":{"p":"/tʃʌk/","s":"n./v.","e":"[n.] Meat from the shoulder of a cow or other animal.\n[n.] Food.\n[n.] A mechanical device that holds an object firmly in place, for example holding a drill bit in a high-speed rotating drill or grinder.\n[v.] To place in a chuck, or hold by means of a chuck, as in turning.\n[v.] To bore or turn (a hole) in a revolving piece held in a chuck.","ex":""},"CHUNK":{"p":"/t͡ʃʌŋk/","s":"n./v.","e":"[n.] A part of something that has been separated.\n[n.] A representative portion of a substance, often large and irregular.\n[n.] A sequence of two or more words that occur in language with high frequency but are not idiomatic; a bundle or cluster.\n[v.] To break into large pieces or chunks.\n[v.] To break down (language, etc.) into conceptual pieces of manageable size.\n[v.] To throw.","ex":"The statue broke into chunks."},"CHURN":{"p":"/tʃɜː(ɹ)n/","s":"n./v.","e":"[n.] A vessel used for churning, especially for producing butter.\n[n.] Customer attrition; the phenomenon or rate of customers leaving a company.\n[n.] The time when a consumer switches his/her service provider.\n[v.] To agitate rapidly and repetitively, or to stir with a rowing or rocking motion; generally applies to liquids, notably cream.\n[v.] To produce excessive and sometimes undesirable or unproductive activity or motion.\n[v.] To move rapidly and repetitively with a rocking motion; to tumble, mix or shake.","ex":"a butter churn"},"CHUTE":{"p":"/ʃ(j)uːt/","s":"n.","e":"[n.] A framework, trough or tube, upon or through which objects are made to slide from a higher to a lower level, or through which water passes to a wheel.\n[n.] A waterfall or rapid.\n[n.] The pen in which an animal is confined before being released in a rodeo.","ex":""},"CIDER":{"p":"/ˈsaɪ̯.də/","s":"n.","e":"[n.] An alcoholic, often sparkling (carbonated) beverage made from fermented apples; hard cider; apple cider\n[n.] A non-alcoholic still beverage consisting of the juice of early-harvest apples, usually unfiltered and still containing pulp; apple cider; sweet cider (without pulp such a beverage is called apple juice).\n[n.] A non-alcoholic carbonated beverage made from apples.","ex":"She liked an aged cider. He liked a harder cider."},"CITY":{"p":"/sɪtɪ/","s":"n.","e":"[n.] A large settlement, bigger than a town; sometimes with a specific legal definition, depending on the place.\n[n.] A settlement granted special status by royal charter or letters patent; traditionally, a settlement with a cathedral regardless of size.\n[n.] The central business district; downtown.","ex":"São Paulo is the largest city in South America."},"CIVIL":{"p":"/ˈsɪv.əl/","s":"adj.","e":"[adj.] Having to do with people and government office as opposed to the military or religion.\n[adj.] Behaving in a reasonable or polite manner.\n[adj.] Relating to private relations among citizens, as opposed to criminal matters.","ex":"She went into civil service because she wanted to help the people."},"CIVIC":{"p":"/ˈsɪvɪk/","s":"adj.","e":"[adj.] Of, relating to, or belonging to a city, a citizen, or citizenship; municipal or civil.\n[adj.] Of or relating to the citizen, or of good citizenship and its rights and duties.","ex":"Thousands of people came to the Civic Center to show off their civic pride."},"CLACK":{"p":"/klæk/","s":"n./v.","e":"[n.] An abrupt, sharp sound, especially one made by two hard objects colliding repetitively; a sound midway between a click and a clunk.\n[n.] Anything that causes a clacking noise, such as the clapper of a mill, or a clack valve.\n[n.] Chatter; prattle.\n[v.] To make a sudden, sharp noise, or succession of noises; to click.\n[v.] To cause to make a sudden, sharp noise, or succession of noises; to click.\n[v.] To chatter or babble; to utter rapidly without consideration.","ex":""},"CLANG":{"p":"/klæŋ/","s":"n./v.","e":"[n.] A loud, ringing sound, like that made by free-hanging metal objects striking each other.\n[n.] Quality of tone.\n[n.] The cry of some birds, including the crane and the goose.\n[v.] To strike (objects) together so as to produce a clang.\n[v.] To give out a clang; to resound.\n[n.] Any periodic sound, especially one composed of a fundamental and harmonics, as opposed to simple periodic sounds (sine tones).","ex":""},"CLASP":{"p":"/klɑːsp/","s":"n./v.","e":"[n.] A fastener or holder, particularly one that clasps.\n[n.] (in the singular) An embrace, a grasp, or handshake.\n[v.] To take hold of; to grasp; to grab tightly.\n[v.] To shut or fasten together with, or as if with, a clasp.","ex":"I always have a hard time working the clasp on this necklace!"},"CLAIM":{"p":"/kleɪm/","s":"n./v.","e":"[n.] A demand of ownership made for something.\n[n.] The thing claimed.\n[n.] The right or ground of demanding.\n[v.] To demand ownership of.\n[v.] To state a new fact, typically without providing evidence to prove it is true.\n[v.] To demand ownership or right to use for land.","ex":"a claim of ownership"},"CLASH":{"p":"/klaʃ/","s":"n./v.","e":"[n.] A loud sound, like the crashing together of metal objects.\n[n.] A skirmish, a hostile encounter.\n[n.] A match; a game between two sides.\n[v.] To make a clashing sound.\n[v.] To cause to make a clashing sound.\n[v.] To come into violent conflict.","ex":"I heard a clash from the kitchen, and rushed in to find the cat had knocked over some pots and pans."},"CLANK":{"p":"/klæŋk/","s":"n./v.","e":"[n.] A loud, hard sound of metal hitting metal.\n[v.] To make a clanking sound\n[v.] To cause to sound with a clank.","ex":"The chains clanked."},"CLASSIC":{"p":"/ˈklæ.sɪk/","s":"n./adj.","e":"[n.] A perfect and/or early example of a particular style.\n[n.] An artistic work of lasting worth, such as a film or song.\n[n.] The author of such a work.\n[adj.] Of or relating to the first class or rank, especially in literature or art.\n[adj.] Exemplary of a particular style; defining a class/category.\n[adj.] Exhibiting timeless quality.","ex":""},"CLEVER":{"p":"/ˈklɛvɚ/","s":"adj.","e":"[adj.] Nimble with hands or body; skillful; adept.\n[adj.] Resourceful, sometimes to the point of cunning.\n[adj.] Smart, intelligent, or witty; mentally quick or sharp.","ex":"clever like a fox"},"CLASS":{"p":"/klas/","s":"n./v./adj.","e":"[n.] A group, collection, category or set sharing characteristics or attributes.\n[n.] A social grouping, based on job, wealth, etc. In Britain, society is commonly split into three main classes; upper class, middle class and working class.\n[n.] The division of society into classes.\n[v.] To assign to a class; to classify.\n[v.] To be grouped or classed.\n[v.] To divide into classes, as students; to form into, or place in, a class or classes.","ex":"Often used to imply membership of a large class."},"CLEAT":{"p":"/kliːt/","s":"n./v.","e":"[n.] A strip of wood or iron fastened on transversely to something in order to give strength, prevent warping, hold position, etc.\n[n.] A continuous metal strip, or angled piece, used to secure metal components.\n[n.] A device to quickly affix a line or rope, and from which it is also easy to release.\n[v.] To strengthen with a cleat.\n[v.] To tie off, affix, stopper a line or rope, especially to a cleat.","ex":""},"CLEFT":{"p":"/klɛft/","s":"n./v.","e":"[n.] An opening, fissure, or V-shaped indentation made by or as if by splitting.\n[n.] A piece made by splitting.\n[n.] A disease of horses; a crack on the band of the pastern.\n[v.] To syntactically separate a prominent constituent from the rest of the clause that concerns it, such as threat in \"The threat which I saw but which he didn't see, was his downfall.\"","ex":"a cleft of wood"},"CLERK":{"p":"/klɐːk/","s":"n./v.","e":"[n.] One who occupationally works with records, accounts, letters, etc.; an office worker.\n[n.] A facilitator of a Quaker meeting for business affairs.\n[n.] In the Church of England, the layman that assists in the church service, especially in reading the responses (also called parish clerk).\n[v.] To act as a clerk, to perform the duties or functions of a clerk","ex":"The law school graduate clerked for the supreme court judge for the summer."},"CLICK":{"p":"/klɪk/","s":"n./v./int.","e":"[n.] A brief, sharp, not particularly loud, relatively high-pitched sound produced by the impact of something small and hard against something hard, such as by the operation of a switch, a lock or a latch, or a finger pressed against the thumb and then released to strike the hand.\n[n.] An ingressive sound made by coarticulating a velar or uvular closure with another closure.\n[n.] Sound made by a dolphin.\n[v.] To cause to make a click; to operate (a switch, etc) so that it makes a click.\n[v.] To press and release (a button on a computer mouse).\n[v.] To select a software item using, usually, but not always, the pressing of a mouse button.","ex":"I turned the key, the lock gave a click and the door opened;  a click of one’s fingers"},"CLIFF":{"p":"/klɪf/","s":"n.","e":"[n.] A vertical (or nearly vertical) rock face.\n[n.] A point where something abruptly fails or decreases in value etc.","ex":""},"CLINK":{"p":"/klɪŋk/","s":"n./v.","e":"[n.] The sound of metal on metal, or glass on glass.\n[v.] To make a clinking sound; to make a sound of metal on metal or glass on glass; to strike materials such as metal or glass against one another.\n[v.] To rhyme.","ex":"You could hear the clink of the glasses from the next room."},"CLIMB":{"p":"/klaɪm/","s":"n./v.","e":"[n.] An act of climbing.\n[n.] The act of getting to somewhere more elevated.\n[n.] An upwards struggle\n[v.] To ascend; rise; to go up.\n[v.] To mount; to move upwards on.\n[v.] To scale; to get to the top of something.","ex":"Prices climbed steeply."},"CLIME":{"p":"/ˈklaɪm/","s":"n.","e":"[n.] A particular region defined by its weather or climate.\n[n.] Climate.","ex":"After working hard all of his life, Max retired to warmer climes in Florida."},"CLING":{"p":"/ˈklɪŋ/","s":"n./v.","e":"[n.] Fruit (especially peach) whose flesh adheres strongly to the pit.\n[n.] Adherence; attachment; devotion\n[v.] To hold very tightly, as to not fall off.\n[v.] To adhere to an object, without being affixed, in such a way as to follow its contours. Used especially of fabrics and films.\n[v.] To cause to adhere to, especially by twining round or embracing.","ex":"Seaweed clung to the anchor."},"CLIMATE":{"p":"/ˈklaɪmɪt/","s":"n./v.","e":"[n.] An area of the earth's surface between two parallels of latitude.\n[n.] A region of the Earth.\n[n.] The long-term manifestations of weather and other atmospheric conditions in a given area or country, now usually represented by the statistical summary of its weather conditions during a period long enough to ensure that representative values are obtained (generally 30 years).\n[v.] To dwell.","ex":""},"CLONE":{"p":"/kləʊn/","s":"n./v.","e":"[n.] A living organism (originally a plant) produced asexually from a single ancestor, to which it is genetically identical.\n[n.] A group of identical cells derived from a single cell.http//www.medterms.com/script/main/art.asp?articlekey=2754\n[n.] A copy or imitation of something already existing, especially when designed to simulate it.\n[v.] To create a clone of.","ex":"The scientists were able to clone a sheep."},"CLOAK":{"p":"/ˈkloʊk/","s":"n./v.","e":"[n.] A long outer garment worn over the shoulders covering the back; a cape, often with a hood.\n[n.] A blanket-like covering, often metaphorical.\n[n.] That which conceals; a disguise or pretext.\n[v.] To cover as with a cloak.\n[v.] To hide or conceal.\n[v.] To render or become invisible via futuristic technology.","ex":"Night hid her movements with its cloak of darkness."},"CLOTHES":{"p":"/kləʊ(ð)z/","s":"n.","e":"[n.] A woven fabric such as used in dressing, decorating, cleaning or other practical use.\n[n.] Specifically, a tablecloth, especially as spread before a meal or removed afterwards.\n[n.] A piece of cloth used for a particular purpose.\n[n.] Items of clothing; apparel.\n[n.] The covering of a bed; bedclothes.\n[n.] Laundry (hung on a clothesline)","ex":""},"CLOSE":{"p":"/kləʊz/","s":"n./v.","e":"[n.] An end or conclusion.\n[n.] The manner of shutting; the union of parts; junction.\n[n.] A grapple in wrestling.\n[v.] (physical) To remove a gap.\n[v.] (social) To finish, to terminate.\n[v.] To come or gather around; to enclose; to encompass; to confine.","ex":"We owe them our thanks for bringing the project to a successful close."},"CLUE":{"p":"/kluː/","s":"n./v.","e":"[n.] A strand of yarn etc. as used to guide one through a labyrinth; something which points the way, a guide.\n[n.] Information which may lead one to a certain point or conclusion.\n[n.] An object or a kind of indication which may be used as evidence.\n[v.] To provide with a clue.\n[v.] To provide someone with information which he or she lacks (often used with \"in\" or \"up\").","ex":"The crossword compiler wasn't sure how to clue the word \"should\"."},"CLOCK":{"p":"/klɒk/","s":"n./v.","e":"[n.] An instrument used to measure or keep track of time; a non-portable timepiece.\n[n.] The odometer of a motor vehicle.\n[n.] An electrical signal that synchronizes timing among digital circuits of semiconductor chips or modules.\n[v.] To measure the duration of.\n[v.] To measure the speed of.\n[v.] To hit (someone) heavily.","ex":"This car has over 300,000 miles on the clock."},"CLOSET":{"p":"/ˈklɒzɪt/","s":"n./v./adj.","e":"[n.] Any private area, (particularly) bowers in the open air.\n[n.] Any private or inner room, (particularly):\n[n.] A pew or side-chapel reserved for a monarch or other feudal lord.\n[v.] To shut away for private discussion.\n[v.] To put into a private place for a secret interview or interrogation.\n[v.] To shut up in, or as in, a closet for concealment or confinement.","ex":"The ambassador has been closeted with the prime minister all afternoon. We're all worried what will be announced when they exit."},"CLOUD":{"p":"/klaʊd/","s":"n./v.","e":"[n.] A rock; boulder; a hill.\n[n.] A visible mass of water droplets suspended in the air.\n[n.] Any mass of dust, steam or smoke resembling such a mass.\n[v.] To become foggy or gloomy, or obscured from sight.\n[v.] To overspread or hide with a cloud or clouds.\n[v.] To make obscure.","ex":"The glass clouds when you breathe on it."},"CLOUT":{"p":"/klʌʊt/","s":"n./v.","e":"[n.] Influence or effectiveness, especially political.\n[n.] A blow with the hand.\n[n.] A home run.\n[v.] To hit, especially with the fist.\n[v.] To cover with cloth, leather, or other material; to bandage, patch, or mend with a clout.\n[v.] To stud with nails, as a timber, or a boot sole.","ex":""},"CLOVE":{"p":"/kləʊv/","s":"n.","e":"[n.] A very pungent aromatic spice, the unexpanded flower bud of the clove tree.\n[n.] A clove tree, of the species Syzygium aromaticum (syn. Caryophyllus aromaticus), native to the Moluccas (Indonesian islands), which produces the spice.\n[n.] An old English measure of weight, containing 7 pounds (3.2 kg), i.e. half a stone.","ex":""},"CLOWN":{"p":"/klaʊn/","s":"n./v.","e":"[n.] A slapstick performance artist often associated with a circus and usually characterized by bright, oversized clothing, a red nose, face paint, and a brightly colored wig.\n[n.] A person who acts in a silly fashion.\n[n.] A stupid person.\n[v.] To act in a silly or playful fashion.\n[v.] To ridicule.","ex":""},"CLUB":{"p":"/klʌb/","s":"n./v.","e":"[n.] An association of members joining together for some common purpose, especially sports or recreation.\n[n.] A heavy stick intended for use as a weapon or plaything.\n[n.] A joint charge of expense, or any person's share of it; a contribution to a common fund.\n[v.] To hit with a club.\n[v.] To join together to form a group.\n[v.] To combine into a club-shaped mass.","ex":"He clubbed the poor dog."},"CLOTH":{"p":"/klɑθ/","s":"n.","e":"[n.] A woven fabric such as used in dressing, decorating, cleaning or other practical use.\n[n.] Specifically, a tablecloth, especially as spread before a meal or removed afterwards.\n[n.] A piece of cloth used for a particular purpose.","ex":""},"CLUNK":{"p":"/klʌŋk/","s":"n./v.","e":"[n.] A dull, metallic sound, especially one made by two bodies coming into contact.\n[n.] The sound of liquid coming out of a bottle, etc.; a glucking sound.\n[v.] To make such a sound","ex":""},"COACH":{"p":"/kəʊtʃ/","s":"n./v.","e":"[n.] A wheeled vehicle, generally drawn by horse power.\n[n.] A passenger car, either drawn by a locomotive or part of a multiple unit.\n[n.] (originally Oxford University slang) A trainer or instructor.\n[v.] To train.\n[v.] To instruct; to train.\n[v.] To study under a tutor.","ex":"She has coached many opera stars."},"COAT":{"p":"/kəʊt/","s":"n./v.","e":"[n.] An outer garment covering the upper torso and arms.Wp\n[n.] A covering of material, such as paint.Wp\n[n.] The fur or feathers covering an animal's skin.Wp\n[v.] To cover with a coating of some material.\n[v.] To cover like a coat.\n[v.] To clothe.","ex":"When the dog shed its coat, it left hair all over the furniture and the carpet."},"CLOVER":{"p":"/ˈkləʊ.və(ɹ)/","s":"n.","e":"[n.] A plant of the genus Trifolium with leaves usually divided into three (rarely four) leaflets and with white or red flowers.\n[n.] The second Lenormand card, representing hope, optimism and short-term luck.","ex":""},"CODE":{"p":"/kəʊd/","s":"n./v.","e":"[n.] A short symbol, often with little relation to the item it represents.\n[n.] A body of law, sanctioned by legislation, in which the rules of law to be specifically applied by the courts are set forth in systematic form; a compilation of laws by public authority; a digest.\n[n.] Any system of principles, rules or regulations relating to one subject.\n[v.] To write software programs.\n[v.] To add codes to a dataset.\n[v.] To categorise by assigning identifiers from a schedule, for example CPT coding for medical insurance purposes.","ex":"This flavour of soup has been assigned the code WRT-9."},"COBRA":{"p":"/ˈkɒbɹə/","s":"n.","e":"[n.] Any of various venomous snakes of the family Elapidae.","ex":""},"CLUCK":{"p":"/klʌk/","s":"n./v.","e":"[n.] The sound made by a hen, especially when brooding, or calling her chicks.\n[n.] Any sound similar to this.\n[n.] A kind of tongue click used to urge on a horse.\n[v.] To make such a sound.\n[v.] To cause (the tongue) to make a clicking sound.\n[v.] To call together, or call to follow, as a hen does her chickens.","ex":"My mother clucked her tongue in disapproval."},"COAL":{"p":"/kɔʊl/","s":"n./v.","e":"[n.] A black rock formed from prehistoric plant remains, composed largely of carbon and burned as a fuel.\n[n.] A piece of coal used for burning (this use is less common in American English)\n[n.] A type of coal, such as bituminous, anthracite, or lignite, and grades and varieties thereof.\n[v.] To take on a supply of coal (usually of steam ships).\n[v.] To supply with coal.\n[v.] To be converted to charcoal.","ex":"Put some coal on the fire."},"COLLEGE":{"p":"/ˈkɒlɪd͡ʒ/","s":"n.","e":"[n.] A corporate group; a group of colleagues.\n[n.] (in some proper nouns) A group sharing common purposes or goals.\n[n.] An electoral college.","ex":"College of Cardinals, College of Surgeons"},"COLUMN":{"p":"/ˈkɑljəm/","s":"n.","e":"[n.] A solid upright structure designed usually to support a larger structure above it, such as a roof or horizontal beam, but sometimes for decoration.\n[n.] A vertical line of entries in a table, usually read from top to bottom.\n[n.] A body of troops or army vehicles, usually strung out along a road.","ex":""},"COLON":{"p":"/ˈkəʊ.lɒn/","s":"n.","e":"[n.] The punctuation mark \":\".\n[n.] The triangular colon (especially in context of not being able to type the actual triangular colon).\n[n.] A rhetorical figure consisting of a clause which is grammatically, but not logically, complete.","ex":""},"COMBAT":{"p":"/ˈkɒmˌbæt/","s":"n./v.","e":"[n.] A battle, a fight (often one in which weapons are used).\n[n.] A struggle for victory\n[v.] To fight; to struggle against.\n[v.] To fight (with); to struggle for victory (against).","ex":"It has proven very difficult to combat drug addiction."},"COMING":{"p":"/ˈkʌmɪŋ/","s":"v.","e":"[v.] To move from further away to nearer to.\n[v.] To arrive.\n[v.] To appear, to manifest itself.","ex":"She’ll be coming ’round the mountain when she comes [...]"},"COMMON":{"p":"/ˈkɒmən/","s":"n./v./adj.","e":"[n.] Mutual good, shared by more than one.\n[n.] A tract of land in common ownership; common land.\n[n.] The people; the community.\n[v.] To communicate (something).\n[v.] To converse, talk.\n[v.] To have sex.","ex":"The two competitors have the common aim of winning the championship."},"COMFY":{"p":"/ˈkʌm.fi/","s":"adj.","e":"[adj.] Comfortable.","ex":"The robe and slippers were so warm and comfy she just fell asleep in her chair."},"COMIC":{"p":"/ˈkɒmɪk/","s":"n./adj.","e":"[n.] A comedian.\n[n.] A story composed of cartoon images arranged in sequence, usually with textual captions; a graphic novel.\n[n.] A children's newspaper.\n[adj.] Funny; amusing; comical.\n[adj.] Relating to comedy.","ex":"a comic stereotype"},"COMMA":{"p":"/ˈkɒm.ə/","s":"n./v.","e":"[n.] The punctuation mark ⟨,⟩ used to indicate a set off parts of a sentence or between elements of a list.\n[n.] A similar-looking subscript diacritical mark.\n[n.] Any of various nymphalid butterflies of the genus Polygonia, having a comma-shaped white mark on the underwings, especially Polygonia c-album and Polygonia c-aureum of North Africa, Europe, and Asia.\n[v.] To place a comma or commas within text; to follow, precede, or surround a portion of text with commas.","ex":""},"COLD":{"p":"/kɔʊld/","s":"adj.","e":"[adj.] (of a thing) Having a low temperature.\n[adj.] (of the weather) Causing the air to be cold.\n[adj.] (of a person or animal) Feeling the sensation of coldness, especially to the point of discomfort.","ex":"A cold wind whistled through the trees."},"COMPANY":{"p":"/ˈkʌmp(ə)ni/","s":"n./v.","e":"[n.] A team; a group of people who work together professionally.\n[n.] A small group of birds or animals.\n[n.] An entity having legal personality, and thus able to own property and to sue and be sued in its own name; a corporation.\n[v.] To accompany, keep company with.\n[v.] To associate.\n[v.] To be a lively, cheerful companion.","ex":""},"COMET":{"p":"/ˈkɒmət/","s":"n.","e":"[n.] A celestial body consisting mainly of ice, dust and gas in a (usually very eccentric) orbit around the Sun and having a \"tail\" of matter blown back from it by the solar wind as it approaches the Sun.\n[n.] A celestial phenomenon with the appearance given by the orbiting celestial body.\n[n.] Any of several species of hummingbird found in the Andes.","ex":""},"COMPETE":{"p":"/kəm.ˈpiːt/","s":"v.","e":"[v.] To be in battle or in a rivalry with another for the same thing, position, or reward; to contend\n[v.] To be in a position in which it is possible to win or triumph.\n[v.] To take part in a contest, game or similar event","ex":""},"COMPLEX":{"p":"","s":"n./v./adj.","e":"[n.] A network of interconnected systems.\n[n.] A collection of buildings with a common purpose, such as a university or military base.\n[n.] An assemblage of related things; a collection.\n[v.] To form a complex with another substance\n[v.] To complicate.\n[adj.] Made up of multiple parts; composite; not simple.","ex":""},"CONDUCT":{"p":"/ˈkɒndʌkt/","s":"n./v.","e":"[n.] The act or method of controlling or directing\n[n.] Skillful guidance or management; leadership\n[n.] Behaviour; the manner of behaving\n[v.] To lead, or guide; to escort.\n[v.] To lead; to direct; to be in charge of (people or tasks)\n[v.] (reflexively to conduct oneself) To behave.","ex":"Good conduct will be rewarded and likewise poor conduct will be punished."},"COME":{"p":"/kʌm/","s":"n./v./prep./int.","e":"[n.] Coming, arrival; approach.\n[n.] Semen\n[n.] Female ejaculatory discharge.\n[v.] To move from further away to nearer to.\n[v.] To arrive.\n[v.] To appear, to manifest itself.","ex":"She’ll be coming ’round the mountain when she comes [...]"},"CONCEPT":{"p":"/ˈkɒn.sɛpt/","s":"n.","e":"[n.] An abstract and general idea; an abstraction.\n[n.] Understanding retained in the mind, from experience, reasoning and imagination; a generalization (generic, basic form), or abstraction (mental impression), of a particular set of instances or occurrences (specific, though different, recorded manifestations of the concept).\n[n.] In generic programming, a description of supported operations on a type, including their syntax and semantics.","ex":""},"CONCERN":{"p":"/kənˈsɜːn/","s":"n./v.","e":"[n.] That which affects one’s welfare or happiness. A matter of interest to someone. The adposition before the matter of interest is usually over, about or for.\n[n.] The expression of solicitude, anxiety, or compassion toward a thing or person.\n[n.] A business, firm or enterprise; a company.\n[v.] To relate or belong to; to have reference to or connection with; to affect the interest of; to be of importance to.\n[v.] To engage by feeling or sentiment; to interest.\n[v.] To make somebody worried.","ex":"Judy's eyes filled with concern as she listened to the news report."},"CONCH":{"p":"/kɒntʃ/","s":"n./v.","e":"[n.] A marine gastropod of the family Strombidae which lives in its own spiral shell.\n[n.] The shell of this sea animal.\n[n.] A musical instrument made from a large spiral seashell, somewhat like a trumpet.\n[v.] To refine the flavour and texture of chocolate by warming and grinding, either in a traditional concher, or between rollers.\n[v.] To play a conch seashell as a musical instrument, by blowing through a hole made close to the origin of the spiral.\n[n.] A machine (rather like a rotating pestle and mortar) used to refine the flavour and texture of chocolate by warming and grinding.","ex":""},"CONE":{"p":"/kəʊn/","s":"n./v.","e":"[n.] A surface of revolution formed by rotating a segment of a line around another line that intersects the first line.\n[n.] A solid of revolution formed by rotating a triangle around one of its altitudes.\n[n.] A space formed by taking the direct product of a given space with a closed interval and identifying all of one end to a point.\n[v.] To fashion into the shape of a cone.\n[v.] To form a cone shape.\n[v.] (frequently followed by \"off\") To segregate or delineate an area using traffic cones","ex":""},"CONIC":{"p":"/ˈkɒ.nɪk/","s":"n./adj.","e":"[n.] A conic section.\n[adj.] Of or relating to a cone or cones.\n[adj.] Shaped like a cone.\n[adj.] Describing a map projection in which meridians are mapped to equally spaced lines radiating out from the apex and parallels of latitude are mapped to circular arcs centred on the apex.","ex":""},"CONDO":{"p":"/ˈkɒndəʊ/","s":"n.","e":"[n.] Joint sovereignty over a territory by two or more countries.\n[n.] A region or territory under such rule.\n[n.] A building in which each unit is owned by an individual but the grounds, structure etc are owned jointly.","ex":""},"CONNECT":{"p":"/kəˈnɛkt/","s":"v.","e":"[v.] (of an object) To join (to another object): to attach, or to be intended to attach or capable of attaching, to another object.\n[v.] (of two objects) To join: to attach, or to be intended to attach or capable of attaching, to each other.\n[v.] (of an object) To join (two other objects), or to join (one object) to (another object): to be a link between two objects, thereby attaching them to each other.","ex":"I think this piece connects to that piece over there."},"CONVERT":{"p":"/ˈkɒn.vəːt/","s":"n./v.","e":"[n.] A person who has converted to a religion.\n[n.] A person who is now in favour of something that he or she previously opposed or disliked.\n[n.] The equivalent of a conversion in rugby\n[v.] To transform or change (something) into another form, substance, state, or product.\n[v.] To change (something) from one use, function, or purpose to another.\n[v.] To induce (someone) to adopt a particular religion, faith, ideology or belief (see also sense 11).","ex":"They were all converts to Islam."},"CONTROL":{"p":"/kənˈtɹəʊl/","s":"n./v.","e":"[n.] Influence or authority over something.\n[n.] A separate group or subject in an experiment against which the results are compared where the primary variable is low or non-existent.\n[n.] The method and means of governing the performance of any apparatus, machine or system, such as a lever, handle or button.\n[v.] To exercise influence over; to suggest or dictate the behavior of.\n[v.] (construed with for) To design (an experiment) so that the effects of one or more variables are reduced or eliminated.","ex":"The government has complete control over the situation."},"COOK":{"p":"/kuːk/","s":"n.","e":"[n.] A person who prepares food.\n[n.] The head cook of a manor house\n[n.] The degree or quality of cookedness of food","ex":"I'm a terrible cook, so I eat a lot of frozen dinners."},"CORRECT":{"p":"/kəˈɹɛkt/","s":"adj.","e":"[adj.] Free from error; true; accurate.\n[adj.] With good manners; well behaved; conforming with accepted standards of behaviour.","ex":""},"COST":{"p":"/ˈkɑst/","s":"v.","e":"[v.] To incur a charge of; to require payment of a (specified) price.\n[v.] To cause something to be lost; to cause the expenditure or relinquishment of.\n[v.] To require to be borne or suffered; to cause.","ex":"It will cost you a lot of money to take a trip around the world."},"EBONY":{"p":"/ˈɛb.ən.i/","s":"n./adj.","e":"[n.] A hard, dense, deep black wood from various subtropical and tropical trees, especially of the genus Diospyros.\n[n.] A tree that yields such wood.\n[n.] A deep, dark black colour.\n[adj.] Made of ebony wood.\n[adj.] A deep, dark black colour.\n[adj.] Dark-skinned; black; especially in reference to African-Americans.","ex":""},"ELSE":{"p":"/ɛls/","s":"adj./adv./conj.","e":"[adj.] (used only with indefinite or interrogative pronouns) Other; in addition to previously mentioned items.\n[adv.] (follows interrogative adverbs) Otherwise, if not.\n[conj.] For otherwise; or else.","ex":"The instructor is busy. Can anyone else help me?"},"EMBER":{"p":"/ˈɛm.bəː/","s":"n.","e":"[n.] A glowing piece of coal or wood.\n[n.] Smoldering ash.","ex":""},"ENDLESS":{"p":"/ˈɛndləs/","s":"adj.","e":"[adj.] Having no end.\n[adj.] Extending indefinitely.\n[adj.] Without profitable end; fruitless; unsatisfying.","ex":"endless time; endless praise"},"ENGLISH":{"p":"/ˈɪŋ.ɡlɪʃ/","s":"n.","e":"[n.] Spinning or rotary motion given to a ball around the vertical axis, as in billiards or bowling.\n[n.] An unusual or unexpected interpretation of a text or idea, a spin, a nuance.","ex":"You can't hit it directly, but maybe if you give it some english."},"ENOUGH":{"p":"/iˈnʌf/","s":"adv./pron./int.","e":"[adv.] Sufficiently.\n[adv.] Fully; quite; used to express slight augmentation of the positive degree, and sometimes equivalent to very.\n[pron.] A sufficient or adequate number, amount, etc.\n[int.] Stop! Don't do that any more!","ex":"Are you man enough to fight me?"},"ENABLE":{"p":"/ɪˈneɪbəl/","s":"v.","e":"[v.] To make somebody able (to do, or to be, something); to give sufficient ability or power to do or to be; to give strength or ability to.\n[v.] To affirm; to make firm and strong.\n[v.] To qualify or approve for some role or position; to render sanction or authorization to; to confirm suitability for.","ex":""},"ENTRY":{"p":"/ˈɛntɹi/","s":"n.","e":"[n.] The act of entering.\n[n.] Permission to enter.\n[n.] A doorway that provides a means of entering a building.","ex":"Children are allowed entry only if accompanied by an adult."},"EQUIP":{"p":"/ɪˈkwɪp/","s":"v.","e":"[v.] To supply with something necessary in order to carry out a specific action or task; to provide with (e.g. weapons, provisions, munitions, rigging)\n[v.] To dress up; to array; to clothe.\n[v.] To prepare (someone) with a skill.","ex":""},"ERECT":{"p":"/ɪˈɹɛkt/","s":"adj.","e":"[adj.] Upright; vertical or reaching broadly upwards.\n[adj.] (of body parts) Rigid, firm; standing out perpendicularly, especially as the result of stimulation.\n[adj.] (of a man) Having an erect penis","ex":"The penis should be fully erect before commencing copulation."},"EQUAL":{"p":"/ˈiːkwəl/","s":"n./v./adj.","e":"[n.] A person or thing of equal status to others.\n[n.] State of being equal; equality.\n[v.] To be equal to, to have the same value as; to correspond to.\n[v.] To make equivalent to; to cause to match.\n[v.] To have as its consequence.\n[adj.] The same in all respects.","ex":"This beer has no equal."},"EPOCH":{"p":"/ˈiːˌpɒk/","s":"n./v.","e":"[n.] A particular period of history, especially one considered noteworthy or remarkable.\n[n.] A notable event which marks the beginning of such a period.\n[n.] A precise instant of time that is used as a point of reference.\n[v.] To divide (data) into segments by time period.","ex":""},"ESSAY":{"p":"/ˈɛˌseɪ/","s":"n.","e":"[n.] (authorship) A written composition of moderate length, exploring a particular issue or subject.\n[n.] A test, experiment; an assay.\n[n.] An attempt.","ex":""},"ERUPT":{"p":"/ɪˈɹʌpt/","s":"v.","e":"[v.] To eject something violently (such as lava or water, as from a volcano or geyser).\n[v.] To burst forth; to break out.\n[v.] To spontaneously release pressure or tension.","ex":"The volcano erupted, spewing lava across a wide area."},"ESCAPE":{"p":"/əˈskeɪp/","s":"n./v.","e":"[n.] The act of leaving a dangerous or unpleasant situation.\n[n.] Leakage or outflow, as of steam or a liquid, or an electric current through defective insulation.\n[n.] Something that has escaped; an escapee.\n[v.] To get free; to free oneself.\n[v.] To avoid (any unpleasant person or thing); to elude, get away from.\n[v.] To avoid capture; to get away with something, avoid punishment.","ex":"The prisoners made their escape by digging a tunnel."},"ETHNIC":{"p":"/ˈɛθ.nɪk/","s":"n./adj.","e":"[n.] An ethnic person, especially a foreigner or member of an immigrant community.\n[n.] An ethnic minority.\n[n.] A heathen, a pagan.\n[adj.] Of or relating to a group of people having common racial, ancestral, national, religious or cultural origins.\n[adj.] Characteristic of a foreign, usually non-Western culture.\n[adj.] Representative of a folk or traditional mode of expression.","ex":"There are many ethnic Indonesians in the Netherlands"},"ESTER":{"p":"/ˈɛstə/","s":"n.","e":"[n.] A compound most often formed by the condensation of an alcohol and an acid, with elimination of water, which contains the functional group carbon-oxygen double bond joined via carbon to another oxygen atom.","ex":""},"EPIC":{"p":"/ˈɛp.ɪk/","s":"n./adj.","e":"[n.] An extended narrative poem in elevated or dignified language, celebrating the feats of a deity, demigod (heroic epic), other legend or traditional hero.\n[n.] A series of events considered appropriate to an epic.\n[n.] In software development, a large or extended user story.\n[adj.] Of, or relating to, an epic.\n[adj.] Momentously heroic; grand in scale or character\n[adj.] Extending beyond the usual or ordinary.","ex":"The Icelandic epic took all night to recite."},"ETUDE":{"p":"/eɪˈtjuːd/","s":"n.","e":"[n.] A short piece of music, designed to give a performer practice in a particular area or skill.","ex":""},"EVEN":{"p":"/ˈiːvən/","s":"n./v./adj./adv.","e":"[n.] (diminutive) An even number.\n[v.] To make flat and level.\n[v.] To equal.\n[v.] To be equal.\n[adj.] Flat and level.\n[adj.] Without great variation.","ex":"So let's see. There are two evens here and three odds."},"ETHIC":{"p":"/ˈɛθɪk/","s":"n./adj.","e":"[n.] A set of principles of right and wrong behaviour guiding, or representative of, a specific culture, society, group, or individual.\n[n.] The morality of an action.\n[adj.] Moral, relating to morals.","ex":"I think the golden rule is a great ethic."},"ETHOS":{"p":"/ˈiːθɒs/","s":"n.","e":"[n.] The character or fundamental values of a person, people, culture, or movement.\n[n.] A form of rhetoric in which the writer or speaker invokes their authority, competence or expertise in an attempt to persuade others that their view is correct.\n[n.] (aesthetics) The traits in a work of art which express the ideal or typic character, as influenced by the ethos (character or fundamental values) of a people, rather than realistic or emotional situations or individual character in a narrow sense; opposed to pathos.","ex":""},"EVENLY":{"p":"","s":"adv.","e":"[adv.] So as to form a flat surface.\n[adv.] In a fair manner of distribution, giving the same amount or number to each; equally.\n[adv.] In a manner that leaves no remainder.","ex":"Spread the icing evenly over the cake."},"EVENING":{"p":"/ˈivnɪŋ/","s":"n.","e":"[n.] The time of the day between dusk and night, when it gets dark.\n[n.] The time of the day between the approximate time of midwinter dusk and midnight (compare afternoon); the period after the end of regular office working hours.\n[n.] A concluding time period; a point in time near the end of something; the beginning of the end of something.","ex":"It was the evening of the Roman Empire."},"EVENT":{"p":"/əˈvɛnt/","s":"n./v.","e":"[n.] An occurrence; something that happens.\n[n.] A prearranged social activity (function, etc.)\n[n.] One of several contests that combine to make up a competition.\n[v.] To occur, take place.","ex":"I went to an event in San Francisco last week."},"EVICT":{"p":"","s":"v.","e":"[v.] To expel (one or more people) from their property; to force (one or more people) to move out.","ex":""},"EXACTLY":{"p":"/ɪɡˈzæk(t)li/","s":"adv./int.","e":"[adv.] (manner) without approximation; precisely.\n[adv.] (focus) Used to provide emphasis.\n[int.] Signifies agreement or recognition.","ex":"He divided the coins exactly in half."},"ETHER":{"p":"/ˈiːθə/","s":"n.","e":"[n.] The substance formerly supposed to fill the upper regions of the atmosphere above the clouds, in particular as a medium breathed by deities.\n[n.] Often as aether and more fully as luminiferous aether: a substance once thought to fill all unoccupied space that allowed electromagnetic waves to pass through it and interact with matter, without exerting any resistance to matter or energy; its existence was disproved by the 1887 Michelson–Morley experiment and the theory of relativity propounded by Albert Einstein (1879–1955).\n[n.] The atmosphere or space as a medium for broadcasting radio and television signals; also, a notional space through which Internet and other digital communications take place; cyberspace.","ex":""},"EVER":{"p":"/ˈɛvə/","s":"adj./adv.","e":"[adj.] Occurring at any time, occurring even but once during a timespan.\n[adv.] Always, frequently, forever.\n[adv.] Continuously, constantly, all the time (for the complete duration).\n[adv.] At any time.","ex":"It was ever thus."},"EVOKE":{"p":"/ɪˈvəʊk/","s":"v.","e":"[v.] To call out; to draw out or bring forth.\n[v.] To cause the manifestation of something (emotion, picture, etc.) in someone's mind or imagination.\n[v.] To elicit a response.","ex":"Being here evokes long forgotten memories."},"EVIL":{"p":"/ˈivəl/","s":"n./adj.","e":"[n.] Moral badness; wickedness; malevolence; the forces or behaviors that are the opposite or enemy of good.\n[n.] Something which impairs the happiness of a being or deprives a being of any good; something which causes suffering of any kind to sentient beings; harm; injury; mischief.\n[n.] A malady or disease; especially in the phrase king's evil (scrofula).\n[adj.] Intending to harm; malevolent.\n[adj.] Morally corrupt.\n[adj.] Unpleasant, foul (of odour, taste, mood, weather, etc.).","ex":"Evil lacks spirituality, hence its need for mind control."},"EXCITED":{"p":"/ɪkˈsaɪtɪd/","s":"v./adj.","e":"[v.] To stir the emotions of.\n[v.] To arouse or bring out (e.g. feelings); to stimulate.\n[v.] To cause an electron to move to a higher than normal state; to promote an electron to an outer level.\n[adj.] Having great enthusiasm.\n[adj.] Being in a state of higher energy.\n[adj.] Having an erection; erect.","ex":"The fireworks which opened the festivities excited anyone present."},"EXAM":{"p":"/ɛɡˈzæm/","s":"n./v.","e":"[n.] The act of examining.\n[n.] Particularly, an inspection by a medical professional to establish the extent and nature of any sickness or injury.\n[n.] A formal test involving answering written or oral questions under a time constraint and usually without access to textbooks.\n[v.] To observe or inspect carefully or critically\n[v.] To check the health or condition of something or someone\n[v.] To determine the aptitude, skills or qualifications of someone by subjecting them to an examination","ex":"He examined the crime scene for clues."},"EXACT":{"p":"/ɪɡˈzækt/","s":"v./adj./adv.","e":"[v.] To demand and enforce the payment or performance of, sometimes in a forcible or imperious way.\n[v.] To make desirable or necessary.\n[v.] To inflict; to forcibly obtain or produce.\n[adj.] Precisely agreeing with a standard, a fact, or the truth; perfectly conforming; neither exceeding nor falling short in any respect.\n[adj.] Habitually careful to agree with a standard, a rule, or a promise; accurate; methodical; punctual.\n[adj.] Precisely or definitely conceived or stated; strict.","ex":"to exact tribute, fees, or obedience from someone"},"EXAMINE":{"p":"/ɪɡˈzæmɪn/","s":"v.","e":"[v.] To observe or inspect carefully or critically\n[v.] To check the health or condition of something or someone\n[v.] To determine the aptitude, skills or qualifications of someone by subjecting them to an examination","ex":"He examined the crime scene for clues."},"EXALT":{"p":"/ɪɡˈzɔːlt/","s":"v.","e":"[v.] To honor; to hold in high esteem.\n[v.] To raise in rank, status etc., to elevate.\n[v.] To elate, or fill with the joy of success.","ex":"They exalted their queen."},"EXIST":{"p":"/ɪɡˈzɪst/","s":"v.","e":"[v.] (stative) to be; have existence; have being or reality","ex":""},"EXILE":{"p":"/ˈɛkˌsaɪl/","s":"n./v.","e":"[n.] The state of being banished from one's home or country.\n[n.] Someone who is banished from their home or country.\n[v.] To send into exile.","ex":"He lived in exile."},"EXAMPLE":{"p":"/əɡˈzæmpl̩/","s":"n./v.","e":"[n.] Something that is representative of all such things in a group.\n[n.] Something that serves to illustrate or explain a rule.\n[n.] Something that serves as a pattern of behaviour to be imitated (a good example) or not to be imitated (a bad example).\n[v.] To be illustrated or exemplified (by).","ex":""},"EXCEPT":{"p":"/ɪkˈsɛpt/","s":"v./prep./conj.","e":"[v.] To exclude; to specify as being an exception.\n[v.] To take exception, to object (to or against).\n[prep.] With the exception of; but.\n[conj.] With the exception (that); used to introduce a clause, phrase or adverb forming an exception or qualification to something previously stated.\n[conj.] Unless; used to introduce a hypothetical case in which an exception may exist.","ex":"to except to a witness or his testimony"},"EXCEL":{"p":"/ɪkˈsɛl/","s":"v.","e":"[v.] To surpass someone or something; to be better or do better than someone or something.\n[v.] To be much better than others.\n[v.] To exceed, to go beyond","ex":"I excelled everyone else with my exam results."},"EXPLAIN":{"p":"/ɛkˈspleɪn/","s":"v.","e":"[v.] To make plain, manifest, or intelligible; to clear of obscurity; to illustrate the meaning of.\n[v.] To give a valid excuse for past behavior.\n[v.] To make flat, smooth out.","ex":"To explain a chapter of the Bible."},"EXERT":{"p":"/ɪɡˈzɜːt/","s":"v.","e":"[v.] To put in vigorous action.\n[v.] To make use of, to apply, especially of something non-material.","ex":"I exerted myself in today's training."},"EXIT":{"p":"/ˈɛksɪt/","s":"n./v.","e":"[n.] An act of going out or going away, or leaving; a departure.\n[n.] A way out.\n[n.] The act of departing from life; death.\n[v.] To go out or go away from a place or situation; to depart, to leave.\n[v.] To depart from life; to die.\n[v.] To end or terminate (a program, subroutine, etc.)","ex":"He made his exit at the opportune time."},"EXPEL":{"p":"/ɪkˈspɛl/","s":"v.","e":"[v.] To eject or erupt.\n[v.] To fire (a bullet, arrow etc.).\n[v.] To remove from membership.","ex":"He was expelled from school multiple times."},"EXPERT":{"p":"/ˈɛkspəːt/","s":"n./adj.","e":"[n.] A person with extensive knowledge or ability in a given subject.\n[n.] A player ranking just below master.\n[adj.] Extraordinarily capable or knowledgeable.\n[adj.] Characteristic of an expert.","ex":"We called in several experts on the subject, but they couldn't reach an agreement."},"EXPORT":{"p":"/ˈɛks.pɔːt/","s":"n./v./adj.","e":"[n.] Something that is exported\n[n.] The act of exporting\n[v.] To carry away\n[v.] To sell (goods) to a foreign country\n[v.] To cause to spread in another part of the world\n[adj.] Of or relating to exportation or exports","ex":"Oil is the main export of Saudi Arabia."},"EXPLORE":{"p":"/ɪkˈsplɔː/","s":"n./v.","e":"[n.] An exploration; a tour of a place to see what it is like.\n[v.] To seek for something or after someone.\n[v.] To examine or investigate something systematically.\n[v.] To travel somewhere in search of discovery.","ex":"The committee has been exploring alternative solutions to the problem at hand."},"EYING":{"p":"","s":"v.","e":"[v.] To observe carefully or appraisingly.\n[v.] To appear; to look.","ex":"After eyeing the document for half an hour, she decided not to sign it."},"EXTEND":{"p":"/ɛkˈstɛnd/","s":"v.","e":"[v.] To increase in extent.\n[v.] To possess a certain extent; to cover an amount of space.\n[v.] To cause to increase in extent.","ex":"The desert extended for miles in all directions."},"EXTENT":{"p":"/ɪksˈtɛnt/","s":"n./adj.","e":"[n.] A range of values or locations.\n[n.] The space, area, volume, etc., to which something extends.\n[n.] A contiguous area of storage in a file system.\n[adj.] Extended.","ex":"The extent of his knowledge of the language is a few scattered words."},"EXTOL":{"p":"/ɪkˈstəʊl/","s":"v.","e":"[v.] To praise; to make high.","ex":""},"EXULT":{"p":"/ɪɡˈzʌlt/","s":"v.","e":"[v.] To rejoice; to be very happy, especially in triumph.","ex":""},"FADE":{"p":"/feɪd/","s":"n./v./adj.","e":"[n.] A golf shot that (for the right-handed player) curves intentionally to the right. See slice, hook, draw.\n[n.] A haircut where the hair is short or shaved on the sides of the head and longer on top. See also high-top fade and low fade.\n[n.] A fight.\n[v.] To grow weak; to lose strength; to decay; to perish gradually; to wither, as a plant.\n[v.] To lose freshness, color, or brightness; to become faint in hue or tint; hence, to be wanting in color.\n[v.] To sink away; to disappear gradually; to grow dim; to vanish.","ex":"The milkman's whistling faded into the distance."},"FACTOR":{"p":"/ˈfæktə/","s":"n./v.","e":"[n.] A doer, maker; a person who does things for another person or organization.\n[n.] An agent or representative.\n[n.] A commission agent.\n[v.] To find all the factors of (a number or other mathematical object) (the objects that divide it evenly).\n[v.] (of a number or other mathematical object) To be a product of other objects.\n[v.] (commercial) To sell a debt or debts to an agent (the factor) to collect.","ex":"The factor of the trading post bought the furs."},"FACTORY":{"p":"/ˈfæktəɹi/","s":"n./adj.","e":"[n.] A trading establishment, especially set up by merchants working in a foreign country.\n[n.] The position or state of being a factor.\n[n.] A building or other place where manufacturing takes place.\n[adj.] (of a configuration, part, etc.) Having come from the factory in the state it is currently in; original, stock.","ex":"See how there's another layer of metal there? That's not factory."},"FAINT":{"p":"/feɪnt/","s":"n./adj.","e":"[n.] The act of fainting, syncope.\n[n.] The state of one who has fainted; a swoon.\n[adj.] (of a being) Lacking strength; weak; languid; inclined to lose consciousness\n[adj.] Lacking courage, spirit, or energy; cowardly; dejected\n[adj.] Barely perceptible; not bright, or loud, or sharp","ex":"She suffered another faint."},"FAITH":{"p":"/feɪθ/","s":"n.","e":"[n.] A trust or confidence in the intentions or abilities of a person, object, or ideal from prior empirical evidence.\n[n.] The process of forming or understanding abstractions, ideas, or beliefs, without empirical evidence, experience or observation.\n[n.] A religious or spiritual belief system.","ex":"I have faith in the goodness of my fellow man."},"FAIRLY":{"p":"/ˈfɛə(ɹ).li/","s":"adv.","e":"[adv.] (manner) In a fair manner; fair; not biased or skewed or favouring a certain party\n[adv.] Favorably; auspiciously; commodiously.\n[adv.] Honestly; properly.","ex":"A jury is expected to ensure that the accused is fairly judged."},"FAMILY":{"p":"/ˈfɛm(ɘ)li/","s":"n./adj.","e":"[n.] A group of people who are closely related to one another (by blood, marriage or adoption); kin; for example, a set of parents and their children; an immediate family.\n[n.] An extended family; a group of people who are related to one another by blood or marriage.\n[n.] A (close-knit) group of people related by blood, friendship, marriage, law, or custom, especially if they live or work together.\n[adj.] Suitable for children and adults.\n[adj.] Conservative, traditional.\n[adj.] Homosexual.","ex":"Our family lives in town."},"FARMER":{"p":"/fɑːmə/","s":"n.","e":"[n.] A person who works the land and/or who keeps livestock, especially on a farm.\n[n.] Agent noun of farm; someone or something that farms.\n[n.] One who takes taxes, customs, excise, or other duties, to collect for a certain rate per cent.","ex":"a farmer of the revenues"},"FAST":{"p":"/fɑːst/","s":"n./adj./adv./int.","e":"[n.] A train that calls at only some stations it passes between its origin and destination, typically just the principal stations\n[adj.] Firmly or securely fixed in place; stable.\n[adj.] Firm against attack; fortified by nature or art; impregnable; strong.\n[adj.] (of people) Steadfast, with unwavering feeling. (Now mostly in set phrases like fast friend(s).)\n[adv.] In a firm or secure manner, securely; in such a way as not to be moved; safe, sound .\n[adv.] (of sleeping) Deeply or soundly .","ex":"That rope is dangerously loose. Make it fast!"},"FALSE":{"p":"/fɒls/","s":"n./adj./adv.","e":"[n.] One of two options on a true-or-false test.\n[adj.] Untrue, not factual, factually incorrect.\n[adj.] Based on factually incorrect premises.\n[adj.] Spurious, artificial.\n[adv.] In a dishonest and disloyal way; falsely.","ex":"The student received a failing grade for circling every true and false on her quiz."},"FATTY":{"p":"/ˈfæt.i/","s":"adj.","e":"[adj.] Containing, composed of, or consisting of fat.\n[adj.] Like fat; greasy.\n[adj.] Literally or figuratively large.","ex":""},"FEAR":{"p":"/fɪə/","s":"n./v.","e":"[n.] A strong, uncontrollable, unpleasant emotion or feeling caused by actual or perceived danger or threat.\n[n.] A phobia, a sense of fear induced by something or someone.\n[n.] Terrified veneration or reverence, particularly towards God, gods, or sovereigns.\n[v.] To feel fear about (something or someone); to be afraid of; to consider or expect with alarm.\n[v.] To feel fear (about something).\n[v.] (used with for) To worry about, to feel concern for, to be afraid for.","ex":"He was struck by fear on seeing the snake."},"FATHER":{"p":"/ˈfaːðə/","s":"n./v.","e":"[n.] A (generally human) male who begets a child.\n[n.] A male ancestor more remote than a parent; a progenitor; especially, a first ancestor.\n[n.] A term of respectful address for an elderly man.\n[v.] To be a father to; to sire.\n[v.] To give rise to.\n[v.] To act as a father; to support and nurture.","ex":"My father was a strong influence on me."},"FAULT":{"p":"/fɒlt/","s":"n./v.","e":"[n.] A defect; something that detracts from perfection.\n[n.] A mistake or error.\n[n.] A weakness of character; a failing.\n[v.] To criticize, blame or find fault with something or someone.\n[v.] To fracture.\n[v.] To commit a mistake or error.","ex":"No! This is my fault, not yours."},"FAVOR":{"p":"/ˈfeɪvə/","s":"n./v.","e":"[n.] A kind or helpful deed; an instance of voluntarily assisting (someone).\n[n.] Goodwill; benevolent regard.\n[n.] A small gift; a party favor.\n[v.] To look upon fondly; to prefer.\n[v.] To encourage, conduce to\n[v.] To do a favor [noun sense 1] for; to show beneficence toward.","ex":"He did me a favor when he took the time to drive me home."},"FEAST":{"p":"/fiːst/","s":"n.","e":"[n.] A very large meal, often of a ceremonial nature.\n[n.] Something delightful\n[n.] A festival; a holy day or holiday; a solemn, or more commonly, a joyous, anniversary.","ex":"We had a feast to celebrate the harvest."},"FELLOW":{"p":"/ˈfɛləʊ/","s":"n./v.","e":"[n.] A colleague or partner.\n[n.] A companion; a comrade.\n[n.] A man without good breeding or worth; an ignoble or mean man.\n[v.] To suit with; to pair with; to match.\n[n.] A person who was a fellow attendee at one's school.","ex":"I've lost touch with all my old schoolmates: I only see them at class reunions."},"FELLA":{"p":"/fɛ.lə/","s":"n.","e":"[n.] (chiefly South US) used to address a male\n[n.] A colleague or partner.\n[n.] A companion; a comrade.\n[n.] A man without good breeding or worth; an ignoble or mean man.\n[n.] A person who was a fellow attendee at one's school.","ex":"Am I right, fellas?"},"FEET":{"p":"/fiːt/","s":"n.","e":"[n.] A biological structure found in many animals that is used for locomotion and that is frequently a separate organ at the terminal part of the leg.\n[n.] Specifically, a human foot, which is found below the ankle and is used for standing and walking.\n[n.] (often used attributively) Travel by walking.","ex":"A spider has eight feet."},"GREEN":{"p":"/ɡɹiːn/","s":"adj.","e":"[adj.] Having green as its color.\n[adj.] (of people) Sickly, unwell.\n[adj.] Unripe, said of certain fruits that change color when they ripen.","ex":"The former flag of Libya is fully green."},"GRAZE":{"p":"/ɡɹeɪz/","s":"n./v.","e":"[n.] The act of grazing; a scratching or injuring lightly on passing.\n[n.] A light abrasion; a slight scratch.\n[n.] The act of animals feeding from pasture.\n[v.] To feed or supply (cattle, sheep, etc.) with grass; to furnish pasture for.\n[v.] To feed on; to eat (growing herbage); to eat grass from (a pasture)\n[v.] To tend (cattle, etc.) while grazing.","ex":"1999: Although it is perfectly good meadowland, none of the villagers has ever grazed animals on the meadow on the other side of the wall. — Stardust, Neil Gaiman, page 4 (2001 Perennial Edition)."},"GRIMY":{"p":"/ˈɡɹaɪmi/","s":"adj.","e":"[adj.] Stained or covered with grime.\n[adj.] From the urban musical genre called grime.","ex":""},"GROUND":{"p":"/ɡɹaʊnd/","s":"n./v.","e":"[n.] The surface of the Earth, as opposed to the sky or water or underground.\n[n.] Terrain.\n[n.] Soil, earth.\n[v.] To connect (an electrical conductor or device) to a ground.\n[v.] To punish, especially a child or teenager, by forcing him/her to stay at home and/or give up certain privileges.\n[v.] To forbid (an aircraft or pilot) to fly.","ex":"Look, I found a ten dollar bill on the ground!"},"GROPE":{"p":"/ɡɹəʊp/","s":"n./v.","e":"[n.] An act of groping, especially sexually.\n[n.] An iron fitting of a medieval cart wheel\n[v.] To feel with or use the hands; to handle.\n[v.] To search or attempt to find something in the dark, or, as a blind person, by feeling; to move about hesitatingly, as in darkness or obscurity; to feel one's way, as with the hands, when one can not see.\n[v.] To touch (another person) closely and (especially) sexually.","ex":"the old man tried to get a quick grope of the young lady on the train."},"GROUP":{"p":"/ɡɹuːp/","s":"n./v.","e":"[n.] A number of things or persons being in some relation to one another.\n[n.] A set with an associative binary operation, under which there exists an identity element, and such that each element has an inverse.\n[n.] An effective divisor on a curve.\n[v.] To put together to form a group.\n[v.] To come together to form a group.","ex":"A group of people gathered in front of the Parliament to demonstrate against the Prime Minister's proposals."},"GROW":{"p":"/ɡɹəʊ/","s":"v.","e":"[v.] To become larger, to increase in magnitude.\n[v.] To appear or sprout.\n[v.] To develop, to mature.","ex":"Children grow quickly."},"GROWL":{"p":"/ɡɹaʊl/","s":"n./v.","e":"[n.] A deep, rumbling, threatening sound made in the throat by an animal.\n[n.] (by extension) The rumbling sound made by a person's stomach when hungry.\n[n.] (by extension) An aggressive grumbling.\n[v.] To utter a deep guttural sound, as an angry animal; to give forth an angry, grumbling sound.\n[v.] Of a wind instrument: to produce a low-pitched rumbling sound.\n[v.] To send a user a message via the Growl software library.","ex":"The dog growled at me as I walked past."},"GRUFF":{"p":"/ɡɹʌf/","s":"v./adj.","e":"[v.] To speak gruffly.\n[adj.] Having a rough, surly, and harsh demeanor and nature.\n[adj.] Hoarse-voiced.","ex":""},"GUILT":{"p":"/ɡɪlt/","s":"n.","e":"[n.] Responsibility for wrongdoing.\n[n.] The state of having been found guilty or admitted guilt in legal proceedings.\n[n.] The regret of having done wrong.","ex":""},"GUITAR":{"p":"/ɡɪˈtɑː(ɹ)/","s":"n./v.","e":"[n.] A stringed musical instrument, of European origin, usually with a fretted fingerboard and six strings, played with the fingers or a plectrum (guitar pick).\n[n.] Any type of musical instrument of the lute family, characterized by a flat back, along with a neck whose upper surface is in the same plane as the soundboard, with strings along the neck and parallel to the soundboard.\n[v.] To play the guitar.","ex":""},"GULF":{"p":"/ɡʌlf/","s":"n./v.","e":"[n.] A hollow place in the earth; an abyss; a deep chasm or basin.\n[n.] That which swallows; the gullet.\n[n.] That which swallows irretrievably; a whirlpool; a sucking eddy.\n[v.] (Oxbridge slang) To award a degree to somebody who has only just passed sufficiently.","ex":""},"GUPPY":{"p":"/ˈɡʌpi/","s":"n.","e":"[n.] A tiny freshwater fish, Poecilia reticulata, popular in home aquariums, that usually has a plain body and black or dark blue tail for the females and a more colorful tail for the males.\n[n.] By extension, any tiny fish.\n[n.] A tube holding paintballs before they are loaded into the gun.","ex":"Fred kept a tank of guppies by the windowsill."},"GULLY":{"p":"/ˈɡʌli/","s":"n./v.","e":"[n.] A trench, ravine or narrow channel which was worn by water flow, especially on a hillside.\n[n.] A small valley.\n[n.] A drop kerb.\n[v.] To flow noisily.\n[v.] To wear away into a gully or gullies.","ex":""},"GUMMY":{"p":"/ˈɡʌmi/","s":"n./adj.","e":"[n.] A sheep that is losing or has lost its teeth.\n[adj.] Showing the gums.\n[n.] A species of shark, Mustelus antarcticus, endemic to southern and south-eastern Australia, the meat of which is sold as flake.","ex":"a gummy grin"},"HALF":{"p":"/hɑːf/","s":"n./v./adj./adv./prep.","e":"[n.] One of two usually roughly equal parts into which anything may be divided, or considered as divided.\n[n.] Half of a standard measure; frequently used for half a pint of beer or cider.\n[n.] (preceded by “a” or a number) The fraction obtained by dividing 1 by 2.\n[v.] To halve.\n[adj.] Consisting of a half (1/2, 50%).\n[adj.] Consisting of some indefinite portion resembling a half; approximately a half, whether more or less; partial; imperfect.","ex":"I ate the slightly smaller half of the apple."},"HABITAT":{"p":"/ˈhæbɪtæt/","s":"n.","e":"[n.] Conditions suitable for an organism or population of organisms to live.\n[n.] A place or type of site where an organism or population naturally occurs.\n[n.] A terrestrial or aquatic area distinguished by geographic, abiotic and biotic features, whether entirely natural or semi-natural.","ex":"This park offers important amphibian habitat and breeding area."},"HALVE":{"p":"/hɑːv/","s":"v.","e":"[v.] To reduce to half the original amount.\n[v.] To divide into two halves.\n[v.] To make up half of.","ex":""},"HAND":{"p":"/hænd/","s":"n./v.","e":"[n.] The part of the forelimb below the forearm or wrist in a human, and the corresponding part in many other animals.\n[n.] That which resembles, or to some extent performs the office of, a human hand.\n[n.] In linear measurement:\n[v.] To give, pass, or transmit with the hand, literally or figuratively.\n[v.] To lead, guide, or assist with the hand; to conduct.\n[v.] To manage.","ex":"Her hands are really strong."},"HANDLE":{"p":"/ˈhæn.dl/","s":"n.","e":"[n.] The part of an object which is (designed to be) held in the hand when used or moved.\n[n.] An instrument for effecting a purpose (either literally or figuratively); a tool, or an opportunity or pretext.\n[n.] The gross amount of wagering within a given period of time or for a given event at one of more establishments.","ex":"The daily handle of a Las Vegas casino is typically millions of dollars."},"HAPPEN":{"p":"/ˈhæpən/","s":"v./adv.","e":"[v.] To occur or take place.\n[v.] To happen to; to befall.\n[v.] (with infinitive) To do or occur by chance or unexpectedly.\n[adv.] Maybe, perhaps.","ex":"Let me tell you how it happened."},"HANDY":{"p":"/ˈhæn.di/","s":"adj.","e":"[adj.] Easy to use, useful.\n[adj.] Nearby, within reach.\n[adj.] Of a person: dexterous, skilful.","ex":"Some people regard duct tape as a handy fix-all."},"HANG":{"p":"[heɪŋ]","s":"n./v.","e":"[n.] The way in which something hangs.\n[n.] A grip, understanding.\n[n.] An instance of ceasing to respond to input.\n[v.] To be or remain suspended.\n[v.] To float, as if suspended.\n[v.] (of a ball in cricket, tennis, etc.) To rebound unexpectedly or unusually slowly, due to backward spin on the ball or imperfections of the ground.","ex":"This skirt has a nice hang."},"HALON":{"p":"","s":"n.","e":"[n.] A hydrocarbon in which one or more hydrogen atoms have been replaced by halogens","ex":""},"HAPPY":{"p":"/ˈhæpiː/","s":"n./v./adj.","e":"[n.] A happy event, thing, person, etc.\n[n.] Preceded by the: happy people as a group.\n[v.] Often followed by up: to become happy; to brighten up, to cheer up.\n[v.] Often followed by up: to make happy; to brighten, to cheer, to enliven.\n[adj.] Having a feeling arising from a consciousness of well-being or of enjoyment; enjoying good of any kind, such as comfort, peace, or tranquillity; blissful, contented, joyous.\n[adj.] Experiencing the effect of favourable fortune; favored by fortune or luck; fortunate, lucky, propitious.","ex":"Music makes me feel happy."},"HARDLY":{"p":"/ˈhɑːdli/","s":"adv./int.","e":"[adv.] (manner) Firmly, vigorously, with strength or exertion.\n[adv.] (manner) Harshly, severely; in a hard manner.\n[adv.] With difficulty.\n[int.] Not really.","ex":"I can't really deal hardly with people."},"HARRY":{"p":"/hæɹi/","s":"v.","e":"[v.] To plunder, pillage, assault.\n[v.] To make repeated attacks on an enemy.\n[v.] To strip, lay waste, ravage.","ex":""},"HASTY":{"p":"/ˈheɪsti/","s":"adj.","e":"[adj.] Acting in haste; being too hurried or quick","ex":"Without much thinking about it they made a hasty decision to buy it."},"HAREM":{"p":"/ˈhæɹəm/","s":"n.","e":"[n.] The private part of an Arab household, traditionally forbidden to male strangers.\n[n.] A group of someone's girlfriends, wives and/or concubines in a polygamous household.\n[n.] A group of female animals (cows) herded and controlled by a male animal (bull) of that species for breeding purposes. Such behaviour is exhibited by bovids including cattle and buffalo as well as moose, elephants, seals, sea lions, baboons, and elephant seals.","ex":""},"HARM":{"p":"/hɑːm/","s":"n./v.","e":"[n.] Physical injury; hurt; damage\n[n.] Emotional or figurative hurt\n[n.] Detriment; misfortune.\n[v.] To cause injury to another; to hurt; to cause damage to something.","ex":"No harm came to my possessions."},"HARPY":{"p":"/ˈhɑːpi/","s":"n.","e":"[n.] A fabulous winged monster, ravenous and filthy, having the face of a woman and the body of a vulture.\n[n.] A shrewish woman.\n[n.] One who is rapacious or ravenous; an extortioner.","ex":""},"HARSH":{"p":"/hɑːʃ/","s":"v./adj.","e":"[v.] To negatively criticize.\n[v.] To put a damper on (a mood).\n[adj.] Unpleasantly rough to the touch or other senses.\n[adj.] Severe or cruel.","ex":"Quit harshing me already, I said that I was sorry!"},"HATCH":{"p":"/hætʃ/","s":"n./v.","e":"[n.] A horizontal door in a floor or ceiling.\n[n.] A trapdoor.\n[n.] An opening in a wall at window height for the purpose of serving food or other items. A pass through.\n[v.] To close with a hatch or hatches.","ex":"The cook passed the dishes through the serving hatch."},"HAVE":{"p":"","s":"n./v.","e":"[n.] A wealthy or privileged person.\n[n.] One who has some (contextually specified) thing.\n[v.] To possess, own.\n[v.] To hold, as something at someone's disposal.\n[v.] Used to state the existence or presence of someone in a specified relationship with the subject.","ex":"I have a house and a car."},"HATE":{"p":"/heɪt/","s":"n./v.","e":"[n.] An object of hatred.\n[n.] Hatred.\n[n.] Negative feedback, abusive behaviour.\n[v.] To dislike intensely or greatly.\n[v.] To experience hatred.","ex":"One of my pet hates is traffic wardens."},"HAUNT":{"p":"/hænt/","s":"n./v.","e":"[n.] A place at which one is regularly found; a habitation or hangout.\n[n.] A ghost.\n[n.] A feeding place for animals.\n[v.] To inhabit, or visit frequently (most often used in reference to ghosts).\n[v.] To make uneasy, restless.\n[v.] To stalk, to follow","ex":"I went back the town I used to live and visited all my old haunts."},"HAVEN":{"p":"/ˈheɪvən/","s":"n./v.","e":"[n.] A harbour or anchorage protected from the sea.\n[n.] (by extension) A place of safety; a refuge or sanctuary.\n[n.] (by extension) A peaceful place.\n[v.] To put into, or provide with a haven.","ex":""},"HATER":{"p":"/ˈheɪtə(ɹ)/","s":"n.","e":"[n.] One who hates.\n[n.] One who expresses unfounded or inappropriate hatred or dislike, particularly if motivated by envy.","ex":""},"HEAD":{"p":"/hɛd/","s":"n./v./adj.","e":"[n.] The part of the body of an animal or human which contains the brain, mouth and main sense organs.\n[n.] The topmost, foremost, or leading part.\n[n.] (social, metonymy) A leader or expert.\n[v.] To be in command of. (See also head up.)\n[v.] To come at the beginning of; to commence.\n[v.] To strike with the head; as in soccer, to head the ball","ex":"Be careful when you pet that dog on the head; it may bite."},"HAVING":{"p":"/ˈhævɪŋ/","s":"v./n./adj.","e":"[v.] To possess, own.\n[v.] To hold, as something at someone's disposal.\n[v.] Used to state the existence or presence of someone in a specified relationship with the subject.\n[n.] The act of possessing; ownership.\n[n.] Something owned; possession; goods; estate.\n[n.] A person's behaviour.","ex":"I have a house and a car."},"HAVOC":{"p":"/ˈhæv.ək/","s":"n./v./int.","e":"[n.] Widespread devastation, destruction\n[n.] Mayhem\n[v.] To pillage.\n[v.] To cause havoc.\n[int.] A cry in war as the signal for indiscriminate slaughter.","ex":""},"HAZEL":{"p":"/ˈheɪzəl/","s":"n./adj.","e":"[n.] A tree or shrub of the genus Corylus, bearing edible nuts called hazelnuts or filberts.\n[n.] The nut of the hazel tree.\n[n.] The wood of a hazelnut tree.\n[adj.] Of a greenish-brown colour. (often used to refer to eye colour)","ex":""},"HEADING":{"p":"[ˈhɛɾ.ɪŋ]","s":"v./n.","e":"[v.] To be in command of. (See also head up.)\n[v.] To come at the beginning of; to commence.\n[v.] To strike with the head; as in soccer, to head the ball\n[n.] The title or topic of a document, article, chapter, or of a section thereof.\n[n.] The direction into which a seagoing or airborne vessel's bow is pointing (apparent heading) and/or the direction into which it is actually moving relative to the ground (true heading)\n[n.] Material for the heads of casks, barrels, etc.","ex":"Who heads the board of trustees?"},"HEALTHY":{"p":"/ˈhɛl.θi/","s":"adj.","e":"[adj.] Enjoying health and vigor of body, mind, or spirit: well.\n[adj.] Conducive to health.\n[adj.] Evincing health.","ex":"He was father to three healthy kids."},"HEADY":{"p":"/ˈhɛdi/","s":"adj.","e":"[adj.] Intoxicating or stupefying.\n[adj.] Tending to upset the mind or senses.\n[adj.] Exhilarating.","ex":"The cocktail was a heady mixture of spirits."},"HEALTH":{"p":"/hɛlθ/","s":"n.","e":"[n.] The state of being free from physical or psychological disease, illness, or malfunction; wellness.\n[n.] A state of well-being or balance, often physical but sometimes also mental and social; the overall level of function of an organism from the cellular (micro) level to the social (macro) level.\n[n.] Physical condition.","ex":"Her mental health is really affected by stressful environments."},"HEAL":{"p":"/hiːl/","s":"n./v.","e":"[n.] A spell or ability that restores hit points or removes a status ailment.\n[n.] Health\n[v.] To make better from a disease, wound, etc.; to revive or cure.\n[v.] To become better or healthy again.\n[v.] To reconcile, as a breach or difference; to make whole; to free from guilt.","ex":"This bandage will heal your cut."},"HEARING":{"p":"/ˈhiːɹ.ɪŋ/","s":"v./n./adj.","e":"[v.] (stative) To perceive sounds through the ear.\n[v.] (stative) To perceive (a sound, or something producing a sound) with the ear, to recognize (something) in an auditory way.\n[v.] To exercise this faculty intentionally; to listen to.\n[n.] The sense used to perceive sound.\n[n.] The act by which something is heard.\n[n.] A proceeding at which discussions are heard.","ex":"I was deaf, and now I can hear."},"HEEL":{"p":"/hiːl/","s":"n./v.","e":"[n.] The rear part of the foot, where it joins the leg.\n[n.] The part of a shoe's sole which supports the foot's heel.\n[n.] The rear part of a sock or similar covering for the foot.\n[v.] To follow at somebody's heels; to chase closely.\n[v.] To add a heel to, or increase the size of the heel of (a shoe or boot).\n[v.] To kick with the heel.","ex":"She called to her dog to heel."},"HEAP":{"p":"/heːp/","s":"n./v./adv.","e":"[n.] A crowd; a throng; a multitude or great number of people.\n[n.] A pile or mass; a collection of things laid in a body, or thrown together so as to form an elevation.\n[n.] A great number or large quantity of things.\n[v.] To pile in a heap.\n[v.] To form or round into a heap, as in measuring.\n[v.] To supply in great quantity.","ex":"a heap of earth or stones"},"HEATH":{"p":"/hiːθ/","s":"n.","e":"[n.] A tract of level uncultivated land with sandy soil and scrubby vegetation; heathland.\n[n.] Any small evergreen shrub of the family Ericaceae.\n[n.] Certain butterflies and moths","ex":""},"HEAVEN":{"p":"/hɛvn/","s":"n./v.","e":"[n.] The sky, specifically:\n[n.] The abode of God or the gods, traditionally conceived as beyond the sky; especially:\n[n.] The afterlife of the blessed dead, traditionally conceived as opposed to an afterlife of the wicked and unjust (compare hell); specifically:\n[v.] To transport to the abode of God, the gods, or the blessed.\n[v.] To beatify, enchant, or please greatly.\n[v.] To beautify, to make into a paradise.","ex":""},"HEART":{"p":"/hɑːt/","s":"n./v.","e":"[n.] A muscular organ that pumps blood through the body, traditionally thought to be the seat of emotion.\n[n.] Emotions, kindness, moral effort, or spirit in general.\n[n.] The seat of the affections or sensibilities, collectively or separately, as love, hate, joy, grief, courage, etc.; rarely, the seat of the understanding or will; usually in a good sense; personality.\n[v.] To be fond of. Often bracketed or abbreviated with a heart symbol.\n[v.] To give heart to; to hearten; to encourage.\n[v.] To fill an interior with rubble, as a wall or a breakwater.","ex":"The team lost, but they showed a lot of heart."},"HEARD":{"p":"/hiːɹd/","s":"v./adj.","e":"[v.] (stative) To perceive sounds through the ear.\n[v.] (stative) To perceive (a sound, or something producing a sound) with the ear, to recognize (something) in an auditory way.\n[v.] To exercise this faculty intentionally; to listen to.\n[adj.] That has been heard or listened to; that has been aurally detected.","ex":"I was deaf, and now I can hear."},"HEAT":{"p":"/hit/","s":"n.","e":"[n.] Thermal energy.\n[n.] The condition or quality of being hot.\n[n.] An attribute of a spice that causes a burning sensation in the mouth.","ex":"This furnace puts out 5000 BTUs of heat.   That engine is really throwing off some heat.   Removal of heat from the liquid caused it to turn into a solid."},"HEAVE":{"p":"/hiːv/","s":"n./v.","e":"[n.] An effort to raise something, such as a weight or one's own body, or to move something heavy.\n[n.] An upward motion; a rising; a swell or distention, as of the breast in difficult breathing, of the waves, of the earth in an earthquake, etc.\n[n.] A horizontal dislocation in a metallic lode, taking place at an intersection with another lode.\n[v.] To lift with difficulty; to raise with some effort; to lift (a heavy thing).\n[v.] To throw, cast.\n[v.] To rise and fall.","ex":"We heaved the chest-of-drawers on to the second-floor landing."},"HEIGHT":{"p":"/haɪt/","s":"n.","e":"[n.] The distance from the base of something to the top.\n[n.] The vertical distance from the ground to the highest part of a standing person or animal (withers in the case of a horse).\n[n.] The highest point or maximum degree.","ex":"She's at the height of her career."},"HEDGE":{"p":"/hɛdʒ/","s":"n.","e":"[n.] A thicket of bushes or other shrubbery, especially one planted as a fence between two portions of land, or to separate the parts of a garden.\n[n.] A barrier (often consisting of a line of persons or objects) to protect someone or something from harm.\n[n.] A mound of earth, stone- or turf-faced, often topped with bushes, used as a fence between any two portions of land.","ex":"He trims the hedge once a week."},"HEAVY":{"p":"/ˈhe.vi/","s":"n./v./adj./adv.","e":"[n.] A villain or bad guy; the one responsible for evil or aggressive acts.\n[n.] A doorman, bouncer or bodyguard.\n[n.] A large multi-engined aircraft. (The term heavy normally follows the call-sign when used by air traffic controllers.)\n[v.] (often with \"up\") To make heavier.\n[v.] To sadden.\n[v.] To use power and/or wealth to exert influence on, e.g., governments or corporations; to pressure.","ex":"With his wrinkled, uneven face, the actor always seemed to play the heavy in films."},"HEFTY":{"p":"/ˈhɛfti/","s":"adj.","e":"[adj.] Heavy, strong, vigorous, mighty, impressive.\n[adj.] Strong; bulky.\n[adj.] (of a person) Possessing physical strength and weight; rugged and powerful; powerfully or heavily built.","ex":"He can throw a hefty punch."},"HENCE":{"p":"/ˈhɛns/","s":"adv.","e":"[adv.] From here, from this place, away\n[adv.] From the living or from this world\n[adv.] (of a length of time) in the future from now","ex":"Get thee hence, Satan!"},"HEIST":{"p":"/ˈhaɪst/","s":"n./v.","e":"[n.] A robbery or burglary, especially from an institution such as a bank or museum.\n[n.] A fiction genre in which a heist is central to the plot.\n[v.] To steal, rob or hold up (something).","ex":""},"HELD":{"p":"/ˈhɛld/","s":"v.","e":"[v.] To grasp or grip.\n[v.] To contain or store.\n[v.] (heading) To maintain or keep to a position or state.","ex":"Hold the pencil like this."},"HELLO":{"p":"/həˈləʊ/","s":"n./v./int.","e":"[n.] \"Hello!\" or an equivalent greeting.\n[v.] To greet with \"hello\".\n[int.] A greeting (salutation) said when meeting someone or acknowledging someone’s arrival or presence.\n[int.] A greeting used when answering the telephone.\n[int.] A call for response if it is not clear if anyone is present or listening, or if a telephone conversation may have been disconnected.","ex":"Hello, everyone."},"HELP":{"p":"/hɛlp/","s":"n.","e":"[n.] Action given to provide assistance; aid.\n[n.] (usually uncountable) Something or someone which provides assistance with a task.\n[n.] Documentation provided with computer software, etc. and accessed using the computer.","ex":"I need some help with my homework."},"HERSELF":{"p":"/hɜːˈsɛlf/","s":"pron.","e":"[pron.] (reflexive pronoun) Her; the female object of a verb or preposition that also appears as the subject.\n[pron.] She; an intensive repetition of the female subject, often used to indicate the exclusiveness of that person as the only satisfier of the predicate.\n[pron.] The subject or non-reflexive object of a predicate; she (used of upper-class ladies, or sarcastically, of women who imagine themselves to be more important than others)","ex":"She injured herself."},"HERE":{"p":"/hiːɹ/","s":"n./adj./adv./int.","e":"[n.] (abstract) This place; this location.\n[n.] (abstract) This time, the present situation.\n[adj.] Filler after a noun or demonstrative pronoun, solely for emphasis.\n[adj.] Filler after a demonstrative pronoun but before the noun it modifies, solely for emphasis.\n[adv.] (location) In, on, or at this place.\n[adv.] (location) To this place; used in place of the more dated hither.","ex":"An Alzheimer patient's here may in his mind be anywhere he called home in the time he presently re-lives."},"HILLY":{"p":"/ˈhɪli/","s":"adj.","e":"[adj.] (of a landscape) Abundant in hills; having many hills.","ex":""},"HERO":{"p":"/ˈhɛɹ.oʊ/","s":"n.","e":"[n.] Somebody who possesses great bravery and carries out extraordinary or noble deeds.\n[n.] A role model.\n[n.] The protagonist in a work of fiction.","ex":""},"HIDDEN":{"p":"/ˈhɪd(ə)n/","s":"adj./v.","e":"[adj.] Located or positioned out of sight; not visually apparent.\n[adj.] Obscure.\n[v.] To put (something) in a place where it will be harder to discover or out of sight.\n[v.] To put oneself in a place where one will be harder to find or out of sight.","ex":"hidden treasure; hidden talents"},"HINGE":{"p":"/ˈhɪndʒ/","s":"n./v.","e":"[n.] A jointed or flexible device that allows the pivoting of a door etc.\n[n.] A naturally occurring joint resembling such hardware in form or action, as in the shell of a bivalve.\n[n.] A stamp hinge, a folded and gummed paper rectangle for affixing postage stamps in an album.\n[v.] To attach by, or equip with a hinge.\n[v.] (with on or upon) To depend on something.\n[v.] The breaking off of the distal end of a knapped stone flake whose presumed course across the face of the stone core was truncated prematurely, leaving not a feathered distal end but instead the scar of a nearly perpendicular break.","ex":"The flake hinged at an inclusion in the core."},"HINT":{"p":"/hɪnt/","s":"n./v.","e":"[n.] A clue.\n[n.] A tacit suggestion that avoids a direct statement.\n[n.] A small, barely detectable amount of.\n[v.] To suggest tacitly without a direct statement; to provide a clue.\n[v.] To bring to mind by a slight mention or remote allusion; to suggest in an indirect manner.\n[v.] To develop and add hints to a font.","ex":"I needed a hint to complete the crossword."},"HIGHLY":{"p":"/ˈhaɪli/","s":"adv.","e":"[adv.] In a high or esteemed manner.\n[adv.] Extremely; greatly; very much.","ex":"He spoke highly of you."},"HIGHWAY":{"p":"/ˈhaɪweɪ/","s":"n.","e":"[n.] A motor vehicle for transporting large numbers of people along roads.\n[n.] An electrical conductor or interface serving as a common connection for two or more circuits or components.\n[n.] (medical industry) An ambulance.\n[n.] A main, direct public road, especially a multi-lane, high speed thoroughfare connecting major population centers.\n[n.] Any public road for vehicular traffic.","ex":""},"HIPPY":{"p":"/ˈhɪpi/","s":"n.","e":"[n.] (1950s slang) A teenager who imitated the beatniks.\n[n.] (1960s slang; still widely used in reference to that era) One who chooses not to conform to prevailing social norms: especially one who subscribes to values or actions such as acceptance or self-practice of recreational drug use, liberal or radical sexual mores, advocacy of communal living, strong pacifism or anti-war sentiment, etc.\n[n.] (modern slang) A person who keeps an unkempt or sloppy appearance and wearing unusually long hair (for males), and because of it, often stereotyped as a deadbeat.","ex":""},"HIPPO":{"p":"/ˈhɪpəʊ/","s":"n.","e":"[n.] A large, semi-aquatic, herbivorous (plant-eating) African mammal (Hippopotamus amphibius)","ex":""},"HOARD":{"p":"/hɔːd/","s":"n./v.","e":"[n.] A hidden supply or fund.\n[n.] A cache of valuable objects or artefacts; a trove.\n[v.] To amass, usually for one's own private collection.","ex":"a hoard of provisions; a hoard of money"},"HOLD":{"p":"/həʊld/","s":"n./v.","e":"[n.] A grasp or grip.\n[n.] An act or instance of holding.\n[n.] A place where animals are held for safety\n[v.] To grasp or grip.\n[v.] To contain or store.\n[v.] (heading) To maintain or keep to a position or state.","ex":"Keep a firm hold on the handlebars."},"HOBBY":{"p":"/ˈhɒ.bi/","s":"n.","e":"[n.] An activity that one enjoys doing in one's spare time.\n[n.] An extinct breed of horse native to the British Isles, also known as the Irish Hobby","ex":"I like to collect stamps from different countries as a hobby."},"HOIST":{"p":"/hɔɪst/","s":"n./v.","e":"[n.] A hoisting device, such as pulley or crane.\n[n.] The act of hoisting; a lift.\n[n.] The perpendicular height of a flag, as opposed to the fly, or horizontal length, when flying from a staff.\n[v.] To raise; to lift; to elevate (especially, to raise or lift to a desired elevation, by means of tackle or pulley, said of a sail, a flag, a heavy package or weight).\n[v.] To lift a trophy or similar prize into the air in celebration of a victory.\n[v.] To lift someone up to be flogged.","ex":"Give me a hoist over that wall."},"HITCH":{"p":"/hɪtʃ/","s":"n./v.","e":"[n.] A sudden pull.\n[n.] Any of various knots used to attach a rope to an object other than another rope.\n[n.] A fastener or connection point, as for a trailer.\n[v.] To pull with a jerk.\n[v.] To attach, tie or fasten.\n[v.] To marry oneself to; especially to get hitched.","ex":"His truck sported a heavy-duty hitch for his boat."},"HERON":{"p":"/ˈhɛɹən/","s":"n.","e":"[n.] A long-legged, long-necked wading bird of the family Ardeidae.","ex":""},"HISTORY":{"p":"/ˈhɪst(ə)ɹi/","s":"n./v.","e":"[n.] The aggregate of past events.\n[n.] The branch of knowledge that studies the past; the assessment of notable events.\n[n.] A set of events involving an entity.\n[v.] To narrate or record.","ex":"History repeats itself if we don’t learn from its mistakes."},"HOLDER":{"p":"/ˈhəʊldə/","s":"n.","e":"[n.] A thing that holds.\n[n.] A person who temporarily or permanently possesses something.\n[n.] One who is employed in the hold of a vessel.","ex":"Put your umbrella in the umbrella holder."},"HOMER":{"p":"/ˈhəʊmə/","s":"n.","e":"[n.] Various former units of volume, particularly:\n[n.] A former Hebrew unit of dry volume, about equal to 230 L or 6 1/2 US bushels.","ex":""},"HOLLY":{"p":"/ˈhɒli/","s":"n.","e":"[n.] Any of various shrubs or (mostly) small trees, of the genus Ilex, either evergreen or deciduous, used as decoration especially at Christmas.\n[n.] The wood from this tree.\n[n.] (with a qualifier) Any of several unrelated plant species likened to Ilex because of their prickly, evergreen foliage and/or round, bright-red berries","ex":""},"HOLY":{"p":"/ˈhəʊli/","s":"n./adj.","e":"[n.] A thing that is extremely holy; used almost exclusively in Holy of Holies.\n[adj.] Dedicated to a religious purpose or a god.\n[adj.] Revered in a religion.\n[adj.] Morally perfect or flawless, or nearly so.","ex":"I'm planning to visit the holy city of Jerusalem this Christmas."},"HOME":{"p":"/(h)əʊm/","s":"n./v./adj./adv.","e":"[n.] A dwelling.\n[n.] One’s native land; the place or country in which one dwells; the place where one’s ancestors dwell or dwelt.\n[n.] The locality where a thing is usually found, or was first found, or where it is naturally abundant; habitat; seat.\n[v.] (of animals) To return to its owner.\n[v.] (always with \"in on\") To seek or aim for something.\n[adj.] Of or pertaining to one’s dwelling or country; domestic; not foreign; as home manufactures; home comforts.","ex":"the home of the pine"},"HONEST":{"p":"/ˈɒnɪst/","s":"v./adj./adv.","e":"[v.] To adorn or grace; to honour; to make becoming, appropriate, or honourable.\n[adj.] (of a person or institution) Scrupulous with regard to telling the truth; not given to swindling, lying, or fraud; upright.\n[adj.] (of a statement) True, especially as far as is known by the person making the statement; fair; unbiased.\n[adj.] In good faith; without malice.\n[adv.] Honestly; really.","ex":"We’re the most honest people you will ever come across."},"HONEY":{"p":"/ˈhʌni/","s":"n./v./adj.","e":"[n.] A viscous, sweet fluid produced from plant nectar by bees. Often used to sweeten tea or to spread on baked goods.\n[n.] A variety of this substance.\n[n.] Nectar.\n[v.] To sweeten; to make agreeable.\n[v.] To be gentle, agreeable, or coaxing; to talk fondly; to use endearments.\n[v.] To be or become obsequiously courteous or complimentary; to fawn.","ex":""},"HOPE":{"p":"/həʊp/","s":"v.","e":"[v.] To want something to happen, with a sense of expectation that it might.\n[v.] To be optimistic; be full of hope; have hopes.\n[v.] To place confidence; to trust with confident expectation of good; usually followed by in.","ex":"I am still hoping that all will turn out well."},"HONORED":{"p":"","s":"v./adj.","e":"[v.] To think of highly, to respect highly; to show respect for; to recognise the importance or spiritual value of\n[v.] To conform to, abide by, act in accordance with (an agreement, treaty, promise, request, or the like)\n[v.] To confer (bestow) an honour or privilege upon (someone)\n[adj.] Respected, having received honour.","ex":"The freedom fighters will be forever remembered and honored by the people."},"HORDE":{"p":"/hɔːd/","s":"n./v.","e":"[n.] A wandering troop or gang; especially, a clan or tribe of a nomadic people (originally Tatars) migrating from place to place for the sake of pasturage, plunder, etc.; a predatory multitude.\n[n.] A large number of people.\n[v.] To travel en masse, to flock","ex":"We were beset by a horde of street vendors who thought we were tourists and would buy their cheap souvenirs."},"HORIZON":{"p":"/həˈɹaɪzən/","s":"n.","e":"[n.] The visible horizontal line or point (in all directions) that appears to connect the Earth to the sky.\n[n.] The range or limit of one's knowledge, experience or interest; a boundary or threshold.\n[n.] The range or limit of any dimension in which one exists.","ex":"A tall building was visible on the horizon."},"HOSTING":{"p":"/ˈhəʊstɪŋ/","s":"v./n.","e":"[v.] To perform the role of a host.\n[v.] To lodge at an inn.\n[v.] To run software made available to a remote user or process.\n[n.] Running and maintaining a computer system on someone's behalf.\n[n.] A battle.","ex":"I was terrible at hosting that show."},"HOST":{"p":"/həʊst/","s":"n./v.","e":"[n.] One which receives or entertains a guest, socially, commercially, or officially.\n[n.] One that provides a facility for an event.\n[n.] A person or organization responsible for running an event.\n[v.] To perform the role of a host.\n[v.] To lodge at an inn.\n[v.] To run software made available to a remote user or process.","ex":"A good host is always considerate of the guest’s needs."},"HOUND":{"p":"/haʊnd/","s":"n.","e":"[n.] A dog, particularly a breed with a good sense of smell developed for hunting other animals.\n[n.] Any canine animal.\n[n.] (by extension) Someone who seeks something.","ex":""},"HOUSING":{"p":"/ˈhaʊzɪŋ/","s":"v.","e":"[v.] To keep within a structure or container.\n[v.] To admit to residence; to harbor/harbour.\n[v.] To take shelter or lodging; to abide; to lodge.","ex":"The car is housed in the garage."},"HUNG":{"p":"/ˈhʌŋ/","s":"v./adj.","e":"[v.] To be or remain suspended.\n[v.] To float, as if suspended.\n[v.] (of a ball in cricket, tennis, etc.) To rebound unexpectedly or unusually slowly, due to backward spin on the ball or imperfections of the ground.\n[adj.] Suspended by hanging.\n[adj.] Having hanging additions or appendages.\n[adj.] Of a jury, unable to reach a unanimous verdict in a trial.","ex":"The lights hung from the ceiling."},"HUMAN":{"p":"/ˈhjuː.mən/","s":"n./v./adj.","e":"[n.] A human being, whether man, woman or child.\n[v.] To behave as or become, or to cause to behave as or become, a human.\n[adj.] (notcomp) Of or belonging to the species Homo sapiens or its closest relatives.\n[adj.] Having the nature or attributes of a human being.","ex":"Humans share common ancestors with other apes."},"HUMID":{"p":"/ˈhjuːmɪd/","s":"adj.","e":"[adj.] Containing perceptible moisture (usually describing air or atmosphere); damp; moist; somewhat wet or watery.","ex":"humid earth"},"HUSSY":{"p":"/ˈhʌsi/","s":"n.","e":"[n.] A housewife or housekeeper.\n[n.] A sexually immoral woman.\n[n.] A cheeky or disrespectful girl; a woman showing inappropriate or improper behavior.","ex":""},"HUMOR":{"p":"/hjuː.mə(ɹ)/","s":"n./v.","e":"[n.] The quality of being amusing, comical, funny.\n[n.] A mood, especially a bad mood; a temporary state of mind or disposition brought upon by an event; an abrupt illogical inclination or whim.\n[n.] Any of the fluids in an animal body, especially the four \"cardinal humours\" of blood, yellow bile, black bile and phlegm that were believed to control the health and mood of the human body.\n[v.] To pacify by indulging.","ex":"She has a great sense of humour, and I always laugh a lot whenever we get together."},"HYDRO":{"p":"","s":"n./adj.","e":"[n.] Hydroelectric power\n[n.] Electrical power supply; specifically, electrical power provided by a utility (as a publicly-owned one); payment or bills for this.\n[n.] A spa.\n[adj.] Hydroelectric\n[adj.] Hydroponic\n[n.] A floatplane, an airplane specialized for operating on water, having pontoon floats instead of skids or wheels","ex":"He crashed his car against a hydro pole."},"HUMUS":{"p":"/ˈhjuːməs/","s":"n.","e":"[n.] A large group of natural organic compounds, found in the soil, formed from the chemical and biological decomposition of plant and animal residues and from the synthetic activity of microorganisms","ex":""},"HUNKY":{"p":"/ˈhʌŋki/","s":"adj.","e":"[adj.] Exhibiting strong, masculine beauty.\n[adj.] Shaped like a hunk, or piece; chunky.\n[adj.] All right; in good condition.","ex":""},"HUNCH":{"p":"/hʌntʃ/","s":"n./v.","e":"[n.] A hump; a protuberance.\n[n.] A stooped or curled posture; a slouch.\n[n.] A theory, idea, or guess; an intuitive impression that something will happen.\n[v.] To bend the top of one's body forward while raising one's shoulders.\n[v.] To raise (one's shoulders) (while lowering one's head or bending the top of one's body forward); to curve (one's body) forward (sometimes followed by up).\n[v.] To walk (somewhere) while hunching one's shoulders.","ex":"The old man walked with a hunch."},"ICING":{"p":"/ˈaɪsɪŋ/","s":"n.","e":"[n.] A sweet glaze made primarily of sugar and often flavored, typically used for baked goods; frosting.\n[n.] A minor violation of ice hockey rules, occurring when a player shoots the puck from his/her side of the red line so that it crosses the goal line on the opponent's side. A team playing short-handed is not penalized for this.\n[n.] The process of forming a layer of ice on a surface.","ex":""},"IDLER":{"p":"","s":"n.","e":"[n.] One who idles; one who spends his or her time in inaction.\n[n.] One who idles; a lazy person; a sluggard.\n[n.] Any member of a ship's crew who is not required to keep the night-watch","ex":""},"ILLNESS":{"p":"/ˈɪl.nəs/","s":"n.","e":"[n.] An instance of a disease or poor health.\n[n.] A state of bad health or disease.","ex":"Her grandmother had passed away after a long illness."},"INCH":{"p":"/ɪntʃ/","s":"n./v.","e":"[n.] A unit of length equal to one twelfth of a foot, or exactly 2.54 centimetres.\n[n.] The amount of water which would cover a surface to the depth of an inch, used as a measurement of rainfall.\n[n.] The amount of an alcoholic beverage which would fill a glass or bottle to the depth of an inch.\n[v.] (followed by a preposition) To advance very slowly, or by a small amount (in a particular direction).\n[v.] To drive by inches, or small degrees.\n[v.] To deal out by inches; to give sparingly.","ex":"Fearful of falling, he inched along the window ledge."},"LOST":{"p":"/lɒst/","s":"v./adj.","e":"[v.] To cause (something) to cease to be in one's possession or capability due to unfortunate or unknown circumstances, events or reasons.\n[v.] To wander from; to miss, so as not to be able to find; to go astray from.\n[v.] To fail to win (a game, competition, trial, etc).\n[adj.] Having wandered from, or unable to find, the way.\n[adj.] In an unknown location; unable to be found.\n[adj.] Not perceptible to the senses; no longer visible.","ex":"He lost his hearing in the explosion."},"LOWER":{"p":"/ˈləʊə/","s":"adj./adv./v.","e":"[adj.] Situated close to, or even below, the ground or another normal reference plane; not high or lofty.\n[adj.] Of less than normal height; below the average or normal level from which elevation is measured.\n[adj.] Not high in status, esteem or rank, dignity, or quality. (Compare vulgar.)\n[adv.] Close to the ground.\n[adv.] Of a pitch, at a lower frequency.\n[adv.] With a low voice or sound; not loudly; gently.","ex":"a low wall  a low shelf"},"LUMPY":{"p":"","s":"adj.","e":"[adj.] Full of lumps, not smooth.\n[adj.] Of a water surface: covered in many small waves as a result of wind; choppy.","ex":"I don't know which was worse, the lumpy soup or the lumpy bed."},"LUNAR":{"p":"/ˈl(j)uːnə/","s":"n./adj.","e":"[n.] The middle bone of the proximal series of the carpus in the wrist, which is shaped like a half-moon.\n[n.] An observation of a lunar distance, especially for establishing the longitude of a ship at sea.\n[adj.] Of, pertaining to, or resembling the Moon (that is, Luna, the Earth's moon); Lunar.\n[adj.] Shaped like a crescent moon; lunate.\n[adj.] (Believed to be) influenced by the Moon, as in character, growth, or properties.","ex":"lunar observations  a lunar eclipse"},"LURID":{"p":"/ˈl(j)ʊə.ɹɪd/","s":"adj.","e":"[adj.] Shocking, horrifying.\n[adj.] Melodramatic.\n[adj.] Ghastly, pale, wan in appearance.","ex":"The accident was described with lurid detail."},"LUPUS":{"p":"/ˈluːpəs/","s":"n.","e":"[n.] Any of a number of autoimmune diseases, the most common of which is systemic lupus erythematosus.","ex":""},"MAFIA":{"p":"/ˈmæfi.ə/","s":"n.","e":"[n.] A hierarchically structured secret organisation engaged in illegal activities like distribution of narcotics, gambling and extortion.\n[n.] A crime syndicate.\n[n.] A trusted group of associates, as of a political leader.","ex":""},"MADE":{"p":"/meɪd/","s":"n.","e":"[n.] A grub or maggot.","ex":""},"MAJOR":{"p":"/ˈmeɪ.dʒə(ɹ)/","s":"n.","e":"[n.] A military rank between captain and lieutenant colonel.","ex":"He used to be a major in the army."},"MAGMA":{"p":"/ˈmæɡ.mə/","s":"n.","e":"[n.] The molten matter within the earth, the source of the material of lava flows, dikes of eruptive rocks, etc.\n[n.] A basic algebraic structure consisting of a set equipped with a single binary operation.\n[n.] Any soft doughy mass.","ex":""},"MAIN":{"p":"/meɪn/","s":"v./adj./adv.","e":"[v.] Short for mainline.\n[v.] To mainly play a specific character, or side, during a game.\n[v.] Of a road: to convert into a main or primary road.\n[adj.] Of chief or leading importance; prime, principal.\n[adj.] Chief, most important, or principal in extent, size, or strength; consisting of the largest part.\n[adj.] (of force, strength, etc.) Full, sheer, undivided.","ex":"He mains the same character as me in that game."},"MAMMY":{"p":"","s":"n.","e":"[n.] Mamma; mother\n[n.] (historical, often pejorative) In the southern United States, a black nanny employed to look after white children; or in the antebellum South, a female slave who was close to the household and looked after the children.","ex":""},"MAMBA":{"p":"","s":"n.","e":"[n.] Any of various venomous snakes of the genus Dendroaspis, native to Africa, that live in trees.","ex":""},"MANAGE":{"p":"/ˈmænɪdʒ/","s":"n./v.","e":"[n.] The act of managing or controlling something.\n[n.] (horseriding) Manège.\n[v.] To direct or be in charge of.\n[v.] To handle or control (a situation, job).\n[v.] To handle with skill, wield (a tool, weapon etc.).","ex":""},"MAMMA":{"p":"/ˈmæmə/","s":"n.","e":"[n.] The milk-secreting organ of female humans and other mammals which includes the mammary gland and the nipple or teat; a breast; an udder. (plural: mammae)\n[n.] An accessory cloud like a mammary in appearance, which can form on the underside of most cloud genera","ex":""},"MANGY":{"p":"/ˈmeɪndʒi/","s":"adj.","e":"[adj.] Afflicted with mange.\n[adj.] (by extension) Worn and squalid-looking; bedraggled or decrepit.","ex":"We stayed in a really mangy hotel in New York."},"MANAGED":{"p":"/ˈmænɪdʒd/","s":"v.","e":"[v.] To direct or be in charge of.\n[v.] To handle or control (a situation, job).\n[v.] To handle with skill, wield (a tool, weapon etc.).","ex":""},"MAMBO":{"p":"/ˈmæmbəʊ/","s":"n./v.","e":"[n.] A voodoo priestess (in Haiti)\n[n.] A Latin-American musical genre, adapted from rumba, originating from Cuba in the 1940s, or a dance or rhythm of this genre.\n[v.] To perform this dance.","ex":""},"MANIA":{"p":"/ˈmeɪ.ni.ə/","s":"n.","e":"[n.] Violent derangement of mind; madness; insanity.\n[n.] Excessive or unreasonable desire; insane passion affecting one or many people; fanaticism.\n[n.] The state of abnormally elevated or irritable mood, arousal, and/or energy levels.","ex":""},"MANIC":{"p":"/ˈmænɪk/","s":"adj.","e":"[adj.] Of or pertaining to someone who exhibits mania or craziness; wicked.\n[adj.] Suffering from mania, the state of an abnormally elevated or irritable mood, arousal, and/or energy levels.","ex":""},"MANLY":{"p":"/ˈmænli/","s":"adj.","e":"[adj.] Having the characteristics of a man.\n[adj.] Having qualities befitting a man; courageous, resolute, noble.","ex":""},"MANGA":{"p":"/ˈmæŋɡə/","s":"n.","e":"[n.] A comic originating in Japan.\n[n.] An artistic style heavily used in, and associated with, Japanese comics, and that has also been adopted by a comparatively low number of comics from other countries.\n[n.] A comic in manga style, regardless of the country of origin.","ex":"Lately I've been reading a Brazilian manga."},"MARSH":{"p":"/mɑː(ɹ)ʃ/","s":"n.","e":"[n.] An area of low, wet land, often with tall grass.","ex":""},"MAPLE":{"p":"/ˈmeɪpl̩/","s":"n.","e":"[n.] A tree of the Acer genus, characterised by its usually palmate leaves and winged seeds.\n[n.] The wood of such a tree, prized for its hardness and attractive appearance","ex":""},"MARRY":{"p":"/ˈmæɹɪ/","s":"v.","e":"[v.] To enter into the conjugal or connubial state; to take a husband or a wife.\n[v.] (in passive) To be joined to (someone) as spouse according to law or custom.\n[v.] To arrange for the marriage of; to give away as wife or husband.","ex":"Neither of her daughters showed any desire to marry."},"MARKET":{"p":"/ˈmɑːkɪt/","s":"n./v.","e":"[n.] A gathering of people for the purchase and sale of merchandise at a set time, often periodic.\n[n.] City square or other fairly spacious site where traders set up stalls and buyers browse the merchandise.\n[n.] A grocery store\n[v.] To make (products or services) available for sale and promote them.\n[v.] To sell\n[v.] To deal in a market; to buy or sell; to make bargains for provisions or goods.","ex":"The privilege to hold a weekly market was invaluable for any feudal era burgh."},"MANGO":{"p":"/ˈmæŋɡəʊ/","s":"n./v.","e":"[n.] A tropical Asian fruit tree, Mangifera indica.\n[n.] The fruit of the mango tree.\n[n.] A pickled vegetable or fruit with a spicy stuffing; a vegetable or fruit which has been mangoed.\n[v.] To stuff and pickle (a fruit).","ex":""},"MASON":{"p":"/ˈmeɪsən/","s":"n./v.","e":"[n.] A bricklayer, one whose occupation is to build with stone or brick\n[n.] One who prepares stone for building purposes.\n[n.] A member of the fraternity of Freemasons. See Freemason.\n[v.] (normally with a preposition) To build stonework or brickwork about, under, in, over, etc.; to construct by masons","ex":"to mason in a kettle or boiler"},"MASTER":{"p":"/ˈmastə/","s":"n./v./adj.","e":"[n.] Someone who has control over something or someone.\n[n.] The owner of an animal or slave.\n[n.] The captain of a merchant ship; a master mariner.\n[v.] To be a master.\n[v.] To become the master of; to subject to one's will, control, or authority; to conquer; to overpower; to subdue.\n[v.] To learn to a high degree of proficiency.","ex":"It took her years to master the art of needlecraft."},"MAUVE":{"p":"/məʊv/","s":"n./adj.","e":"[n.] A bright purple synthetic dye.\n[n.] The colour of this dye; a pale purple or violet colour.\n[adj.] Having a pale purple colour.","ex":""},"MATCH":{"p":"/mæt͡ʃ/","s":"n./v.","e":"[n.] A competitive sporting event such as a boxing meet, a baseball game, or a cricket match.\n[n.] Any contest or trial of strength or skill, or to determine superiority.\n[n.] Someone with a measure of an attribute equaling or exceeding the object of comparison.\n[v.] To agree; to be equal; to correspond.\n[v.] To agree with; to be equal to; to correspond to.\n[v.] To make a successful match or pairing.","ex":"My local team are playing in a match against their arch-rivals today."},"MATTE":{"p":"/mæt/","s":"n./adj.","e":"[n.] A decorative border around a picture used to inset and center the contents of a frame.\n[n.] A background, often painted or created with computers\n[n.] (pyrometallurgy) The molten metal sulfide phases typically formed during smelting of copper, nickel, and other base metals.\n[adj.] Dull; not reflective of light.","ex":"The image is a perfect square of 8 cm (with white matte border the total dimensions are 14 cm tall by 11 cm wide)."},"MAYS":{"p":"","s":"v./n.","e":"[v.] To gather may, or flowers in general.\n[v.] To celebrate May Day.\n[n.] A maiden.","ex":""},"MEAL":{"p":"/miːl/","s":"n.","e":"[n.] Food that is prepared and eaten, usually at a specific time, and usually in a comparatively large quantity (as opposed to a snack).\n[n.] Food served or eaten as a repast.\n[n.] A time or an occasion.","ex":"Breakfast is the morning meal, lunch is the noon meal, and dinner, or supper, is the evening meal."},"MEANT":{"p":"/ˈmɛnt/","s":"v.","e":"[v.] To intend.\n[v.] To convey (a meaning).\n[v.] To have conviction in (something said or expressed); to be sincere in (what one says).","ex":"Does she really mean what she said to him last night?"},"MAXIMUM":{"p":"/ˈmæksɪməm/","s":"n./adj.","e":"[n.] The highest limit\n[n.] The greatest value of a set or other mathematical structure, especially the global maximum or a local maximum of a function\n[n.] An upper bound of a set which is also an element of that set\n[adj.] To the highest degree.","ex":"Use the proper dose for the maximum effect."},"MAYBE":{"p":"/ˈmeɪbi/","s":"n./adj./adv.","e":"[n.] Something that is possibly true.\n[n.] An answer that shows neither agreement nor disagreement.\n[n.] A future event that may or may not happen.\n[adj.] Possible; uncertain.\n[adv.] Modifies a verb, indicating a lack of certainty: it may be that...\n[adv.] (as a pro-sentence) Perhaps that is true (expressing no commitment to a decision or a neutral viewpoint to a statement).","ex":"The results of the poll were inconclusive. We got two yeses, three nos, and four maybes."},"MAVEN":{"p":"/ˈmeɪvən/","s":"n.","e":"[n.] An expert in a given field.","ex":""},"MEASURE":{"p":"/ˈmɛʒə/","s":"n./v.","e":"[n.] A prescribed quantity or extent.\n[n.] The act or result of measuring.\n[n.] Metrical rhythm.\n[v.] To ascertain the quantity of a unit of material via calculated comparison with respect to a standard.\n[v.] To be of (a certain size), to have (a certain measurement)\n[v.] To estimate the unit size of something.","ex":"We measured the temperature with a thermometer.   You should measure the angle with a spirit level."},"MEALY":{"p":"/miːli/","s":"adj.","e":"[adj.] Resembling meal (the foodstuff).","ex":""},"MEAN":{"p":"/miːn/","s":"v.","e":"[v.] To lament.\n[v.] To intend.\n[v.] To convey (a meaning).\n[v.] To have conviction in (something said or expressed); to be sincere in (what one says).","ex":"Does she really mean what she said to him last night?"},"MEANING":{"p":"/ˈmiːnɪŋ/","s":"n.","e":"[n.] (of words or symbols) The entity, perception, feeling or concept thereby represented or evoked.\n[n.] The value, purpose, importance, point or significance (of something beyond the fact of that thing's existence).\n[n.] The object or concept that a word or phrase denotes, or that which a sentence says.","ex":"the meaning of life"},"MEATY":{"p":"/ˈmiːti/","s":"adj.","e":"[adj.] Of, relating to, or containing meat.\n[adj.] Resembling meat in flavour, etc.\n[adj.] Of a person or a body part, large and solid.","ex":"This tastes rather meaty. Are you sure it's vegetarian?"},"MEAT":{"p":"/miːt/","s":"n.","e":"[n.] The flesh (muscle tissue) of an animal used as food.\n[n.] A type of meat, by anatomic position and provenance.\n[n.] Food, for animals or humans, especially solid food. See also meat and drink.","ex":"A large portion of domestic meat production comes from animals raised on factory farms."},"MEDIUM":{"p":"/ˈmiːdɪəm/","s":"n./adj./adv.","e":"[n.] (plural media or mediums) The chemistry of the surrounding environment, e.g. solid, liquid, gas, vacuum, or a specific substance such as a solvent.\n[n.] (plural media or mediums) The materials or empty space through which signals, waves or forces pass.\n[n.] (plural media or mediums) A format for communicating or presenting information.\n[adj.] Arithmetically average.\n[adj.] Of intermediate size, degree, amount etc.\n[adj.] Of meat, cooked to a point greater than rare but less than well done; typically, so the meat is still red in the centre.","ex":""},"MEDIA":{"p":"/ˈmiːdɪə/","s":"n.","e":"[n.] The middle layer of the wall of a blood vessel or lymph vessel which is composed of connective and muscular tissue.\n[n.] A voiced stop consonant.\n[n.] One of the major veins of the insect wing, between the radius and the cubitus","ex":""},"MEDIC":{"p":"","s":"n./adj.","e":"[n.] A doctor.\n[n.] A paramedic, someone with special training in first aid, especially in the military.\n[n.] A medical student.\n[adj.] Of or pertaining to medicines; medical.","ex":""},"MEDAL":{"p":"[ˈmeɾ.ɫ̩]","s":"n./v.","e":"[n.] A stamped metal disc used as a personal ornament, a charm, or a religious object.\n[n.] A stamped or cast metal object (usually a disc), particularly one awarded as a prize or reward.\n[v.] To win a medal.\n[v.] To award a medal to.","ex":"He medalled twice at the Olympics."},"MEET":{"p":"/miːt/","s":"n./v.","e":"[n.] A sports competition, especially for track and field (a track meet) or swimming (a swim meet).\n[n.] A gathering of riders, horses and hounds for foxhunting; a field meet for hunting.\n[n.] A meeting of two trains in opposite directions on a single track, when one is put into a siding to let the other cross.\n[v.] To make contact (with) while in proximity.\n[v.] (Of groups) To come together.\n[v.] To make physical or perceptual contact.","ex":""},"MENTAL":{"p":"/ˈmɛntəl/","s":"adj.","e":"[adj.] Of or relating to the mind or an intellectual process.\n[adj.] Insane, mad, crazy.\n[adj.] Enjoyable or fun, especially in a frenetic way.","ex":"He is the most mental freshman I've seen yet."},"MEETING":{"p":"/ˈmiːtɪŋ/","s":"n.","e":"[n.] (gerund) The act of persons or things that meet.\n[n.] A gathering of persons for a purpose; an assembly.\n[n.] (collective) The people at such a gathering.","ex":"Meeting him will be exciting. I enjoy meeting new people."},"MELEE":{"p":"/ˈmɛ.li/","s":"n./v.","e":"[n.] A battle fought at close range; hand-to-hand combat; brawling.\n[n.] A noisy, confused or tumultuous fight, argument or scrap.\n[n.] Any any confused, disorganised, disordered or chaotic situation.\n[v.] To physically hit in close quarters, as opposed to shooting, blowing up, or other ranged means of damage. Often refers to the usage of a hand-to-hand weapon.","ex":""},"MENTION":{"p":"/ˈmɛnʃən/","s":"n./v.","e":"[n.] A speaking or notice of anything, usually in a brief or cursory manner. Used especially in the phrase make mention of.\n[n.] A social media feed, a list of replies or posts mentioning a person.\n[v.] To make a short reference to something.\n[v.] To utter a word or expression in order to refer to the expression itself, as opposed to its usual referent.","ex":""},"MENU":{"p":"/ˈmɛnju/","s":"n.","e":"[n.] The details of the food to be served at a banquet; a bill of fare.\n[n.] A list of dishes offered in a restaurant.\n[n.] A list from which the user may select an operation to be performed, often done with a keyboard, mouse, or controller under a graphical user interface","ex":""},"MELON":{"p":"/ˈmɛlən/","s":"n./adj.","e":"[n.] Any of various plants of the family Cucurbitaceae grown for food, generally not including the cucumber.\n[n.] The fruit of such plants.\n[n.] A light pinkish orange colour, like that of some melon flesh.\n[adj.] Of a light pinkish orange colour, like that of melon flesh.","ex":""},"MERCY":{"p":"/ˈmɜːsi/","s":"n./v./int.","e":"[n.] Relenting; forbearance to cause or allow harm to another.\n[n.] Forgiveness or compassion, especially toward those less fortunate.\n[n.] A tendency toward forgiveness, pity, or compassion.\n[v.] To feel mercy\n[v.] To show mercy; to pardon or treat leniently because of mercy\n[int.] Expressing surprise or alarm.","ex":"She took mercy on him and quit embarrassing him."},"MERELY":{"p":"/ˈmɪəli/","s":"adv.","e":"[adv.] Wholly, entirely.\n[adv.] (focus) Without any other reason etc.; only, just, and nothing more.","ex":""},"MEDICAL":{"p":"/ˈmɛdɪkl̩/","s":"n./adj.","e":"[n.] A medical examination.\n[adj.] Of or pertaining to the practice of medicine.\n[adj.] Intended to have a therapeutic effect; medicinal.\n[adj.] Requiring medical treatment.","ex":"You'll have to get a medical before you apply for that job."},"MERGE":{"p":"/mɜːdʒ/","s":"n./v.","e":"[n.] The joining together of multiple sources.\n[v.] To combine into a whole.\n[v.] To blend gradually into something else.","ex":"The merge of the two documents failed."},"MERIT":{"p":"/ˈmɛɹət/","s":"n./v.","e":"[n.] A claim to commendation or a reward.\n[n.] A mark or token of approbation or to recognize excellence.\n[n.] Something deserving or worthy of positive recognition or reward.\n[v.] To deserve, to earn.\n[v.] To be deserving or worthy.\n[v.] To reward.","ex":"For her good performance in the examination, her teacher gave her ten merits."},"MERGER":{"p":"/ˈmɜːdʒə/","s":"n.","e":"[n.] One that merges.","ex":""},"MICRO":{"p":"/ˈmaɪ.kɹoʊ/","s":"n./v./adj.","e":"[n.] (gaming slang) micromanagement\n[v.] (gaming slang) to micromanage\n[adj.] Small, relatively small; used to contrast levels of the noun modified.\n[n.] A computer designed around a microprocessor, smaller than a minicomputer or a mainframe.\n[n.] The field of economics that deals with small-scale economic activities such as those of an individual or company.","ex":"At the micro level he was a good manager. At the macro level he failed."},"METER":{"p":"/ˈmiːtə/","s":"n./v.","e":"[n.] (always meter) A device that measures things.\n[n.] (always meter) A parking meter or similar device for collecting payment.\n[n.] (always meter) One who metes or measures.\n[v.] To measure with a metering device.\n[v.] To imprint a postage mark with a postage meter.\n[v.] To regulate the flow of or to deliver in regulated amounts (usually of fluids but sometimes of other things such as anticipation or breath).","ex":"a labouring coal-meter"},"METAL":{"p":"/ˈmɛtəl/","s":"n./v./adj.","e":"[n.] (heading) Chemical elements or alloys, and the mines where their ores come from.\n[n.] A light tincture used in a coat of arms, specifically argent and or.\n[n.] Molten glass that is to be blown or moulded to form objects.\n[v.] To make a road using crushed rock, stones etc.\n[adj.] Characterized by strong drum-beats and distorted guitars.\n[adj.] Having the emotional or social characteristics associated with metal music; brash, bold, frank, unyielding, etc.","ex":""},"MERE":{"p":"","s":"n.","e":"[n.] A body of standing water, such as a lake or a pond. More specifically, it can refer to a lake that is broad in relation to its depth. Also included in place names such as Windermere.","ex":""},"MIDDLE":{"p":"/ˈmɪdəl/","s":"n./v./adj.","e":"[n.] A centre, midpoint.\n[n.] The part between the beginning and the end.\n[n.] The middle stump.\n[v.] To take a middle view of.\n[v.] To double (a rope) into two equal portions; to fold in the middle.\n[adj.] Located in the middle; in between.","ex":"The middle of a circle is the point which has the same distance to every point of circle."},"MIDGE":{"p":"/mɪdʒ/","s":"n.","e":"[n.] Any of various small two-winged flies, for example, from the family Chironomidae or non-biting midges, the family Chaoboridae or phantom midges, and the family Ceratopogonidae or biting midges, all belonging to the order Diptera\n[n.] Any bait or lure designed to resemble a midge","ex":""},"MILKY":{"p":"/ˈmɪlki/","s":"adj.","e":"[adj.] Resembling milk in color, consistency, smell, etc.; consisting of milk.\n[adj.] (color science) Of the black in an image, appearing as dark gray rather than black.\n[adj.] (of a drink) Containing (an especially large amount of) milk.","ex":"milky tea; milky cocoa"},"METRO":{"p":"/ˈmɛtɹəʊ/","s":"n.","e":"[n.] An underground railway.\n[n.] A train that runs on such an underground railway.\n[n.] An urban rapid transit light railway","ex":""},"MIGHTY":{"p":"/ˈmaɪti/","s":"n./adj./adv.","e":"[n.] A warrior of great strength and courage.\n[adj.] Very strong; possessing might.\n[adj.] Very heavy and powerful.\n[adj.] Very large; hefty.\n[adv.] Very; to a high degree.","ex":"He's a mighty wrestler, but you are faster than him."},"MIKE":{"p":"/ˈmaɪk/","s":"n./v.","e":"[n.] A microphone.\n[v.] To microphone; to place one or more microphones (mikes) on.\n[v.] To measure using a micrometer.","ex":""},"MIDST":{"p":"/mɪdst/","s":"n./prep.","e":"[n.] A place in the middle of something; may be used of a literal or metaphorical location.\n[prep.] Among, in the middle of; amid.","ex":""},"MIGHT":{"p":"/maɪt/","s":"n./adj.","e":"[n.] Power, strength, force or influence held by a person or group.\n[n.] Physical strength or force.\n[n.] The ability to do something.\n[adj.] Mighty; powerful.\n[adj.] Possible.","ex":"He pushed with all his might, but still it would not move."},"MINER":{"p":"/ˈmaɪnə/","s":"n.","e":"[n.] A person who works in a mine.\n[n.] An operator of ordnance mines and similar explosives.\n[n.] Any bird of one of four species of Australian endemic honeyeaters in the genus Manorina.","ex":""},"MILD":{"p":"/ˈmaɪld/","s":"n./adj.","e":"[n.] A relatively low-gravity beer, often with a dark colour; mild ale\n[adj.] Gentle and not easily angered.\n[adj.] (of a rule or punishment) Of only moderate severity; not strict.\n[adj.] Not overly felt or seriously intended.","ex":"a mild man"},"MILK":{"p":"[mɛlk]","s":"n.","e":"[n.] A white liquid produced by the mammary glands of female mammals to nourish their young. From certain animals, especially cows, it is also called dairy milk and is a common food for humans as a beverage or used to produce various dairy products such as butter, cheese, and yogurt.\n[n.] A white (or whitish) liquid obtained from a vegetable source such as almonds, coconuts, oats, rice, and/or soy beans. Also called non-dairy milk.\n[n.] An individual serving of milk.","ex":"Table three ordered three milks. (Formally: The guests at table three ordered three glasses of milk.)"},"MINE":{"p":"/maɪn/","s":"pron.","e":"[pron.] My; belonging to me; that which belongs to me.","ex":""},"MIMIC":{"p":"/ˈmɪm.ɪk/","s":"n./v./adj.","e":"[n.] A person who practices mimicry, or mime.\n[n.] An imitation.\n[v.] To imitate, especially in order to ridicule.\n[v.] To take on the appearance of another, for protection or camouflage.\n[adj.] Pertaining to mimicry; imitative.\n[adj.] Mock, pretended.","ex":""},"MINCE":{"p":"/mɪns/","s":"n./v.","e":"[n.] Finely chopped meat.\n[n.] Finely chopped mixed fruit used in Christmas pies; mincemeat.\n[n.] An affected (often dainty or short and precise) gait.\n[v.] To make less; make small.\n[v.] To lessen; diminish; to diminish in speaking; speak of lightly or slightingly; minimise.\n[v.] To effect mincingly.","ex":"During Christmas time my dad loves to eat mince pies."},"MIND":{"p":"/maɪnd/","s":"n./v.","e":"[n.] The ability for rational thought.\n[n.] The ability to be aware of things.\n[n.] The ability to remember things.\n[v.] (originally and chiefly in negative or interrogative constructions) To dislike, to object to; to be bothered by.\n[v.] To look after, to take care of, especially for a short period of time.\n[v.] (chiefly in the imperative) To make sure, to take care (that).","ex":"Despite advancing age, his mind was still as sharp as ever."},"MINIM":{"p":"/ˈmɪ.nɪm/","s":"n.","e":"[n.] A half note, drawn as a semibreve with a stem.\n[n.] A unit of volume, in the Imperial and U.S. customary systems, 1/60 fluid drachm. Approximately equal to 1 drop, 62 μL or 0.9 grain (weight) of water.\n[n.] A short vertical stroke used in handwriting.","ex":""},"MINIMUM":{"p":"/ˈmɪn.ɪ.məm/","s":"n./adj.","e":"[n.] The lowest limit.\n[n.] The smallest amount.\n[n.] A period of minimum brightness or energy intensity (of a star).\n[adj.] To the lowest degree.","ex":"We need a minimum of three staff members on duty at all time."},"MILL":{"p":"/mɪl/","s":"n./v.","e":"[n.] A grinding apparatus for substances such as grains, seeds, etc.\n[n.] The building housing such a grinding apparatus.\n[n.] A machine used for expelling the juice, sap, etc., from vegetable tissues by pressure, or by pressure in combination with a grinding, or cutting process.\n[v.] To grind or otherwise process in a mill or other machine.\n[v.] To shape, polish, dress or finish using a machine.\n[v.] To engrave one or more grooves or a pattern around the edge of (a cylindrical object such as a coin).","ex":"Pepper has a stronger flavor when it is ground straight from a mill."},"MINING":{"p":"/ˈmaɪnɪŋ/","s":"v./n.","e":"[v.] To remove (ore) from the ground.\n[v.] To dig into, for ore or metal.\n[v.] To sow mines (the explosive devices) in (an area).\n[n.] The activity of removing solid valuables from the earth.\n[n.] Any activity that extracts or undermines.\n[n.] The activity of placing explosives underground, rigged to explode","ex":"gold mining"},"MINOR":{"p":"/ˈmaɪnɚ/","s":"n./v./adj.","e":"[n.] A person who is below the age of majority, consent, criminal responsibility or other adult responsibilities and accountabilities.\n[n.] A subject area of secondary concentration of a student at a college or university, or the student who has chosen such a secondary concentration.\n[n.] Determinant of a square submatrix\n[v.] To choose or have an area of secondary concentration as a student in a college or university.\n[adj.] Of little significance or importance.\n[adj.] Of a scale which has lowered scale degrees three, six, and seven relative to major, but with the sixth and seventh not always lowered","ex":"It is illegal to sell weapons to minors under the age of eighteen."},"MIRACLE":{"p":"/ˈmiɹəkəl/","s":"n./v.","e":"[n.] An event that appears inexplicable by the laws of nature and so is held to be supernatural in origin.\n[n.] A fortunate outcome that prevails despite overwhelming odds against it.\n[n.] An awesome and exceptional example of something\n[v.] To affect by a miracle; to work a miracle upon.","ex":"An example of a miracle associated with Muhammad is the splitting of the moon."},"MIRROR":{"p":"/ˈmɘ.ɹɘ/","s":"n./v.","e":"[n.] A smooth surface, usually made of glass with reflective material painted on the underside, that reflects light so as to give an image of what is in front of it.\n[n.] An object, person, or event that reflects or gives a picture of another.\n[n.] A disk, website or other resource that contains replicated data.\n[v.] Of an event, activity, behaviour, etc, to be identical to, to be a copy of.\n[v.] To create something identical to (a web site, etc.).\n[v.] To reflect, as in a mirror.","ex":"I had a look in the mirror to see if the blood had come off my face."},"MISSY":{"p":"/ˈmɪs.i/","s":"n./adj.","e":"[n.] A young female, or miss; as a term of mild disparagement, typically used jokingly or rebukingly.\n[adj.] Girlish; effeminate; sentimental.\n[adj.] Of, or pertaining to, female clothing or clothing sizes.","ex":"That's enough out of you, missy!"},"MISER":{"p":"/ˈmaɪzə(ɹ)/","s":"n.","e":"[n.] A person who hoards money rather than spending it; one who is cheap or extremely parsimonious.\n[n.] A kind of earth auger, typically large-bored and often hand-operated.","ex":""},"MIRTH":{"p":"/mɜːθ/","s":"n.","e":"[n.] The emotion usually following humour and accompanied by laughter; merriment; jollity; gaiety.\n[n.] That which causes merriment.","ex":""},"MISS":{"p":"/mɪs/","s":"n./v.","e":"[n.] A failure to hit.\n[n.] A failure to obtain or accomplish.\n[n.] An act of avoidance (used with the verb give).\n[v.] To fail to hit.\n[v.] To fail to achieve or attain.\n[v.] To avoid; to escape.","ex":"I think I’ll give the meeting a miss."},"MODAL":{"p":"","s":"n./adj.","e":"[n.] A modal proposition.\n[n.] A modal form, notably a modal auxiliary.\n[n.] (grammar) A modal verb.\n[adj.] Of, or relating to a mode or modus\n[adj.] (grammar) of, relating to, or describing the mood of a clause\n[adj.] Of, relating to, or composed in the musical modi by which an octave is divided, associated with emotional moods in Ancient — and in medieval ecclesiastical music","ex":""},"MIXTURE":{"p":"/ˈmɪkstʃə/","s":"n.","e":"[n.] The act of mixing.\n[n.] Something produced by mixing.\n[n.] Something that consists of diverse elements.","ex":""},"MODEL":{"p":"/ˈmɒdl̩/","s":"n./v./adj.","e":"[n.] A person who serves as a subject for artwork or fashion, usually in the medium of photography but also for painting or drawing.\n[n.] A person, usually an attractive female, hired to show items or goods to the public, such as items given away as prizes on a TV game show.\n[n.] A representation of a physical object, usually in miniature.\n[v.] To display for others to see, especially in regard to wearing clothing while performing the role of a fashion model\n[v.] To use as an object in the creation of a forecast or model\n[v.] To make a miniature model of","ex":"The beautiful model had her face on the cover of almost every fashion magazine imaginable."},"MOBILE":{"p":"/ˈməʊbaɪl/","s":"n./adj.","e":"[n.] A kinetic sculpture or decorative arrangement made of items hanging so that they can move independently from each other.\n[n.] The internet accessed via mobile devices.\n[n.] Something that can move.\n[adj.] Capable of being moved, especially on wheels.\n[adj.] Pertaining to or by agency of mobile phones.\n[adj.] Characterized by an extreme degree of fluidity; moving or flowing with great freedom.","ex":"there are many business opportunities in mobile"},"MISTAKE":{"p":"/mɪˈsteɪk/","s":"n./v.","e":"[n.] An error; a blunder.\n[n.] A pitch which was intended to be pitched in a hard-to-hit location, but instead ends up in an easy-to-hit place.\n[v.] To understand wrongly, taking one thing or person for another.\n[v.] To misunderstand (someone).\n[v.] To commit an unintentional error; to do or think something wrong.","ex":"Don't mistake my kindness for weakness."},"MODEM":{"p":"/ˈməʊdəm/","s":"n./v.","e":"[n.] A device that encodes digital computer signals into analog/analogue telephone signals and vice versa and allows computers to communicate over a phone line.\n[v.] To transmit by modem.","ex":""},"MODEST":{"p":"/ˈmɑdəst/","s":"adj.","e":"[adj.] Not bragging or boasting about oneself or one's achievements; unpretentious, humble.\n[adj.] Small, moderate in size.\n[adj.] Pure and delicate from a sense of propriety.","ex":"He earns a modest amount of money."},"MODE":{"p":"/məʊd/","s":"n.","e":"[n.] One of several ancient Greek scales.\n[n.] One of several common scales in modern Western music, one of which corresponds to the modern major scale and one to the natural minor scale.\n[n.] A particular means of accomplishing something.","ex":"What was the mode of entry?"},"MOLDY":{"p":"/ˈmoʊldi/","s":"adj.","e":"[adj.] Covered with mold.\n[adj.] Stale or musty.","ex":""},"MOMENT":{"p":"/ˈməʊmənt/","s":"n.","e":"[n.] A brief, unspecified amount of time.\n[n.] The smallest portion of time; an instant.\n[n.] Weight or importance.","ex":"Wait a moment, while I lock the front door."},"MOLAR":{"p":"/ˈmoʊlɚ/","s":"n./adj.","e":"[n.] A back tooth having a broad surface used for grinding one's food.\n[adj.] Of or relating to the molar teeth, or to grinding.","ex":""},"MOIST":{"p":"/mɔɪst/","s":"v./adj.","e":"[v.] To moisten.\n[adj.] Slightly wet; characterised by the presence of moisture, not dry; damp.\n[adj.] Of eyes: tearful, wet with tears.\n[adj.] Of weather, climate etc.: rainy, damp.","ex":""},"MONEY":{"p":"/ˈmʌni/","s":"n.","e":"[n.] A legally or socially binding conceptual contract of entitlement to wealth, void of intrinsic value, payable for all debts and taxes, and regulated in supply.\n[n.] A generally accepted means of exchange and measure of value.\n[n.] A currency maintained by a state or other entity which can guarantee its value (such as a monetary union).","ex":"Before colonial times cowry shells imported from Mauritius were used as money in Western Africa."},"MOMMY":{"p":"","s":"n./v./adj.","e":"[n.] (usually childish) Mother.\n[v.] To treat someone like a mother would; to mother someone.\n[adj.] (chiefly in the superlative) Characteristic of a mother; motherly.","ex":"She is the mommiest of mommies."},"MORNING":{"p":"/ˈmɔːnɪŋ/","s":"n./int.","e":"[n.] The part of the day from dawn to noon.\n[n.] The part of the day between midnight and noon.\n[n.] The early part of anything.\n[int.] A greeting said in the morning; shortening of good morning","ex":"I'll see you tomorrow morning."},"MOOSE":{"p":"/muːs/","s":"n.","e":"[n.] The largest member of the deer family (Alces americanus, sometimes included in Alces alces), of which the male has very large, palmate antlers.\n[n.] An ugly person.","ex":"We saw a moose at the edge of the woods."},"MORPH":{"p":"/mɔː(ɹ)f/","s":"n.","e":"[n.] (grammar) A physical form representing some morpheme in language. It is a recurrent distinctive sound or sequence of sounds.\n[n.] An allomorph: one of a set of realizations that a morpheme can have in different contexts.","ex":""},"MOTEL":{"p":"/moʊˈtɛl/","s":"n./v.","e":"[n.] A type of hotel or lodging establishment, often located near a major highway, which typically features a series of rooms the entrances of which are immediately adjacent to a parking lot to facilitate convenient access to automobiles parked there.\n[n.] A low-cost short-stay hotel, often with hourly rates rather than daily rates, and notorious for permitting illicit sexual activities; love hotel.\n[v.] To stay in a motel or motels.","ex":""},"MOTTO":{"p":"/ˈmɒtəʊ/","s":"n.","e":"[n.] A sentence, phrase, or word, forming part of an heraldic achievement.\n[n.] A sentence, phrase, or word, prefixed to an essay, discourse, chapter, canto, or the like, suggestive of its subject matter; a short, suggestive expression of a guiding principle; a maxim.\n[n.] A paper packet containing a sweetmeat, cracker, etc., together with a scrap of paper bearing a motto.","ex":""},"MOTHER":{"p":"/ˈmʌðə(ɹ)/","s":"n.","e":"[n.] A (human) female who has given birth to a baby\n[n.] A human female who parents an adopted or fostered child\n[n.] A human female who donates a fertilized egg or donates a body cell which has resulted in a clone.","ex":"He had something of his mother in him."},"MOTOR":{"p":"/ˈməʊtə/","s":"n./v./adj.","e":"[n.] A machine or device that converts other energy forms into mechanical energy, or imparts motion.\n[n.] A motor car, or automobile.\n[n.] A source of power for something; an inspiration; a driving force.\n[v.] To make a journey by motor vehicle; to drive.\n[v.] To move at a brisk pace.\n[v.] To leave.","ex":"Nice motor!"},"MOTIF":{"p":"/moʊˈtiːf/","s":"n.","e":"[n.] A recurring or dominant element; a theme.\n[n.] A short melodic passage that is repeated in several parts of a work.\n[n.] A decorative figure that is repeated in a design or pattern.","ex":"See how the artist repeats the scroll motif throughout the work?"},"MOTION":{"p":"/ˈməʊʃən/","s":"n./v.","e":"[n.] A state of progression from one place to another.\n[n.] A change of position with respect to time.\n[n.] A change from one place to another.\n[v.] To gesture indicating a desired movement.\n[v.] To introduce a motion in parliamentary procedure.\n[v.] To make a proposal; to offer plans.","ex":"He motioned for me to come closer."},"MOURN":{"p":"/mɔːn/","s":"n./v.","e":"[n.] Sorrow, grief.\n[n.] A ring fitted upon the head of a lance to prevent wounding an adversary in tilting.\n[v.] To express sadness or sorrow for; to grieve over (especially a death).\n[v.] To utter in a sorrowful manner.\n[v.] To wear mourning.","ex":""},"MOULT":{"p":"/mɒlt/","s":"n./v.","e":"[n.] The process of shedding or losing a covering of fur, feathers or skin etc.\n[n.] The skin or feathers cast off during the process of moulting.\n[v.] To shed or lose a covering of hair or fur, feathers, skin, horns, etc, and replace it with a fresh one.\n[v.] To shed in such a manner.","ex":"Some birds change colour during their winter moult."},"MOUNT":{"p":"/maʊnt/","s":"n.","e":"[n.] A hill or mountain.\n[n.] Any of seven fleshy prominences in the palm of the hand, taken to represent the influences of various heavenly bodies.\n[n.] A bulwark for offence or defence; a mound.","ex":"the mount of Jupiter"},"MOUTH":{"p":"/mʌʊθ/","s":"n./v.","e":"[n.] The opening of a creature through which food is ingested.\n[n.] The end of a river out of which water flows into a sea or other large body of water.\n[n.] An outlet, aperture or orifice.\n[v.] To speak; to utter.\n[v.] To make the actions of speech, without producing sound.\n[v.] To utter with a voice that is overly loud or swelling.","ex":"\"Open your mouth and say 'aah',\" directed the doctor."},"MOVER":{"p":"","s":"n.","e":"[n.] Someone who or something that moves.\n[n.] A dancer.\n[n.] A person employed to help people move their possessions from one residence to another.","ex":""},"MOVIE":{"p":"/ˈmuːvi/","s":"n.","e":"[n.] A recorded sequence of images displayed on a screen at a rate sufficiently fast to create the appearance of motion.\n[n.] (usually plural) A cinema.","ex":"Let's go to the movies."},"MUCH":{"p":"/mʌt͡ʃ/","s":"adj./adv./pron.","e":"[adj.] Large, great.\n[adj.] Long in duration.\n[adv.] To a great extent.\n[adv.] Often; frequently.\n[adv.] (in combinations such as 'as much', 'this much') Used to indicate or compare extent.\n[pron.] A large amount or great extent.","ex":"He is much fatter than I remember him."},"MOWER":{"p":"/ˈməʊ.ə(ɹ)/","s":"n.","e":"[n.] A lawnmower, a machine used to cut grass.\n[n.] A person who cuts grass.","ex":""},"MULCH":{"p":"/mʌltʃ/","s":"n./v.","e":"[n.] Any material used to cover the top layer of soil to protect, insulate, or decorate it, or to discourage weeds or retain moisture.\n[n.] A material used as mulch, as a decorative redwood bark mulch.\n[v.] To apply mulch.\n[v.] To turn into mulch.","ex":"An organic mulch is a mulch made of natural substances such as leaves or grass clippings."},"MUMMY":{"p":"/ˈmʌmi/","s":"n./v.","e":"[n.] An embalmed human or animal corpse wrapped in linen bandages for burial, especially as practised by the ancient Egyptians and some Native American tribes.\n[n.] (by extension) A reanimated embalmed human corpse, as a typical character in horror films.\n[n.] (by extension) Any naturally preserved human or animal body.\n[v.] To mummify.","ex":""},"MUNCH":{"p":"/mʌntʃ/","s":"n./v.","e":"[n.] A location or restaurant where good eating can be expected.\n[n.] An act of eating.\n[n.] Food.\n[v.] To chew with a grinding, crunching sound, and with the mouth closed — often used with on.\n[v.] To eat vigorously or with excitement.","ex":"Sally is having a breakfast munch at her place!"},"MUGGY":{"p":"/ˈmʌɡi/","s":"adj.","e":"[adj.] (Of the weather, air, etc) humid, or hot and humid.\n[adj.] Wet or mouldy","ex":"muggy straw"},"MUCUS":{"p":"/ˈmjuːkəs/","s":"n.","e":"[n.] A slippery secretion from the lining of the mucous membranes.","ex":""},"MUSHY":{"p":"/ˈmʊʃi/","s":"adj.","e":"[adj.] Resembling or having the consistency of mush; semiliquid, pasty, or granular.\n[adj.] Soft; squishy.\n[adj.] Overly sappy, corny, or cheesy; maudlin.","ex":"I don't especially like mushy oatmeal."},"MURDER":{"p":"/ˈmɜːdə(ɹ)/","s":"n./v.","e":"[n.] The crime of deliberately killing another person without justification.\n[n.] The act of deliberate killing of another person or other being without justification, especially with malice aforethought.\n[n.] (in jurisdictions which use the felony murder rule) The commission of an act which abets the commission of a crime the commission of which causes the death of a human.\n[v.] To deliberately kill (a person or persons) without justification, especially with malice aforethought.\n[v.] To defeat decisively.\n[v.] To kick someone's ass or chew someone out (used to express one’s anger at somebody).","ex":"The defendant was charged with murder."},"MURAL":{"p":"/ˈmjʊəɹəl/","s":"n./v./adj.","e":"[n.] A large painting, usually drawn on a wall.\n[v.] To create a mural.\n[adj.] Of or relating to a wall; on, or in, or against a wall.\n[adj.] Resembling a wall; perpendicular or steep.","ex":"a mural quadrant"},"MUST":{"p":"","s":"n./v.","e":"[n.] Something that is mandatory or required.\n[v.] (modal auxiliary, defective) To do with certainty; indicates that the speaker is certain that the subject will have executed the predicate.\n[v.] (modal auxiliary, defective) To do as a requirement; indicates that the sentence subject is required as an imperative or directive to execute the sentence predicate, with failure to do so resulting in a negative consequence.\n[v.] (modal auxiliary, defective) said about something that is very likely, probable, or certain to be true","ex":"If you'll be out all day, a map is a must."},"MUSKY":{"p":"/mʌs.ki/","s":"adj.","e":"[adj.] Having the scent of musk","ex":""},"NANNY":{"p":"/ˈnæni/","s":"n./v.","e":"[n.] A child's nurse.\n[n.] A grandmother.\n[n.] A godmother.\n[v.] To serve as a nanny.\n[v.] To treat like a nanny's charges; to coddle.","ex":""},"NATAL":{"p":"","s":"adj.","e":"[adj.] Of or relating to birth.","ex":""},"MYRRH":{"p":"[mɜː(ɹ)]","s":"n.","e":"[n.] A red-brown resinous material, the dried sap of a tree of the species Commiphora myrrha.\n[n.] The herb chervil.","ex":""},"MANNER":{"p":"/ˈmænə/","s":"n.","e":"[n.] Mode of action; way of performing or doing anything\n[n.] Characteristic mode of acting or behaving; bearing\n[n.] One's customary method of acting; habit.","ex":"His natural manner makes him seem like the boss."},"PECAN":{"p":"/piːˈkæn/","s":"n.","e":"[n.] A deciduous tree, Carya illinoinensis, of the central and southern United States, having deeply furrowed bark, pinnately compound leaves, and edible nuts.\n[n.] A smooth, thin-shelled, edible oval nut of this tree.\n[n.] A half of the edible portion of the inside of this nut.","ex":""},"PAYMENT":{"p":"/ˈpeɪmənt/","s":"n.","e":"[n.] The act of paying.\n[n.] A sum of money paid in exchange for goods or services.","ex":""},"PENNY":{"p":"/pəni/","s":"n./v.","e":"[n.] In the United Kingdom and Ireland, a copper coin worth 1/240 of a pound sterling or Irish pound before decimalisation. Abbreviation: d.\n[n.] In the United Kingdom, a copper coin worth 1/100 of a pound sterling. Abbreviation: p.\n[n.] In Ireland, a coin worth 1/100 of an Irish pound before the introduction of the euro. Abbreviation: p.\n[v.] To jam a door shut by inserting pennies between the doorframe and the door.\n[v.] To circumvent the tripping of an electrical circuit breaker by the dangerous practice of inserting a coin in place of a fuse in a fuse socket.","ex":"Zach and Ben had only been at college for a week when their door was pennied by the girls down the hall."},"PESKY":{"p":"/ˈpɛski/","s":"adj.","e":"[adj.] Annoying, troublesome, irritating (usually of an animal or child).","ex":""},"PHONE":{"p":"/fəʊ̯n/","s":"n./v.","e":"[n.] A device for transmitting conversations and other sounds in real time across distances, now often a small portable unit also capable of running software etc.\n[v.] To call (someone) using a telephone.","ex":""},"PINKY":{"p":"/ˈpɪŋki/","s":"n./adj.","e":"[n.] Methylated spirits mixed with red wine or Condy's crystals.\n[n.] A baby mouse, especially when used as food for a snake, etc.\n[n.] A white person.\n[adj.] Pinkish.","ex":""},"PITCHER":{"p":"/ˈpɪtʃə/","s":"n.","e":"[n.] One who pitches anything, as hay, quoits, a ball, etc.\n[n.] , the player who delivers the ball to the batter.\n[n.] The top partner in a homosexual relationship or penetrator in a sexual encounter between two men.","ex":""},"PLAIN":{"p":"/pleɪn/","s":"adj./adv.","e":"[adj.] Flat, level.\n[adj.] Simple.\n[adj.] Obvious.\n[adv.] Simply.\n[adv.] Plainly; distinctly.","ex":"I plain forgot."},"PLATE":{"p":"/pleɪt/","s":"n./v.","e":"[n.] A slightly curved but almost flat dish from which food is served or eaten.\n[n.] Such dishes collectively.\n[n.] The contents of such a dish.\n[v.] To cover the surface material of an object with a thin coat of another material, usually a metal.\n[v.] To place the various elements of a meal on the diner's plate prior to serving.\n[v.] To score a run.","ex":"I filled my plate from the bountiful table."},"PLASTIC":{"p":"/ˈplæstɪk/","s":"n./adj.","e":"[n.] A synthetic, solid, hydrocarbon-based polymer, whether thermoplastic or thermosetting.\n[n.] (metonym) Credit or debit cards used in place of cash to buy goods and services.\n[n.] Fakeness, or a person who is fake or arrogant, or believes that they are better than the rest of the population.\n[adj.] Capable of being moulded; malleable, flexible, pliant.\n[adj.] Producing tissue.\n[adj.] Creative, formative.","ex":""},"PLAY":{"p":"/pleɪ/","s":"n./v.","e":"[n.] Activity for amusement only, especially among the young.\n[n.] Similar activity in young animals, as they explore their environment and learn new skills.\n[n.] The conduct, or course, of a game.\n[v.] To act in a manner such that one has fun; to engage in activities expressly for the purpose of recreation or entertainment.\n[v.] To perform in (a sport); to participate in (a game).\n[v.] To take part in amorous activity; to make love.","ex":"Children learn through play."},"PLEAT":{"p":"/pliːt/","s":"n./v.","e":"[n.] A fold in the fabric of a garment, usually a skirt, as a part of the design of the garment, with the purpose of adding controlled fullness and freedom of movement, or taking up excess fabric. There are many types of pleats, differing in their construction and appearance.\n[n.] A fold in an organ, usually a longitudinal fold in a long leaf such as that of palmetto, lending it stiffness.\n[n.] A plait.\n[v.] To form one or more pleats in a piece of fabric or a garment.\n[v.] To plait.","ex":""},"PLOT":{"p":"/plɒt/","s":"n./v.","e":"[n.] (authorship) The course of a story, comprising a series of incidents which are gradually unfolded, sometimes by unexpected means.\n[n.] An area or land used for building on or planting on.\n[n.] A graph or diagram drawn by hand or produced by a mechanical or electronic device.\n[v.] To conceive (a crime, etc).\n[v.] To trace out (a graph or diagram).\n[v.] To mark (a point on a graph, chart, etc).","ex":"They had plotted a robbery."},"PLUCK":{"p":"/plʌk/","s":"n./v.","e":"[n.] An instance of plucking.\n[n.] The lungs, heart with trachea and often oesophagus removed from slaughtered animals.\n[n.] Guts, nerve, fortitude or persistence.\n[v.] To pull something sharply; to pull something out\n[v.] To take or remove (someone) quickly from a particular place or situation.\n[v.] To gently play a single string, e.g. on a guitar, violin etc.","ex":"Those tiny birds are hardly worth the tedious pluck."},"PLUSH":{"p":"/plʌʃ/","s":"n./adj.","e":"[n.] A textile fabric with a nap or shag on one side, longer and softer than the nap of velvet.\n[n.] A plush toy.\n[adj.] Very extravagant.\n[adj.] Very expensive, or appearing expensive.\n[adj.] (of a man-made object) Having a soft, fluffy exterior.","ex":"They lived in a plush apartment complex."},"PLUMS":{"p":"/plʌmz/","s":"n.","e":"[n.] The fruit and its tree.\n[n.] Extended senses.","ex":""},"PLUNK":{"p":"/plʌŋk/","s":"n./v.","e":"[n.] The dull thud of something landing on a surface.\n[n.] A large sum of money.\n[n.] A dollar.\n[v.] To drop or throw something heavily onto or into something else, so that it makes a dull sound.\n[v.] To land suddenly or heavily; to plump down.\n[v.] To intentionally hit the batter with a pitch.","ex":"Enrique plunked his money down on the counter with a sigh and bellied up to the bar."},"PLUS":{"p":"/plʌs/","s":"n./v./adj./prep.","e":"[n.] A positive quantity.\n[n.] An asset or useful addition.\n[n.] A plus sign: +.\n[v.] To add; to subject to addition.\n[v.] (often followed by 'up') To increase in magnitude.\n[v.] To improve.","ex":"He is a real plus to the team."},"POEM":{"p":"/ˈpoʊ̯ɪm/","s":"n.","e":"[n.] A literary piece written in verse.\n[n.] A piece of writing in the tradition of poetry, an instance of poetry.\n[n.] A piece of poetic writing, that is with an intensity or depth of expression or inspiration greater than is usual in prose.","ex":""},"POEMS":{"p":"/ˈpəʊ.ɪmz/","s":"n.","e":"[n.] A literary piece written in verse.\n[n.] A piece of writing in the tradition of poetry, an instance of poetry.\n[n.] A piece of poetic writing, that is with an intensity or depth of expression or inspiration greater than is usual in prose.","ex":""},"POET":{"p":"/ˈpəʊɪt/","s":"n.","e":"[n.] A person who writes poems.\n[n.] A person with a creative or romantic imagination.","ex":""},"POESY":{"p":"/ˈpəʊɪzi/","s":"n.","e":"[n.] A poem.\n[n.] The class of literature comprising poems; poetry, verse.","ex":""},"POISON":{"p":"/ˈpɔɪz(ə)n/","s":"n./v.","e":"[n.] A substance that is harmful or lethal to a living organism.\n[n.] Something that harms a person or thing.\n[n.] A drink; liquor.\n[v.] To use poison to kill or paralyse (somebody).\n[v.] To pollute; to cause to become poisonous.\n[v.] To cause to become much worse.","ex":"We used a poison to kill the weeds."},"POLAR":{"p":"/ˈpəʊ̯lə(ɹ)/","s":"n./adj.","e":"[n.] The line joining the points of contact of tangents drawn to meet a curve from a point called the pole of the line.\n[adj.] Of or having a pole or polarity.\n[adj.] Of, relating to, measured from, or referred to a geographic pole (the North Pole or South Pole); within the Arctic or Antarctic circles.\n[adj.] (space sciences) Of an orbit that passes over, or near, one of these poles.","ex":""},"POKER":{"p":"/ˈpəʊkə/","s":"n.","e":"[n.] A metal rod, generally of wrought iron, for adjusting the burning logs or coals in a fire; a firestick.\n[n.] A tool like a soldering iron for making poker drawings.\n[n.] One who pokes.","ex":""},"POLED":{"p":"","s":"v.","e":"[v.] To propel by pushing with poles, to push with a pole.\n[v.] To identify something quite precisely using a telescope.\n[v.] To furnish with poles for support.\n[v.] To induce piezoelectricity in (a substance) by aligning the dipoles.","ex":"Huck Finn poled that raft southward down the Mississippi because going northward against the current was too much work."},"POINTER":{"p":"/ˈpɔɪntə/","s":"n.","e":"[n.] Anything that points or is used for pointing.\n[n.] A teacher's pointer, pointing stick, a rod with an arrow.\n[n.] A needle-like component of a timepiece or measuring device that indicates the time or the current reading of the device.","ex":""},"POPPY":{"p":"/ˈpɒpi/","s":"n./adj.","e":"[n.] Any plant of the genus Papaver or the family Papaveraceae, with crumpled, often red, petals and a milky juice having narcotic properties; especially the common poppy or corn poppy (Papaver rhoeas) which has orange-red flowers; the flower of such a plant.\n[n.] A bright red colour tinted with orange, like that of the common poppy flower.\n[n.] A simple artificial poppy flower worn in a buttonhole or displayed in other contexts to remember those who died in the two World Wars and other armed conflicts, especially around Remembrance Sunday.\n[adj.] Of a bright red colour tinted with orange, like that of the common poppy flower (Papaver rhoeas).","ex":""},"POND":{"p":"/pɒnd/","s":"n./v.","e":"[n.] An inland body of standing water, either natural or man-made, that is smaller than a lake.\n[n.] An inland body of standing water of any size that is fed by springs rather than by a river.\n[n.] The Atlantic Ocean. Especially in across the pond.\n[v.] To block the flow of water so that it can escape only through evaporation or seepage; to dam.\n[v.] To make into a pond; to collect, as water, in a pond by damming.\n[v.] To form a pond; to pool.","ex":"I haven't been back home across the pond in twenty years."},"PONDS":{"p":"","s":"n.","e":"[n.] An inland body of standing water, either natural or man-made, that is smaller than a lake.\n[n.] An inland body of standing water of any size that is fed by springs rather than by a river.\n[n.] The Atlantic Ocean. Especially in across the pond.","ex":"I haven't been back home across the pond in twenty years."},"POLKA":{"p":"/ˈpɒl.kə/","s":"n./v.","e":"[n.] A lively dance originating in Bohemia.\n[n.] The music for this dance.\n[n.] A polka jacket.\n[v.] To dance the polka.","ex":""},"POSER":{"p":"/ˈpəʊzə(ɹ)/","s":"n.","e":"[n.] A particularly difficult question or puzzle.\n[n.] Someone who asks a question or sets a problem.\n[n.] Someone who, or something which, poses; a person who sets their body in a fixed position, such as for photography or painting.","ex":"Even as a child, she was a habitual poser of difficult questions."},"POSE":{"p":"/pəʊz/","s":"n.","e":"[n.] Common cold, head cold; catarrh.","ex":""},"POSIT":{"p":"/ˈpɒzɪt/","s":"n./v.","e":"[n.] Something that is posited; a postulate.\n[v.] Assume the existence of; to postulate.\n[v.] Propose for consideration or study; to suggest.\n[v.] Put (something somewhere) firmly; to place or position.\n[n.] A place or location.\n[n.] A post of employment; a job.","ex":"Chief of Staff is the second-highest position in the army."},"PORT":{"p":"/pɔːt/","s":"n./v./adj.","e":"[n.] A place on the coast at which ships can shelter, or dock to load and unload cargo or passengers.\n[n.] A town or city containing such a place, a port city.\n[n.] The left-hand side of a vessel, including aircraft, when one is facing the front. Used to unambiguously refer to directions relative to the vessel structure, rather than to a person or object on board.\n[v.] To turn or put to the left or larboard side of a ship; said of the helm.\n[adj.] Of or relating to port, the left-hand side of a vessel when facing the bow.","ex":"Port your helm!"},"POSSE":{"p":"/ˈpɒ.si/","s":"n.","e":"[n.] A group or company of people, originally especially one having hostile intent; a throng, a crowd.\n[n.] A group of people summoned to help law enforcement.\n[n.] A search party.","ex":""},"POWDER":{"p":"/ˈpaʊ.də(ɹ)/","s":"n./v.","e":"[n.] The fine particles which are the result of reducing dry substance by pounding, grinding, or triturating, or the result of decay; dust.\n[n.] A mixture of fine dry, sweet-smelling particles applied to the face or other body parts, to reduce shine or to alleviate chaffing.\n[n.] An explosive mixture used in gunnery, blasting, etc.; gunpowder.\n[v.] To reduce to fine particles; to pound, grind, or rub into a powder.\n[v.] To sprinkle with powder, or as if with powder.\n[v.] To use powder on the hair or skin.","ex":"to powder one's hair"},"POSTS":{"p":"/pəʊsts/","s":"n./v.","e":"[n.] A long dowel or plank protruding from the ground; a fencepost; a lightpost.\n[n.] A stud; a two-by-four.\n[n.] A pole in a battery.\n[v.] To hang (a notice) in a conspicuous manner for general review.\n[v.] To hold up to public blame or reproach; to advertise opprobriously; to denounce by public proclamation.\n[v.] To carry (an account) from the journal to the ledger.","ex":"ram a post into the ground"},"POUND":{"p":"/paʊnd/","s":"n.","e":"[n.] A unit of mass equal to 16 avoirdupois ounces (= 453.592 37 g). Today this value is the most common meaning of \"pound\" as a unit of weight.\n[n.] A unit of mass equal to 12 troy ounces (≈ 373.242 g). Today, this is a common unit of weight when measuring precious metals, and is little used elsewhere.\n[n.] The symbol # (octothorpe, hash)","ex":""},"POVERTY":{"p":"/ˈpɒvəti/","s":"n.","e":"[n.] The quality or state of being poor; lack of money\n[n.] Any deficiency of elements or resources that are needed or desired, or that constitute richness","ex":"poverty of soil"},"POUR":{"p":"/pɔː/","s":"n./v.","e":"[n.] The act of pouring.\n[n.] Something, or an amount, poured.\n[n.] A downpour, or flood of precipitation.\n[v.] To cause (liquid, or liquid-like substance) to flow in a stream, either out of a container or into it.\n[v.] To send out as in a stream or a flood; to cause (an emotion) to come out; to cause to escape.\n[v.] To send forth from, as in a stream; to discharge uninterruptedly.","ex":"The bartender's inexpert pour left me with a pint of beer that was half foam."},"PRANK":{"p":"/pɹæŋk/","s":"n./v./adj.","e":"[n.] A practical joke or mischievous trick.\n[n.] An evil deed; a malicious trick, an act of cruel deception.\n[v.] To perform a practical joke on; to trick.\n[v.] To call someone's phone and promptly hang up\n[v.] To adorn in a showy manner; to dress or equip ostentatiously.\n[adj.] Full of gambols or tricks.","ex":"He pulled a gruesome prank on his sister."},"PRAY":{"p":"/pɹeɪ/","s":"v./adv.","e":"[v.] To direct words and/or thoughts to God or any higher being, for the sake of adoration, thanks, petition for help, etc.\n[v.] To humbly beg a person for aid or their time.\n[v.] To ask earnestly for; to seek to obtain by supplication; to entreat for.\n[adv.] Please; used to make a polite request.","ex":"Muslims pray in the direction of Mecca."},"PRAYER":{"p":"/pɹɛə(ɹ)/","s":"n.","e":"[n.] A practice of communicating with one's God.\n[n.] The act of praying.\n[n.] The specific words or methods used for praying.","ex":"Through prayer I ask for God's blessings."},"PREEN":{"p":"/pɹiːn/","s":"n./v.","e":"[n.] A forked tool used by clothiers for dressing cloth.\n[n.] (dialectal) pin\n[n.] (dialectal) bodkin; brooch\n[v.] To pin; fasten.","ex":""},"PRECISE":{"p":"/pɹɪˈsaɪs/","s":"v./adj.","e":"[v.] (NNES or European Union documents) To make or render precise; to specify.\n[adj.] Exact, accurate\n[adj.] (of experimental results) consistent, clustered close together, agreeing with each other (this does not mean that they cluster near the true, correct, or accurate value)\n[adj.] Adhering too much to rules; prim or punctilious","ex":""},"POUTS":{"p":"/paʊts/","s":"n./v.","e":"[n.] A young bird, a chick; now especially, a young game bird (turkey, partridge, grouse etc.).\n[n.] One's facial expression when pouting.\n[n.] A fit of sulking or sullenness.\n[v.] To push out one's lips.\n[v.] To thrust itself outward; to be prominent.\n[v.] To be or pretend to be ill-tempered; to sulk.","ex":""},"PRETTY":{"p":"/ˈpɹɪti/","s":"n./v./adj./adv.","e":"[n.] A pretty person; a term of address to a pretty person.\n[n.] Something that is pretty.\n[v.] To make pretty; to beautify\n[adj.] Pleasant to the sight or other senses; attractive, especially of women or children, but less strikingly than something beautiful.\n[adj.] Of objects or things: nice-looking, appealing.\n[adj.] Fine-looking; only superficially attractive; initially appealing but having little substance; see petty.","ex":"We'll stop at the knife store and look at the sharp pretties."},"PREPARE":{"p":"/pɹɪˈpɛə/","s":"n./v.","e":"[n.] Preparation\n[v.] To make ready for a specific future purpose; to set up; to assemble or equip.\n[v.] To make ready for eating or drinking; to cook.\n[v.] To make oneself ready; to get ready, make preparation.","ex":"We prepared the spacecraft for takeoff."},"PRESENT":{"p":"/pɹəˈzɛnt/","s":"n./adj.","e":"[n.] The current moment or period of time.\n[n.] The present tense.\n[adj.] Relating to now, for the time being; current.\n[adj.] Located in the immediate vicinity.\n[adj.] Having an immediate effect (of a medicine, poison etc.); fast-acting.","ex":"The barbaric practice continues to the present day."},"PRICK":{"p":"/pɹɪk/","s":"n.","e":"[n.] A small hole or perforation, caused by piercing.\n[n.] An indentation or small mark made with a pointed object.\n[n.] A dot or other diacritical mark used in writing; a point.","ex":""},"PRESS":{"p":"/pɹɛs/","s":"n.","e":"[n.] A device used to apply pressure to an item.\n[n.] A printing machine.\n[n.] (collective) The print-based media (both the people and the newspapers).","ex":"a flower press"},"PRIDE":{"p":"/pɹaɪd/","s":"n./v.","e":"[n.] The quality or state of being proud; an unreasonable overestimation of one's own superiority in terms of talents, looks, wealth, importance etc., which manifests itself in lofty airs, distance, reserve and often contempt of others.\n[n.] (often with of or in) A sense of one's own worth, and abhorrence of what is beneath or unworthy of one; lofty self-respect; noble self-esteem; elevation of character; dignified bearing; proud delight; -- in a good sense.\n[n.] Proud or disdainful behavior or treatment; insolence or arrogance of demeanor; haughty bearing and conduct; insolent exultation; disdain; hubris.\n[v.] To take or experience pride in something; to be proud of it.","ex":"He had pride of ownership in his department."},"PRIMP":{"p":"/pɹɪmp/","s":"v.","e":"[v.] To spend time improving one's appearance, often in front of a mirror.\n[v.] To dress in an affected manner.","ex":""},"PRIES":{"p":"/pɹaɪz/","s":"v.","e":"[v.] To look where one is not welcome; to be nosy.\n[v.] To keep asking about something that does not concern one.\n[v.] To look closely and curiously at (something closed or not public).\n[v.] To use leverage to open or widen.","ex":""},"PRIMARY":{"p":"/ˈpɹɒeməɹi/","s":"n./v./adj.","e":"[n.] A primary election; a preliminary election to select a political candidate of a political party.\n[n.] The first year of grade school.\n[n.] A base or fundamental component; something that is irreducible.\n[v.] To challenge (an incumbent sitting politician) for their political party's endorsement to run for re-election, through running a challenger campaign in a primary election, especially one that is more ideologically extreme.\n[v.] To take part in a primary election.\n[adj.] First or earliest in a group or series.","ex":"Children attend primary school, and teenagers attend secondary school."},"PRIMO":{"p":"/ˈpɹiː.moʊ/","s":"n./adj.","e":"[n.] The principal part of a duet.\n[adj.] Best; first-class.","ex":""},"PREYS":{"p":"/pɹeɪz/","s":"v.","e":"[v.] To act as a predator.","ex":""},"PRIED":{"p":"/pɹɑjd/","s":"v.","e":"[v.] To look where one is not welcome; to be nosy.\n[v.] To keep asking about something that does not concern one.\n[v.] To look closely and curiously at (something closed or not public).\n[v.] To use leverage to open or widen.","ex":""},"PRISE":{"p":"/pɹaɪz/","s":"n./v.","e":"[n.] The cost required to gain possession of something.\n[n.] The cost of an action or deed.\n[n.] Value; estimation; excellence; worth.\n[n.] An enterprise or adventure.\n[v.] To force (open) with a lever; to pry.\n[n.] That which is taken from another; something captured; a thing seized by force, stratagem, or superior power.","ex":"I paid a high price for my folly."},"PRIOR":{"p":"/ˈpɹaɪɚ/","s":"n./adj./adv.","e":"[n.] A high-ranking member of a monastery, usually lower in rank than an abbot.\n[n.] A chief magistrate in Italy.\n[n.] (law enforcement) A previous arrest or criminal conviction on someone's record.\n[adj.] Advance; previous; coming before.\n[adj.] Former, previous.\n[adv.] Previously.","ex":"I had no prior knowledge you were coming."},"PROCEED":{"p":"/pɹəˈsiːd/","s":"v.","e":"[v.] To move, pass, or go forward or onward; to advance; to carry on\n[v.] To pass from one point, topic, or stage, to another.\n[v.] To come from; to have as its source or origin.","ex":"To proceed on a journey."},"PRIVATE":{"p":"/ˈpɹaɪvət/","s":"n./adj.","e":"[n.] A soldier of the lowest rank in the army.\n[n.] A doctor working in privately rather than publicly funded health care.\n[n.] (in the plural) The genitals.\n[adj.] Belonging to, concerning, or accessible only to an individual person or a specific group.\n[adj.] Not accessible by the public.\n[adj.] Not in governmental office or employment.","ex":"Her address is private; you can't have it."},"PRIZE":{"p":"/pɹaɪz/","s":"n.","e":"[n.] That which is taken from another; something captured; a thing seized by force, stratagem, or superior power.\n[n.] Anything captured by a belligerent using the rights of war; especially, property captured at sea in virtue of the rights of war, as a vessel.\n[n.] An honour or reward striven for in a competitive contest; anything offered to be competed for, or as an inducement to, or reward of, effort.","ex":""},"PRODUCE":{"p":"/pɹəˈdjuːs/","s":"v.","e":"[v.] To yield, make or manufacture; to generate.\n[v.] To make (a thing) available to a person, an authority, etc.; to provide for inspection.\n[v.] To sponsor and present (a motion picture, etc) to an audience or to the public.","ex":""},"PRODUCT":{"p":"/ˈpɹɒd.əkt/","s":"n./v.","e":"[n.] A commodity offered for sale.\n[n.] Any preparation to be applied to the hair, skin, nails, etc.\n[n.] Anything that is produced; a result.\n[v.] To produce.","ex":"That store offers a variety of products.  We've got to sell a lot of product by the end of the month."},"PROFS":{"p":"","s":"n.","e":"[n.] The most senior rank for an academic at a university or similar institution, informally also known as \"full professor.\" Abbreviated Prof.\n[n.] A teacher or faculty member at a college or university regardless of formal rank.\n[n.] One who professes something, such as a religious doctrine.\n[n.] Total income or cash flow minus expenditures. The money or other benefit a non-governmental organization or individual receives in exchange for products and services sold at an advertised price.\n[n.] Benefit, positive result obtained.\n[n.] In property law, a nonpossessory interest in land whereby a party is entitled to enter the land of another for the purpose of taking the soil or the substance of the soil (coal, oil, minerals, and in some jurisdictions timber and game).","ex":"Reading such an enlightening book on the subject was of much profit to his studies."},"PROJECT":{"p":"","s":"n./v.","e":"[n.] A planned endeavor, usually with a specific goal and accomplished in several steps or stages.\n[n.] (usually in the plural) An urban low-income housing building.\n[n.] An idle scheme; an impracticable design.\n[v.] To extend beyond a surface.\n[v.] To cast (an image or shadow) upon a surface; to throw or cast forward; to shoot forth.\n[v.] To extend (a protrusion or appendage) outward.","ex":"Projects like Pruitt-Igoe were considered irreparably dangerous and demolished."},"PROMOTE":{"p":"/pɹəˈməʊt/","s":"v.","e":"[v.] To raise (someone) to a more important, responsible, or remunerative job or rank.\n[v.] To advocate or urge on behalf of (something or someone); to attempt to popularize or sell by means of advertising or publicity.\n[v.] To encourage, urge or incite.","ex":"He promoted his clerk to office manager."},"PRONE":{"p":"/pɹəʊn/","s":"adj.","e":"[adj.] Lying face downward.\n[adj.] Having a downward inclination or slope.\n[adj.] Predisposed, liable, inclined.","ex":"prone position"},"PROSE":{"p":"/ˈpɹəʊz/","s":"n./v.","e":"[n.] Language, particularly written language, not intended as poetry.\n[n.] Language which evinces little imagination or animation; dull and commonplace discourse.\n[n.] A hymn with no regular meter, sometimes introduced into the Mass.\n[v.] To write or repeat in a dull, tedious, or prosy way.","ex":"Though known mostly for her prose, she also produced a small body of excellent poems."},"PROOF":{"p":"/pɹʉːf/","s":"n./v./adj.","e":"[n.] An effort, process, or operation designed to establish or discover a fact or truth; an act of testing; a test; a trial.\n[n.] The degree of evidence which convinces the mind of any truth or fact, and produces belief; a test by facts or arguments which induce, or tend to induce, certainty of the judgment; conclusive evidence; demonstration.\n[n.] The quality or state of having been proved or tried; firmness or hardness which resists impression, or does not yield to force; impenetrability of physical bodies.\n[v.] To proofread.\n[v.] To make resistant, especially to water.\n[v.] To allow yeast-containing dough to rise.","ex":"a proof load; a proof charge"},"PROVEN":{"p":"/ˈpɹuːvən/","s":"v./adj.","e":"[v.] To proofread.\n[v.] To make resistant, especially to water.\n[v.] To allow yeast-containing dough to rise.\n[v.] To demonstrate that something is true or viable; to give proof for.\n[v.] To turn out; to manifest.\n[v.] To turn out to be.","ex":"I will prove that my method is more effective than yours."},"PROXY":{"p":"/ˈpɹɒk.si/","s":"n./v./adj.","e":"[n.] An agent or substitute authorized to act for another person.\n[n.] The authority to act for another, especially when written.\n[n.] The written appointment of a proctor in suits in the ecclesiastical courts.\n[v.] To serve as a proxy for.\n[v.] To function as a server for a client device, but pass on the requests to another server for service.\n[adj.] Used as a proxy or acting as a proxy.","ex":"a proxy indicator"},"PRUNE":{"p":"/pɹuːn/","s":"n./v.","e":"[n.] A plum.\n[n.] The dried, wrinkled fruit of certain species of plum.\n[n.] An old woman, especially a wrinkly one.\n[v.] To become wrinkled like a dried plum, as the fingers and toes do when kept submerged in water.","ex":""},"PSALM":{"p":"/sɑːm/","s":"n./v.","e":"[n.] A sacred song; a poetical composition for use in the praise or worship of God.\n[n.] One of the hymns by David and others, collected into one book of the Old Testament, or a modern metrical version of such a hymn for public worship.\n[v.] To extol in psalms; to make music; to sing","ex":"to psalm his praises."},"PUBIC":{"p":"/ˈpjuːbɪk/","s":"adj.","e":"[adj.] Of, or relating to the area of the body adjacent to the pubis or the pubes.","ex":""},"PSYCH":{"p":"/saɪk/","s":"n./v./adj./int.","e":"[n.] Psychology or psychiatry.\n[n.] A psychologist; a psychiatrist.\n[v.] To put (someone) into a required psychological frame of mind (also psych up).\n[v.] To intimidate (someone) emotionally or using psychology (also psych out).\n[v.] To treat (someone) using psychoanalysis.\n[adj.] Psychedelic.","ex":"a psych class"},"PUMAS":{"p":"","s":"n.","e":"[n.] The mountain lion or cougar, Puma concolor.\n[n.] A woman in her 20s or 30s who seeks relationships with younger men; a younger cougar.","ex":""},"PUNCH":{"p":"/pʌntʃ/","s":"n./v.","e":"[n.] A hit or strike with one's fist.\n[n.] Power, strength, energy.\n[n.] Impact.\n[v.] To strike with one's fist.\n[v.] (of cattle) To herd.\n[v.] To operate (a device or system) by depressing a button, key, bar, or pedal, or by similar means.","ex":"If she punches me, I'm gonna break her nose."},"PUMP":{"p":"/pʌmp/","s":"n./v.","e":"[n.] A device for moving or compressing a liquid or gas.\n[n.] An instance of the action of a pump; one stroke of a pump; any action similar to pumping\n[n.] A device for dispensing liquid or gas to be sold, particularly fuel.\n[v.] To use a pump to move (liquid or gas).\n[v.] (often followed by up) To fill with air.\n[v.] To move rhythmically, as the motion of a pump.","ex":"This pump can deliver 100 gallons of water per minute."},"PULPY":{"p":"","s":"adj.","e":"[adj.] Having the characteristics of pulp\n[adj.] Having the characteristics of pulp fiction; thus, having a garish focus on sex and violence","ex":"the pulpy texture of overripe fruit"},"PUNKS":{"p":"/pʌŋks/","s":"n./v.","e":"[n.] A person used for sex, particularly:\n[n.] A worthless person, particularly:\n[n.] Short for punk rock, a genre known for short, loud, energetic songs with electric guitars and strong drums.\n[v.] To pimp.\n[v.] To forcibly perform anal sex upon an unwilling partner.\n[v.] To prank.","ex":"Ricky punked his new cell-mates."},"PULSE":{"p":"/pʊls/","s":"n.","e":"[n.] A normally regular beat felt when arteries are depressed, caused by the pumping action of the heart.\n[n.] A beat or throb.\n[n.] The beat or tactus of a piece of music.","ex":""},"RICE":{"p":"/ɹaɪs/","s":"n./v.","e":"[n.] Cereal plants, Oryza sativa of the grass family whose seeds are used as food.\n[n.] A specific variety of this plant.\n[n.] The seeds of this plant used as food.\n[v.] To squeeze through a ricer; to mash or make into rice-sized pieces (especially potatoes).\n[v.] To harvest wild rice (Zizania sp.)\n[v.] To throw rice at a person (usually at a wedding).","ex":""},"RIDING":{"p":"/ˈɹaɪdɪŋ/","s":"v./n.","e":"[v.] To transport oneself by sitting on and directing a horse, later also a bicycle etc.\n[v.] To be transported in a vehicle; to travel as a passenger.\n[v.] (chiefly US and South Africa) To transport (someone) in a vehicle.\n[n.] A path cut through woodland.\n[n.] The act of one who rides; a mounted excursion.\n[n.] A festival procession.","ex":"The cab rode him downtown."},"RICKS":{"p":"","s":"n./v.","e":"[n.] Straw, hay etc. stored in a stack for winter fodder, commonly protected with thatch.\n[n.] A stack of wood, especially cut to a regular length; also used as a measure of wood, typically four by eight feet.\n[v.] To heap up (hay, etc.) in ricks.\n[v.] To slightly sprain or strain the neck, back, ankle etc.\n[n.] A brand new (naive) boot camp inductee.","ex":"No turning back now rick, you are the property of the US government now."},"RIGOR":{"p":"/ɹɪɡɚ/","s":"n.","e":"[n.] Short for rigor mortis.\n[n.] Severity or strictness.\n[n.] Harshness, as of climate.\n[n.] A trembling or shivering response.","ex":""},"RILES":{"p":"","s":"v.","e":"[v.] To make angry\n[v.] To stir or move from a state of calm or order","ex":"It riles me that she never closes the door after she leaves."},"RIPEN":{"p":"/ˈɹaɪpən/","s":"v.","e":"[v.] To grow ripe; to become mature (said of grain, fruit, flowers etc.)\n[v.] To approach or come to perfection.\n[v.] To cause to mature; to make ripe","ex":"Grapes ripen in the sun."},"RIMES":{"p":"","s":"v./n.","e":"[v.] To compose or treat in verse; versify.\n[v.] (followed by with) Of a word, to be pronounced identically with another from the vowel in its stressed syllable to the end.\n[v.] Of two or more words, to be pronounced identically from the vowel in the stressed syllable of each to the end of each.\n[n.] Ice formed by the rapid freezing of cold water droplets of fog on to a cold surface.\n[n.] A coating or sheet of ice so formed.\n[n.] A film or slimy coating.","ex":"\"Creation\" rhymes with \"integration\" and \"station\"."},"RISKY":{"p":"/ˈɹɪski/","s":"adj.","e":"[adj.] Dangerous, involving risks.","ex":"Investing in this start-up company could be risky."},"RITES":{"p":"/ɹaɪts/","s":"n.","e":"[n.] That which complies with justice, law or reason.\n[n.] A legal, just or moral entitlement.\n[n.] The right side or direction.\n[n.] A religious custom.\n[n.] (by extension) A prescribed behavior.","ex":"We're on the side of right in this contest."},"RISK":{"p":"/ɹɪsk/","s":"n./v.","e":"[n.] A possible adverse event or outcome\n[n.] The probability of a negative outcome to a decision or event.\n[n.] The magnitude of possible loss consequent to a decision or event.\n[v.] To incur risk of (something).\n[v.] To incur risk of harming or jeopardizing.\n[v.] To incur risk as a result of (doing something).","ex":"2006, Trever Ramsey on BBC News website, Exercise 'cuts skin cancer risk' read at http//news.bbc.co.uk/1/hi/health/4764535.stm on 14 May 2006"},"RIVER":{"p":"/ˈɹɪvə/","s":"n./v.","e":"[n.] A large and often winding stream which drains a land mass, carrying water down from higher areas to a lower point, oftentimes ending in another body of water, such as an ocean or in an inland sea.\n[n.] Any large flow of a liquid in a single body.\n[n.] The last card dealt in a hand.\n[v.] To improve one’s hand to beat another player on the final card in a poker game.","ex":"Occasionally rivers overflow their banks and cause floods."},"RIVES":{"p":"","s":"n./v.","e":"[n.] A place torn; a rent; a rift.\n[v.] To tear apart by force; to rend; to split; to cleave.\n[v.] To pierce or cleave with a weapon.\n[n.] A bank or shore.","ex":""},"RISE":{"p":"/ɹaɪs/","s":"v.","e":"[v.] To move, or appear to move, physically upwards relative to the ground.\n[v.] To increase in value or standing.\n[v.] To begin; to develop.","ex":""},"ROARS":{"p":"/ɹɔːz/","s":"n./v.","e":"[n.] A long, loud, deep shout, as of rage or laughter, made with the mouth wide open.\n[n.] The cry of the lion.\n[n.] The deep cry of the bull.\n[v.] To make a loud, deep cry, especially from pain, anger, or other strong emotion.\n[v.] To laugh in a particularly loud manner.\n[v.] Of animals (especially the lion), to make a loud deep noise.","ex":"The audience roared at his jokes."},"ROAST":{"p":"/ɹəʊst/","s":"n./v./adj.","e":"[n.] A cut of meat suited to roasting\n[n.] A meal consisting of roast foods.\n[n.] The degree to which something, especially coffee, is roasted.\n[v.] To cook food by heating in an oven or over a fire without covering, resulting in a crisp, possibly even slightly charred appearance.\n[v.] To cook by surrounding with hot embers, ashes, sand, etc.\n[v.] To process by drying through exposure to sun or artificial heat","ex":"Dark roast means that the coffee bean has been roasted to a higher temperature and for a longer period of time than in light roast."},"ROBE":{"p":"/ɹəʊb/","s":"n./v.","e":"[n.] A long loose outer garment, often signifying honorary stature.\n[n.] The skin of an animal, especially the bison, dressed with the fur on, and used as a wrap.\n[n.] A wardrobe, especially one built into a bedroom.\n[v.] To clothe; to dress.\n[v.] To put on official vestments.","ex":""},"ROCKY":{"p":"[ˈɹʷɔkiː]","s":"adj.","e":"[adj.] Unstable; easily rocked.\n[adj.] In the style of rock music.\n[adj.] Troubled; or difficult; in danger or distress.","ex":"The table was rocky, so we put a book under one leg."},"ROBIN":{"p":"/ˈɹɒb.ɪn/","s":"n.","e":"[n.] Any of various passerine birds (about 100 species) of the families Muscicapidae, Turdidae and Petroicidae (formerly Eopsaltriidae), typically with a red breast.\n[n.] A trimming in front of a dress.","ex":""},"ROBED":{"p":"","s":"v./adj.","e":"[v.] To clothe; to dress.\n[v.] To put on official vestments.\n[adj.] Wearing a robe.","ex":""},"ROBUST":{"p":"/ɹəʊˈbʌst/","s":"adj.","e":"[adj.] Evincing strength and health; strong.\n[adj.] Violent; rough; rude.\n[adj.] Requiring strength or vigor","ex":"A robust wall was put up."},"ROLES":{"p":"/ɹəʊlz/","s":"n.","e":"[n.] A character or part played by a performer or actor.\n[n.] The expected behaviour of an individual in a society.\n[n.] The function or position of something.\n[n.] An ancient unit of quantity, 72 sheets of parchment.","ex":"Her dream was to get a role in a Hollywood movie, no matter how small."},"ROLE":{"p":"/ɹəʊl/","s":"n.","e":"[n.] A character or part played by a performer or actor.\n[n.] The expected behaviour of an individual in a society.\n[n.] The function or position of something.","ex":"Her dream was to get a role in a Hollywood movie, no matter how small."},"ROLLS":{"p":"/ɹəʊlz/","s":"n./v.","e":"[n.] The act or result of rolling, or state of being rolled.\n[n.] A forward or backward roll in gymnastics; going head over heels. A tumble.\n[n.] Something which rolls.\n[v.] To cause to revolve by turning over and over; to move by turning on an axis; to impel forward by causing to turn over and over on a supporting surface.\n[v.] To turn over and over.\n[v.] To tumble in gymnastics; to do a somersault.","ex":"Look at the roll of the waves."},"ROOMS":{"p":"/ɹuːmz/","s":"n./v.","e":"[n.] Opportunity or scope (to do something).\n[n.] Space for something, or to carry out an activity.\n[n.] A particular portion of space.\n[v.] To reside, especially as a boarder or tenant.\n[v.] To assign to a room; to allocate a room to.","ex":"Doctor Watson roomed with Sherlock Holmes at Baker Street."},"ROOMY":{"p":"","s":"n./adj.","e":"[n.] A roommate.\n[adj.] Spacious, expansive, comfortable.","ex":"Our new apartment is roomy enough to accommodate all our furniture."},"ROOST":{"p":"/ɹuːst/","s":"n./v.","e":"[n.] The place where a bird sleeps (usually its nest or a branch).\n[n.] A group of birds roosting together.\n[n.] A bedroom\n[v.] (of birds or bats) To settle on a perch in order to sleep or rest\n[v.] To spend the night","ex":""},"ROUTINE":{"p":"/ɹuːˈtiːn/","s":"n./adj.","e":"[n.] A course of action to be followed regularly; a standard procedure.\n[n.] A set of normal procedures, often performed mechanically.\n[n.] A set piece of an entertainer's act.\n[adj.] According to established procedure.\n[adj.] Regular; habitual.\n[adj.] Ordinary with nothing to distinguish it from all the others.","ex":"Connie was completely robotic and emotionless by age 12; her entire life had become one big routine."},"ROVED":{"p":"","s":"v.","e":"[v.] To shoot with arrows (at).\n[v.] To roam, or wander about at random, especially over a wide area.\n[v.] To roam or wander through.","ex":""},"ROSES":{"p":"/ɹoʊzɨz̥/","s":"n./v.","e":"[n.] A shrub of the genus Rosa, with red, pink, white or yellow flowers.\n[n.] A flower of the rose plant.\n[n.] A plant or species in the rose family. (Rosaceae)\n[v.] To make rose-coloured; to redden or flush.\n[v.] To perfume, as with roses.\n[n.] A pale pink wine made by removing the dark grape skins at the required point during fermentation.","ex":""},"ROWDY":{"p":"/ˈɹaʊdi/","s":"n./adj.","e":"[n.] A boisterous person; a brawler.\n[adj.] Loud and disorderly; riotous; boisterous.","ex":""},"ROWER":{"p":"/ˈɹəʊ.ə(ɹ)/","s":"n.","e":"[n.] One who rows.\n[n.] A rowing machine.","ex":""},"RUDDY":{"p":"/ˈɹʌdi/","s":"n./v./adj./adv.","e":"[n.] A ruddy duck.\n[n.] A ruddy ground dove.\n[v.] To make reddish in colour.\n[adj.] Reddish in color, especially of the face, fire, or sky.\n[adj.] A mild intensifier, expressing irritation.\n[adv.] A mild intensifier, expressing irritation.","ex":"The sunset ruddied our faces."},"RUDER":{"p":"","s":"adj.","e":"[adj.] Bad-mannered.\n[adj.] Somewhat obscene, pornographic, offensive.\n[adj.] Tough, robust.","ex":"Karen broke up with Fred because he was often rude to her."},"RUMOR":{"p":"/ˈɹuːmə(ɹ)/","s":"n./v.","e":"[n.] A statement or claim of questionable accuracy, from no known reliable source, usually spread by word of mouth.\n[n.] Information or misinformation of the kind contained in such claims.\n[v.] (usually used in the passive voice) To tell a rumor about; to gossip.","ex":"There's a rumor going round that he's going to get married."},"RUMPS":{"p":"","s":"n.","e":"[n.] The hindquarters of a four-legged mammal, not including its legs\n[n.] A cut of meat from the rump of an animal.\n[n.] The buttocks.","ex":""},"RUNES":{"p":"","s":"n.","e":"[n.] A letter, or character, belonging to the written language of various ancient Germanic peoples, especially the Scandinavians and the Anglo-Saxons.\n[n.] A Finnish or Scandinavian epic poem, or a division of one, especially a division of the Kalevala.\n[n.] A letter or mark used as mystical or magic symbol.","ex":""},"RUNNY":{"p":"/ˈɹʌni/","s":"adj.","e":"[adj.] Fluid; capable of flowing.\n[adj.] Liable to run or drip.","ex":"runny honey"},"RUNTS":{"p":"","s":"n.","e":"[n.] The smallest animal of a litter.\n[n.] (by extension) The smallest child in the family.\n[n.] Undersized or stunted plant, animal or person.","ex":"the runt of the family"},"RUPEE":{"p":"/ɹʊ-/","s":"n.","e":"[n.] The common name for the monetary currencies used in modern India, Mauritius, Nepal, Pakistan, the Seychelles, or Sri Lanka, often abbreviated ₨.\n[n.] A silver coin circulating in India between the 16th and 20th centuries, weighing one tola (formerly 170–180 troy grains; from 1833, 180 troy grains).","ex":""},"RURAL":{"p":"/ˈɹɔːɹəl/","s":"n./adj.","e":"[n.] A person from the countryside; a rustic.\n[adj.] Relating to the countryside or to agriculture.","ex":""},"RUSHED":{"p":"/ɹʌʃt/","s":"v./adj.","e":"[v.] To hurry; to perform a task with great haste.\n[v.] To flow or move forward rapidly or noisily.\n[v.] To dribble rapidly.\n[adj.] Very busy.\n[adj.] Done in haste; done quickly.\n[adj.] Abounding or covered with rushes.","ex":"rush one's dinner;   rush off an email response"},"RUSTY":{"p":"/ˈɹʌsti/","s":"adj.","e":"[adj.] Marked or corroded by rust.\n[adj.] Of the rust color, reddish or reddish-brown.\n[adj.] Lacking recent experience, out of practice, especially with respect to a skill or activity.","ex":""},"SADLY":{"p":"/ˈsadli/","s":"adv.","e":"[adv.] In a sad manner; sorrowfully.\n[adv.] Unfortunately, sad to say.\n[adv.] Very much (of a desire etc.); dearly; urgently.","ex":"“Only when we climb up can we see it,” he said sadly."},"SABER":{"p":"/ˈseɪ.bɚ/","s":"n./v.","e":"[n.] A light sword, sharp along the front edge, part of the back edge, and at the point.\n[n.] A modern fencing sword modeled after the sabre.\n[v.] To strike or kill with a sabre.","ex":""},"RUTH":{"p":"/ɹuːθ/","s":"n.","e":"[n.] Sorrow for the misery of another; pity, compassion; mercy.\n[n.] Repentance; regret; remorse.\n[n.] Sorrow; misery; distress.","ex":""},"SABRE":{"p":"/ˈseɪ.bɚ/","s":"n./v.","e":"[n.] A light sword, sharp along the front edge, part of the back edge, and at the point.\n[n.] A modern fencing sword modeled after the sabre.\n[v.] To strike or kill with a sabre.","ex":""},"SAGAS":{"p":"","s":"n.","e":"[n.] An Old Norse (Icelandic) prose narrative, especially one dealing with family or social histories and legends.\n[n.] Something with the qualities of such a saga; an epic, a long story.","ex":""},"SACKS":{"p":"","s":"n./v.","e":"[n.] A bag or pouch inside a plant or animal that typically contains a fluid.\n[n.] (games) A sacrifice.\n[v.] (games) To sacrifice.\n[n.] The privilege, formerly enjoyed by the lord of a manor, of holding courts, trying causes, and imposing fines.\n[n.] A bag; especially a large bag of strong, coarse material for storage and handling of various commodities, such as potatoes, coal, coffee; or, a bag with handles used at a supermarket, a grocery sack; or, a small bag for small items, a satchel.\n[n.] The amount a sack holds; also, an archaic or historical measure of varying capacity, depending on commodity type and according to local usage; an old English measure of weight, usually of wool, equal to 13 stone (182 pounds), or in other sources, 26 stone (364 pounds).","ex":"Kasparov's queen sac early in the game gained him a positional advantage against Kramnik."},"SAINT":{"p":"/sən(t)/","s":"n.","e":"[n.] A person whom a church or another religious group has officially recognised as especially holy or godly; one eminent for piety and virtue.\n[n.] (by extension) A person with positive qualities; one who does good.\n[n.] One of the blessed in heaven.","ex":"Kateri Tekakwitha was proclaimed a saint."},"SAGES":{"p":"","s":"n.","e":"[n.] A wise person or spiritual teacher; someone of gravity and wisdom, especially, a teacher venerable for years, and of sound judgment and prudence; a grave or stoic philosopher.","ex":""},"SAGGY":{"p":"/ˈsæɡi/","s":"adj.","e":"[adj.] Baggy or loose-fitting.\n[adj.] That sinks or droops from wear or its own weight.","ex":""},"SALLY":{"p":"/ˈsæli/","s":"n.","e":"[n.] A willow\n[n.] Any tree that looks like a willow\n[n.] An object made from the above trees' wood","ex":""},"SAID":{"p":"/sɛd/","s":"adj./v.","e":"[adj.] Mentioned earlier; aforesaid.\n[v.] To pronounce.\n[v.] To recite.\n[v.] To tell, either verbally or in writing.","ex":"The said party has denied the charges."},"SAFER":{"p":"","s":"adj.","e":"[adj.] Not in danger; out of harm's reach.\n[adj.] Free from risk.\n[adj.] Providing protection from danger; providing shelter.","ex":"You’ll be safe here."},"SALAD":{"p":"/ˈsæləd/","s":"n.","e":"[n.] A food made primarily of a mixture of raw or cold ingredients, typically vegetables, usually served with a dressing such as vinegar or mayonnaise.\n[n.] A raw vegetable of the kind used in salads.","ex":""},"SAKE":{"p":"/seɪk/","s":"n.","e":"[n.] Cause, interest or account\n[n.] Purpose or end; reason\n[n.] The benefit or regard of someone or something","ex":"For the sake of argument"},"SALES":{"p":"/seɪlz/","s":"n.","e":"[n.] A hall.\n[n.] An exchange of goods or services for currency or credit.\n[n.] (Short for discount sale) The sale of goods at reduced prices.\n[n.] The act of putting up for auction to the highest bidder.\n[n.] The activities involved in selling goods or services.\n[n.] The amount or value of goods and services sold.","ex":"He celebrated after the sale of company."},"SAFES":{"p":"","s":"n./v.","e":"[n.] A box, usually made of metal, in which valuables can be locked for safekeeping.\n[n.] A condom.\n[n.] A ventilated or refrigerated chest or closet for securing provisions from noxious animals or insects.\n[v.] To make something safe.","ex":""},"SALT":{"p":"/sɔlt/","s":"n./v./adj.","e":"[n.] A common substance, chemically consisting mainly of sodium chloride (NaCl), used extensively as a condiment and preservative.\n[n.] One of the compounds formed from the reaction of an acid with a base, where a positive ion replaces a hydrogen of the acid.\n[n.] A salt marsh, a saline marsh at the shore of a sea.\n[v.] To add salt to.\n[v.] To deposit salt as a saline solution.\n[v.] To fill with salt between the timbers and planks, as a ship, for the preservation of the timber.","ex":"to salt fish, beef, or pork; to salt the city streets in the winter"},"SALVE":{"p":"/sælv/","s":"n.","e":"[n.] An ointment, cream, or balm with soothing, healing, or calming effects.\n[n.] Any remedy or action that soothes or heals.","ex":""},"SALVO":{"p":"/ˈsælvəʊ/","s":"n.","e":"[n.] An exception; a reservation; an excuse.","ex":""},"SAND":{"p":"/sænd/","s":"n./adj.","e":"[n.] Rock that is ground more finely than gravel, but is not as fine as silt (more formally, see grain sizes chart), forming beaches and deserts and also used in construction.\n[n.] (often in the plural) A beach or other expanse of sand.\n[n.] (circa 1920) Personal courage.\n[adj.] Of a light beige colour, like that of typical sand.","ex":"The Canadian tar sands are a promising source of oil."},"SALTY":{"p":"/ˈsɒl.ti/","s":"adj.","e":"[adj.] Tasting of salt.\n[adj.] Containing salt.\n[adj.] Coarse, provocative, earthy; said of language.","ex":""},"SALE":{"p":"/seɪl/","s":"n.","e":"[n.] A hall.","ex":""},"SAME":{"p":"/seɪm/","s":"adj./pron./int.","e":"[adj.] Not different or other; not another or others; not different as regards self; selfsame; identical.\n[adj.] Lacking variety from; indistinguishable.\n[adj.] Similar, alike.\n[pron.] The identical thing, ditto.\n[pron.] Something similar, something of the identical type.\n[pron.] It or them, without a connotation of similarity.","ex":"Are you the same person who phoned me yesterday?"},"SALSA":{"p":"/ˈsɑl.sə/","s":"n./v.","e":"[n.] A spicy tomato sauce, often including onions and hot peppers.\n[n.] A style of urban music originally from New York heavily influenced by Cuban dance music, jazz and rock.\n[n.] Any of several dances performed to salsa music.\n[v.] To dance the salsa.","ex":""},"SANDS":{"p":"","s":"n./v.","e":"[n.] Rock that is ground more finely than gravel, but is not as fine as silt (more formally, see grain sizes chart), forming beaches and deserts and also used in construction.\n[n.] (often in the plural) A beach or other expanse of sand.\n[n.] (circa 1920) Personal courage.\n[v.] To abrade the surface of (something) with sand or sandpaper in order to smooth or clean it.\n[v.] To cover with sand.\n[v.] To blot ink using sand.","ex":"The Canadian tar sands are a promising source of oil."},"SANG":{"p":"[sɛŋ]","s":"v.","e":"[v.] To produce musical or harmonious sounds with one’s voice.\n[v.] To express audibly by means of a harmonious vocalization.\n[v.] To soothe with singing.","ex":"\"I really want to sing in the school choir,\" said Vera."},"SAPPY":{"p":"/ˈsæpi/","s":"adj.","e":"[adj.] Excessively sweet, emotional, nostalgic; cheesy; mushy. (British equivalent: soppy)\n[adj.] Having (a particularly large amount of) sap.\n[adj.] Juicy.","ex":"It was a sappy love song, but it reminded them of their first dance."},"SASSY":{"p":"/ˈsasi/","s":"adj.","e":"[adj.] Bold and spirited, cheeky, impudent, saucy.\n[adj.] Somewhat sexy and provocative.\n[adj.] Lively, vigorous.","ex":""},"SATED":{"p":"","s":"v./adj.","e":"[v.] To satisfy the appetite or desire of; to fill up.\n[adj.] In a state of complete and thorough satisfaction; having ones appetite fully satisfied, by having enough of something.\n[adj.] Quelled of thirst or hunger.","ex":"At last he stopped, his hunger and thirst sated."},"SAUCE":{"p":"/sɔːs/","s":"n./v.","e":"[n.] A liquid (often thickened) condiment or accompaniment to food.\n[n.] Tomato sauce (similar to US tomato ketchup), as in:\n[n.] (usually “the”) Alcohol, booze.\n[v.] To add sauce to; to season.\n[v.] To cause to relish anything, as if with a sauce; to tickle or gratify, as the palate; to please; to stimulate.\n[v.] To make poignant; to give zest, flavour or interest to; to set off; to vary and render attractive.","ex":"apple sauce; mint sauce"},"SATIN":{"p":"/ˈsætɪn/","s":"n./v./adj.","e":"[n.] A cloth woven from silk, nylon or polyester with a glossy surface and a dull back. (The same weaving technique applied to cotton produces cloth termed sateen).\n[v.] To make (paper, silver, etc.) smooth and glossy like satin.\n[adj.] Semigloss.","ex":"satin paint"},"SARAN":{"p":"","s":"n.","e":"[n.] A plastic resin used to make packaging films.","ex":""},"SAVOR":{"p":"","s":"n.","e":"[n.] The specific taste or smell of something.\n[n.] A distinctive sensation.\n[n.] Sense of smell; power to scent, or trace by scent.","ex":""},"SAUCY":{"p":"/ˈsɔː.sɪ/","s":"adj.","e":"[adj.] Similar to sauce; having the consistency or texture of sauce.\n[adj.] Impertinent or disrespectful, often in a manner that is regarded as entertaining or amusing; smart.\n[adj.] Impudently bold; pert.","ex":"She is a loud, saucy child who doesn't show a lot of respect to her elders."},"SAVED":{"p":"/seɪvd/","s":"v./adj.","e":"[v.] To prevent harm or difficulty.\n[v.] To put aside, to avoid.\n[adj.] Rescued from the consequences of sin.\n[adj.] Retained for future use rather than spent e.g. ː\"A penny saved is a penny earned.\"","ex":""},"SAVER":{"p":"","s":"n.","e":"[n.] One who saves.\n[n.] One who keeps savings more than usual.","ex":"a saver of souls"},"SATYR":{"p":"/ˈsæt.ə(ɹ)/","s":"n.","e":"[n.] A woodland creature with pointed ears, legs, and short horns of a goat and a fondness for unrestrained revelry.\n[n.] Any of various nymphalid butterflies of the genus Faunis.\n[n.] A sylvan deity or demigod, male companion of Pan or Dionysus, represented as part man and part goat, and characterized by riotous merriment and lasciviousness, sometimes pictured with a perpetual erection.\n[n.] (by extension) A lecherous man.\n[n.] Any of various butterflies of the nymphalid subfamily Satyrinae, having brown wings marked with eyelike spots; a meadow brown.","ex":""},"SAVES":{"p":"/seɪvz/","s":"n./v.","e":"[n.] In various sports, a block that prevents an opponent from scoring.\n[n.] When a relief pitcher comes into a game leading by 3 points (runs) or less, and his team wins while continually being ahead.\n[n.] A point in a professional wrestling match when one or more wrestlers run to the ring to aid a fellow wrestler who is being beaten.\n[v.] To prevent harm or difficulty.\n[v.] To put aside, to avoid.","ex":"The goaltender made a great save."},"SAWED":{"p":"","s":"v.","e":"[v.] To cut (something) with a saw.\n[v.] To make a motion back and forth similar to cutting something with a saw.\n[v.] To be cut with a saw.","ex":"They were stoned, they were sawn asunder, were tempted, were slain with the sword: they wandered about in sheepskins and goatskins; being destitute, afflicted, tormented;"},"SCALE":{"p":"/skeɪl/","s":"n./v.","e":"[n.] A ladder; a series of steps; a means of ascending.\n[n.] An ordered, usually numerical sequence used for measurement, means of assigning a magnitude.\n[n.] Size; scope.\n[v.] To change the size of something whilst maintaining proportion; especially to change a process in order to produce much larger amounts of the final product.\n[v.] To climb to the top of.\n[v.] To tolerate significant increases in throughput or other potentially limiting factors.","ex":"Please rate your experience on a scale from 1 to 10."},"SCALP":{"p":"/skælp/","s":"n./v.","e":"[n.] The top of the head; the skull.\n[n.] The part of the head where the hair grows from, or used to grow from.\n[n.] A part of the skin of the head, with the hair attached, formerly cut or torn off from an enemy by warriors in some cultures as a token of victory.\n[v.] To remove the scalp (part of the head from where the hair grows), by brutal act or accident.\n[v.] To resell, especially tickets, usually for an inflated price, often illegally.\n[v.] On an open outcry exchange trading floor, to buy and sell rapidly for one's own account, aiming to buy from a seller and a little later sell to a buyer, making a small profit from the difference (roughly the amount of the bid/offer spread, or less).","ex":"Some tribes used to collect scalps to prove how many of the enemy they had killed in battle."},"SCARF":{"p":"/skɑːf/","s":"n./v.","e":"[n.] A long, often knitted, garment worn around the neck.\n[n.] A headscarf.\n[n.] A neckcloth or cravat.\n[v.] To throw on loosely; to put on like a scarf.\n[v.] To dress with a scarf, or as with a scarf; to cover with a loose wrapping.","ex":""},"SCARE":{"p":"/skɛə/","s":"n.","e":"[n.] A minor fright.\n[n.] A cause of slight terror; something that inspires fear or dread.\n[n.] A device or object used to frighten.","ex":"Johnny had a bad scare last night."},"SCENT":{"p":"/sɛnt/","s":"n./v.","e":"[n.] A distinctive odour or smell.\n[n.] An odour left by an animal that may be used for tracing.\n[n.] The sense of smell.\n[v.] To detect the scent of; to discern by the sense of smell.\n[v.] To have a suspicion of.\n[v.] To impart an odour to.","ex":"the scent of a skunk"},"SCOOP":{"p":"/skuːp/","s":"n./v.","e":"[n.] Any cup- or bowl-shaped tool, usually with a handle, used to lift and move loose or soft solid material.\n[n.] The amount or volume of loose or solid material held by a particular scoop.\n[n.] The act of scooping, or taking with a scoop or ladle; a motion with a scoop, as in dipping or shovelling.\n[v.] To lift, move, or collect with a scoop or as though with a scoop.\n[v.] To make hollow; to dig out.\n[v.] To report on something, especially something worthy of a news article, before (someone else).","ex":"She kept a scoop in the dog food."},"SIGNAL":{"p":"/ˈsɪɡnəl/","s":"n./v./adj.","e":"[n.] A sequence of states representing an encoded message in a communication channel.\n[n.] Any variation of a quantity or change in an entity over time that conveys information upon detection.\n[n.] A sign made to give notice of some occurrence, command, or danger, or to indicate the start of a concerted action.\n[v.] To indicate; to convey or communicate by a signal.\n[v.] To communicate with (a person or system) by a signal.\n[adj.] Standing above others in rank, importance, or achievement.","ex":"Seeing the flames, he ran to the control room and signalled headquarters."},"SILOS":{"p":"","s":"n.","e":"[n.] A vertical building, usually cylindrical, used for the production of silage.\n[n.] From the shape, a building used for the storage of grain.\n[n.] An underground bunker used to hold missiles which may be launched.","ex":""},"SINGLE":{"p":"/ˈsɪŋɡəl/","s":"n./v./adj.","e":"[n.] A 45 RPM vinyl record with one song on side A and one on side B.\n[n.] A popular song released and sold (on any format) nominally on its own though usually having at least one extra track.\n[n.] One who is not married or does not have a romantic partner.\n[v.] To identify or select one member of a group from the others; generally used with out, either to single out or to single (something) out.\n[v.] To get a hit that advances the batter exactly one base.\n[v.] To thin out.","ex":"The Offspring released four singles from their most recent album."},"SISAL":{"p":"/ˈsʌɪsəl/","s":"n.","e":"[n.] A Central American plant, Agave sisalana, cultivated for its sword-shaped leaves that yield fibers used for rope.\n[n.] The fibre of the plant.\n[n.] A sisal mat.","ex":""},"SISSY":{"p":"/ˈsɪsi/","s":"n./adj.","e":"[n.] An effeminate boy or man.\n[n.] A timid, unassertive or cowardly person.\n[n.] (BDSM) A male crossdresser who adopts feminine behaviours.\n[adj.] Effeminate.\n[adj.] Cowardly.","ex":""},"SIRUP":{"p":"","s":"n.","e":"[n.] Any thick liquid that has a high sugar content and which is added to or poured over food as a flavouring.\n[n.] (by extension) Any viscous liquid.\n[n.] (shortened from \"syrup of figs\") A wig.","ex":"maple syrup"},"SISTER":{"p":"/ˈsɪs.tə/","s":"n./v.","e":"[n.] A daughter of the same parents as another person; a female sibling.\n[n.] A female member of a religious order; especially one devoted to more active service; (informally) a nun.\n[n.] Any butterfly in the genus Adelpha, so named for the resemblance of the dark-colored wings to the black habit traditionally worn by nuns.\n[v.] To strengthen (a supporting beam) by fastening a second beam alongside it.\n[v.] To be sister to; to resemble closely.","ex":"My sister is always driving me crazy."},"SKATE":{"p":"/skeɪt/","s":"n./v./adj.","e":"[n.] A light boot, fitted with a blade, used for ice skating.\n[n.] A boot having small wheels or casters attached to its sole; used for roller skating\n[n.] A runner or blade, usually of steel, with a frame shaped to fit the sole of a shoe, made to be fastened under the foot, and used for gliding on ice.\n[n.] The act of skateboarding\n[n.] The act of roller skating or ice skating\n[v.] To move along a surface (ice or ground) using skates.","ex":"There's time for a quick skate before dinner."},"SKIER":{"p":"","s":"n.","e":"[n.] One who skis.","ex":""},"SKIES":{"p":"/skaɪz/","s":"n./v.","e":"[n.] The atmosphere above a given point, especially as visible from the ground during the day.\n[n.] The part of the sky which can be seen from a specific place or at a specific time; its condition, climate etc.\n[n.] Heaven.\n[v.] To hit, kick or throw (a ball) extremely high.\n[v.] To clear (a hurdle, high jump bar, etc.) by a large margin.\n[v.] To hang (a picture on exhibition) near the top of a wall, where it cannot be well seen.","ex":"That year, a meteor fell from the sky."},"SKIPS":{"p":"","s":"n./v.","e":"[n.] A leaping, jumping or skipping movement.\n[n.] The act of passing over an interval from one thing to another; an omission of a part.\n[n.] A passage from one sound to another by more than a degree at once.\n[v.] To move by hopping on alternate feet.\n[v.] To leap about lightly.\n[v.] To skim, ricochet or bounce over a surface.","ex":"She will skip from one end of the sidewalk to the other."},"SKIMS":{"p":"","s":"v.","e":"[v.] To pass lightly; to glide along in an even, smooth course; to glide along near the surface.\n[v.] To pass near the surface of; to brush the surface of; to glide swiftly along the surface of.\n[v.] To hasten along with superficial attention.","ex":""},"SKIN":{"p":"/skɪn/","s":"n./v.","e":"[n.] The outer protective layer of the body of any animal, including of a human.\n[n.] The outer protective layer of the fruit of a plant.\n[n.] The skin and fur of an individual animal used by humans for clothing, upholstery, etc.\n[v.] To injure the skin of.\n[v.] To remove the skin and/or fur of an animal or a human.\n[v.] To high five.","ex":"He is so disgusting he makes my skin crawl."},"SKIRT":{"p":"/skɜːt/","s":"n./v.","e":"[n.] An article of clothing, usually worn by women and girls, that hangs from the waist and covers the lower part of the body.\n[n.] The part of a dress or robe, etc., that hangs below the waist.\n[n.] A loose edging to any part of a dress.\n[v.] To be on or form the border of.\n[v.] To move around or along the border of; to avoid the center of.\n[v.] To cover with a skirt; to surround.","ex":"The plain was skirted by rows of trees."},"SLABS":{"p":"/slæbs/","s":"n.","e":"[n.] A large, flat piece of solid material; a solid object that is large and flat.\n[n.] A paving stone; a flagstone.\n[n.] A carton containing 24 cans of beer.\n[n.] Mud, sludge.\n[n.] A car that has been modified with equipment such as loudspeakers, lights, special paint, hydraulics, and other accessories.","ex":""},"SKINK":{"p":"/skɪŋk/","s":"n.","e":"[n.] A shin of beef.\n[n.] A soup or pottage made from a boiled shin of beef.\n[n.] (by extension) Usually preceded by a descriptive word: a soup or pottage made using other ingredients.","ex":"lean sirloin, skink and pot-roast"},"SLANT":{"p":"/ˈslænt/","s":"n./v./adj.","e":"[n.] A slope; an incline, inclination.\n[n.] A sloped surface or line.\n[n.] A run: a heading driven diagonally between the dip and strike of a coal seam.\n[v.] To lean, tilt or incline.\n[v.] To bias or skew.\n[v.] To lie or exaggerate.","ex":"The house was built on a bit of a slant and was never quite level."},"SLEEP":{"p":"/sliːp/","s":"v.","e":"[v.] To rest in a state of reduced consciousness.\n[v.] (of a spinning top or yo-yo) To spin on its axis with no other perceptible motion.\n[v.] To cause (a spinning top or yo-yo) to spin on its axis with no other perceptible motion.","ex":"You should sleep 8 hours a day."},"SLEET":{"p":"/sliːt/","s":"n./v.","e":"[n.] Pellets of ice made of mostly frozen raindrops or refrozen melted snowflakes.\n[n.] A mixture of rain and snow.\n[n.] A smooth coating of ice formed on ground or other objects by freezing rain.\n[v.] (of the weather) To be in a state in which sleet is falling.","ex":"I won't bother going out until it's stopped sleeting."},"SLAYS":{"p":"","s":"v.","e":"[v.] To kill, murder.\n[v.] To eradicate or stamp out.\n[v.] (by extension) To defeat, overcome (in a competition or contest).","ex":"Our foes must all be slain."},"SLIME":{"p":"/slaɪm/","s":"n./v.","e":"[n.] Soft, moist earth or clay, having an adhesive quality; viscous mud; any substance of a dirty nature, that is moist, soft, and adhesive; bitumen; mud containing metallic ore, obtained in the preparatory dressing.\n[n.] Any mucilaginous substance; or a mucus-like substance which exudes from the bodies of certain animals, such as snails or slugs.\n[n.] A sneaky, unethical person; a slimeball.\n[v.] To coat with slime.\n[v.] To besmirch or disparage.\n[v.] To carve (fish), removing the offal.","ex":""},"SLIMY":{"p":"/ˈslaɪ.mi/","s":"n./adj.","e":"[n.] A ponyfish.\n[adj.] Of or pertaining to slime\n[adj.] Resembling, of the nature of, covered or daubed with, or abounding in slime\n[adj.] Friendly in a false, calculating way; underhanded; sneaky; slick; smarmy.","ex":""},"SLIP":{"p":"/slɪp/","s":"n.","e":"[n.] A thin, slippery mix of clay and water.\n[n.] Mud, slime.","ex":""},"SLICK":{"p":"/slɪk/","s":"n./v./adj.","e":"[n.] A covering of liquid, particularly oil.\n[n.] Someone who is clever and untrustworthy.\n[n.] A tool used to make something smooth or even.\n[v.] To make slick.\n[adj.] Slippery or smooth due to a covering of liquid; often used to describe appearances.\n[adj.] Appearing expensive or sophisticated.","ex":"Careful in turn three — there's an oil slick on the road."},"SLOOP":{"p":"/sluːp/","s":"n.","e":"[n.] A single-masted sailboat with only one headsail.\n[n.] A sailing warship, smaller than a frigate, with its guns all on one deck.\n[n.] A sloop-of-war, smaller than a frigate, larger than a corvette.","ex":""},"SLOBS":{"p":"","s":"n.","e":"[n.] A lazy and slovenly person.\n[n.] A lazy and obese person.","ex":""},"SLOGS":{"p":"","s":"n.","e":"[n.] A long, tedious walk, or session of work.\n[n.] An aggressive shot played with little skill.","ex":""},"SLUMP":{"p":"/slʌmp/","s":"n./v.","e":"[n.] A heavy or helpless collapse; a slouching or drooping posture; a period of poor activity or performance, especially an extended period.\n[n.] A measure of the fluidity of freshly mixed concrete, based on how much the concrete formed in a standard slump cone sags when the cone is removed.\n[n.] A boggy place.\n[v.] To collapse heavily or helplessly.\n[v.] To decline or fall off in activity or performance.\n[v.] To slouch or droop.","ex":"Exhausted, he slumped down onto the sofa."},"SLURS":{"p":"","s":"n./v.","e":"[n.] An insult or slight.\n[n.] A set of notes that are played legato, without separate articulation.\n[n.] The symbol indicating a legato passage, written as an arc over the slurred notes (not to be confused with a tie).\n[v.] To insult or slight.\n[v.] To run together; to articulate poorly.\n[v.] To play legato or without separate articulation; to connect (notes) smoothly.","ex":"a racial slur"},"SMELL":{"p":"/smɛl/","s":"n./v.","e":"[n.] A sensation, pleasant or unpleasant, detected by inhaling air (or, the case of water-breathing animals, water) carrying airborne molecules of a substance.\n[n.] The sense that detects odours.\n[n.] A conclusion or intuition that a situation is wrong, more complex than it seems, or otherwise inappropriate.\n[v.] To sense a smell or smells.\n[v.] Followed by like or of if descriptive: to have a particular smell, whether good or bad.\n[v.] (without a modifier) To smell bad; to stink.","ex":"I love the smell of fresh bread."},"SLUSH":{"p":"/slʌʃ/","s":"n./v.","e":"[n.] Half-melted snow or ice.\n[n.] Liquid mud or mire.\n[n.] Flavored shaved ice served as a drink.\n[v.] To smear with slushy liquid or grease.\n[v.] To slosh or splash; to move as, or through, a slushy or liquid substance.\n[v.] To paint with a mixture of white lead and lime.","ex":""},"SLUNK":{"p":"/slʌŋk/","s":"v./n.","e":"[v.] To sneak about furtively.\n[v.] To give birth to an animal prematurely.\n[n.] An animal, especially a calf, born prematurely or abortively.","ex":"a cow that slinks her calf"},"SLOTH":{"p":"/slɑθ/","s":"n./v.","e":"[n.] Laziness; slowness in the mindset; disinclination to action or labour.\n[n.] A herbivorous, arboreal South American mammal of the families Megalonychidae and Bradypodidae, noted for its slowness and inactivity.\n[n.] A collective term for a group of bears.\n[v.] To be idle; to idle (away time).","ex":""},"SMELT":{"p":"/ˈsmɛlt/","s":"n.","e":"[n.] Any small anadromous fish of the family Osmeridae, found in the Atlantic and Pacific Oceans and in lakes in North America and northern part of Europe.\n[n.] A fool; a simpleton.","ex":""},"SMIRK":{"p":"/smɜːk/","s":"n./v./adj.","e":"[n.] An uneven, often crooked smile that is insolent, self-satisfied or scornful\n[n.] A forced or affected smile; a simper\n[v.] To smile in a way that is affected, smug, insolent or contemptuous.\n[adj.] Smart; spruce; affected; simpering","ex":""},"SMOKING":{"p":"/ˈsməʊkɪŋ/","s":"v./adj.","e":"[v.] To inhale and exhale the smoke from a burning cigarette, cigar, pipe, etc.\n[v.] To inhale and exhale tobacco smoke.\n[v.] To give off smoke.\n[adj.] Giving off smoke.\n[adj.] Sexually attractive, usually referring to a woman.\n[adj.] Showing great skill or talent.","ex":"He's smoking his pipe."},"SMOKY":{"p":"/ˈsmoʊki/","s":"adj.","e":"[adj.] Filled with smoke.\n[adj.] Giving off smoke.\n[adj.] Of a colour or colour pattern similar to that of smoke.","ex":"a smoky cabin"},"SMOTE":{"p":"/sməʊt/","s":"v.","e":"[v.] To hit, to strike.\n[v.] To strike down or kill with godly force.\n[v.] To injure with divine power.","ex":""},"SNAIL":{"p":"/sneɪl/","s":"n./v.","e":"[n.] Any of very many animals (either hermaphroditic or nonhermaphroditic), of the class Gastropoda, having a coiled shell.\n[n.] (by extension) A slow person; a sluggard.\n[n.] A spiral cam, or a flat piece of metal of spirally curved outline, used for giving motion to, or changing the position of, another part, as the hammer tail of a striking clock.\n[v.] To move or travel very slowly.","ex":"The cars were snailing along the motorway during the rush hour."},"SNAFU":{"p":"","s":"n./v.","e":"[n.] A ridiculously chaotic situation.\n[n.] A major glitch or breakdown.\n[v.] To screw up or foul up.","ex":""},"SNAP":{"p":"/snæp/","s":"n./v./adj./int.","e":"[n.] A quick breaking or cracking sound or the action of producing such a sound.\n[n.] A sudden break.\n[n.] An attempt to seize, bite, attack, or grab.\n[v.] To fracture or break apart suddenly.\n[v.] To give forth or produce a sharp cracking noise; to crack.\n[v.] To attempt to seize with the teeth or bite.","ex":"He snapped his stick in anger."},"SNAKE":{"p":"/ˈsneɪk/","s":"n./v.","e":"[n.] A legless reptile of the sub-order Serpentes with a long, thin body and a fork-shaped tongue.\n[n.] A treacherous person.\n[n.] Somebody who acts deceitfully for social gain.\n[v.] To follow or move in a winding route.\n[v.] To steal slyly.\n[v.] To clean using a plumbing snake.","ex":"The path snaked through the forest."},"SNAKY":{"p":"","s":"adj.","e":"[adj.] Resembling or relating to snakes.\n[adj.] Windy; winding; twisty; sinuous, wavy.\n[adj.] Sly; cunning; deceitful.","ex":"Walking through the snaky passages I was soon completely lost."},"SNIPE":{"p":"/snaɪp/","s":"n./v.","e":"[n.] Any of various limicoline game birds of the genera Gallinago, Lymnocryptes and Coenocorypha in the family Scolopacidae, having a long, slender, nearly straight beak.\n[n.] A fool; a blockhead.\n[n.] A shot fired from a concealed place.\n[v.] To hunt snipe.\n[v.] To shoot at individuals from a concealed place.\n[v.] (by extension) To shoot with a sniper rifle.","ex":""},"SNIFF":{"p":"/snɪf/","s":"n./v./int.","e":"[n.] An instance of sniffing.\n[n.] A quantity of something that is inhaled through the nose\n[n.] A brief perception, or tiny amount.\n[v.] To make a short, audible inhalation, through the nose, as when smelling something.\n[v.] To say something while sniffing, for example in case of illness or unhappiness, or in contempt.\n[v.] To perceive vaguely","ex":"She gave the flowers a quick sniff to check they were real."},"SNIPS":{"p":"/snɪps/","s":"n./v.","e":"[n.] The act of snipping; cutting a small amount off of something.\n[n.] A single cut with scissors, clippers, or similar tool.\n[n.] Something acquired for a low price; a bargain.\n[v.] To cut with short sharp actions, as with scissors.\n[v.] To reduce the price of a product, to create a snip.\n[v.] To break off; to snatch away.","ex":"That wholesale lot on eBay was a snip at $10"},"SNICK":{"p":"/snɪk/","s":"n./v.","e":"[n.] A small deflection of the ball off the side of the bat; often carries to the wicketkeeper for a catch\n[n.] A small cut or mark.\n[n.] A knot or irregularity in yarn.\n[v.] To cut or snip.\n[v.] To hit (the ball) with the edge of the bat, causing a slight deflection.","ex":""},"SNITS":{"p":"","s":"n.","e":"[n.] A temper; a lack of patience; a bad mood.\n[n.] A U.S. unit of volume for liquor equal to 2 jiggers, 3 U.S. fluid ounces, or 88.7 milliliters.\n[n.] A beer chaser commonly served in three-ounce servings in highball or juice glasses with a Bloody Mary cocktail in the upper midwest states of United States including Minnesota, North Dakota, Wisconsin, Iowa, Michigan, and Illinois.","ex":"He's in a snit because he got passed over for promotion."},"SNIDE":{"p":"/snaɪd/","s":"n./adj.","e":"[n.] An underhanded, tricky person given to sharp practise; a sharper; a cheat.\n[n.] Counterfeit money\n[adj.] Disparaging or derisive in an insinuative way.\n[adj.] Tricky; deceptive; false; spurious; contemptible.","ex":"Don't make snide remarks to me."},"SNOOP":{"p":"/snuːp/","s":"n./v.","e":"[n.] The act of snooping\n[n.] One who snoops\n[n.] A private detective\n[v.] To be devious and cunning so as not to be seen.\n[v.] To secretly spy on or investigate, especially into the private personal life of others.","ex":"Be careful what you say around Gene because he's the bosses' snoop."},"SNORT":{"p":"/snɔɹt/","s":"n./v.","e":"[n.] The sound made by exhaling or inhaling roughly through the nose.\n[n.] A dose of a drug to be snorted. Here, \"drug\" includes snuff (i.e., pulverized tobacco).\n[n.] A consumed portion of alcoholic drink.\n[v.] To make a snort; to exhale roughly through the nose.\n[v.] To express or force out by snorting.\n[v.] To inhale (usually a drug) through the nose.","ex":"She snorted with laughter."},"SNORE":{"p":"/snɔː/","s":"n./v.","e":"[n.] The act of snoring, and the noise produced.\n[n.] An extremely boring person or event.\n[v.] To breathe during sleep with harsh, snorting noises caused by vibration of the soft palate.","ex":""},"SNOOT":{"p":"/snuːt/","s":"n./v.","e":"[n.] An elitist individual; one who looks down upon lower social classes.\n[n.] A language pedant or snob; one who practices linguistic elitism.\n[n.] A nose or snout, especially in derogatory use.\n[v.] To behave disdainfully toward.","ex":""},"SNOWS":{"p":"","s":"n./v.","e":"[n.] The frozen, crystalline state of water that falls as precipitation.\n[n.] Any similar frozen form of a gas or liquid.\n[n.] A snowfall; a blanket of frozen, crystalline water.\n[v.] To have snow fall from the sky.\n[v.] To hoodwink someone, especially by presenting confusing information.\n[v.] To bluff in draw poker by refusing to draw any cards.","ex":"We have had several heavy snows this year."},"SNOBS":{"p":"","s":"n.","e":"[n.] A person who wishes to be seen as a member of the upper classes and who looks down on those perceived to have inferior or unrefined tastes.\n[n.] A cobbler or shoemaker.\n[n.] A member of the lower classes; a commoner.","ex":""},"SNUCK":{"p":"/snʌk/","s":"v.","e":"[v.] To creep or go stealthily; to come or go while trying to avoid detection, as a person who does not wish to be seen.\n[v.] To take something stealthily without permission.\n[v.] (ditransitive) To stealthily bring someone something.","ex":"He decided to sneak into the kitchen for a second cookie while his mom was on the phone."},"SNOUT":{"p":"/snʌʊt/","s":"n./v.","e":"[n.] The long, projecting nose, mouth, and jaw of a beast, as of pigs.\n[n.] The front of the prow of a ship or boat.\n[n.] A person's nose.\n[v.] To furnish with a nozzle or point.","ex":"The pig rooted around in the dirt with its snout."},"SOCKET":{"p":"/ˈsɒkɪt/","s":"n./v.","e":"[n.] An opening into which a plug or other connecting part is designed to fit (e.g. a light bulb socket).\n[n.] A hollow into a bone which a part fits, such as an eye, or another bone, in the case of a joint.\n[n.] One endpoint of a two-way communication link, used for interprocess communication across a network.\n[v.] To place or fit in a socket.","ex":""},"SNOW":{"p":"/snəʊ/","s":"n./v.","e":"[n.] The frozen, crystalline state of water that falls as precipitation.\n[n.] Any similar frozen form of a gas or liquid.\n[n.] A snowfall; a blanket of frozen, crystalline water.\n[v.] To have snow fall from the sky.\n[v.] To hoodwink someone, especially by presenting confusing information.\n[v.] To bluff in draw poker by refusing to draw any cards.","ex":"We have had several heavy snows this year."},"SOARS":{"p":"","s":"n./v.","e":"[n.] The act of soaring.\n[n.] An upward flight.\n[v.] To fly high with little effort, like a bird.\n[v.] To mount upward on wings, or as on wings.\n[v.] To remain aloft by means of a glider or other unpowered aircraft.","ex":""},"SOCIAL":{"p":"/ˈsəʊʃəl/","s":"n./adj.","e":"[n.] A festive gathering to foster introductions.\n[n.] A dance held to raise money for a couple to be married.\n[n.] A dinner dance event, usually held annually by a company or sporting club.\n[adj.] Being extroverted or outgoing.\n[adj.] Of or relating to society.\n[adj.] Relating to social media or social networks.","ex":"They organized a social at the dance club to get people to know each other."},"SOCKS":{"p":"/sɒks/","s":"n./v.","e":"[n.] A knitted or woven covering for the foot.\n[n.] A shoe worn by Greco-Roman comedy actors.\n[n.] A color pattern (usually white) on a cat's or dog's lower leg that is different from the color pattern on the rest of the animal.\n[n.] A violent blow; a punch.\n[v.] To hit or strike violently; to deliver a blow to.\n[v.] To throw.","ex":""},"SOFT":{"p":"/sɑft/","s":"n./adj./adv./int.","e":"[n.] A soft or foolish person; an idiot.\n[n.] Ellipsis of soft tyre (A tyre whose compound is softer than mediums, and harder than supersofts.)\n[n.] A soft sound or part of a sound.\n[adj.] Easily giving way under pressure.\n[adj.] (of cloth or similar material) Smooth and flexible; not rough, rugged, or harsh.\n[adj.] (of a sound) Quiet.","ex":"My head sank easily into the soft pillow."},"SOLED":{"p":"","s":"v./adj.","e":"[v.] To pull by the ears; to pull about; haul; lug.\n[v.] To put a sole on (a shoe or boot)\n[adj.] (in combination) Having a specified kind of sole.","ex":"a rubber-soled shoe"},"SOILS":{"p":"","s":"n./v.","e":"[n.] A mixture of mineral particles and organic material, used to support plant growth.\n[n.] The unconsolidated mineral or organic material on the immediate surface of the earth that serves as a natural medium for the growth of land plants.\n[n.] The unconsolidated mineral or organic matter on the surface of the earth that has been subjected to and shows effects of genetic and environmental factors of: climate (including water and temperature effects), and macro- and microorganisms, conditioned by relief, acting on parent material over a period of time. A product-soil differs from the material from which it is derived in many physical, chemical, biological, and morphological properties and characteristics.\n[n.] Faeces or urine etc. when found on clothes.\n[n.] A bag containing soiled items.\n[v.] To make dirty.","ex":"Light colours soil sooner than dark ones."},"SOIL":{"p":"/sɔɪl/","s":"n.","e":"[n.] A mixture of mineral particles and organic material, used to support plant growth.\n[n.] The unconsolidated mineral or organic material on the immediate surface of the earth that serves as a natural medium for the growth of land plants.\n[n.] The unconsolidated mineral or organic matter on the surface of the earth that has been subjected to and shows effects of genetic and environmental factors of: climate (including water and temperature effects), and macro- and microorganisms, conditioned by relief, acting on parent material over a period of time. A product-soil differs from the material from which it is derived in many physical, chemical, biological, and morphological properties and characteristics.","ex":""},"SOLAR":{"p":"/ˈsəʊlə/","s":"adj.","e":"[adj.] Of or pertaining to the sun; proceeding from the sun\n[adj.] Born under the predominant influence of the sun.\n[adj.] Measured by the progress or revolution of the sun in the ecliptic; as, the solar year.","ex":"solar influence"},"SOME":{"p":"/sɐm/","s":"adv./pron.","e":"[adv.] Of a measurement: approximately, roughly.\n[pron.] A certain number, at least two.\n[pron.] An indefinite quantity.\n[pron.] An indefinite amount, a part.","ex":"I guess he must have weighed some 90 kilos."},"SOLVE":{"p":"/sɒlv/","s":"n./v.","e":"[n.] (chiefly law enforcement) A solution; an explanation.\n[v.] To find an answer or solution to a problem or question; to work out.\n[v.] To find the values of variables that satisfy a system of equations and/or inequalities.\n[v.] To algebraically manipulate an equation or inequality into a form that isolates a chosen variable on one side, so that the other side consists of an expression that may be used to generate solutions.","ex":""},"SOLES":{"p":"","s":"n.","e":"[n.] A wooden band or yoke put around the neck of an ox or cow in the stall.\n[n.] A pond or pool; a dirty pond of standing water.\n[n.] The bottom or plantar surface of the foot.\n[n.] (footwear) The bottom of a shoe or boot.\n[n.] The foot itself.","ex":""},"SONG":{"p":"/sɒŋ/","s":"n.","e":"[n.] A musical composition with lyrics for voice or voices, performed by singing.\n[n.] (by extension) Any musical composition.\n[n.] Poetical composition; poetry; verse.","ex":"Thomas listened to his favorite song on the radio yesterday."},"SOLOS":{"p":"","s":"n.","e":"[n.] A piece of music for one performer.\n[n.] A job or performance done by one person alone.\n[n.] (games) A card game similar to whist in which each player plays against the others in turn without a partner","ex":""},"SONIC":{"p":"/ˈsɒnɪk/","s":"adj.","e":"[adj.] Of or relating to sound.\n[adj.] Having a speed approaching that of the speed of sound in air.","ex":""},"SOMEHOW":{"p":"/ˈsʌmhaʊ/","s":"adv.","e":"[adv.] In one way or another; in a way not yet known or explained; by some means","ex":"This problem has to be tackled somehow."},"SONNY":{"p":"/ˈsʌni/","s":"n.","e":"[n.] A familiar form of address for a boy\n[n.] Form of address to a boy or man, to express contempt, warning etc.","ex":""},"SOON":{"p":"/suːn/","s":"adj./adv.","e":"[adj.] Short in length of time from the present.\n[adj.] Early\n[adv.] Immediately, instantly.\n[adv.] Within a short time; quickly.\n[adv.] Early.","ex":"I need the soonest date you have available."},"SORTS":{"p":"/sɔːts/","s":"n./v.","e":"[n.] A general type.\n[n.] Manner; form of being or acting.\n[n.] Condition above the vulgar; rank.\n[v.] To separate items into different categories according to certain criteria that determine their sorts.\n[v.] To arrange into some sequence, usually numerically, alphabetically or chronologically.\n[v.] To conjoin; to put together in distribution; to class.","ex":"Sort the letters in those bags into a separate pile for each language."},"SOPPY":{"p":"/ˈsɒpi/","s":"adj.","e":"[adj.] Very wet; sodden, soaked.\n[adj.] Sentimental, maudlin, schmaltzy.","ex":""},"SOOTH":{"p":"/suːθ/","s":"n./adj./adv.","e":"[n.] Truth.\n[n.] Augury; prognostication.\n[n.] Blandishment; cajolery.\n[adj.] True.\n[adj.] Pleasing; delightful; sweet.\n[adv.] In truth; indeed.","ex":""},"SORT":{"p":"/sɔːt/","s":"n.","e":"[n.] A general type.\n[n.] Manner; form of being or acting.\n[n.] Condition above the vulgar; rank.","ex":""},"SORER":{"p":"","s":"adj.","e":"[adj.] Causing pain or discomfort; painfully sensitive.\n[adj.] Sensitive; tender; easily pained, grieved, or vexed; very susceptible of irritation.\n[adj.] Dire; distressing.","ex":"Her feet were sore from walking so far."},"SORRY":{"p":"/ˈsɔɹi/","s":"n./adj./int.","e":"[n.] The act of saying sorry; an apology.\n[adj.] (of a person) Regretful for an action; grieved or saddened, especially by the loss of something or someone.\n[adj.] Poor, pitifully sad or regrettable.\n[adj.] Pathetic and inferior to the point of causing others disgust.\n[int.] Expresses regret, remorse, or sorrow.\n[int.] Used as a request for someone to repeat something not heard or understood clearly.","ex":"I am sorry I stepped on your toes. It was an accident."},"SOUGHT":{"p":"/sɔːt/","s":"v.","e":"[v.] To try to find; to look for; to search for.\n[v.] To ask for; to solicit; to beseech.\n[v.] To try to acquire or gain; to strive after; to aim at.","ex":"I seek wisdom."},"SOULS":{"p":"/səʊlz/","s":"n./v.","e":"[n.] The spirit or essence of a person usually thought to consist of one's thoughts and personality. Often believed to live on after the person's death.\n[n.] The spirit or essence of anything.\n[n.] Life, energy, vigor.\n[v.] To endow with a soul; to furnish with a soul or mind.\n[v.] To beg on All Soul's Day.\n[v.] To afford suitable sustenance.","ex":""},"SOUPS":{"p":"","s":"n./v.","e":"[n.] Any of various dishes commonly made by combining liquids, such as water or stock with other ingredients, such as meat and vegetables, that contribute flavor and texture.\n[n.] Any mixture or substance suggestive of soup consistency.\n[v.] To feed: to provide with soup or a meal.\n[v.] To develop (film) in a (chemical) developing solution.\n[v.] Alternative form of sup\n[n.] Alternative form of sup","ex":"Pho is a traditional Vietnamese soup."},"SOUTH":{"p":"/sæoθ/","s":"n./v./adj./adv.","e":"[n.] One of the four major compass points, specifically 180°, directed toward the South Pole, and conventionally downwards on a map, abbreviated as S.\n[n.] The side of a church on the right hand of a person facing the altar.\n[v.] To turn or move toward the south; to veer toward the south.\n[v.] To come to the meridian; to cross the north and south line.\n[adj.] Toward the south; southward.\n[adj.] (of wind) from the south.","ex":"The moon souths at nine."},"SOURS":{"p":"","s":"n./v.","e":"[n.] The sensation of a sour taste.\n[n.] A drink made with whiskey, lemon or lime juice and sugar.\n[n.] (by extension) Any cocktail containing lemon or lime juice.\n[v.] To make sour.\n[v.] To become sour.\n[v.] To spoil or mar; to make disenchanted.","ex":"Too much lemon juice will sour the recipe."},"SPADE":{"p":"/speɪd/","s":"n./v.","e":"[n.] A garden tool with a handle and a flat blade for digging. Not to be confused with a shovel which is used for moving earth or other materials.\n[n.] A playing card marked with the symbol ♠.\n[n.] A black person.\n[v.] To turn over soil with a spade to loosen the ground for planting.","ex":"I've got only one spade in my hand."},"SPARK":{"p":"/spɑːk/","s":"n./v.","e":"[n.] A small particle of glowing matter, either molten or on fire.\n[n.] A short or small burst of electrical discharge.\n[n.] A small, shining body, or transient light; a sparkle.\n[v.] To trigger, kindle into activity (an argument, etc).\n[v.] To light; to kindle.\n[v.] To give off a spark or sparks.","ex":""},"SPASM":{"p":"/ˈspæz.əm/","s":"n./v.","e":"[n.] A sudden, involuntary contraction of a muscle, a group of muscles, or a hollow organ.\n[n.] A violent, excruciating seizure of pain.\n[n.] A sudden and temporary burst of energy, activity, or emotion.\n[v.] To produce and undergo a spasm.","ex":""},"SPATS":{"p":"","s":"n.","e":"[n.] (often in the plural) A covering or decorative covering worn over a shoe.\n[n.] A piece of bodywork that covers the upper portions of the rear tyres of a car.\n[n.] A brief argument, falling out, quarrel.\n[n.] A light blow with something flat.\n[n.] An obsolete unit of distance in astronomy (symbol S), equal to one billion kilometres.\n[n.] A stiff legging worn over the instep and ankles of a shoe.","ex":"get into a trivial spat over punctuality"},"SPANK":{"p":"/spæŋk/","s":"n./v.","e":"[n.] An instance of spanking, separately or part of a multiple blows-beating; a smack, swat, or slap.\n[n.] A slapping sound, as produced by spanking.\n[v.] To beat, smack or slap a person's buttocks, with the bare hand or other object, as punishment, gesture, or form of sexual interaction.\n[v.] To soundly defeat, to trounce.\n[v.] To hit very hard","ex":""},"SPARE":{"p":"/ˈspɛə(ɹ)/","s":"n./adj.","e":"[n.] The act of sparing; moderation; restraint.\n[n.] Parsimony; frugal use.\n[n.] An opening in a petticoat or gown; a placket.\n[adj.] Scant; not abundant or plentiful.\n[adj.] Sparing; frugal; parsimonious; not spending much money.\n[adj.] Being more than what is necessary, or what must be used or reserved; not wanted, or not used; superfluous.","ex":"a spare diet"},"SPARS":{"p":"","s":"n./v.","e":"[n.] A rafter of a roof.\n[n.] A thick pole or piece of wood.\n[n.] A bar of wood used to fasten a door.\n[v.] To bolt, bar.\n[v.] To supply or equip (a vessel) with spars.\n[n.] A sparring session; a preliminary fight, as in boxing or cock-fighting.","ex":""},"SPEAK":{"p":"/spiːk/","s":"n./v.","e":"[n.] A low class bar, a speakeasy.\n[n.] Language, jargon, or terminology used uniquely in a particular environment or group.\n[n.] Speech, conversation.\n[v.] To communicate with one's voice, to say words out loud.\n[v.] To have a conversation.\n[v.] (by extension) To communicate or converse by some means other than orally, such as writing or facial expressions.","ex":"Corporate speak; IT speak."},"SPATE":{"p":"/speɪt/","s":"n.","e":"[n.] A river flood; an overflow or inundation.\n[n.] (by extension) A sudden rush or increase.","ex":""},"SPECIAL":{"p":"/ˈspɛ.ʃəl/","s":"n./v./adj.","e":"[n.] A reduction in consumer cost (usually for a limited time) for items or services rendered.\n[n.] One of a rotation of meals systematically offered for a lower price at a restaurant.\n[n.] Unusual or exceptional episode of a series.\n[v.] (nursing) To supervise a patient one-on-one.\n[adj.] Distinguished by a unique or unusual quality.\n[adj.] Of particular personal interest or value; dear; beloved.","ex":"We're running a special on turkey for Thanksgiving."},"SPEND":{"p":"/spɛnd/","s":"n./v.","e":"[n.] Amount of money spent (during a period); expenditure.\n[n.] (in the plural) Expenditures; money or pocket money.\n[n.] Discharged semen.\n[v.] To pay out (money).\n[v.] To bestow; to employ; often with on or upon.\n[v.] To squander.","ex":"I’m sorry, boss, but the advertising spend exceeded the budget again this month."},"SPEAR":{"p":"/spɪɹ/","s":"n./v./adj.","e":"[n.] A long stick with a sharp tip used as a weapon for throwing or thrusting, or anything used to make a thrusting motion.\n[n.] A soldier armed with such a weapon; a spearman.\n[n.] A lance with barbed prongs, used by fishermen to retrieve fish.\n[v.] To pierce with a spear.\n[v.] (by extension) To penetrate or strike with, or as if with, any long narrow object; to make a thrusting motion that catches an object on the tip of a long device.\n[v.] To shoot into a long stem, as some plants do.","ex":"a spear counterpart"},"SPECS":{"p":"/spɛks/","s":"n.","e":"[n.] Two similar or identical things taken together; often followed by of.\n[n.] Two people in a relationship, partnership or friendship.\n[n.] Used with binary nouns (often in the plural to indicate multiple instances, since such nouns are plural only, except in some technical contexts)\n[n.] A special place (for hiding or viewing)\n[n.] A spectacular mark (catch) in Australian rules football.\n[n.] A reduction in consumer cost (usually for a limited time) for items or services rendered.","ex":"I couldn't decide which of the pair of designer shirts I preferred, so I bought the pair."},"SPELL":{"p":"/spɛl/","s":"n./v.","e":"[n.] Words or a formula supposed to have magical powers.\n[n.] A magical effect or influence induced by an incantation or formula.\n[n.] Speech, discourse.\n[v.] To put under the influence of a spell; to affect by a spell; to bewitch; to fascinate; to charm.","ex":"He cast a spell to cure warts."},"SPICE":{"p":"/spaɪs/","s":"n./v.","e":"[n.] Aromatic or pungent plant matter (usually dried) used to season or flavour food.\n[n.] Appeal, interest; an attribute that makes something appealing, interesting, or engaging.\n[n.] A synthetic cannabinoid drug.\n[v.] To add spice or spices to; season.\n[v.] To spice up.","ex":""},"SPEWS":{"p":"","s":"v.","e":"[v.] To eject forcibly and in a stream\n[v.] To speak or write quickly and voluminously, especially words that are not worth listening to or reading.\n[v.] To vomit","ex":""},"SPICY":{"p":"","s":"adj.","e":"[adj.] Of, pertaining to, or containing spice.\n[adj.] (of flavors) Provoking a burning sensation due to the presence of chilis or similar hot spices\n[adj.] (of flavors or odors) Tangy, zesty, or pungent.","ex":"He prepared a spicy casserole."},"SPIKE":{"p":"/spaɪk/","s":"n./v.","e":"[n.] In a violin-family instrument, the carved wooden plug which sits in the bottom block of the instrument.\n[n.] The spike of a cello or double bass that makes contact with the floor and supports the weight of the instrument.\n[n.] A sort of very large nail.\n[n.] A piece of pointed metal etc. set with points upward or outward.\n[n.] Anything resembling such a nail in shape.\n[v.] To fasten with spikes, or long, large nails.","ex":"The trap was lined with spikes."},"SPITZ":{"p":"","s":"n.","e":"[n.] Any of several Nordic breeds of dog such as the Pomeranian or Samoyed","ex":""},"SPIT":{"p":"/spɪt/","s":"n./v.","e":"[n.] A thin metal or wooden rod on which meat is skewered for cooking, often over a fire.\n[n.] A generally low, narrow, pointed, usually sandy peninsula.\n[v.] To impale on a spit; to pierce with a sharp object.\n[v.] To use a spit to cook; to attend to food that is cooking on a spit.","ex":"to spit a loin of veal"},"SPIES":{"p":"/spaɪz/","s":"n./v.","e":"[n.] A person who secretly watches and examines the actions of other individuals or organizations and gathers information on them (usually to gain an advantage).\n[v.] To act as a spy.\n[v.] To spot; to catch sight of.\n[v.] To search narrowly; to scrutinize.","ex":"During the Cold War, Russia and America would each spy on each other for recon."},"SPITS":{"p":"","s":"n./v.","e":"[n.] A sudden impact or blow.\n[n.] The shock and noise produced by violently closing a door or other object.\n[n.] A slam dunk.\n[n.] A type of card game, also called ruff and honours.\n[n.] A card game, played all at once without separate turns, in which players attempt to get rid of their cards as quickly as possible according to certain rules.\n[n.] Losing or winning all the tricks in a game.","ex":"to spit a loin of veal"},"SPLAY":{"p":"/spleɪ/","s":"n./v./adj.","e":"[n.] A slope or bevel, especially of the sides of a door or window, by which the opening is made larger at one face of the wall than at the other, or larger at each of the faces than it is between them.\n[v.] To spread; spread out.\n[v.] To dislocate, as a shoulder bone.\n[v.] To turn on one side; to render oblique; to slope or slant, as the side of a door, window etc.\n[adj.] Spread out; turned outward.\n[adj.] Flat and ungainly.","ex":"to sit splay-legged"},"SPOOF":{"p":"/spuːf/","s":"n./v./adj.","e":"[n.] An act of deception; a hoax; a joking prank.\n[n.] A light parody.\n[n.] A drinking game in which players hold up to three (or another specified number of) coins hidden in a fist and attempt to guess the total number of coins held.\n[v.] To gently satirize.\n[v.] To deceive.\n[v.] To falsify.","ex":""},"SPOKEN":{"p":"/ˈspoʊkən/","s":"v./adj.","e":"[v.] To communicate with one's voice, to say words out loud.\n[v.] To have a conversation.\n[v.] (by extension) To communicate or converse by some means other than orally, such as writing or facial expressions.\n[adj.] Relating to speech\n[adj.] Speaking in a specified way","ex":"I was so surprised I couldn't speak."},"SPURN":{"p":"/spɜːn/","s":"n./v.","e":"[n.] An act of spurning; a scornful rejection.\n[n.] A kick; a blow with the foot.\n[n.] Disdainful rejection; contemptuous treatment.\n[v.] To reject disdainfully; contemn; scorn.\n[v.] To reject something by pushing it away with the foot.\n[v.] To waste; fail to make the most of (an opportunity)","ex":""},"SQUAB":{"p":"/ˈskwɒb/","s":"n./v./adj./adv.","e":"[n.] (sometimes attributive) A baby pigeon, dove, or chicken.\n[n.] The meat of such a baby bird used as food.\n[n.] A baby rook.\n[v.] To fall plump; to strike at one dash, or with a heavy stroke.\n[v.] To furnish with squabs, or cushions.\n[v.] To stuff thickly and sew through, the stitches being concealed by buttons, etc.","ex":"a squab pigeon"},"SWAMI":{"p":"/ˈswɑː.mi/","s":"n.","e":"[n.] (used as a title) A Hindu ascetic or religious teacher.","ex":""},"SWANK":{"p":"/swæŋk/","s":"n./v./adj.","e":"[n.] A fashionably elegant person.\n[n.] Ostentation; bravado.\n[v.] To swagger, to show off.\n[adj.] Fashionably elegant, posh.","ex":"He's such a swank."},"SWARM":{"p":"/swɔːm/","s":"n./v.","e":"[n.] A large number of insects, especially when in motion or (for bees) migrating to a new colony.\n[n.] A mass of people, animals or things in motion or turmoil.\n[n.] A group of nodes sharing the same torrent in a BitTorrent network.\n[v.] To move as a swarm.\n[v.] To teem, or be overrun with insects, people, etc.\n[v.] To fill a place as a swarm.","ex":"a swarm of meteorites"},"SWANS":{"p":"","s":"n./v.","e":"[n.] Any of various species of large, long-necked waterfowl, of genus Cygnus (bird family: Anatidae), most of which have white plumage.\n[n.] One whose grace etc. suggests a swan.\n[n.] This bird used as a heraldic charge, sometimes with a crown around its neck (e. g. the arms of Buckinghamshire).\n[v.] To travel or move about in an aimless, idle, or pretentiously casual way.\n[v.] To declare (chiefly in first-person present constructions).","ex":""},"SWELL":{"p":"/swɛl/","s":"v.","e":"[v.] To become bigger, especially due to being engorged.\n[v.] To cause to become bigger.\n[v.] To grow gradually in force or loudness.","ex":"Rains and dissolving snow swell the rivers in spring."},"SWIM":{"p":"/swɪm/","s":"n./v.","e":"[n.] An act or instance of swimming.\n[n.] The sound, or air bladder, of a fish.\n[n.] A part of a stream much frequented by fish.\n[v.] To move through the water, without touching the bottom; to propel oneself in water by natural means.\n[v.] To become immersed in, or as if in, or flooded with, or as if with, a liquid\n[v.] To move around freely because of excess space.","ex":"I'm going for a swim."},"SWIRL":{"p":"/swɜːl/","s":"n./v.","e":"[n.] A whirling eddy.\n[n.] A twist or coil of something.\n[n.] The upward rushing of a fish through the water to take the bait.\n[v.] To twist or whirl, as an eddy.\n[v.] To be arranged in a twist, spiral or whorl.\n[v.] To circulate.","ex":"I swirled my brush around in the paint."},"SWITCH":{"p":"/swɪtʃ/","s":"n./v./adj.","e":"[n.] A bundle of thin sticks, typically made of wood, sometimes bond in such a way that binding can be moved so that it varies the tightness of the binding.\n[n.] A device to turn electric current on and off or direct its flow.\n[n.] A change or exchange.\n[n.] A movable section of railroad track which allows the train to be directed down one of two destination tracks; (set of) points.\n[v.] To exchange.\n[v.] To change (something) to the specified state using a switch.","ex":"I want to switch this red dress for a green one."},"SWOON":{"p":"/swuːn/","s":"n.","e":"[n.] A faint.\n[n.] An infatuation.","ex":""},"SWORE":{"p":"/swɔː/","s":"v.","e":"[v.] To take an oath, to promise.\n[v.] To use offensive, profane, or obscene language.","ex":""},"SWUNG":{"p":"/ˈswʌŋ/","s":"v.","e":"[v.] To rotate about an off-centre fixed point.\n[v.] To dance.\n[v.] To ride on a swing.","ex":"The plant swung in the breeze."},"SWORN":{"p":"/swɔːn/","s":"v./adj.","e":"[v.] To take an oath, to promise.\n[v.] To use offensive, profane, or obscene language.\n[adj.] Given or declared under oath.\n[adj.] Bound as though by an oath.\n[adj.] Ardent, devout.","ex":"His sworn statement convinced the judge."},"SYNOD":{"p":"/ˈsɪn.əd/","s":"n.","e":"[n.] An ecclesiastic council or meeting to consult on church matters.\n[n.] An administrative division of churches, either the entire denomination, as in the Lutheran Church–Missouri Synod, or a mid-level division (middle judicatory, district) as in the Evangelical Lutheran Church in America\n[n.] An assembly or council having civil authority; a legislative body.","ex":""},"TACOS":{"p":"","s":"n./v.","e":"[n.] A Mexican snack food; a small tortilla (soft or hard shelled), with typically some type of meat, rice, beans, cheese, diced vegetables (usually tomatoes and lettuce, as served in the United States, and cilantro, onion, and avocado, as served in México) and salsa.\n[n.] The vulva.\n[n.] A yellow stain on a shirt armpit caused by sweat or deodorant.\n[v.] To fold or cause to buckle in half, similar to the way a taco is folded.","ex":""},"TAFFY":{"p":"/ˈtæ.fi/","s":"n.","e":"[n.] A soft, chewy candy made from boiled molasses or brown sugar.\n[n.] Flattery.","ex":""},"TAILS":{"p":"/teɪlz/","s":"n./v.","e":"[n.] The caudal appendage of an animal that is attached to its posterior and near the anus.\n[n.] An object or part of an object resembling a tail in shape, such as the thongs on a cat-o'-nine-tails.\n[n.] The back, last, lower, or inferior part of anything.\n[v.] To follow and observe surreptitiously.\n[v.] To hold by the end; said of a timber when it rests upon a wall or other support; with in or into\n[v.] To swing with the stern in a certain direction; said of a vessel at anchor.","ex":"Most primates have a tail and fangs."},"TAKER":{"p":"/ˈteɪkɚ/","s":"n.","e":"[n.] One who takes something.\n[n.] A person or thing that takes or receives, often more than he or she gives.\n[n.] One who is willing to participate in, or buy, something.","ex":"She is known as quite a risk taker."},"TAKE":{"p":"/teɪk/","s":"n./v.","e":"[n.] The or an act of taking.\n[n.] Something that is taken; a haul.\n[n.] An interpretation or view, opinion or assessment; perspective.\n[v.] To get into one's hands, possession or control, with or without force.\n[v.] To receive or accept (something) (especially something given or bestowed, awarded, etc).\n[v.] To remove.","ex":"What's your take on this issue, Fred?"},"TALE":{"p":"/ˈteɪl/","s":"n.","e":"[n.] An account of an asserted fact or circumstance; a rumour; a report, especially an idle or malicious story; a piece of gossip or slander; a lie.\n[n.] A rehearsal of what has occurred; narrative; discourse; statement; history; story.\n[n.] A number told or counted off; a reckoning by count; an enumeration.","ex":"Don't tell tales!"},"TAKING":{"p":"/ˈteɪkɪŋ/","s":"v./n./adj.","e":"[v.] To get into one's hands, possession or control, with or without force.\n[v.] To receive or accept (something) (especially something given or bestowed, awarded, etc).\n[v.] To remove.\n[n.] The act by which something is taken.\n[n.] A seizure of someone's goods or possessions.\n[n.] A state of mental distress, resulting in excited or erratic behavior (in the expression in a taking).","ex":"I'll take that plate off the table."},"TALES":{"p":"/teɪlz/","s":"n.","e":"[n.] Any of several units of measure used in China and elsewhere in eastern Asia, approximately 40 grams.\n[n.] Any of several monetary units equal to the equivalent weight in silver.\n[n.] Leung, a traditional unit of weight, in modern usage legally defined as 1/16 of a catty or kan (斤) or 0.0377993638 kilograms\n[n.] An account of an asserted fact or circumstance; a rumour; a report, especially an idle or malicious story; a piece of gossip or slander; a lie.\n[n.] A rehearsal of what has occurred; narrative; discourse; statement; history; story.\n[n.] A number told or counted off; a reckoning by count; an enumeration.","ex":"Don't tell tales!"},"TAMER":{"p":"/ˈteɪmɚ/","s":"adj./n.","e":"[adj.] Not or no longer wild; domesticated\n[adj.] (chiefly of animals) Mild and well-behaved; accustomed to human contact\n[adj.] Not exciting.\n[n.] One who tames or subdues.","ex":"They have a tame wildcat."},"TAMPS":{"p":"","s":"v.","e":"[v.] (blasting) To plug up with clay, earth, dry sand, sod, or other material, as a hole bored in a rock.\n[v.] To drive in or pack down by frequent gentle strokes\n[v.] To reduce the intensity of.","ex":"Tamp earth so as to make a smooth place."},"TALON":{"p":"/ˈtælən/","s":"n.","e":"[n.] A sharp, hooked claw of a bird of prey or other predatory animal.\n[n.] One of certain small prominences on the hind part of the face of an elephant's tooth.\n[n.] A kind of moulding, concave at the bottom and convex at the top; an ogee. (When the concave part is at the top, it is called an inverted talon.)","ex":""},"TALL":{"p":"/tɔːl/","s":"n./adj.","e":"[n.] (possibly nonstandard) Someone or something that is tall.\n[adj.] (of a person) Having a vertical extent greater than the average. For example, somebody with a height of over 6 feet would generally be considered to be tall.\n[adj.] (of a building, etc.) Having its top a long way up; having a great vertical (and often greater than horizontal) extent; high.\n[adj.] (of a story) Hard to believe, such as a tall story or a tall tale.","ex":"Being tall is an advantage in basketball."},"TANGS":{"p":"","s":"n.","e":"[n.] A refreshingly sharp aroma or flavor.\n[n.] A strong or offensive taste; especially, a taste of something extraneous to the thing itself.\n[n.] A sharp, specific flavor or tinge.\n[n.] A sharp, twanging sound; an unpleasant tone; a twang.\n[n.] Knotted wrack, Ascophyllum nodosum (coarse blackish seaweed)\n[n.] The vagina.","ex":"Wine or cider has a tang of the cask."},"TANK":{"p":"/tæŋk/","s":"n./v.","e":"[n.] A closed container for liquids or gases.\n[n.] An open container or pool for storing water or other liquids.\n[n.] A pond, pool, or small lake, natural or artificial.\n[v.] To fail or fall (often used in describing the economy or the stock market); to degenerate or decline rapidly; to plummet.\n[v.] To attract the attacks of an enemy target in cooperative team-based combat, so that one's teammates can defeat the enemy in question more efficiently.\n[v.] To put (fuel, etc.) into a tank.","ex":""},"TARDY":{"p":"/ˈtɑːdi/","s":"n./v./adj.","e":"[n.] A piece of paper given to students who are late to class.\n[n.] An instance of a student being marked as tardy by a teacher in his or her attendance sheet.\n[v.] To make tardy.\n[adj.] Late; overdue or delayed.\n[adj.] Moving with a slow pace or motion; not swift.\n[adj.] Ineffectual; slow-witted, slow to act, or dull.","ex":"The teacher gave her a tardy because she did not come into the classroom until after the bell."},"TAMES":{"p":"/teɪmz/","s":"v.","e":"[v.] To make (an animal) tame; to domesticate.\n[v.] To become tame or domesticated.\n[v.] To make gentle or meek.\n[v.] To broach or enter upon; to taste, as a liquor; to divide; to distribute; to deal out.","ex":"He tamed the wild horse."},"TAROT":{"p":"/ˈtɛɹoʊ/","s":"n.","e":"[n.] (singular or plural) A card game played in various different variations.\n[n.] Any of the set of 78 playing cards (divided into five suits, including one of permanent trumps), often used for mystical divination.","ex":""},"TARTS":{"p":"","s":"n./v.","e":"[n.] A type of small open pie, or piece of pastry, containing jelly or conserve; a sort of fruit pie.\n[n.] A prostitute.\n[n.] By extension, any woman with loose sexual morals.\n[v.] To practice prostitution\n[v.] To practice promiscuous sex\n[v.] To dress garishly, ostentatiously, whorishly, or sluttily","ex":""},"TASTE":{"p":"/teɪst/","s":"n./v.","e":"[n.] One of the sensations produced by the tongue in response to certain chemicals; the quality of giving this sensation.\n[n.] The sense that consists in the perception and interpretation of this sensation.\n[n.] A small sample of food, drink, or recreational drugs.\n[v.] To sample the flavor of something orally.\n[v.] To have a taste; to excite a particular sensation by which flavour is distinguished.\n[v.] To experience.","ex":"He had a strange taste in his mouth."},"TAUNT":{"p":"/tɔːnt/","s":"n./v.","e":"[n.] A scornful or mocking remark; a jeer or mockery\n[v.] To make fun of (someone); to goad (a person) into responding, often in an aggressive manner.","ex":""},"TARPS":{"p":"","s":"n.","e":"[n.] A tarpaulin.","ex":""},"TASK":{"p":"/tɑːsk/","s":"n./v.","e":"[n.] A piece of work done as part of one’s duties.\n[n.] A difficult or tedious undertaking.\n[n.] An objective.\n[v.] To assign a task to, or impose a task on.\n[v.] To oppress with severe or excessive burdens; to tax.\n[v.] To charge, as with a fault.","ex":"On my first day in the office, I was tasked with sorting a pile of invoices."},"TAXES":{"p":"/ˈtæksɪz/","s":"n./v.","e":"[n.] Money paid to the government other than for transaction-specific goods and services.\n[n.] A burdensome demand.\n[n.] A task exacted from one who is under control; a contribution or service, the rendering of which is imposed upon a subject.\n[v.] To impose and collect a tax from (a person or company).\n[v.] To impose and collect a tax on (something).\n[v.] To make excessive demands on.","ex":"a heavy tax on time or health"},"TEALS":{"p":"","s":"n.","e":"[n.] Any of various small freshwater ducks of the genus Anas that are brightly coloured and have short necks.\n[n.] A dark, somewhat bluish-green colour; a dark cyan.","ex":""},"TEACH":{"p":"/tiːt͡ʃ/","s":"v.","e":"[v.] To show (someone) the way; to guide, conduct; to point, indicate.\n[v.] (ditransitive) To pass on knowledge to.\n[v.] To pass on knowledge, especially as one's profession; to act as a teacher.","ex":"‘The bliss is there’, mumbled the old man and taught to Heaven."},"TEAMS":{"p":"","s":"n./v.","e":"[n.] A set of draught animals, such as two horses in front of a carriage.\n[n.] Any group of people involved in the same activity, especially sports or work.\n[n.] A group of animals moving together, especially young ducks.\n[v.] To form a group, as for sports or work.\n[v.] (by extension) To go together well; to harmonize.\n[v.] To convey or haul with a team.","ex":"The IT manager leads a team of three software developers."},"TEDIOUS":{"p":"/ˈtiː.dɪəs/","s":"adj.","e":"[adj.] Boring, monotonous, time-consuming, wearisome.","ex":""},"TEEMS":{"p":"","s":"v.","e":"[v.] To be stocked to overflowing.\n[v.] To be prolific; to abound; to be rife.\n[v.] To bring forth young, as an animal; to produce fruit, as a plant; to bear; to be pregnant; to conceive; to multiply.\n[v.] To empty.\n[v.] To pour (especially with rain)\n[v.] To pour, as steel, from a melting pot; to fill, as a mould, with molten metal.","ex":"Fish teem in this pond."},"TEASE":{"p":"/tiːz/","s":"n./v.","e":"[n.] One who teases.\n[n.] A single act of teasing.\n[n.] One who deliberately arouses others (usually men) sexually with no intention of satisfying that arousal.\n[v.] To separate the fibres of a fibrous material.\n[v.] To comb (originally with teasels) so that the fibres all lie in one direction.\n[v.] To back-comb.","ex":""},"TEATS":{"p":"","s":"n.","e":"[n.] The projection of a mammary gland from which, on female mammals, milk is secreted.\n[n.] Something resembling a teat, such as a small protuberance or nozzle.\n[n.] An artificial nipple used for bottle-feeding infants.","ex":""},"TECHS":{"p":"","s":"n.","e":"[n.] Technology\n[n.] Technician\n[n.] Technique","ex":""},"TEARY":{"p":"/ˈtɪəɹi/","s":"adj.","e":"[adj.] Of a person, having eyes filled with tears; inclined to cry.\n[adj.] Of eyes, filled with tears.","ex":"No wonder Ryan was teary; he missed his parents."},"TELLS":{"p":"/tɛlz/","s":"n./v.","e":"[n.] A reflexive, often habitual behavior, especially one occurring in a context that often features attempts at deception by persons under psychological stress (such as a poker game or police interrogation), that reveals information that the person exhibiting the behavior is attempting to withhold.\n[n.] That which is told; a tale or account.\n[n.] A private message to an individual in a chat room; a whisper.\n[v.] (archaic outside of idioms) To count, reckon, or enumerate.\n[v.] To narrate.\n[v.] To convey by speech; to say.","ex":"All told, there were over a dozen.  Can you tell time on a clock?  He had untold wealth."},"TELEX":{"p":"/tɛlɛks/","s":"n./v.","e":"[n.] A communications system consisting of a network of teletypewriters.\n[n.] A message sent through such a network.\n[n.] The machine used to send and receive such messages.\n[v.] To send (a message) by telex.","ex":""},"TEND":{"p":"/tɛnd/","s":"v.","e":"[v.] (Old English law) To make a tender of; to offer or tender.\n[v.] (followed by a to-infinitive) To be likely, or probable to do something, or to have a certain habit or leaning.\n[v.] To contribute to or toward some outcome.","ex":"It tends to snow here in winter."},"TERMS":{"p":"/tɜːmz/","s":"n./v.","e":"[n.] That which limits the extent of anything; limit, extremity, bound, boundary.\n[n.] A chronological limitation or restriction.\n[n.] Any of the binding conditions or promises in a legal contract.\n[v.] To phrase a certain way; to name or call.\n[n.] A computer program that emulates a physical terminal.\n[n.] One whose employment has been terminated","ex":"\"Alright, look...we can spend the holidays with your parents, but this time it will be on my terms.\""},"TERRA":{"p":"/ˈtɛɹə/","s":"n.","e":"[n.] (astrogeology) A rough upland or mountainous region of the Moon with a relatively high albedo.","ex":""},"TESTS":{"p":"/tests/","s":"n./v.","e":"[n.] A challenge, trial.\n[n.] A cupel or cupelling hearth in which precious metals are melted for trial and refinement.\n[n.] (academia) An examination, given often during the academic term.\n[v.] To challenge.\n[v.] To refine (gold, silver, etc.) in a test or cupel; to subject to cupellation.\n[v.] To put to the proof; to prove the truth, genuineness, or quality of by experiment, or by some principle or standard; to try.","ex":"Climbing the mountain tested our stamina."},"THAN":{"p":"/ðæn/","s":"adv./prep./conj.","e":"[adv.] At that time; then.\n[prep.] Introduces a comparison, and is associated with comparatives, and with words such as more, less, and fewer. Typically, it seeks to measure the force of an adjective or similar description between two predicates.\n[conj.] Used in comparisons, to introduce the basis of comparison.\n[conj.] (obsolete outside dialectal, usually used with for) Because; for.","ex":"A player than whom none is more skillful."},"TEPEE":{"p":"","s":"n.","e":"[n.] Alternative form of teepee","ex":""},"THANKS":{"p":"/θæŋks/","s":"n./v./int.","e":"[n.] An expression of appreciation; a thought.\n[v.] To express gratitude or appreciation toward.\n[v.] To feel gratitude or appreciation toward.\n[v.] To credit or hold responsible.\n[n.] An expression of gratitude.\n[n.] Grateful feelings or thoughts.","ex":"She thanked him for the lift."},"THERM":{"p":"","s":"n.","e":"[n.] A former unit of heat equal to 100,000 British thermal units. Symbol: thm.","ex":""},"THEY":{"p":"/ðeɪ/","s":"pron.","e":"[pron.] (the third-person plural) A group of people, animals, plants or objects previously mentioned.\n[pron.] (the third-person singular, sometimes proscribed) A single person, previously mentioned, especially if of unknown or non-binary gender, but typically not if previously named and identified as male or female.\n[pron.] (indefinite pronoun, vague meaning) People; some people; people in general; someone, excluding the speaker.","ex":"Dogs may bark if they want to be fed."},"THEORY":{"p":"/ˈθiːəɹi/","s":"n.","e":"[n.] A description of an event or system that is considered to be accurate.\n[n.] Mental conception; reflection, consideration.\n[n.] A coherent statement or set of ideas that explains observed facts or phenomena and correctly predicts new facts or phenomena not previously observed, or which sets out the laws and principles of something known or observed; a hypothesis confirmed by observation, experiment etc.","ex":""},"THERE":{"p":"/ðeː(ɹ)/","s":"n./adv./pron./int.","e":"[n.] That place.\n[n.] That status; that position.\n[adv.] (location) In a place or location (stated, implied or otherwise indicated) at some distance from the speaker (compare here).\n[adv.] In that matter, relation, etc.; at that point, stage, etc., regarded as a distinct place.\n[adv.] (location) To or into that place; thither.\n[pron.] Used as an expletive subject of be in its sense of “exist”, with the semantic, usually indefinite subject being postponed or (occasionally) implied.","ex":"You rinse and de-string the green beans; I'll take it from there."},"THESE":{"p":"/ðiːz/","s":"pron.","e":"[pron.] The thing, item, etc. being indicated.","ex":"This isn't the item that I ordered."},"THETA":{"p":"/ˈθiːtə/","s":"n.","e":"[n.] The eighth letter of the Modern Greek alphabet, ninth in Old Greek: Θ, θ.\n[n.] The measure of an angle.\n[n.] The sensitivity of the value of a derivative with respect to time; the \"time decay\".","ex":""},"THINE":{"p":"/ðaɪn/","s":"pron.","e":"[pron.] Singular second person possessive pronoun; yours","ex":""},"THICK":{"p":"/θɪk/","s":"n./v./adj./adv.","e":"[n.] The thickest, or most active or intense, part of something.\n[n.] A thicket.\n[n.] A stupid person; a fool.\n[v.] To thicken.\n[adj.] Relatively great in extent from one surface to the opposite in its smallest solid dimension.\n[adj.] Measuring a certain number of units in this dimension.","ex":"It was mayhem in the thick of battle."},"THIEF":{"p":"/θiːf/","s":"n.","e":"[n.] One who carries out a theft.\n[n.] One who steals another person's property, especially by stealth and without using force or violence.\n[n.] A waster in the snuff of a candle.","ex":""},"THING":{"p":"/θɪŋ/","s":"n./v.","e":"[n.] That which is considered to exist as a separate entity, object, quality or concept.\n[n.] A word, symbol, sign, or other referent that can be used to refer to any entity.\n[n.] An individual object or distinct entity.\n[v.] To express as a thing; to reify.","ex":""},"THINS":{"p":"","s":"n./v.","e":"[n.] A loss or tearing of paper from the back of a stamp, although not sufficient to create a complete hole.\n[n.] Any food produced or served in thin slices.\n[v.] To make thin or thinner.\n[v.] To become thin or thinner.\n[v.] To dilute.","ex":"chocolate mint thins"},"THOUGH":{"p":"/ðəʊ/","s":"adv./conj.","e":"[adv.] Despite that; however.\n[adv.] (degree) Used to intensify statements or questions; indeed.\n[conj.] Despite the fact that; although.\n[conj.] If, that, even if.","ex":"I will do it, though."},"THREAT":{"p":"/θɹɛt/","s":"n.","e":"[n.] An expression of intent to injure or punish another.\n[n.] An indication of potential or imminent danger.\n[n.] A person or object that is regarded as a danger; a menace.","ex":""},"THORN":{"p":"/θɔːn/","s":"n./v.","e":"[n.] A sharp protective spine of a plant.\n[n.] Any shrub or small tree that bears thorns, especially a hawthorn.\n[n.] That which pricks or annoys; anything troublesome.\n[v.] To pierce with, or as if with, a thorn","ex":"the cockspur thorn"},"THIRTY":{"p":"/ˈθɜːti/","s":"n./num.","e":"[n.] A rack of thirty beers.\n[num.] The cardinal number occurring after twenty-nine and before thirty-one, represented in Arabic numerals as 30.","ex":""},"THREE":{"p":"/θɹiː/","s":"n./num.","e":"[n.] The digit/figure 3.\n[n.] Anything measuring three units, as length.\n[n.] A person who is three years old.\n[num.] A numerical value after two and before four. Represented in Arabic digits as 3; this many dots (•••).\n[num.] Describing a set or group with three elements.\n[n.] A goal or other means of scoring worth three points.","ex":"Put all the threes in a separate container."},"THROB":{"p":"/θɹɒb/","s":"n./v.","e":"[n.] A beating, vibration or palpitation.\n[v.] To pound or beat rapidly or violently.\n[v.] To vibrate or pulsate with a steady rhythm.\n[v.] (of a body part) To pulse (often painfully) in time with the circulation of blood.","ex":""},"THRUM":{"p":"/θɹʌm/","s":"n./v.","e":"[n.] A thrumming sound; a hum or vibration.\n[n.] A spicy taste; a tang.\n[v.] To cause a steady rhythmic vibration, usually by plucking.\n[v.] To make a monotonous drumming noise.","ex":"She watched as he thrummed the guitar strings absently."},"THUGS":{"p":"","s":"n.","e":"[n.] Someone with an intimidating and unseemly appearance and mannerisms, who treats others violently and roughly, often for hire.\n[n.] One of a band of assassins formerly active in northern India who worshipped Kali and offered their victims to her.\n[n.] In gardening, an over-vigorous plant that spreads and dominates the flowerbed.","ex":""},"THUMB":{"p":"/θʌm/","s":"n./v.","e":"[n.] The short thick digit of the hand that for humans has the most mobility and can be made to oppose (moved to touch) all of the other fingers.\n[n.] The part of a slider that may be moved linearly along the slider.\n[n.] A thumbnail picture.\n[v.] To touch or cover with the thumb.\n[v.] (with through) To turn the pages of (a book) in order to read it cursorily.\n[v.] (travel) To hitchhike","ex":"2001, \"Gary\", Wanna See Porn? Take a Look At These (Free Expandable Thumbs) - CLICK HERE (on newsgroup alt.sex.services)"},"TIDE":{"p":"/taɪd/","s":"n./v.","e":"[n.] The periodic change of the sea level, particularly when caused by the gravitational influence of the sun and the moon.\n[n.] A stream, current or flood.\n[n.] (chronology, except in liturgy) Time, notably anniversary, period or season linked to an ecclesiastical feast.\n[v.] To cause to float with the tide; to drive or carry with the tide or stream.\n[v.] To pour a tide or flood.\n[v.] To work into or out of a river or harbor by drifting with the tide and anchoring when it becomes adverse.","ex":"The ocean tided most impressively."},"TIFFS":{"p":"/tɪfs/","s":"n./v.","e":"[n.] A small argument; a petty quarrel.\n[n.] Liquor; especially, a small draught of liquor.\n[v.] To quarrel.\n[v.] To deck out; to dress.\n[v.] (British India) To have lunch.","ex":""},"THUDS":{"p":"","s":"n.","e":"[n.] The sound of a dull impact.\n[n.] Republic F-105 Thunderchief jet ground attack fighter.","ex":""},"TIDES":{"p":"","s":"n./v.","e":"[n.] The periodic change of the sea level, particularly when caused by the gravitational influence of the sun and the moon.\n[n.] A stream, current or flood.\n[n.] (chronology, except in liturgy) Time, notably anniversary, period or season linked to an ecclesiastical feast.\n[v.] To cause to float with the tide; to drive or carry with the tide or stream.\n[v.] To pour a tide or flood.\n[v.] To work into or out of a river or harbor by drifting with the tide and anchoring when it becomes adverse.","ex":"The ocean tided most impressively."},"TIERS":{"p":"","s":"n./v.","e":"[n.] One who ties (knots, etc).\n[n.] Something that ties.\n[n.] A child's apron.\n[n.] A layer or rank, especially of seats or a wedding cake.\n[v.] To arrange in layers.\n[v.] To cascade in an overlapping sequence.","ex":""},"TIGER":{"p":"/ˈtaɪɡə/","s":"n.","e":"[n.] Panthera tigris, a large predatory mammal of the cat family, indigenous to Asia.\n[n.] A representation of a large mythological cat, used on a coat of arms.\n[n.] A servant in livery, who rides with his master or mistress.","ex":""},"THUMP":{"p":"/θʌmp/","s":"n./v.","e":"[n.] A blow that produces a muffled sound.\n[n.] The sound of such a blow; a thud.\n[n.] Used to replace the vulgar or blasphemous element in \"what the hell\" and similar phrases.\n[v.] To hit (someone or something) as if to make a thump.\n[v.] To cause to make a thumping sound.\n[v.] To thud or pound.","ex":"Where the thump have you been?!"},"TILDE":{"p":"/ˈtɪldi/","s":"n.","e":"[n.] The grapheme of character ~.\n[n.] The character used to represent negation, usually ~ or ¬.","ex":""},"TILER":{"p":"","s":"n.","e":"[n.] A person who sets tiles.\n[n.] A doorkeeper or attendant at a lodge of Freemasons.","ex":""},"TIMID":{"p":"/ˈtɪmɪd/","s":"adj.","e":"[adj.] Lacking in courage or confidence.","ex":"John's a very timid person. I'll doubt he'll be brave enough to face his brother."},"TILES":{"p":"","s":"n./v.","e":"[n.] A regularly-shaped slab of clay or other material, affixed to cover or decorate a surface, as in a roof-tile, glazed tile, stove tile, carpet tile etc.\n[n.] A rectangular graphic.\n[n.] Any of various flat cuboid playing pieces used in certain games, such as dominoes, Scrabble, or mahjong.\n[v.] To cover with tiles.\n[v.] To arrange in a regular pattern, with adjoining edges (applied to tile-like objects, graphics, windows in a computer interface).\n[v.] To optimize (a loop in program code) by means of the tiling technique.","ex":"Each tile within Google Maps consists of 256 × 256 pixels."},"TIMED":{"p":"","s":"v./adj.","e":"[v.] To measure or record the time, duration, or rate of.\n[v.] To choose when something begins or how long it lasts.\n[v.] To keep or beat time; to proceed or move in time.\n[adj.] Happening at a certain time.\n[adj.] Regulated by time.","ex":"I used a stopwatch to time myself running around the block."},"TILLS":{"p":"","s":"n./v.","e":"[n.] A cash register.\n[n.] A removable box within a cash register containing the money.\n[n.] The contents of a cash register, for example at the beginning or end of the day or of a cashier's shift.\n[v.] To develop so as to improve or prepare for usage; to cultivate (said of knowledge, virtue, mind etc.).\n[v.] To work or cultivate or plough (soil); to prepare for growing vegetation and crops.\n[v.] To cultivate soil.","ex":"Pull all the tills and lock them in the safe."},"TIME":{"p":"/tɑem/","s":"n./v./int.","e":"[n.] The inevitable progression into the future with the passing of present and past events.\n[n.] A duration of time.\n[n.] An instant of time.\n[v.] To measure or record the time, duration, or rate of.\n[v.] To choose when something begins or how long it lasts.\n[v.] To keep or beat time; to proceed or move in time.","ex":"Time stops for nobody.   the ebb and flow of time"},"TIMING":{"p":"/ˈtaɪmɪŋ/","s":"v./n.","e":"[v.] To measure or record the time, duration, or rate of.\n[v.] To choose when something begins or how long it lasts.\n[v.] To keep or beat time; to proceed or move in time.\n[n.] An occurrence or event.\n[n.] The regulation of the pace of e.g. an athletic race, the speed of an engine, the delivery of a joke, or the occurrence of a series of events.\n[n.] The time when something happens.","ex":"I used a stopwatch to time myself running around the block."},"TIMBER":{"p":"/ˈtɪmbə/","s":"n./v./int.","e":"[n.] Trees in a forest regarded as a source of wood.\n[n.] (outside North America) Wood that has been pre-cut and is ready for use in construction.\n[n.] A heavy wooden beam, generally a whole log that has been squared off and used to provide heavy support for something such as a roof.\n[v.] To fit with timbers.\n[v.] To construct, frame, build.\n[v.] To light or land on a tree.","ex":"the timbers of a ship"},"TIRE":{"p":"/ˈtʌɪ̯ɚ/","s":"v.","e":"[v.] To become sleepy or weary.\n[v.] To make sleepy or weary.\n[v.] To become bored or impatient (with).","ex":"I tire of this book."},"TIMER":{"p":"/ˈtaɪmɚ/","s":"n.","e":"[n.] Someone or something which times.\n[n.] A device used to measure amounts of time.\n[n.] Any electronic function that causes a device to be able to do something automatically after a preset amount of time.","ex":""},"TINGE":{"p":"/tɪn(d)ʒ/","s":"n./v.","e":"[n.] A small added amount of colour; (by extension) a small added amount of some other thing.\n[n.] The degree of vividness of a colour; hue, shade, tint.\n[v.] To add a small amount of colour; to tint; (by extension) to add a small amount of some other thing.\n[v.] To affect or alter slightly, particularly due to the actual or metaphorical influence of some element or thing.\n[v.] To change slightly in shade due to the addition of colour; (by extension) to change slightly in quality due to the addition of some other thing.","ex":""},"TINY":{"p":"/ˈtaɪni/","s":"n./adj.","e":"[n.] A small child; an infant.\n[n.] Anything very small.\n[adj.] Very small.","ex":""},"TIZZY":{"p":"","s":"n.","e":"[n.] A state of nervous excitement, confusion, or distress; a dither.\n[n.] A sixpence; a tester.","ex":""},"TITAN":{"p":"/ˈtaɪtən/","s":"n.","e":"[n.] Something or someone of very large stature, greatness, or godliness.","ex":""},"TOADS":{"p":"","s":"n./v.","e":"[n.] An amphibian, a kind of frog (order Anura) with shorter hindlegs and a drier, wartier skin, many in family Bufonidae.\n[n.] A contemptible or unpleasant person.\n[n.] An ugly person.\n[v.] To expel (a user) permanently from a MUD or similar system, so that their account is deleted.","ex":""},"TOAST":{"p":"/təʊst/","s":"n.","e":"[n.] Toasted bread.\n[n.] A proposed salutation (e.g. to say \"cheers\") while drinking alcohol.\n[n.] A person, group, or notable object to which a salutation with alcohol is made; a person or group held in similar esteem.","ex":"I ate a piece of toast for breakfast."},"TIPSY":{"p":"/ˈtɪp.si/","s":"adj.","e":"[adj.] Slightly drunk, fuddled, staggering, foolish as a result of drinking alcoholic beverages\n[adj.] (metonymy) unsteady, askew","ex":""},"TITLE":{"p":"/ˈtaɪtl̩/","s":"n./v.","e":"[n.] A prefix (honorific) or suffix (post-nominal) added to a person's name to signify either veneration, official position or a professional or academic qualification. See also\n[n.] Legal right to ownership of a property; a deed or other certificate proving this.\n[n.] In canon law, that by which a beneficiary holds a benefice.\n[v.] To assign a title to; to entitle.","ex":"a good title to an estate, or an imperfect title"},"TOLLS":{"p":"","s":"n./v.","e":"[n.] Loss or damage incurred through a disaster.\n[n.] A fee paid for some liberty or privilege, particularly for the privilege of passing over a bridge or on a highway, or for that of vending goods in a fair, market, etc.\n[n.] A fee for using any kind of material processing service.\n[v.] To impose a fee for the use of.\n[v.] To levy a toll on (someone or something).\n[v.] To take as a toll.","ex":"The war has taken its toll on the people."},"TONAL":{"p":"/ˈtəʊnəl/","s":"adj.","e":"[adj.] Of or relating to tones or tonality.\n[adj.] Of or relating to the general character, mood, or trend of something.\n[adj.] Employing tones that have a predictable relationship to some tonic.","ex":""},"TOOL":{"p":"/tuːl/","s":"n./v.","e":"[n.] A mechanical device intended to make a task easier.\n[n.] Equipment used in a profession, e.g., tools of the trade.\n[n.] Something to perform an operation; an instrument; a means.\n[v.] To work on or shape with tools, e.g., hand-tooled leather.\n[v.] To equip with tools.\n[v.] To work very hard.","ex":"Hand me that tool, would you?   I don't have the right tools to start fiddling around with the engine."},"TORTS":{"p":"","s":"n.","e":"[n.] An injury or wrong.\n[n.] A wrongful act, whether intentional or negligent, which causes an injury and can be remedied in civil court, usually through the awarding of damages.\n[n.] (only in the plural torts) Tort law (the area of law dealing with such wrongful acts).\n[n.] A tortoise.\n[n.] A tortoiseshell (animal with coloured markings on fur).","ex":""},"TOWN":{"p":"/taʊn/","s":"n.","e":"[n.] A settlement; an area with residential districts, shops and amenities, and its own local government; especially one larger than a village and smaller than a city.\n[n.] Any more urbanized center than the place of reference.\n[n.] A rural settlement in which a market was held at least once a week.","ex":"This town is really dangerous because these youngsters have Beretta handguns."},"TRAIN":{"p":"/tɹeɪn/","s":"n./v.","e":"[n.] Elongated portion.\n[n.] Connected sequence of people or things.\n[v.] To practice an ability.\n[v.] To teach and form (someone) by practice; to educate (someone).\n[v.] To improve one's fitness.","ex":"She trained seven hours a day to prepare for the Olympics."},"TRAINER":{"p":"/ˈtɹeɪnə/","s":"n.","e":"[n.] A person who trains another; a coach.\n[n.] A person responsible for treating injuries sustained by players during matches; a physiotherapist.\n[n.] A running shoe or sneaker.","ex":""},"TRAIT":{"p":"/tɹeɪ/","s":"n.","e":"[n.] An identifying characteristic, habit or trend.\n[n.] An uninstantiable collection of methods that provides functionality to a class by using the class’s own interface.","ex":"The number one personality trait I hate is hypocrisy. Why can't you be consistent!?"},"TRASH":{"p":"/tɹæʃ/","s":"n./v.","e":"[n.] Useless things to be discarded; rubbish; refuse.\n[n.] A container into which things are discarded.\n[n.] Something worthless or of poor quality.\n[v.] To discard.\n[v.] To make into a mess.\n[v.] To beat soundly in a game.","ex":"The burglars trashed the house."},"TRAMS":{"p":"","s":"n./v.","e":"[n.] A passenger vehicle for public use that runs on tracks in the road (called a streetcar or trolley in North America).\n[n.] A similar vehicle for carrying materials.\n[n.] A people mover.\n[v.] To operate, or conduct the business of, a tramway.\n[v.] To travel by tram.\n[v.] To transport (material) by tram.","ex":""},"USED":{"p":"/juːzd/","s":"v./adj.","e":"[v.] To utilize or employ.\n[v.] To accustom; to habituate. (Now common only in participial form. Uses the same pronunciation as the noun; see usage notes.)\n[v.] (except in past tense) To habitually do; to be wont to do. (Now chiefly in past-tense forms; see used to.)\n[adj.] That is or has or have been used.\n[adj.] That has or have previously been owned by someone else.\n[adj.] Familiar through use; usual; accustomed.","ex":"soldiers who are used to hardships and danger"},"USURP":{"p":"/juːˈzɜːp/","s":"v.","e":"[v.] To seize power from another, usually by illegitimate means.\n[v.] To use and assume the coat of arms of another person.\n[v.] To take the place rightfully belonging to someone or something else.","ex":""},"VALET":{"p":"/ˈvæleɪ/","s":"n./v.","e":"[n.] A man's personal male attendant, responsible for his clothes and appearance.\n[n.] A hotel employee performing such duties for guests.\n[n.] (professional wrestling) A female performer in professional wrestling, acting as either a manager or personal chaperone; often used to attract and titillate male members of the audience.\n[v.] To serve (someone) as a valet.\n[v.] To clean and service (a car), as a valet does.\n[v.] To leave (a car) with a valet to park it.","ex":""},"VALLEY":{"p":"/ˈvæli/","s":"n.","e":"[n.] An elongated depression between hills or mountains, often with a river flowing through it.\n[n.] The area which drains into a river.\n[n.] Any structure resembling one, e.g., the meeting point of two pitched roofs.","ex":""},"VAMPS":{"p":"","s":"n./v.","e":"[n.] The top part of a boot or shoe, above the sole and welt and in front of the ankle seam, that covers the instep and toes; the front part of an upper; the analogous part of a stocking.\n[n.] Something added to give an old thing a new appearance.\n[n.] Something patched up, pieced together, improvised, or refurbished.\n[v.] To patch, repair, or refurbish.\n[v.] Often as vamp up: to fabricate or put together (something) from existing material, or by adding new material to something existing.\n[v.] To cobble together, to extemporize, to improvise.","ex":""},"VAPOR":{"p":"/ˈveɪpə/","s":"n./v.","e":"[n.] Cloudy diffused matter such as mist, steam or fumes suspended in the air.\n[n.] The gaseous state of a substance that is normally a solid or liquid.\n[n.] Something insubstantial, fleeting, or transitory; unreal fancy; vain imagination; idle talk; boasting.\n[v.] To become vapor; to be emitted or circulated as vapor.\n[v.] To turn into vapor.\n[v.] To emit vapor or fumes.","ex":"to vapor away a heated fluid"},"VALVE":{"p":"/ˈvælv/","s":"n./v.","e":"[n.] A device that controls the flow of a gas or fluid through a pipe.\n[n.] A device that admits fuel and air into the cylinder of an internal combustion engine, or one that allows combustion gases to exit.\n[n.] One or more membranous partitions, flaps, or folds, which permit the passage of the contents of a vessel or cavity in one direction, but stop or control the flow in the opposite direction\n[v.] To control (flow) by means of a valve.","ex":"the ileocolic, mitral, and semilunar valves"},"VARIETY":{"p":"/vəˈɹaɪ.ɪ.ti/","s":"n.","e":"[n.] The quality of being varied; diversity.\n[n.] A specific variation of something.\n[n.] A number of different things.","ex":"Variety is the spice of life."},"VEEPS":{"p":"/viːps/","s":"n.","e":"[n.] (US politics) The Vice President of the United States; the office of Vice President of the United States, especially during an election cycle where several are in the running for the nomination.\n[n.] Any vice president (in a corporation, organization, etc.)","ex":"She's running for veep."},"VAULT":{"p":"/vɒlt/","s":"n./v.","e":"[n.] An arched masonry structure supporting and forming a ceiling, whether freestanding or forming part of a larger building.\n[n.] Any arched ceiling or roof.\n[n.] Anything resembling such a downward-facing concave structure, particularly the sky and caves.\n[v.] To build as, or cover with a vault.","ex":""},"VAUNT":{"p":"/vɑːnt/","s":"n./v.","e":"[n.] A boast; an instance of vaunting.\n[v.] To speak boastfully.\n[v.] To speak boastfully about.\n[v.] To boast of; to make a vain display of; to display with ostentation.","ex":""},"VEERS":{"p":"","s":"n.","e":"[n.] A turn or swerve; an instance of veering.","ex":""},"VEHICLE":{"p":"/ˈvɪː(ə).kəl/","s":"n.","e":"[n.] A conveyance; a device for carrying or transporting substances, objects or individuals.\n[n.] A medium for expression of talent or views.\n[n.] A liquid content (e.g. oil) which acts as a binding and drying agent in paint. (FM 55-501).","ex":""},"VEILS":{"p":"","s":"n.","e":"[n.] Something hung up or spread out to hide or protect the face, or hide an object from view; usually of gauze, crepe, or similar diaphanous material.\n[n.] A cover; disguise; a mask; a pretense.\n[n.] The calyptra of mosses.","ex":""},"VELDS":{"p":"","s":"n.","e":"[n.] The open pasture land or grassland of South Africa and neighboring countries.","ex":""},"VERBS":{"p":"","s":"n./v.","e":"[n.] (grammar) A word that indicates an action, event, or state.\n[n.] Any word; a vocable.\n[n.] An action as opposed to a trait or thing.\n[v.] To use any word that is not, or had not been a verb (especially a noun) as if it were a verb.\n[v.] (used as a neutral, unspecific verb) To perform any action that is normally expressed by a verb.","ex":"The word “speak” is an English verb."},"VERGE":{"p":"/vɜːd͡ʒ/","s":"n.","e":"[n.] A rod or staff of office, e.g. of a verger.\n[n.] An edge or border.\n[n.] The phallus.","ex":""},"VENUE":{"p":"/ˈvɛnjuː/","s":"n.","e":"[n.] A theater, auditorium, arena, or other area designated for sporting or entertainment events.\n[n.] A neighborhood or near place; the place or county in which anything is alleged to have happened; also, the place where an action is laid, or the district from which a jury comes.\n[n.] A bout; a hit; a turn. See venew.","ex":""},"VERB":{"p":"/vɜːb/","s":"n./v.","e":"[n.] (grammar) A word that indicates an action, event, or state.\n[n.] Any word; a vocable.\n[n.] An action as opposed to a trait or thing.\n[v.] To use any word that is not, or had not been a verb (especially a noun) as if it were a verb.\n[v.] (used as a neutral, unspecific verb) To perform any action that is normally expressed by a verb.","ex":"The word “speak” is an English verb."},"VERSE":{"p":"/ˈvɜːs/","s":"n./v.","e":"[n.] A poetic form with regular meter and a fixed rhyme scheme.\n[n.] Poetic form in general.\n[n.] One of several similar units of a song, consisting of several lines, generally rhymed.\n[v.] To compose verses.\n[v.] To tell in verse, or poetry.\n[v.] To educate about, to teach about.","ex":"Restoration literature is well known for its carefully constructed verse."},"VERSO":{"p":"","s":"n.","e":"[n.] The back side of a flat object which is to be examined visually, as for reading, such as a sheet, leaf, coin or medal;\n[n.] The left-hand page of a book of a script which reads from left to right, usually having an even page number.","ex":""},"VERY":{"p":"/ˈvɛɹi/","s":"adj./adv.","e":"[adj.] True, real, actual.\n[adj.] The same; identical.\n[adj.] With limiting effect: mere.\n[adv.] To a great extent or degree.\n[adv.] Conforming to fact, reality or rule; true.\n[adv.] (with superlatives) Used to firmly establish that nothing else surpasses in some respect.","ex":"He tried his very best."},"VERVE":{"p":"/vɜː(r)v/","s":"n.","e":"[n.] Excitement of imagination such as that which animates a poet, artist, or musician, in composing or performing\n[n.] Artistic energy and enthusiasm\n[n.] Vigour, vitality and liveliness","ex":""},"VEXED":{"p":"/ˈvɛkst/","s":"v./adj.","e":"[v.] To trouble aggressively, to harass.\n[v.] To annoy, irritate.\n[v.] To cause (mental) suffering to; to distress.\n[adj.] Annoyed, irritated or distressed\n[adj.] Much debated, discussed or disputed","ex":"She became more and more vexed as she struggled to cope with the demands of the job."},"VICAR":{"p":"/ˈvɪkɚ/","s":"n.","e":"[n.] In the Church of England, the priest of a parish, receiving a salary or stipend but not tithes.\n[n.] In the Roman Catholic and some other churches, a cleric acting as local representative of a higher ranking member of the clergy.\n[n.] A person acting on behalf of, or representing, another person.","ex":""},"VIEW":{"p":"/vjuː/","s":"n./v.","e":"[n.] (physical) Visual perception.\n[n.] A picture, drawn or painted; a sketch.\n[n.] (psychological) Opinion, judgement, imagination.\n[v.] To look at.\n[v.] To regard in a stated way.","ex":"a fine view of Lake George"},"VIRUS":{"p":"/ˈvaɪɹəs/","s":"n.","e":"[n.] A submicroscopic, non-cellular structure consisting of a core of DNA or RNA surrounded by a protein coat, that requires a living host cell to replicate, and often causes disease in the host organism.\n[n.] A disease caused by these organisms.\n[n.] Venom, as produced by a poisonous animal etc.","ex":"He caught a virus and had to stay home from school."},"VISTA":{"p":"/ˈviːstə/","s":"n./v.","e":"[n.] A distant view or prospect, especially one seen through some opening, avenue or passage.\n[n.] A site offering such a view.\n[n.] A vision; a view presented to the mind in prospect or in retrospect by the imagination.\n[v.] To make a vista or landscape of.","ex":"a vista of pleasure to come"},"VITAL":{"p":"/ˈvaɪt̬əl/","s":"adj.","e":"[adj.] Relating to, or characteristic of life.\n[adj.] Necessary to the continuation of life; being the seat of life; being that on which life depends.\n[adj.] Invigorating or life-giving.","ex":"vital energies; vital functions; vital actions"},"VISAS":{"p":"","s":"n./v.","e":"[n.] A permit to enter and leave a country, normally issued by the authorities of the country to be visited.\n[v.] To endorse (a passport, etc.).","ex":""},"VISOR":{"p":"/ˈvaɪzɚ/","s":"n.","e":"[n.] A part of a helmet, arranged so as to lift or open, and so show the face. The openings for seeing and breathing are generally in it.\n[n.] A mask for the face.\n[n.] The fore piece of a cap, projecting over, and protecting the eyes.","ex":""},"VIXEN":{"p":"/ˈvɪk.sən/","s":"n.","e":"[n.] A female fox.\n[n.] A malicious, quarrelsome or temperamental woman.\n[n.] A racy or salacious woman.","ex":""},"VOCAL":{"p":"/ˈvəʊ.kəl/","s":"n./adj.","e":"[n.] A vocal sound; specifically, a purely vocal element of speech, unmodified except by resonance; a vowel or a diphthong; a tonic element; a tonic; distinguished from a subvocal, and a nonvocal\n[n.] (Roman Catholic Church) A man who has a right to vote in certain elections.\n[adj.] Of or pertaining to the voice or speech\n[adj.] Having a voice\n[adj.] Uttered or modulated by the voice; oral","ex":"vocal problems"},"VODKA":{"p":"/ˈvɑdkə/","s":"n.","e":"[n.] A clear distilled alcoholic liquor made from grain mash.\n[n.] A serving of the above beverage.\n[n.] Neutral spirits distilled (or treated after distillation) so as to have no distinctive character, aroma, taste or color.","ex":""},"VIVID":{"p":"/ˈvɪvɪd/","s":"n./adj.","e":"[n.] A felt-tipped permanent marker.\n[adj.] (of perception) Clear, detailed or powerful.\n[adj.] (of an image) Bright, intense or colourful.\n[adj.] Full of life, strikingly alive.","ex":""},"VOLUME":{"p":"/ˈvɒl.juːm/","s":"n./v.","e":"[n.] A three-dimensional measure of space that comprises a length, a width and a height. It is measured in units of cubic centimeters in metric, cubic inches or cubic feet in English measurement.\n[n.] Strength of sound; loudness.\n[n.] The issues of a periodical over a period of one year.\n[v.] To be conveyed through the air, waft.\n[v.] To cause to move through the air, waft.\n[v.] To swell.","ex":"The room is 9x12x8, so its volume is 864 cubic feet."},"VOILE":{"p":"/vɔɪl/","s":"n.","e":"[n.] A light, translucent cotton fabric used for making curtains and dresses.","ex":""},"VOIDS":{"p":"","s":"n./v.","e":"[n.] An empty space; a vacuum.\n[n.] An extended region of space containing no galaxies\n[n.] A collection of adjacent vacancies inside a crystal lattice.\n[v.] To make invalid or worthless.\n[v.] To empty.\n[v.] To throw or send out; to evacuate; to emit; to discharge.","ex":"Nobody has crossed the void since one man died trying three hundred years ago; it's high time we had another go."},"VOMIT":{"p":"/ˈvɒmɪt/","s":"n./v.","e":"[n.] The regurgitated former contents of a stomach; vomitus.\n[n.] The act of regurgitating.\n[n.] That which causes vomiting; an emetic.\n[v.] To regurgitate or eject the contents of the stomach through the mouth; puke.\n[v.] To regurgitate and discharge (something swallowed); to spew.\n[v.] To eject from any hollow place; to belch forth; to emit.","ex":""},"VOTER":{"p":"/ˈvəʊtə(ɹ)/","s":"n.","e":"[n.] Someone who votes.","ex":"In your opinion, should we allow 16 and 17 year olds to become voters?"},"VOTING":{"p":"","s":"v./n./adj.","e":"[v.] To cast a vote; to assert a formalized choice in an election\n[v.] To choose or grant by means of a vote, or by general consent\n[n.] Action of the verb to vote\n[adj.] Having an associated right for the holder to vote as an owner of business.","ex":"Did you vote last month?"},"VOUCH":{"p":"/ˈvaʊtʃ/","s":"n./v.","e":"[n.] Warrant; attestation.\n[v.] To take responsibility for; to express confidence in; to witness; to obtest.\n[v.] To warrant; to maintain by affirmations\n[v.] To back; to support; to confirm.","ex":"I can vouch that the match took place."},"WADER":{"p":"","s":"n.","e":"[n.] One who wades.\n[n.] (chiefly in the plural) A waterproof boot that comes up to the hip, used by fishermen, etc.\n[n.] A long-legged bird associated with wetland or coastal environments.","ex":""},"WADES":{"p":"","s":"n./v.","e":"[n.] An act of wading.\n[n.] A ford; a place to cross a river.\n[v.] To walk through water or something that impedes progress.\n[v.] To progress with difficulty\n[v.] To walk through (water or similar impediment); to pass through by wading","ex":"We had to be careful during our dangerous wade across the river.}}"},"WADIS":{"p":"","s":"n.","e":"[n.] A valley, gully, or stream bed in northern Africa and southwest Asia that remains dry except during the rainy season.","ex":""},"WACKO":{"p":"/ˈwækəʊ/","s":"n./adj./int.","e":"[n.] An amusingly eccentric or irrational person.\n[adj.] Amusingly eccentric or irrational.\n[int.] Hurrah!","ex":""},"WAGE":{"p":"/weɪd͡ʒ/","s":"n.","e":"[n.] (often in plural) An amount of money paid to a worker for a specified quantity of work, usually calculated on an hourly basis and expressed in an amount of money per hour.","ex":"Before her promotion, her wages were 20% less."},"WADED":{"p":"","s":"v.","e":"[v.] To walk through water or something that impedes progress.\n[v.] To progress with difficulty\n[v.] To walk through (water or similar impediment); to pass through by wading","ex":"to wade through a dull book"},"WAFTS":{"p":"","s":"v.","e":"[v.] To (cause to) float easily or gently through the air.\n[v.] To be moved, or to pass, on a buoyant medium; to float.\n[v.] To give notice to by waving something; to wave the hand to; to beckon.","ex":"A breeze came in through the open window and wafted her sensuous perfume into my eager nostrils."},"WAGON":{"p":"/ˈwæɡ(ə)n/","s":"n./v.","e":"[n.] A four-wheeled cart for hauling loads.\n[n.] A four-wheeled child's riding toy, pulled or steered by a long handle attached to the front.\n[n.] An enclosed vehicle for carrying goods or people; (by extension) a lorry, a truck.\n[v.] To load into a wagon in preparation for transportation; to transport by means of a wagon.\n[v.] To travel in a wagon.","ex":""},"WAIVE":{"p":"/weɪv/","s":"v.","e":"[v.] To relinquish (a right etc.); to give up claim to; to forego.\n[v.] To put aside, avoid.\n[v.] To outlaw (someone).","ex":"If you waive the right to be silent, anything you say can be used against you in a court of law."},"WAKE":{"p":"/ˈweɪk/","s":"n./v.","e":"[n.] The act of waking, or state of being awake.\n[n.] The state of forbearing sleep, especially for solemn or festive purposes; a vigil.\n[v.] (often followed by up) To stop sleeping.\n[v.] (often followed by up) To make somebody stop sleeping; to rouse from sleep.\n[v.] To put in motion or action; to arouse; to excite.","ex":"I woke up at four o'clock this morning."},"WAKES":{"p":"","s":"n./v.","e":"[n.] The act of waking, or state of being awake.\n[n.] The state of forbearing sleep, especially for solemn or festive purposes; a vigil.\n[v.] (often followed by up) To stop sleeping.\n[v.] (often followed by up) To make somebody stop sleeping; to rouse from sleep.\n[v.] To put in motion or action; to arouse; to excite.\n[n.] A period after a person's death before or after the body is buried, cremated, etc.; in some cultures accompanied by a party and/or collectively sorting through the deceased's personal effects.","ex":"I woke up at four o'clock this morning."},"WALK":{"p":"/wɔːk/","s":"v.","e":"[v.] To move on the feet by alternately setting each foot (or pair or group of feet, in the case of animals with four or more feet) forward, with at least one foot on the ground at all times. Compare run.\n[v.] To \"walk free\", i.e. to win, or avoid, a criminal court case, particularly when actually guilty.\n[v.] Of an object, to go missing or be stolen.","ex":"To walk briskly for an hour every day is to keep fit."},"WALKED":{"p":"/wɔːkt/","s":"v.","e":"[v.] To move on the feet by alternately setting each foot (or pair or group of feet, in the case of animals with four or more feet) forward, with at least one foot on the ground at all times. Compare run.\n[v.] To \"walk free\", i.e. to win, or avoid, a criminal court case, particularly when actually guilty.\n[v.] Of an object, to go missing or be stolen.","ex":"To walk briskly for an hour every day is to keep fit."},"WALKS":{"p":"/wɑks/","s":"v./n.","e":"[v.] To move on the feet by alternately setting each foot (or pair or group of feet, in the case of animals with four or more feet) forward, with at least one foot on the ground at all times. Compare run.\n[v.] To \"walk free\", i.e. to win, or avoid, a criminal court case, particularly when actually guilty.\n[v.] Of an object, to go missing or be stolen.\n[n.] A trip made by walking.\n[n.] A distance walked.\n[n.] An Olympic Games track event requiring that the heel of the leading foot touch the ground before the toe of the trailing foot leaves the ground.","ex":"To walk briskly for an hour every day is to keep fit."},"WALLS":{"p":"/wɔːlz/","s":"n./v.","e":"[n.] A rampart of earth, stones etc. built up for defensive purposes.\n[n.] A structure built for defense surrounding a city, castle etc.\n[n.] Each of the substantial structures acting either as the exterior of or divisions within a structure.\n[v.] To enclose with, or as if with, a wall or walls.\n[v.] To boil.\n[v.] To well, as water; spring.","ex":"The town wall was surrounded by a moat."},"WANED":{"p":"","s":"v./adj.","e":"[v.] To progressively lose its splendor, value, ardor, power, intensity etc.; to decline.\n[v.] Said of light that dims or diminishes in strength.\n[v.] Said of the Moon as it passes through the phases of its monthly cycle where its surface is less and less visible.\n[adj.] Having wanes, i.e. rounded corners caused by lack of wood, often showing bark.","ex":""},"WANES":{"p":"","s":"n./v.","e":"[n.] A gradual diminution in power, value, intensity etc.\n[n.] The lunar phase during which the sun seems to illuminate less of the moon as its sunlit area becomes progressively smaller as visible from Earth.\n[n.] The end of a period.\n[v.] To progressively lose its splendor, value, ardor, power, intensity etc.; to decline.\n[v.] Said of light that dims or diminishes in strength.\n[v.] Said of the Moon as it passes through the phases of its monthly cycle where its surface is less and less visible.","ex":""},"WANDS":{"p":"","s":"n.","e":"[n.] A hand-held narrow rod, usually used for pointing or instructing, or as a traditional emblem of authority.\n[n.] (by extension) An instrument shaped like a wand, such as a curling wand.\n[n.] A magic wand.","ex":""},"WARDS":{"p":"","s":"n./v.","e":"[n.] A warden; a guard; a guardian or watchman.\n[n.] Protection, defence.\n[n.] A protected place, and by extension, a type of subdivision.\n[n.] A person under guardianship.\n[v.] To keep in safety, to watch over, to guard.\n[v.] To defend, to protect.","ex":""},"WARM":{"p":"/wɔːm/","s":"adj.","e":"[adj.] Having a temperature slightly higher than usual, but still pleasant; mildly hot.\n[adj.] Caring and friendly, of relations to another person.\n[adj.] Having a color in the red-orange-yellow part of the visible electromagnetic spectrum.","ex":"The tea is still warm."},"WARN":{"p":"/wɔːn/","s":"v.","e":"[v.] To make (someone) aware of (something impending); especially:\n[v.] To caution or admonish (someone) against unwise or unacceptable behaviour.\n[v.] (chiefly with \"off\", \"away\", and similar words) To advise or order to go or stay away.","ex":"Don't let me catch you running in the corridor again, I warn you."},"WARTS":{"p":"","s":"n.","e":"[n.] A type of deformed growth occurring on the skin caused by the human papillomavirus (HPV).\n[n.] Any similar growth occurring in plants or animals, such as the parotoid glands in the back of toads.\n[n.] Any of the prefixes used in Hungarian notation.","ex":""},"WARPS":{"p":"","s":"v.","e":"[v.] To twist or become twisted, physically or mentally:\n[v.] (ropemaking) To run (yarn) off the reel into hauls to be tarred.\n[v.] To arrange (strands of thread, etc) so that they run lengthwise in weaving.","ex":""},"WASH":{"p":"/wɑʃ/","s":"n./v.","e":"[n.] The process or an instance of washing or being washed by water or other liquid.\n[n.] A liquid used for washing.\n[n.] A lotion or other liquid with medicinal or hygienic properties.\n[v.] To clean with water.\n[v.] To move or erode by the force of water in motion.\n[v.] To separate valuable material (such as gold) from worthless material by the action of flowing water.","ex":"I'm going to have a quick wash before coming to bed."},"WASPS":{"p":"","s":"n.","e":"[n.] A member of the dominant American upper-class culture: a white Anglo-Saxon Protestant.\n[n.] A member of the Women Airforce Service Pilots.\n[n.] Any of many types of stinging flying insect resembling a hornet.\n[n.] Any of the members of suborder Apocrita, excepting the ants (family Formicidae) and bees (clade Anthophila).\n[n.] A person who behaves in an angry or insolent way, hence waspish.","ex":""},"WAVES":{"p":"/weɪvz/","s":"v./n.","e":"[v.] To relinquish (a right etc.); to give up claim to; to forego.\n[v.] To put aside, avoid.\n[v.] To outlaw (someone).\n[v.] To move from side to side; to sway.\n[v.] To stray, wander.\n[v.] To move back and forth repeatedly and somewhat loosely.","ex":"If you waive the right to be silent, anything you say can be used against you in a court of law."},"WAVED":{"p":"/weɪvd/","s":"v./adj.","e":"[v.] To relinquish (a right etc.); to give up claim to; to forego.\n[v.] To put aside, avoid.\n[v.] To outlaw (someone).\n[v.] To move from side to side; to sway.\n[v.] To stray, wander.\n[v.] To move back and forth repeatedly and somewhat loosely.","ex":"If you waive the right to be silent, anything you say can be used against you in a court of law."},"WEAK":{"p":"/wiːk/","s":"adj.","e":"[adj.] Lacking in force (usually strength) or ability.\n[adj.] Unable to sustain a great weight, pressure, or strain.\n[adj.] Unable to withstand temptation, urgency, persuasion, etc.; easily impressed, moved, or overcome; accessible; vulnerable.","ex":"The child was too weak to move the boulder."},"WAXES":{"p":"","s":"n./v.","e":"[n.] Beeswax.\n[n.] Earwax.\n[n.] Any oily, water-resistant substance; normally long-chain hydrocarbons, alcohols or esters.\n[v.] To apply wax to (something, such as a shoe, a floor, a car, or an apple), usually to make it shiny.\n[v.] To remove hair at the roots from (a part of the body) by coating the skin with a film of wax that is then pulled away sharply.\n[v.] To defeat utterly.","ex":"What role does the wax in your earhole fulfill?"},"WASHY":{"p":"","s":"n./adj.","e":"[n.] A wash, an act of washing.\n[adj.] Watery; damp; soft.\n[adj.] Lacking substance or strength; weak; thin; dilute; feeble.\n[adj.] Not firm or hardy; liable to sweat profusely with labour.","ex":"Swishy, swishy, swashy. Give your hands a washy."},"WAXED":{"p":"","s":"v./adj.","e":"[v.] To apply wax to (something, such as a shoe, a floor, a car, or an apple), usually to make it shiny.\n[v.] To remove hair at the roots from (a part of the body) by coating the skin with a film of wax that is then pulled away sharply.\n[v.] To defeat utterly.\n[v.] To increasingly assume the specified characteristic.\n[v.] To grow.\n[v.] (of the moon) To appear larger each night as a progression from a new moon to a full moon.","ex":""},"WEALTH":{"p":"/wɛlθ/","s":"n.","e":"[n.] Riches; valuable material possessions.\n[n.] A great amount; an abundance or plenty.\n[n.] Prosperity; well-being; happiness.","ex":"She brings a wealth of knowledge to the project."},"WEEKEND":{"p":"/wiːˈkɛnd/","s":"n./v./adj.","e":"[n.] The break in the working week, usually two days including the traditional holy or sabbath day. Thus in western countries, Saturday and Sunday.\n[v.] To spend the weekend.\n[adj.] Of, relating to or for the weekend.\n[adj.] Occurring at the weekend.","ex":"We'll weekend at the beach."},"WEEDS":{"p":"/wiːdz/","s":"n./v.","e":"[n.] Any plant regarded as unwanted at the place where, and at the time when it is growing.\n[n.] Short for duckweed.\n[n.] Underbrush; low shrubs.\n[v.] To remove unwanted vegetation from a cultivated area.\n[n.] A garment or piece of clothing.\n[n.] Clothing collectively; clothes, dress.","ex":"If it isn't in a straight line or marked with a label, it's a weed."},"WEEKS":{"p":"/wiːks/","s":"n.","e":"[n.] Any period of seven consecutive days.\n[n.] A period of seven days beginning with Sunday or Monday.\n[n.] A period of five days beginning with Monday.","ex":""},"WELCOME":{"p":"/ˈwɛlkəm/","s":"n./v./adj./int.","e":"[n.] The act of greeting someone’s arrival, especially by saying \"Welcome!\"; reception.\n[n.] The utterance of such a greeting.\n[n.] Kind reception of a guest or newcomer.\n[v.] To affirm or greet the arrival of someone, especially by saying \"Welcome!\".\n[v.] To accept something willingly or gladly.\n[adj.] Whose arrival is a cause of joy; received with gladness; admitted willingly to the house, entertainment, or company.","ex":"We entered the house and found a ready welcome."},"WEIGH":{"p":"/weɪ/","s":"v.","e":"[v.] To determine the weight of an object.\n[v.] Often with \"out\", to measure a certain amount of something by its weight, e.g. for sale.\n[v.] To determine the intrinsic value or merit of an object, to evaluate.","ex":"He weighed out two kilos of oranges for a client."},"WELCH":{"p":"/wɛltʃ/","s":"n./v.","e":"[n.] A person who defaults on an obligation, especially a small one.\n[v.] To fail to repay a small debt.\n[v.] To fail to fulfill an obligation.","ex":"She's a welch. That watering-can isn't hers: I lent it to her three years ago."},"WEEDY":{"p":"/ˈwiːdi/","s":"adj.","e":"[adj.] Abounding with weeds.\n[adj.] Of, relating to or resembling weeds.\n[adj.] Consisting of weeds.","ex":"a weedy garden"},"WELFARE":{"p":"/ˈwɛlˌfɛə/","s":"n./v.","e":"[n.] Health, safety, happiness and prosperity; well-being in any respect.\n[n.] Various forms of financial aid provided by the government to those who are in need of it (abbreviated form of welfare assistance).\n[n.] Such payment.\n[v.] To provide with welfare or aid.","ex":"welfaring the poor"},"WELL":{"p":"/wɛl/","s":"adj./adv./int.","e":"[adj.] In good health.\n[adj.] Good, content.\n[adj.] Prudent; good; well-advised.\n[adv.] (manner) Accurately, competently, satisfactorily.\n[adv.] (manner) Completely, fully.\n[adv.] (degree) To a significant degree.","ex":"I had been sick, but now I'm well."},"WELSH":{"p":"/wɛlʃ/","s":"v.","e":"[v.] To swindle someone by not paying a debt, especially a gambling debt.","ex":""},"WENCH":{"p":"/wɛntʃ/","s":"n./v.","e":"[n.] (possibly offensive) A girl or young woman, especially a buxom or lively one.\n[n.] Used as a term of endearment for a female person, especially a wife, daughter, or girlfriend: darling, sweetheart.\n[n.] A woman servant; a maidservant.\n[v.] To frequent prostitutes; to whore; also, to womanize.","ex":"Jane played the role of a wench in an Elizabethan comedy."},"WHELK":{"p":"/hwɛlk/","s":"n.","e":"[n.] Certain edible sea snails, especially, any one of numerous species of large marine gastropods belonging to Buccinidae, much used as food in Europe.","ex":""},"WHINE":{"p":"/waɪn/","s":"n./v.","e":"[n.] A long-drawn, high-pitched complaining cry or sound\n[n.] A complaint or criticism\n[v.] To utter a high-pitched cry.\n[v.] To make a sound resembling such a cry.\n[v.] To complain or protest with a whine or as if with a whine.","ex":"The jet engines whined at take off."},"WHIMS":{"p":"","s":"n.","e":"[n.] A fanciful impulse, or whimsical idea\n[n.] A large capstan or vertical drum turned by horse power or steam power, for raising ore or water, etc., from mines, or for other purposes\n[n.] A bird, the Eurasian wigeon.","ex":""},"WHINY":{"p":"/ˈwaɪni/","s":"adj.","e":"[adj.] Whining; tending to whine or complain.","ex":"Emily is very whiny; she keeps complaining about trivial things."},"WHITE":{"p":"/waɪt/","s":"n./v./adj.","e":"[n.] The color/colour of snow or milk; the colour of light containing equal amounts of all visible wavelengths.\n[n.] A person of European descent with light-coloured skin.\n[n.] Any butterfly of the family Pieridae.\n[v.] To make white; to whiten; to bleach.\n[adj.] Bright and colourless; reflecting equal quantities of all frequencies of visible light.\n[adj.] (sometimes capitalized) Of or relating to Caucasians, people of European descent with light-coloured skin.","ex":"Write in black ink on white paper."},"WIDER":{"p":"/ˈwaɪdə/","s":"adj./adv.","e":"[adj.] Having a large physical extent from side to side.\n[adj.] Large in scope.\n[adj.] Operating at the side of the playing area.\n[adv.] Extensively\n[adv.] Completely\n[adv.] Away from a given goal","ex":"We walked down a wide corridor."},"WIKIS":{"p":"","s":"n./v.","e":"[n.] A collaborative website which can be directly edited merely by using a web browser, often by anyone with access to it.\n[v.] To research on Wikipedia or some similar wiki.\n[v.] To contribute to a wiki.\n[v.] To participate in the wiki-based production of.","ex":"To get an understanding of the topics, he quickly went online and wikied each one."},"WILES":{"p":"/waɪlz/","s":"n.","e":"[n.] (usually in the plural) A trick or stratagem practiced for ensnaring or deception; a sly, insidious artifice","ex":"He was seduced by her wiles."},"ANOTHER":{"p":"/æˈnʌð.ə(ɹ)/","s":"pron.","e":"[pron.] An additional one of the same kind.\n[pron.] One that is different from the current one.\n[pron.] One of a group of things of the same kind.","ex":"There is one sterling and here is another"},"ANSWER":{"p":"/ˈan.sə/","s":"n.","e":"[n.] A response or reply; something said or done in reaction to a statement or question.\n[n.] A solution to a problem.\n[n.] A document filed in response to a complaint, responding to each point raised in the complaint and raising counterpoints.","ex":"Her answer to his proposal was a slap in the face."},"ANVIL":{"p":"/ˈæn.vɪl/","s":"n./v.","e":"[n.] A heavy iron block used in the blacksmithing trade as a surface upon which metal can be struck and shaped.\n[n.] An incus bone in the middle ear.\n[n.] A stone or other hard surface used by a bird for breaking the shells of snails.\n[v.] To fashion on an anvil (often used figuratively).","ex":""},"APHID":{"p":"/ˈeɪ.fɪd/","s":"n.","e":"[n.] Sapsucking pest insect of the superfamily Aphidoidea; an aphidian.","ex":""},"AORTA":{"p":"/eɪˈɔːtə/","s":"n.","e":"[n.] The great artery which carries the blood from the heart to all parts of the body except the lungs; the main trunk of the arterial system.\n[n.] The liveliest part of something.","ex":"Tracing their battles, I had many occasions to walk along Second Avenue, the aorta of the Lower East Side, exploring places that were once as vibrant and tumultuous as Midtown Manhattan. http//travel.nytimes.com/2007/01/26/travel/escapes/26yiddish.html?8dpc"},"ANTIC":{"p":"/ˈæn.tɪk/","s":"n./v./adj.","e":"[n.] A grotesque representation of a figure; a gargoyle.\n[n.] A caricature.\n[n.] (often in plural) A ludicrous gesture or act; ridiculous behaviour; caper.\n[v.] To perform antics, caper.\n[v.] To make a fool of, to cause to look ridiculous.\n[v.] To perform (an action) as an antic; to mimic ridiculously.","ex":""},"ANYONE":{"p":"/ˈæniˌwʌn/","s":"pron.","e":"[pron.] Any person; anybody.","ex":"Almost anyone can change a light bulb."},"APTLY":{"p":"/ˈæp(t).li/","s":"adv.","e":"[adv.] In an apt or suitable manner; fitly; appropriately","ex":"My friend, aptly nicknamed \"Shorty\""},"ARDOR":{"p":"/ˈɑː(ɹ)də(ɹ)/","s":"n.","e":"[n.] Great warmth of feeling; fervor; passion.\n[n.] Spirit; enthusiasm; passion.\n[n.] Intense heat.","ex":""},"ARMED":{"p":"/ɑːmd/","s":"v./adj.","e":"[v.] To take by the arm; to take up in one's arms.\n[v.] To supply with armour or (later especially) weapons.\n[v.] To prepare a tool or a weapon for action; to activate.\n[v.] To cover or furnish with a plate, or with whatever will add strength, force, security, or efficiency.\n[adj.] (sometimes in combination) Equipped, especially with a weapon.\n[adj.] (of a weapon) Prepared for use; loaded.","ex":"The king armed his knights with swords and shields."},"ARRIVE":{"p":"/əˈɹaɪv/","s":"v.","e":"[v.] To reach; to get to a certain place.\n[v.] To obtain a level of success or fame; to succeed.\n[v.] To come; said of time.","ex":"He arrived home for two days."},"AROMA":{"p":"/əˈɹəʊmə/","s":"n.","e":"[n.] A smell; especially a pleasant spicy or fragrant one.","ex":"I love the aroma of cinnamon."},"ARTICLE":{"p":"/ˈɑːtɪkəl/","s":"n./v.","e":"[n.] A piece of nonfictional writing such as a story, report, opinion piece, or entry in a newspaper, magazine, journal, dictionary, encyclopedia, etc.\n[n.] An object, a member of a group or class.\n[n.] (grammar) A part of speech that indicates, specifies and limits a noun (a, an, or the in English). In some languages the article may appear as an ending (e.g. definite article in Swedish) or there may be none (e.g. Russian, Pashto).\n[v.] To bind by articles of apprenticeship.\n[v.] To accuse or charge by an exhibition of articles or accusations.\n[v.] To formulate in articles; to set forth in distinct particulars.","ex":"a sales article"},"ARTIST":{"p":"/ˈɑːtɪst/","s":"n./adj.","e":"[n.] A person who creates art.\n[n.] A person who is skilled at some activity.\n[n.] A recording artist.\n[adj.] Artistic.","ex":""},"ASKEW":{"p":"/əˈskjuː/","s":"adj./adv.","e":"[adj.] Turned or twisted to one side.\n[adj.] Untoward, unfavourable.\n[adv.] Tilted to one side.","ex":"He wore his hat askew"},"ASPECT":{"p":"/ˈæspɛkt/","s":"n./v.","e":"[n.] Any specific feature, part, or element of something.\n[n.] The way something appears when viewed from a certain direction or perspective.\n[n.] The way something appears when considered from a certain point of view.\n[v.] (of a planet) To have a particular aspect or type of aspect.\n[v.] To channel a divine being.\n[v.] To look at.","ex":"Japan's aging population is an important aspect of its economy."},"ATOLL":{"p":"/əˈtɒl/","s":"n.","e":"[n.] A type of island consisting of a ribbon reef that nearly or entirely surrounds a lagoon and supports, in most cases, one to many islets on the reef platform. Atolls have a unique geology, so not all islands with a reef and a lagoon are atolls","ex":""},"ATONE":{"p":"/əˈtəʊn/","s":"v.","e":"[v.] To make reparation, compensation, amends or satisfaction for an offence, crime, mistake or deficiency.\n[v.] To bring at one or at concordance; to reconcile; to suffer appeasement.\n[v.] To agree or accord; to be in accordance or harmony.","ex":""},"AUGUST":{"p":"/ɔːˈɡʌst/","s":"adj.","e":"[adj.] Awe-inspiring, majestic, noble, venerable.\n[adj.] Of noble birth.","ex":"an august patron of the arts"},"ATTACK":{"p":"/əˈtæk/","s":"n./v.","e":"[n.] An attempt to cause damage, injury to, or death of opponent or enemy.\n[n.] An attempt to detract from the worth or credibility of, a person, position, idea, object, or thing, by physical, verbal, emotional, or other assault.\n[n.] A time in which one attacks; the offence of a battle.\n[v.] To apply violent force to someone or something.\n[v.] To aggressively challenge a person, idea, etc., with words (particularly in newspaper headlines, because it typesets into less space than \"criticize\" or similar).\n[v.] To begin to affect; to act upon injuriously or destructively; to begin to decompose or waste.","ex":"They claimed the censorship of the article was an attack on free speech."},"AVERT":{"p":"/əˈvɜːt/","s":"v.","e":"[v.] To turn aside or away.\n[v.] To ward off, or prevent, the occurrence or effects of.\n[v.] To turn away.","ex":"To avert the eyes from an object."},"AUNTY":{"p":"","s":"n.","e":"[n.] The sister or sister-in-law of one’s parent.\n[n.] The female cousin of one’s parent.\n[n.] A woman of an older generation than oneself, especially a friend of one's parents, by means of fictive kin.\n[n.] Term of familiarity or respect for a middle-aged or elderly woman.","ex":""},"AWAY":{"p":"/əˈweɪ/","s":"v./adj./adv./int.","e":"[v.] To depart; to go to another place.\n[adj.] Not here, gone, absent, unavailable, traveling; on vacation.\n[adj.] At a specified distance in space, time, or figuratively.\n[adj.] Not on one's home territory.\n[adv.] From a place, hence.\n[adv.] Aside; off; in another direction.","ex":"At 9 o'clock sharp he awayed to bed."},"AURIC":{"p":"","s":"adj.","e":"[adj.] Of or pertaining to trivalent gold.\n[adj.] Of, or pertaining to the ear; aural\n[adj.] Pertaining to an aura.","ex":""},"AWAIT":{"p":"/əˈwɛɪt/","s":"n./v.","e":"[n.] A waiting for; ambush.\n[n.] Watching, watchfulness, suspicious observation.\n[v.] To wait for.\n[v.] To expect.\n[v.] To be in store for; to be ready or in waiting for.","ex":"I await your reply to my letter."},"AWASH":{"p":"/əˈwɒʃ/","s":"adj.","e":"[adj.] Washed by the waves or tide (of a rock or strip of shore, or of an anchor, etc., when flush with the surface of the water, so that the waves break over it); covered with water.\n[adj.] (by extension) Covered, overspread (with or in something).","ex":""},"AZURE":{"p":"/æˈzjʊə/","s":"n./v./adj.","e":"[n.] A blue colour on a coat of arms, represented in engraving by horizontal parallel lines.\n[n.] The clear blue colour of the sky; also, a pigment or dye of this colour.\n[n.] The unclouded sky; the blue vault above.\n[v.] To colour blue.\n[adj.] Sky blue; resembling the clear blue colour of the unclouded sky\n[adj.] Cloudless","ex":""},"BAKER":{"p":"/ˈbeɪ.kə(ɹ)/","s":"n.","e":"[n.] A person who bakes and sells bread, cakes and similar items.\n[n.] A portable oven for baking.","ex":""},"BAGGY":{"p":"/ˈbæɡi/","s":"adj.","e":"[adj.] Of clothing, very loose-fitting, so as to hang away from the body.\n[adj.] Of or relating to a British music genre of the 1980s and 1990s, influenced by Madchester and psychedelia and associated with baggy clothing.\n[adj.] Of writing, etc.: overwrought; flabby; having too much padding.","ex":"a baggy book"},"BALANCE":{"p":"/ˈbæləns/","s":"n./v.","e":"[n.] A state in which opposing forces harmonise; equilibrium.\n[n.] Mental equilibrium; mental health; calmness, a state of remaining clear-headed and unperturbed.\n[n.] Something of equal weight used to provide equilibrium; counterweight.\n[v.] To bring (items) to an equipoise, as the scales of a balance by adjusting the weights.\n[v.] To make (concepts) agree.\n[v.] To hold (an object or objects) precariously; to support on a narrow base, so as to keep from falling.","ex":"Blair thought he could provide a useful balance to Bush's policies."},"BALER":{"p":"","s":"n.","e":"[n.] A machine for creating bales, e.g., of hay or cotton.\n[n.] A person who creates bales, either by operating or feeding such a machine, or by creating the bales by hand.","ex":"Farmer Jones is in straits because his baler is broken down and he's got three fields of hay ready to bale."},"BAND":{"p":"/bænd/","s":"n./v.","e":"[n.] A strip of material used for strengthening or coupling.\n[n.] A long strip of material, color, etc, that is different from the surrounding area.\n[n.] A strip of decoration.\n[v.] To fasten with a band.\n[v.] To fasten an identifying band around the leg of (a bird).","ex":""},"BARON":{"p":"/ˈbæɹən/","s":"n.","e":"[n.] The male ruler of a barony.\n[n.] A male member of the lowest rank of English nobility (the equivalent rank in Scotland is lord).\n[n.] A particular cut of beef, made up of a double sirloin.","ex":""},"BANK":{"p":"/bæŋk/","s":"n./v.","e":"[n.] An institution where one can place and borrow money and take care of financial affairs.\n[n.] A branch office of such an institution.\n[n.] An underwriter or controller of a card game; also banque.\n[v.] To deal with a bank or financial institution, or for an institution to provide financial services to a client.\n[v.] To put into a bank.\n[v.] To conceal in the rectum for use in prison.","ex":"He banked with Barclays."},"BASAL":{"p":"[ˈbeɪsəɫ]","s":"n./adj.","e":"[n.] Base, bottom, minimum\n[n.] Any basal structure or part\n[adj.] Basic, elementary; relating to, or forming, the base, or point of origin.\n[adj.] Associated with the base of an organism or structure.\n[adj.] Of a minimal level that is necessary for maintaining the health or life of an organism.","ex":"A basal reader is a kind of book that is used to teach reading."},"BASTE":{"p":"/beɪst/","s":"v.","e":"[v.] To sew with long or loose stitches, as for temporary use, or in preparation for gathering the fabric.","ex":""},"BASE":{"p":"/beɪs/","s":"n./v.","e":"[n.] Something from which other things extend; a foundation.\n[n.] The starting point of a logical deduction or thought; basis.\n[n.] A permanent structure for housing military personnel and material.\n[v.] To give as its foundation or starting point; to lay the foundation of.\n[v.] To be located (at a particular place).\n[v.] (acrobatics, cheerleading) To act as a base; to be the person supporting the flyer.","ex":"Peter adjusted the equalizer on his audio equipment to emphasize the bass."},"BATH":{"p":"/bɐːθ/","s":"n./v.","e":"[n.] A tub or pool which is used for bathing: bathtub.\n[n.] A building or area where bathing occurs.\n[n.] The act of bathing.\n[v.] To wash a person or animal in a bath\n[n.] A room containing a shower and/or bathtub, and (typically but not necessarily) a toilet.\n[n.] A lavatory: a room containing a toilet and (typically but not necessarily) a bathtub.","ex":"Most Americans don't know 'WC' and many Brits mock 'bathroom' but almost everyone understands 'toilet' or 'lavatory'."},"BASIS":{"p":"/ˈbeɪsɪs/","s":"n.","e":"[n.] A physical base or foundation.\n[n.] A starting point, base or foundation for an argument or hypothesis.\n[n.] An underlying condition or circumstance.","ex":""},"BATON":{"p":"/ˈbætɒn/","s":"n./v.","e":"[n.] A staff or truncheon, used for various purposes\n[n.] The stick of a conductor in musical performances.\n[n.] An object transferred by runners in a relay race.\n[v.] To strike with a baton.","ex":"the baton of a field marshal"},"BATTERY":{"p":"/ˈbætəɹi/","s":"n.","e":"[n.] A device used to power electric devices, consisting of a set of electrically connected electrochemical or, archaically, electrostatic cells. A single such cell when used by itself.\n[n.] The infliction of unlawful physical violence on a person, legally distinguished from assault, which includes the threat of impending violence.\n[n.] A coordinated group of artillery weapons.","ex":""},"BEAT":{"p":"/biːt/","s":"n./v./adj.","e":"[n.] A stroke; a blow.\n[n.] A pulsation or throb.\n[n.] A pulse on the beat level, the metric level at which pulses are heard as the basic unit. Thus a beat is the basic time unit of a piece.\n[v.] To hit; strike\n[v.] To strike or pound repeatedly, usually in some sort of rhythm.\n[v.] To strike repeatedly; to inflict repeated blows; to knock vigorously or loudly.","ex":"a beat of the heart; the beat of the pulse"},"BATTY":{"p":"/ˈbæti/","s":"adj.","e":"[adj.] Mad, crazy, silly.\n[adj.] Belonging to, or resembling, a bat (mammal).","ex":""},"BECAME":{"p":"/bɪˈkeɪm/","s":"v.","e":"[v.] To arrive, come (to a place).\n[v.] To come about; happen; come into being; arise.\n[v.] Begin to be; turn into.","ex":"It hath becomen so that many a man had to sterve."},"BECOME":{"p":"/bəˈkʊm/","s":"v.","e":"[v.] To arrive, come (to a place).\n[v.] To come about; happen; come into being; arise.\n[v.] Begin to be; turn into.","ex":"It hath becomen so that many a man had to sterve."},"BECAUSE":{"p":"/bɪˈkɒz/","s":"adv./prep./conj.","e":"[adv.] For the reason (that).\n[adv.] On account (of), for sake (of).\n[adv.] (by ellipsis) Used alone to refuse to provide a full answer a question begun with \"why\", usually taken as an anapodoton of the elided full phrase \"Because I said so\".\n[prep.] On account of, because of.\n[conj.] By or for the cause that; on this account that; for the reason that.\n[conj.] As is known, inferred, or determined from the fact that.","ex":"My life is ruined because of you!"},"BEAUTY":{"p":"/ˈbuːti/","s":"n./v./adj./int.","e":"[n.] The quality of being (especially visually) attractive, pleasing, fine or good-looking; comeliness.\n[n.] Someone who is beautiful.\n[n.] Something that is particularly good or pleasing.\n[v.] To make beautiful.\n[adj.] Of high quality, well done.\n[int.] Thanks!","ex":"1988, \"… beauty and recollection, like danger, glamour, greed, hunger- everything but disappointment and desire- were concepts belonging to other people.” -Second Son, Robert Ferro"},"BEDROOM":{"p":"/ˈbɛdɹʊm/","s":"n.","e":"[n.] A room in a house where a bed is kept for sleeping.","ex":"Please don't enter my bedroom without knocking."},"BEEFY":{"p":"/ˈbiːfi/","s":"adj.","e":"[adj.] Similar to, or tasting like beef.\n[adj.] Containing beef.\n[adj.] Strong or muscular.","ex":"The barman was a big, beefy guy with his sleeves rolled up and tattoos on his arms."},"BEEN":{"p":"/biːn/","s":"n.","e":"[n.] A flying insect, of the clade Anthophila within the hymenopteran superfamily Apoidea, known for its organised societies (though only a minority have them), for collecting pollen and (in some species) producing wax and honey.","ex":""},"BEFIT":{"p":"","s":"v.","e":"[v.] To be fit for","ex":"His conduct was not befitting an officer of his station."},"BEGAN":{"p":"/bɪˈɡæn/","s":"v.","e":"[v.] To start, to initiate or take the first step into something.\n[v.] To be in the first stage of some situation\n[v.] To come into existence.","ex":"I began playing the piano at the age of five.   Now that everyone is here, we should begin the presentation."},"BEHIND":{"p":"/bəˈhaɪnd/","s":"n./adv./prep.","e":"[n.] The rear, back-end\n[n.] Butt, the buttocks, bottom\n[n.] A one-point score.\n[adv.] At the back part; in the rear.\n[adv.] Toward the back part or rear; backward.\n[adv.] Overdue, in arrears.","ex":"to look behind"},"BENEFIT":{"p":"/ˈbɛn.ɪ.fɪt/","s":"n./v.","e":"[n.] An advantage; help or aid from something.\n[n.] A payment made in accordance with an insurance policy or a public assistance scheme.\n[n.] An event such as a performance, given to raise funds for some cause.\n[v.] To be or to provide a benefit to.\n[v.] To receive a benefit (from); to be a beneficiary.","ex":"It was for her benefit.   His benefit was free beer."},"BELL":{"p":"/bɛl/","s":"n./v.","e":"[n.] A percussive instrument made of metal or other hard material, typically but not always in the shape of an inverted cup with a flared rim, which resonates when struck.\n[n.] The sounding of a bell as a signal.\n[n.] A telephone call.\n[v.] To attach a bell to.\n[v.] To shape so that it flares out like a bell.\n[v.] To telephone.","ex":"I’ll give you a bell later."},"BESIDE":{"p":"/bɪˈsaɪd/","s":"adv./prep.","e":"[adv.] Otherwise; else.\n[prep.] Next to; at the side of.\n[prep.] Not relevant to.\n[prep.] Besides; in addition to.","ex":"A small table beside the bed"},"BEST":{"p":"/ˈbɛst/","s":"n./v./adj./adv.","e":"[n.] The supreme effort one can make, or has made.\n[n.] One's best behavior.\n[n.] The person (or persons; or thing or things) that is (are) most excellent.\n[v.] To surpass in skill or achievement.\n[v.] To beat in a contest\n[adj.] Most; largest.","ex":"I did my best."},"BEYOND":{"p":"/biˈjɒnd/","s":"n./adv./prep.","e":"[n.] The unknown.\n[n.] The hereafter.\n[n.] Something that is far beyond.\n[adv.] Farther along or away.\n[adv.] In addition; more.\n[adv.] Extremely, more than","ex":"2017 July 13, Joseph Gamp \"Marvel release stirring new set images of Black Panther and we are BEYOND excited\" Metro (UK)"},"BIDDY":{"p":"/ˈbɪdi/","s":"n.","e":"[n.] A woman, especially an old woman; especially one regarded as fussy or mean or a gossipy busybody.\n[n.] An attractive girl.\n[n.] An Irish maidservant.","ex":""},"BIDET":{"p":"[ˈbiːdeɪ]","s":"n.","e":"[n.] A low-mounted plumbing fixture or type of sink intended for washing the external genitalia and the anus.\n[n.] A small horse formerly allowed to each trooper or dragoon for carrying his baggage.","ex":""},"BIGGEST":{"p":"/ˈbɪɡəst/","s":"adj.","e":"[adj.] Of great size, large.\n[adj.] (of an industry or other field, often capitalized) Thought to have undue influence.\n[adj.] Popular.","ex":"Elephants are big animals, and they eat a lot."},"BIKE":{"p":"[bɐɪk]","s":"n./v.","e":"[n.] A vehicle that has two wheels, one behind the other, a steering handle, and a saddle seat or seats and is usually propelled by the action of a rider’s feet upon pedals.\n[n.] A traveling block used on a cable in skidding logs.\n[n.] The best possible hand in lowball.\n[v.] To ride a bike.\n[v.] To travel by bike.\n[v.] To transport by bicycle","ex":"I biked so much yesterday that I'm very sore today."},"BILL":{"p":"/bɪl/","s":"n./v.","e":"[n.] Any of various bladed or pointed hand weapons, originally designating an Anglo-Saxon sword, and later a weapon of infantry, especially in the 14th and 15th centuries, commonly consisting of a broad, heavy, double-edged, hook-shaped blade, with a short pike at the back and another at the top, attached to the end of a long staff.\n[n.] A cutting instrument, with hook-shaped point, and fitted with a handle, used in pruning, etc.; a billhook.\n[n.] Somebody armed with a bill; a billman.\n[v.] To dig, chop, etc., with a bill.","ex":""},"BINGO":{"p":"/ˈbɪŋ.ɡəʊ/","s":"n./v./adj./int.","e":"[n.] A game of chance for two or more players, who mark off numbers on a grid as they are announced by the caller; the game is won by the first person to call out \"bingo!\" or \"house!\" after crossing off all numbers on the grid or in one line of the grid.\n[n.] A win in such a game.\n[n.] (Scrabble) A play where all seven of a player's letter tiles are played.\n[v.] To play the game of bingo.\n[v.] To give the winning cry of \"bingo!\" in a game.\n[v.] To play all of one's seven tiles in one move in the game of Scrabble, earning a score bonus.","ex":"There were two bingos in the last game, so the players split the prize money."},"BIRD":{"p":"/bɜd/","s":"n./v.","e":"[n.] A member of the class of animals Aves in the phylum Chordata, characterized by being warm-blooded, having feathers and wings usually capable of flight, and laying eggs.\n[n.] A man, fellow.\n[n.] A girl or woman, especially one considered sexually attractive.\n[v.] To observe or identify wild birds in their natural environment.\n[v.] To catch or shoot birds.\n[v.] To seek for game or plunder; to thieve.","ex":"Ducks and sparrows are birds."},"BIRCH":{"p":"/bɜːtʃ/","s":"n./v.","e":"[n.] Any of various trees of the genus Betula, native to countries in the Northern Hemisphere.\n[n.] A hard wood taken from the birch tree, typically used to make furniture.\n[n.] A stick, rod or bundle of twigs made from birch wood, used for punishment.\n[v.] To punish with a stick, bundle of twigs, or rod made of birch wood.\n[v.] To punish as though one were using a stick, bundle of twigs, or rod made of birch wood.","ex":""},"BITE":{"p":"/bʌɪt/","s":"n./v.","e":"[n.] The act of biting.\n[n.] The wound left behind after having been bitten.\n[n.] The swelling of one's skin caused by an insect's mouthparts or sting.\n[v.] To cut into something by clamping the teeth.\n[v.] To hold something by clamping one's teeth.\n[v.] To attack with the teeth.","ex":"That snake bite really hurts!"},"BLARE":{"p":"/blɛə(ɹ)/","s":"n./v.","e":"[n.] A loud sound.\n[n.] Dazzling, often garish, brilliance.\n[v.] To make a loud sound.\n[v.] To cause to sound like the blare of a trumpet; to proclaim loudly.","ex":"I can hardly hear you over the blare of the radio."},"BLAND":{"p":"/blænd/","s":"adj.","e":"[adj.] Having a soothing effect; not irritating or stimulating.\n[adj.] Lacking in taste, flavor, or vigor.\n[adj.] Lacking interest; boring; dull.","ex":"a bland diet"},"BLANKET":{"p":"/ˈblæŋkɪt/","s":"n./v./adj.","e":"[n.] A heavy, loosely woven fabric, usually large and woollen, used for warmth while sleeping or resting.\n[n.] A layer of anything.\n[n.] A thick rubber mat used in the offset printing process to transfer ink from the plate to the paper being printed.\n[v.] To cover with, or as if with, a blanket.\n[v.] To traverse or complete thoroughly.\n[v.] To toss in a blanket by way of punishment.","ex":"The baby was cold, so his mother put a blanket over him."},"BLEAT":{"p":"/ˈbliːt/","s":"n./v.","e":"[n.] The characteristic cry of a sheep or a goat.\n[v.] Of a sheep or goat, to make its characteristic cry; of a human, to mimic this sound.\n[v.] Of a person, to complain.","ex":"The last thing we need is to hear them bleating to us about organizational problems."},"BLEEP":{"p":"","s":"n./v.","e":"[n.] A brief high-pitched sound, as from some electronic device.\n[n.] Something named by an explicit noun in the original, unedited version of the containing sentence.\n[n.] A broad genre of electronic music with goth and industrial influences, as opposed to traditional gothic rock.\n[v.] To emit one or more bleeps.\n[v.] To edit out inappropriate spoken language in a broadcast by replacing offending words with bleeps.","ex":"What the bleep are you doing?"},"BLEED":{"p":"/ˈbliːd/","s":"n./v.","e":"[n.] An incident of bleeding, as in haemophilia.\n[n.] A narrow edge around a page layout, to be printed but cut off afterwards (added to allow for slight misalignment, especially with pictures that should run to the edge of the finished sheet).\n[n.] (sound recording) The situation where sound is picked up by a microphone from a source other than that which is intended.\n[v.] (of a person or animal) To lose blood through an injured blood vessel.\n[v.] To let or draw blood from.\n[v.] To take large amounts of money from.","ex":"If her nose bleeds, try to use ice."},"BLEND":{"p":"/blɛnd/","s":"n./v.","e":"[n.] A mixture of two or more things.\n[n.] A word formed by combining two other words; a grammatical contamination, portmanteau word.\n[v.] To mingle; to mix; to unite intimately; to pass or shade insensibly into each other.\n[v.] To be mingled or mixed.\n[v.] To pollute by mixture or association; to spoil or corrupt; to blot; to stain.","ex":"Our department has a good blend of experienced workers and young promise."},"BLIMP":{"p":"/blɪmp/","s":"n./v.","e":"[n.] An airship constructed with a non-rigid lifting agent container.\n[n.] (by extension) Any large airborne inflatable.\n[n.] An obese person.\n[v.] To expand like a blimp or balloon; to become fat.","ex":"After college, she started blimping and could no longer wear her favorite little black dress."},"BLITZ":{"p":"/blɪts/","s":"n./v.","e":"[n.] A sudden attack, especially an air raid; usually with reference to the Blitz.\n[n.] A swift and overwhelming attack or effort.\n[n.] A play in which additional defenders beyond the defensive linemen rush the passer.\n[v.] To attack quickly or suddenly, as by an air raid or similar action.\n[v.] To perform a blitz.\n[v.] To purée or chop (food products) using a food processor or blender.","ex":"We embarked on a publicity blitz, putting posters and flyers all around town."},"BLISS":{"p":"/blɪs/","s":"n.","e":"[n.] Perfect happiness","ex":""},"BLOKE":{"p":"/bləʊk/","s":"n.","e":"[n.] A man, a fellow; an ordinary man, a man on the street.\n[n.] A man who behaves in a particularly laddish or overtly heterosexual manner.\n[n.] (A lower deck term for) the Captain or Executive Officer of a warship, with particular reference to discipline and punishment.","ex":""},"BLUFF":{"p":"/blʌf/","s":"n./v.","e":"[n.] An act of bluffing; a false expression of the strength of one's position in order to intimidate; braggadocio.\n[n.] An attempt to represent oneself as holding a stronger hand than one actually does.\n[n.] The card game poker.\n[v.] To make a bluff; to give the impression that one's hand is stronger than it is.\n[v.] (by analogy) To frighten or deter with a false show of strength or confidence; to give a false impression of strength or temerity in order to intimidate and gain some advantage.\n[v.] To take advantage by bluffing.","ex":"That is only bluff, or a bluff."},"BLUER":{"p":"","s":"adj.","e":"[adj.] Of the colour blue.\n[adj.] Depressed, melancholic, sad.\n[adj.] Pale, without redness or glare; said of a flame.","ex":"the deep blue sea"},"BOAST":{"p":"/bəʊst/","s":"n./v.","e":"[n.] A brag; ostentatious positive appraisal of oneself.\n[n.] Something that one brags about.\n[n.] A shot where the ball is driven off a side wall and then strikes the front wall.\n[v.] To brag; to talk loudly in praise of oneself.\n[v.] To speak of with pride, vanity, or exultation, with a view to self-commendation; to extol.\n[v.] To speak in exulting language of another; to glory; to exult.","ex":"It was his regular boast that he could eat two full English breakfasts in one sitting."},"BOBBY":{"p":"/ˈbɒbi/","s":"n.","e":"[n.] A police officer.\n[n.] A railway signaller.","ex":""},"BOMB":{"p":"/bɒm/","s":"n./v./adj.","e":"[n.] An explosive device used or intended as a weapon.\n[n.] A failure; an unpopular commercial product.\n[n.] A large amount of money.\n[v.] To attack using one or more bombs; to bombard.\n[v.] To fail dismally.\n[v.] To jump into water in a squatting position, with the arms wrapped around the legs.","ex":"box office bomb"},"BOAT":{"p":"/bəʊt/","s":"n./v.","e":"[n.] A craft used for transportation of goods, fishing, racing, recreational cruising, or military use on or in the water, propelled by oars or outboard motor or inboard motor or by wind.\n[n.] A full house.\n[n.] A vehicle, utensil, or dish somewhat resembling a boat in shape.\n[v.] To travel by boat.\n[v.] To transport in a boat.\n[v.] To place in a boat.","ex":"a stone boat;  a gravy boat"},"BOOK":{"p":"/buːk/","s":"n.","e":"[n.] A collection of sheets of paper bound together to hinge at one edge, containing printed or written material, pictures, etc.\n[n.] A long work fit for publication, typically prose, such as a novel or textbook, and typically published as such a bound collection of sheets, but now sometimes electronically as an e-book.\n[n.] A major division of a long work.","ex":"He was frustrated because he couldn't find anything about dinosaurs in the book."},"BONE":{"p":"/bəʉn/","s":"n./v./adj.","e":"[n.] A composite material consisting largely of calcium phosphate and collagen and making up the skeleton of most vertebrates.\n[n.] Any of the components of an endoskeleton, made of bone.\n[n.] A bone of a fish; a fishbone.\n[v.] To prepare (meat, etc) by removing the bone or bones from.\n[v.] To fertilize with bone.\n[v.] To put whalebone into.","ex":"to bone stays"},"BONGO":{"p":"","s":"n.","e":"[n.] A striped bovine mammal found in Africa, Tragelaphus eurycerus.","ex":""},"BOOKS":{"p":"/bʊks/","s":"n./v.","e":"[n.] A collection of sheets of paper bound together to hinge at one edge, containing printed or written material, pictures, etc.\n[n.] A long work fit for publication, typically prose, such as a novel or textbook, and typically published as such a bound collection of sheets, but now sometimes electronically as an e-book.\n[n.] A major division of a long work.\n[v.] To reserve (something) for future use.\n[v.] To write down, to register or record in a book or as in a book.\n[v.] (law enforcement) To record the name and other details of a suspected offender and the offence for later judicial action.","ex":"He was frustrated because he couldn't find anything about dinosaurs in the book."},"BOOZE":{"p":"/buːz/","s":"n./v.","e":"[n.] Any alcoholic beverage.\n[n.] A session of drinking alcohol; a drinking party.\n[v.] To drink alcohol.","ex":"We were out all night boozing until we dragged ourselves home hung over."},"BOOZY":{"p":"/ˈbuːzi/","s":"adj.","e":"[adj.] (of a person) Intoxicated by alcohol.\n[adj.] (of a person) Inclined to consume a significant amount of alcohol.\n[adj.] (of an event) Involving a large consumption of alcohol.","ex":"We all had hangovers after a boozy weekend in town."},"BORNE":{"p":"/bɔːn/","s":"v./adj.","e":"[v.] To carry or convey, literally or figuratively.\n[v.] To support, sustain, or endure.\n[v.] To support, keep up, or maintain.\n[adj.] Carried, supported.","ex":"Judging from the look on his face, he wasn't bearing good news."},"BOTTLE":{"p":"/ˈbɑ.təl/","s":"n./v.","e":"[n.] A container, typically made of glass or plastic and having a tapered neck, used primarily for holding liquids.\n[n.] The contents of such a container.\n[n.] A container with a rubber nipple used for giving liquids to infants, a baby bottle.\n[v.] To seal (a liquid) into a bottle for later consumption. Also fig.\n[v.] To feed (an infant) baby formula.\n[v.] To refrain from doing (something) at the last moment because of a sudden loss of courage.","ex":"Beer is often sold in bottles."},"BOSS":{"p":"/bɑs/","s":"n./v./adj.","e":"[n.] A person who oversees and directs the work of others; a supervisor.\n[n.] A person in charge of a business or company.\n[n.] A leader, the head of an organized group or team.\n[v.] To exercise authoritative control over; to tell (someone) what to do, often repeatedly.\n[adj.] Of excellent quality, first-rate.","ex":"Chat turned to whisper when the boss entered the conference room."},"BOOTY":{"p":"/ˈbuːti/","s":"n.","e":"[n.] A form of prize which, when a ship was captured at sea, could be distributed at once.\n[n.] Plunder taken from an enemy in time of war, or seized by piracy.\n[n.] Something that has been stolen or illegally obtained from elsewhere.","ex":""},"BRASS":{"p":"/bɹɑːs/","s":"n./v./adj.","e":"[n.] A metallic alloy of copper and zinc used in many industrial and plumbing applications.\n[n.] A class of wind instruments, usually made of metal (such as brass), that use vibrations of the player's lips to produce sound; the section of an orchestra that features such instruments\n[n.] Spent shell casings (usually made of brass); the part of the cartridge left over after bullets have been fired.\n[v.] To coat with brass.\n[adj.] Made of brass, of or pertaining to brass.\n[adj.] Of the colour of brass.","ex":""},"BRIAR":{"p":"/bɹʌɪə/","s":"n.","e":"[n.] Any of many plants with thorny stems growing in dense clusters, such as many in the Rosa, Rubus, and Smilax genera.\n[n.] Anything sharp or unpleasant to the feelings.","ex":""},"BRAWL":{"p":"/bɹɔːl/","s":"n./v.","e":"[n.] A disorderly argument or fight, usually with a large number of people involved.\n[v.] To engage in a brawl; to fight or quarrel.\n[v.] To create a disturbance; to complain loudly.\n[v.] Especially of a rapid stream running over stones: to make a loud, confused noise.","ex":""},"BREATH":{"p":"/bɹɛθ/","s":"n.","e":"[n.] The act or process of breathing.\n[n.] A single act of breathing in or out; a breathing of air.\n[n.] Air expelled from the lungs.","ex":"I could hear the breath of the runner behind me."},"BORN":{"p":"/ˈbɔːn/","s":"v./adj.","e":"[v.] To carry or convey, literally or figuratively.\n[v.] To support, sustain, or endure.\n[v.] To support, keep up, or maintain.\n[adj.] Having from birth (or as if from birth) a certain quality or character; innate; inherited.","ex":"Judging from the look on his face, he wasn't bearing good news."},"BRINK":{"p":"/bɹɪŋk/","s":"n.","e":"[n.] The edge, margin, or border of a steep place, as of a precipice; a bank or edge.\n[n.] The edge or border","ex":"the brink of a river"},"BRUTE":{"p":"/bɹuːt/","s":"n./v./adj.","e":"[n.] An animal seen as being without human reason; a senseless beast.\n[n.] A person with the characteristics of an unthinking animal; a coarse or brutal person.\n[n.] (Cambridge University slang) One who has not yet matriculated.\n[v.] To shape (diamonds) by grinding them against each other.\n[adj.] Without reason or intelligence (of animals).\n[adj.] Characteristic of unthinking animals; senseless, unreasoning (of humans).","ex":"One of them was a hulking brute of a man, heavily tattooed and with a hardened face that practically screamed \"I just got out of jail.\""},"BROKEN":{"p":"/ˈbɹəʊkən/","s":"v./adj.","e":"[v.] To separate into two or more pieces, to fracture or crack, by a process that cannot easily be reversed for reassembly.\n[v.] To divide (something, often money) into smaller units.\n[v.] To cause (a person or animal) to lose spirit or will; to crush the spirits of.\n[adj.] Fragmented, in separate pieces.\n[adj.] (of a promise, etc) Breached; violated; not kept.\n[adj.] Non-functional; not functioning properly.","ex":"If the vase falls to the floor, it might break."},"BUGLE":{"p":"/ˈbjuːɡəl/","s":"n./v.","e":"[n.] A horn used by hunters.\n[n.] A simple brass instrument consisting of a horn with no valves, playing only pitches in its harmonic series\n[n.] A plant in the family Lamiaceae grown as a ground cover, Ajuga reptans, and other plants in the genus Ajuga.\n[v.] To announce, sing, or cry in the manner of a musical bugle","ex":""},"BOTH":{"p":"/bəʊθ/","s":"pron./conj.","e":"[pron.] Each of the two, or of the two kinds.\n[conj.] Including both of (used with and).\n[conj.] Including all of (used with and).","ex":"\"Did you want this one or that one?\" — \"Give me both.\""},"BUNNY":{"p":"/ˈbʌni/","s":"n./adj.","e":"[n.] A rabbit, especially a juvenile.\n[n.] A bunny girl: a nightclub waitress who wears a costume having rabbit ears and tail.\n[n.] In basketball, an easy shot (i.e., one right next to the bucket) that is missed.\n[adj.] Easy or unchallenging.","ex":"Let’s start on the bunny slope."},"BUILDER":{"p":"/ˈbɪl.də/","s":"n.","e":"[n.] A person who builds or constructs things.\n[n.] Master artisan, who receives his instructions from the architect, and employs workers.\n[n.] A bodybuilder.","ex":""},"BURN":{"p":"/bɜːn/","s":"n./v.","e":"[n.] A physical injury caused by heat, cold, electricity, radiation or caustic chemicals.\n[n.] A sensation resembling such an injury.\n[n.] The act of burning something with fire.\n[v.] To cause to be consumed by fire.\n[v.] To be consumed by fire, or in flames.\n[v.] To overheat so as to make unusable.","ex":"She had second-degree burns from falling in the bonfire."},"BURNING":{"p":"/bɜːnɪŋ/","s":"v./n./adj.","e":"[v.] To cause to be consumed by fire.\n[v.] To be consumed by fire, or in flames.\n[v.] To overheat so as to make unusable.\n[n.] The act by which something burns or is burned.\n[n.] A fire.\n[adj.] So hot as to seem to burn (something).","ex":"He burned his manuscript in the fireplace."},"BUSED":{"p":"/bʌst/","s":"v.","e":"[v.] To transport via a motor bus.\n[v.] To transport students to school, often to a more distant school for the purposes of achieving racial integration.\n[v.] To travel by bus.","ex":""},"BUSY":{"p":"/ˈbɪzi/","s":"n./v./adj.","e":"[n.] A police officer.\n[v.] To make somebody busy or active; to occupy.\n[v.] To rush somebody.\n[adj.] Crowded with business or activities; having a great deal going on.\n[adj.] Engaged in activity or by someone else.\n[adj.] Having a lot going on; complicated or intricate.","ex":"On my vacation I'll busy myself with gardening."},"BUXOM":{"p":"/ˈbʌksəm/","s":"adj.","e":"[adj.] Pliant, obedient, tractable (to) (i.e. easily moved or bent, morally).\n[adj.] Submissive, humble, meek (as subsense of 4).\n[adj.] Gracious, indulgent, favourable; obliging, amiable, courteous, affable, kindly (as subsense of 1).","ex":""},"BUTTE":{"p":"/ˈbjuːt/","s":"n.","e":"[n.] An isolated hill with steep sides and a flat top.","ex":""},"BUGGY":{"p":"/bʌ.ɡi/","s":"n./adj.","e":"[n.] A small horse-drawn cart.\n[n.] A small motor vehicle, such as a dune buggy.\n[n.] A hearse.\n[adj.] Infested with insects\n[adj.] Containing programming errors\n[adj.] Resembling an insect","ex":"This software is so buggy that I don't know how anyone can use it!"},"BYLAW":{"p":"/ˈbaɪ.lɔː/","s":"n.","e":"[n.] A local custom or law of a settlement or district.\n[n.] A rule made by a local authority to regulate its own affairs.\n[n.] A law or rule governing the internal affairs of an organization (e.g., corporation or business).","ex":""},"CACAO":{"p":"/kəˈkeɪ̯əʊ̯/","s":"n.","e":"[n.] A tree, Theobroma cacao, whose seed is used to make chocolate.\n[n.] This tree's seed, the cocoa bean.","ex":""},"CADDY":{"p":"/ˈkædi/","s":"n./v.","e":"[n.] One hired to assist another in playing the game of golf.\n[v.] To serve as a caddy, carrying golf clubs etc.","ex":"\"Caddy, pass me my five iron.\""},"CADET":{"p":"/kəˈdɛt/","s":"n.","e":"[n.] A student at a military school who is training to be an officer.\n[n.] A younger or youngest son, who would not inherit as a firstborn son would.\n[n.] (in compounds, chiefly in genealogy) Junior. (See also the heraldic term cadency.)","ex":"a cadet branch of the family"},"CACTI":{"p":"/ˈkæktaɪ/","s":"n.","e":"[n.] Any member of the family Cactaceae, a family of flowering New World succulent plants suited to a hot, semi-desert climate.\n[n.] Any succulent plant with a thick fleshy stem bearing spines but no leaves, such as euphorbs.","ex":""},"BUSHY":{"p":"/ˈbʊʃi/","s":"adj.","e":"[adj.] Like a bush in having many widely spread branches.\n[adj.] Growing thickly.\n[adj.] (Racial slur) Derogatory word used to refer to Afro-textured Hair.","ex":"the bushy tail of a squirrel"},"CANTON":{"p":"/ˈkæntn̩/","s":"n./v.","e":"[n.] A division of a political unit.\n[n.] A small community or clan.\n[n.] A subdivision of a flag, the rectangular inset on the upper hoist (i.e., flagpole) side (e.g., the stars of the US national flag are in a canton).\n[v.] To delineate as a separate district.\n[v.] To divide into cantons.\n[v.] To allot quarters to troops.","ex":""},"BUZZY":{"p":"/ˈbʌzi/","s":"adj.","e":"[adj.] Having a buzzing sound.\n[adj.] Being the subject of cultural buzz.","ex":""},"CARBON":{"p":"/ˈkɑɹbən/","s":"n./v.","e":"[n.] The chemical element (symbol C) with an atomic number of 6. It can be found in pure form for example as graphite, a black, shiny and very soft material, or diamond, a colourless, transparent, crystalline solid and the hardest known material.\n[n.] An atom of this element, in reference to a molecule containing it.\n[n.] A sheet of carbon paper.\n[v.] To cause (someone) to receive a carbon copy of an email message.","ex":"A methane molecule is made up of a single carbon with four hydrogens."},"CARAT":{"p":"/ˈkæɹ.ət/","s":"n.","e":"[n.] A unit of weight for precious stones and pearls, equivalent to 200 milligrams.\n[n.] Any of several units of weight, varying from 189 to 212 mg, the weight of a carob seed.\n[n.] A measure of the purity of gold, pure gold being 24 carats.","ex":""},"CARD":{"p":"/kaːd/","s":"n./v.","e":"[n.] A playing card.\n[n.] (in the plural) Any game using playing cards; a card game.\n[n.] A resource or an argument, used to achieve a purpose.\n[v.] To check IDs, especially against a minimum age requirement.\n[v.] To play cards.\n[v.] To make (a stated score), as recorded on a scoring card.","ex":"He played cards with his friends."},"CACHE":{"p":"/kæɪʃ/","s":"n./v.","e":"[n.] A store of things that may be required in the future, which can be retrieved rapidly, protected or hidden in some way.\n[n.] A fast temporary storage where recently or frequently used information is stored to avoid having to reload it from a slower storage medium.\n[n.] (geocaching) A container containing treasure in a global treasure-hunt game.\n[v.] To place in a cache.","ex":"Members of the 29-man Discovery team laid down food caches to allow the polar team to travel light, hopping from food cache to food cache on their return journey."},"CAKE":{"p":"/keɪk/","s":"n./v.","e":"[n.] A rich, sweet dessert food, typically made of flour, sugar and eggs and baked in an oven, and often covered in icing.\n[n.] A small mass of baked dough, especially a thin loaf from unleavened dough.\n[n.] A thin wafer-shaped mass of fried batter; a griddlecake or pancake.\n[v.] Coat (something) with a crust of solid material.\n[v.] To form into a cake, or mass.","ex":"a johnnycake"},"CAREER":{"p":"/kəˈɹɪə/","s":"n./v.","e":"[n.] One's calling in life; a person's occupation; one's profession.\n[n.] General course of action or conduct in life, or in a particular part of it.\n[n.] Speed.\n[v.] To move rapidly straight ahead, especially in an uncontrolled way.","ex":"Washington's career as a soldier"},"CANNY":{"p":"/ˈkæni/","s":"adj./adv.","e":"[adj.] Careful, prudent, cautious.\n[adj.] Knowing, shrewd, astute.\n[adj.] Frugal, thrifty.\n[adv.] Very, considerably; quite, rather.\n[adv.] Gently, quietly; carefully, skilfully.","ex":"The politician gave a canny response to the reporter's questions."},"CAREFUL":{"p":"/ˈkɛːfəl/","s":"adj.","e":"[adj.] Taking care; attentive to potential danger, error or harm; cautious.\n[adj.] Conscientious and painstaking; meticulous.\n[adj.] Full of care or grief; sorrowful, sad.","ex":"He was a slow and careful driver."},"CARVE":{"p":"/kɑːv/","s":"n./v.","e":"[n.] A carucate.\n[n.] The act of carving\n[v.] To cut.\n[v.] To cut meat in order to serve it.\n[v.] To shape to sculptural effect; to produce (a work) by cutting, or to cut (a material) into a finished work.","ex":"give that turkey a careful carve"},"CAST":{"p":"/kæst/","s":"n./v.","e":"[n.] An act of throwing.\n[n.] An instance of throwing out a fishing line.\n[n.] Something which has been thrown, dispersed etc.\n[v.] (physical) To move, or be moved, away.\n[v.] To direct (one's eyes, gaze etc.).\n[v.] To add up (a column of figures, accounts etc.); cross-cast refers to adding up a row of figures.","ex":""},"CAPABLE":{"p":"/ˈkeɪpəbl̩/","s":"adj.","e":"[adj.] Able and efficient; having the ability needed for a specific task; having the disposition to do something; permitting or being susceptible to something.\n[adj.] Of sufficient capacity or size for holding, containing, receiving or taking in; accessible to. Construed with of, for or an infinitive.","ex":"As everyone knew, he was capable of violence when roused."},"CAPTAIN":{"p":"/ˈkæp.tən/","s":"n./v.","e":"[n.] A chief or leader.\n[n.] The person lawfully in command of a ship or other vessel.\n[n.] An army officer with a rank between the most senior grade of lieutenant and major.\n[v.] To act as captain\n[v.] To exercise command of a ship, aircraft or sports team.","ex":"The captain is the last man to leave a sinking ship."},"CAUGHT":{"p":"[k̠ʰoːt]","s":"v./adj.","e":"[v.] (heading) To capture, overtake.\n[v.] (heading) To seize hold of.\n[v.] (heading) To intercept.\n[adj.] Of the method of being out in which the striker hits the ball and a fielder catches it.","ex":""},"CAUTION":{"p":"/ˈkɔːʃ(ə)n/","s":"n./v.","e":"[n.] Precept or warning against evil or danger of any kind; exhortation to wariness; advice; injunction; prudence in regard to danger; provident care\n[n.] A careful attention to the probable effects of an act, in order that failure or harm may be avoided\n[n.] Security; guaranty; bail.\n[v.] To warn; to alert, advise that caution is warranted.\n[v.] To give a yellow card","ex":"The guideline expressed caution against excessive radiographic imaging."},"CENTRAL":{"p":"/ˈsɛntɹəl/","s":"adj.","e":"[adj.] Being in the centre.\n[adj.] Having or containing the centre of something.\n[adj.] Being very important, or key to something.","ex":""},"CAVIL":{"p":"/ˈkæv.əl/","s":"n./v.","e":"[n.] A petty or trivial objection or criticism.\n[v.] To criticise for petty or frivolous reasons.","ex":""},"CASTLE":{"p":"/kæsl̩/","s":"n./v.","e":"[n.] A large building that is fortified and contains many defences; in previous ages often inhabited by a nobleman or king.\n[n.] An instance of castling.\n[n.] A rook; a chess piece shaped like a castle tower.\n[v.] To house or keep in a castle.\n[v.] To protect or separate in a similar way.\n[v.] To make into a castle: to build in the form of a castle or add (real or imitation) battlements to an existing building.","ex":""},"CHAFF":{"p":"/tʃæf/","s":"n./v.","e":"[n.] The inedible parts of a grain-producing plant.\n[n.] Straw or hay cut up fine for the food of cattle.\n[n.] Any excess or unwanted material, resource, or person; anything worthless.\n[v.] To use light, idle language by way of fun or ridicule; to banter.\n[v.] To make fun of; to turn into ridicule by addressing in ironical or bantering language; to quiz.","ex":"To separate out the chaff, early cultures tossed baskets of grain into the air and let the wind blow away the lighter chaff."},"CHARGE":{"p":"/t͡ʃɑːd͡ʒ/","s":"n./v.","e":"[n.] The amount of money levied for a service.\n[n.] A ground attack against a prepared enemy.\n[n.] A forceful forward movement.\n[v.] To assign a duty or responsibility to\n[v.] To assign (a debit) to an account\n[v.] To pay on account, as by using a credit card","ex":"There will be a charge of five dollars."},"CAULK":{"p":"/kɑk/","s":"n./v.","e":"[n.] A pointed projection on a horseshoe to prevent it slipping.\n[n.] A spike on the sole of a boot to prevent slipping, particularly used in logging\n[n.] Caulking.\n[n.] A composition of vehicle and pigment used at ambient temperatures for filling/sealing joints or junctures, that remains elastic for an extended period of time after application.\n[v.] To drive oakum into the seams of a ship's wooden deck or hull to make it watertight.\n[v.] To apply caulking to joints, cracks, or a juncture of different materials.","ex":""},"CELL":{"p":"/sɛl/","s":"n./v.","e":"[n.] A single-room dwelling for a hermit.\n[n.] A small monastery or nunnery dependent on a larger religious establishment.\n[n.] A small room in a monastery or nunnery accommodating one person.\n[v.] To place or enclose in a cell.","ex":"Gregor Mendel must have spent a good amount of time outside of his cell."},"CHEST":{"p":"/t͡ʃɛst/","s":"n./v.","e":"[n.] A box, now usually a large strong box with a secure convex lid.\n[n.] A coffin.\n[n.] The place in which public money is kept; a treasury.\n[v.] To hit with one's chest (front of one's body)\n[v.] To deposit in a chest.\n[v.] To place in a coffin.","ex":"The clothes are kept in a chest."},"CIRCLE":{"p":"/ˈsɜɹkəl/","s":"n./v.","e":"[n.] A two-dimensional geometric figure, a line, consisting of the set of all those points in a plane that are equally distant from a given point (center).\n[n.] A two-dimensional geometric figure, a disk, consisting of the set of all those points of a plane at a distance less than or equal to a fixed distance (radius) from a given point.\n[n.] Any shape, curve or arrangement of objects that approximates to or resembles the geometric figures.\n[v.] To travel around along a curved path.\n[v.] To surround.\n[v.] To place or mark a circle around.","ex":"The set of all points (x, y) such that (x − 1)2 + y2 = r2 is a circle of radius r around the point (1, 0)."},"CINCH":{"p":"/sɪntʃ/","s":"n./v.","e":"[n.] A simple saddle girth used in Mexico.\n[n.] Something that is very easy to do.\n[n.] A firm hold.\n[v.] To bring to certain conclusion.\n[v.] To tighten down.","ex":"No problem. It's a cinch."},"CARE":{"p":"/kɛə/","s":"n.","e":"[n.] Grief, sorrow.\n[n.] Close attention; concern; responsibility.\n[n.] Worry.","ex":"Care should be taken when holding babies."},"CLAMP":{"p":"/klæmp/","s":"n./v.","e":"[n.] A brace, band, or clasp for strengthening or holding things together.\n[n.] An instrument used to temporarily shut off blood vessels, etc.\n[n.] A parking enforcement device used to immobilise a car until it can be towed or a fine is paid; a wheel clamp.\n[v.] To fasten in place or together with (or as if with) a clamp.\n[v.] To hold or grip tightly.\n[v.] To modify (a numeric value) so it lies within a specific range.","ex":""},"CHANGE":{"p":"/tʃeɪndʒ/","s":"n./v.","e":"[n.] The process of becoming different.\n[n.] Small denominations of money given in exchange for a larger denomination.\n[n.] A replacement, e.g. a change of clothes\n[v.] To become something different.\n[v.] To make something into something else.\n[v.] To replace.","ex":"The product is undergoing a change in order to improve it."},"CLUNG":{"p":"/ˈklʌŋ/","s":"v./adj.","e":"[v.] To hold very tightly, as to not fall off.\n[v.] To adhere to an object, without being affixed, in such a way as to follow its contours. Used especially of fabrics and films.\n[v.] To cause to adhere to, especially by twining round or embracing.\n[adj.] Wasted away; shrunken","ex":"Seaweed clung to the anchor."},"CHANCE":{"p":"[tʃʰans]","s":"n./adj./adv.","e":"[n.] An opportunity or possibility.\n[n.] Random occurrence; luck.\n[n.] The probability of something happening.\n[adj.] Happening by chance, casual.\n[adv.] Perchance; perhaps.","ex":"We had the chance to meet the president last week."},"COFFEE":{"p":"/ˈkɑ.fi/","s":"n./v./adj.","e":"[n.] A beverage made by infusing the beans of the coffee plant in hot water.\n[n.] A serving of this beverage.\n[n.] The seeds of the plant used to make coffee, misnamed ‘beans’ due to their shape.\n[v.] To drink coffee.\n[adj.] Of a pale brown colour, like that of milk coffee.\n[adj.] Of a table: a small, low table suitable for people in lounge seating to put coffee cups on.","ex":""},"CONFIRM":{"p":"/kənˈfɜːm/","s":"v.","e":"[v.] To strengthen; to make firm or resolute.\n[v.] To administer the sacrament of confirmation on (someone).\n[v.] To assure the accuracy of previous statements.","ex":""},"CONTACT":{"p":"","s":"n./v.","e":"[n.] The act of touching physically; being in close association.\n[n.] The establishment of communication (with).\n[n.] A nodule designed to connect a device with something else.\n[v.] To touch; to come into physical contact with.\n[v.] To establish communication with something or someone","ex":"I haven't been in contact with her for years."},"CATALOG":{"p":"","s":"n./v.","e":"[n.] A systematic list of names, books, pictures etc.\n[n.] A complete (usually alphabetical) list of items.\n[n.] A list of all the publications in a library.\n[v.] To put into a catalogue.\n[v.] To make a catalogue of.\n[v.] To add items (e.g. books) to an existing catalogue.","ex":""},"CONTAIN":{"p":"/kənˈteɪn/","s":"v.","e":"[v.] To hold inside.\n[v.] To include as a part.\n[v.] To put constraint upon; to restrain; to confine; to keep within bounds.","ex":"I'm so excited, I can hardly contain myself!"},"CONTENT":{"p":"/kənˈtɛnt/","s":"n./v./adj./int.","e":"[n.] (except in phrases) Satisfaction, contentment; pleasure.\n[v.] To give contentment or satisfaction; to satisfy; to make happy.\n[v.] To satisfy the expectations of; to pay; to requite\n[adj.] Satisfied\n[int.] Alright, agreed","ex":"You can't have any more - you'll have to content yourself with what you already have."},"COO":{"p":"/kuː/","s":"n./v.","e":"[n.] The murmuring sound made by a dove or pigeon.\n[n.] (by extension) An expression of pleasure made by a person.\n[v.] To make a soft murmuring sound, as a pigeon.\n[v.] To speak in an admiring fashion, to be enthusiastic about.","ex":""},"CONCERT":{"p":"/ˈkɒnsət/","s":"n./v.","e":"[n.] Agreement in a design or plan; union formed by mutual communication of opinions and views; accordance in a scheme; harmony; simultaneous action.\n[n.] Musical accordance or harmony; concord.\n[n.] A musical entertainment in which several voices or instruments take part.\n[v.] To plan together; to settle or adjust by conference, agreement, or consultation.\n[v.] To plan; to devise; to arrange.\n[v.] To act in harmony or conjunction; to form combined plans.","ex":"I'm going to the rock concert on Friday."},"CORE":{"p":"/kɔː/","s":"n./v.","e":"[n.] The central part of fruit, containing the kernels or seeds.\n[n.] The heart or inner part of a physical thing\n[n.] The center or inner part of a space or area\n[v.] To remove the core of an apple or other fruit.\n[v.] To extract a sample with a drill.","ex":"the core of an apple or quince"},"CORGI":{"p":"/ˈkɔːɡi/","s":"n.","e":"[n.] A dog of a breed having a small body, short legs and fox-like features.","ex":""},"CONSULT":{"p":"","s":"n./v.","e":"[n.] The act of consulting or deliberating; consultation\n[n.] The result of consultation; determination; decision.\n[n.] A council; a meeting for consultation.\n[v.] To seek the opinion or advice of another; to take counsel; to deliberate together; to confer.\n[v.] To advise or offer expertise.\n[v.] To work as a consultant or contractor rather than as a full-time employee of a firm.","ex":""},"COSTLY":{"p":"/ˈkɒst.li/","s":"adj.","e":"[adj.] Of high cost; expensive.","ex":"a costly activity"},"COPY":{"p":"/ˈkɒpi/","s":"n./v.","e":"[n.] The result of copying; an identical duplicate of an original.\n[n.] An imitation, sometimes of inferior quality.\n[n.] The text that is to be typeset.\n[v.] To produce an object identical to a given object.\n[v.] To give or transmit a copy to (a person).\n[v.] To place a copy of an object in memory for later use.","ex":"Please bring me the copies of those reports."},"COTTON":{"p":"/ˈkɒt.n̩/","s":"n./v./adj.","e":"[n.] Gossypium, a genus of plant used as a source of cotton fiber.\n[n.] Any plant that encases its seed in a thin fiber that is harvested and used as a fabric or cloth.\n[n.] Any fiber similar in appearance and use to Gossypium fiber.\n[v.] To provide with cotton.\n[v.] To make or become cotton-like\n[v.] To protect from harsh stimuli, coddle, or muffle.","ex":""},"COOL":{"p":"/kuːl/","s":"n./adj.","e":"[n.] A moderate or refreshing state of cold; moderate temperature of the air between hot and cold; coolness.\n[n.] A calm temperament.\n[n.] The property of being cool, popular or in fashion.\n[adj.] Having a slightly low temperature; mildly or pleasantly cold.\n[adj.] Allowing or suggesting heat relief.\n[adj.] Of a color, in the range of violet to green.","ex":"in the cool of the morning"},"COUNTER":{"p":"/ˈkaʊntə/","s":"n.","e":"[n.] One who counts\n[n.] A reckoner; someone who collects data by counting; an enumerator.\n[n.] An object (now especially a small disc) used in counting or keeping count, or as a marker in games, etc.","ex":"He's only 16 months, but is already a good counter – he can count to 100."},"COUPLE":{"p":"/ˈkʌpəl/","s":"n./v./adj.","e":"[n.] Two partners in a romantic or sexual relationship.\n[n.] Two of the same kind connected or considered together.\n[n.] A small number.\n[v.] To join (two things) together, or (one thing) to (another).\n[v.] To join in wedlock; to marry.\n[v.] To join in sexual intercourse; to copulate.","ex":"I've coupled our system to theirs."},"COURSE":{"p":"/kɔːs/","s":"n./v.","e":"[n.] A sequence of events.\n[n.] A path that something or someone moves along.\n[n.] The lowest square sail in a fully rigged mast, often named according to the mast.\n[v.] To run or flow (especially of liquids and more particularly blood).\n[v.] To run through or over.\n[v.] To pursue by tracking or estimating the course taken by one's prey; to follow or chase after.","ex":"The normal course of events seems to be just one damned thing after another."},"CORNER":{"p":"/ˈkɔːnə(ɹ)/","s":"n./v.","e":"[n.] The point where two converging lines meet; an angle, either external or internal.\n[n.] An edge or extremity; the part farthest from the center; hence, any quarter or part, or the direction in which it lies.\n[n.] A secret or secluded place; a remote or out of the way place; a nook.\n[v.] To drive (someone or something) into a corner or other confined space.\n[v.] To trap in a position of great difficulty or hopeless embarrassment.\n[v.] To put (someone) in an awkward situation.","ex":"The corners of the wire mesh were reinforced with little blobs of solder."},"COVET":{"p":"/ˈkʌvɪt/","s":"v.","e":"[v.] To wish for with eagerness; to desire possession of, often enviously.\n[v.] To long for inordinately or unlawfully; to hanker after (something forbidden).\n[v.] To yearn; to have or indulge an inordinate desire, especially for another's possession.","ex":""},"COWED":{"p":"/kaʊd/","s":"v./adj.","e":"[v.] (chiefly in the passive voice) To intimidate; to daunt the spirits or courage of.\n[adj.] Frightened into submission.","ex":"Con artists are not cowed by the law."},"COUNCIL":{"p":"/ˈkaʊn.səl/","s":"n.","e":"[n.] A committee that leads or governs (e.g. city council, student council).\n[n.] Discussion or deliberation.","ex":""},"COWER":{"p":"/ˈkaʊə/","s":"v.","e":"[v.] To crouch or cringe, or to avoid or shy away from something, in fear.\n[v.] To crouch in general.\n[v.] To cause to cower; to frighten into submission.","ex":"He'd be useless in war. He'd just cower in his bunker until the enemy came in and shot him, or until the war was over."},"COUNTRY":{"p":"/ˈkɐntɹi/","s":"n./adj.","e":"[n.] (chiefly British) An area of land; a district, region.\n[n.] A set region of land having particular human occupation or agreed limits, especially inhabited by members of the same race, speakers of the same language etc., or associated with a given person, occupation, species etc.\n[n.] The territory of a nation, especially an independent nation state or formerly independent nation; a political entity asserting ultimate authority over a geographical area; a sovereign state.\n[adj.] From or in the countryside or connected with it.\n[adj.] Of or connected to country music.\n[n.] A style of popular music that originated in the folk music of the rural population of the southern and western United States and characterized by string-band instruments and simple melodies.","ex":""},"CREATE":{"p":"/kɹiːˈeɪt/","s":"v./adj.","e":"[v.] To bring into existence; (sometimes in particular:)\n[v.] To cause, to bring (a non-object) about by an action, behavior, or event, to occasion.\n[v.] To confer or invest with a rank or title of nobility, to appoint, ordain or constitute.\n[adj.] Created, resulting from creation.","ex":"You can create the color orange by mixing yellow and red."},"COOKIE":{"p":"/ˈkuːki/","s":"n./v.","e":"[n.] A small, flat, baked good which is either crisp or soft but firm.\n[n.] A sweet baked good (as in the previous sense) usually having chocolate chips, fruit, nuts etc. baked into it.\n[n.] A bun.\n[v.] To send a cookie to (a user, computer, etc.).","ex":""},"COOKING":{"p":"/ˈkʊ.kɪŋ/","s":"v./n./adj.","e":"[v.] To prepare (food) for eating by heating it, often by combining it with other ingredients.\n[v.] To prepare (unspecified) food for eating by heating it, often by combining it with other ingredients.\n[v.] To be cooked.\n[v.] To make the noise of the cuckoo.\n[v.] To throw.\n[n.] The process of preparing food by using heat.","ex":"I'm cooking bangers and mash."},"COUPE":{"p":"/kuːp/","s":"n.","e":"[n.] An ice cream dessert; the glass it is served in.\n[n.] A car with two doors (variant of coupé).\n[n.] An area of forest where harvesting of wood is planned or has taken place.","ex":""},"CREDIT":{"p":"/ˈkɹɛdɪt/","s":"n./v.","e":"[n.] Reliance on the truth of something said or done; faith; trust.\n[n.] Recognition and respect.\n[n.] Acknowledgement of a contribution, especially in the performing arts.\n[v.] To believe; to put credence in.\n[v.] To add to an account.\n[v.] To acknowledge the contribution of.","ex":"He arrived five minutes late, but to his credit he did work an extra ten minutes at the end of his shift."},"CRIER":{"p":"/ˈkraɪə/","s":"n.","e":"[n.] One who cries.\n[n.] An officer who proclaims the orders or directions of a court, or who gives public notice by loud proclamation, such as a town crier.","ex":""},"CRIMP":{"p":"/kɹɪmp/","s":"n./v./adj.","e":"[n.] A fastener or a fastening method that secures parts by bending metal around a joint and squeezing it together, often with a tool that adds indentations to capture the parts.\n[n.] The natural curliness of wool fibres.\n[n.] (usually in the plural) Hair that is shaped so it bends back and forth in many short kinks.\n[v.] To press into small ridges or folds, to pleat, to corrugate.\n[v.] To fasten by bending metal so that it squeezes around the parts to be fastened.\n[v.] To pinch and hold; to seize.","ex":"The strap was held together by a simple metal crimp."},"CROCK":{"p":"/kɹɒk/","s":"n./v.","e":"[n.] A stoneware or earthenware jar or storage container.\n[n.] A piece of broken pottery, a shard.\n[n.] A person who is physically limited by age, illness or injury.\n[v.] To break something or injure someone.\n[v.] (leatherworking) To transfer coloring through abrasion from one item to another.\n[v.] To cover the drain holes of a planter with stones or similar material, in order to ensure proper drainage.","ex":"old crocks’ home"},"CROP":{"p":"/kɹɒp/","s":"n.","e":"[n.] A plant, especially a cereal, grown to be harvested as food, livestock fodder or fuel or for any other economic purpose.\n[n.] The natural production for a specific year, particularly of plants.\n[n.] A group, cluster or collection of things occurring at the same time.","ex":"the farmer had lots of crops to sell at the market"},"CRYSTAL":{"p":"/ˈkɹɪstəl/","s":"n./adj.","e":"[n.] A solid composed of an array of atoms or molecules possessing long-range order and arranged in a pattern which is periodic in three dimensions.\n[n.] A piece of glimmering, shining mineral resembling ice or glass.\n[n.] A fine type of glassware, or the material used to make it.\n[adj.] Very clear.","ex":"\"Do I make myself clear?\" / \"Crystal.\""},"CULTURE":{"p":"/ˈkʌlt͡ʃə/","s":"n./v.","e":"[n.] The arts, customs, lifestyles, background, and habits that characterize a particular society or nation.\n[n.] The beliefs, values, behaviour and material objects that constitute a people's way of life.\n[n.] The conventional conducts and ideologies of a community; the system comprising of the accepted norms and values of a society.\n[v.] To maintain in an environment suitable for growth (especially of bacteria) (compare cultivate)\n[v.] To increase the artistic or scientific interest (in something) (compare cultivate)","ex":""},"CUMIN":{"p":"/ˈkjuːmɪn/","s":"n.","e":"[n.] The flowering plant Cuminum cyminum, in the family Apiaceae.\n[n.] Its aromatic long seed, used as a spice, notably in Indian, Middle Eastern, and Mexican cookery.","ex":"Cumin is native to the region from the eastern Mediterranean to India."},"CRESS":{"p":"/kɹɛs/","s":"n.","e":"[n.] (plants) A plant of various species, chiefly cruciferous. The leaves have a moderately pungent taste, and are used as a salad and antiscorbutic.","ex":""},"CUSTOM":{"p":"/ˈkʌstəm/","s":"n./v./adj.","e":"[n.] Frequent repetition of the same behavior; way of behavior common to many; ordinary manner; habitual practice; method of doing, living or behaving.\n[n.] Traditional beliefs or rituals\n[n.] Habitual buying of goods; practice of frequenting, as a shop, factory, etc., for making purchases or giving orders; business support.\n[v.] To make familiar; to accustom.\n[v.] To supply with customers.\n[v.] To pay the customs of.","ex":"The Ancient Egyptian culture had many distinctive and interesting beliefs and customs."},"CYBER":{"p":"/ˈsʌɪ.bə/","s":"n./v./adj.","e":"[n.] Everything having to do with the Internet considered collectively.\n[v.] To engage in cybersex.\n[adj.] Of, or having to do with, the Internet; alternative spelling of cyber-\n[adj.] Cybergoth.","ex":"Wanna cyber?"},"DAILY":{"p":"/ˈdeɪli/","s":"n./v./adj.","e":"[n.] Something that is produced, consumed, used, or done every day.\n[v.] To drive an automobile frequently, on a daily basis, for regular and mundane tasks.\n[adj.] That occurs every day, or at least every working day\n[adj.] Diurnal, by daylight, as opposed to nightly","ex":""},"DAISY":{"p":"/ˈdeɪ.zi/","s":"n.","e":"[n.] A wild flowering plant Bellis perennis of the Asteraceae family, with a yellow head and white petals\n[n.] Many other flowering plants of various species.\n[n.] A boot or other footwear.","ex":""},"CREATED":{"p":"/kɹiˈeɪtɪd/","s":"v.","e":"[v.] To bring into existence; (sometimes in particular:)\n[v.] To cause, to bring (a non-object) about by an action, behavior, or event, to occasion.\n[v.] To confer or invest with a rank or title of nobility, to appoint, ordain or constitute.","ex":"You can create the color orange by mixing yellow and red."},"CRISIS":{"p":"/ˈkɹaɪsɪs/","s":"n.","e":"[n.] A crucial or decisive point or situation; a turning point.\n[n.] An unstable situation, in political, social, economic or military affairs, especially one involving an impending abrupt change.\n[n.] A sudden change in the course of a disease, usually at which point the patient is expected to either recover or die.","ex":""},"DANGER":{"p":"/ˈdeɪn.dʒə(ɹ)/","s":"n./v.","e":"[n.] Exposure to likely harm; peril.\n[n.] An instance or cause of likely harm.\n[n.] Mischief.\n[v.] To claim liability.\n[v.] To imperil; to endanger.\n[v.] To run the risk.","ex":"There's plenty of danger in the desert."},"CURRENT":{"p":"/ˈkʌɹənt/","s":"n./adj.","e":"[n.] The generally unidirectional movement of a gas or fluid.\n[n.] The part of a fluid that moves continuously in a certain direction, especially short for ocean current.\n[n.] The time rate of flow of electric charge.\n[adj.] Existing or occurring at the moment\n[adj.] Generally accepted, used, practiced, or prevalent at the moment\n[adj.] Running or moving rapidly","ex":"current events;  current leaders;  current negotiations"},"DATE":{"p":"/deɪt/","s":"n.","e":"[n.] The fruit of the date palm, Phoenix dactylifera, somewhat in the shape of an olive, containing a soft, sweet pulp and enclosing a hard kernel.\n[n.] The date palm.","ex":"We made a nice cake from dates."},"DATER":{"p":"/ˈdeɪtə(ɹ)/","s":"n.","e":"[n.] One who dates.\n[n.] A date-stamping device.","ex":""},"DAMAGE":{"p":"/ˈdæmɪdʒ/","s":"n./v.","e":"[n.] Injury or harm; the condition or measure of something not being intact.\n[n.] Cost or expense.\n[v.] To impair the soundness, goodness, or value of; to harm or cause destruction.\n[v.] To undergo damage.","ex":"The storm did a lot of damage to the area."},"DAWN":{"p":"/doːn/","s":"n./v.","e":"[n.] The morning twilight period immediately before sunrise.\n[n.] The rising of the sun.\n[n.] The time when the sun rises.\n[v.] To begin to brighten with daylight.\n[v.] To start to appear or be realized.\n[v.] To begin to give promise; to begin to appear or to expand.","ex":"She rose before dawn to meet the train."},"DALLY":{"p":"/ˈdæli/","s":"v.","e":"[v.] To waste time in trivial activities, or in idleness; to trifle.\n[v.] To caress, especially of a sexual nature; to fondle or pet\n[v.] To delay unnecessarily; to while away.","ex":""},"DARED":{"p":"/dɛəd/","s":"v.","e":"[v.] To have enough courage (to do something).\n[v.] To defy or challenge (someone to do something)\n[v.] To have enough courage to meet or do something, go somewhere, etc.; to face up to\n[v.] To stare stupidly or vacantly; to gaze as though amazed or terrified.\n[v.] To lie or crouch down in fear.","ex":"I wouldn't dare argue with my boss."},"DEAL":{"p":"/diːl/","s":"n.","e":"[n.] A division, a portion, a share.\n[n.] (often followed by of) An indefinite quantity or amount; a lot (now usually qualified by great or good).","ex":"We gave three deals of grain in tribute to the king."},"DARK":{"p":"/dɑːk/","s":"adj.","e":"[adj.] Having an absolute or (more often) relative lack of light.\n[adj.] (of colour) Dull or deeper in hue; not bright or light.\n[adj.] Hidden, secret, obscure.","ex":"The room was too dark for reading."},"DEAR":{"p":"/diːɹ/","s":"n./v./adj./adv.","e":"[n.] A very kind, loving person.\n[n.] A beloved person.\n[n.] An affectionate, familiar term of address, such as used between husband and wife.\n[v.] To endear.\n[adj.] High in price; expensive.\n[adj.] Loved; lovable.","ex":"My cousin is such a dear, always drawing me pictures."},"DEATH":{"p":"/diːθ/","s":"n.","e":"[n.] The cessation of life and all associated processes; the end of an organism's existence as an entity independent from its environment and its return to an inert, nonliving state.\n[n.] (often capitalized) The personification of death as a hooded figure with a scythe; the Grim Reaper. The pronoun he is not the only option, but probably the most traditional one, as it matches with the male grammatical gender of Old English dēaþ, also with cognate German der Tod. The fourth apocalyptic rider (Bible, revelations 6:8) is male θᾰ́νᾰτος (thanatos) in Greek. It has the female name Mors in Latin, but is referred to with male forms qui and eum. The following quotes show this rider on a pale horse is his in the English Bible and she in Peter Gabriel's lyrics.\n[n.] (the death) The collapse or end of something.","ex":"The death of my grandmother saddened the whole family."},"DEBATE":{"p":"/dɪˈbeɪt/","s":"n./v.","e":"[n.] An argument, or discussion, usually in an ordered or formal setting, often with more than two people, generally ending with a vote or other decision.\n[n.] An informal and spirited but generally civil discussion of opposing views.\n[n.] Discussion of opposing views.\n[v.] To participate in a debate; to dispute, argue, especially in a public arena.\n[v.] To fight.\n[v.] To engage in combat for; to strive for.","ex":"After a four-hour debate, the committee voted to table the motion."},"DECADE":{"p":"/dəˈkeɪd/","s":"n.","e":"[n.] A group, set, or series of ten , particularly:\n[n.] A set of resistors, capacitors, etc. connected so as to provide even increments between one and ten times a base electrical resistance.\n[n.] The interval between any two quantities having a ratio of 10 to 1.","ex":"a decade of soldiers"},"DEBAR":{"p":"/dɪˈbɑː(ɹ)/","s":"v.","e":"[v.] To exclude or shut out; to bar.\n[v.] To hinder or prevent.\n[v.] To prohibit (a person or company that has been convicted of criminal acts in connection with a government program) from future participation in that program.","ex":""},"DAUNT":{"p":"/dɔːnt/","s":"v.","e":"[v.] To discourage, intimidate.\n[v.] To overwhelm.","ex":""},"DECAL":{"p":"/dɪˈkæl/","s":"n./v.","e":"[n.] A design or picture produced in order to be transferred to another surface either permanently or temporarily.\n[n.] A decorative sticker.\n[v.] To apply decals to.","ex":""},"DEALER":{"p":"/ˈdiːlə(ɹ)/","s":"n.","e":"[n.] One who deals in goods, especially automobiles; a middleman.\n[n.] A drug dealer, one who peddles illicit drugs.\n[n.] A particular type of stock broker or trader.","ex":"That used car dealer gave me a great deal on my 1962 rusted-out Volkswagen bug!"},"DECIDE":{"p":"/dɪˈsaɪd/","s":"v.","e":"[v.] To resolve (a contest, problem, dispute, etc.); to choose, determine, or settle\n[v.] To make a judgment, especially after deliberation\n[v.] To cause someone to come to a decision","ex":"Her last-minute goal decided the game."},"DEFINE":{"p":"/dɪˈfaɪn/","s":"n./v.","e":"[n.] A kind of macro in source code that replaces one text string with another wherever it occurs.\n[v.] To determine with precision; to mark out with distinctness; to ascertain or exhibit clearly.\n[v.] To settle, decide (an argument etc.)\n[v.] To express the essential nature of something.","ex":"the defining power of an optical instrument"},"DEGREE":{"p":"/dɪˈɡɹiː/","s":"n.","e":"[n.] A stage of proficiency or qualification in a course of study, now especially an award bestowed by a university or, in some countries, a college, as a certification of academic achievement. (In the United States, can include secondary schools.)\n[n.] A unit of measurement of angle equal to 1/360 of a circle's circumference.\n[n.] A unit of measurement of temperature on any of several scales, such as Celsius or Fahrenheit.","ex":"She has two bachelor's degrees and is studying towards a master's degree."},"DEIGN":{"p":"/deɪn/","s":"v.","e":"[v.] To condescend; to do despite a perceived affront to one's dignity.\n[v.] To condescend to give; to do something.\n[v.] To esteem worthy; to consider worth notice.","ex":"He didn't even deign to give us a nod of the head; he thought us that far beneath him."},"DEBIT":{"p":"/ˈdɛb.ɪt/","s":"n./v./adj.","e":"[n.] In bookkeeping, an entry in the left hand column of an account.\n[n.] A sum of money taken out of a bank account. Thus called, because in bank's bookkeeping a cash withdrawal diminishes the amount of money held on the account, i.e. bank's debt to the customer.\n[v.] To make an entry on the debit side of an account.\n[v.] To record a receivable in the bookkeeping.\n[adj.] Of or relating to process of taking money from an account\n[adj.] Of or relating to the debit card function of a debit card rather than its often available credit card function","ex":"A cash sale is recorded as debit on the cash account and as credit on the sales account."},"DEBUG":{"p":"/diːˈbʌɡ/","s":"n./v.","e":"[n.] The action, or a session, of reviewing source code to find and eliminate errors.\n[v.] To search for and eliminate malfunctioning elements or errors in something, especially a computer program or machinery.\n[v.] To remove a hidden electronic surveillance device from (somewhere).\n[v.] To remove insects from (somewhere), especially lice.","ex":""},"DECAY":{"p":"/dɪˈkeɪ/","s":"n./v.","e":"[n.] The process or result of being gradually decomposed.\n[n.] A deterioration of condition; loss of status or fortune.\n[v.] To deteriorate, to get worse, to lose strength or health, to decline in quality.\n[v.] (of organic material) To rot, to go bad.\n[v.] (of an unstable atom) To change by undergoing fission, by emitting radiation, or by capturing or losing one or more electrons.","ex":"The pair loved to take pictures in the decaying hospital on forty-third street."},"DELVE":{"p":"/dɛlv/","s":"v.","e":"[v.] To dig the ground, especially with a shovel.\n[v.] To search thoroughly and carefully for information, research, dig into, penetrate, fathom, trace out\n[v.] To dig, to excavate.","ex":""},"DECRY":{"p":"/dɪˈkɹaɪ/","s":"v.","e":"[v.] To denounce as harmful.\n[v.] To blame for ills.","ex":""},"DELIVER":{"p":"/dɪˈlɪvə(ɹ)/","s":"v.","e":"[v.] To set free from restraint or danger.\n[v.] (process) To do with birth.\n[v.] To free from or disburden of anything.","ex":"deliver a captive from the prison"},"DEMON":{"p":"/ˈdiː.mən/","s":"n.","e":"[n.] An evil supernatural spirit.\n[n.] A neutral supernatural spirit.\n[n.] Someone with great strength, passion or skill for a particular activity, pursuit etc.; an enthusiast.","ex":"He’s a demon at the card tables."},"DEMAND":{"p":"/dɪˈmɑːnd/","s":"n./v.","e":"[n.] The desire to purchase goods and services.\n[n.] The amount of a good or service that consumers are willing to buy at a particular price.\n[n.] A forceful claim for something.\n[v.] To request forcefully.\n[v.] To claim a right to something.\n[v.] To ask forcefully for information.","ex":"Prices usually go up when demand exceeds supply."},"DEFEND":{"p":"/dɪˈfɛnd/","s":"v.","e":"[v.] To ward off attacks against; to fight to protect; to guard.\n[v.] To support by words or writing; to vindicate, talk in favour of.\n[v.] To make legal defence of; to represent (the accused).","ex":""},"DEFENSE":{"p":"/dɪˈfɛns/","s":"n.","e":"[n.] The action of defending or protecting from attack, danger, or injury.\n[n.] Anything employed to oppose attack(s).\n[n.] An argument in support or justification of something.","ex":""},"DEPOSIT":{"p":"/dɪˈpɒzɪt/","s":"n./v.","e":"[n.] Sediment or rock that is not native to its present location or is different from the surrounding material. Sometimes refers to ore or gems.\n[n.] That which is placed anywhere, or in anyone's hands, for safekeeping; something entrusted to the care of another.\n[n.] Money placed in an account.\n[v.] To lay down; to place; to put.\n[v.] To lay up or away for safekeeping; to put up; to store.\n[v.] To entrust one's assets to the care of another. Sometimes done as collateral.","ex":"A crocodile deposits her eggs in the sand."},"DESIRE":{"p":"/dɪˈzaɪə/","s":"n./v.","e":"[n.] Someone or something wished for.\n[n.] Strong attraction, particularly romantic or sexual.\n[n.] The feeling of desiring; an eager longing for something.\n[v.] To want; to wish for earnestly.\n[v.] To put a request to (someone); to entreat.\n[v.] To want emotionally or sexually.","ex":"It is my desire to speak with you."},"DESKTOP":{"p":"[ˈdɛsk.ˌtɔp]","s":"n./adj.","e":"[n.] The top surface of a desk.\n[n.] A desktop computer.\n[n.] The main graphical user interface of an operating system, usually displaying icons, windows and background wallpaper.\n[adj.] Designed for use on a desk or similar piece of furniture.\n[adj.] Of an application, designed to be run on a personal computer.","ex":"Laptops are often more expensive than desktops."},"DETER":{"p":"/dɪˈtɜː(ɹ)/","s":"v.","e":"[v.] To prevent something from happening.\n[v.] To persuade someone not to do something; to discourage.\n[v.] To distract someone from something.","ex":""},"DIAMOND":{"p":"/ˈdaɪ(ə)mənd/","s":"n./v./adj.","e":"[n.] A glimmering glass-like mineral that is an allotrope of carbon in which each atom is surrounded by four others in the form of a tetrahedron.\n[n.] A gemstone made from this mineral.\n[n.] A ring containing a diamond.\n[v.] To adorn with or as if with diamonds\n[adj.] Made of, or containing diamond, a diamond or diamonds.\n[adj.] Of, relating to, or being a sixtieth anniversary.","ex":"The saw is coated with diamond."},"DEPEND":{"p":"/dɪˈpɛnd/","s":"v.","e":"[v.] (followed by on or upon, formerly also by of) To be contingent or conditioned; to have something as a necessary condition; to hinge on.\n[v.] (followed by on or upon) To trust; to have confidence; to rely.\n[v.] To hang down; to be sustained by being fastened or attached to something above.","ex":"We would like to go skiing, but it depends on the amount of snow."},"DESIGN":{"p":"/dɪˈzaɪn/","s":"n./v.","e":"[n.] A specification of an object or process, referring to requirements to be satisfied and thus conditions to be met for them to solve a problem.\n[n.] A plan (with more or less detail) for the structure and functions of an artifact, building or system.\n[n.] A pattern, as an element of a work of art or architecture.\n[v.] To plan and carry out (a picture, work of art, construction etc.).\n[v.] To plan (to do something).\n[v.] To assign, appoint (something to someone); to designate.","ex":"The king designed to mount an expedition to the New World."},"DEITY":{"p":"/ˈdeɪ.ɪ.tɪ/","s":"n.","e":"[n.] A supernatural divine being; a god or goddess.\n[n.] The state, position, or fact of being a god or God. [from 14th c.]\n[n.] A celestial being inferior to a supreme God but superior to man.\n[n.] The study of religion or religions.","ex":""},"DETAIL":{"p":"/ˈdiːteɪl/","s":"n./v.","e":"[n.] Something small enough to escape casual notice.\n[n.] A profusion of details.\n[n.] The small things that can escape casual notice.\n[v.] To explain in detail.\n[v.] To clean carefully (particularly of road vehicles) (always pronounced. /ˈdiːteɪl/)\n[v.] To assign to a particular task","ex":"Note this fine detail in the lower left corner."},"DICEY":{"p":"/ˈdaɪsi/","s":"adj.","e":"[adj.] Fraught with danger.\n[adj.] Of uncertain, risky outcome.\n[adj.] Of doubtful or uncertain efficacy, provenance, etc.; dodgy.","ex":""},"DIGITAL":{"p":"/ˈdɪd͡ʒɪtəɫ/","s":"n./adj.","e":"[n.] A digital option.\n[n.] Digital equipment or technology.\n[n.] Short for digital art.\n[adj.] Having to do with digits (fingers or toes); performed with a finger.\n[adj.] Property of representing values as discrete, usually binary, numbers rather than a continuous spectrum.\n[adj.] Of or relating to computers or the Information Age.","ex":"He moved to digital for the first time, using a Sony camera."},"DEVICE":{"p":"/dəˈvaɪs/","s":"n.","e":"[n.] Any piece of equipment made for a particular purpose, especially a mechanical or electrical one.\n[n.] A peripheral device; an item of hardware.\n[n.] A project or scheme, often designed to deceive; a stratagem; an artifice.","ex":"There are a number of household devices in a kitchen such as a dishwasher, a garbage disposal, or an electric can opener."},"DINGO":{"p":"/ˈdɪŋɡəʊ/","s":"n.","e":"[n.] Canis lupus dingo, a wild dog native to Australia.","ex":""},"DINNER":{"p":"/ˈdɪnə/","s":"n./v.","e":"[n.] A midday meal (in a context in which the evening meal is called supper or tea).\n[n.] The main meal of the day, often eaten in the evening.\n[n.] An evening meal.\n[v.] To eat a dinner.\n[v.] To provide (someone) with a dinner.","ex":""},"DIARY":{"p":"/ˈdaɪəɹi/","s":"n./v./adj.","e":"[n.] A daily log of experiences, especially those of the writer.\n[n.] A personal organizer or appointment diary.\n[v.] To keep a diary or journal.\n[adj.] Lasting for one day.","ex":"They kept separate diaries. His was on paper and her diary was on her computer's hard drive."},"DEPUTY":{"p":"/ˈdɛpjəti/","s":"n./v.","e":"[n.] One appointed as the substitute of another, and empowered to act for them, in their name or their behalf; a substitute in office\n[n.] A person employed to install and remove props, brattices, etc. and to clear gas, for the safety of the miners.\n[n.] (France): A member of the Chamber of Deputies, formerly called Corps Législatif\n[v.] To deputise","ex":"As the deputy store manager, he is able to fire staff."},"DIRTY":{"p":"/ˈdɜːti/","s":"v./adj./adv.","e":"[v.] To make (something) dirty.\n[v.] To stain or tarnish (somebody) with dishonor.\n[v.] To debase by distorting the real nature of (something).\n[adj.] Unclean; covered with or containing unpleasant substances such as dirt or grime.\n[adj.] That makes one unclean; corrupting, infecting.\n[adj.] Morally unclean; obscene or indecent, especially sexually.","ex":"Despite a walk in the rain, my shoes weren't too dirty."},"DESERT":{"p":"/dɪˈzɜːt/","s":"n.","e":"[n.] (usually in the plural) That which is deserved or merited; a just punishment or reward","ex":""},"DERBY":{"p":"/ˈdɑː.bi/","s":"n.","e":"[n.] Any of several annual horse races.\n[n.] (by extension) Any organized race.\n[n.] A bowler hat.","ex":"a donkey derby"},"DISCO":{"p":"/ˈdɪskəʊ/","s":"n./v.","e":"[n.] A genre of dance music that was popular in the 1970s, characterized by elements of soul music with a strong Latin-American beat and often accompanied by pulsating lights.\n[v.] To dance disco-style dances.\n[v.] To go to discotheques.\n[n.] (slightly obsolete) A nightclub where dancing takes place.","ex":""},"DITTO":{"p":"/ˈdɪtəʊ/","s":"n./v./adv./int.","e":"[n.] That which was stated before, the aforesaid, the above, the same, likewise.\n[n.] A duplicate or copy of a document, particularly one created by a spirit duplicator.\n[n.] A copy; an imitation.\n[v.] To repeat the aforesaid, the earlier action etc.\n[adv.] As said before, likewise.\n[int.] Used as an expression of agreement with what another person has said, or to indicate that what they have said equally applies to the person being addressed.","ex":"Please run off twenty-four dittos of this assignment, for my students."},"DIFFER":{"p":"/ˈdɪfə/","s":"v.","e":"[v.] Not to have the same traits or characteristics; to be unalike or distinct.\n[v.] (people, groups, etc.) To have diverging opinions, disagree.\n[v.] To be separated in quantity.","ex":"These shoes only differ from those ones in having slightly longer laces."},"DINGY":{"p":"/ˈdɪn.dʒi/","s":"adj.","e":"[adj.] Drab; shabby; dirty; squalid","ex":""},"DIVER":{"p":"/ˈdaɪ̯vəɹ/","s":"n.","e":"[n.] Someone who dives, especially as a sport.\n[n.] Someone who works underwater; a frogman.\n[n.] The loon (bird).","ex":""},"DOES":{"p":"","s":"v.","e":"[v.] (auxiliary) A syntactic marker.\n[v.] To perform; to execute.\n[v.] To cause, make (someone) (do something).","ex":"All you ever do is surf the Internet. What will you do this afternoon?"},"DOCK":{"p":"/dɒk/","s":"n.","e":"[n.] Any of the genus Rumex of coarse weedy plants with small green flowers related to buckwheat, especially common dock, and used as potherbs and in folk medicine, especially in curing nettle rash.\n[n.] A burdock plant, or the leaves of that plant.","ex":""},"DIPLOMA":{"p":"/dɪˈpləʊmə/","s":"n.","e":"[n.] A document issued by an educational institution testifying that the recipient has earned a degree or has successfully completed a particular course of study.","ex":""},"DIZZY":{"p":"/ˈdɪzi/","s":"v./adj.","e":"[v.] To make dizzy, to bewilder.\n[adj.] Having a sensation of whirling, with a tendency to fall; giddy; feeling unbalanced or lightheaded.\n[adj.] Producing giddiness.\n[adj.] Empty-headed, scatterbrained or frivolous; ditzy.","ex":"I stood up too fast and felt dizzy."},"DOCTOR":{"p":"/ˈdɒktə/","s":"n./v.","e":"[n.] A physician; a member of the medical profession; one who is trained and licensed to heal the sick or injured. The final examination and qualification may award a doctor degree in which case the post-nominal letters are D.O., DPM, M.D., DMD, DDS, in the US or MBBS in the UK.\n[n.] A person who has attained a doctorate, such as a Ph.D. or Th.D. or one of many other terminal degrees conferred by a college or university.\n[n.] A veterinarian; a medical practitioner who treats non-human animals.\n[v.] To act as a medical doctor to.\n[v.] To act as a medical doctor.\n[v.] To make (someone) into an (academic) doctor; to confer a doctorate upon.","ex":"If you still feel unwell tomorrow, see your doctor."},"DOILY":{"p":"/ˈdɔɪli/","s":"n.","e":"[n.] A small ornamental piece of lace or linen or paper used to protect a surface from scratches by hard objects such as vases or bowls; or to decorate a plate of food.\n[n.] An old kind of woollen material.","ex":""},"DOING":{"p":"/ˈduːɪŋ/","s":"v./n.","e":"[v.] (auxiliary) A syntactic marker.\n[v.] To perform; to execute.\n[v.] To cause, make (someone) (do something).\n[n.] A deed or action, especially when somebody is held responsible for it.","ex":"All you ever do is surf the Internet. What will you do this afternoon?"},"DIRECT":{"p":"/d(a)ɪˈɹɛkt/","s":"v./adj./adv.","e":"[v.] To manage, control, steer.\n[v.] To aim (something) at (something else).\n[v.] To point out or show to (somebody) the right course or way; to guide, as by pointing out the way.\n[adj.] Proceeding without deviation or interruption.\n[adj.] Straight; not crooked, oblique, or circuitous; leading by the short or shortest way to a point or end.\n[adj.] Straightforward; sincere.","ex":"to direct the affairs of a nation or the movements of an army"},"DONE":{"p":"/dʌn/","s":"v./adj.","e":"[v.] (auxiliary) A syntactic marker.\n[v.] To perform; to execute.\n[v.] To cause, make (someone) (do something).\n[adj.] (of food) Ready, fully cooked.\n[adj.] Having completed or finished an activity.\n[adj.] Being exhausted or fully spent.","ex":"All you ever do is surf the Internet. What will you do this afternoon?"},"DONOR":{"p":"/ˈdəʊnə/","s":"n.","e":"[n.] One who makes a donation.\n[n.] A group or molecule that donates either a radical, electrons or a moiety in a chemical reaction. Compare acceptor.","ex":"The charity raised $2,000 from various donors."},"DOOR":{"p":"/dɔː/","s":"n./v.","e":"[n.] A portal of entry into a building, room, or vehicle, consisting of a rigid plane movable on a hinge. Doors are frequently made of wood or metal. May have a handle to help open and close, a latch to hold the door closed and a lock that ensures the door cannot be opened without the key.\n[n.] Any flap, etc. that opens like a door.\n[n.] (immigration) An entry point.\n[v.] To cause a collision by opening the door of a vehicle in front of an oncoming cyclist or pedestrian.","ex":"I knocked on the vice president's door"},"DOPEY":{"p":"/ˈdəʊpi/","s":"adj.","e":"[adj.] Stupid, silly.","ex":""},"DIVIDE":{"p":"/dɪˈvaɪd/","s":"n./v.","e":"[n.] A thing that divides.\n[n.] An act of dividing.\n[n.] A distancing between two people or things.\n[v.] To split or separate (something) into two or more parts.\n[v.] To share (something) by dividing it.\n[v.] (with by) To calculate the number (the quotient) by which you must multiply one given number (the divisor) to produce a second given number (the dividend).","ex":"Stay on your side of the divide, please."},"DOORS":{"p":"/dɔːz/","s":"n./v.","e":"[n.] A portal of entry into a building, room, or vehicle, consisting of a rigid plane movable on a hinge. Doors are frequently made of wood or metal. May have a handle to help open and close, a latch to hold the door closed and a lock that ensures the door cannot be opened without the key.\n[n.] Any flap, etc. that opens like a door.\n[n.] (immigration) An entry point.\n[v.] To cause a collision by opening the door of a vehicle in front of an oncoming cyclist or pedestrian.","ex":"I knocked on the vice president's door"},"DOTTY":{"p":"/ˈdɒti/","s":"adj.","e":"[adj.] Mildly insane or eccentric; often, senile.\n[adj.] Having an unsteady gait.","ex":"My nan has got dottier and dottier since passing the age of eighty."},"DOUBLE":{"p":"/ˈdʌb.əl/","s":"n./v./adj./adv.","e":"[n.] Twice the number, amount, size, etc.\n[n.] A person who resembles and stands in for another person, often for safety purposes\n[n.] A drink with two portions of alcohol.\n[v.] To multiply by two.\n[v.] To fold over so as to make two folds.\n[v.] To be the double of; to exceed by twofold; to contain or be worth twice as much as.","ex":"Saddam Hussein was rumored to have many doubles."},"DOUBT":{"p":"/dʌʊt/","s":"n./v.","e":"[n.] Disbelief or uncertainty (about something); a particular instance of such disbelief or uncertainty.\n[n.] A point of uncertainty; a query.\n[v.] To be undecided about; to lack confidence in; to disbelieve, to question.\n[v.] To harbour suspicion about; suspect.\n[v.] To anticipate with dread or fear; to apprehend.","ex":"I have doubts about how to convert this code to JavaScript."},"DRAPE":{"p":"/dɹeɪp/","s":"n./v.","e":"[n.] A curtain; a drapery.\n[n.] The way in which fabric falls or hangs.\n[n.] A member of a youth subculture distinguished by its sharp dress, especially peg-leg pants (1950s: e.g. Baltimore, MD). Antonym: square\n[v.] To cover or adorn with drapery or folds of cloth, or as with drapery\n[v.] To spread over, cover.\n[v.] To rail at; to banter.","ex":"to drape a bust, a building, etc."},"DOMAIN":{"p":"/dəʊˈmeɪn/","s":"n.","e":"[n.] A geographic area owned or controlled by a single person or organization.\n[n.] A field or sphere of activity, influence or expertise.\n[n.] A group of related items, topics, or subjects.","ex":"The king ruled his domain harshly."},"DOLLY":{"p":"/ˈdɒli/","s":"n./v.","e":"[n.] A doll.\n[n.] A contrivance for stirring:\n[n.] A tool with an indented head for shaping the head of a rivet.\n[v.] To hit a dolly.\n[v.] To move (an object) using a dolly.\n[v.] To wash (laundry) in a tub using the stirring device called a dolly.","ex":""},"DRAWING":{"p":"/ˈdɹɔ.(w)ɪŋ(ɡ)/","s":"v.","e":"[v.] To move or develop something.\n[v.] To exert or experience force.\n[v.] (fluidic) To remove or separate or displace.","ex":""},"DOSSIER":{"p":"/ˈdɒs.i.eɪ/","s":"n.","e":"[n.] A collection of papers and/or other sources, containing detailed information about a particular person or subject, together with a synopsis of their content.","ex":""},"DRAW":{"p":"/dɹɔː/","s":"n./v.","e":"[n.] The result of a contest that neither side has won; a tie.\n[n.] The procedure by which the result of a lottery is determined.\n[n.] Something that attracts e.g. a crowd.\n[v.] To move or develop something.\n[v.] To exert or experience force.\n[v.] (fluidic) To remove or separate or displace.","ex":"The game ended in a draw."},"DRAWL":{"p":"/dɹɔːl/","s":"n./v.","e":"[n.] A way of speaking slowly while lengthening vowel sounds and running words together. Characteristic of some southern US accents, as well as Scots.\n[v.] To drag on slowly and heavily; to while or dawdle away time indolently.\n[v.] To utter or pronounce in a dull, spiritless tone, as if by dragging out the utterance.\n[v.] To move slowly and heavily; move in a dull, slow, lazy manner.","ex":""},"DREAD":{"p":"/dɹɛd/","s":"n./v./adj.","e":"[n.] Great fear in view of impending evil; fearful apprehension of danger; anticipatory terror.\n[n.] Reverential or respectful fear; awe.\n[n.] Somebody or something dreaded.\n[v.] To fear greatly.\n[v.] To anticipate with fear.\n[v.] To be in dread, or great fear.","ex":"my visit to the doctor is filling me with dread"},"DITTY":{"p":"/ˈdɪti/","s":"n./v.","e":"[n.] A short verse or tune.\n[n.] A saying or utterance, especially one that is short and frequently repeated.\n[v.] To sing; to warble a little tune.","ex":"The Acme mattress ditty has been stuck in my head all day."},"DRAWN":{"p":"[dɹɔːn]","s":"v./adj.","e":"[v.] To move or develop something.\n[v.] To exert or experience force.\n[v.] (fluidic) To remove or separate or displace.\n[adj.] Appearing tired and unwell, as from stress; haggard.\n[adj.] Of a game: undecided; having no definite winner and loser.","ex":""},"DRIFT":{"p":"/dɹɪft/","s":"n./v.","e":"[n.] (physical) Movement; that which moves or is moved.\n[n.] The act or motion of drifting; the force which impels or drives; an overpowering influence or impulse.\n[n.] A place (a ford) along a river where the water is shallow enough to permit crossing to the opposite side.\n[v.] To move slowly, especially pushed by currents of water, air, etc.\n[v.] To move haphazardly without any destination.\n[v.] To deviate gently from the intended direction of travel.","ex":"The balloon was drifting in the breeze."},"DRILL":{"p":"/dɹɪl/","s":"n./v.","e":"[n.] A tool used to remove material so as to create a hole, typically by plunging a rotating cutting bit into a stationary workpiece.\n[n.] The portion of a drilling tool that drives the bit.\n[n.] An activity done as an exercise or practice (especially a military exercise), particularly in preparation for some possible future event or occurrence.\n[v.] To create (a hole) by removing material with a drill (tool).\n[v.] To practice, especially in (or as in) a military context.\n[v.] To cause to drill (practice); to train in military arts.","ex":"Wear safety glasses when operating an electric drill."},"DRAG":{"p":"/dɹæɡ/","s":"n./v.","e":"[n.] Resistance of the air (or some other fluid) to something moving through it.\n[n.] (foundry) The bottom part of a sand casting mold.\n[n.] A device dragged along the bottom of a body of water in search of something, e.g. a dead body, or in fishing.\n[v.] To pull along a surface or through a medium, sometimes with difficulty.\n[v.] To move onward heavily, laboriously, or slowly; to advance with weary effort; to go on lingeringly.\n[v.] To act or proceed slowly or without enthusiasm; to be reluctant.","ex":"When designing cars, manufacturers have to take drag into consideration."},"DOZEN":{"p":"/ˈdʌzən/","s":"n.","e":"[n.] A set of twelve.\n[n.] (as plural only, always followed by of) A large, unspecified number of, comfortably estimated in small multiples of twelve, thus generally implied to be significantly more than ten or twelve, but less than perhaps one or two hundred; many.\n[n.] An old English measure of ore containing 12 hundredweight.","ex":"Can I have a dozen eggs, please?"},"DREW":{"p":"/dɹuː/","s":"v.","e":"[v.] To move or develop something.\n[v.] To exert or experience force.\n[v.] (fluidic) To remove or separate or displace.","ex":""},"DRIVER":{"p":"/ˈdɹaɪ.və(ɹ)/","s":"n.","e":"[n.] One who drives something, in any sense of the verb to drive.\n[n.] Something that drives something, in any sense of the verb to drive.\n[n.] A person who drives a motorized vehicle such as a car or a bus.","ex":""},"DROSS":{"p":"/dɹɑs/","s":"n./v.","e":"[n.] Waste or impure matter.\n[n.] Residue that forms on the surface of a metal from oxidation.\n[n.] The impurities in metal.\n[v.] To remove dross from.","ex":""},"DRYLY":{"p":"/ˈdɹaɪ.li/","s":"adv.","e":"[adv.] In a dry manner.","ex":""},"DRIED":{"p":"/dɹaɪd/","s":"adj./v.","e":"[adj.] Without water or moisture, said of something that has previously been wet or moist; resulting from the process of drying.\n[adj.] Usually of foods: cured, preserved by drying.\n[adj.] Sold raw and unprocessed.\n[v.] To lose moisture.\n[v.] To remove moisture from.\n[v.] To be thirsty.","ex":"dried fish; dried fruit"},"DULLY":{"p":"","s":"adv.","e":"[adv.] In a dull manner; without liveliness; without lustre.","ex":""},"DURING":{"p":"/ˈdjɔː.ɹɪŋ/","s":"v./prep.","e":"[v.] To last, continue, endure.\n[prep.] For all of a given time interval.\n[prep.] At any time or period within a given time interval.","ex":"I lived with my parents during the 1970s."},"DRIVE":{"p":"/dɹaɪv/","s":"n./v.","e":"[n.] Motivation to do or achieve something; ability coupled with ambition.\n[n.] Violent or rapid motion; a rushing onward or away; especially, a forced or hurried dispatch of business.\n[n.] An act of driving animals forward, as to be captured, hunted etc.\n[v.] To provide an impetus for motion or other physical change, to move an object by means of the provision of force thereto.\n[v.] To provide an impetus for a non-physical change, especially a change in one's state of mind.\n[v.] To displace either physically or non-physically, through the application of force.","ex":"Crassus had wealth and wit, but Pompey had drive and Caesar as much again."},"DUTCH":{"p":"/dʌtʃ/","s":"n.","e":"[n.] Wife","ex":""},"DUCHY":{"p":"/ˈdʌtʃi/","s":"n.","e":"[n.] A dominion or region ruled by a duke or duchess. (A grand duchy may be a self-governing state. A simple duchy tends to be a part of a larger kingdom or empire.)","ex":""},"DYING":{"p":"/ˈdaɪ.ɪŋ/","s":"v./n./adj.","e":"[v.] To stop living; to become dead; to undergo death.\n[v.] To (stop living and) undergo (a specified death).\n[v.] To yearn intensely.\n[v.] To colour with dye, or as if with dye.\n[n.] The process of approaching death; loss of life; less precisely, death.\n[n.] (with \"the\") Those who are currently expiring, moribund.","ex":"He died a hero's death."},"DWELT":{"p":"/ˈdwɛlt/","s":"v.","e":"[v.] To live; to reside.\n[v.] To linger (on) a particular thought, idea etc.; to remain fixated (on).\n[v.] To be in a given state.","ex":""},"DWARF":{"p":"/dwɔːf/","s":"n./v./adj.","e":"[n.] Any member of a race of beings from (especially Scandinavian and other Germanic) folklore, usually depicted as having some sort of supernatural powers and being skilled in crafting and metalworking, often as short with long beards, and sometimes as clashing with elves.\n[n.] A person of short stature, often one whose limbs are disproportionately small in relation to the body as compared with normal adults, usually as the result of a genetic condition.\n[n.] An animal, plant or other thing much smaller than the usual of its sort.\n[v.] To render (much) smaller, turn into a dwarf (version).\n[v.] To make appear (much) smaller, puny, tiny.\n[v.] To make appear insignificant.","ex":"dwarf honeysuckle"},"DYNAMIC":{"p":"/daɪˈnæ.mɪk/","s":"n./adj.","e":"[n.] A characteristic or manner of an interaction; a behavior.\n[n.] A moving force.\n[n.] The varying loudness or volume of a song or the markings that indicate the loudness.\n[adj.] Changing; active; in motion.\n[adj.] Powerful; energetic.\n[adj.] Able to change and adapt.","ex":"Watch the dynamic between the husband and wife when they disagree."},"DUSTY":{"p":"/ˈdʌsti/","s":"adj.","e":"[adj.] Covered with dust.\n[adj.] Powdery and resembling dust.\n[adj.] Grey in parts.","ex":""},"DREAM":{"p":"/dɹiːm/","s":"n./v./adj.","e":"[n.] Imaginary events seen in the mind while sleeping.\n[n.] A hope or wish.\n[n.] A visionary scheme; a wild conceit; an idle fancy.\n[v.] To see imaginary events in one's mind while sleeping.\n[v.] To hope, to wish.\n[v.] To daydream.","ex":"a dream of bliss"},"EACH":{"p":"/iːt͡ʃ/","s":"n./adv./pron.","e":"[n.] (operations) An individual item: the least quantitative unit in a grouping.\n[adv.] For one; apiece; per.\n[pron.] Every one; every thing.","ex":"The apples cost 50 cents each."},"EARLY":{"p":"/ˈɜː.li/","s":"n./adj./adv.","e":"[n.] A shift (scheduled work period) that takes place early in the day.\n[adj.] At a time in advance of the usual or expected event.\n[adj.] Arriving a time before expected; sooner than on time.\n[adj.] Near the start or beginning.\n[adv.] At a time before expected; sooner than usual.\n[adv.] Soon; in good time; seasonably.","ex":"at eleven, we went for an early lunch;  she began reading at an early age;  his mother suffered an early death"},"DRINK":{"p":"/dɹɪŋk/","s":"v.","e":"[v.] To consume (a liquid) through the mouth.\n[v.] (metonymic) To consume the liquid contained within (a bottle, glass, etc.).\n[v.] To consume alcoholic beverages.","ex":"He drank the water I gave him."},"EAGER":{"p":"/ˈiːɡə/","s":"adj.","e":"[adj.] Sharp; sour; acid.\n[adj.] Sharp; keen; bitter; severe.\n[adj.] Desirous; keen to do or obtain something.","ex":"I was eager to show my teacher how much I'd learned over the holidays."},"EARTH":{"p":"/ɜːθ/","s":"pro./n./v.","e":"[pro.] The third planet of the Solar System; the world upon which humans live.\n[pro.] The personification of the Earth or earth, as a fertile woman or goddess.\n[n.] Soil.\n[n.] Any general rock-based material.\n[n.] The ground, land (as opposed to the sky or sea).\n[v.] To connect electrically to the earth.","ex":"This is good earth for growing potatoes."},"EASEL":{"p":"/ˈiː.z(ə)l/","s":"n.","e":"[n.] An upright frame, typically on three legs, for displaying or supporting something, such as an artist's canvas.","ex":""},"DRIVEN":{"p":"/ˈdɹɪvən/","s":"v./adj.","e":"[v.] To provide an impetus for motion or other physical change, to move an object by means of the provision of force thereto.\n[v.] To provide an impetus for a non-physical change, especially a change in one's state of mind.\n[v.] To displace either physically or non-physically, through the application of force.\n[adj.] Obsessed; passionately motivated to achieve goals.\n[adj.] (of snow) Formed into snowdrifts by wind.","ex":"You drive nails into wood with a hammer."},"EASTERN":{"p":"/ˈiːstən/","s":"adj.","e":"[adj.] Of, facing, situated in, or related to the east.\n[adj.] (of a wind) Blowing from the east; easterly.\n[adj.] Oriental.","ex":""},"EASY":{"p":"/ˈiːzi/","s":"n./adj./adv./v.","e":"[n.] Something that is easy\n[adj.] Comfortable; at ease.\n[adj.] Requiring little skill or effort.\n[adj.] Causing ease; giving comfort, or freedom from care or labour.\n[adv.] In a relaxed or casual manner.\n[adv.] In a manner without strictness or harshness.","ex":"Now that I know it's taken care of, I can rest easy at night."},"EATEN":{"p":"/ˈiːt(ə)n/","s":"v./adj.","e":"[v.] To ingest; to be ingested.\n[v.] To use up.\n[v.] To cause (someone) to worry.\n[adj.] (especially in combination) That has been consumed by eating","ex":"What’s eating you?"},"EATER":{"p":"/ˈiːtə/","s":"n.","e":"[n.] One who eats.\n[n.] An eating apple.\n[n.] One who performs fellatio or cunnilingus.","ex":""},"EASILY":{"p":"/ˈiː.zə.liː/","s":"adv.","e":"[adv.] Comfortably, without discomfort or anxiety.\n[adv.] Without difficulty.\n[adv.] Absolutely, without question.","ex":"Individuals without a family network are easily controlled."},"EATING":{"p":"/ˈiːtɪŋ/","s":"v./adj.","e":"[v.] To ingest; to be ingested.\n[v.] To use up.\n[v.] To cause (someone) to worry.\n[adj.] Bred to be eaten.\n[adj.] Suitable to be eaten without being cooked.","ex":"What’s eating you?"},"ECONOMY":{"p":"/iːˈkɒn.ə.mi/","s":"n./adj.","e":"[n.] Effective management of a community or system, or especially its resources.\n[n.] The study of money, currency and trade, and the efficient use of resources.\n[n.] Frugal use of resources.\n[adj.] Cheap to run; using minimal resources; representing good value for money.","ex":"economy of word"},"EDGE":{"p":"/ɛdʒ/","s":"n./v.","e":"[n.] The boundary line of a surface.\n[n.] A one-dimensional face of a polytope. In particular, the joining line between two vertices of a polygon; the place where two faces of a polyhedron meet.\n[n.] An advantage.\n[v.] To move an object slowly and carefully in a particular direction.\n[v.] To move slowly and carefully in a particular direction.\n[v.] (usually in the form 'just edge') To win by a small margin.","ex":"I have the edge on him."},"EDITOR":{"p":"/ˈɛdɪtə/","s":"n.","e":"[n.] A person who edits or makes changes to documents.\n[n.] A copy editor.\n[n.] A person who edited a specific document.","ex":"John Johnson wrote this term paper and the editor was Joan Johnson."},"EDICT":{"p":"/ˈiː.dɪkt/","s":"n.","e":"[n.] A proclamation of law or other authoritative command.","ex":""},"EGRET":{"p":"/ˈi.ɡɹɪt/","s":"n.","e":"[n.] Any of various wading birds of the genera Egretta or Ardea that includes herons, many of which are white or buff, and several of which develop fine plumes during the breeding season.\n[n.] A plume or tuft of feathers worn as a part of a headdress, or anything imitating such an ornament.\n[n.] The flying feathery or hairy crown of seeds or achenes, such as the down of the thistle.","ex":""},"EFFECT":{"p":"/ɪˈfɛkt/","s":"n./v.","e":"[n.] The result or outcome of a cause.\n[n.] Impression left on the mind; sensation produced.\n[n.] Execution; performance; realization; operation.\n[v.] To make or bring about; to implement.","ex":"The effect of the hurricane was a devastated landscape."},"EFFORT":{"p":"/ˈɛfət/","s":"n./v.","e":"[n.] The work involved in performing an activity; exertion.\n[n.] An endeavour.\n[n.] A force acting on a body in the direction of its motion.\n[v.] To make an effort.\n[v.] To strengthen, fortify or stimulate","ex":"It took a lot of effort to find a decent-sized, fully-furnished apartment within walking distance of the office.   He made a conscious effort to not appear affected by the stories in the paper."},"EIGHT":{"p":"/eɪt/","s":"n./num./adj.","e":"[n.] The digit/figure 8.\n[n.] Any of the four cards in a normal deck with the value eight.\n[n.] A light, narrow rowing boat, especially one used in competitive rowing, steered by a cox, in which eight rowers each have two oars.\n[num.] A numerical value equal to 8; the number occurring after seven and before nine.\n[num.] Describing a group or set with eight elements.\n[adj.] The ordinal form of the number eight.","ex":"He works eight hours a day."},"EJECT":{"p":"/ɪˈdʒɛkt/","s":"v.","e":"[v.] To compel (a person or persons) to leave.\n[v.] To throw out or remove forcefully.\n[v.] To compel (a sports player) to leave the field because of inappropriate behaviour.","ex":"Andrew was ejected from his apartment for not paying the rent."},"EITHER":{"p":"/ˈaɪð.ə(ɹ)/","s":"adv./pron./conj.","e":"[adv.] (after a negative) As well.\n[pron.] One or other of two people or things.\n[pron.] Both, each of two or more.\n[conj.] Introduces the first of two (or occasionally more) options or possibilities, the second (or last) of which is introduced by “or”.","ex":"I don't like him, and I don't like her either."},"ELEMENT":{"p":"/ˈɛlɪmənt/","s":"n./v.","e":"[n.] One of the simplest or essential parts or principles of which anything consists, or upon which the constitution or fundamental powers of anything are based.\n[n.] A small part of the whole.\n[n.] The sky.\n[v.] To compound of elements.\n[v.] To constitute and be the elements of.","ex":"Letters are the elements of written language."},"ELDER":{"p":"/ˈeldə/","s":"n./v./adj.","e":"[n.] An older person or an older member, usually a leader, of some community.\n[n.] One who is older than another.\n[n.] One who lived at an earlier period; a predecessor.\n[v.] To admonish or reprove for improper conduct by the elders of the meeting.\n[adj.] Of an object, concept, relationship, etc., having existed for a relatively long period of time.\n[adj.] Having been used and thus no longer new or unused.","ex":"We were presented to the village elder."},"ELIDE":{"p":"/ɪˈlaɪd/","s":"v.","e":"[v.] To leave out or omit (something).\n[v.] To cut off, as a vowel or a syllable.\n[v.] To conflate; to smear together; to blur the distinction between.","ex":""},"ELITE":{"p":"/eɪˈliːt/","s":"n./adj.","e":"[n.] A special group or social class of people which have a superior intellectual, social or economic status as, the elite of society.\n[n.] Someone who is among the best at a certain task.\n[adj.] Of high birth or social position; aristocratic or patrician.\n[adj.] Representing the choicest or most select of a group.","ex":""},"ELECT":{"p":"/iːˈlɛkt/","s":"n./v./adj.","e":"[n.] One chosen or set apart.\n[n.] In Calvinist theology, one foreordained to Heaven. In other Christian theologies, someone chosen by God for salvation.\n[v.] To choose or make a decision (to do something)\n[v.] To choose (a candidate) in an election\n[adj.] Who has been elected in a specified post, but has not yet entered office.\n[adj.] Chosen; taken by preference from among two or more.","ex":"He is the President elect."},"EMAIL":{"p":"/ˈiːmeɪl/","s":"n./v.","e":"[n.] A system for transferring messages from one computer to another, usually through a network.\n[n.] A quantity of messages sent through an email system.\n[n.] A message sent through an email system.\n[v.] To send an email or emails to.\n[v.] (may take two objects) To send (something) through email.\n[v.] To send, or compose and send, an email or emails.","ex":"He sent me his details via email."},"ELOPE":{"p":"/ɛˈləʊp/","s":"v.","e":"[v.] (of a married person) To run away from home with a paramour.\n[v.] (of an unmarried person) To run away secretly for the purpose of getting married with one's intended spouse; to marry in a quick or private fashion, especially without a public period of engagement.\n[v.] To run away from home (for any reason).","ex":""},"ELUDE":{"p":"/ɪˈluːd/","s":"v.","e":"[v.] To evade, or escape from someone or something, especially by using cunning or skill\n[v.] To shake off a pursuer; to give someone the slip\n[v.] To escape understanding of; to be incomprehensible to","ex":""},"EMOTION":{"p":"/iˈmoʊʃən/","s":"n.","e":"[n.] A person's internal state of being and involuntary physiological response to an object or a situation, based on or tied to physical state and sensory data.\n[n.] A reaction by a non-human organism with behavioral and physiological elements similar to a person's response.","ex":""},"ENEMY":{"p":"/ˈɛnəmi/","s":"n./v./adj.","e":"[n.] Someone who is hostile to, feels hatred towards, opposes the interests of, or intends injury to someone else.\n[n.] A hostile force or nation; a fighting member of such a force or nation.\n[n.] Something harmful or threatening to another\n[v.] To make an enemy of.\n[adj.] Of, relating to, or belonging to an enemy","ex":"Crush the enemy!"},"ENERGY":{"p":"/ˈɛnəd͡ʒi/","s":"n.","e":"[n.] The impetus behind all motion and all activity.\n[n.] The capacity to do work.\n[n.] A quantity that denotes the ability to do work and is measured in a unit dimensioned in mass × distance²/time² (ML²/T²) or the equivalent.","ex":""},"ENGINE":{"p":"/end͡ʒən/","s":"n./v.","e":"[n.] A large construction used in warfare, such as a battering ram, catapult etc.\n[n.] A tool; a utensil or implement.\n[n.] A complex mechanical device which converts energy into useful motion or physical effects.\n[v.] To equip with an engine; said especially of steam vessels.\n[v.] To assault with an engine.\n[v.] To contrive; to put into action.","ex":"Vessels are often built by one firm and engined by another."},"ENSUE":{"p":"/ɛnˈsjʉː/","s":"v.","e":"[v.] To follow (a leader, inclination etc.).\n[v.] To follow (in time), to be subsequent to.\n[v.] To occur afterwards, as a result or effect.","ex":"Give three freshmen six bottles of wine, and hilarity will ensue."},"ENSURE":{"p":"/ɪnˈʃɔː/","s":"v.","e":"[v.] To make a pledge to (someone); to promise, guarantee (someone of something); to assure.\n[v.] To make sure or certain of something (usually some future event or condition).","ex":"I use an alarm clock to ensure that I get up on time."},"ENTIRE":{"p":"/ənˈtaɪə/","s":"n./adj.","e":"[n.] The whole of something; the entirety.\n[n.] An uncastrated horse; a stallion.\n[n.] A complete envelope with stamps and all official markings: (prior to the use of envelopes) a page folded and posted.\n[adj.] (sometimes postpositive) Whole; complete.\n[adj.] Having a smooth margin without any indentation.\n[adj.] Consisting of a single piece, as a corolla.","ex":"We had the entire building to ourselves for the evening."},"ENVOY":{"p":"/ˈɛn.vɔɪ/","s":"n.","e":"[n.] A short stanza at the end of a poem, used either to address a person or to comment on the preceding body of the poem.\n[n.] A diplomatic agent of the second rank, next in status after an ambassador.\n[n.] A representative.\n[n.] A diplomat.","ex":""},"ENDING":{"p":"/ˈɛndɪŋ/","s":"n.","e":"[n.] A termination or conclusion.\n[n.] The last part of something.\n[n.] (grammar) The last morpheme of a word, added to some base to make an inflected form (such as -ing in \"ending\").","ex":""},"ENEMA":{"p":"/ˈɛn.ə.mə/","s":"n.","e":"[n.] An injection of fluid into the large intestine by way of the rectum, usually for medical purposes.\n[n.] The fluid so injected.\n[n.] A device for administering such an injection.","ex":""},"EQUITY":{"p":"/ˈɛk.wɪ.ti/","s":"n.","e":"[n.] Fairness, impartiality, or justice as determined in light of \"natural law\" or \"natural right\".\n[n.] Various related senses originating with the Court of Chancery in late Medieval England\n[n.] Various senses related to net value","ex":""},"ENNUI":{"p":"/ɒnˈwiː/","s":"n./v.","e":"[n.] A gripping listlessness or melancholia caused by boredom; depression.\n[v.] To make bored or listless; to weary.","ex":""},"ENJOY":{"p":"/ənˈd͡ʒɔɪ/","s":"v.","e":"[v.] To receive pleasure or satisfaction from something\n[v.] To have the use or benefit of something.\n[v.] To be satisfied or receive pleasure.","ex":"Enjoy your holidays!   I enjoy dancing."},"EXPRESS":{"p":"/ɛk.ˈspɹɛs/","s":"n./adj.","e":"[n.] A mode of transportation, often a train, that travels quickly or directly.\n[n.] A service that allows mail or money to be sent rapidly from one destination to another.\n[n.] An express rifle.\n[adj.] Moving or operating quickly, as a train not making local stops.\n[adj.] Specific or precise; directly and distinctly stated; not merely implied.\n[adj.] Truly depicted; exactly resembling.","ex":"I took the express into town."},"EXTREME":{"p":"/ɛkˈstɹiːm/","s":"n./adj./adv.","e":"[n.] The greatest or utmost point, degree or condition.\n[n.] Each of the things at opposite ends of a range or scale.\n[n.] A drastic expedient.\n[adj.] Of a place, the most remote, farthest or outermost.\n[adj.] In the greatest or highest degree; intense.\n[adj.] Excessive, or far beyond the norm.","ex":"extremes of temperature"},"EMBED":{"p":"/əmˈbɛd/","s":"n./v.","e":"[n.] An embedded reporter or journalist, such as a war reporter assigned to and travelling with a military unit, or a political reporter assigned to follow and report on the campaign of a candidate.\n[n.] An element of an advertisement, etc. serving as a subliminal message.\n[n.] An item embedded in another document.\n[v.] To lay as in a bed; to lay in surrounding matter; to bed.\n[v.] (by extension) To include in surrounding matter.\n[v.] To encapsulate within another document or data file.","ex":"to embed something in clay, mortar, or sand"},"FACET":{"p":"/ˈfæsɪt/","s":"n./v.","e":"[n.] Any one of the flat surfaces cut into a gem.\n[n.] One among many similar or related, yet still distinct things.\n[n.] One of a series of things, such as steps in a project.\n[v.] To cut a facet into a gemstone.","ex":"This facet of the diamond was masterfully cut to enhance its value."},"ESTATE":{"p":"/ɪsˈteɪt/","s":"n./v./adj.","e":"[n.] The collective property and liabilities of someone, especially a deceased person.\n[n.] State; condition.\n[n.] Status, rank.\n[v.] To give an estate to.\n[v.] To bestow upon.\n[adj.] (jewelry) Previously owned; secondhand.","ex":"an estate diamond; estate jewelry"},"EXPAND":{"p":"/ɛkˈspænd/","s":"v.","e":"[v.] To change (something) from a smaller form and/or size to a larger one; to spread out or lay open.\n[v.] To increase the extent, number, volume or scope of (something).\n[v.] To express (something) at length and/or in detail.","ex":"You can expand this compact umbrella to cover a large table."},"FABRIC":{"p":"/ˈfæb.ɹɪk/","s":"n.","e":"[n.] An edifice or building.\n[n.] The act of constructing, construction, fabrication.\n[n.] The structure of anything, the manner in which the parts of a thing are united; workmanship, texture, make.","ex":"cloth of a beautiful fabric"},"FACT":{"p":"/fækt/","s":"n./int.","e":"[n.] Something actual as opposed to invented.\n[n.] Something which is real.\n[n.] Something concrete used as a basis for further interpretation.\n[int.] Used before making a statement to introduce it as a trustworthy one.","ex":"In this story, the Gettysburg Address is a fact, but the rest is fiction."},"FACULTY":{"p":"/ˈfæ.kəl.ti/","s":"n.","e":"[n.] The academic staff at schools, colleges, universities or not-for-profit research institutes, as opposed to the students or support staff.\n[n.] A division of a university.\n[n.] An ability, skill, or power, often plural.","ex":"She transferred from the Faculty of Science to the Faculty of Medicine."},"FAILURE":{"p":"/ˈfeɪl.jɚ/","s":"n.","e":"[n.] State or condition of not meeting a desirable or intended objective, opposite of success.\n[n.] An object, person or endeavour in a state of failure or incapable of success.\n[n.] Termination of the ability of an item to perform its required function; breakdown.","ex":""},"EXPECT":{"p":"/ɛkˈspɛkt/","s":"v.","e":"[v.] To predict or believe that something will happen\n[v.] To consider obligatory or required.\n[v.] To consider reasonably due.","ex":"He never expected to be discovered."},"FAIRY":{"p":"/ˈfɛə̯ɹi/","s":"n./adj.","e":"[n.] The realm of faerie; enchantment, illusion.\n[n.] A mythical being with magical powers, known in many sizes and descriptions, although often depicted in modern illustrations only as a small sprite with gauze-like wings, and revered in some modern forms of paganism.\n[n.] An enchantress, or creature of overpowering charm.\n[adj.] Like a fairy; fanciful, whimsical, delicate.","ex":""},"FACE":{"p":"/feɪs/","s":"n./v.","e":"[n.] The front part of the head of a human or other animal, featuring the eyes, nose and mouth, and the surrounding area.\n[n.] One's facial expression.\n[n.] (in expressions such as 'make a face') A distorted facial expression; an expression of displeasure, insult, etc.\n[v.] (of a person or animal) To position oneself or itself so as to have one's face closest to (something).\n[v.] (of an object) To have its front closest to, or in the direction of (something else).\n[v.] To cause (something) to turn or present a face or front, as in a particular direction.","ex":"That girl has a pretty face."},"FALL":{"p":"/fɔːl/","s":"n./v.","e":"[n.] The act of moving to a lower position under the effect of gravity.\n[n.] A reduction in quantity, pitch, etc.\n[n.] The time of the year when the leaves typically fall from the trees; autumn; the season of the year between the autumnal equinox and the winter solstice.\n[v.] (heading) To be moved downwards.\n[v.] To move downwards.\n[v.] To happen, to change negatively.","ex":""},"FARM":{"p":"/fɑːɹm/","s":"n./v.","e":"[n.] A place where agricultural and similar activities take place, especially the growing of crops or the raising of livestock.\n[n.] A tract of land held on lease for the purpose of cultivation.\n[n.] (usually in combination) A location used for an industrial purpose, having many similar structures\n[v.] To work on a farm, especially in the growing and harvesting of crops.\n[v.] To devote (land) to farming.\n[v.] To grow (a particular crop).","ex":"antenna farm"},"FANCY":{"p":"/ˈfæn.si/","s":"n./adj./adv.","e":"[n.] The imagination.\n[n.] An image or representation of anything formed in the mind.\n[n.] An opinion or notion formed without much reflection.\n[adj.] Decorative.\n[adj.] Of a superior grade.\n[adj.] Executed with skill.","ex":"This is a fancy shawl."},"FATE":{"p":"/feɪt/","s":"n./v.","e":"[n.] The presumed cause, force, principle, or divine will that predetermines events.\n[n.] The effect, consequence, outcome, or inevitable events predetermined by this cause.\n[n.] An event or a situation which is inevitable in the fullness of time.\n[v.] To foreordain or predetermine, to make inevitable.","ex":"The oracle's prediction fated Oedipus to kill his father; not all his striving could change what would occur."},"FEATURE":{"p":"/ˈfiːtʃə/","s":"n./v.","e":"[n.] One's structure or make-up: form, shape, bodily proportions.\n[n.] An important or main item.\n[n.] A long, prominent article or item in the media, or the department that creates them; frequently used technically to distinguish content from news.\n[v.] To ascribe the greatest importance to something within a certain context.\n[v.] To star, to contain.\n[v.] To appear, to make an appearance.","ex":""},"FECAL":{"p":"/ˈfiːkəl/","s":"adj.","e":"[adj.] Of or relating to feces.","ex":""},"FAILED":{"p":"/feɪld/","s":"v./adj.","e":"[v.] To be unsuccessful.\n[v.] Not to achieve a particular stated goal. (Usage note: The direct object of this word is usually an infinitive.)\n[v.] To neglect.\n[adj.] Unsuccessful\n[adj.] Decayed; worn out.\n[adj.] Bankrupt.","ex":"Throughout my life, I have always failed."},"FARCE":{"p":"/fɑːs/","s":"n.","e":"[n.] A style of humor marked by broad improbabilities with little regard to regularity or method.\n[n.] A motion picture or play featuring this style of humor.\n[n.] A situation abounding with ludicrous incidents.","ex":"The farce that we saw last night had us laughing and shaking our heads at the same time."},"FELT":{"p":"/fɛlt/","s":"n./v.","e":"[n.] A cloth or stuff made of matted fibres of wool, or wool and fur, fulled or wrought into a compact substance by rolling and pressure, with lees or size, without spinning or weaving.\n[n.] A hat made of felt.\n[n.] A skin or hide; a fell; a pelt.\n[v.] To make into felt, or a feltlike substance; to cause to adhere and mat together.\n[v.] To cover with, or as if with, felt.\n[v.] To cause a player to lose all their chips.","ex":"to felt the cylinder of a steam engine"},"FEMUR":{"p":"/ˈfiːmə(ɹ)/","s":"n.","e":"[n.] A thighbone.\n[n.] The middle segment of the leg of an insect, between the trochanter and the tibia.\n[n.] A segment of the leg of an arachnid.","ex":""},"FETAL":{"p":"/ˈfitl̩/","s":"adj.","e":"[adj.] Pertaining to, or connected with, a fetus.","ex":"fetal circulation"},"FELON":{"p":"/ˈfɛlən/","s":"n./adj.","e":"[n.] A person who has committed a felony.\n[n.] A person who has been tried and convicted of a felony.\n[n.] A wicked person.\n[adj.] Wicked; cruel","ex":""},"FANNY":{"p":"/ˈfæni/","s":"n.","e":"[n.] The female genitalia.\n[n.] The buttocks; arguably the most nearly polite of several euphemisms.\n[n.] Sexual intercourse with a woman.","ex":"Her dress was so short you could nearly see her fanny."},"FERAL":{"p":"/ˈfɛɹəl/","s":"n./adj.","e":"[n.] A domesticated animal that has returned to the wild; an animal, particularly a domesticated animal, living independently of humans.\n[n.] A contemptible young person, a lout, a person who behaves wildly.\n[n.] A person who has isolated themselves from the outside world; one living an alternative lifestyle.\n[adj.] Wild, untamed, especially of domesticated animals having returned to the wild.\n[adj.] (of a person) Contemptible, unruly, misbehaved.","ex":""},"FIERY":{"p":"/ˈfaɪəɹi/","s":"adj.","e":"[adj.] Of or relating to fire.\n[adj.] Burning or glowing.\n[adj.] Inflammable or easily ignited.","ex":""},"FERRY":{"p":"/ˈfɛɹɪ/","s":"n./v.","e":"[n.] A ship used to transport people, smaller vehicles and goods from one port to another, usually on a regular schedule.\n[n.] A place where passengers are transported across water in such a ship.\n[n.] The legal right or franchise that entitles a corporate body or an individual to operate such a service.\n[v.] To carry; transport; convey.\n[v.] To move someone or something from one place to another, usually repeatedly.\n[v.] To carry or transport over a contracted body of water, as a river or strait, in a boat or other floating conveyance plying between opposite shores.","ex":"Trucks plowed through the water to ferry flood victims to safety."},"FASHION":{"p":"/ˈfæʃən/","s":"n./v.","e":"[n.] A current (constantly changing) trend, favored for frivolous rather than practical, logical, or intellectual reasons.\n[n.] Popular trends.\n[n.] A style or manner in which something is done.\n[v.] To make, build or construct, especially in a crude or improvised way.\n[v.] To make in a standard manner; to work.\n[v.] To fit, adapt, or accommodate to.","ex":"Check out the latest in fashion."},"FETUS":{"p":"/ˈfiːtəs/","s":"n.","e":"[n.] An unborn or unhatched vertebrate showing signs of the mature animal.\n[n.] A human embryo after the eighth week of gestation.","ex":"The sequence is: molecules in reproductive systems, then gametes, zygotes, morulas, blastocysts, and then fetuses."},"FIGURE":{"p":"/ˈfɪɡjɚ/","s":"n./v.","e":"[n.] A drawing or diagram conveying information.\n[n.] The representation of any form, as by drawing, painting, modelling, carving, embroidering, etc.; especially, a representation of the human body.\n[n.] A person or thing representing a certain consciousness.\n[v.] To calculate, to solve a mathematical problem.\n[v.] To come to understand.\n[v.] To think, to assume, to suppose, to reckon.","ex":"a figure in bronze; a figure cut in marble"},"FIGHT":{"p":"[fʌɪt]","s":"v.","e":"[v.] To contend in physical conflict, either singly or in war, battle etc.\n[v.] To contend in physical conflict with each other, either singly or in war, battle etc.\n[v.] To strive for something; to campaign or contend for success.","ex":"A wounded animal will fight like a maniac, relentless, savage and murderous."},"FIGHTER":{"p":"/ˈfaɪ.tə(ɹ)/","s":"n.","e":"[n.] A person who fights; a combatant.\n[n.] A warrior; fighting soldier.\n[n.] A pugnacious, competitive person.","ex":""},"FILTER":{"p":"/ˈfɪltə/","s":"n./v.","e":"[n.] A device which separates a suspended, dissolved, or particulate matter from a fluid, solution, or other substance; any device that separates one substance from another.\n[n.] Electronics or software that separates unwanted signals (for example noise) from wanted signals or that attenuates selected frequencies.\n[n.] Any item, mechanism, device or procedure that acts to separate or isolate.\n[v.] To sort, sift, or isolate.\n[v.] To diffuse; to cause to be less concentrated or focused.\n[v.] To pass through a filter or to act as though passing through a filter.","ex":"He runs an email filter to catch the junk mail."},"FICTION":{"p":"/ˈfɪk.ʃən/","s":"n.","e":"[n.] Literary type using invented or imaginative writing, instead of real facts, usually written as prose.\n[n.] A verbal or written account that is not based on actual events (often intended to mislead).\n[n.] A legal fiction.","ex":"I am a great reader of fiction."},"FILTH":{"p":"/fɪlθ/","s":"n.","e":"[n.] Dirt; foul matter; that which soils or defiles.\n[n.] Smut; that which sullies or defiles the moral character; corruption; pollution.\n[n.] (with definite article) The police.","ex":"Before we start cooking we need to clean up the filth in this kitchen."},"FINGER":{"p":"/ˈfɪŋəɹ/","s":"n./v.","e":"[n.] A slender jointed extremity of the human hand, exclusive of the thumb.\n[n.] Similar or similar-looking extremities in other animals, particularly:\n[n.] Something similar in shape to the human finger, particularly:\n[v.] To identify or point out. Also put the finger on. To report to or identify for the authorities, rat on, rat out, squeal on, tattle on, turn in.\n[v.] To poke, probe, feel, or fondle with a finger or fingers.\n[v.] To use the fingers to penetrate and sexually stimulate one's own or another person's vagina or anus; to fingerbang","ex":"Humans have two hands and ten fingers. Each hand has one thumb and four fingers."},"FILL":{"p":"/fɪl/","s":"v.","e":"[v.] To occupy fully, to take up all of.\n[v.] To add contents to (a container, cavity or the like) so that it is full.\n[v.] To enter (something), making it full.","ex":""},"FINAL":{"p":"/ˈfaɪ.nəl/","s":"n./adj.","e":"[n.] A final examination; a test or examination given at the end of a term or class; the test that concludes a class.\n[n.] The last round, game or match in a contest, after which the winner is determined.\n[n.] A contest that narrows a field of contestants (finalists) to ranked positions, usually in numbered places (1st place/prize, 2nd place/prize, etc.) or a winner and numbered runners-up (1st runner-up, etc.).\n[adj.] Last; ultimate.\n[adj.] Conclusive; decisive.\n[adj.] Respecting an end or object to be gained; respecting the purpose or ultimate end in view.","ex":"final solution;   the final day of a school term"},"FIRE":{"p":"/ˈfɑeə(ɹ)/","s":"n.","e":"[n.] A (usually self-sustaining) chemical reaction involving the bonding of oxygen with carbon or other fuel, with the production of heat and the presence of flame or smouldering.\n[n.] An instance of this chemical reaction, especially when intentionally created and maintained in a specific location to a useful end (such as a campfire or a hearth fire).\n[n.] The occurrence, often accidental, of fire in a certain place, causing damage and danger.","ex":"We sat about the fire singing songs and telling tales."},"FIFTH":{"p":"/fɪft/","s":"n./v./adj.","e":"[n.] The person or thing in the fifth position.\n[n.] One of five equal parts of a whole.\n[n.] The fifth gear of an engine.\n[v.] To support something fifth, after four others have already done so.\n[v.] To divide by 5, equates to multiplying a denominator by 5\n[adj.] The ordinal form of the number five.","ex":""},"FIRST":{"p":"/fɪrst/","s":"n./adj./adv.","e":"[n.] The person or thing in the first position.\n[n.] The first gear of an engine.\n[n.] Something that has never happened before; a new occurrence.\n[adj.] Preceding all others of a series or kind; the ordinal of one; earliest.\n[adj.] Most eminent or exalted; most excellent; chief; highest.\n[adv.] Before anything else; firstly.","ex":"He was the first to complete the course."},"FIVE":{"p":"/fɑev/","s":"n./num.","e":"[n.] The digit/figure 5.\n[n.] A banknote with a denomination of five units of currency. See also fiver.\n[n.] Anything measuring five units, as length.\n[num.] A numerical value equal to 5; the number following four and preceding six.\n[num.] Describing a group or set with five elements.","ex":"He wrote a five followed by four zeroes."},"FLASH":{"p":"/flæʃ/","s":"n./v./adj.","e":"[n.] A device that produces a short flash of light to help illuminate a scene, mostly for night-time or indoors photography.\n[n.] A sudden, short, temporary burst of light.\n[n.] A very short amount of time.\n[n.] A flashlight; an electric torch.\n[v.] To cause to shine briefly or intermittently.\n[v.] To blink; to shine or illuminate intermittently.","ex":"He flashed the light at the water, trying to see what made the noise."},"FLASK":{"p":"/flæsk/","s":"n./v.","e":"[n.] A narrow-necked vessel of metal or glass, used for various purposes; as of sheet metal, to carry gunpowder in; or of wrought iron, to contain quicksilver; or of glass, to heat water in, etc.\n[n.] A container used to discreetly carry a small amount of a hard alcoholic beverage; a pocket flask.\n[n.] Laboratory glassware used to hold larger volumes than test tubes, normally having a narrow mouth of a standard size which widens to a flat or spherical base.\n[v.] To invest a denture in a flask so as to produce a sectional mold.","ex":""},"FLAKE":{"p":"/fleɪk/","s":"n./v.","e":"[n.] A loose filmy mass or a thin chiplike layer of anything\n[n.] A scale of a fish or similar animal\n[n.] A prehistoric tool chipped out of stone.\n[v.] To break or chip off in a flake.\n[v.] To prove unreliable or impractical; to abandon or desert, to fail to follow through.\n[v.] To store an item such as rope or sail in layers","ex":"There were a few flakes of paint on the floor from when we were painting the walls."},"FLECK":{"p":"/flɛk/","s":"n./v.","e":"[n.] A flake\n[n.] A lock, as of wool.\n[n.] A small spot or streak; a speckle.\n[v.] To mark with small spots","ex":""},"FLAT":{"p":"/flæt/","s":"n./v./adj./adv.","e":"[n.] An area of level ground.\n[n.] A note played a semitone lower than a natural, denoted by the symbol ♭ placed after the letter representing the note (e.g., B♭) or in front of the note symbol (e.g. ♭♪).\n[n.] A flat tyre/tire.\n[v.] To make a flat call; to call without raising.\n[v.] To become flat or flattened; to sink or fall to an even surface.\n[v.] To fall from the pitch.","ex":"The land around here is flat."},"FLED":{"p":"/ˈflɛd/","s":"v.","e":"[v.] To run away; to escape.\n[v.] To escape from.\n[v.] To disappear quickly; to vanish.","ex":"The prisoner tried to flee, but was caught by the guards."},"FLEECE":{"p":"/fliːs/","s":"n./v.","e":"[n.] Hair or wool of a sheep or similar animal\n[n.] Insulating skin with the wool attached\n[n.] A textile similar to velvet, but with a longer pile that gives it a softness and a higher sheen.\n[v.] To con or trick (someone) out of money.\n[v.] To shear the fleece from (a sheep or other animal).\n[v.] To cover with, or as if with, wool.","ex":"During spring shearing we have to fleece all the sheep in just a few days."},"FLICK":{"p":"/flɪk/","s":"n./v.","e":"[n.] A short, quick movement, especially a brush, sweep, or flip.\n[n.] A motion picture; (in plural, usually preceded by \"the\") movie theater, cinema.\n[n.] A cut that lands with the point, often involving a whip of the foible of the blade to strike at a concealed target.\n[v.] To move or hit (something) with a short, quick motion.","ex":"He removed the speck of dust with a flick of his finger."},"FLIGHT":{"p":"/flaɪt/","s":"n./v./adj.","e":"[n.] The act of flying.\n[n.] An instance of flying.\n[n.] The act of fleeing.\n[v.] (of a spin bowler) To throw the ball in such a way that it has more airtime and more spin than usual.\n[v.] (by extension) To throw or kick something so as to send it flying with more loft or airtime than usual.\n[adj.] Fast, swift, fleet.","ex":"Most birds are capable of flight."},"FLOAT":{"p":"/fləʊt/","s":"n./v.","e":"[n.] A buoyant device used to support something in water or another liquid.\n[n.] A mass of timber or boards fastened together, and conveyed down a stream by the current; a raft.\n[n.] A float board.\n[v.] Of an object or substance, to be supported by a liquid of greater density than the object so as that part of the object or substance remains above the surface.\n[v.] To cause something to be suspended in a liquid of greater density.\n[v.] To be capable of floating.","ex":"Attach the float and the weight to the fishing line, above the hook."},"FLING":{"p":"/ˈflɪŋ/","s":"n.","e":"[n.] An act of throwing, often violently.\n[n.] An act of moving the limbs or body with violent movements, especially in a dance.\n[n.] An act or period of unrestrained indulgence.","ex":"the fling of a horse"},"FLIRT":{"p":"/flɜːt/","s":"n./v./adj.","e":"[n.] A sudden jerk; a quick throw or cast; a darting motion\n[n.] Someone who flirts a lot or enjoys flirting; a flirtatious person.\n[n.] An act of flirting.\n[v.] To throw (something) with a jerk or sudden movement; to fling.\n[v.] To jeer at; to mock.\n[v.] To dart about; to move with quick, jerky motions.","ex":"They flirt water in each other's faces."},"FLIP":{"p":"/flɪp/","s":"n./v.","e":"[n.] A maneuver which rotates an object end over end.\n[n.] A complete change of direction, decision, movement etc.\n[n.] A slingshot.\n[v.] To throw so as to turn over.\n[v.] To put into a quick revolving motion through a snap of the thumb and index finger.\n[v.] To win a state (or county) won by another party in the preceding elections","ex":"The diver did a couple of flips before landing in the pool."},"FLOOD":{"p":"/flʌd/","s":"n./v.","e":"[n.] A (usually disastrous) overflow of water from a lake or other body of water due to excessive rainfall or other input of water.\n[n.] A large number or quantity of anything appearing more rapidly than can easily be dealt with.\n[n.] The flowing in of the tide, opposed to the ebb.\n[v.] To overflow, as by water from excessive rainfall.\n[v.] To cover or partly fill as if by a flood.\n[v.] To provide (someone or something) with a larger number or quantity of something than can easily be dealt with.","ex":"a flood of complaints"},"FLOUR":{"p":"/ˈflaʊə/","s":"n./v.","e":"[n.] Powder obtained by grinding or milling cereal grains, especially wheat, or other foodstuffs such as soybeans and potatoes, and used to bake bread, cakes, and pastry.\n[n.] The food made by grinding and bolting cleaned wheat (not durum or red durum) until it meets specified levels of fineness, dryness and freedom from bran and germ, also containing any of certain enzymes, ascorbic acid and certain bleaching agents.\n[n.] Powder of other material.\n[v.] To apply flour to something; to cover with flour.\n[v.] To reduce to flour.\n[v.] To break up into fine globules of mercury in the amalgamation process.","ex":"mustard flour"},"FLOCK":{"p":"/flɒk/","s":"n./v.","e":"[n.] A large number of birds, especially those gathered together for the purpose of migration.\n[n.] A large number of animals, especially sheep or goats kept together.\n[n.] Those served by a particular pastor or shepherd.\n[v.] To congregate in or head towards a place in large numbers.\n[v.] To flock to; to crowd.\n[v.] To treat a pool with chemicals to remove suspended particles.","ex":"People flocked to the cinema to see the new film."},"FLOOR":{"p":"/flɔː/","s":"n./v.","e":"[n.] The interior bottom or surface of a house or building; the supporting surface of a room.\n[n.] Ground (surface of the Earth, as opposed to the sky or water or underground).\n[n.] The lower inside surface of a hollow space.\n[v.] To cover or furnish with a floor.\n[v.] To strike down or lay level with the floor; to knock down.\n[v.] (driving) To accelerate rapidly.","ex":"The room has a wooden floor."},"FLOSS":{"p":"/flɑs/","s":"n./v.","e":"[n.] A thread used to clean the gaps between the teeth.\n[n.] Raw silk fibres.\n[n.] The fibres covering a corncob etc.; the loose downy or silky material inside the husks of certain plants, such as beans.\n[v.] To clean the area between the teeth using floss.\n[v.] To show off, especially by exhibiting one's wealth or talent.\n[v.] To perform the floss dance move.","ex":""},"FLOWER":{"p":"/ˈflaʊ.ə/","s":"n./v.","e":"[n.] A colorful, conspicuous structure associated with angiosperms, frequently scented and attracting various insects, and which may or may not be used for sexual reproduction.\n[n.] A reproductive structure in angiosperms (flowering plants), often conspicuously colourful and typically including sepals, petals, and either or both stamens and/or a pistil.\n[n.] A plant that bears flowers, especially a plant that is small and lacks wood.\n[v.] To put forth blooms.\n[v.] To decorate with pictures of flowers.\n[v.] To reach a state of full development or achievement.","ex":"We transplanted the flowers to a larger pot."},"FLOW":{"p":"/fləʊ/","s":"n./v.","e":"[n.] A movement in people or things with a particular way in large numbers or amounts\n[n.] The movement of a real or figurative fluid.\n[n.] A formalization of the idea of the motion of particles in a fluid, as a group action of the real numbers on a set.\n[v.] To move as a fluid from one position to another.\n[v.] To proceed; to issue forth.\n[v.] To move or match smoothly, gracefully, or continuously.","ex":"The notion of flow is basic to the study of ordinary differential equations."},"FLUNK":{"p":"/flʌŋk/","s":"v.","e":"[v.] Of a student, to fail a class; to not pass.\n[v.] Of a teacher, to deny a student a passing grade.\n[v.] To shirk (a task or duty).","ex":"He flunked math, again."},"FOAMY":{"p":"/fəʊmi/","s":"n./adj.","e":"[n.] An inexpensive surfboard made of extruded polystyrene foam\n[adj.] Full of foam.","ex":"A young surfer learning on a foamie Surfing: Skills - Training - Techniques"},"FLUTE":{"p":"/fluːt/","s":"n./v.","e":"[n.] A woodwind instrument consisting of a tube with a row of holes that produce sound through vibrations caused by air blown across the edge of the holes, often tuned by plugging one or more holes with a finger; the Western concert flute, a transverse side-blown flute of European origin.\n[n.] A recorder, also a woodwind instrument.\n[n.] A glass with a long, narrow bowl and a long stem, used for drinking wine, especially champagne.\n[v.] To play on a flute.\n[v.] To make a flutelike sound.\n[v.] To utter with a flutelike sound.","ex":""},"FOCUS":{"p":"/ˈfəʊ.kəs/","s":"n./v.","e":"[n.] A point at which reflected or refracted rays of light converge.\n[n.] A point of a conic at which rays reflected from a curve or surface converge.\n[n.] The fact of the convergence of light on the photographic medium.\n[v.] (followed by on or upon) To concentrate one's attention.\n[v.] To cause (rays of light, etc) to converge at a single point.\n[v.] To adjust (a lens, an optical instrument) in order to position an image with respect to the focal plane.","ex":"The heat of sunlight at the focus of a magnifying glass can easily set dry leaves on fire."},"FOOD":{"p":"/fuːd/","s":"n.","e":"[n.] Any solid substance that can be consumed by living organisms, especially by eating, in order to sustain life.\n[n.] A foodstuff.\n[n.] Anything that nourishes or sustains.","ex":"The innkeeper brought them food and drink."},"FOIST":{"p":"/fɔɪst/","s":"n./v.","e":"[n.] A thief or pickpocket.\n[v.] To introduce or insert surreptitiously or without warrant.\n[v.] To force another to accept especially by stealth or deceit.\n[v.] To pass off as genuine or worthy.","ex":""},"FOLK":{"p":"/fəʊk/","s":"n./adj.","e":"[n.] A grouping of smaller peoples or tribes as a nation.\n[n.] The inhabitants of a region, especially the native inhabitants.\n[n.] (plural: folks) One’s relatives, especially one’s parents.\n[adj.] Of or pertaining to the inhabitants of a land, their culture, tradition, or history.\n[adj.] Of or pertaining to common people as opposed to ruling classes or elites.\n[adj.] Of or related to local building materials and styles.","ex":""},"FOOT":{"p":"[fʊt̚]","s":"n./v.","e":"[n.] A biological structure found in many animals that is used for locomotion and that is frequently a separate organ at the terminal part of the leg.\n[n.] Specifically, a human foot, which is found below the ankle and is used for standing and walking.\n[n.] (often used attributively) Travel by walking.\n[v.] To use the foot to kick (usually a ball).\n[v.] To pay (a bill).\n[v.] To tread to measure or music; to dance; to trip; to skip.","ex":"A spider has eight feet."},"FORCE":{"p":"/fɔːs/","s":"n./v.","e":"[n.] Strength or energy of body or mind; active power; vigour; might; capacity of exercising an influence or producing an effect.\n[n.] Power exerted against will or consent; compulsory power; violence; coercion.\n[n.] Anything that is able to make a substantial change in a person or thing.\n[v.] To violate (a woman); to rape.\n[v.] To exert oneself, to do one's utmost.\n[v.] To compel (someone or something) to do something.","ex":"the force of an appeal, an argument, or a contract"},"FLUFF":{"p":"/flʌf/","s":"n./v.","e":"[n.] Anything light, soft or fuzzy, especially fur, hair, feathers.\n[n.] Anything inconsequential or superficial.\n[n.] A lapse or mistake, especially a mistake in an actor's lines.\n[v.] To make something fluffy.\n[v.] To become fluffy, puff up.\n[v.] To move lightly like fluff.","ex":"That article was basically a bunch of fluff. It didn't say anything substantive."},"FOREST":{"p":"/ˈfɒɹɪst/","s":"n./v.","e":"[n.] A dense uncultivated tract of trees and undergrowth, larger than woods.\n[n.] Any dense collection or amount.\n[n.] A defined area of land set aside in England as royal hunting ground or for other privileged use; all such areas.\n[v.] To cover an area with trees.","ex":"a forest of criticism"},"FOREIGN":{"p":"/ˈfɒɹən/","s":"n./adj.","e":"[n.] A foreign person, particularly:\n[n.] A foreign ship.\n[n.] Clipping of chamber foreign: an outhouse.\n[adj.] Located outside a country or place, especially one's own.\n[adj.] Originating from, characteristic of, belonging to, or being a citizen of a country or place other than the one under discussion.\n[adj.] Relating to a different nation.","ex":"He liked visiting foreign cities."},"FORGE":{"p":"/fɔːd͡ʒ/","s":"n.","e":"[n.] Furnace or hearth where metals are heated prior to hammering them into shape.\n[n.] Workshop in which metals are shaped by heating and hammering them.\n[n.] The act of beating or working iron or steel.","ex":""},"FOAM":{"p":"/fəʊm/","s":"n./v.","e":"[n.] A substance composed of a large collection of bubbles or their solidified remains.\n[n.] A substance formed by trapping pockets of gas in a liquid or solid.\n[n.] (by extension) Sea foam; the sea.\n[v.] To form or emit foam.\n[v.] To spew saliva as foam, to foam at the mouth.","ex":"He doesn't like so much foam in his beer."},"FORGET":{"p":"/fəˈɡɛt/","s":"v.","e":"[v.] To lose remembrance of.\n[v.] To unintentionally not do, neglect.\n[v.] To unintentionally leave something behind.","ex":"I have forgotten most of the things I learned in school."},"FORM":{"p":"/fɔːm/","s":"n./v.","e":"[n.] (heading, physical) To do with shape.\n[n.] (social) To do with structure or procedure.\n[n.] A blank document or template to be filled in by the user.\n[v.] To assume (a certain shape or visible structure).\n[v.] To give (a shape or visible structure) to a thing or person.\n[v.] To take shape.","ex":"To apply for the position, complete the application form."},"FOAL":{"p":"/fɔʊl/","s":"n./v.","e":"[n.] A young horse or related animal, especially just after birth or less than a year old.\n[n.] A young boy who assisted the headsman by pushing or pulling the tub.\n[v.] To give birth to (a foal); to bear offspring.","ex":""},"FOLLOW":{"p":"/ˈfɒləʊ/","s":"n./v.","e":"[n.] (sometimes attributive) In billiards and similar games, a stroke causing a ball to follow another ball after hitting it.\n[n.] The act of following another user's online activity.\n[v.] To go after; to pursue; to move behind in the same path or direction.\n[v.] To go or come after in a sequence.\n[v.] To carry out (orders, instructions, etc.).","ex":"a follow shot"},"FORT":{"p":"/fɔːt/","s":"n./v.","e":"[n.] A fortified defensive structure stationed with troops.\n[n.] Any permanent army post.\n[n.] An outlying trading-station, as in British North America.\n[v.] To create a fort, fortifications, a strong point, or a redoubt.","ex":""},"FORTH":{"p":"/fɔːθ/","s":"adv./prep.","e":"[adv.] Forward in time, place or degree.\n[adv.] Out into view; from a particular place or position.\n[adv.] Beyond a (certain) boundary; away; abroad; out.\n[prep.] Forth from; out of.","ex":"The plants in spring put forth leaves."},"FORWARD":{"p":"/ˈfoːwəd/","s":"n./v./adj./adv.","e":"[n.] One of the eight players (comprising two props, one hooker, two locks, two flankers and one number eight, collectively known as the pack) whose primary task is to gain and maintain possession of the ball (compare back).\n[n.] A player on a team in football (soccer) in the row nearest to the opposing team's goal, who are therefore principally responsible for scoring goals.\n[n.] An umbrella term for a centre or winger in ice hockey.\n[v.] To advance, promote.\n[v.] To send (a letter, email etc.) to a third party.\n[v.] To assemble (a book) by sewing sections, attaching cover boards, and so on.","ex":"I'll be glad to forward your mail to you while you're gone."},"FORTE":{"p":"/fɔːt/","s":"n.","e":"[n.] A strength or talent.\n[n.] The strong part of a sword blade, close to the hilt.","ex":"He writes respectably, but poetry is not his forte."},"FORTUNE":{"p":"/ˈfɔːtʃuːn/","s":"n./v.","e":"[n.] Destiny, especially favorable.\n[n.] A prediction or set of predictions about a person's future provided by a fortune teller.\n[n.] A small slip of paper with wise or vaguely prophetic words printed on it, baked into a fortune cookie.\n[v.] To happen, take place.\n[v.] To provide with a fortune.\n[v.] To presage; to tell the fortune of.","ex":"She read my fortune. Apparently I will have a good love life this week, but I will have a bad week for money."},"FORTY":{"p":"/ˈfɔɹti/","s":"n./num.","e":"[n.] A bottle of beer containing forty fluid ounces.\n[num.] The cardinal number occurring after thirty-nine and before forty-one.","ex":""},"FOUND":{"p":"/faʊnd/","s":"v./n.","e":"[v.] To encounter or discover by accident; to happen upon.\n[v.] To encounter or discover something being searched for; to locate.\n[v.] (ditransitive) To discover by study or experiment direct to an object or end.\n[n.] Food and lodging; board.","ex":"I found my car keys. They were under the couch."},"FOUR":{"p":"/foː/","s":"n./num.","e":"[n.] The digit or figure 4; an occurrence thereof.\n[n.] Anything measuring four units, as length.\n[n.] A person who is four years old.\n[num.] A numerical value equal to 4; the number after three and before five; two plus two. This many dots (••••)\n[num.] Describing a set or group with four elements.","ex":"Do you have any more fours? I want to make this a little taller."},"FOUNDER":{"p":"/ˈfaʊndə/","s":"n.","e":"[n.] One who founds or establishes (especially said of a company, project, organisation, state)\n[n.] Someone for whose parents one has no data.","ex":"the founder of Facebook, Mark Zuckerberg"},"FOURTH":{"p":"/fɔːθ/","s":"n./adj.","e":"[n.] (not used in the plural) The person or thing in the fourth position.\n[n.] (chiefly American) A quarter, one of four equal parts of a whole.\n[n.] (not used in the plural) The fourth gear of an engine.\n[adj.] The ordinal form of the number four.","ex":""},"FRAME":{"p":"/fɹeɪm/","s":"n./v.","e":"[n.] The structural elements of a building or other constructed object.\n[n.] Anything composed of parts fitted and united together; a fabric; a structure.\n[n.] The structure of a person's body; the human body.\n[v.] To fit, as for a specific end or purpose; make suitable or comfortable; adapt; adjust.\n[v.] To construct by fitting or uniting together various parts; fabricate by union of constituent parts.\n[v.] To bring or put into form or order; adjust the parts or elements of; compose; contrive; plan; devise.","ex":"Now that the frame is complete, we can start on the walls."},"FRANK":{"p":"/fɹæŋk/","s":"n./v./adj.","e":"[n.] Free postage, a right exercised by governments (usually with definite article).\n[n.] The notice on an envelope where a stamp would normally be found.\n[v.] To place a frank on an envelope.\n[v.] To exempt from charge for postage, as a letter, package, or packet, etc.\n[v.] To send by public conveyance free of expense.\n[adj.] Honest, especially in a manner that seems slightly blunt; candid; not reserved or disguised.","ex":"May I be frank with you?"},"FRAUD":{"p":"/fɹɔːd/","s":"n./v.","e":"[n.] The crime of stealing or otherwise illegally obtaining money by use of deception tactics.\n[n.] Any act of deception carried out for the purpose of unfair, undeserved and/or unlawful gain.\n[n.] The assumption of a false identity to such deceptive end.\n[v.] To defraud","ex":""},"FRAT":{"p":"/fɹæt/","s":"n.","e":"[n.] Shortened form for fraternity, college organization. (Often used as a noun modifier.)","ex":"\"All the frats will be there.\""},"FOUGHT":{"p":"/fɔːt/","s":"v.","e":"[v.] To contend in physical conflict, either singly or in war, battle etc.\n[v.] To contend in physical conflict with each other, either singly or in war, battle etc.\n[v.] To strive for something; to campaign or contend for success.","ex":"A wounded animal will fight like a maniac, relentless, savage and murderous."},"FREEDOM":{"p":"/ˈfɹiːdəm/","s":"n.","e":"[n.] The state of being free, of not being imprisoned or enslaved.\n[n.] The lack of a specific constraint, or of constraints in general; a state of being free, unconstrained.\n[n.] Frankness; openness; unreservedness.","ex":"Having recently been released from prison, he didn't know what to do with his newfound freedom."},"FREEZE":{"p":"/ˈfɹiːz/","s":"v.","e":"[v.] Especially of a liquid, to become solid due to low temperature.\n[v.] To lower something's temperature to the point that it freezes or becomes hard.\n[v.] To drop to a temperature below zero degrees celsius, where water turns to ice.","ex":"The lake froze solid."},"FRIED":{"p":"/fɹaɪd/","s":"adj./v.","e":"[adj.] Cooked by frying.\n[adj.] (specifically, of an egg) Fried with the yolk unbroken.\n[adj.] Cooked in a deep fryer or pressure fryer or the like after being coated (breaded) in batter; compare deep-fried.\n[v.] A method of cooking food.\n[v.] To be affected by extreme heat or current.","ex":"He always ate his eggs fried, never scrambled."},"FRISK":{"p":"/fɹɪsk/","s":"n./v./adj.","e":"[n.] A frolic; a fit of wanton gaiety; a gambol: a little playful skip or leap.\n[v.] To frolic, gambol, skip, dance, leap.\n[v.] To search somebody by feeling his or her body and clothing.\n[adj.] Lively; brisk","ex":"The police frisked the suspiciously-acting individual and found a knife as well as a bag of marijuana."},"FROCK":{"p":"/fɹɒk/","s":"n./v.","e":"[n.] A dress, a piece of clothing for a female, which consists of a skirt and a cover for the upper body.\n[n.] An outer garment worn by priests and other clericals; a habit.\n[n.] A sailor's jersey.\n[v.] To clothe in a frock.\n[v.] To make a cleric.","ex":""},"FORMAL":{"p":"/ˈfɔːməl/","s":"n./adj.","e":"[n.] Formalin.\n[n.] An evening gown.\n[n.] An event with a formal dress code.\n[adj.] Being in accord with established forms.\n[adj.] Official.\n[adj.] Relating to the form or structure of something.","ex":"Jenny took Sam to her Year 12 formal."},"FORMER":{"p":"/ˈfɔːmə/","s":"adj.","e":"[adj.] Previous.\n[adj.] First of aforementioned two items. Used with the, often without a noun.","ex":"A former president;  the former East Germany"},"FRIEND":{"p":"/fɹɛnd/","s":"n./v.","e":"[n.] A person other than a family member, spouse or lover whose company one enjoys and towards whom one feels affection.\n[n.] An associate who provides assistance.\n[n.] A person with whom one is vaguely or indirectly acquainted.\n[v.] To act as a friend to, to befriend; to be friendly to, to help.\n[v.] To add (a person) to a list of friends on a social networking site; to officially designate (someone) as a friend.","ex":"John and I have been friends ever since we were roommates at college.   Trust is important between friends.   I used to find it hard to make friends when I was shy."},"FROWN":{"p":"/fɹaʊn/","s":"n.","e":"[n.] A facial expression in which the eyebrows are brought together, and the forehead is wrinkled, usually indicating displeasure, sadness or worry, or less often confusion or concentration.\n[n.] A facial expression in which the corners of the mouth are pointed down.","ex":""},"FROZEN":{"p":"/ˈfɹəʊzən/","s":"v./adj.","e":"[v.] Especially of a liquid, to become solid due to low temperature.\n[v.] To lower something's temperature to the point that it freezes or becomes hard.\n[v.] To drop to a temperature below zero degrees celsius, where water turns to ice.\n[adj.] Having undergone the process of freezing; in ice form.\n[adj.] Immobilized.\n[adj.] (of a bank account or assets) In a state such that transactions are not allowed.","ex":"The lake froze solid."},"FRAIL":{"p":"/fɹeɪl/","s":"n./v./adj.","e":"[n.] A basket made of rushes, used chiefly to hold figs and raisins.\n[n.] The quantity of fruit or other items contained in a frail.\n[n.] A rush for weaving baskets.\n[v.] To play a stringed instrument, usually a banjo, by picking with the back of a fingernail.\n[adj.] Easily broken physically; not firm or durable; liable to fail and perish\n[adj.] Weak; infirm.","ex":""},"FUMED":{"p":"/fjuːmd/","s":"v.","e":"[v.] To expose (something) to fumes; specifically, to expose wood, etc., to ammonia in order to produce dark tints.\n[v.] To apply or offer incense to.\n[v.] To emit fumes.","ex":""},"FREAK":{"p":"/fɹiːk/","s":"n./v./adj.","e":"[n.] A sudden change of mind\n[n.] Someone or something that is markedly unusual or unpredictable.\n[n.] A hippie.\n[v.] To make greatly distressed and/or a discomposed appearance\n[v.] To be placed or place someone under the influence of a psychedelic drug\n[v.] To streak; to variegate","ex":"a freak genius"},"FROM":{"p":"/fɹɒm/","s":"prep.","e":"[prep.] Used to indicate source or provenance.\n[prep.] Originating at (a year, time, etc.)\n[prep.] Used to indicate a starting point or initial reference.","ex":"I got a letter from my brother."},"FUTURE":{"p":"/ˈfjuːt͡ʃə/","s":"n./adj.","e":"[n.] The time ahead; those moments yet to be experienced.\n[n.] Something that will happen in moments yet to come.\n[n.] Goodness in what is yet to come. Something to look forward to.\n[adj.] Having to do with or occurring in the future.\n[n.] Short for futures contract.","ex":"There is no future in dwelling on the past."},"FUNKY":{"p":"","s":"adj.","e":"[adj.] Offbeat, unconventional or eccentric.\n[adj.] Not quite right; of questionable quality; not appropriate to the context.\n[adj.] Cool; great; excellent.","ex":""},"FUZZY":{"p":"/ˈfʌzi/","s":"n./adj.","e":"[n.] (often in the plural) A very small piece of plush material.\n[n.] Something covered with fuzz or hair, as an animal or plush toy.\n[n.] A person, especially a college student, interested in humanities or social sciences, as opposed to one interested in mathematics, science, or engineering.\n[adj.] Covered with fuzz or a large number of tiny loose fibres like a carpet or many stuffed animals\n[adj.] Vague or imprecise.\n[adj.] Not clear; unfocused.","ex":"You've got a fuzzy on your coat."},"GAIN":{"p":"/ɡeɪn/","s":"n./v.","e":"[n.] The act of gaining; acquisition.\n[n.] What is gained.\n[n.] The factor by which a signal is multiplied.\n[v.] To acquire possession of.\n[v.] To have or receive advantage or profit; to acquire gain; to grow rich; to advance in interest, health, or happiness; to make progress.\n[v.] To come off winner or victor in; to be successful in; to obtain by competition.","ex":"Looks like you've gained a new friend."},"GALLERY":{"p":"/ˈɡæləɹi/","s":"n./v.","e":"[n.] An institution, building, or room for the exhibition and conservation of works of art.\n[n.] An establishment that buys, sells, and displays works of art.\n[n.] The uppermost seating area projecting from the rear or side walls of a theater, concert hall, or auditorium.\n[v.] To show off","ex":""},"GAME":{"p":"/ɡeɪm/","s":"n./v./adj.","e":"[n.] A playful or competitive activity.\n[n.] A video game.\n[n.] (nearly always singular) A field of gainful activity, as an industry or profession.\n[v.] To gamble.\n[v.] To play card games, board games, or video games.\n[v.] To exploit loopholes in a system or bureaucracy in a way which defeats or nullifies the spirit of the rules in effect, usually to obtain a result which otherwise would be unobtainable.","ex":"He's in the securities game somehow."},"FUNGI":{"p":"/ˈfʌn.dʒaɪ/","s":"n.","e":"[n.] Any member of the kingdom Fungi; a eukaryotic organism typically having chitin cell walls but no chlorophyll or plastids. Fungi may be unicellular or multicellular.\n[n.] A spongy, abnormal excrescence, such as excessive granulation tissue formed in a wound.","ex":""},"GAMUT":{"p":"/ˈɡæm.ət/","s":"n.","e":"[n.] A (normally) complete range.\n[n.] All the notes in the musical scale.\n[n.] All the colours available to a device such as a monitor or printer.","ex":""},"GARDEN":{"p":"/ˈɡɑːdn̩/","s":"n./v./adj.","e":"[n.] An outdoor area containing one or more types of plants, usually plants grown for food or ornamental purposes.\n[n.] The grounds at the front or back of a house.\n[n.] The twentieth Lenormand card.\n[v.] To grow plants in a garden; to create or maintain a garden.\n[v.] Of a batsman, to inspect and tap the pitch lightly with the bat so as to smooth out small rough patches and irregularities.\n[adj.] Common, ordinary, domesticated.","ex":"a vegetable garden  a flower garden"},"GATE":{"p":"/ɡeɪt/","s":"n./v.","e":"[n.] A doorlike structure outside a house.\n[n.] Doorway, opening, or passage in a fence or wall.\n[n.] Movable barrier.\n[v.] To keep something inside by means of a closed gate.\n[v.] To punish, especially a child or teenager, by not allowing them to go out.\n[v.] To open a closed ion channel.","ex":"The gate in front of the railroad crossing went up after the train had passed."},"GAUNT":{"p":"/ɡɑːnt/","s":"adj.","e":"[adj.] Lean, angular and bony\n[adj.] Haggard, drawn and emaciated\n[adj.] Bleak, barren and desolate","ex":""},"GAMMA":{"p":"/ˈɡæmə/","s":"n.","e":"[n.] The third letter of the Greek alphabet (Γ, γ), preceded by beta (Β, β) and followed by delta, (Δ, δ).\n[n.] The Gamma function, symbolized by Γ.\n[n.] A constant approximately equal to 0.55721566, symbolized by γ (also known as the Euler–Mascheroni constant).\n[n.] A nonlinear operation used to encode and decode luminance or tristimulus values in video or still image systems.","ex":""},"GAUGE":{"p":"/ˈɡeɪdʒ/","s":"n./v.","e":"[n.] A measure; a standard of measure; an instrument to determine dimensions, distance, or capacity; a standard\n[n.] An act of measuring.\n[n.] An estimate.\n[v.] To measure or determine with a gauge; to measure the capacity of.\n[v.] To estimate.\n[v.] To appraise the character or ability of; to judge of.","ex":""},"GAVE":{"p":"/ɡeɪv/","s":"v.","e":"[v.] (ditransitive) To move, shift, provide something abstract or concrete to someone or something or somewhere.\n[v.] (ditransitive) To estimate or predict (a duration or probability) for (something).\n[v.] To yield slightly when a force is applied.","ex":"I give it a 95% chance of success."},"GAVEL":{"p":"/ˈɡa.vəl/","s":"n./v.","e":"[n.] Rent.\n[n.] Usury; interest on money.\n[n.] An old Saxon and Welsh form of tenure by which an estate passed, on the holder's death, to all the sons equally.\n[v.] To divide or distribute according to the gavel system.","ex":""},"GANG":{"p":"/ɡæŋ/","s":"v.","e":"[v.] To go; walk; proceed.","ex":""},"FUSSY":{"p":"/ˈfʌ.si/","s":"adj.","e":"[adj.] Anxious or particular about petty details.\n[adj.] Having a tendency to fuss, cry, or be bad-tempered/ill-tempered (especially of babies).","ex":""},"GAWKY":{"p":"/ˈɡɔːki/","s":"n./adj.","e":"[n.] An awkward, ungainly person.\n[adj.] Awkward, ungainly; lacking grace or dexterity in movement","ex":""},"GAYER":{"p":"","s":"adj./n.","e":"[adj.] (possibly obsolete) Happy, joyful, and lively.\n[adj.] Quick, fast.\n[adj.] (possibly obsolete) Festive, bright, or colourful.\n[n.] Somebody who is gay (in the sense of either homosexual or uncool).","ex":"The Gay Science"},"GEAR":{"p":"/ɡɪə(ɹ)/","s":"n./v./adj.","e":"[n.] Equipment or paraphernalia, especially that used for an athletic endeavor.\n[n.] Clothing; garments.\n[n.] Goods; property; household items.\n[v.] To provide with gearing; to fit with gears in order to achieve a desired gear ratio.\n[v.] To be in, or come into, gear.\n[v.] To dress; to put gear on; to harness.","ex":""},"GAZE":{"p":"/ɡeɪz/","s":"n./v.","e":"[n.] A fixed look; a look of eagerness, wonder, or admiration; a continued look of attention.\n[n.] The object gazed on.\n[n.] In Lacanian psychoanalysis, the relationship of the subject with the desire to look and awareness that one can be viewed.\n[v.] To stare intently or earnestly.\n[v.] To stare at.","ex":"In fact, for Antonioni this gazing is probably the most fundamental of all cognitive activities ... (from Thinking in the Absence of Image)"},"GATHER":{"p":"/ˈɡæðə/","s":"n./v.","e":"[n.] A plait or fold in cloth, made by drawing a thread through it; a pucker.\n[n.] The inclination forward of the axle journals to keep the wheels from working outward.\n[n.] The soffit or under surface of the masonry required in gathering. See gather (transitive verb).\n[v.] To collect; normally separate things.\n[v.] To bring parts of a whole closer.\n[v.] To infer or conclude; to know from a different source.","ex":"I've been gathering ideas from the people I work with."},"GENERAL":{"p":"/ˈd͡ʒɛnɹəl/","s":"n./v./adj./adv.","e":"[n.] A general fact or proposition; a generality.\n[n.] The holder of a senior military title, originally designating the commander of an army and now a specific rank falling under field marshal (in the British army) and below general of the army or general of the air force in the US army and air forces.\n[n.] A great strategist or tactician.\n[v.] To lead (soldiers) as a general.\n[adj.] Including or involving every part or member of a given or implied entity, whole etc.; as opposed to specific or particular.\n[adj.] (sometimes postpositive) Applied to a person (as a postmodifier or a normal preceding adjective) to indicate supreme rank, in civil or military titles, and later in other terms; pre-eminent.","ex":"We have dealt with the generals; now let us turn to the particulars."},"GENETIC":{"p":"[d͡ʒəˈnɛtɪk]","s":"adj.","e":"[adj.] Relating to genetics or genes.\n[adj.] Caused by genes.\n[adj.] Of or relating to origin (genesis).","ex":""},"GENIE":{"p":"/ˈdʒiː.ni/","s":"n.","e":"[n.] A jinn, a being descended from the jann, normally invisible to the human eye, but who may also appear in animal or human form.\n[n.] A fictional magical being that is typically bound to obey the commands of a mortal possessing its container.","ex":""},"GENRE":{"p":"/(d)ʒɒn.ɹə/","s":"n.","e":"[n.] A kind; a stylistic category or sort, especially of literature or other artworks.","ex":"The computer game Half-Life redefined the first-person shooter genre."},"GENTLY":{"p":"/ˈdʒɛntli/","s":"adv.","e":"[adv.] In a gentle manner","ex":""},"GECKO":{"p":"/ˈɡɛ.kəʊ/","s":"n./v.","e":"[n.] Any lizard of the family Gekkonidae. They are small, carnivorous, mostly nocturnal animals with large eyes and adhesive toes enabling them to climb on vertical and upside-down surfaces.\n[v.] To move in the manner of a gecko; to attach to a vertical or upside-down surface.","ex":""},"GASSY":{"p":"/ˈɡæsi/","s":"adj.","e":"[adj.] Having the nature of, or containing, gas.\n[adj.] Of food or drink: tending to cause flatulence.\n[adj.] Tending to be long-winded or wordy, especially in a boastful and vain manner.","ex":"Beans are a gassy food."},"GEOLOGY":{"p":"/dʒɪˈɒlədʒɪ/","s":"n.","e":"[n.] The science that studies the structure of the earth (or other planets), together with its origin and development, especially by examination of its rocks.\n[n.] The geological structure of a region.","ex":"The geology of the Alps."},"GEESE":{"p":"/ˈɡiːs/","s":"n.","e":"[n.] Any of various grazing waterfowl of the family Anatidae, which have feathers and webbed feet and are capable of flying, swimming, and walking on land, and which are bigger than ducks.\n[n.] A female goose (sense 1).\n[n.] The flesh of the goose used as food.","ex":"There is a flock of geese on the pond."},"GIRL":{"p":"/ɡɵːl/","s":"n./v.","e":"[n.] A female child, adolescent, or a young woman.\n[n.] A young female animal.\n[n.] (sometimes offensive) A woman, especially a young woman\n[v.] To feminize or girlify; to gender as a girl or as for girls.\n[v.] (somewhat informal) To staff with or as a girl or girls.","ex":""},"GIVE":{"p":"/ɡɪv/","s":"n./v.","e":"[n.] The amount of bending that something undergoes when a force is applied to it; a tendency to yield under pressure; resilence.\n[v.] (ditransitive) To move, shift, provide something abstract or concrete to someone or something or somewhere.\n[v.] (ditransitive) To estimate or predict (a duration or probability) for (something).\n[v.] To yield slightly when a force is applied.","ex":"There is no give in his dogmatic religious beliefs."},"GIVEN":{"p":"/ˈɡɪ.vən/","s":"v./n./adj./prep.","e":"[v.] (ditransitive) To move, shift, provide something abstract or concrete to someone or something or somewhere.\n[v.] (ditransitive) To estimate or predict (a duration or probability) for (something).\n[v.] To yield slightly when a force is applied.\n[n.] A condition that is assumed to be true without further evaluation.\n[adj.] Already arranged.\n[adj.] Currently discussed.","ex":"I give it a 95% chance of success."},"GIVER":{"p":"","s":"n.","e":"[n.] One who gives; a donor or contributor.","ex":""},"GLAD":{"p":"/ɡlæd/","s":"v./adj.","e":"[v.] To make glad\n[adj.] Pleased, happy, gratified.\n[adj.] Having a bright or cheerful appearance; expressing or exciting joy; producing gladness.","ex":"I'm glad the rain has finally stopped."},"GENUINE":{"p":"/ˈdʒɛnjuːˌaɪn/","s":"adj.","e":"[adj.] Belonging to, or proceeding from the original stock; native\n[adj.] Not counterfeit, spurious, false, or adulterated","ex":"a genuine text;  a genuine production;  genuine materials; genuine friendship"},"GLADE":{"p":"/ɡleɪd/","s":"n.","e":"[n.] An open passage through a wood; a grassy open or cleared space in a forest.\n[n.] An everglade.\n[n.] An open space in the ice on a river or lake.","ex":""},"GLARE":{"p":"/ɡlɛə/","s":"n./v./adj.","e":"[n.] An intense, blinding light.\n[n.] Showy brilliance; gaudiness.\n[n.] An angry or fierce stare.\n[v.] To stare angrily.\n[v.] To shine brightly.\n[v.] To be bright and intense, or ostentatiously splendid.","ex":"He walked in late, with the teacher glaring at him the whole time."},"GLASS":{"p":"/ɡlɑːs/","s":"v./n.","e":"[v.] To apply fibreglass to.\n[n.] An amorphous solid, often transparent substance made by melting sand with a mixture of soda, potash and lime.\n[n.] A vessel from which one drinks, especially one made of glass, plastic, or similar translucent or semi-translucent material.\n[n.] (metonymically) The quantity of liquid contained in such a vessel.\n[v.] To fit with glass; to glaze.\n[v.] To enclose in glass.","ex":"to fibreglass the hull of a fishing-boat"},"GEEKY":{"p":"/ˈɡiːki/","s":"adj.","e":"[adj.] Resembling or characteristic of a geek.","ex":"2004, Buddy Holly is a slightly more contentious inclusion, even if he did live fast, die young and leave a geeky-looking corpse. — Fiona Shepherd in Return of the Sun King, The Scotsman, 2 July 2004"},"GLEAN":{"p":"/ɡliːn/","s":"n./v.","e":"[n.] A collection made by gleaning.\n[v.] To collect (grain, grapes, etc.) left behind after the main harvest or gathering.\n[v.] To gather what is left in (a field or vineyard).\n[v.] To gather information in small amounts, with implied difficulty, bit by bit.","ex":"to glean a field"},"GLEAM":{"p":"/ɡliːm/","s":"n./v.","e":"[n.] A small or indistinct shaft or stream of light.\n[n.] A glimpse or hint; an indistinct sign of something.\n[n.] Brightness or shininess; splendor.\n[v.] To shine; to glitter; to glisten.\n[v.] To be briefly but strongly apparent.\n[v.] To disgorge filth, as a hawk.","ex":"The rescue workers preserved a gleam of optimism that they might still survive."},"GIRTH":{"p":"/ɡɜːθ/","s":"n./v.","e":"[n.] A band passed under the belly of an animal, which holds a saddle or a harness saddle in place.\n[n.] The part of an animal around which the girth fits.\n[n.] One's waistline circumference, most often a large one.\n[v.] To bind as if with a girth or band.","ex":""},"GLOBAL":{"p":"/ˈɡləʊbəl/","s":"n./adj./adv.","e":"[n.] A globally scoped identifier.\n[adj.] Concerning all parts of the world.\n[adj.] Pertaining to the whole of something; total, universal:\n[adj.] Spherical, ball-shaped.\n[adv.] In the global manner; world-wide.","ex":"Pollution is a global problem."},"GLOBE":{"p":"/ɡloːb/","s":"n./v.","e":"[n.] Any spherical (or nearly spherical) object.\n[n.] The planet Earth.\n[n.] A spherical model of Earth or any planet.\n[v.] To become spherical.\n[v.] To make spherical.","ex":"the globe of the eye; the globe of a lamp"},"GLOOM":{"p":"/ɡlum/","s":"n./v.","e":"[n.] Darkness, dimness or obscurity.\n[n.] A melancholic, depressing or despondent atmosphere.\n[n.] Cloudiness or heaviness of mind; melancholy; aspect of sorrow; low spirits; dullness.\n[v.] To be dark or gloomy.\n[v.] To look or feel sad, sullen or despondent.\n[v.] To render gloomy or dark; to obscure; to darken.","ex":"the gloom of a forest, or of midnight"},"GENDER":{"p":"/ˈdʒɛndə/","s":"n./v.","e":"[n.] Class; kind.\n[n.] (grammar) A division of nouns and pronouns (and sometimes of other parts of speech) into masculine or feminine, and sometimes other categories like neuter or common, and animate or inanimate.\n[n.] (now sometimes proscribed) Sex (a category such as \"male\" or \"female\" into which sexually-reproducing organisms are divided on the basis of their reproductive roles in their species).\n[v.] To assign a gender to (a person); to perceive as having a gender; to address using terms (pronouns, nouns, adjectives...) that express a certain gender.\n[v.] To perceive (a thing) as having characteristics associated with a certain gender, or as having been authored by someone of a certain gender.\n[n.] Sound uttered by the mouth, especially by human beings in speech or song; sound thus uttered considered as possessing some special quality or character","ex":"The effect of the medication is dependent upon age, gender, and other factors."},"GNASH":{"p":"/næʃ/","s":"n./v.","e":"[n.] A sudden snapping of the teeth.\n[v.] To grind (one's teeth) in pain or in anger.\n[v.] To grind between the teeth.\n[v.] To run away.","ex":"gnashing your teeth"},"GLYPH":{"p":"/ɡlɪf/","s":"n.","e":"[n.] A figure carved in relief or incised, especially representing a sound, word, or idea.\n[n.] Any non-verbal symbol that imparts information.\n[n.] A visual representation of a letter, character, or symbol, in a specific font and style.","ex":""},"GLOVE":{"p":"/ɡlʌv/","s":"n./v.","e":"[n.] An item of clothing other than a mitten, covering all or part of the hand and fingers, but usually allowing independent movement of the fingers.\n[n.] A baseball mitt.\n[n.] The ability to catch a hit ball.\n[v.] To catch the ball in a baseball mitt.\n[v.] To put a glove or gloves on.\n[v.] To touch a delivery with one's glove while the gloved hand is on the bat. Under the rules of cricket, the batsman is deemed to have hit the ball.","ex":"I wore gloves to keep my hands warm."},"GODLY":{"p":"/ˈɡɒdli/","s":"adj./adv.","e":"[adj.] Of or pertaining to a god\n[adj.] Devoted to a god or God; devout; righteous.\n[adj.] Gloriously good.\n[adv.] In a godly manner; piously; devoutly; righteously.","ex":"her godly powers = her superhuman powers"},"GOES":{"p":"/ɡəʊz/","s":"n./v.","e":"[n.] The act of going.\n[n.] A turn at something, or in something (e.g. a game).\n[n.] An attempt, a try.\n[v.] To move:\n[v.] (chiefly of a machine) To work or function (properly); to move or perform (as required).\n[v.] To start; to begin (an action or process).","ex":"It’s your go."},"GOING":{"p":"/ˈɡəʊɪŋ/","s":"v./n./adj.","e":"[v.] To move:\n[v.] (chiefly of a machine) To work or function (properly); to move or perform (as required).\n[v.] To start; to begin (an action or process).\n[n.] A departure.\n[n.] The suitability of ground for riding, walking etc.\n[n.] Progress.","ex":"The engine just won't go anymore."},"GLORY":{"p":"/ˈɡlo(ː)ɹi/","s":"n./v.","e":"[n.] Great or overwhelming beauty or splendour.\n[n.] Honour, admiration, or distinction, accorded by common consent to a person or thing; high reputation; renown.\n[n.] That quality in a person or thing which secures general praise or honour.\n[v.] To exult with joy; to rejoice.\n[v.] To boast; to be proud.\n[v.] To shine radiantly.","ex":""},"GNOME":{"p":"/nəʊm/","s":"n.","e":"[n.] A brief reflection or maxim; a pithy saying.","ex":""},"GOLDEN":{"p":"/ˈɡəʊl.dən/","s":"n./adj.","e":"[n.] Kyphosus vaigiensis, a fish found in southeast Asia.\n[adj.] Made of, or relating to, gold.\n[adj.] Having a colour or other richness suggestive of gold.\n[adj.] Of a beverage, flavoured or colored with turmeric.","ex":"She wore a golden crown."},"GLAND":{"p":"/ɡlænd/","s":"n.","e":"[n.] An organ that synthesizes a substance, such as hormones or breast milk, and releases it, often into the bloodstream (endocrine gland) or into cavities inside the body or its outer surface (exocrine gland).\n[n.] A secretory structure on the surface of an organ.","ex":""},"GOLF":{"p":"/ɡɒlf/","s":"n./v.","e":"[n.] A ball game played by individuals competing against one another in which the object is to hit a ball into each of a series of (usually 18 or nine) holes in the minimum number of strokes.\n[n.] The letter G in the ICAO spelling alphabet.\n[v.] To play the game of golf.\n[v.] To write something in as few characters as possible (e.g. in code golf, regex golf)","ex":""},"GOODY":{"p":"/ˈɡʊdi/","s":"n./adj.","e":"[n.] A good character in a story, often a hero.\n[n.] A small amount of something good to eat.\n[n.] Any small, usually free, item.\n[n.] Pudding made by boiling bread in milk with sugar and spices.\n[adj.] Mawkishly good; weakly benevolent or pious.","ex":""},"GONE":{"p":"/ɡɔːn/","s":"v./adj./prep.","e":"[v.] To move:\n[v.] (chiefly of a machine) To work or function (properly); to move or perform (as required).\n[v.] To start; to begin (an action or process).\n[adj.] Away, having left.\n[adj.] No longer part of the present situation.\n[adj.] No longer existing, having passed.","ex":"The engine just won't go anymore."},"GOOFY":{"p":"/ɡuːfi/","s":"adj.","e":"[adj.] Silly, quirky","ex":""},"GOAL":{"p":"/ɡɒʊl/","s":"n./v.","e":"[n.] A result that one is attempting to achieve.\n[n.] In many sports, an area into which the players attempt to put an object.\n[n.] The act of placing the object into the goal.\n[v.] To score a goal.","ex":"My lifelong goal is to get into a Hollywood movie."},"GOOD":{"p":"/ɡʊ(d)/","s":"adj./int.","e":"[adj.] (of people)\n[adj.] (of capabilities)\n[adj.] (properties and qualities)\n[int.] That is good; an elliptical exclamation of satisfaction or commendation.","ex":"Good! I can leave now."},"GOODBYE":{"p":"/ɡədˈbaɪ/","s":"n./v./int.","e":"[n.] An utterance of goodbye, the wishing of farewell to someone.\n[v.] To say goodbye; to wish somebody farewell on parting.\n[int.] Farewell; a formula used to another person or persons when the speaker, writer, or person addressed is departing.","ex":"They made their good-byes."},"GOUGE":{"p":"/ɡaʊdʒ/","s":"n./v.","e":"[n.] Senses relating to cutting tools.\n[n.] A cut or groove, as left by a gouge or something sharp.\n[n.] (originally United States) An act of gouging.\n[v.] To make a groove, hole, or mark in by scooping with or as if with a gouge.\n[v.] To cheat or impose upon; in particular, to charge an unfairly or unreasonably high price.\n[v.] To dig or scoop (something) out with or as if with a gouge; in particular, to use a thumb to push or try to push the eye (of a person) out of its socket.","ex":"The nail left a deep gouge in the tire."},"GOLD":{"p":"/ɡɒʊld/","s":"n./v./adj.","e":"[n.] A heavy yellow elemental metal of great value, with atomic number 79 and symbol Au.\n[n.] A coin or coinage made of this material, or supposedly so.\n[n.] A deep yellow colour, resembling the metal gold.\n[v.] To pyrolyze or burn food until the color begins to change to a light brown, but not as dark as browning\n[adj.] Made of gold.\n[adj.] Having the colour of gold.","ex":""},"GRAB":{"p":"/ɡɹæb/","s":"n./v.","e":"[n.] A sudden snatch at something.\n[n.] An acquisition by violent or unjust means.\n[n.] A mechanical device that grabs or clutches.\n[v.] To grip suddenly; to seize; to clutch.\n[v.] To make a sudden grasping or clutching motion (at something).\n[v.] To restrain someone; to arrest.","ex":"I grabbed her hand to pull her back from the cliff edge."},"GOOEY":{"p":"/ˈɡuː.i/","s":"adj.","e":"[adj.] Of or relating to goo\n[adj.] Soft, sticky and viscous","ex":""},"GOOSE":{"p":"/ˈɡuːs/","s":"n./v.","e":"[n.] Any of various grazing waterfowl of the family Anatidae, which have feathers and webbed feet and are capable of flying, swimming, and walking on land, and which are bigger than ducks.\n[n.] A female goose (sense 1).\n[n.] The flesh of the goose used as food.\n[v.] To sharply poke or pinch someone's buttocks. Derived from a goose's inclination to bite at a retreating intruder's hindquarters.\n[v.] To stimulate, to spur.\n[v.] To gently accelerate an automobile or machine, or give repeated small taps on the accelerator.","ex":"There is a flock of geese on the pond."},"GRACE":{"p":"/ɡɹeɪs/","s":"n./v.","e":"[n.] Charming, pleasing qualities.\n[n.] A short prayer of thanks before or after a meal.\n[n.] In the games of patience or solitaire: a special move that is normally against the rules.\n[v.] To adorn; to decorate; to embellish and dignify.\n[v.] To dignify or raise by an act of favour; to honour.\n[v.] To supply with heavenly grace.","ex":"The Princess brought grace to an otherwise dull and boring party."},"GRAFT":{"p":"/ɡɹæft/","s":"n./v.","e":"[n.] A small shoot or scion of a tree inserted in another tree, the stock of which is to support and nourish it. The two unite and become one tree, but the graft determines the kind of fruit.\n[n.] A branch or portion of a tree growing from such a shoot.\n[n.] A portion of living tissue used in the operation of autoplasty.\n[v.] To insert (a graft) in a branch or stem of another tree; to propagate by insertion in another stock; also, to insert a graft upon.\n[v.] To insert scions (grafts) from one tree, or kind of tree, etc., into another; to practice grafting.\n[v.] To implant a portion of (living flesh or akin) in a lesion so as to form an organic union.","ex":""},"GRAIL":{"p":"/ɡɹeɪɫ/","s":"n.","e":"[n.] The Holy Grail.\n[n.] The object of an extended or difficult quest.http//www.merriam-webster.com/dictionary/grail","ex":"Becoming an astronaut was his grail."},"GRAIN":{"p":"/ɡɹeɪn/","s":"n./v.","e":"[n.] The harvested seeds of various grass food crops eg: wheat, corn, barley.\n[n.] Similar seeds from any food crop, e.g., buckwheat, amaranth, quinoa.\n[n.] A single seed of grass food crops.\n[v.] To feed grain to.\n[v.] To make granular; to form into grains.\n[v.] To form grains, or to assume a granular form, as the result of crystallization; to granulate.","ex":"We stored a thousand tons of grain for the winter."},"GRANT":{"p":"/ɡɹɑːnt/","s":"n./v.","e":"[n.] The act of granting; a bestowing or conferring; concession; allowance; permission.\n[n.] The yielding or admission of something in dispute.\n[n.] The thing or property granted; a gift; a boon.\n[v.] (ditransitive) to give (permission or wish)\n[v.] (ditransitive) To bestow or confer, with or without compensation, particularly in answer to prayer or request; to give.\n[v.] To agree with (someone) on (something); to accept (something) for the sake of argument; to admit to (someone) that (something) is true.","ex":"I got a grant from the government to study archeology in Egypt."},"GRAND":{"p":"/ɡɹænd/","s":"n./adj.","e":"[n.] (plural \"grand\") A thousand of some unit of currency, such as dollars or pounds. (Compare G.)\n[n.] (plural \"grands\") A grand piano\n[adj.] Of a large size or extent; great.\n[adj.] Great in size, and fine or imposing in appearance or impression; illustrious, dignified, magnificent.\n[adj.] Having higher rank or more dignity, size, or importance than other persons or things of the same name.","ex":"a grand army"},"GRAPE":{"p":"/ɡɹeɪp/","s":"n./v./adj.","e":"[n.] A small, round, smooth-skinned edible fruit, usually purple, red, or green, that grows in bunches on vines of genus Vitis.\n[n.] A woody vine that bears clusters of grapes; a grapevine; of genus Vitis.\n[n.] A dark purplish-red colour, the colour of many grapes.\n[v.] To pick grapes.\n[v.] (of livestock) To develop tubercules as a result of tuberculosis.\n[v.] To develop a texture with small grape-like clusters of a contaminant or foreign substance.","ex":""},"GRAPH":{"p":"/ɡɹæf/","s":"n./v.","e":"[n.] (applied mathematics) A data chart (graphical representation of data) intended to illustrate the relationship between a set (or sets) of numbers (quantities, measurements or indicative numbers) and a reference set, whose elements are indexed to those of the former set(s) and may or may not be numbers.\n[n.] A set of points constituting a graphical representation of a real function; (formally) a set of tuples (x_1, x_2, \\ldots, x_m, y)\\in\\R^{m+1}, where y=f(x_1, x_2, \\ldots, x_m) for a given function f: \\R^m\\rightarrow\\R.\n[n.] (formally) An ordered pair of sets (V,E), where the elements of V are called vertices or nodes and E is a set of pairs (called edges) of elements of V; (less formally) a set of vertices (or nodes) together with a set of edges that connect (some of) the vertices.\n[v.] To draw a graph.\n[v.] To draw a graph of a function.","ex":""},"GRASP":{"p":"/ɡɹɑːsp/","s":"n./v.","e":"[n.] (sometimes figurative) Grip.\n[n.] Understanding.\n[n.] That which is accessible; that which is within one's reach or ability.\n[v.] To grip; to take hold, particularly with the hand.\n[v.] To understand.\n[v.] To take advantage of something, to seize, to jump at a chance.","ex":"The goal is within my grasp."},"GRATE":{"p":"/ɡɹeɪt/","s":"n./v.","e":"[n.] A horizontal metal grill through which water, ash, or small objects can fall, while larger objects cannot\n[n.] A frame or bed, or kind of basket, of iron bars, for holding fuel while burning\n[v.] To furnish with grates; to protect with a grating or crossbars","ex":"The grate stopped the sheep from escaping from their field."},"GRAVE":{"p":"/ɡɹeɪv/","s":"n.","e":"[n.] An excavation in the earth as a place of burial\n[n.] Any place of interment; a tomb; a sepulcher.\n[n.] (by extension) Death, destruction.","ex":""},"GRADE":{"p":"/ɡɹeɪd/","s":"n./v.","e":"[n.] A rating.\n[n.] The performance of an individual or group on an examination or test, expressed by a number, letter, or other symbol; a score.\n[n.] A degree or level of something; a position within a scale; a degree of quality.\n[v.] To assign scores to the components of an academic test.\n[v.] To assign a score to overall academic performance.\n[v.] To organize in grades.","ex":"I gave him a good grade for effort."},"GRAY":{"p":"/ɡɹeɪ/","s":"n./v./adj.","e":"[n.] An achromatic colour intermediate between black and white.\n[n.] An animal or thing of grey colour, such as a horse, badger, or salmon.\n[n.] An extraterrestrial humanoid with grayish skin, bulbous black eyes, and an enlarged head.\n[v.] To become gray.\n[v.] To cause to become gray.\n[v.] To turn progressively older, alluding to graying of hair through aging (used in context of the population of a geographic region)","ex":"My hair is beginning to gray."},"GREW":{"p":"/ɡɹuː/","s":"v.","e":"[v.] To become larger, to increase in magnitude.\n[v.] To appear or sprout.\n[v.] To develop, to mature.","ex":"Children grow quickly."},"GRAPHIC":{"p":"/ˈɡɹæfɪk/","s":"n./adj.","e":"[n.] A drawing or picture.\n[n.] (mostly in plural) A computer-generated image as viewed on a screen forming part of a game or a film etc.\n[adj.] Drawn, pictorial.\n[adj.] Vivid, descriptive, often in relation to depictions of sex or violence.\n[adj.] Having a texture that resembles writing, commonly created by exsolution, devitrification and immiscibility processes in igneous rocks.","ex":"I've just played this new computer game: the graphics are amazing."},"GREY":{"p":"/ɡɹeɪ/","s":"adj./n./v.","e":"[adj.] Having a color.\n[adj.] Having a particular color or kind of color.\n[adj.] Having prominent colors; colorful.\n[n.] An achromatic colour intermediate between black and white.\n[n.] An animal or thing of grey colour, such as a horse, badger, or salmon.\n[n.] An extraterrestrial humanoid with greyish skin, bulbous black eyes, and an enlarged head.","ex":"Wash colored items separately from whites and darks to prevent the colors from bleeding."},"GREED":{"p":"/ɡɹid/","s":"n./v.","e":"[n.] A selfish or excessive desire for more than is needed or deserved, especially of money, wealth, food, or other possessions.\n[v.] To desire in a greedy manner, or to act on such a desire.","ex":"His greed was his undoing."},"GRASS":{"p":"[ɡɹ̠äːs]","s":"n./v.","e":"[n.] Any plant of the family Poaceae, characterized by leaves that arise from nodes in the stem and leaf bases that wrap around the stem, especially those grown as ground cover rather than for grain.\n[n.] Various plants not in family Poaceae that resemble grasses.\n[n.] A lawn.\n[v.] To lay out on the grass; to knock down (an opponent etc.).\n[v.] To act as a grass or informer, to betray; to report on (criminals etc) to the authorities.\n[v.] To cover with grass or with turf.","ex":""},"GOURD":{"p":"/ɡɔːd/","s":"n.","e":"[n.] Any of the trailing or climbing vines producing fruit with a hard rind or shell, from the genera Lagenaria and Cucurbita (in Cucurbitaceae).\n[n.] A hard-shelled fruit from a plant in Lagenaria or Cucurbita.\n[n.] The dried and hardened shell of such fruit, made into a drinking vessel, bowl, spoon, or other objects designed for use or decoration.","ex":""},"GRAVY":{"p":"/ˈɡɹeɪvi/","s":"n.","e":"[n.] A thick sauce made from the fat or juices that come out from meat or vegetables as they are being cooked.\n[n.] A type of gravy.\n[n.] (Italian-American) Sauce used for pasta.","ex":""},"GRIP":{"p":"/ɡɹɪp/","s":"v.","e":"[v.] To take hold of, particularly with the hand.\n[v.] To help or assist, particularly in an emotional sense.\n[v.] To do something with another that makes you happy/gives you relief.","ex":"After a few slips, the tires gripped the pavement."},"GRIME":{"p":"/ɡɹaɪm/","s":"n./v.","e":"[n.] Dirt, grease, soot, etc. that is ingrained and difficult to remove.\n[n.] A genre of urban music that emerged in London, England, in the early 2000s, primarily a development of UK garage, dancehall, and hip hop.\n[v.] To begrime; to cake with dirt.","ex":"Underneath all that soot, dirt and grime is the true beauty of the church in soft shades of sandstone."},"GREET":{"p":"/ɡɹiːt/","s":"v.","e":"[v.] To welcome in a friendly manner, either in person or through another means e.g. writing or over the phone/internet\n[v.] To arrive at or reach, or meet (talking of something which brings joy)\n[v.] To accost; to address.","ex":""},"GROOM":{"p":"/ɡɹuːm/","s":"n.","e":"[n.] A man who is about to marry.","ex":""},"GROSS":{"p":"/ɡɹəʊs/","s":"n./v./adj.","e":"[n.] Twelve dozen = 144.\n[n.] The total nominal earnings or amount, before taxes, expenses, exceptions or similar are deducted. That which remains after all deductions is called net.\n[n.] The bulk, the mass, the masses.\n[v.] To earn money, not including expenses.\n[adj.] (of behaviour considered to be wrong) Highly or conspicuously offensive.\n[adj.] (of an amount) Excluding any deductions; including all associated amounts.","ex":"The movie grossed three million on the first weekend."},"GROUT":{"p":"/ɡɹʌut/","s":"n./v.","e":"[n.] A thin mortar used to fill the gaps between tiles and cavities in masonry.\n[n.] Coarse meal; groats.\n[n.] (typically used in the plural) Dregs, sediment.\n[v.] To insert mortar between tiles.","ex":"I spent the whole afternoon grouting the kitchen floor."},"GRIEF":{"p":"/ɡɹiːf/","s":"n./v.","e":"[n.] Suffering, hardship.\n[n.] Pain of mind arising from misfortune, significant personal loss, bereavement, misconduct of oneself or others, etc.; sorrow; sadness.\n[n.] Cause or instance of sorrow or pain; that which afflicts or distresses; trial.\n[v.] To deliberately harass and annoy or cause grief to other players of a game in order to interfere with their enjoyment of it; especially, to do this as one’s primary activity in the game.","ex":"She was worn out from so much grief."},"GRILL":{"p":"/ɡɹɪl/","s":"n./v.","e":"[n.] A grating; a grid of wire or a sheet of material with a pattern of holes or slots, usually used to protect something while allowing the passage of air and liquids. Typical uses: to allow air through a fan while preventing fingers or objects from passing; to allow people to talk to somebody, while preventing attack.\n[n.] On a vehicle, a slotted cover as above, to protect and hide the radiator, while admitting air to cool it.\n[n.] A cooking device comprising a source of radiative heat and a means of holding food under it; a broiler in US English\n[v.] To cook (food) on a grill; to barbecue.\n[v.] To cook food under the element of a stove or only under the top element of an oven – broil, salamander.\n[v.] To interrogate; to question aggressively or harshly.","ex":"Why don't we get together Saturday and grill some burgers?"},"GREAT":{"p":"/ɡɹeɪt/","s":"n./adj./adv./int.","e":"[n.] A person of major significance, accomplishment or acclaim.\n[n.] The main division in a pipe organ, usually the loudest division.\n[n.] (in combinations such as \"two-greats\", \"three-greats\" etc.) An instance of the word \"great\" signifying an additional generation in phrases expressing family relationships.\n[adj.] Relatively large in scale, size, extent, number (i.e. having many parts or members) or duration (i.e. relatively long); very big.\n[adj.] Of larger size or more importance than others of its kind.\n[adj.] (qualifying nouns of family relationship) Involving more generations than the qualified word implies — as many extra generations as repetitions of the word great (from 1510s). [see Derived terms]","ex":"Newton and Einstein are two of the greats of the history of science."},"GROVE":{"p":"/ɡɹəʊv/","s":"n./v.","e":"[n.] A small forest.\n[n.] An orchard of fruit trees.\n[n.] (Druidism) A place of worship.\n[v.] To cultivate in groves; to grow naturally so as to form groves.\n[v.] (of trees) To cultivate with periodic harvesting that also serves to create order (gaps and lines of trees) to facilitate further harvesting.\n[v.] To plough or gouge with lines.","ex":""},"GROWTH":{"p":"/ɡɹəʊθ/","s":"n.","e":"[n.] An increase in size, number, value, or strength.\n[n.] The act of growing, getting bigger or higher.\n[n.] Something that grows or has grown.","ex":"Growth was dampened by a softening of the global economy in 2001, but picked up in the subsequent years due to strong growth in China."},"GRUNT":{"p":"/ɡɹʌnt/","s":"n./v.","e":"[n.] A short snorting sound, often to show disapproval, or used as a reply when one is reluctant to speak.\n[n.] The snorting cry of a pig.\n[n.] Any fish of the perciform family Haemulidae.\n[v.] (of a person) To make a grunt or grunts.\n[v.] (of a pig) To make a grunt or grunts.\n[v.] To break wind; to fart.","ex":"Who just grunted?"},"GUAVA":{"p":"/ˈɡwɑvə/","s":"n.","e":"[n.] A tropical tree or shrub of the myrtle family, Psidium guajava.\n[n.] Its yellowish tropical fruit, 1¼ to 2 inches, globular or pear-shaped with thin, yellow, green or brown skin, is often made into jams and jellies. The meat is yellowish or pale green to pink in color.\n[n.] A medium reddish-pink colour, like that of guava flesh (also called guava pink).","ex":""},"GROWN":{"p":"/ɡɹəʊn/","s":"v./adj.","e":"[v.] To become larger, to increase in magnitude.\n[v.] To appear or sprout.\n[v.] To develop, to mature.\n[adj.] Covered by growth; overgrown.\n[adj.] Of a person: adult.","ex":"Children grow quickly."},"GUIDE":{"p":"/ɡaɪd/","s":"n.","e":"[n.] Someone who guides, especially someone hired to show people around a place or an institution and offer information and explanation.\n[n.] A document or book that offers information or instruction; guidebook.\n[n.] A sign that guides people; guidepost.","ex":"The guide led us around the museum and explained the exhibits."},"GRUEL":{"p":"/ɡɹuː(ə)l/","s":"n.","e":"[n.] A thin, watery porridge, formerly eaten primarily by the poor and the ill.","ex":""},"GRIPE":{"p":"/ɡɹʌɪp/","s":"n./v.","e":"[n.] A complaint, often a petty or trivial one.\n[n.] A wire rope, often used on davits and other life raft launching systems.\n[n.] Grasp; clutch; grip\n[v.] To complain; to whine.\n[v.] To annoy or bother.\n[v.] To tend to come up into the wind, as a ship which, when sailing close-hauled, requires constant labour at the helm.","ex":"What's griping you?"},"GROAN":{"p":"/ɡɹəʊn/","s":"n./v.","e":"[n.] A low, mournful sound uttered in pain or grief.\n[n.] A low, guttural sound uttered in frustration, disapproval, or ecstasy.\n[n.] (of an object) A low creaking sound from applied pressure or weight.\n[v.] To make a groan.\n[v.] To strive after earnestly, as if with groans.","ex":"The wooden table groaned under the weight of the banquet."},"GUESS":{"p":"/ɡɛs/","s":"v.","e":"[v.] To reach a partly (or totally) unqualified conclusion.\n[v.] To solve by a correct conjecture; to conjecture rightly.\n[v.] To suppose (introducing a proposition of uncertain plausibility).","ex":"He who guesses the riddle shall have the ring."},"GUILD":{"p":"/ɡɪld/","s":"n.","e":"[n.] A group or association mainly of tradespeople made up of merchants, craftspeople, or artisans for mutual aid, particularly in the Middle Ages.\n[n.] A corporation.\n[n.] A group of diverse species that share common characteristics or habits.","ex":""},"GUARD":{"p":"/ɡɑːd/","s":"n./v.","e":"[n.] A person who, or thing that, protects or watches over something.\n[n.] A garda; a police officer.\n[n.] A squad responsible for protecting something.\n[v.] To protect from danger; to secure against surprise, attack, or injury; to keep in safety; to defend.\n[v.] To keep watch over, in order to prevent escape or restrain from acts of violence, or the like.\n[v.] To watch by way of caution or defense; to be caution; to be in a state or position of defense or safety.","ex":"The prison guard unlocked the door of the cell.   After completing the repairs, he replaced the sump guard."},"GUILE":{"p":"/ɡaɪl/","s":"n./v.","e":"[n.] Astuteness often marked by a certain sense of cunning or artful deception.\n[n.] Deceptiveness, deceit, fraud, duplicity, dishonesty.\n[v.] To deceive, beguile, bewile.","ex":""},"GUEST":{"p":"/ɡɛst/","s":"n./v.","e":"[n.] A recipient of hospitality, specifically someone staying by invitation at the house of another.\n[n.] A patron or customer in a hotel etc.\n[n.] An invited visitor or performer to an institution or to a broadcast.\n[v.] To appear as a guest, especially on a broadcast\n[v.] As a musician, to play as a guest, providing an instrument that a band/orchestra does not normally have in its line up (for instance, percussion in a string band)\n[v.] To receive or entertain hospitably.","ex":"The guests were let in by the butler."},"GUISE":{"p":"/ˈɡaɪz/","s":"n./v.","e":"[n.] Customary way of speaking or acting; fashion, manner, practice (often used formerly in such phrases as \"at his own guise\"; that is, in his own fashion, to suit himself.)\n[n.] External appearance in manner or dress; appropriate indication or expression; garb; shape.\n[n.] Misleading appearance; cover, cloak.\n[v.] To dress.\n[v.] To act as a guiser; to go dressed up in a parade etc.","ex":"Under the guise of patriotism"},"GULCH":{"p":"/ɡʌltʃ/","s":"n./v.","e":"[n.] A ravine-like or deep V-shaped valley, often eroded by flash floods; shallower than a canyon and deeper than a gully.\n[n.] An act of gulching or gulping.\n[n.] A glutton.\n[v.] To swallow greedily; to gulp down.\n[v.] To fall heavily.","ex":""},"GYPSY":{"p":"/ˈd͡ʒɪp.si/","s":"n./adj./v.","e":"[n.] (sometimes offensive) A member of the Romani people, or one of the sub-groups (Roma, Sinti, Romanichal, etc).\n[adj.] (sometimes offensive) Of or belonging to the Romani people or one of it sub-groups (Roma, Sinti, Romanichel, etc).\n[n.] An itinerant person or any person, not necessarily Romani; a tinker, a traveller or a carny.\n[n.] (sometimes offensive) A move in contra dancing in which two dancers walk in a circle around each other while maintaining eye contact (but not touching as in a swing). (Compare whole gyp, half gyp, and gypsy meltdown, in which this step precedes a swing.)\n[n.] A member of a Broadway musical chorus line.\n[v.] To roam around the country like a gypsy.","ex":""},"GUSTO":{"p":"/ˈɡʌstəʊ/","s":"n.","e":"[n.] Enthusiasm; enjoyment, vigor.","ex":"He sang with more gusto than talent."},"HAIR":{"p":"/heː/","s":"n./v.","e":"[n.] A pigmented filament of keratin which grows from a follicle on the skin of humans and other mammals.\n[n.] The collection or mass of such growths growing from the skin of humans and animals, and forming a covering for a part of the head or for any part or the whole body.\n[n.] A slender outgrowth from the chitinous cuticle of insects, spiders, crustaceans, and other invertebrates. Such hairs are totally unlike those of vertebrates in structure, composition, and mode of growth.\n[v.] To remove the hair from.\n[v.] To grow hair (where there was a bald spot).\n[v.] To cause to have hair; to provide with hair","ex":"In the western world, women usually have long hair while men usually have short hair."},"HAIRY":{"p":"/ˈhɛəɹi/","s":"adj.","e":"[adj.] Of a person, having a lot of hair on the body.\n[adj.] Of an animal, having a lot of fur.\n[adj.] Of a body part other than the head, having hair growing from it.","ex":"a hairy man"},"HALFWAY":{"p":"/hɑːfˈweɪ/","s":"adv.","e":"[adv.] Half of the way between two points; midway.\n[adv.] Moderately; somewhat.","ex":"a halfway decent place to sleep"},"HANGING":{"p":"/ˈhæŋɪŋ/","s":"v./adj.","e":"[v.] To be or remain suspended.\n[v.] To float, as if suspended.\n[v.] (of a ball in cricket, tennis, etc.) To rebound unexpectedly or unusually slowly, due to backward spin on the ball or imperfections of the ground.\n[adj.] Suspended.\n[adj.] (of a piece) Unprotected and exposed to capture.\n[adj.] (of an off-speed pitch) Hittable; poorly executed by the pitcher hence relatively easy to hit.","ex":"The lights hung from the ceiling."},"HALL":{"p":"/hɔːl/","s":"n.","e":"[n.] A corridor; a hallway.\n[n.] A meeting room.\n[n.] A manor house (originally because a magistrate's court was held in the hall of his mansion).","ex":"The drinking fountain was out in the hall."},"HARD":{"p":"/hɑːd/","s":"n./adj./adv.","e":"[n.] A firm or paved beach or slope convenient for hauling vessels out of the water.\n[n.] A tyre whose compound is softer than superhards, and harder than mediums.\n[n.] Crack cocaine.\n[adj.] (of material or fluid) Having a severe property; presenting difficulty.\n[adj.] (personal or social) Having a severe property; presenting difficulty.\n[adj.] Unquestionable.","ex":"hard evidence;  a hard requirement"},"HASTE":{"p":"/heɪst/","s":"n./v.","e":"[n.] Speed; swiftness; dispatch.\n[n.] Urgency; sudden excitement of feeling or passion; precipitance; vehemence.\n[v.] To urge onward; to hasten.\n[v.] To move with haste.","ex":"We were running late so we finished our meal in haste."},"GUSTY":{"p":"/ˈɡʌs.ti/","s":"adj.","e":"[adj.] (of wind) Blowing in gusts; blustery; tempestuous.\n[adj.] (by extension, metaphoric) Characterized by or occurring in instances of sudden strong expression\n[adj.] (metaphoric) Bombastic, verbose.","ex":""},"HABIT":{"p":"/ˈhæbət/","s":"n.","e":"[n.] An action performed on a regular basis.\n[n.] An action performed repeatedly and automatically, usually without awareness.\n[n.] A long piece of clothing worn by monks and nuns.","ex":"It’s become a habit of mine to have a cup of coffee after dinner."},"GUMBO":{"p":"","s":"n.","e":"[n.] A soup or stew made with okra.\n[n.] A fine silty soil that when wet becomes very thick and heavy.\n[n.] The edible immature mucilaginous seed pod (properly, capsule) of the Abelmoschus esculentus.\n[n.] The flowering mallow plant Abelmoschus esculentus itself, now commonly grown in the tropics and warmer parts of the temperate zones.","ex":""},"HIGH":{"p":"/haɪ/","s":"n./v./adj./adv.","e":"[n.] A high point or position, literally or figuratively; an elevated place; a superior region; a height; the sky; heaven.\n[n.] A point of success or achievement; a time when things are at their best.\n[n.] A period of euphoria, from excitement or from an intake of drugs.\n[v.] To rise.\n[adj.] Very elevated; extending or being far above a base; tall; lofty.\n[adj.] Relatively elevated; rising or raised above the average or normal level from which elevation is measured.","ex":"It was one of the highs of his career."},"HILL":{"p":"/hɪl/","s":"n./v.","e":"[n.] An elevated location smaller than a mountain.\n[n.] A sloping road.\n[n.] A heap of earth surrounding a plant.\n[v.] To form into a heap or mound.\n[v.] To heap or draw earth around plants.","ex":"The park is sheltered from the wind by a hill to the east."},"HIRE":{"p":"/haɪə/","s":"n.","e":"[n.] Payment for the temporary use of something.\n[n.] Reward, payment.\n[n.] The state of being hired, or having a job; employment.","ex":"The sign offered pedalos on hire."},"HARVEST":{"p":"/ˈhaːvəst/","s":"n./v.","e":"[n.] The third season of the year; autumn; fall.\n[n.] The season of gathering ripened crops; specifically, the time of reaping and gathering grain.\n[n.] The process of gathering the ripened crop; harvesting.\n[v.] To bring in a harvest; reap; glean.\n[v.] To be occupied bringing in a harvest\n[v.] To win, achieve a gain.","ex":"Harvest is usually very damp and rainy."},"HOLIDAY":{"p":"/ˈhɒlɪdeɪ/","s":"n./v.","e":"[n.] A day on which a festival, religious event, or national celebration is traditionally observed.\n[n.] A day declared free from work by the state or government.\n[n.] A period of one or more days taken off work for leisure and often travel; often plural.\n[v.] To take a period of time away from work or study.\n[v.] To spend a period of time for travel.","ex":"Today is a Wiccan holiday!"},"HELIX":{"p":"/ˈhiːlɪks/","s":"n./v.","e":"[n.] A curve on the surface of a cylinder or cone such that its angle to a plane perpendicular to the axis is constant; the three-dimensional curve seen in a screw or a spiral staircase.\n[n.] A small volute under the abacus of a Corinthian capital.\n[n.] The incurved rim of the external ear.\n[v.] To form or cause to form a helix.","ex":""},"HORNY":{"p":"/ˈhɔɹ.ni/","s":"adj.","e":"[adj.] Hard or bony, like an animal's horn.\n[adj.] Having horns.\n[adj.] Sexually aroused.","ex":"That girl makes me feel horny."},"HORROR":{"p":"/ˈhɔɹɚ/","s":"n.","e":"[n.] An intense distressing emotion of fear or repugnance.\n[n.] Something horrible; that which excites horror.\n[n.] Intense dislike or aversion; an abhorrence.","ex":"I saw many horrors during the war."},"HORSE":{"p":"/hɔːs/","s":"n.","e":"[n.] Any of several animals related to Equus ferus caballus.\n[n.] Equipment with legs.\n[n.] Type of equipment.","ex":""},"HOSTA":{"p":"/ˈhɒstə/","s":"n.","e":"[n.] Any of several herbaceous Asiatic plants of the genus Hosta.","ex":""},"HONOR":{"p":"/ˈɒn.ə/","s":"n./v.","e":"[n.] Recognition of importance or value; respect; veneration (of someone, usually for being morally upright or successful)\n[n.] The state of being morally upright, honest, noble, virtuous, and magnanimous; excellence of character; the perception of such a state; favourable reputation; dignity\n[n.] A token of praise or respect; something that represents praiseworthiness or respect, such as a prize or award given by the state to a citizen\n[v.] To think of highly, to respect highly; to show respect for; to recognise the importance or spiritual value of\n[v.] To conform to, abide by, act in accordance with (an agreement, treaty, promise, request, or the like)\n[v.] To confer (bestow) an honour or privilege upon (someone)","ex":"The crowds gave the returning general much honor and praise."},"HOLE":{"p":"/həʊl/","s":"n./v.","e":"[n.] A hollow place or cavity; an excavation; a pit; an opening in or through a solid body, a fabric, etc.; a perforation; a rent; a fissure.\n[n.] (heading) In games.\n[n.] An excavation pit or trench.\n[v.] To make holes in (an object or surface).\n[v.] (by extension) To destroy.\n[v.] To go into a hole.","ex":"There’s a hole in my shoe.  Her stocking has a hole in it."},"HOUR":{"p":"/ˈaʊɚ/","s":"n.","e":"[n.] A time period of sixty minutes; one twenty-fourth of a day.\n[n.] A season, moment, or time.\n[n.] The time.","ex":"I spent an hour at lunch."},"HOUSE":{"p":"/hʌʊs/","s":"n.","e":"[n.] A structure built or serving as an abode of human beings.\n[n.] The people who live in a house; a household.\n[n.] A building used for something other than a residence (typically with qualifying word).","ex":"This is my house and my family's ancestral home."},"HOVEL":{"p":"/ˈhɒvəl/","s":"n./v.","e":"[n.] An open shed for sheltering cattle, or protecting produce, etc., from the weather.\n[n.] A poor cottage; a small, mean house; a hut.\n[n.] In the manufacture of porcelain, a large, conical brick structure around which the firing kilns are grouped.\n[v.] To put in a hovel; to shelter.\n[v.] To construct a chimney so as to prevent smoking, by making two of the more exposed walls higher than the others, or making an opening on one side near the top.","ex":""},"HOTEL":{"p":"/(h)əʊˈtɛl/","s":"n.","e":"[n.] A large town house or mansion; a grand private residence, especially in France.\n[n.] An establishment that provides accommodation and other services for paying guests; normally larger than a guesthouse, and often one of a chain.\n[n.] A restaurant; any dining establishment.","ex":""},"HOWDY":{"p":"/ˈhaʊdi/","s":"n./v./int.","e":"[n.] A wife, a midwife.\n[v.] To greet informally, especially by saying \"howdy\"\n[int.] An informal greeting used in the South of the USA.","ex":"Howdy folks, and welcome to our ninth annual chili cookoff!"},"HOWEVER":{"p":"/hɑʊˈɛvə/","s":"adv./conj.","e":"[adv.] Nevertheless; yet, still; in spite of (that).\n[adv.] (degree) To whatever degree or extent\n[adv.] (manner) In whatever way or manner.\n[conj.] In whatever way or manner.\n[conj.] Although, though, but, yet.","ex":"He told me not to do it. I, however, did it anyway. / I did it anyway, however. / (sometimes proscribed:) However, I did it anyway."},"HUGE":{"p":"[hʊudʒ]","s":"adj.","e":"[adj.] Very large.\n[adj.] Distinctly interesting, significant, important, likeable, well regarded.","ex":"The castle was huge."},"HOVER":{"p":"/ˈhɒ.və(ɹ)/","s":"n./v.","e":"[n.] The act of hovering\n[v.] To float in the air.\n[v.] To linger or hang in one place, especially in an uncertain manner.\n[v.] To waver, or be uncertain.","ex":"The hummingbird hovered by the plant."},"HOTLY":{"p":"","s":"adv.","e":"[adv.] With great amounts of heat\n[adv.] In a heated manner; intensely or vehemently","ex":""},"HUMPH":{"p":"/h(ə)mf/","s":"v./int.","e":"[v.] To utter \"humph!\" in doubt or disapproval.\n[int.] Used to express doubt or disapproval","ex":""},"HUNT":{"p":"/hʌnt/","s":"n./v.","e":"[n.] The act of hunting.\n[n.] A hunting expedition.\n[n.] An organization devoted to hunting, or the people belonging to it.\n[v.] To find or search for an animal in the wild with the intention of killing the animal for its meat or for sport.\n[v.] To try to find something; search (for).\n[v.] To drive; to chase; with down, from, away, etc.","ex":"Her uncle will go out and hunt for deer, now that it is open season."},"HUTCH":{"p":"/hʌtʃ/","s":"n./v.","e":"[n.] A cage for keeping rabbits, guinea pigs, etc.\n[n.] A piece of furniture in which items may be displayed.\n[n.] A measure of two Winchester bushels.\n[v.] To hoard or lay up, in a chest.\n[v.] To wash (ore) in a box or jig.","ex":""},"HURT":{"p":"/hɜːt/","s":"n./v./adj.","e":"[n.] An emotional or psychological humiliation or bad experience.\n[n.] A bodily injury causing pain; a wound or bruise.\n[n.] Injury; damage; detriment; harm\n[v.] To be painful.\n[v.] To cause (a creature) physical pain and/or injury.\n[v.] To cause (somebody) emotional pain.","ex":"how to overcome old hurts of the past"},"HURRY":{"p":"/ˈhʌ.ɹi/","s":"n./v.","e":"[n.] Rushed action.\n[n.] Urgency.\n[n.] An incidence of a defensive player forcing the quarterback to act faster than the quarterback was prepared to, resulting in a failed offensive play.\n[v.] To do things quickly.\n[v.] Often with up, to speed up the rate of doing something.\n[v.] To cause to be done quickly.","ex":"Why are you in such a big hurry?"},"HUSKY":{"p":"/ˈhʌs.ki/","s":"adj.","e":"[adj.] (of a voice) Hoarse and rough-sounding.\n[adj.] Burly, stout.\n[adj.] Abounding with husks; consisting of husks.","ex":""},"HYMEN":{"p":"/ˈhaɪmən/","s":"n.","e":"[n.] A membrane which completely or partially occludes the vaginal opening in human females.\n[n.] Marriage.","ex":""},"HYPER":{"p":"/ˈhaɪpə/","s":"n./adj.","e":"[n.] Hyperextension exercise\n[n.] Hyperspace\n[adj.] Hyperactive\n[adj.] Energetic; overly diligent","ex":""},"ICON":{"p":"/ˈaɪ.kən/","s":"n.","e":"[n.] An image, symbol, picture, or other representation usually as an object of religious devotion.\n[n.] (especially Eastern Christianity) A type of religious painting portraying a saint or scene from Scripture, often done on wooden panels.\n[n.] (by extension) A person or thing that is the best example of a certain profession or some doing.","ex":"That man is an icon in the business; he personifies loyalty and good business sense."},"IDEA":{"p":"/ɑeˈdiə̯/","s":"n.","e":"[n.] An abstract archetype of a given thing, compared to which real-life examples are seen as imperfect approximations; pure essence, as opposed to actual examples.\n[n.] The conception of someone or something as representing a perfect example; an ideal.\n[n.] The form or shape of something; a quintessential aspect or characteristic.","ex":""},"IDEAL":{"p":"/aɪˈdiː.əl/","s":"n./adj.","e":"[n.] A perfect standard of beauty, intellect etc., or a standard of excellence to aim at.\n[n.] A subring closed under multiplication by its containing ring.\n[n.] (lattice theory) A non-empty lower set (of a partially ordered set) which is closed under binary suprema (a.k.a. joins).\n[adj.] Optimal; being the best possibility.\n[adj.] Perfect, flawless, having no defects.\n[adj.] Pertaining to ideas, or to a given idea.","ex":""},"IDIOM":{"p":"/ˈɪdɪəm/","s":"n.","e":"[n.] A manner of speaking, a mode of expression peculiar to a language, person, or group of people.\n[n.] A language or language variety; specifically, a restricted dialect used in a given historical period, context etc.\n[n.] An established expression whose meaning is not deducible from the literal meanings of its component words, often peculiar to a given language.","ex":""},"IDYLL":{"p":"/ˈɪdəl/","s":"n.","e":"[n.] Any poem or short written piece composed in the style of Theocritus' short pastoral poems, the Idylls.\n[n.] An episode or series of events or circumstances of pastoral or rural simplicity, fit for an idyll; a carefree or lighthearted experience.\n[n.] A composition, usually instrumental, of a pastoral or sentimental character, e.g. Siegfried Idyll by Richard Wagner.","ex":""},"IGLOO":{"p":"/ˈɪɡluː/","s":"n.","e":"[n.] A dome-shaped Inuit shelter, constructed of blocks cut from snow.\n[n.] A cavity, or excavation, made in the snow by a seal, over its breathing hole in the sea ice.\n[n.] A reinforced bunker for the storage of nuclear weapons.","ex":""},"ILIAC":{"p":"","s":"adj.","e":"[adj.] Of or pertaining to the ilium.","ex":""},"IMAGINE":{"p":"/ɪˈmædʒ.ɪn/","s":"n./v.","e":"[n.] A short fanfic or prompt placing a reader insert in a novel scenario with a character or celebrity.\n[v.] To form a mental image of something; to envision or create something in one's mind.\n[v.] To believe in something created by one's own mind.\n[v.] To assume","ex":"Try to imagine a pink elephant."},"IMAGE":{"p":"/ˈɪmɪd͡ʒ/","s":"n./v.","e":"[n.] An optical or other representation of a real object; a graphic; a picture.\n[n.] A mental picture of something not real or not present.\n[n.] A statue or idol.\n[v.] To represent by an image or symbol; to portray.\n[v.] To reflect, mirror.\n[v.] To create an image of.","ex":"The Bible forbids the worship of graven images."},"IMPACT":{"p":"","s":"n./v.","e":"[n.] The striking of one body against another; collision.\n[n.] The force or energy of a collision of two objects.\n[n.] A forced impinging.\n[v.] To collide or strike, the act of impinging.\n[v.] To compress; to compact; to press into something or pack together.\n[v.] To influence; to affect; to have an impact on.","ex":"The hatchet cut the wood on impact."},"IMPLY":{"p":"/ɪmˈplaɪ/","s":"v.","e":"[v.] (of a proposition) to have as a necessary consequence\n[v.] (of a person) to suggest by logical inference\n[v.] (of a person or proposition) to hint; to insinuate; to suggest tacitly and avoid a direct statement","ex":"The proposition that \"all dogs are mammals\" implies that my dog is a mammal"},"IMPOSE":{"p":"/ɪmˈpəʊz/","s":"v.","e":"[v.] To establish or apply by authority.\n[v.] To be an inconvenience (on or upon)\n[v.] To enforce: compel to behave in a certain way","ex":"Congress imposed new tariffs."},"IMPROVE":{"p":"/ɪmˈpɹuːv/","s":"v.","e":"[v.] To make (something) better; to increase the value or productivity (of something).\n[v.] To become better.\n[v.] To disprove or make void; to refute.","ex":"Buying more servers would improve performance."},"INBOX":{"p":"/ˈɪmbɒks/","s":"n./v.","e":"[n.] A container in which papers to be dealt with are put.\n[n.] An electronic folder serving the same purpose.\n[n.] The aggregate of items that demand one's attention or effort.\n[v.] To put (something) in someone's inbox.\n[v.] To communicate with (a person) by writing to their electronic inbox.","ex":"The kids, my ex, my parents, the job, bills — my inbox is full."},"IMBUE":{"p":"/ɪmˈbjuː/","s":"v.","e":"[v.] To wet or stain an object completely with some physical quality.\n[v.] In general, to act in a way which results in an object becoming completely permeated or impregnated by some quality.","ex":"The shirt was imbued with his scent."},"INCOME":{"p":"/ˈɪnˌkʌm/","s":"n.","e":"[n.] Money one earns by working or by capitalising on the work of others.\n[n.] Money coming in to a fund, account, or policy.\n[n.] A coming in; arrival; entrance; introduction.","ex":""},"INCUR":{"p":"/ɪnˈkəː/","s":"v.","e":"[v.] To bring upon oneself or expose oneself to, especially something inconvenient, harmful, or onerous; to become liable or subject to\n[v.] To enter or pass into\n[v.] To fall within a period or scope; to occur; to run into danger","ex":""},"IMPORT":{"p":"/ˈɪm.pɔːt/","s":"n./v.","e":"[n.] Something brought in from an exterior source, especially for sale or trade.\n[n.] The practice of importing.\n[n.] Significance, importance.\n[v.] To bring (something) in from a foreign country, especially for sale or trade.\n[v.] To load a file into a software application from another version or system.","ex":"It was a matter of great import."},"INDEX":{"p":"/ˈɪndɛks/","s":"n./v.","e":"[n.] An alphabetical listing of items and their location.\n[n.] The index finger; the forefinger.\n[n.] A movable finger on a gauge, scale, etc.\n[v.] To arrange an index for something, especially a long text.\n[v.] To inventory, to take stock.\n[v.] To normalise in order to account for inflation; to correct for inflation by linking to a price index in order to maintain real levels.","ex":"The index of a book lists words or expressions and the pages of the book upon which they are to be found."},"INANE":{"p":"/ɪˈneɪn/","s":"n./adj.","e":"[n.] That which is void or empty.\n[adj.] Lacking sense or meaning (often to the point of boredom or annoyance)\n[adj.] Purposeless; pointless","ex":"This supremely gifted kid told me that in the early elementary grades, the songs sung in music class were so inane that he wanted to skip grades already! Eventually he did, so better late than never."},"INCLUDE":{"p":"/ɪnˈkluːd/","s":"n./v.","e":"[n.] A piece of source code or other content that is dynamically retrieved for inclusion in another item.\n[v.] To bring into a group, class, set, or total as a (new) part or member.\n[v.] To contain, as parts of a whole; to comprehend.\n[v.] To enclose, confine.","ex":"I will purchase the vacation package if you will include car rental."},"INJURY":{"p":"/ˈɪn.dʒə.ɹi/","s":"n./v.","e":"[n.] Damage to the body of a human or animal.\n[n.] The violation of a person's reputation, rights, property, or interests.\n[n.] Injustice.\n[v.] To wrong, to injure.","ex":"The passenger sustained a severe injury in the car accident."},"INFER":{"p":"/ɪnˈfɜː/","s":"v.","e":"[v.] To introduce (something) as a reasoned conclusion; to conclude by reasoning or deduction, as from premises or evidence.\n[v.] To lead to (something) as a consequence; to imply. (Now often considered incorrect, especially with a person as subject.)\n[v.] To cause, inflict (something) upon or to someone.","ex":""},"IMPEL":{"p":"/ɪmˈpɛl/","s":"v.","e":"[v.] To urge a person; to press on; to incite to action or motion via intrinsic motivation.\n[v.] To drive forward; to propel an object, to provide an impetus for motion or action.","ex":""},"INNER":{"p":"/ˈɪnə/","s":"n./adj.","e":"[n.] An inner part.\n[n.] A duvet, excluding the cover.\n[n.] A forward who plays in or near the center of the field.\n[adj.] Being or occurring (farther) inside, situated farther in, located (situated) or happening on the inside of something, situated within or farther within contained within something.\n[adj.] Close to the centre, located near or closer to center.\n[adj.] Inside or closer to the inside of the body.","ex":"inner door;  inner room;  inner sanctum;  inner surface"},"INLAY":{"p":"","s":"n./v.","e":"[n.] The material placed within a different material in the form of a decoration.\n[n.] A filling for a tooth, made of ceramic or gold to fit the cavity and shape of tooth and cemented into place.\n[n.] The piece of paper or the booklet inside the case of a CD or DVD\n[v.] To place (pieces of a foreign material) within another material to form a decorative design.\n[v.] To place an inlay in a tooth.","ex":""},"INGOT":{"p":"/ˈɪŋɡət/","s":"n./v.","e":"[n.] A solid block of more or less pure metal, often but not necessarily bricklike in shape and trapezoidal in cross-section, the result of pouring out and cooling molten metal, often immediately after smelting from raw ore or alloying from constituents.\n[v.] To form (scraps of metal) into ingots.","ex":""},"INPUT":{"p":"/ˈɪnpʊt/","s":"n./v.","e":"[n.] The act or process of putting in; infusion.\n[n.] That which is put in, as in an amount.\n[n.] Contribution of work or information, as an opinion or advice.\n[v.] To put in; put on.\n[v.] To enter data.\n[v.] To accept data that is entered.","ex":"The user inputs his date of birth and the computer displays his age."},"INDEED":{"p":"/ɪnˈdiːd/","s":"adv./int.","e":"[adv.] (modal) Truly; in fact; actually.\n[adv.] (degree, after the adjective modified) In fact.\n[int.] Indicates emphatic agreement.\n[int.] With interrogative intonation (low-high) indicates serious doubt.","ex":"Indeed, he made several misplays."},"INSIDE":{"p":"/ɪnˈsaɪd/","s":"n./adj./adv./prep.","e":"[n.] The interior or inner part.\n[n.] The left-hand side of a road if one drives on the left, or right-hand side if one drives on the right.\n[n.] The side of a curved road, racetrack etc. that has the shorter arc length; the side of a racetrack nearer the interior of the course or some other point of reference.\n[adj.] Of or pertaining to the inner surface, limit or boundary.\n[adj.] Nearer to the interior or centre of something.\n[adj.] Originating from, arranged by, or being someone inside an organisation.","ex":"The inside of the building has been extensively restored."},"INSPECT":{"p":"/ɪnˈspɛkt/","s":"v.","e":"[v.] To examine critically or carefully; especially, to search out problems or determine condition; to scrutinize.\n[v.] To view and examine officially.","ex":"Inspect the system for leaks."},"INDUSTRY":{"p":"/ˈɪndəstɹi/","s":"n.","e":"[n.] The tendency to work persistently. Diligence.\n[n.] Businesses of the same type, considered as a whole. Trade.\n[n.] Businesses that produce goods as opposed to services.","ex":"Over the years, their industry and business sense made them wealthy."},"INSTALL":{"p":"/ɪnˈstɔːl/","s":"n./v.","e":"[n.] Installer. A software utility that installs an application.\n[n.] An installation. (Usage originated as a truncated form of the word installation.)\n[v.] To connect, set up or prepare something for use.\n[v.] To admit formally into an office, rank or position.\n[v.] To establish or settle in.","ex":"After inserting the disk, you need to run the install."},"INSTANT":{"p":"/ˈɪnstənt/","s":"n.","e":"[n.] A very short period of time; a moment.\n[n.] A single, usually precise, point in time.\n[n.] A beverage or food which has been pre-processed to reduce preparation time, especially instant coffee.\n[n.] A camera that uses self-developing film to create a chemically developed print shortly after the photograph is taken.","ex":"She paused for only an instant, which was just enough time for John to change the subject."},"INTERIM":{"p":"/ˈɪntəɹɪm/","s":"n./adj.","e":"[n.] A transitional or temporary period between other events.\n[adj.] Transitional.\n[adj.] Temporary.","ex":"His car is in the shop, but they gave him a rental to drive in the interim."},"INLET":{"p":"","s":"v.","e":"[v.] To let in; admit.\n[v.] To insert; inlay.","ex":""},"INTO":{"p":"/ˈɪn.tuː/","s":"prep.","e":"[prep.] To or towards the inside of.\n[prep.] To or towards the region of.\n[prep.] Against, especially with force or violence.","ex":"Mary danced into the house."},"INSPIRE":{"p":"/ɪn.ˈspaɪə(ɹ)/","s":"v.","e":"[v.] To infuse into the mind; to communicate to the spirit; to convey, as by a divine or supernatural influence; to disclose preternaturally; to produce in, as by inspiration.\n[v.] To infuse into; to affect, as with a superior or supernatural influence; to fill with what animates, enlivens or exalts; to communicate inspiration to.\n[v.] To draw in by the operation of breathing; to inhale.","ex":"Elders should inspire children with sentiments of virtue."},"INTRO":{"p":"/ˈɪntɹoʊ/","s":"n./v.","e":"[n.] An introduction.\n[n.] The opening sequence at beginning of a film, television program, etc.\n[n.] A small demo produced to promote one's demogroup or for a competition.\n[v.] To introduce.","ex":""},"INSERT":{"p":"/ɪnˈsɜːt/","s":"n./v.","e":"[n.] An image inserted into text.\n[n.] A promotional or instructive leaflet inserted into a magazine, newspaper, tape or disk package, etc.\n[n.] A mechanical component inserted into another.\n[v.] To put in between or into.","ex":"This software can print compact disc inserts if you have the right size of paper."},"INSTEAD":{"p":"/ɪnˈstɛd/","s":"adv.","e":"[adv.] In the place of something (usually mentioned earlier); as a substitute or alternative.","ex":"I was going to go shopping, but I went dancing instead."},"INVENT":{"p":"/ɪnˈvɛnt/","s":"v.","e":"[v.] To design a new process or mechanism.\n[v.] To create something fictional for a particular purpose.\n[v.] To come upon; to find; to discover.","ex":"After weeks of hard work, I invented a new way to alphabetize matchbooks."},"INQUIRE":{"p":"/ɪnˈkwaɪə/","s":"v.","e":"[v.] To ask (about something).\n[v.] To make an inquiry or an investigation.\n[v.] To call; to name.","ex":""},"IRATE":{"p":"/aɪˈɹeɪt/","s":"adj.","e":"[adj.] Extremely angry; wrathful; enraged.","ex":""},"INVEST":{"p":"/ɪnˈvɛst/","s":"v.","e":"[v.] To spend money, time, or energy on something, especially for some benefit or purpose; used with in.\n[v.] To clothe or wrap (with garments).\n[v.] To put on (clothing).","ex":"We'd like to thank all the contributors who have invested countless hours into this event."},"IRONY":{"p":"/ˈaɪə.ɹən.i/","s":"n.","e":"[n.] A statement that, when taken in context, may actually mean something different from, or the opposite of, what is written literally; the use of words expressing something other than their literal intention, often in a humorous context.\n[n.] Dramatic irony: a theatrical effect in which the meaning of a situation, or some incongruity in the plot, is understood by the audience, but not by the characters in the play.\n[n.] Ignorance feigned for the purpose of confounding or provoking an antagonist; Socratic irony.","ex":""},"ISLET":{"p":"/ˈaɪ.lət/","s":"n.","e":"[n.] A small island\n[n.] An isolated piece of tissue that has a specific function","ex":""},"ISLAND":{"p":"/ˈaɪ̯lənd/","s":"n./v.","e":"[n.] A contiguous area of land, smaller than a continent, totally surrounded by water.\n[n.] An entity surrounded by other entities that are very different from itself.\n[n.] A superstructure on an aircraft carrier's deck.\n[v.] To surround with water; make into an island.\n[v.] To set, dot (as if) with islands.\n[v.] To isolate.","ex":"an island of colors on a butterfly's wing"},"ISSUE":{"p":"/ˈɪsjuː/","s":"n./v.","e":"[n.] The action or an instance of flowing or coming out, an outflow, particularly:\n[n.] Someone or something that flows out or comes out, particularly:\n[n.] The means or opportunity by which something flows or comes out, particularly:\n[v.] To flow out, to proceed from, to come out or from.\n[v.] To rush out, to sally forth.\n[v.] To extend into, to open onto.","ex":"The rents issuing from the land permitted him to live as a man of independent means."},"INVITED":{"p":"/ɪnˈvaɪtɪd/","s":"v./adj.","e":"[v.] To ask for the presence or participation of someone or something.\n[v.] To request formally.\n[v.] To encourage.\n[adj.] Having been asked to attend.\n[adj.] Having an invitation.","ex":"We invited our friends round for dinner."},"ITCHY":{"p":"/ˈɪtʃi/","s":"adj.","e":"[adj.] Having or creating an itch, causing a person or animal to tend to want to scratch.","ex":""},"ITEM":{"p":"[ˈaɪ̯ɾm̩]","s":"n./v./adv.","e":"[n.] A distinct physical object.\n[n.] (by extension) An object that can be picked up for later use.\n[n.] A line of text having a legal or other meaning; a separate particular in an account.\n[v.] To make a note of.\n[adv.] Likewise","ex":"Tweezers are great for manipulating small items."},"IVORY":{"p":"/ˈaɪvəɹi/","s":"n./adj.","e":"[n.] The hard white form of dentin which forms the tusks of elephants, walruses and other animals.\n[n.] A creamy white color, the color of ivory.\n[n.] Something made from or resembling ivory.\n[adj.] Made of ivory.\n[adj.] Resembling or having the colour of ivory.","ex":""},"ITSELF":{"p":"/ɪtˈsɛlf/","s":"pron.","e":"[pron.] (reflexive pronoun) it; A thing as the object of a verb or preposition that also appears as the subject\n[pron.] It; used to intensify the subject, especially to emphasize that it is the only participant in the predicate\n[pron.] It; used to refer back to an earlier subject","ex":"The door closed by itself"},"INTER":{"p":"/ɪnˈtɜː(ɹ)/","s":"v.","e":"[v.] To bury in a grave.\n[v.] To confine, as in a prison.","ex":""},"INTENSE":{"p":"/ɪnˈtɛns/","s":"adj.","e":"[adj.] Strained; tightly drawn.\n[adj.] Strict, very close or earnest.\n[adj.] Extreme in degree; excessive.","ex":"intense study;  intense thought"},"JAUNT":{"p":"/ˈdʒɑːnt/","s":"n./v.","e":"[n.] A wearisome journey.\n[n.] A short excursion for pleasure or refreshment; a ramble; a short journey.\n[v.] To ramble here and there; to stroll; to make an excursion.\n[v.] To ride on a jaunting car.\n[v.] To jolt; to jounce.","ex":""},"JEAN":{"p":"/dʒiːn/","s":"n.","e":"[n.] Denim.","ex":"She wore a tattered jean jacket."},"JAZZ":{"p":"/d͡ʒæz/","s":"n./v.","e":"[n.] A musical art form rooted in West African cultural and musical expression and in the African American blues tradition, with diverse influences over time, commonly characterized by blue notes, syncopation, swing, call and response, polyrhythms and improvisation.\n[n.] Energy, excitement, excitability.\n[n.] The substance or makeup of a thing.\n[v.] To destroy.\n[v.] To play (jazz music).\n[v.] To dance to the tunes of jazz music.","ex":"What is all this jazz lying around?"},"JAZZY":{"p":"/ˈdʒæzi/","s":"adj.","e":"[adj.] In the style of jazz.\n[adj.] Flashy or showy.\n[adj.] Lacking focus; jittery or jangly.","ex":""},"JERSEY":{"p":"/ˈdʒɜːzi/","s":"n.","e":"[n.] A garment knitted from wool, worn over the upper body.\n[n.] A shirt worn by a member of an athletic team, usually oversized, typically depicting the athlete's name and team number as well as the team's logotype.\n[n.] A type of fabric knit","ex":""},"JELLY":{"p":"/ˈd͡ʒɛl.i/","s":"n./v.","e":"[n.] An explosive mixture of nitroglycerine and nitrate absorbed onto a base of wood pulp.\n[n.] A dessert made by boiling gelatine, sugar and some flavouring (often derived from fruit) and allowing it to set, known as \"jello\" in North America.\n[n.] A clear or translucent fruit preserve, made from fruit juice and set using either naturally occurring, or added, pectin. Known as \"jam\" in Commonwealth English.\n[n.] A savoury substance, derived from meat, that has the same texture as the dessert.\n[v.] To wiggle like jelly.\n[v.] To make jelly.","ex":""},"JEWEL":{"p":"/dʒul/","s":"n./v.","e":"[n.] A precious or semi-precious stone; gem, gemstone.\n[n.] A valuable object used for personal ornamentation, especially one made of precious metals and stones; a piece of jewellery.\n[n.] Anything precious or valuable.\n[v.] To bejewel; to decorate or bedeck with jewels or gems.","ex":"Galveston was the jewel of Texas prior to the hurricane."},"JACK":{"p":"/dʒæk/","s":"n.","e":"[n.] A coarse mediaeval coat of defence, especially one made of leather.","ex":""},"JIFFY":{"p":"/ˈd͡ʒɪ.fi/","s":"n.","e":"[n.] A very short, unspecified length of time.\n[n.] A unit of time defined by the frequency of its basic timer – historically, and by convention, 0.01 of a second, but some computer operating systems use other values.\n[n.] The length of an alternating current power cycle (1/60 or 1/50 of a second).","ex":"I’ll be back in a jiffy."},"JANE":{"p":"/dʒeɪn/","s":"n.","e":"[n.] A silver Genovese coin, first used in England in the 14th century.","ex":""},"IONIC":{"p":"/aɪˈɒnɪk/","s":"adj.","e":"[adj.] Of, relating to, or containing ions","ex":""},"IRON":{"p":"/ˈaɪən/","s":"n./v./adj.","e":"[n.] A common, inexpensive metal, silvery grey when untarnished, that rusts, is attracted by magnets, and is used in making steel.\n[n.] A metallic chemical element having atomic number 26 and symbol Fe.\n[n.] Any material, not a steel, predominantly made of elemental iron.\n[v.] To pass an iron over (clothing or some other item made of cloth) in order to remove creases.\n[v.] To shackle with irons; to fetter or handcuff.\n[v.] To furnish or arm with iron.","ex":"wrought iron, ductile iron, cast iron, pig iron, gray iron"},"JOB":{"p":"/d͡ʒɒb/","s":"n./v.","e":"[n.] A task.\n[n.] An economic role for which a person is paid.\n[n.] (in noun compounds) Plastic surgery.\n[v.] To do odd jobs or occasional work for hire.\n[v.] To work as a jobber.\n[v.] To take the loss.","ex":"A job half done is hardly done at all."},"JOHN":{"p":"/ˈdʒɒn/","s":"n.","e":"[n.] A prostitute's client.\n[n.] A device or place to urinate and defecate: now usually a toilet or lavatory, but also a chamber pot or outhouse.\n[n.] A Western man traveling in East Asia.","ex":""},"JOIN":{"p":"/ˈdʒɔɪn/","s":"n./v.","e":"[n.] An intersection of piping or wiring; an interconnect.\n[n.] An intersection of data in two or more database tables.\n[n.] The act of joining something, such as a network.\n[v.] To connect or combine into one; to put together.\n[v.] To come together; to meet.\n[v.] To come into the company of.","ex":"The plumber joined the two ends of the broken pipe."},"JOINT":{"p":"/dʒɔɪnt/","s":"n./v./adj.","e":"[n.] The point where two components of a structure join, but are still able to rotate.\n[n.] The point where two components of a structure join rigidly.\n[n.] Any part of the body where two bones join, in most cases allowing that part of the body to be bent or straightened.\n[v.] To unite by a joint or joints; to fit together; to prepare so as to fit together\n[v.] To join; to connect; to unite; to combine.\n[v.] To provide with a joint or joints; to articulate.","ex":"This rod is free to swing at the joint with the platform."},"JOIST":{"p":"/dʒɔɪst/","s":"n./v.","e":"[n.] A piece of timber laid horizontally, or nearly so, to which the planks of the floor, or the laths or furring strips of a ceiling, are nailed.\n[v.] To fit or furnish with joists.","ex":""},"JOKER":{"p":"/ˈdʒəʊkə/","s":"n.","e":"[n.] A person who makes jokes.\n[n.] A funny person.\n[n.] A jester.","ex":""},"JOURNAL":{"p":"/ˈd͡ʒɜːnəl/","s":"n./v./adj.","e":"[n.] A diary or daily record of a person, organization, vessel etc.; daybook.\n[n.] A newspaper or magazine dealing with a particular subject.\n[n.] A chronological record of payments.\n[v.] To archive or record something.\n[v.] To scrapbook.\n[v.] To insert (a shaft, etc.) in a journal bearing.","ex":"The university's biology department subscribes to half a dozen academic journals."},"JOLLY":{"p":"/ˈdʒɒli/","s":"n./v./adj./adv.","e":"[n.] A pleasure trip or excursion.\n[n.] A marine in the English navy.\n[v.] To amuse or divert.\n[adj.] Full of merriment and high spirits; jovial.\n[adj.] Full of life and mirth; jouous; merry.\n[adj.] Splendid, excellent, pleasant","ex":""},"JOURNEY":{"p":"/ˈd͡ʒɜːni/","s":"n./v.","e":"[n.] A set amount of travelling, seen as a single unit; a discrete trip, a voyage.\n[n.] Any process or progression likened to a journey, especially one that involves difficulties or personal development.\n[n.] A day.\n[v.] To travel, to make a trip or voyage.","ex":"my journey of dealing with grief"},"JUDGE":{"p":"/d͡ʒʌd͡ʒ/","s":"n.","e":"[n.] A public official whose duty it is to administer the law, especially by presiding over trials and rendering judgments; a justice.\n[n.] A person who decides the fate of someone or something that has been called into question.\n[n.] A person officiating at a sports event or similar.","ex":"At a boxing match, the decision of the judges is final."},"JOUST":{"p":"/dʒʌʊst/","s":"n./v.","e":"[n.] A tilting match: a mock combat between two mounted knights or men-at-arms using lances in the lists or enclosed field.\n[v.] To engage in mock combat on horseback, as two knights in the lists; to tilt.\n[v.] To engage in verbal sparring over an important issue. (used of two people, both of whom participate more or less equally)\n[v.] To touch penises while engaging in a sex act, especially oral sex.","ex":""},"JUMPY":{"p":"/ˈdʒʌmpi/","s":"adj.","e":"[adj.] Nervous and excited.","ex":""},"JUMP":{"p":"/dʒʌmp/","s":"n./v./adj./adv.","e":"[n.] The act of jumping; a leap; a spring; a bound.\n[n.] An effort; an attempt; a venture.\n[n.] A dislocation in a stratum; a fault.\n[v.] To propel oneself rapidly upward, downward and/or in any horizontal direction such that momentum causes the body to become airborne.\n[v.] To cause oneself to leave an elevated location and fall downward.\n[v.] To pass by a spring or leap; to overleap.","ex":"Kangaroos are known for their ability to jump high."},"JUMBO":{"p":"/ˈd͡ʒʌmbəʊ/","s":"n./adj.","e":"[n.] An especially large or powerful person, animal, or thing.\n[n.] A platform-mounted machine for drilling rock.\n[adj.] Especially large or powerful.","ex":""},"JOKE":{"p":"/dʒəʊk/","s":"n./v.","e":"[n.] An amusing story.\n[n.] Something said or done for amusement, not in seriousness.\n[n.] The root cause or main issue, especially an unexpected one\n[v.] To do or say something for amusement rather than seriously.\n[v.] (intransitive, followed by with) To dupe in a friendly manner for amusement; to mess with, play with.\n[v.] To make merry with; to make jokes upon; to rally.","ex":"It was a joke!"},"JUNIOR":{"p":"/ˈdʒuːnɪə/","s":"n./adj.","e":"[n.] A younger person.\n[n.] A name suffix used after a son's name when his father has the same name (abbreviations: Jnr., Jr., Jun.).\n[n.] A third-year student at a high school or university.\n[adj.] Low in rank; having a subordinate role, job, or situation.\n[adj.] (often preceded by a possessive adjective or a possessive form of a noun) Younger.\n[adj.] Belonging to a younger person, or an earlier time of life.","ex":"four years his junior"},"JERKY":{"p":"/ˈdʒɝki/","s":"adj.","e":"[adj.] Characterized by physical jerking.\n[adj.] Having the behavior of a jerk (unpleasant person).","ex":""},"JURY":{"p":"/ˈd͡ʒʊə.ɹi/","s":"n./v.","e":"[n.] A group of individuals chosen from the general population to hear and decide a case in a court of law.\n[n.] A group of judges in a competition.\n[n.] The audience attending the first night of a performance, whose reaction may determine whether it succeeds or fails.\n[v.] To judge by means of a jury.","ex":""},"JUICY":{"p":"/ˈdʒusi/","s":"adj.","e":"[adj.] Having lots of juice.\n[adj.] (of a story, etc.) Exciting; titillating.\n[adj.] (of a blow, strike, etc.) Strong, painful.","ex":"a juicy peach"},"JUST":{"p":"/d͡ʒʌst/","s":"adj./adv./int.","e":"[adj.] Factually right, correct; factual.\n[adj.] Rationally right, correct.\n[adj.] Morally right; upright, righteous, equitable; fair.\n[adv.] Only, simply, merely.\n[adv.] (sentence adverb) Used to reduce the force of an imperative; simply.\n[adv.] Used to convey a less serious or formal tone","ex":"It is a just assessment of the facts."},"JUROR":{"p":"/ˈdʒʊəɹɔɹ/","s":"n.","e":"[n.] A member of a jury.","ex":""},"JUNTA":{"p":"/ˈdʒʊntə/","s":"n.","e":"[n.] A council, convention, tribunal or assembly; especially, the grand council of state in Spain.\n[n.] The ruling council of a military dictatorship.","ex":""},"JUICE":{"p":"/d͡ʒuːs/","s":"n./v.","e":"[n.] A liquid from a plant, especially fruit.\n[n.] A beverage made of juice.\n[n.] Any liquid resembling juice.\n[v.] To extract the juice from something.\n[v.] To energize or stimulate something.","ex":"Squeeze the orange and some juice will come out."},"JUSTICE":{"p":"/ˈdʒʌs.tɪs/","s":"n.","e":"[n.] The state or characteristic of being just or fair.\n[n.] The ideal of fairness, impartiality, etc., especially with regard to the punishment of wrongdoing.\n[n.] Judgment and punishment of a party who has allegedly wronged another.","ex":"the justice of a description"},"JETTY":{"p":"/ˈdʒɛti/","s":"n./v.","e":"[n.] A structure of wood or stone extended into the sea to influence the current or tide, or to protect a harbor or beach.\n[n.] A wharf or dock extending from the shore.\n[n.] A part of a building that jets or projects beyond the rest, and overhangs the wall below.\n[v.] To jut out; to project.","ex":""},"KAPPA":{"p":"/ˈkæpə/","s":"n.","e":"[n.] The tenth letter of the Greek alphabet.\n[n.] A measurement of the sensitivity of the value of an option to changes in the implied volatility of the price of the underlying asset.","ex":""},"KARMA":{"p":"[ˈkəɾm(ə)]","s":"n.","e":"[n.] The sum total of a person's actions, which determine the person's next incarnation in samsara, the cycle of death and rebirth.\n[n.] A force or law of nature which causes one to reap what one sows; destiny; fate.\n[n.] A distinctive feeling, aura, or atmosphere.","ex":""},"KEEP":{"p":"/kiːp/","s":"n./v.","e":"[n.] The main tower of a castle or fortress, located within the castle walls.\n[n.] The food or money required to keep someone alive and healthy; one's support, maintenance.\n[n.] The act or office of keeping; custody; guard; care; heed; charge; notice.\n[v.] To continue in (a course or mode of action); not to intermit or fall from; to uphold or maintain.\n[v.] (heading) To hold the status of something.\n[v.] (heading) To hold or be held in a state.","ex":"He works as a cobbler's apprentice for his keep."},"KEEPING":{"p":"/ˈkiːpɪŋ/","s":"v./n.","e":"[v.] To continue in (a course or mode of action); not to intermit or fall from; to uphold or maintain.\n[v.] (heading) To hold the status of something.\n[v.] (heading) To hold or be held in a state.\n[n.] Conformity or harmony.\n[n.] Charge or care.\n[n.] Maintenance; support; provision; feed.","ex":"to keep silence;  to keep one's word;  to keep possession"},"KAYAK":{"p":"/ˈkaɪˌæk/","s":"n./v.","e":"[n.] A type of small boat, covered over by a surface deck, powered by the occupant or occupants using a double-bladed paddle in a sitting position, from a hole in the surface deck\n[v.] To use a kayak, to travel or race in a kayak.\n[v.] To traverse (a body of water) by kayak.","ex":"Kayaking is an Olympic sport."},"KEEN":{"p":"/kiːn/","s":"v./adj.","e":"[v.] To make cold, to sharpen.\n[adj.] Often with a prepositional phrase, or with to and an infinitive: showing a quick and ardent responsiveness or willingness; eager, enthusiastic, interested.\n[adj.] Fierce, intense, vehement.\n[adj.] Having a fine edge or point; sharp.","ex":"I’m keen on computers."},"KEEPER":{"p":"/ˈkiːpə/","s":"n.","e":"[n.] One who keeps something.\n[n.] A person or thing worth keeping.\n[n.] A person charged with guarding or caring for, storing, or maintaining something; a custodian, a guard; sometimes a gamekeeper.","ex":"Finders keepers; losers weepers]."},"KEPT":{"p":"/ˈkɛpt/","s":"v.","e":"[v.] To continue in (a course or mode of action); not to intermit or fall from; to uphold or maintain.\n[v.] (heading) To hold the status of something.\n[v.] (heading) To hold or be held in a state.","ex":"to keep silence;  to keep one's word;  to keep possession"},"KEBAB":{"p":"/kəˈbæb/","s":"n./v.","e":"[n.] A dish of pieces of meat, fish, or vegetables roasted on a skewer or spit, especially a doner kebab.\n[n.] A shish kebab or any other food on a skewer.\n[n.] The outward growing portions of a shish kebab structure.\n[v.] To roast in the style of a kebab\n[v.] To stab or skewer","ex":""},"KEY":{"p":"/kiː/","s":"n./v./adj.","e":"[n.] An object designed to open and close a lock.\n[n.] An object designed to fit between two other objects (such as a shaft and a wheel) in a mechanism and maintain their relative orientation.\n[n.] A crucial step or requirement.\n[v.] To fit (a lock) with a key.\n[v.] To fit (pieces of a mechanical assembly) with a key to maintain the orientation between them.\n[v.] To mark or indicate with a symbol indicating membership in a class.","ex":"The key to solving this problem is persistence."},"KICK":{"p":"/kɪk/","s":"n./v.","e":"[n.] A hit or strike with the leg, foot or knee.\n[n.] The action of swinging a foot or leg.\n[n.] Something that tickles the fancy; something fun or amusing.\n[v.] To strike or hit with the foot or other extremity of the leg.\n[v.] To make a sharp jerking movement of the leg, as to strike something.\n[v.] To direct to a particular place by a blow with the foot or leg.","ex":"A kick to the knee."},"KHAKI":{"p":"/ˈkɑː.ki/","s":"n./adj.","e":"[n.] A dull, yellowish-brown colour, the colour of dust.\n[n.] Khaki green, a dull green colour.\n[n.] A strong cloth of wool or cotton, often used for military or other uniforms.\n[adj.] Dust-coloured; of the colour of dust.","ex":""},"KING":{"p":"/kɪŋ/","s":"n./v.","e":"[n.] A male monarch; a man who heads a monarchy. If it's an absolute monarchy, then he is the supreme ruler of his nation.\n[n.] A powerful or majorly influential person.\n[n.] Something that has a preeminent position.\n[v.] To crown king, to make (a person) king.\n[v.] To rule over as king.\n[v.] To perform the duties of a king.","ex":"Henry VIII was the king of England from 1509 to 1547."},"KIOSK":{"p":"/ˈkiːˌɒsk/","s":"n.","e":"[n.] A small enclosed structure, often freestanding, open on one side or with a window, used as a booth to sell newspapers, cigarettes, etc.\n[n.] A similar unattended stand for the automatic dispensing of tickets, etc.\n[n.] A public telephone booth.","ex":""},"KILL":{"p":"/kɪl/","s":"n./v.","e":"[n.] The act of killing.\n[n.] Specifically, the death blow.\n[n.] The result of killing; that which has been killed.\n[v.] To put to death; to extinguish the life of.\n[v.] To render inoperative.\n[v.] To stop, cease or render void; to terminate.","ex":"The assassin liked to make a clean kill, and thus favored small arms over explosives."},"KISS":{"p":"/kɪs/","s":"v.","e":"[v.] To touch with the lips or press the lips against, usually to show love or affection or passion, or as part of a greeting.\n[v.] To (cause to) touch lightly or slightly; to come into contact.\n[v.] Of two or more people, to touch each other's lips together, usually to express love or affection or passion.","ex":"His ball kissed the black into the corner pocket."},"KINKY":{"p":"/ˈkɪŋ.ki/","s":"adj.","e":"[adj.] Full of kinks; liable to kink or curl.\n[adj.] Marked by unconventional sexual preferences or behavior, as fetishism, sadomasochism, and other sexual practices.\n[adj.] Queer; eccentric; crotchety.","ex":"kinky hair"},"KITCHEN":{"p":"/ˈkɪt͡ʃən/","s":"n./v.","e":"[n.] A room or area for preparing food.\n[n.] Cuisine.\n[n.] The nape of a person's hairline, often referring to its uncombed or \"nappy\" look.\n[v.] To do kitchen work; to prepare food.\n[v.] To embellish a basic food; to season, add condiments, etc.\n[v.] (by extension) To embellish; to dress up.","ex":""},"KIND":{"p":"/kaɪnd/","s":"n.","e":"[n.] A type, race or category; a group of entities that have common characteristics such that they may be grouped together.\n[n.] A makeshift or otherwise atypical specimen.\n[n.] One's inherent nature; character, natural disposition.","ex":"This is a strange kind of tobacco."},"KITTY":{"p":"/ˈkɪti/","s":"n.","e":"[n.] A kitten or young cat.\n[n.] (sometimes capitalized) A pet name for a cat.\n[n.] A money pool, as for a card game, or for shared expenses.","ex":"Aw, look at the kitty!"},"KNAVE":{"p":"/neɪv/","s":"n.","e":"[n.] A boy; especially, a boy servant.\n[n.] Any male servant; a menial.\n[n.] A tricky, deceitful fellow; a dishonest person.","ex":""},"KNACK":{"p":"/næk/","s":"n./v.","e":"[n.] A readiness in performance; aptness at doing something.\n[n.] A petty contrivance; a toy.\n[n.] Something performed, or to be done, requiring aptness and dexterity.\n[v.] To crack; to make a sharp, abrupt noise; to chink.\n[v.] To speak affectedly.","ex":""},"KNELL":{"p":"/nɛl/","s":"n./v.","e":"[n.] The sound of a bell knelling; a toll (particularly one signalling a death).\n[n.] A sign of the end or demise of something or someone.\n[v.] To ring a bell slowly, especially for a funeral; to toll.\n[v.] To signal or proclaim something (especially a death) by ringing a bell.\n[v.] To summon by, or as if by, ringing a bell.","ex":""},"KNEW":{"p":"/ˈnjuː/","s":"v.","e":"[v.] To perceive the truth or factuality of; to be certain of or that.\n[v.] To be aware of; to be cognizant of.\n[v.] To be acquainted or familiar with; to have encountered.","ex":"He knew something terrible was going to happen."},"KNELT":{"p":"/nɛlt/","s":"v.","e":"[v.] To rest on one's bent knees, sometimes only one; to move to such a position.\n[v.] To cause to kneel.\n[v.] To rest on (one's) knees","ex":"She knelt the doll to fit it into the box."},"KNIFE":{"p":"/naɪf/","s":"n./v.","e":"[n.] A utensil or a tool designed for cutting, consisting of a flat piece of hard material, usually steel or other metal (the blade), usually sharpened on one edge, attached to a handle. The blade may be pointed for piercing.\n[n.] A weapon designed with the aforementioned specifications intended for slashing and/or stabbing and too short to be called a sword. A dagger.\n[n.] Any blade-like part in a tool or a machine designed for cutting, such as that of a chipper.\n[v.] To cut with a knife.\n[v.] To use a knife to injure or kill by stabbing, slashing, or otherwise using the sharp edge of the knife as a weapon.\n[v.] To cut through as if with a knife.","ex":""},"KNIT":{"p":"/ˈnɪt/","s":"n./v.","e":"[n.] A knitted garment.\n[n.] A session of knitting.\n[v.] To turn thread or yarn into a piece of fabric by forming loops that are pulled through each other. This can be done by hand with needles or by machine.\n[v.] To join closely and firmly together.\n[v.] To become closely and firmly joined; become compacted.","ex":"The first generation knitted to order; the second still knits for its own use; the next leaves knitting to industrial manufacturers."},"KNOLL":{"p":"/nəʊl/","s":"n.","e":"[n.] A small mound or rounded hill.","ex":""},"KNOCK":{"p":"/nɒk/","s":"n./v.","e":"[n.] Sudden fatigue as a result of glycogen depletion from not having taken in enough nutrition.\n[n.] An abrupt rapping sound, as from an impact of a hard object against wood.\n[n.] A sharp impact.\n[n.] Criticism.\n[v.] To strike for admittance; to rap upon, as a door.\n[v.] To criticize verbally; to denigrate; to undervalue.","ex":"I heard a knock on my door."},"KNOWING":{"p":"/ˈnəʊɪŋ/","s":"v./n./adj.","e":"[v.] To perceive the truth or factuality of; to be certain of or that.\n[v.] To be aware of; to be cognizant of.\n[v.] To be acquainted or familiar with; to have encountered.\n[n.] The act or condition of having knowledge.\n[adj.] Possessing knowledge or understanding; intelligent.\n[adj.] Shrewd or showing clever awareness.","ex":"He knew something terrible was going to happen."},"KNEE":{"p":"/niː/","s":"n./v.","e":"[n.] In humans, the joint or the region of the joint in the middle part of the leg between the thigh and the shank.\n[n.] In the horse and allied animals, the carpal joint, corresponding to the wrist in humans.\n[n.] The part of a garment that covers the knee.\n[v.] To kneel to.\n[v.] To poke or strike with the knee.\n[v.] To move on the knees; to use the knees to move.","ex":"Penny was wearing a miniskirt, so she skinned her exposed knees when she fell."},"KNOWN":{"p":"/nəʊn/","s":"v./n./adj.","e":"[v.] To perceive the truth or factuality of; to be certain of or that.\n[v.] To be aware of; to be cognizant of.\n[v.] To be acquainted or familiar with; to have encountered.\n[n.] Any fact or situation which is known or familiar.\n[n.] A constant or variable the value of which is already determined.\n[adj.] Identified as a specific type; famous, renowned.","ex":"He knew something terrible was going to happen."},"KRILL":{"p":"/kɹɪl/","s":"n.","e":"[n.] Any of several small marine crustacean species of plankton in the order Euphausiacea in the class Malacostraca.","ex":""},"KOALA":{"p":"/koʊ.ˈɑː.lə/","s":"n.","e":"[n.] A tree-dwelling marsupial, Phascolarctos cinereus, that resembles a small bear with a broad head, large ears and sharp claws, mainly found in eastern Australia.","ex":""},"KNEEL":{"p":"/niːl/","s":"v.","e":"[v.] To rest on one's bent knees, sometimes only one; to move to such a position.\n[v.] To cause to kneel.\n[v.] To rest on (one's) knees","ex":"She knelt the doll to fit it into the box."},"LABEL":{"p":"/ˈleɪbəl/","s":"n./v.","e":"[n.] A small ticket or sign giving information about something to which it is attached or intended to be attached.\n[n.] A name given to something or someone to categorise them as part of a particular social group.\n[n.] A company that sells records.\n[v.] To put a label (a ticket or sign) on (something).\n[v.] (ditransitive) To give a label to (someone or something) in order to categorise that person or thing.\n[v.] To replace specific atoms by their isotope in order to track the presence or movement of this isotope through a reaction, metabolic pathway or cell.","ex":"Although the label priced this poster at three pounds, I got it for two."},"LACK":{"p":"/lak/","s":"n./v.","e":"[n.] A defect or failing; moral or spiritual degeneracy.\n[n.] A deficiency or need (of something desirable or necessary); an absence, want.\n[v.] To be without, to need, to require.\n[v.] To be short (of or for something).\n[v.] To be in want.","ex":"My life lacks excitement."},"LADLE":{"p":"/ˈleɪ.dəl/","s":"n./v.","e":"[n.] A deep-bowled spoon with a long, usually curved, handle.\n[n.] A container used in a foundry to transport and pour out molten metal.\n[n.] The float of a mill wheel; a ladle board.\n[v.] To pour or serve something with a ladle.","ex":"One man ladled molten steel into the shot sleeve."},"LADEN":{"p":"/ˈleɪdən/","s":"v./adj.","e":"[v.] To fill or load (related to cargo or a shipment).\n[v.] To weigh down, oppress, or burden.\n[v.] To use a ladle or dipper to remove something (generally water).\n[adj.] Weighed down with a load, burdened.\n[adj.] Heavy.\n[adj.] Oppressed.","ex":"to lade water out of a tub, or into a cistern"},"LAGER":{"p":"/ˈlɑːɡə/","s":"n./v.","e":"[n.] A type of beer, brewed using a bottom-fermenting yeast.\n[v.] To store (lager beer) at a low temperature for maturing and clarification.","ex":""},"LAMP":{"p":"/læmp/","s":"n./v.","e":"[n.] A device that generates heat, light or other radiation. Especially an electric light bulb.\n[n.] A device containing oil, burnt through a wick for illumination; an oil lamp.\n[n.] A piece of furniture holding one or more electric light sockets.\n[v.] To hit, clout, belt, wallop.\n[v.] To hunt at night using a lamp; see lamping.\n[v.] To hang out or chill; to do nothing in particular.","ex":""},"LAID":{"p":"/leɪd/","s":"adj./v.","e":"[adj.] (of paper) Marked with parallel lines, as if ribbed, from wires in the mould.\n[v.] To place down in a position of rest, or in a horizontal position.\n[v.] To cause to subside or abate.\n[v.] To prepare (a plan, project etc.); to set out, establish (a law, principle).\n[v.] To don or put on (tefillin (phylacteries)).","ex":"A shower of rain lays the dust."},"LAND":{"p":"/lænd/","s":"n./v./adj.","e":"[n.] The part of Earth which is not covered by oceans or other bodies of water.\n[n.] Real estate or landed property; a partitioned and measurable area which is owned and on which buildings can be erected.\n[n.] A country or region.\n[v.] To descend to a surface, especially from the air.\n[v.] To alight, to descend from a vehicle.\n[v.] To come into rest.","ex":"Most insects live on land."},"LANCE":{"p":"/lɑːns/","s":"n./v.","e":"[n.] A weapon of war, consisting of a long shaft or handle and a steel blade or head; a spear carried by horsemen.\n[n.] A wooden spear, sometimes hollow, used in jousting or tilting, designed to shatter on impact with the opposing knight’s armour.\n[n.] A spear or harpoon used by whalers and fishermen.\n[v.] To pierce with a lance, or with any similar weapon.\n[v.] To open with a lancet; to pierce\n[v.] To throw in the manner of a lance; to lanch.","ex":"Seized the due victim, and with fury lanced Her back. Dryden."},"LANKY":{"p":"/ˈlæŋk.i/","s":"adj.","e":"[adj.] Tall, slim, and rather ungraceful or awkward.","ex":""},"LABOR":{"p":"/ˈleɪ.bɚ/","s":"n./v.","e":"[n.] Effort expended on a particular task; toil, work.\n[n.] That which requires hard work for its accomplishment; that which demands effort.\n[n.] Workers in general; the working class, the workforce; sometimes specifically the labour movement, organised labour.\n[v.] To toil, to work.\n[v.] To belabour, to emphasise or expand upon (a point in a debate, etc).\n[v.] To be oppressed with difficulties or disease; to do one's work under conditions which make it especially hard or wearisome; to move slowly, as against opposition, or under a burden.","ex":"I think we've all got the idea. There's no need to labour the point."},"LANE":{"p":"/leɪn/","s":"n.","e":"[n.] (used in street names) A road, street, or similar thoroughfare.\n[n.] A narrow passageway between fences, walls, hedges or trees.\n[n.] A narrow road, as in the country.","ex":""},"KNEAD":{"p":"/niːd/","s":"n./v.","e":"[n.] The act of kneading something.\n[v.] To work and press into a mass, usually with the hands; especially, to work, as by repeated pressure with the knuckles, into a well mixed mass, the materials of bread, cake, etc.\n[v.] To treat or form as if by kneading; to beat.\n[v.] (of cats) To make an alternating pressing motion with the two front paws.","ex":""},"LADY":{"p":"/ˈleɪdi/","s":"n.","e":"[n.] An aristocratic title for a woman; the wife of a lord and/or a woman who holds the position in her own right; a title for a peeress, the wife of a peer or knight, and the daughters and daughters-in-law of certain peers.\n[n.] A high priestess.\n[n.] The mistress of a household.\n[n.] A woman of breeding or higher class, a woman of authority.\n[n.] The feminine of lord.","ex":"Sir John Smith and Lady Smith."},"LAPEL":{"p":"/ləˈpɛl/","s":"n.","e":"[n.] Each of the two triangular pieces of cloth on the front of a jacket or coat that are folded back below the throat, leaving a triangular opening between.","ex":""},"LAPSE":{"p":"/læps/","s":"n./v.","e":"[n.] A temporary failure; a slip.\n[n.] A decline or fall in standards.\n[n.] A pause in continuity.\n[v.] To fall away gradually; to subside.\n[v.] To fall into error or heresy.\n[v.] To slip into a bad habit that one is trying to avoid.","ex":""},"LAKE":{"p":"/leɪk/","s":"n.","e":"[n.] A small stream of running water; a channel for water; a drain.\n[n.] A large, landlocked stretch of water.\n[n.] A large amount of liquid; as, a wine lake.","ex":""},"LASER":{"p":"/ˈleɪz.ə(ɹ)/","s":"n./v.","e":"[n.] A device that produces a monochromatic, coherent beam of light.\n[n.] A beam of light produced by such a device; a laser beam.\n[n.] A laser printer.\n[v.] To cut with a laser\n[v.] To throw with laser-like precision","ex":""},"LARGE":{"p":"/ˈlɑːd͡ʒ/","s":"n./adj./adv.","e":"[n.] An old musical note, equal to two longas, four breves, or eight semibreves.\n[n.] Liberality, generosity.\n[n.] (plural: large) A thousand dollars/pounds.\n[adj.] Of considerable or relatively great size or extent.\n[adj.] Abundant; ample.\n[adj.] Full in statement; diffuse; profuse.","ex":"Getting a car tricked out like that will cost you 50 large."},"LARGELY":{"p":"[ˈlaːdʒ.li]","s":"adv.","e":"[adv.] In a widespread or large manner.\n[adv.] For the most part; mainly or chiefly.\n[adv.] On a large scale; amply.","ex":"They were largely successful in their efforts."},"LASSO":{"p":"/læsˈuː/","s":"n./v.","e":"[n.] A long rope with a sliding loop on one end, generally used in ranching to catch cattle and horses.\n[n.] An image-editing function allowing the user to capture an irregularly-shaped object by drawing an approximate outline.\n[v.] To catch with a lasso.","ex":""},"KNOW":{"p":"/nəʊ/","s":"n./v.","e":"[n.] Knowledge; the state of knowing.\n[v.] To perceive the truth or factuality of; to be certain of or that.\n[v.] To be aware of; to be cognizant of.\n[v.] To be acquainted or familiar with; to have encountered.","ex":"He knew something terrible was going to happen."},"LATE":{"p":"/leɪt/","s":"n./adj./adv.","e":"[n.] A shift (scheduled work period) that takes place late in the day or at night.\n[adj.] Near the end of a period of time.\n[adj.] Specifically, near the end of the day.\n[adj.] (usually not comparable) Associated with the end of a period.\n[adv.] After a deadline has passed, past a designated time.\n[adv.] Formerly, especially in the context of service in a military unit.","ex":"It was late in the evening when we finally arrived."},"LATER":{"p":"/ˈleɪtə/","s":"adj./adv./int.","e":"[adj.] Near the end of a period of time.\n[adj.] Specifically, near the end of the day.\n[adj.] (usually not comparable) Associated with the end of a period.\n[adv.] After a deadline has passed, past a designated time.\n[adv.] Formerly, especially in the context of service in a military unit.\n[adv.] Not long ago; just now.","ex":"It was late in the evening when we finally arrived."},"LAST":{"p":"/last/","s":"adj./adv.","e":"[adj.] Final, ultimate, coming after all others of its kind.\n[adj.] Most recent, latest, last so far.\n[adj.] Farthest of all from a given quality, character, or condition; most unlikely, or least preferable.\n[adv.] Most recently.\n[adv.] (sequence) after everything else; finally","ex":"“Eyes Wide Shut” was the last film to be directed by Stanley Kubrick."},"LATTE":{"p":"/ˈlæ.teɪ/","s":"n.","e":"[n.] A drink of coffee made from espresso and steamed milk, generally topped with foam.\n[n.] A similar drink, where the espresso is replaced with some other flavoring ingredient such as chai, maté or matcha (green tea).","ex":""},"LATHE":{"p":"/leɪð/","s":"v.","e":"[v.] To invite; bid; ask.","ex":""},"LATTER":{"p":"/ˈlæt̬.əɹ/","s":"adj.","e":"[adj.] Relating to or being the second of two items.\n[adj.] Near (or nearer) to the end.\n[adj.] In the past, but close (or closer) to the present time.","ex":""},"LARVA":{"p":"/ˈlɑː.və/","s":"n.","e":"[n.] An early stage of growth for some insects and amphibians, in which after hatching from their egg, insects are wingless and resemble a caterpillar or grub, and amphibians lack limbs and resemble fish.\n[n.] An animal in the aforementioned stage.\n[n.] A form of a recently born or hatched animal that is quite different from its adult stage.","ex":""},"LAUNCH":{"p":"/lɔːnt͡ʃ/","s":"n./v.","e":"[n.] The movement of a vessel from land into the water; especially, the sliding on ways from the stocks on which it is built. (Compare: to splash a ship.)\n[n.] The act or fact of launching (a ship/vessel, a project, a new book, etc.).\n[n.] An event held to celebrate the launch of a ship/vessel, project, a new book, etc.; a launch party.\n[v.] To throw (a projectile such as a lance, dart or ball); to hurl; to propel with force.\n[v.] To pierce with, or as with, a lance.\n[v.] To cause (a vessel) to move or slide from the land or a larger vessel into the water; to set afloat.","ex":"book launch"},"LAWYER":{"p":"/ˈlɔɪ.ə(ɹ)/","s":"n./v.","e":"[n.] A professional person qualified (as by a law degree or bar exam) and authorized to practice law, i.e. represent parties in lawsuits or trials and give legal advice.\n[n.] (by extension) A legal layman who argues points of law.\n[n.] The burbot.\n[v.] To practice law.\n[v.] To perform, or attempt to perform, the work of a lawyer.\n[v.] To make legalistic arguments.","ex":"A lawyer's time and advice are his stock in trade. - aphorism often credited to Abraham Lincoln, but without attestation"},"LASTING":{"p":"/ˈlastɪŋ/","s":"v./n./adj.","e":"[v.] To perform, carry out.\n[v.] To endure, continue over time.\n[v.] To hold out, continue undefeated or entire.\n[v.] To shape with a last; to fasten or fit to a last; to place smoothly on a last.\n[n.] The action or state of persisting; the time during which something or someone persists.\n[n.] A durable woollen material formerly used for women's shoes.","ex":"Summer seems to last longer each year."},"LATCH":{"p":"/lætʃ/","s":"v.","e":"[v.] To close or lock as if with a latch.\n[v.] To catch; lay hold of.","ex":""},"LAYER":{"p":"/leɪə/","s":"n./v.","e":"[n.] A single thickness of some material covering a surface.\n[n.] A (usually) horizontal deposit; a stratum.\n[n.] One of the items in a hierarchy.\n[v.] To cut or divide (something) into layers\n[v.] To arrange (something) in layers.","ex":"After the first coat of paint dried, he applied another layer."},"LATEST":{"p":"/ˈleɪt.ɪst/","s":"adj./adv./n.","e":"[adj.] Near the end of a period of time.\n[adj.] Specifically, near the end of the day.\n[adj.] (usually not comparable) Associated with the end of a period.\n[adv.] After a deadline has passed, past a designated time.\n[adv.] Formerly, especially in the context of service in a military unit.\n[adv.] Not long ago; just now.","ex":"It was late in the evening when we finally arrived."},"LEAD":{"p":"/lɛd/","s":"n./v.","e":"[n.] A heavy, pliable, inelastic metal element, having a bright, bluish color, but easily tarnished; both malleable and ductile, though with little tenacity. It is easily fusible, forms alloys with other metals, and is an ingredient of solder and type metal. Atomic number 82, symbol Pb (from Latin plumbum).\n[n.] A plummet or mass of lead attached to a line, used in sounding depth at sea or to estimate velocity in knots.\n[n.] A thin strip of type metal, used to separate lines of type in printing.\n[v.] To cover, fill, or affect with lead\n[v.] To place leads between the lines of.","ex":"continuous firing leads the grooves of a rifle."},"LATEX":{"p":"/ˈleɪtɛks/","s":"n.","e":"[n.] A clear liquid believed to be a component of a humour or other bodily fluid (esp. plasma and lymph)\n[n.] The milky sap of several trees that coagulates on exposure to air; used to make rubber.\n[n.] An emulsion of rubber in water, used in adhesives and the like.","ex":""},"LEADER":{"p":"/ˈlidɚ/","s":"n.","e":"[n.] Any person that leads or directs\n[n.] An animal that leads\n[n.] Someone or something that leads or conducts","ex":""},"LEACH":{"p":"/liːtʃ/","s":"n.","e":"[n.] A quantity of wood ashes, through which water passes, and thus imbibes the alkali.\n[n.] A tub or vat for leaching ashes, bark, etc.\n[n.] A jelly-like sweetmeat popular in the fifteenth century.\n[n.] An aquatic blood-sucking annelid of class Hirudinea, especially Hirudo medicinalis.\n[n.] A person who derives profit from others in a parasitic fashion.\n[n.] A glass tube designed for drawing blood from damaged tissue by means of a vacuum.","ex":"1670 Hannah Woolley The Queen-like Closet, Or, Rich Cabinet https//en.m.wikipedia.org/wiki/The_Queen-Like_Closet \"To make Leach and to colour it\""},"LEAF":{"p":"/liːf/","s":"n./v.","e":"[n.] The usually green and flat organ that represents the most prominent feature of most vegetative plants.\n[n.] Anything resembling the leaf of a plant.\n[n.] A sheet of any substance beaten or rolled until very thin.\n[v.] To produce leaves; put forth foliage.\n[v.] To divide (a vegetable) into separate leaves.","ex":"gold leaf"},"LEAGUE":{"p":"/liːɡ/","s":"n./v.","e":"[n.] A group or association of cooperating members.\n[n.] An organization of sports teams which play against one another for a championship.\n[n.] (often in the negative) A class or type of people or things that are evenly matched or on the same level.\n[v.] To form an association; to unite in a league or confederacy; to combine for mutual support.\n[n.] A version of rugby football, played between two teams of thirteen.","ex":"the League of Nations"},"LEAFY":{"p":"/ˈliːfi/","s":"adj.","e":"[adj.] Covered with leaves\n[adj.] Containing much foliage\n[adj.] In the form of leaves (of some material)","ex":"leafy trees"},"LEAKY":{"p":"/ˈliːki/","s":"adj.","e":"[adj.] Having leaks; not fully sealed.","ex":"The leaky bucket only dripped one drop at a time, but by the time I got back to the house it was half empty."},"LEAN":{"p":"/liːn/","s":"n./v.","e":"[n.] (of an object taller than its width and depth) An inclination away from the vertical.\n[v.] To incline, deviate, or bend, from a vertical position; to be in a position thus inclining or deviating.\n[v.] To incline in opinion or desire; to conform in conduct; often with to, toward, etc.\n[v.] Followed by against, on, or upon: to rest or rely, for support, comfort, etc.","ex":"The trees had various leans toward gaps in the canopy."},"LAUGH":{"p":"/laːf/","s":"n./v.","e":"[n.] An expression of mirth particular to the human species; the sound heard in laughing; laughter.\n[n.] Something that provokes mirth or scorn.\n[n.] A fun person.\n[v.] To show mirth, satisfaction, or derision, by peculiar movement of the muscles of the face, particularly of the mouth, causing a lighting up of the face and eyes, and usually accompanied by the emission of explosive or chuckling sounds from the chest and throat; to indulge in laughter.\n[v.] To be or appear cheerful, pleasant, mirthful, lively, or brilliant; to sparkle; to sport.\n[v.] (followed by \"at\") To make an object of laughter or ridicule; to make fun of; to deride; to mock.","ex":"His deep laughs boomed through the room."},"LEARN":{"p":"/lɜːn/","s":"n./v.","e":"[n.] The act of learning something\n[v.] To acquire, or attempt to acquire knowledge or an ability to do something.\n[v.] To attend a course or other educational activity.\n[v.] To gain knowledge from a bad experience so as to improve.","ex":"learn from one's mistakes"},"LEAPT":{"p":"/lɛpt/","s":"v.","e":"[v.] To jump.\n[v.] To pass over by a leap or jump.\n[v.] To copulate with (a female beast); to cover.","ex":"to leap a wall or a ditch"},"LEASE":{"p":"/liːs/","s":"v.","e":"[v.] (chiefly dialectal) To gather.\n[v.] (chiefly dialectal) To pick, select, pick out; to pick up.\n[v.] (chiefly dialectal) To glean.","ex":""},"LECTURE":{"p":"/ˈlɛk.t͡ʃə/","s":"n./v.","e":"[n.] A spoken lesson or exposition, usually delivered to a group.\n[n.] (by extension) a class that primarily consists of a (weekly or other regularly held) lecture (as in sense 1) [usually at college or university]\n[n.] A berating or scolding.\n[v.] To teach (somebody) by giving a speech on a given topic.\n[v.] To preach, to berate, to scold.","ex":"During class today the professor delivered an interesting lecture."},"LEAVES":{"p":"/liːvz/","s":"n./v.","e":"[n.] The usually green and flat organ that represents the most prominent feature of most vegetative plants.\n[n.] Anything resembling the leaf of a plant.\n[n.] A sheet of any substance beaten or rolled until very thin.\n[v.] To have a consequence or remnant.\n[v.] To depart; to separate from.\n[v.] To transfer something.","ex":"gold leaf"},"LEANT":{"p":"/ˈlɛnt/","s":"v.","e":"[v.] To incline, deviate, or bend, from a vertical position; to be in a position thus inclining or deviating.\n[v.] To incline in opinion or desire; to conform in conduct; often with to, toward, etc.\n[v.] Followed by against, on, or upon: to rest or rely, for support, comfort, etc.","ex":"She leaned out of the window."},"LEASH":{"p":"/liːʃ/","s":"n./v.","e":"[n.] A strap, cord or rope with which to restrain an animal, often a dog.\n[n.] A brace and a half; a tierce.\n[n.] A set of three; three creatures of any kind, especially greyhounds, foxes, bucks, and hares; hence, the number three in general.\n[v.] To fasten or secure with a leash.\n[v.] To curb, restrain","ex":""},"LEAVE":{"p":"/liːv/","s":"v.","e":"[v.] To have a consequence or remnant.\n[v.] To depart; to separate from.\n[v.] To transfer something.","ex":""},"LEFTY":{"p":"/ˈlɛfti/","s":"n./adj.","e":"[n.] One who is left-handed.\n[n.] One who has left-wing political views.\n[n.] One's left testicle.\n[adj.] Left-handed.\n[adj.] Intended for left-handed use.\n[adj.] Left-wing.","ex":"I'll bet my lefty he won't show up for work today."},"LEATHER":{"p":"/ˈlɛðə/","s":"n./v./adj.","e":"[n.] A tough material produced from the skin of animals, by tanning or similar process, used e.g. for clothing.\n[n.] A piece of the above used for polishing.\n[n.] A cricket ball or football.\n[v.] To cover with leather.\n[v.] To strike forcefully.\n[v.] To beat with a leather belt or strap.","ex":"He leathered the ball all the way down the street."},"LEECH":{"p":"/liːtʃ/","s":"n./v.","e":"[n.] An aquatic blood-sucking annelid of class Hirudinea, especially Hirudo medicinalis.\n[n.] A person who derives profit from others in a parasitic fashion.\n[n.] A glass tube designed for drawing blood from damaged tissue by means of a vacuum.\n[v.] To apply a leech medicinally, so that it sucks blood from the patient.\n[v.] To drain (resources) without giving back.","ex":"Bert leeched hundreds of files from the BBS, but never uploaded anything in return."},"LEGGY":{"p":"/ˈlɛɡi/","s":"adj.","e":"[adj.] (chiefly of a woman) Having long, attractive legs; long-legged.\n[adj.] (chiefly of a woman) Exposing the bare or pantyhose-clad legs, especially the thighs.\n[adj.] Taller or longer than usual.","ex":"Fred preferred leggy blondes."},"LEGAL":{"p":"/ˈliː.ɡəl/","s":"n./adj.","e":"[n.] The legal department of a company.\n[n.] Paper in sheets 8½ in × 14 in (215.9 mm × 355.6 mm).\n[n.] A spy who is attached to, and ostensibly employed by, an embassy, military outpost, etc.\n[adj.] Relating to the law or to lawyers.\n[adj.] Having its basis in the law.\n[adj.] Being allowed or prescribed by law.","ex":"Legal wants this in writing."},"LEMON":{"p":"/ˈlɛmən/","s":"n./v./adj.","e":"[n.] A yellowish citrus fruit.\n[n.] A semitropical evergreen tree, Citrus limon, that bears such fruits.\n[n.] A taste or flavour/flavor of lemons.\n[v.] To flavour with lemon.\n[adj.] Containing or having the flavour/flavor and/or scent of lemons.\n[adj.] Of the pale yellow colour/color of lemons.","ex":"You can start the vegetables cooking while you are lemoning the fish."},"LEERY":{"p":"/ˈlɪə.ɹi/","s":"adj.","e":"[adj.] Cautious, suspicious, wary, hesitant, or nervous about something; having reservations or concerns.","ex":"Since he was bitten by a dog when he was young, he has always been leery of animals."},"LEMUR":{"p":"/ˈliːmə(ɹ)/","s":"n.","e":"[n.] Any strepsirrhine primate of the infraorder Lemuriformes, superfamily Lemuroidea, native only to Madagascar and some surrounding islands.\n[n.] Any of the genus Lemur, represented by the ring-tailed lemur (Lemur catta).\n[n.] A loris (Lemur tardigradus, now Loris tardigradus), predating the 10th edition of Systema Naturæ.","ex":""},"LENDING":{"p":"","s":"v./n./adj.","e":"[v.] To allow to be used by someone temporarily, on condition that it or its equivalent will be returned.\n[v.] To make a loan.\n[v.] To be suitable or applicable, to fit.\n[n.] The action of, or an instance of the action of the verb to lend.\n[adj.] That lends.","ex":"I lent her 10 euros to pay for the train tickets, and she paid me back the next day."},"LEAST":{"p":"/list/","s":"n./adv.","e":"[n.] Something of the smallest possible extent; an indivisible unit.\n[adv.] Used for forming superlatives of adjectives, especially those that do not form the superlative by adding -est.\n[adv.] In the smallest or lowest degree; in a degree below all others.","ex":"It was the least surprising thing."},"LESS":{"p":"/lɛs/","s":"n./v./adv./prep.","e":"[n.] A smaller amount or quantity.\n[v.] To make less; to lessen.\n[adv.] To a smaller extent or degree.\n[prep.] Minus; not including","ex":"I have less to do today than yesterday."},"LESSON":{"p":"/ˈlɛsn̩/","s":"n./v.","e":"[n.] A section of learning or teaching into which a wider learning content is divided.\n[n.] A learning task assigned to a student; homework.\n[n.] Something learned or to be learned.\n[v.] To give a lesson to; to teach.","ex":"In our school a typical working week consists of around twenty lessons and ten hours of related laboratory work."},"LETTER":{"p":"/-ɾə(ɹ)/","s":"n./v.","e":"[n.] A symbol in an alphabet.\n[n.] A written or printed communication, generally longer and more formal than a note.\n[n.] The literal meaning of something, as distinguished from its intended and remoter meaning (often contrasted with the spirit).\n[v.] To print, inscribe, or paint letters on something.\n[v.] (scholastic) To earn a varsity letter (award).\n[n.] An identifying initial of the academic institution that is awarded to a member of a varsity team. It is made from structured cloth, and intended to be sewn to a piece of clothing such as a varsity sweater or varsity jacket.","ex":"There are twenty-six letters in the English alphabet."},"LEDGE":{"p":"/lɛdʒ/","s":"n./v.","e":"[n.] A shelf on which articles may be laid; also, that which resembles such a shelf in form or use, as a projecting ridge or part, or a molding or edge in joinery.\n[n.] A shelf, ridge, or reef, of rocks.\n[n.] A layer or stratum.\n[v.] To cause to have, or to develop, a ledge (during mining, canal construction, building, etc).","ex":""},"LEVEL":{"p":"/ˈlɛv.əl/","s":"n./v./adj.","e":"[n.] A tool for finding whether a surface is level, or for creating a horizontal or vertical line of reference.\n[n.] A distance relative to a given reference elevation.\n[n.] Degree or amount.\n[v.] To adjust so as to make as flat or perpendicular to the ground as possible.\n[v.] To destroy by reducing to ground level; to raze.\n[v.] To progress to the next level.","ex":"Hand me the level so I can tell if this is correctly installed."},"LEND":{"p":"/lɛnd/","s":"n.","e":"[n.] The lumbar region; loin.\n[n.] (of a person or animal) The loins; flank; buttocks.","ex":""},"LIBEL":{"p":"/ˈlaɪbəl/","s":"n./v.","e":"[n.] A written or pictorial false statement which unjustly seeks to damage someone's reputation.\n[n.] The act or crime of displaying such a statement publicly.\n[n.] Any defamatory writing; a lampoon; a satire.\n[v.] To defame someone, especially in a manner that meets the legal definition of libel.\n[v.] To proceed against (a ship, goods, etc.) by filing a libel.","ex":"He libelled her when he published that."},"LIBERAL":{"p":"/ˈlɪbɹəl/","s":"n./adj.","e":"[n.] One with liberal views, supporting individual liberty (see Wikipedia's article on Liberalism).\n[n.] Someone left-wing; one with a left-wing ideology.\n[n.] A supporter of any of several liberal parties.\n[adj.] (now rare outside set phrases) Pertaining to those arts and sciences the study of which is considered to provide general knowledge, as opposed to vocational/occupational, technical or mechanical training.\n[adj.] Generous; willing to give unsparingly.\n[adj.] Ample, abundant; generous in quantity.","ex":"1983, David Leslie Wagner, The Seven liberal arts in the Middle Ages"},"LIBRARY":{"p":"/ˈlaɪbɹi/","s":"n.","e":"[n.] An institution which holds books and/or other forms of media for use by the public or qualified people often lending them out, as well as providing various other services for its users.\n[n.] (by extension) Any institution that lends out its goods for use by the public or a community.\n[n.] A collection of books or other forms of stored information.","ex":""},"LIFE":{"p":"/laɪf/","s":"n.","e":"[n.] The state of organisms preceding their death, characterized by biological processes such as metabolism and reproduction and distinguishing them from inanimate objects; the state of being alive and living.\n[n.] The animating principle or force that keeps an inorganic thing or concept metaphorically alive (dynamic, relevant, etc) and makes it a \"living document\", \"living constitution\", etc.\n[n.] Lifeforms, generally or collectively.","ex":"Having experienced both, the vampire decided that he preferred (un)death to life.  He gave up on life."},"LIABLE":{"p":"/ˈlaɪ̯əbəl/","s":"adj.","e":"[adj.] Bound or obliged in law or equity; responsible; answerable.\n[adj.] Subject; susceptible.\n[adj.] Exposed to a certain contingency or causality, more or less probable.","ex":"1748. David Hume. Enquiries concerning the human understanding and concerning the principles of moral. London: Oxford University Press, 1973. § 34."},"LEGEND":{"p":"/ˈlɛdʒ.ənd/","s":"n./v.","e":"[n.] An unrealistic story depicting past events.\n[n.] A person related to a legend or legends.\n[n.] A key to the symbols and color codes on a map, chart, etc.\n[v.] To tell or narrate; to recount.","ex":"According to the legend on the map, that building is a school."},"LIFETIME":{"p":"/ˈlaɪftaɪm/","s":"n.","e":"[n.] The duration of the life of someone or something.\n[n.] A long period of time.","ex":"I've been waiting a lifetime for a train."},"LEPER":{"p":"","s":"n.","e":"[n.] A person who has leprosy.\n[n.] A person who is shunned; a pariah.","ex":""},"LIKEWISE":{"p":"/ˈlaɪkˌwaɪz/","s":"adv.","e":"[adv.] (manner) In a similar manner.\n[adv.] Also; moreover; too.\n[adv.] The same to you; used as a response.","ex":"Public transportation is virtually inaccessible in this country; likewise, its hospitals are also not very user-friendly."},"LIFT":{"p":"/lɪft/","s":"n./v.","e":"[n.] An act of lifting or raising.\n[n.] The act of transporting someone in a vehicle; a ride; a trip.\n[n.] Mechanical device for vertically transporting goods or people between floors in a building; an elevator.\n[v.] To raise or rise.\n[v.] To steal.\n[v.] To source directly without acknowledgement; to plagiarise.","ex":"He gave me a lift to the bus station."},"LIMBO":{"p":"/ˈlɪmbəʊ/","s":"n.","e":"[n.] (Roman Catholic theology, since circa 400 A.D.) The place where innocent souls exist temporarily until they can enter heaven, notably those of the saints who died before the advent of Christ (limbus patruum) and those of unbaptized but innocent children (limbus infantum).\n[n.] (by extension, since the 16th century) Any in-between place, state or condition of neglect or oblivion which results in an unresolved status, delay or deadlock.","ex":"My application has been stuck in bureaucratic limbo for two weeks."},"LIMIT":{"p":"/ˈlɪmt/","s":"n./adj.","e":"[n.] A restriction; a bound beyond which one may not go.\n[n.] A value to which a sequence converges. Equivalently, the common value of the upper limit and the lower limit of a sequence: if the upper and lower limits are different, then the sequence has no limit (i.e., does not converge).\n[n.] Any of several abstractions of this concept of limit.\n[adj.] Being a fixed limit game.","ex":"There are several existing limits to executive power."},"LILAC":{"p":"/ˈlaɪlək/","s":"n./adj.","e":"[n.] A large shrub of the genus Syringa, especially Syringa vulgaris, bearing white, pale-pink or purple flowers.\n[n.] A flower of the lilac shrub.\n[n.] (color) A pale purple color, the color of some lilac flowers.\n[adj.] Having a pale purple colour.","ex":""},"LINGO":{"p":"/ˈlɪŋ.ɡəʊ/","s":"n.","e":"[n.] Language, especially language peculiar to a particular group, field, or region; jargon or a dialect.","ex":""},"LINK":{"p":"/lɪŋk/","s":"n./v.","e":"[n.] Some text or a graphic in an electronic document that can be activated to display another document or trigger an action.\n[n.] (by extension) An address, URL, or program that defines a hyperlink's function.\n[n.] A connection between places, people, events, things, or ideas.\n[n.] One element of a chain or other connected series.\n[n.] The connection between buses or systems.\n[v.] To connect two or more things.","ex":"Click the hyperlink to go to the next page."},"LINE":{"p":"/laɪn/","s":"n./v.","e":"[n.] A path through two or more points (compare ‘segment’); a continuous mark, including as made by a pen; any path, curved or straight.\n[n.] A rope, cord, string, or thread, of any thickness.\n[n.] A hose or pipe, of any size.\n[v.] To place (objects) into a line (usually used with \"up\"); to form into a line; to align.\n[v.] To place persons or things along the side of for security or defense; to strengthen by adding; to fortify.\n[v.] To form a line along.","ex":"The arrow descended in a curved line."},"LINEN":{"p":"/ˈlɪnɪn/","s":"n./adj.","e":"[n.] Thread or cloth made from flax fiber.\n[n.] Domestic textiles, such as tablecloths, bedding, towels, underclothes, etc., that are made of linen or linen-like fabrics of cotton or other fibers; linens.\n[n.] A light beige colour, like that of linen cloth undyed.\n[adj.] Made from linen cloth or thread.\n[adj.] Having the colour linen, light beige.","ex":"She put the freshly cleaned linens into the linen closet."},"LITTLE":{"p":"/ˈlɪ.ɾɫ̩/","s":"n./adj./adv./pron.","e":"[n.] A small amount.\n[adj.] Small in size.\n[adj.] Insignificant, trivial.\n[adj.] Very young.\n[adv.] Not much.\n[adv.] Not at all.","ex":"Can I try a little of that sauce?"},"LIVID":{"p":"/ˈlɪvɪd/","s":"adj.","e":"[adj.] Having a dark, bluish appearance.\n[adj.] Pale, pallid.\n[adj.] So angry that one turns pale; very angry; furious.","ex":""},"LIST":{"p":"/lɪst/","s":"n./v.","e":"[n.] A strip of fabric, especially from the edge of a piece of cloth.\n[n.] Material used for cloth selvage.\n[n.] A register or roll of paper consisting of a compilation or enumeration of a set of possible items; the compilation or enumeration itself.\n[v.] To create or recite a list.\n[v.] To place in listings.\n[v.] To sew together, as strips of cloth, so as to make a show of colours, or to form a border.","ex":""},"LISTEN":{"p":"/ˈlɪs.ən/","s":"n./v.","e":"[n.] An instance of listening.\n[v.] To pay attention to a sound or speech.\n[v.] To expect or wait for a sound, such as a signal.\n[v.] To accept advice or obey instruction; to agree or assent.","ex":"Give the motor a listen and tell me if it sounds off."},"LIVING":{"p":"/ˈlɪvɪŋ/","s":"v./n./adj.","e":"[v.] To be alive; to have life.\n[v.] To have permanent residence somewhere, to inhabit, to reside.\n[v.] To survive; to persevere; to continue.\n[n.] The state of being alive.\n[n.] (plural, with \"the\", a demonstrative, or a possessive) Those who are alive.\n[n.] Financial means; a means of maintaining life; livelihood","ex":"He's not expected to live for more than a few months."},"LLAMA":{"p":"/ˈlɑː.mə/","s":"n.","e":"[n.] A South American mammal of the camel family, Lama glama, used as a domestic beast of burden and a source of wool and meat.","ex":""},"LOAD":{"p":"/ləʊd/","s":"n./v.","e":"[n.] A burden; a weight to be carried.\n[n.] A worry or concern to be endured, especially in the phrase a load off one's mind.\n[n.] A certain number of articles or quantity of material that can be transported or processed at one time.\n[v.] To put a load on or in (a means of conveyance or a place of storage).\n[v.] To place in or on a conveyance or a place of storage.\n[v.] To put a load on something.","ex":"I struggled up the hill with the heavy load in my rucksack."},"LINER":{"p":"/ˈlaɪnə/","s":"n.","e":"[n.] Someone who fits a lining to something.\n[n.] A removable cover or lining\n[n.] The pamphlet which is contained inside an album of music or movie","ex":"1973, A good liner has a pretty shrewd idea of the value of the painting he is treating and usually charges accordingly. — Kyril Bonfiglioli, Don't Point That Thing at Me (Penguin 2001, p. 41)"},"LIVER":{"p":"/ˈlɪvə/","s":"n./adj.","e":"[n.] A large organ in the body that stores and metabolizes nutrients, destroys toxins and produces bile. It is responsible for thousands of biochemical reactions.\n[n.] This organ, as taken from animals used as food.\n[n.] A dark brown colour, tinted with red and gray, like the colour of liver.\n[adj.] Of the colour of liver (dark brown, tinted with red and gray).","ex":"Steve Jobs is a famous liver transplant recipient."},"LOAN":{"p":"/ləʊn/","s":"n./v.","e":"[n.] An act or instance of lending, an act or instance of granting something for temporary use.\n[n.] A sum of money or other property that a natural or legal person borrows from another with the condition that it be returned or repaid over time or at a later date (sometimes with interest).\n[n.] The contract and array of legal or ethical obligations surrounding a loan.\n[v.] To lend (something) to (someone).","ex":"Because of the loan that John made to me, I was able to pay my tuition for the upcoming semester."},"LOBBY":{"p":"/lɒbi/","s":"n./v.","e":"[n.] An entryway or reception area; vestibule; passageway; corridor.\n[n.] That part of a hall of legislation not appropriated to the official use of the assembly.\n[n.] A class or group of people who try to influence public officials; collectively, lobbyists.\n[v.] To attempt to influence (a public official or decision-maker) in favor of a specific opinion or cause.","ex":"I had to wait in the lobby for hours before seeing the doctor."},"LIPID":{"p":"/ˈlɪpɪd/","s":"n.","e":"[n.] Any of a group of organic compounds including the fats, oils, waxes, sterols, and triglycerides. Lipids are characterized by being insoluble in water, and account for most of the fat present in the human body.","ex":""},"LOCATE":{"p":"/ləʊˈkeɪt/","s":"v.","e":"[v.] To place; to set in a particular spot or position.\n[v.] To find out where something is located.\n[v.] To designate the site or place of; to define the limits of (Note: the designation may be purely descriptive: it need not be prescriptive.)","ex":"The council must locate the new hospital"},"LITHE":{"p":"/laɪð/","s":"v.","e":"[v.] To go.","ex":""},"LOCATED":{"p":"/ləʊˈkeɪtɪd/","s":"v.","e":"[v.] To place; to set in a particular spot or position.\n[v.] To find out where something is located.\n[v.] To designate the site or place of; to define the limits of (Note: the designation may be purely descriptive: it need not be prescriptive.)","ex":"The council must locate the new hospital"},"LOAMY":{"p":"","s":"adj.","e":"[adj.] Consisting of loam; partaking of the nature of loam; resembling loam.","ex":""},"LOADING":{"p":"/ˈləʊ.dɪŋ/","s":"v./n.","e":"[v.] To put a load on or in (a means of conveyance or a place of storage).\n[v.] To place in or on a conveyance or a place of storage.\n[v.] To put a load on something.\n[n.] The process by which something is loaded.\n[n.] A load, especially in the engineering and electrical engineering senses of force exerted, or electrical current or power supplied.\n[n.] (industrial relations) A hourly pay rate given to a casual employee which is higher than the equivalent full-time or part-time employee's rate, usually paid to compensate for a lack of benefits such as sick leave or annual leave.","ex":"The dock workers refused to load the ship."},"LOCUS":{"p":"/ˈləʊkəs/","s":"n.","e":"[n.] A place or locality, especially a centre of activity or the scene of a crime.\n[n.] The set of all points whose coordinates satisfy a given equation or condition.\n[n.] A fixed position on a chromosome that may be occupied by one or more genes.","ex":"The cafeteria was the locus of activity."},"LIVE":{"p":"/lɪv/","s":"v.","e":"[v.] To be alive; to have life.\n[v.] To have permanent residence somewhere, to inhabit, to reside.\n[v.] To survive; to persevere; to continue.","ex":"He's not expected to live for more than a few months."},"LOFT":{"p":"/lɑft/","s":"n./v./adj.","e":"[n.] (except in derivatives) air, the air; the sky, the heavens.\n[n.] An attic or similar space (often used for storage) in the roof of a house or other building.\n[n.] The thickness of a soft object when not under pressure.\n[v.] To propel high into the air.\n[v.] To fly or travel through the air, as though propelled\n[v.] To throw the ball erroneously through the air instead of releasing it on the lane's surface.","ex":""},"LOGICAL":{"p":"/ˈlɒdʒɪkəɫ/","s":"adj.","e":"[adj.] In agreement with the principles of logic.\n[adj.] Reasonable.\n[adj.] Of or pertaining to logic.","ex":""},"LOCK":{"p":"/lɒk/","s":"n./v.","e":"[n.] Something used for fastening, which can only be opened with a key or combination.\n[n.] (by extension) A mutex or other token restricting access to a resource.\n[n.] A segment of a canal or other waterway enclosed by gates, used for raising and lowering boats between levels.\n[v.] To become fastened in place.\n[v.] To fasten with a lock.\n[v.] To be capable of becoming fastened in place.","ex":"If you put the brakes on too hard, the wheels will lock."},"LOGIC":{"p":"/ˈlɒdʒɪk/","s":"n./v./adj.","e":"[n.] A method of human thought that involves thinking in a linear, step-by-step manner about how a problem can be solved. Logic is the basis of many principles including the scientific method.\n[n.] The study of the principles and criteria of valid inference and demonstration.\n[n.] The mathematical study of relationships between rigorously defined concepts and of mathematical proof of statements.\n[v.] To engage in excessive or inappropriate application of logic.\n[v.] To apply logical reasoning to.\n[v.] To overcome by logical argument.","ex":""},"LOCAL":{"p":"/ˈləʊkl̩/","s":"n./adj./adv.","e":"[n.] A person who lives near a given place.\n[n.] A branch of a nationwide organization such as a trade union.\n[n.] A train that stops at all, or almost all, stations between its origin and destination, including very small ones.\n[adj.] From or in a nearby location.\n[adj.] (of a variable or identifier) Having limited scope (either lexical or dynamic); only being accessible within a certain portion of a program.\n[adj.] (of a condition or state) Applying to each point in a space rather than the space as a whole.","ex":"It's easy to tell the locals from the tourists."},"LOGO":{"p":"/ˈləʊɡəʊ/","s":"n.","e":"[n.] A visual symbol or emblem that acts as a trademark or a means of identification of a company or organization.\n[n.] (by extension) An audio recording for the same purpose; a jingle.\n[n.] A single graphic which contains one or more separate elements.","ex":""},"LOGIN":{"p":"/ˈlɒɡ.ɪn/","s":"n.","e":"[n.] A combination of a user's identification and password used to enter a computer, program, network, etc.\n[n.] The process of logging in.","ex":"I've forgotten my login again."},"LONG":{"p":"/ˈlɔːŋ/","s":"n./v./adj.","e":"[n.] A long vowel.\n[n.] A long syllable.\n[n.] A note formerly used in music, one half the length of a large, twice that of a breve.\n[v.] To take a long position in.\n[adj.] Having much distance from one terminating point on an object or an area to another terminating point (usually applies to horizontal dimensions; see Usage Notes below).\n[adj.] Having great duration.","ex":"It's a long way from the Earth to the Moon."},"LOOPY":{"p":"/ˈluːpi/","s":"adj.","e":"[adj.] Having loops.\n[adj.] Idiotic, crazy or drunk.","ex":"A loopy rollercoaster."},"LOOSE":{"p":"/luːs/","s":"n./v./adj./int.","e":"[n.] The release of an arrow.\n[n.] A state of laxity or indulgence; unrestrained freedom, abandonment.\n[n.] All play other than set pieces (scrums and line-outs).\n[v.] To let loose, to free from restraints.\n[v.] To unfasten, to loosen.\n[v.] To make less tight, to loosen.","ex":"This wheelbarrow has a loose wheel."},"LOOKING":{"p":"/ˈlʊkɪŋ/","s":"n.","e":"[n.] The act of one who looks; a glance.\n[n.] The manner in which one looks; appearance; countenance.","ex":""},"LORD":{"p":"/lɔːd/","s":"n./v.","e":"[n.] The master of the servants of a household; the master of a feudal manor\n[n.] One possessing similar mastery over others; any feudal superior generally; any nobleman or aristocrat; any chief, prince, or sovereign ruler; in Scotland, a male member of the lowest rank of nobility (the equivalent rank in England is baron)\n[n.] One possessing similar mastery in figurative senses (esp. as lord of ~)\n[v.] Domineer or act like a lord.\n[v.] To invest with the dignity, power, and privileges of a lord; to grant the title of lord.","ex":""},"LODGE":{"p":"/lɒdʒ/","s":"n./v.","e":"[n.] A building for recreational use such as a hunting lodge or a summer cabin.\n[n.] Short for porter's lodge: a building or room near the entrance of an estate or building, especially as a college mailroom.\n[n.] A local chapter of some fraternities, such as freemasons.\n[v.] To be firmly fixed in a specified position.\n[v.] To stay in a boarding-house, paying rent to the resident landlord or landlady.\n[v.] To stay in any place or shelter.","ex":"I've got some spinach lodged between my teeth."},"LORRY":{"p":"/ˈlɒɹi/","s":"n./v.","e":"[n.] A motor vehicle for transporting goods, and in some cases people; a truck.\n[n.] A barrow or truck for shifting baggage, as at railway stations.\n[n.] A small cart or wagon used on the tramways in mines to carry coal or rubbish.\n[v.] To transport by, or as if by, lorry.","ex":""},"LOSE":{"p":"/luːz/","s":"v.","e":"[v.] To cause (something) to cease to be in one's possession or capability due to unfortunate or unknown circumstances, events or reasons.\n[v.] To wander from; to miss, so as not to be able to find; to go astray from.\n[v.] To fail to win (a game, competition, trial, etc).","ex":"He lost his hearing in the explosion."},"LOFTY":{"p":"/ˈlɑfti/","s":"adj.","e":"[adj.] High, tall, having great height or stature\n[adj.] Idealistic, implying over-optimism\n[adj.] Extremely proud; arrogant; haughty","ex":"a lofty goal"},"LOSER":{"p":"/luzɚ/","s":"n.","e":"[n.] A person who loses; one who fails to win or thrive.\n[n.] Something of poor quality.\n[n.] A person who is frequently unsuccessful in life.","ex":"He was always a good loser."},"LOATH":{"p":"/ləʊθ/","s":"adj.","e":"[adj.] Averse, disinclined; reluctant, unwilling.\n[adj.] Angry, hostile.\n[adj.] Loathsome, unpleasant.","ex":"I was loath to return to the office without the Henderson file."},"LOSSES":{"p":"","s":"n.","e":"[n.] The result of no longer possessing an object, a function, or a characteristic due to external causes or misplacement.\n[n.] The destruction or ruin of an object.\n[n.] Something that has been destroyed or ruined.","ex":"In other areas, glacier loss creates serious risk of a dry period across the Third Pole, Wang said."},"LOSS":{"p":"/lɑs/","s":"n.","e":"[n.] The result of no longer possessing an object, a function, or a characteristic due to external causes or misplacement.\n[n.] The destruction or ruin of an object.\n[n.] Something that has been destroyed or ruined.","ex":"In other areas, glacier loss creates serious risk of a dry period across the Third Pole, Wang said."},"LOTS":{"p":"/lɒts/","s":"n./v./adv.","e":"[n.] A large quantity or number; a great deal.\n[n.] A separate portion; a number of things taken collectively.\n[n.] One or more items auctioned or sold as a unit, separate from other items.\n[v.] To allot; to sort; to apportion.\n[v.] To count or reckon (on or upon).\n[n.] A lot; a great deal; tons; loads.","ex":"lots of people think so"},"LOUD":{"p":"/laʊd/","s":"n./adj.","e":"[n.] A loud sound or part of a sound.\n[n.] High-quality marijuana.\n[adj.] (of a sound) Of great intensity.\n[adj.] (of a person, thing, event, etc.) Noisy.\n[adj.] (of a person, event, etc.) Not subtle or reserved, brash.","ex":"Turn that music down; it's too loud."},"LOUSE":{"p":"/laʊs/","s":"n./v.","e":"[n.] A small parasitic wingless insect of the order Psocodea.\n[n.] (not usually used in plural form) A contemptible person; one who is deceitful or causes harm.\n[v.] To remove lice from.","ex":""},"LOUSY":{"p":"/laʊ.zi/","s":"adj.","e":"[adj.] Remarkably bad; of poor quality, dirty, or underhanded; mean, contemptible.\n[adj.] Infested with lice.\n[adj.] (usually with with) Filled or packed (with something, usually bad).","ex":"No offense, but his cooking is lousy."},"LOVE":{"p":"/lʊv/","s":"n./v.","e":"[n.] Strong affection.\n[n.] A person who is the object of romantic feelings; a darling, a sweetheart, a beloved.\n[n.] A term of friendly address, regardless of feelings.\n[v.] (usually transitive, sometimes intransitive, stative) To have a strong affection for (someone or something).\n[v.] To need, thrive on.\n[v.] To be strongly inclined towards something; an emphatic form of like.","ex":"Hello love, how can I help you?"},"LOYAL":{"p":"/ˈlɔɪəl/","s":"adj.","e":"[adj.] Having or demonstrating undivided and constant support for someone or something.\n[adj.] Firm in allegiance to a person or institution.\n[adj.] Faithful to a person or cause.","ex":""},"LOVER":{"p":"/ˈlʌvə/","s":"n.","e":"[n.] One who loves and cares for another person in a romantic way; a sweetheart, love, soulmate, boyfriend, girlfriend or spouse.\n[n.] A sexual partner, especially one with whom someone is having an affair.\n[n.] A person who loves something.","ex":"a lover of fine wines"},"LOWLY":{"p":"/ˈləʊli/","s":"adj./adv.","e":"[adj.] Not high; not elevated in place; low.\n[adj.] Low in rank or social importance.\n[adj.] Not lofty or sublime; humble.\n[adv.] In a low manner; humbly; meekly; modestly.\n[adv.] In a low condition; meanly.\n[adv.] At low pitch or volume.","ex":"He muttered lowly."},"LUCID":{"p":"/ˈl(j)uːsɪd/","s":"n./adj.","e":"[n.] A lucid dream.\n[adj.] Clear; easily understood\n[adj.] Mentally rational; sane\n[adj.] Bright, luminous, translucent or transparent","ex":""},"LUCK":{"p":"/lʊk/","s":"n./v.","e":"[n.] Something that happens to someone by chance, a chance occurrence, especially a favourable one.\n[n.] A superstitious feeling that brings fortune or success.\n[n.] Success.\n[v.] To succeed by chance.\n[v.] To rely on luck.\n[v.] To carry out relying on luck.","ex":"Gilbert had some bad luck yesterday — he got pick-pocketed and lost fifty dollars."},"LUMEN":{"p":"/ˈluːmən/","s":"n.","e":"[n.] In the International System of Units, the derived unit of luminous flux; the light that is emitted in a solid angle of one steradian from a source of one candela. Symbol: lm.\n[n.] The cavity or channel within a tube or tubular organ.\n[n.] The cavity bounded by a plant cell wall.","ex":""},"LUNCH":{"p":"/lʌnt͡ʃ/","s":"n./v.","e":"[n.] A light meal usually eaten around midday, notably when not as main meal of the day.\n[n.] A break in play between the first and second sessions.\n[n.] (Minnesota) Any small meal, especially one eaten at a social gathering.\n[v.] To eat lunch.\n[v.] To treat to lunch.","ex":"After the funeral there was a lunch for those who didn't go to the cemetery."},"LUNGE":{"p":"/lʌndʒ/","s":"n./v.","e":"[n.] A sudden forward movement, especially with a sword.\n[n.] A long rope or flat web line, more commonly referred to as a lunge line, approximately 20–30 feet long, attached to the bridle, lungeing cavesson, or halter of a horse and used to control the animal while lungeing.\n[n.] An exercise performed by stepping forward one leg while kneeling with the other leg, then returning to a standing position.\n[v.] To (cause to make) a sudden forward movement (present participle: lunging).\n[v.] To longe or work a horse in a circle around a handler (present participle: lunging or lungeing).","ex":"I lunged at the police officer and made a grab for her gun."},"LUCKY":{"p":"/ˈlʌki/","s":"adj.","e":"[adj.] (of people) Favoured by luck; fortunate; having good success or good fortune\n[adj.] Producing, or resulting in, good fortune","ex":"The downed pilot is very lucky to be alive."},"LURCH":{"p":"/lɝt͡ʃ/","s":"n./v.","e":"[n.] A sudden or unsteady movement.\n[v.] To make such a sudden, unsteady movement.","ex":"the lurch of a ship, or of a drunkard"},"LUSTY":{"p":"/lʌsti/","s":"adj.","e":"[adj.] Exhibiting lust (in the obsolete sense meaning \"vigor\"); strong, healthy, robust; vigorous; full of sap or vitality.\n[adj.] Hearty, merry, gleesome, enthusiastic, lively, stirring.\n[adj.] Given to experiencing lust; enjoying physical sensations; lustful.","ex":""},"LUXURY":{"p":"/ˈlʌk.ʃə.ɹi/","s":"n./adj.","e":"[n.] Very wealthy and comfortable surroundings.\n[n.] Something desirable but expensive.\n[n.] Something that is pleasant but not necessary in life.\n[adj.] Very expensive\n[adj.] Not essential but desirable and enjoyable and indulgent.\n[adj.] Pertaining to the top-end market segment for mass production mass market vehicles, above the premium market segment.","ex":""},"LYMPH":{"p":"/lɪmf/","s":"n.","e":"[n.] (poetical) Pure water.\n[n.] A colourless, watery bodily fluid, carried by the lymphatic system, that consists mainly of white blood cells.\n[n.] Discharge from a sore, inflammation etc.","ex":""},"LYING":{"p":"/ˈlaɪ.ɪŋ/","s":"v./n.","e":"[v.] To rest in a horizontal position on a surface.\n[v.] To be placed or situated.\n[v.] To abide; to remain for a longer or shorter time; to be in a certain state or condition.\n[v.] To give false information intentionally with intent to deceive.\n[v.] To convey a false image or impression.\n[v.] To be mistaken or unintentionally spread false information.","ex":"The book lies on the table;  the snow lies on the roof;  he lies in his coffin"},"LYRIC":{"p":"/ˈlɪɹ.ɪk/","s":"n./adj.","e":"[n.] A lyric poem.\n[n.] (also in plural) The words of a song or other vocal music. The singular form often refers to a part of the words, whereas the plural form can refer to all of the words.\n[adj.] Of, or relating to a type of poetry (such as a sonnet or ode) that expresses subjective thoughts and feelings, often in a songlike style\n[adj.] Of or relating to a writer of such poetry\n[adj.] Lyrical","ex":"The lyric in line 3 doesn't rhyme."},"MACRO":{"p":"/ˈmæk.ɹəʊ/","s":"adj./n.","e":"[adj.] Very large in scope or scale.\n[adj.] Of a lifestyle incorporating a dietary regimen including locally grown, seasonal, natural foods, or of the diet itself.\n[adj.] Long-lived.\n[n.] The study of the entire economy in terms of the total amount of goods and services produced, total income earned, the level of employment of productive resources, and the general behavior of prices.\n[n.] Any of the elements required in large amounts by all living things.","ex":""},"MACAW":{"p":"/məˈkɔː/","s":"n.","e":"[n.] Any of various parrots of the genera Ara, Anodorhynchus, Cyanopsitta, Orthopsittaca, Primolius and Diopsittaca of Central and South America, including the largest parrots and characterized by long sabre-shaped tails, curved powerful bills, and usually brilliant plumage.","ex":""},"MACHINE":{"p":"/məˈʃin/","s":"n./v.","e":"[n.] A device that directs and controls energy, often in the form of movement or electricity, to produce a certain effect.\n[n.] A vehicle operated mechanically, such as an automobile or an airplane.\n[n.] (abbreviation) An answering machine or, by extension, voice mail.\n[v.] To make by machinery.\n[v.] To shape or finish by machinery.","ex":"I called you earlier, but all I got was the machine."},"MACHO":{"p":"/ˈmætʃəʊ/","s":"n./adj.","e":"[n.] A macho person; a person who tends to display masculine characteristics, such as domineering, fierceness, and bravado.\n[n.] The striped mullet of California (Mugil cephalus, syn. Mugil mexicanus).\n[n.] A male llama.\n[adj.] Tending to display masculine characteristics, such as domineering, fierceness, bravado, etc., in ways that are showily and histrionically tough","ex":""},"MADAM":{"p":"/ˈmæd.əm/","s":"n./v.","e":"[n.] A polite form of address for a woman or lady.\n[n.] The mistress of a household.\n[n.] A conceited or quarrelsome girl.\n[v.] To address as \"madam\".","ex":"Later, Mrs Grey was sitting in her favourite tea shop. “Would madam like the usual cream cakes and patisserie with her tea?” the waitress asked."},"MAGIC":{"p":"/ˈmadʒɪk/","s":"n./v./adj.","e":"[n.] The application of rituals or actions, especially those based on occult knowledge, to subdue or manipulate natural or supernatural beings and forces in order to have some benefit from them\n[n.] A specific ritual or procedure associated with such magic; a spell.\n[n.] The supernatural forces which are drawn on in such a ritual\n[v.] To produce, transform (something), (as if) by magic.\n[adj.] Having supernatural talents, properties or qualities attributed to magic.\n[adj.] Producing extraordinary results, as though through the use of magic; wonderful, amazing.","ex":"a magic moment"},"MAIL":{"p":"/meɪ̯l/","s":"n./v.","e":"[n.] A bag or wallet.\n[n.] A bag containing letters to be delivered by post.\n[n.] The material conveyed by the postal service.\n[v.] (ditransitive) To send (a letter, parcel, etc.) through the mail.\n[v.] (ditransitive) To send by electronic mail.\n[v.] To contact (a person) by electronic mail.","ex":"Don't forget to pick up the mail on your way."},"MADLY":{"p":"/ˈmædli/","s":"adv.","e":"[adv.] In a mad manner; without reason or understanding; wildly.","ex":"I'm madly in love with you."},"MAIZE":{"p":"/meɪz/","s":"n.","e":"[n.] Corn; a type of grain of the species Zea mays.","ex":""},"MAKE":{"p":"/meɪk/","s":"n./v.","e":"[n.] Brand or kind; model.\n[n.] Manner or style of construction (style of how a thing is made); form.\n[n.] Origin (of a manufactured article); manufacture; production.\n[v.] To create.\n[v.] To behave, to act.\n[v.] To tend; to contribute; to have effect; with for or against.","ex":"What make of car do you drive?"},"MAKER":{"p":"/ˈmeɪk.ə/","s":"n.","e":"[n.] Someone who makes; a person or thing that makes or produces something.\n[n.] (usually capitalized and preceded by the) God.\n[n.] A poet.","ex":""},"MAKING":{"p":"/ˈmeɪkɪŋ/","s":"n.","e":"[n.] The act of forming, causing, or constituting; workmanship; construction.\n[n.] Process of growth or development.","ex":"As a child, he didn’t seem like a genius in the making."},"MANUAL":{"p":"/ˈman.j(ʊ)əl/","s":"n.","e":"[n.] A handbook.\n[n.] A booklet that instructs on the usage of a particular machine or product.\n[n.] A drill in the use of weapons, etc.","ex":"The dishwasher isn't working; can you remember where we put the manual?"},"MALE":{"p":"/meɪl/","s":"n./adj.","e":"[n.] One of the male (masculine) sex or gender.\n[adj.] Belonging to the sex which typically produces sperm, or to the gender which is typically associated with it.\n[adj.] Characteristic of this sex/gender. (Compare masculine, manly.)\n[adj.] Tending to lead to or regulate the development of sexual characteristics typical of this sex.","ex":"a male bird feeding a seed to a female"},"MANOR":{"p":"/ˈmænə/","s":"n.","e":"[n.] A landed estate.\n[n.] The main house of such an estate or a similar residence; a mansion.\n[n.] A district over which a feudal lord could exercise certain rights and privileges in medieval western Europe.","ex":""},"MARCH":{"p":"/mɑːtʃ/","s":"n./v.","e":"[n.] A formal, rhythmic way of walking, used especially by soldiers, bands and in ceremonies.\n[n.] A political rally or parade\n[n.] Any song in the genre of music written for marching (see Wikipedia's article on this type of music)\n[v.] To walk with long, regular strides, as a soldier does.\n[v.] To cause someone to walk somewhere.\n[v.] To go to war; to make military advances.","ex":""},"MANGE":{"p":"/meɪndʒ/","s":"n.","e":"[n.] A skin disease of mammals caused by parasitic mites (Sarcoptes spp., Demodecidae spp.).","ex":""},"MANY":{"p":"/ˈmæni/","s":"n./adj./pron.","e":"[n.] A multitude; a great aggregate; a mass of people; the generality; the common herd.\n[n.] A considerable number.\n[adj.] A large number of; numerous.\n[pron.] An indefinite large number of people or things.","ex":"Democracy must balance the rights of the few against the will of the many."},"MARK":{"p":"/mɑɹk/","s":"n./v.","e":"[n.] (heading) Boundary, land within a boundary.\n[n.] (heading) Characteristic, sign, visible impression.\n[n.] (heading) Indicator of position, objective etc.\n[v.] To put a mark on (something); to make (something) recognizable by a mark; to label or write on (something).\n[v.] To leave a mark (often an undesirable or unwanted one) on (something).\n[v.] To have a long-lasting negative impact on (someone or something).","ex":"to mark a box or bale of merchandise"},"MARTIAL":{"p":"/ˈmɑːʃəl/","s":"n./adj.","e":"[n.] A person under the astrological influence of the planet Mars.\n[n.] An inhabitant of the planet Mars.\n[n.] A soldier, a warrior.\n[n.] A celestial object under the astrological influence of the planet Mars.\n[adj.] Of, relating to, or suggestive of war; warlike.\n[adj.] Connected with or relating to armed forces or the profession of arms or military life.","ex":""},"MASK":{"p":"/mæsk/","s":"n./v.","e":"[n.] A cover, or partial cover, for the face, used for disguise or protection.\n[n.] That which disguises; a pretext or subterfuge.\n[n.] A festive entertainment of dancing or other diversions, where all wear masks; a masquerade\n[v.] To cover (the face or something else), in order to conceal the identity or protect against injury; to cover with a mask or visor.\n[v.] To disguise; to cover; to hide.\n[v.] To conceal; also, to intervene in the line of.","ex":"a dancer's mask; a fencer's mask; a ball player's mask"},"MASS":{"p":"/mæs/","s":"n./v./adj.","e":"[n.] (physical) Matter, material.\n[n.] A large quantity; a sum.\n[v.] To form or collect into a mass; to form into a collective body; to bring together into masses; to assemble.\n[v.] To have a certain mass.\n[adj.] Involving a mass of things; concerning a large quantity or number.\n[adj.] Involving a mass of people; of, for, or by the masses.","ex":"I mass 70 kilograms."},"MATCHED":{"p":"","s":"v./n.","e":"[v.] To agree; to be equal; to correspond.\n[v.] To agree with; to be equal to; to correspond to.\n[v.] To make a successful match or pairing.\n[n.] Short for matched grip.","ex":"Their interests didn't match, so it took a long time to agree what to do together."},"MATTER":{"p":"/ˈmætə/","s":"n./v.","e":"[n.] Substance, material.\n[n.] A condition, subject or affair, especially one of concern.\n[n.] An approximate amount or extent.\n[v.] To be important.\n[v.] (in negative constructions) To care about, to mind; to find important.\n[v.] To form pus or matter, as an abscess; to maturate.","ex":"What's the matter?;   state matters"},"MATEY":{"p":"","s":"n./adj.","e":"[n.] The conclusive victory in a game of chess that occurs when an opponent's king is threatened with unavoidable capture.\n[n.] (by extension) Any losing situation with no escape; utter defeat.\n[n.] A fellow, comrade, colleague, partner or someone with whom something is shared, e.g. shipmate, classmate.\n[n.] (especially of a non-human animal) A breeding partner.\n[n.] A friend, usually of the same sex.\n[n.] The abovementioned plant; the leaves and shoots used for the tea","ex":"He's my best mate."},"MATE":{"p":"/meɪt/","s":"n./v.","e":"[n.] A fellow, comrade, colleague, partner or someone with whom something is shared, e.g. shipmate, classmate.\n[n.] (especially of a non-human animal) A breeding partner.\n[n.] A friend, usually of the same sex.\n[v.] To match, fit together without space between.\n[v.] To copulate.\n[v.] To pair in order to raise offspring","ex":"He's my best mate."},"MAYOR":{"p":"/ˈmeɪ.ə/","s":"n.","e":"[n.] The chief executive of the municipal government of a city, borough, &c., formerly usually appointed as a caretaker by European royal courts but now usually appointed or elected locally.\n[n.] Short for mayor of the palace, the royal stewards of the Frankish Empire.\n[n.] Synonym of mair, various former officials in the Kingdom of Scotland.","ex":""},"MAXIM":{"p":"/ˈmæk.sɪm/","s":"n.","e":"[n.] A self-evident axiom or premise; a pithy expression of a general principle or rule.\n[n.] A precept; a succinct statement or observation of a rule of conduct or moral teaching.","ex":""},"MEMBER":{"p":"/ˈmɛmbə/","s":"n.","e":"[n.] One who officially belongs to a group.\n[n.] A part of a whole.\n[n.] Part of an animal capable of performing a distinct office; an organ; a limb.","ex":"The I-beams were to become structural members of a pedestrian bridge."},"MEMORY":{"p":"/ˈmɛm(ə)ɹi/","s":"n.","e":"[n.] The ability of the brain to record information or impressions with the facility of recalling them later at will.\n[n.] A record of a thing or an event stored and available for later use by the organism.\n[n.] The part of a computer that stores variable executable code or data (RAM) or unalterable executable code or default data (ROM).","ex":"Memory is a facility common to all animals."},"MERRY":{"p":"/ˈmɛɹi/","s":"adj.","e":"[adj.] Jolly and full of high spirits.\n[adj.] Festive and full of fun and laughter.\n[adj.] Brisk","ex":"We had a very merry Christmas."},"MESS":{"p":"/mɛs/","s":"n./v.","e":"[n.] A disagreeable mixture or confusion of things; hence, a situation resulting from blundering or from misunderstanding; disorder.\n[n.] A large quantity or number.\n[n.] Excrement.\n[v.] (transitive, often used with \"up\") To make untidy or dirty.\n[v.] (transitive, often used with \"up\") To throw into disorder or to ruin.\n[v.] To interfere.","ex":"He made a mess of it."},"METHOD":{"p":"/ˈmɛθəd/","s":"n./v.","e":"[n.] A process by which a task is completed; a way of doing something (followed by the adposition of, to or for before the purpose of the process):\n[n.] (often \"the method\") A technique for acting based on the ideas articulated by Constantin Stanislavski and focusing on authentically experiencing the inner life of the character being portrayed.\n[n.] A subroutine or function belonging to a class or object, synonym of member function\n[v.] To apply a method\n[v.] (casting, by extension) to apply particular treatment methods to a mold","ex":"If one method doesn't work, you should ask a friend to help you."},"MILE":{"p":"/maɪ̯l/","s":"n.","e":"[n.] The international mile: a unit of length precisely equal to 1.609344 kilometers established by treaty among Anglophone nations in 1959, divided into 5,280 feet or 1,760 yards.\n[n.] Any of several customary units of length derived from the 1593 English statute mile of 8 furlongs, equivalent to 5,280 feet or 1,760 yards of various precise values.\n[n.] Any of many customary units of length derived from the Roman mile (mille passus) of 8 stades or 5,000 Roman feet.","ex":""},"MINERAL":{"p":"/ˈmɪ.nəɹ.əl/","s":"n./adj.","e":"[n.] Any naturally occurring inorganic material that has a (more or less) definite chemical composition and characteristic physical properties.\n[n.] Any inorganic material (as distinguished from animal or vegetable).\n[n.] (nutrition) Any inorganic element that is essential to nutrition; a dietary mineral.\n[adj.] Of, related to, or containing minerals","ex":""},"MILLION":{"p":"/ˈmɪljən/","s":"num.","e":"[num.] (long and short scales) The cardinal number 1,000,000: 106; a thousand thousand.\n[num.] An unspecified very large number.","ex":"I can think of millions of reasons not to go."},"MINUS":{"p":"/ˈmaɪnəs/","s":"n./v./adj./prep.","e":"[n.] The minus sign (−).\n[n.] A negative quantity.\n[n.] A downside or disadvantage.\n[v.] To subtract.\n[adj.] Being a negative quantity; pertaining to a deficit or reduction.\n[adj.] That is below zero by (a specified amount) on a scale.","ex":"a minus number"},"MINUTE":{"p":"/ˈmɪnɪt/","s":"n./v.","e":"[n.] A unit of time equal to sixty seconds (one-sixtieth of an hour).\n[n.] A short but unspecified time period.\n[n.] A unit of angle equal to one-sixtieth of a degree.\n[v.] Of an event, to write in a memo or the minutes of a meeting.\n[v.] To set down a short sketch or note of; to jot down; to make a minute or a brief summary of.","ex":"You have twenty minutes to complete the test."},"MODERN":{"p":"/ˈmɒd(ə)n/","s":"n./adj.","e":"[n.] Someone who lives in modern times.\n[adj.] Pertaining to a current or recent time and style; not ancient.\n[adj.] (history) Pertaining to the modern period (c.1800 to contemporary times), particularly in academic historiography.","ex":"Our online interactive game is a modern approach to teaching about gum disease.  Although it was built in the 1600s, the building still has a very modern look."},"MOCHA":{"p":"/ˈmɒkə/","s":"n./adj.","e":"[n.] A coffee drink with chocolate syrup added, or a serving thereof; a caffè mocha.\n[n.] A coffee and chocolate mixed flavour.\n[n.] A dark brown colour, like that of mocha coffee.\n[adj.] Of a dark brown colour, like that of mocha coffee.","ex":"mocha fudge"},"MOGUL":{"p":"/ˈmoʊɡəl/","s":"n.","e":"[n.] A rich or powerful person; a magnate.","ex":"a Silicon Valley tech mogul"},"MONTH":{"p":"/mʌnθ/","s":"n.","e":"[n.] A period into which a year is divided, historically based on the phases of the moon.\n[n.] A period of 30 days, 31 days, or some alternation thereof.\n[n.] (in the plural) A woman's period; menstrual discharge.","ex":"July is my favourite month."},"MONITOR":{"p":"/ˈmɒnɨtə/","s":"n./v.","e":"[n.] Someone who watches over something; a person in charge of something or someone.\n[n.] A device that detects and informs on the presence, quantity, etc., of something.\n[n.] A device similar to a television set used as to give a graphical display of the output from a computer.\n[v.] To watch over; to guard.","ex":"The camp monitors look after the children during the night, when the teachers are asleep."},"MONTHLY":{"p":"/ˈmʌnθli/","s":"n./adj./adv.","e":"[n.] A publication that is published once a month.\n[n.] The menstrual period.\n[adj.] Occurring every month.\n[adv.] Every month.","ex":""},"MOOD":{"p":"/muːd/","s":"n.","e":"[n.] A mental or emotional state, composure.\n[n.] Emotional character (of a work of music, literature, or other art).\n[n.] A sullen, gloomy or angry mental state; a bad mood.","ex":"I've been in a bad mood since I dumped my boyfriend."},"MORON":{"p":"/ˈmɔːɹɒn/","s":"n.","e":"[n.] A stupid person; an idiot; a fool.\n[n.] A person of mild mental subnormality in the former classification of mental retardation, having an intelligence quotient of 50–70.","ex":""},"MOODY":{"p":"/ˈmuːdi/","s":"adj.","e":"[adj.] Given to sudden or frequent changes of mind; temperamental.\n[adj.] Sulky or depressed.\n[adj.] Dour, gloomy or brooding.","ex":""},"MORE":{"p":"/ˈmɔː/","s":"adv./pron.","e":"[adv.] To a greater degree or extent.\n[adv.] Used to form the comparative form of adjectives and adverbs.\n[adv.] In negative constructions: any further, any longer; any more.\n[pron.] A greater number or quantity (of something).\n[pron.] An extra or additional quantity (of something).","ex":"I could no more climb that than fly!"},"MOON":{"p":"/muːn/","s":"pro./n./v.","e":"[pro.] The Earth's moon Luna; the sole natural satellite of the Earth, represented in astronomy and astrology by ☾.\n[pro.] The god of the Moon in Heathenry.\n[pro.] A surname.\n[n.] (by extension of Moon) Any natural satellite of a planet.\n[n.] A month, particularly a lunar month.\n[n.] A crescent-like outwork in a fortification.","ex":"That's no moon, you idiot... it's a space station!"},"MORAL":{"p":"/ˈmɒɹəl/","s":"n./v./adj.","e":"[n.] (of a narrative) The ethical significance or practical lesson.\n[n.] (chiefly in the plural) Moral practices or teachings: modes of conduct.\n[n.] A morality play.\n[v.] To moralize.\n[adj.] Of or relating to principles of right and wrong in behaviour, especially for teaching right behaviour.\n[adj.] Conforming to a standard of right behaviour; sanctioned by or operative on one's conscience or ethical judgment.","ex":"a candidate with strong morals"},"MOSSY":{"p":"/ˈmɒsi/","s":"n./adj.","e":"[n.] Mosquito\n[adj.] Covered in or overgrown with moss.","ex":""},"MOUND":{"p":"/maʊnd/","s":"n./v.","e":"[n.] An artificial hill or elevation of earth; a raised bank; an embankment thrown up for defense\n[n.] A natural elevation appearing as if thrown up artificially; a regular and isolated hill, hillock, or knoll.\n[n.] Elevated area of dirt upon which the pitcher stands to pitch.\n[v.] To fortify with a mound; add a barrier, rampart, etc. to.\n[v.] To force or pile into a mound or mounds.","ex":"He mounded up his mashed potatoes so they left more space on the plate for the meat."},"MOST":{"p":"/ˈməʊst/","s":"n./adv./pron.","e":"[n.] The greatest amount.\n[n.] The greater part.\n[n.] A record-setting amount.\n[adv.] Forms the superlative of many adjectives.\n[adv.] To a great extent or degree; highly; very.\n[adv.] Superlative of many","ex":"The most I can offer for the house is $150,000."},"MOULD":{"p":"/məʊld/","s":"n./v.","e":"[n.] A hollow form or matrix for shaping a fluid or plastic substance.\n[n.] A frame or model around or on which something is formed or shaped.\n[n.] Something that is made in or shaped on a mold.\n[v.] To shape in or on a mold; to form into a particular shape; to give shape to.\n[v.] To guide or determine the growth or development of; influence\n[v.] To fit closely by following the contours of.","ex":""},"MOUSE":{"p":"","s":"n./v.","e":"[n.] Any small rodent of the genus Mus.\n[n.] A member of the many small rodent and marsupial species resembling such a rodent.\n[n.] A quiet or shy person.\n[v.] To move cautiously or furtively, in the manner of a mouse (the rodent) (frequently used in the phrasal verb to mouse around).\n[v.] To hunt or catch mice (the rodents), usually of cats.\n[v.] To close the mouth of a hook by a careful binding of marline or wire.","ex":"Captain Higgins moused the hook with a bit of marline to prevent the block beckets from falling out under slack."},"MOVING":{"p":"/ˈmuːvɪŋ/","s":"v./n./adj.","e":"[v.] To change place or posture; to go, in any manner, from one place or position to another.\n[v.] To act; to take action; to begin to act\n[v.] To change residence, for example from one house, town, or state, to another; to go and live at another place. See also move out and move in.\n[n.] The relocation of goods\n[n.] A causing of a movement\n[adj.] That moves or move.","ex":"A ship moves rapidly."},"MUDDY":{"p":"[ˈmʌdi]","s":"v./adj.","e":"[v.] To get mud on (something).\n[v.] To make a mess of, or create confusion with regard to; to muddle.\n[adj.] Covered with or full of mud or wet soil.\n[adj.] With mud or other sediment brought into suspension, turbid.\n[adj.] Not clear; mixed up or blurry.","ex":"If you muddy your shoes don't wear them inside."},"MUCKY":{"p":"/ˈmʌki/","s":"adj.","e":"[adj.] Covered in muck.\n[adj.] Obscene, pornographic.","ex":"a mucky magazine"},"MUFTI":{"p":"/ˈmʊfti/","s":"n.","e":"[n.] A Muslim scholar and interpreter of shari’a law, who can deliver a fatwa.\n[n.] A civilian dress when worn by a member of the military, or casual dress when worn by a pupil of a school who normally would wear uniform.","ex":""},"MUSEUM":{"p":"/mjuːˈziːəm/","s":"n.","e":"[n.] A building or institution dedicated to the acquisition, conservation, study, exhibition, and educational interpretation of objects having scientific, historical, cultural or artistic value.","ex":""},"MUSTY":{"p":"[ˈmʌstɪ]","s":"adj.","e":"[adj.] Having a stale odor.","ex":""},"MUSIC":{"p":"/ˈmjuːzɪk/","s":"n./v.","e":"[n.] A series of sounds organized in time, employing melody, harmony, tempo etc. usually to convey a mood.\n[n.] Any pleasing or interesting sounds.\n[n.] An art form, created by organizing of pitch, rhythm, and sounds made using musical instruments and sometimes singing.\n[v.] To seduce or entice with music.","ex":"I keep listening to this music because it's a masterpiece."},"MOVE":{"p":"/muːv/","s":"n./v.","e":"[n.] The act of moving; a movement.\n[n.] An act for the attainment of an object; a step in the execution of a plan or purpose.\n[n.] A formalized or practiced action used in athletics, dance, physical exercise, self-defense, hand-to-hand combat, etc.\n[v.] To change place or posture; to go, in any manner, from one place or position to another.\n[v.] To act; to take action; to begin to act\n[v.] To change residence, for example from one house, town, or state, to another; to go and live at another place. See also move out and move in.","ex":"A slight move of the tiller, and the boat will go off course."},"MURKY":{"p":"","s":"adj.","e":"[adj.] Hard to see through, as a fog or mist.\n[adj.] Dark, dim, gloomy.\n[adj.] Cloudy, indistinct, obscure.","ex":""},"MYTH":{"p":"/mɪθ/","s":"n.","e":"[n.] A traditional story which embodies a belief regarding some fact or phenomenon of experience, and in which often the forces of nature and of the soul are personified; a sacred narrative regarding a god, a hero, the origin of the world or of a people, etc.\n[n.] Such stories as a genre.\n[n.] A commonly-held but false belief, a common misconception; a fictitious or imaginary person or thing; a popular conception about a real person or event which exaggerates or idealizes reality.","ex":"Myth was the product of man's emotion and imagination, acted upon by his surroundings. (E. Clodd, Myths & Dreams (1885), 7, cited after OED)"},"NAIVE":{"p":"/naɪˈiːv/","s":"n./adj.","e":"[n.] A naive person; a greenhorn.\n[adj.] Lacking worldly experience, wisdom, or judgement; unsophisticated.\n[adj.] Not having been exposed to something.\n[adj.] (of art) Produced in a simple, childlike style, deliberately rejecting sophisticated techniques.","ex":""},"NAME":{"p":"/neɪm/","s":"n.","e":"[n.] Any nounal word or phrase which indicates a particular person, place, class, or thing.\n[n.] Reputation.\n[n.] An abusive or insulting epithet.","ex":"I've never liked the name my parents gave me so I changed it at the age of twenty."},"MUTUAL":{"p":"/ˈmjuːt͡ʃuəl/","s":"n./adj.","e":"[n.] A mutual fund.\n[n.] A mutual organization.\n[n.] Either of a pair of people who follow each other's social media accounts.\n[adj.] Having the same relationship, each to each other.\n[adj.] Collective, done or held in common.\n[adj.] Reciprocal.","ex":"They were mutual enemies."},"NAVAL":{"p":"/ˈneɪvəl/","s":"adj.","e":"[adj.] Of or relating to a navy.\n[adj.] Of or relating to ships in general.","ex":"naval architect"},"NAVEL":{"p":"/ˈneɪvəl/","s":"n.","e":"[n.] The indentation or bump remaining in the abdomen of mammals where the umbilical cord was attached before birth.\n[n.] The central part or point of anything; the middle.\n[n.] A navel orange.","ex":""},"NECK":{"p":"/nɛk/","s":"n./v.","e":"[n.] The part of the body connecting the head and the trunk found in humans and some animals.\n[n.] The corresponding part in some other anatomical contexts.\n[n.] The part of a shirt, dress etc., which fits a person's neck.\n[v.] To hang by the neck; strangle; kill, eliminate\n[v.] To make love; to intently kiss or cuddle; to canoodle.\n[v.] To drink rapidly.","ex":"Giraffes have long necks."},"NATURAL":{"p":"/ˈnætʃəɹəl/","s":"n./adj./adv.","e":"[n.] A native inhabitant of a place, country etc.\n[n.] A note that is not or is no longer to be modified by an accidental.\n[n.] The symbol ♮ used to indicate such a natural note.\n[adj.] That exists and evolved within the confines of an ecosystem.\n[adj.] Of or relating to nature.\n[adj.] Without artificial additives.","ex":"The species will be under threat if its natural habitat is destroyed."},"NEED":{"p":"/niːd/","s":"n.","e":"[n.] A requirement for something; something needed.\n[n.] Lack of means of subsistence; poverty; indigence; destitution.","ex":"I've always tried to have few needs beyond food, clothing and shelter."},"NEEDY":{"p":"/ˈniːdi/","s":"adj.","e":"[adj.] In need; poor.\n[adj.] Desiring constant affirmation; lacking self-confidence.\n[adj.] Needful; necessary.","ex":"Needy people want to give too, but have few material goods to offer."},"NEATLY":{"p":"/ˈniːtli/","s":"adv.","e":"[adv.] In a neat manner.","ex":""},"NERDY":{"p":"/nɜː(ɹ)di/","s":"adj.","e":"[adj.] (of a person) Being or like a nerd.\n[adj.] (of a quality or interest) Of, pertaining to, in the style of, or appealing to nerds.","ex":"That guy is nerdy and weird."},"NEITHER":{"p":"/ˈnaɪð.ə(ɹ)/","s":"adv./pron./conj.","e":"[adv.] Similarly not.\n[pron.] Not either one of two.\n[conj.] Not either (used with nor).","ex":"Just as you would not correct it, neither would I."},"NEAREST":{"p":"/ˈnɪəɹɪst/","s":"adj./prep.","e":"[adj.] Physically close.\n[adj.] Close in time.\n[adj.] Closely connected or related.\n[prep.] Closest to.","ex":"I can't see near objects very clearly without my glasses."},"NERVOUS":{"p":"/ˈnɜːvəs/","s":"adj.","e":"[adj.] Of sinews and tendons.\n[adj.] Of nerves.","ex":""},"NETWORK":{"p":"/nɛtwɜːk/","s":"n./v.","e":"[n.] A fabric or structure of fibrous elements attached to each other at regular intervals.\n[n.] Any interconnected group or system\n[n.] A directory of people maintained for their advancement\n[v.] To interact socially for the purpose of getting connections or personal advancement.\n[v.] To connect two or more computers or other computerized devices.\n[v.] To interconnect a group or system.","ex":"A network of roads crisscrossed the country."},"NEARBY":{"p":"","s":"adj./adv.","e":"[adj.] Adjacent, near, close by\n[adv.] Next to, close to","ex":"He stopped at a nearby store for some groceries."},"NERVE":{"p":"/nɛɾv/","s":"n./v.","e":"[n.] A bundle of neurons with their connective tissue sheaths, blood vessels and lymphatics.\n[n.] A neuron.\n[n.] A vein in a leaf; a grain in wood\n[v.] To give courage.\n[v.] To give strength; to supply energy or vigour.","ex":"The nerves can be seen through the skin."},"NEWER":{"p":"/ˈn(j)uː.ɚ/","s":"adj.","e":"[adj.] Recently made, or created.\n[adj.] Additional; recently discovered.\n[adj.] Current or later, as opposed to former.","ex":"This is a new scratch on my car!   The band just released a new album."},"NICE":{"p":"/naɪs/","s":"n./adj./adv./int.","e":"[n.] Niceness.\n[adj.] Pleasant, satisfactory.\n[adj.] Of a person: friendly, attractive.\n[adj.] Respectable; virtuous.\n[adv.] Nicely.\n[int.] Used to signify a job well done.","ex":"What is a nice person like you doing in a place like this?"},"NICER":{"p":"","s":"adj./adv.","e":"[adj.] Pleasant, satisfactory.\n[adj.] Of a person: friendly, attractive.\n[adj.] Respectable; virtuous.\n[adv.] Nicely.","ex":"What is a nice person like you doing in a place like this?"},"NEWLY":{"p":"/ˈnjuːli/","s":"adv.","e":"[adv.] Very recently; in the immediate past.","ex":"She smelled the newly budding flowers."},"NIECE":{"p":"/niːs/","s":"n.","e":"[n.] A daughter of one’s sibling, brother-in-law, or sister-in-law; either the daughter of one's brother (\"fraternal niece\"), or of one's sister (\"sororal niece\").","ex":"My niece just celebrated her 15th birthday."},"NIGHT":{"p":"/naɪt/","s":"n./v./int.","e":"[n.] The period between sunset and sunrise, when a location faces far away from the sun, thus when the sky is dark.\n[n.] (Astronomy) The period of darkness beginning at the end of evening astronomical twilight when the sun is 18 degrees below the horizon, and ending at the beginning of morning astronomical twilight.\n[n.] (Legal) Often defined in the legal system as beginning 30 minutes after sunset, and ending 30 minutes before sunrise.\n[v.] To spend a night (in a place), to overnight.\n[int.] Ellipsis of good night","ex":"How do you sleep at night when you attack your kids like that!?"},"NIFTY":{"p":"/ˈnɪfti/","s":"adj.","e":"[adj.] Good, smart; useful or beneficial.\n[adj.] Stylish.","ex":"a nifty trick for reducing your household energy bill"},"NINJA":{"p":"/ˈnɪndʒə/","s":"n./v./adj.","e":"[n.] An adult male human.\n[n.] (collective) All human males collectively: mankind.\n[n.] A human, a person of either gender, usually an adult. (See usage notes.)\n[n.] A person trained in ninjutsu, especially one used for espionage, assassination, and other tasks requiring stealth during Japan's shogunate period.\n[n.] A person considered similarly skillful to the historical ninja, especially in covert or stealthy operation.\n[n.] A person considered to look like the historical ninja in some way, including (Mongolia) amateur private miners.","ex":"The show is especially popular with middle-aged men."},"NICHE":{"p":"/niːʃ/","s":"n./v./adj.","e":"[n.] A cavity, hollow, or recess, generally within the thickness of a wall, for a statue, bust, or other erect ornament. Hence, any similar position, literal or figurative.\n[n.] A function within an ecological system to which an organism is especially suited.\n[n.] (by extension) Any position of opportunity for which one is well-suited, such as a particular market in business.\n[v.] To place in a niche.\n[v.] To specialize in a niche, or particular narrow section of the market.\n[adj.] Pertaining to or intended for a market niche; having specific appeal.","ex":"a niched vase"},"NINTH":{"p":"/naɪnθ/","s":"n./v./adj.","e":"[n.] The person or thing in the ninth position.\n[n.] One of nine equal parts of a whole.\n[n.] The compound interval between any tone and the tone represented on the ninth degree of the staff above it, as between one of the scale and two of the octave above; the octave of the second, consisting of 13 or 14 semitones (called minor and major ninth).\n[v.] To lose a ninth\n[v.] To divide by nine\n[adj.] The ordinal form of the number nine.","ex":""},"NINNY":{"p":"/ˈnɪni/","s":"n.","e":"[n.] A silly or foolish person.","ex":""},"NEUTRAL":{"p":"/ˈnjuːtɹəl/","s":"n./adj.","e":"[n.] A nonaligned state, or a member of such a state.\n[n.] A person who takes no side in a dispute.\n[n.] An individual or entity serving as an arbitrator or adjudicator.\n[adj.] Not taking sides in a conflict such as war; nonaligned.\n[adj.] Favouring neither the supporting nor opposing viewpoint of a topic of debate; unbiased.\n[adj.] (grammar) Neither positive nor negative.","ex":"I am neutral regarding the issue of gay marriage."},"NICK":{"p":"/nɪk/","s":"n./v.","e":"[n.] A small cut in a surface.\n[n.] Senses connoting something small.\n[n.] Often in the expressions in bad nick and in good nick: condition, state.\n[v.] To make a nick or notch in; to cut or scratch in a minor way.\n[v.] To fit into or suit, as by a correspondence of nicks; to tally with.\n[v.] To make a cut at the side of the face.","ex":"The car I bought was cheap and in good nick."},"NEVER":{"p":"/ˈnɛv.ə(ɹ)/","s":"adv.","e":"[adv.] At no time; on no occasion; in no circumstance.\n[adv.] Not at any other time; not on any other occasion; not previously.\n[adv.] Negative particle (used to negate verbs in the simple past tense; also used absolutely).","ex":"I finally finished, and I never want to do that again."},"NOBLE":{"p":"/ˈnəʊbəl/","s":"n./adj.","e":"[n.] An aristocrat; one of aristocratic blood.\n[n.] A medieval gold coin of England in the 14th and 15th centuries, usually valued at 6s 8d.\n[adj.] Having honorable qualities; having moral eminence and freedom from anything petty, mean or dubious in conduct and character.\n[adj.] Grand; stately; magnificent; splendid.\n[adj.] Of exalted rank; of or relating to the nobility; distinguished from the masses by birth, station, or title; highborn.","ex":"This country house was occupied by nobles in the 16th century."},"NINE":{"p":"/naɪn/","s":"n./num.","e":"[n.] The digit or figure 9.\n[n.] A playing card with nine pips.\n[n.] A nine-millimeter semi-automatic pistol.\n[num.] A numerical value equal to 9; the number following eight and preceding ten.\n[num.] Describing a group or set with nine elements.","ex":"A cat has nine lives."},"NEXT":{"p":"/nɛkst/","s":"n./adj./adv./prep.","e":"[n.] The one that follows after this one.\n[adj.] Nearest in place or position, having nothing similar intervening; adjoining.\n[adj.] Nearest in order, succession, or rank; immediately following (or sometimes preceding) in order.\n[adj.] Following in a hypothetical sequence of some kind.\n[adv.] In a time, place, rank or sequence closest or following.\n[adv.] On the first subsequent occasion.","ex":"Next, please, don't hold up the queue!"},"NEWS":{"p":"/njuːz/","s":"n./v.","e":"[n.] New information of interest.\n[n.] Information about current events disseminated via media.\n[n.] Posts published on newsgroups\n[v.] To report; to make known.","ex":"Is there any news about the storm?"},"NODE":{"p":"","s":"n.","e":"[n.] A knot, knob, protuberance or swelling.\n[n.] The point where the orbit of a planet, as viewed from the Sun, intersects the ecliptic. The ascending and descending nodes refer respectively to the points where the planet moves from South to North and N to S; their respective symbols are ☊ and ☋.\n[n.] A leaf node.","ex":""},"NOBODY":{"p":"/ˈnəʊ.bɒ.di/","s":"n./pron.","e":"[n.] Someone who is not important or well-known.\n[pron.] Not any person; the logical negation of somebody.","ex":"Whether you're a nobody or a player, everyone in Tinseltown wants to be King of Hollywood! - Conquering Hollywood"},"NOISY":{"p":"/ˈnɔːɪzɪ/","s":"adj.","e":"[adj.] Making a noise, especially a loud unpleasant sound\n[adj.] Full of noise.\n[adj.] Unpleasant-looking and causing unwanted attention","ex":"the noisy crowd."},"NOISE":{"p":"/nɔɪz/","s":"n./v.","e":"[n.] Various sounds, usually unwanted or unpleasant.\n[n.] Sound or signal generated by random fluctuations.\n[n.] Unwanted part of a signal.\n[v.] To make a noise; to sound.\n[v.] To spread news of; to spread as rumor or gossip.","ex":"He knew that it was trash day, when the garbage collectors made all the noise."},"NOMAD":{"p":"/ˈnəʊmæd/","s":"n./adj.","e":"[n.] A member of a society or class who herd animals from pasture to pasture with no fixed home.\n[n.] A person who changes residence frequently.\n[n.] A player who changes teams frequently.\n[adj.] Of or relating to nomads, whether\n[n.] One who wanders, who travels aimlessly.\n[n.] Any of various far-migrating nymphalid butterflies of the genus Danaus.","ex":""},"NONE":{"p":"/nɒn/","s":"n./adv./pron.","e":"[n.] A person without religious affiliation.\n[adv.] To no extent, in no way.\n[adv.] Not at all, not very.\n[adv.] No, not.\n[pron.] Not any of a given number or group.","ex":"I felt none the worse for my recent illness."},"NOON":{"p":"/nuːn/","s":"n./v.","e":"[n.] The ninth hour of the day counted from sunrise; around three o'clock in the afternoon.\n[n.] Time of day when the sun is in its zenith; twelve o'clock in the day, midday.\n[n.] The corresponding time in the middle of the night; midnight.\n[v.] To relax or sleep around midday","ex":"1885, When night was at its noon I heard a voice chanting the Koran in sweetest accents — Sir Richard Burton, The Book of the Thousand Nights and One Night, Night 17:"},"NOOSE":{"p":"/nuːs/","s":"n./v.","e":"[n.] An adjustable loop of rope, such as the one placed around the neck in hangings, or the one at the end of a lasso.\n[v.] To tie or catch in a noose; to entrap or ensnare.","ex":""},"NORM":{"p":"/nɔːm/","s":"n.","e":"[n.] That which is normal or typical.\n[n.] A rule that is enforced by members of a community.\n[n.] A sentence with non-descriptive meaning, such as a command, permission or prohibition.","ex":"Unemployment is the norm in this part of the country."},"NORMAL":{"p":"/ˈnɔːməl/","s":"n./adj.","e":"[n.] A line or vector that is perpendicular to another line, surface, or plane.\n[n.] A person who is normal, who fits into mainstream society, as opposed to those who live alternative lifestyles.\n[n.] The usual state.\n[adj.] According to norms or rules or to a regular pattern.\n[adj.] Usual, healthy; not sick or ill or unlike oneself.\n[adj.] (of a school) teaching teachers how to teach (to certain norms)","ex":"Heavy workload is the new normal."},"NORTH":{"p":"/noːθ/","s":"n./v./adj./adv.","e":"[n.] One of the four major compass points, specifically 0°, directed toward the North Pole, and conventionally upwards on a map, abbreviated as N.\n[n.] The up or positive direction.\n[n.] The positive or north pole of a magnet, which seeks the magnetic pole near Earth's geographic North Pole (which, for its magnetic properties, is a south pole).\n[v.] To turn or move toward the north.\n[adj.] Of or pertaining to the north; northern.\n[adj.] Toward the north; northward.","ex":"Minnesota is in the north of the USA."},"NOSE":{"p":"/nəʊz/","s":"n./v.","e":"[n.] A protuberance on the face housing the nostrils, which are used to breathe or smell.\n[n.] A snout, the nose of an animal.\n[n.] The tip of an object.\n[v.] To move cautiously by advancing its front end.\n[v.] To snoop.\n[v.] To detect by smell or as if by smell.","ex":"She has a cold in the nose."},"NOSEY":{"p":"","s":"n./adj.","e":"[n.] A look at something to satisfy one's curiosity.\n[adj.] Prying, inquisitive or curious in other’s affairs; tending to snoop or meddle.\n[adj.] Having a large or elongated nose.","ex":"I might wander down to the construction site for a nosy at what they're building."},"NOTCH":{"p":"/nɒtʃ/","s":"n./v.","e":"[n.] A V-shaped cut.\n[n.] An indentation.\n[n.] A mountain pass; a defile.\n[v.] To cut a notch in (something).\n[v.] To record (a score or similar) by making notches on something.\n[v.] To join by means of notches.","ex":"The tribe's hunters notch their kills by notches on each's axe's handle."},"NOTABLE":{"p":"/ˈnəʊtəbl̩/","s":"n./adj.","e":"[n.] A person or thing of distinction.\n[adj.] Worthy of note; remarkable; memorable; noted or distinguished.\n[adj.] Easily noted (without connotations of value); clearly noticeable, conspicuous.\n[adj.] That can be observed; perceptible.","ex":""},"NOTE":{"p":"/nəʊt/","s":"n./v.","e":"[n.] (heading) A symbol or annotation.\n[n.] (heading) A written or printed communication or commitment.\n[n.] (heading) A sound.\n[v.] To notice with care; to observe; to remark; to heed.\n[v.] To record in writing; to make a memorandum of.\n[v.] To denote; to designate.","ex":"If you look to the left, you can note the old cathedral."},"NOTHING":{"p":"/ˈnʌθɪŋ/","s":"n./adv./pron.","e":"[n.] Something trifling, or of no consequence or importance.\n[n.] A trivial remark (especially in the term sweet nothings).\n[n.] A nobody (insignificant person).\n[adv.] Not at all; in no way.\n[pron.] Not any thing; no thing.\n[pron.] An absence of anything, including empty space, brightness, darkness, matter, or a vacuum.","ex":"You're nothing to me now!"},"NOTICE":{"p":"/ˈnəʊtɪs/","s":"n./v.","e":"[n.] The act of observing; perception.\n[n.] A written or printed announcement.\n[n.] A formal notification or warning.\n[v.] To remark upon; to mention.\n[v.] To become aware of; to observe.\n[v.] To lavish attention upon; to treat (someone) favourably.","ex":"He took no notice of the changes, and went on as though nothing had happened."},"NOUN":{"p":"/naʊn/","s":"n./v.","e":"[n.] (grammar, narrow sense) A word that can be used to refer to a person, animal, place, thing, phenomenon, substance, quality, or idea; one of the basic parts of speech in many languages, including English.\n[n.] (grammar, now rare, broad sense) Either a word that can be used to refer to a person, animal, place, thing, phenomenon, substance, quality or idea, or a word that modifies or describes a previous word or its referent; a substantive or adjective, sometimes also including other parts of speech such as numeral or pronoun.\n[v.] To convert a word to a noun.","ex":""},"NOVEL":{"p":"/ˈnɒvl̩/","s":"adj.","e":"[adj.] Newly made, formed or evolved; having no precedent; of recent origin; new.\n[adj.] Original, especially in an interesting way; new and striking; not of the typical or ordinary type.","ex":""},"NUDGE":{"p":"/nʌdʒ/","s":"n./v.","e":"[n.] A gentle push.\n[n.] A feature of instant messaging software used to get the attention of another user, as by shaking the conversation window or playing a sound.\n[n.] The rotation by one step of a fruit machine reel of the player's choice.\n[v.] To push against gently, especially in order to gain attention or give a signal.\n[v.] To near or come close to something.","ex":"Since the machine was showing two lemons and a cherry, I decided to try a nudge."},"NUCLEAR":{"p":"/ˈn(j)ukliɚ/","s":"n./adj.","e":"[n.] Nuclear power\n[adj.] Pertaining to the nucleus of an atom.\n[adj.] Involving energy released by nuclear reactions (fission, fusion, radioactive decay).\n[adj.] Relating to a weapon that derives its force from rapid release of energy through nuclear reactions.","ex":"a nuclear reactor"},"NUDE":{"p":"/n(j)uːd/","s":"n./adj.","e":"[n.] A painting, sculpture, photograph or other artwork or mass-media-reproduced image depicting one or more human figure(s) in a state of near or total undress.\n[n.] (with article, \"the nude\") The state of total nudity.\n[n.] A color that resembles or evokes bare flesh; a paint, dye, etc. of such color.\n[adj.] Without clothing or other covering of the skin; without clothing on the genitals or female nipples.\n[adj.] Characterized by the nudity of people concerned or to whom the described noun is attributed.\n[adj.] (of clothing, makeup, etc) Of a color (such as beige or tan) that evokes bare flesh.","ex":"Lexa sent me a nude last week."},"NUMBER":{"p":"/ˈnʌmbə/","s":"n./v.","e":"[n.] An abstract entity used to describe quantity.\n[n.] A numeral: a symbol for a non-negative integer.\n[n.] An element of one of several sets: natural numbers, integers, rational numbers, real numbers, complex numbers, and sometimes extensions such as hypercomplex numbers, etc.\n[v.] To label (items) with numbers; to assign numbers to (items).\n[v.] To total or count; to amount to.","ex":"Zero, one, −1, 2.5, and pi are all numbers."},"NURSE":{"p":"/nɜːs/","s":"n./v.","e":"[n.] A wet nurse.\n[n.] A person (usually a woman) who takes care of other people’s young.\n[n.] A person trained to provide care for the sick.\n[v.] To breastfeed: to feed (a baby) at the breast; to suckle.\n[v.] To breastfeed: to be fed at the breast.\n[v.] To care for (someone), especially in sickness; to tend to.","ex":"They hired a nurse to care for their young boy."},"NURSING":{"p":"/ˈnɜːsɪŋ/","s":"v./n./adj.","e":"[v.] To breastfeed: to feed (a baby) at the breast; to suckle.\n[v.] To breastfeed: to be fed at the breast.\n[v.] To care for (someone), especially in sickness; to tend to.\n[n.] Suckling, such as breastfeeding.\n[n.] The process or profession of caring for patients as a nurse.\n[adj.] In the state of suckling young, lactating.","ex":"She believes that nursing her baby will make him strong and healthy."},"NUTS":{"p":"/nʌts/","s":"n./v./adj./int.","e":"[n.] A hard-shelled seed.\n[n.] A piece of metal, usually square or hexagonal in shape, with a hole through it having machined internal threads, intended to be screwed onto a bolt or other threaded shaft.\n[n.] A crazy person.\n[v.] (mostly in the form \"nutting\") To gather nuts.\n[v.] To hit deliberately with the head; to headbutt.\n[v.] (mildly) To orgasm; to ejaculate.","ex":"There are many sort of nuts: peanuts, cashews, pistachios, Brazil nuts and more."},"NYMPH":{"p":"/ˈnɪmf/","s":"n.","e":"[n.] (Greek, Roman) Any female nature spirit associated with water, forests, grotto, wind, etc.\n[n.] A young girl, especially one who is attractive, beautiful or graceful.\n[n.] The larva of certain insects.","ex":""},"NYLON":{"p":"/ˈnaɪlɒn/","s":"n.","e":"[n.] Originally, the DuPont company trade name for polyamide, a copolymer whose molecules consist of alternating diamine and dicarboxylic acid monomers bonded together; now generically used for this type of polymer.\n[n.] (in the plural) A stocking originally fabricated from nylon; also used generically for any long, sheer stocking worn on a woman's legs.","ex":"I tore a hole in my nylons while walking home through the woods."},"NUTTY":{"p":"/ˈnʌti/","s":"adj.","e":"[adj.] Containing nuts.\n[adj.] Resembling or characteristic of nuts.\n[adj.] Barmy, crazy, mad.","ex":"This is a nutty chocolate bar."},"OAKEN":{"p":"/əʊk.ən/","s":"adj.","e":"[adj.] Made from the wood of the oak tree. Also in metaphorical uses, suggesting robustness.","ex":""},"OASIS":{"p":"/əʊˈeɪsəs/","s":"n.","e":"[n.] A spring of fresh water, surrounded by a fertile region of vegetation, in a desert.\n[n.] A quiet, peaceful place or situation separated from surrounding noise or bustle.","ex":"The park was an oasis in the middle of the busy city."},"OATH":{"p":"/ˈəʊθ/","s":"n./v.","e":"[n.] A solemn pledge or promise, appealing to a deity, a ruler, or another entity (not necessarily present) to attest to the truth of a statement or sincerity of one's desire to fulfill a contract or promise.\n[n.] A statement or promise which is strengthened (affirmed) by such a pledge.\n[n.] A light, irreverent or insulting appeal to a deity or other entity.\n[v.] To pledge.","ex":"After taking the oath of office, she became the country's forty-third premier."},"OBESE":{"p":"/əʊˈbiːs/","s":"adj.","e":"[adj.] Extremely overweight, especially: weighing more than 20% (for men) or 25% (for women) over their ideal weight determined by height and build; or, having a body mass index over 30 kg/m2.","ex":""},"OBEY":{"p":"/əʊˈbeɪ/","s":"v.","e":"[v.] To do as ordered by (a person, institution etc), to act according to the bidding of.\n[v.] To do as one is told.\n[v.] To be obedient, compliant (to a given law, restriction etc.).","ex":""},"OBJECT":{"p":"/ˈɒb.d͡ʒɛkt/","s":"n./v.","e":"[n.] A thing that has physical existence.\n[n.] Objective; the goal, end or purpose of something.\n[n.] (grammar) The noun phrase which is an internal complement of a verb phrase or a prepositional phrase. In a verb phrase with a transitive action verb, it is typically the receiver of the action.\n[v.] To disagree with or oppose something or someone; (especially in a Court of Law) to raise an objection.\n[v.] To offer in opposition as a criminal charge or by way of accusation or reproach; to adduce as an objection or adverse reason.\n[v.] To set before or against; to bring into opposition; to oppose.","ex":"I object to the proposal to build a new airport terminal."},"OCTAL":{"p":"/ˈɒk.təl/","s":"n./adj.","e":"[n.] The number system that uses the eight digits 0, 1, 2, 3, 4, 5, 6, 7.\n[n.] A digit or value in the octal number system.\n[adj.] Concerning numbers expressed in octal or mathematical calculations performed using octal.","ex":""},"OCCUR":{"p":"/əˈkɜː/","s":"v.","e":"[v.] To happen or take place.\n[v.] To present or offer itself.\n[v.] To come or be presented to the mind; to suggest itself.","ex":"The liftoff will occur in exactly twelve seconds."},"OBVIOUS":{"p":"/ˈɒ.vɪəs/","s":"adj.","e":"[adj.] Easily discovered, seen, or understood; self-explanatory.","ex":""},"OBTAIN":{"p":"/əbˈteɪn/","s":"v.","e":"[v.] To get hold of; to gain possession of, to procure; to acquire, in any way.\n[v.] To secure (that) a specific objective or state of affairs be reached.\n[v.] To prevail, be victorious; to succeed.","ex":""},"OCEAN":{"p":"/ˈəʊ.ʃən/","s":"n.","e":"[n.] One of the large bodies of water separating the continents.\n[n.] Water belonging to an ocean.\n[n.] An immense expanse; any vast space or quantity without apparent limits.","ex":"The island is surrounded by ocean"},"OCTET":{"p":"/ɒkˈtɛt/","s":"n.","e":"[n.] A group or set of eight of something.\n[n.] A group of eight musicians performing together.\n[n.] A composition for such a group of musicians.","ex":"An octet of waiters sang her \"Happy Birthday\"."},"ODDER":{"p":"/ˈɑd.ɚ/","s":"adj.","e":"[adj.] Differing from what is usual, ordinary or expected.\n[adj.] Without a corresponding mate in a pair or set; unmatched; (of a pair or set) mismatched.\n[adj.] Left over, remaining after the rest have been paired or grouped.","ex":"She slept in, which was very odd."},"ODDLY":{"p":"","s":"adv.","e":"[adv.] In a peculiar manner; strangely; unusually.\n[adv.] In a manner measured by an odd number.","ex":"For December, it was oddly warm."},"ODDS":{"p":"/ɒdz/","s":"n.","e":"[n.] (diminutive) An odd number.\n[n.] Something left over, not forming part of a set.\n[n.] The ratio of the probability of an event happening to that of it not happening.\n[n.] The ratio of winnings to stake in betting situations.","ex":"So let's see. There are two evens here and three odds."},"OFFICE":{"p":"/ˈɑfɪs/","s":"n./v.","e":"[n.] A ceremonial duty or service, particularly:\n[n.] A position of responsibility.\n[n.] Official position, particularly high employment within government; tenure in such a position.\n[v.] To provide (someone) with an office.\n[v.] To have an office.","ex":"When the office of Secretary of State is vacant, its duties fall upon an official within the department."},"OFFEND":{"p":"/əˈfɛnd/","s":"v.","e":"[v.] To hurt the feelings of; to displease; to make angry; to insult.\n[v.] To feel or become offended; to take insult.\n[v.] To physically harm, pain.","ex":"Your accusations offend me deeply."},"OFFENSE":{"p":"/əˈfɛns/","s":"n.","e":"[n.] The act of offending:\n[n.] The state of being offended or displeased; anger; displeasure.\n[n.] A strategy and tactics employed when in position to score; contrasted with defense.","ex":""},"OFFER":{"p":"/ˈɑfɚ/","s":"n.","e":"[n.] A proposal that has been made.\n[n.] Something put forth, bid, proffered or tendered.\n[n.] An invitation to enter into a binding contract communicated to another party which contains terms sufficiently definite to create an enforceable contract if the other party accepts the invitation.","ex":"I decline your offer to contract."},"OFTEN":{"p":"/ˈɑf(t)ən/","s":"adj./adv.","e":"[adj.] Frequent.\n[adv.] Frequently, many times.","ex":"I often walk to work when the weather is nice."},"OFFAL":{"p":"/ˈɑfl̩/","s":"n.","e":"[n.] The internal organs of an animal, used as animal food.\n[n.] A by-product of the grain milling process, which may include bran, husks, etc.\n[n.] A dead body; carrion.","ex":""},"OLDEN":{"p":"/ˈəʊl.dn̩/","s":"adj.","e":"[adj.] From or relating to a previous era.\n[adj.] Old; ancient.","ex":"olden days, olden times"},"OFFICER":{"p":"/ˈɑfɪsɚ/","s":"n./v.","e":"[n.] One who has a position of authority in a hierarchical organization, especially in military, police or government organizations.\n[n.] A respectful term of address for an officer, especially a police officer.\n[n.] One who holds a public office.\n[v.] To supply with officers.\n[v.] To command like an officer.","ex":""},"OKAY":{"p":"/ˌəˈkæɪ/","s":"n./v./adj./adv./int.","e":"[n.] Endorsement; approval.\n[v.] To approve.\n[v.] To confirm by activating a button marked OK.\n[adj.] All right, permitted.\n[adj.] Satisfactory, reasonably good; not exceptional.\n[adj.] In good health or a good emotional state.","ex":"We can start as soon as we get the OK."},"OMEGA":{"p":"/ˈəʊmiːɡə/","s":"n.","e":"[n.] The twenty-fourth letter of the Classical and the Modern Greek alphabet, and the twenty-eighth letter of the Old and the Ancient Greek alphabet, i.e. the last letter of every Greek alphabet. Uppercase version: Ω; lowercase: ω.\n[n.] (often capitalized) The end; the final, last or ultimate in a sequence.\n[n.] Angular velocity; symbol: ω.","ex":""},"OMBRE":{"p":"","s":"n.","e":"[n.] A large Mediterranean food fish Umbrina cirrosa","ex":""},"OLIVE":{"p":"/ˈɒlɪv/","s":"n./adj.","e":"[n.] A tree, Olea europaea, cultivated since ancient times in the Mediterranean for its fruit and the oil obtained from it.\n[n.] The small oval fruit of this tree, eaten ripe (usually black) or unripe (usually green).\n[n.] The wood of the olive tree.\n[adj.] Of a grayish green color, that of an unripe olive.","ex":""},"ONCE":{"p":"/wɒn(t)s/","s":"adv./conj.","e":"[adv.] (frequency) One and only one time.\n[adv.] (temporal location) Formerly; during some period in the past.\n[adv.] Multiplied by one: indicating that a number is multiplied by one.\n[conj.] As soon as; when; after.","ex":"I have only once eaten pizza."},"ONION":{"p":"/ˈʌŋjɪn/","s":"n.","e":"[n.] A monocotyledonous plant (Allium cepa), allied to garlic, used as vegetable and spice.\n[n.] The bulb of such a plant.\n[n.] The genus as a whole.","ex":""},"OLDER":{"p":"/ˈəʊldə/","s":"adj.","e":"[adj.] Of an object, concept, relationship, etc., having existed for a relatively long period of time.\n[adj.] Having been used and thus no longer new or unused.\n[adj.] Having existed or lived for the specified time.","ex":"an old abandoned building;  an old friend"},"ONLINE":{"p":"/ɒnˈlaɪn/","s":"v./adj./adv.","e":"[v.] To bring (a system, etc.) online; to promote to an active or running state.\n[adj.] Of a system: connected (generally electrically) to a larger network.\n[adj.] Available over, or delivered from, the Internet.\n[adj.] Connected to the Internet.\n[adv.] While online; while in a running or active state, or connected to the Internet.","ex":"I prefer to read online newspapers."},"OPERA":{"p":"/ˈɒp.əɹ.ə/","s":"n.","e":"[n.] A theatrical work, combining drama, music, song and sometimes dance.\n[n.] The score for such a work.\n[n.] A building designed for the performance of such works; an opera house.","ex":""},"ONSET":{"p":"/ˈɒnˌsɛt/","s":"n./v.","e":"[n.] An attack; an assault especially of an army.\n[n.] The initial phase of a disease or condition, in which symptoms first become apparent.\n[n.] The initial portion of a syllable, preceding the syllable nucleus.\n[v.] To assault; to set upon.\n[v.] To set about; to begin.","ex":"the onset of schizophrenia"},"ONTO":{"p":"/ˈɒn.tuː/","s":"adj./prep.","e":"[adj.] (of a function) Assuming each of the values in its codomain; having its range equal to its codomain.\n[prep.] Upon; on top of.\n[prep.] Aware of.\n[prep.] Being an onto function with a codomain of (see below).","ex":"Considered as a function on the real numbers, the exponential function is not onto."},"ONLY":{"p":"/ˈəʊn.li/","s":"n./adj./adv./conj.","e":"[n.] An only child.\n[adj.] Alone in a category.\n[adj.] Singularly superior; the best.\n[adj.] Without sibling; without a sibling of the same gender.\n[adv.] Without others or anything further; exclusively.\n[adv.] No more than; just.","ex":"He is the only doctor for miles."},"OPEN":{"p":"/ˈəʊ.pən/","s":"adj.","e":"[adj.] Not closed\n[adj.] Not physically drawn together, closed, folded or contracted; extended\n[adj.] Actively conducting or prepared to conduct business.","ex":"an open hand; an open flower"},"OPERATE":{"p":"/ˈɒpəɹeɪt/","s":"v.","e":"[v.] To perform a work or labour; to exert power or strength, physical or mechanical; to act.\n[v.] To produce an appropriate physical effect; to issue in the result designed by nature; especially to take appropriate effect on the human system.\n[v.] To act or produce effect on the mind; to exert moral power or influence.","ex":""},"NOBLY":{"p":"/ˈnəʊbli/","s":"adv.","e":"[adv.] In a noble manner.","ex":"In the end he died nobly, trying to save the lives of others."},"OPINE":{"p":"/ə(ʊ)ˈpaɪn/","s":"v.","e":"[v.] To have or express an opinion; to state as an opinion; to suppose, consider (that).\n[v.] To give one's formal opinion (on or upon something).","ex":"\"Your decisions,\" she opined, \"have been unfailingly disastrous for this company.\""},"OPINION":{"p":"/əˈpɪnjən/","s":"n./v.","e":"[n.] A subjective belief, judgment or perspective that a person has formed about a topic, issue, person or thing.\n[n.] The judgment or sentiment which the mind forms of persons or things; estimation.\n[n.] Favorable estimation; hence, consideration; reputation; fame; public sentiment or esteem.\n[v.] To have or express as an opinion.","ex":"Every man is a fool in some man's opinion."},"ORANGE":{"p":"/ˈɔɹɪ̈nd͡ʒ/","s":"n./v./adj.","e":"[n.] An evergreen tree of the genus Citrus such as Citrus sinensis.\n[n.] The fruit of an orange tree; a citrus fruit with a slightly sour flavour.\n[n.] The colour of a ripe fruit of an orange tree, midway between red and yellow.\n[v.] To color orange.\n[v.] To become orange.\n[adj.] Having the colour of the fruit of an orange tree; yellowred; reddish-yellow.","ex":""},"OPIUM":{"p":"/ˈəʊpi.əm/","s":"n.","e":"[n.] A yellow-brown, addictive narcotic drug obtained from the dried juice of unripe pods of the opium poppy, Papaver somniferum, and containing alkaloids such as morphine, codeine, and papaverine.\n[n.] Anything that numbs or stupefies.","ex":""},"OPTIC":{"p":"/ˈɒptɪk/","s":"n./adj.","e":"[n.] An eye.\n[n.] A lens or other part of an optical instrument that interacts with light.\n[n.] A measuring device with a small window, attached to an upside-down bottle, used to dispense alcoholic drinks in a bar.\n[adj.] Of, or relating to the eye or to vision.\n[adj.] Of, or relating to optics or optical instruments.","ex":""},"OPTION":{"p":"/ˈɒpʃən/","s":"n./v.","e":"[n.] One of a set of choices that can be made.\n[n.] The freedom or right to choose.\n[n.] A contract giving the holder the right to buy or sell an asset at a set strike price; can apply to financial market transactions, or to ordinary transactions for tangible assets such as a residence or automobile.\n[v.] To purchase an option on something.\n[v.] To configure, by setting an option.","ex":"The new novel was optioned by the film studio, but they'll probably never decide to make a movie from it."},"ORBIT":{"p":"/ˈɔː(ɹ)bɪt/","s":"n./v.","e":"[n.] A circular or elliptical path of one object around another object, particularly in astronomy and space travel.\n[n.] A sphere of influence; an area of control.\n[n.] The course of one's usual progression, or the extent of one's typical range.\n[v.] To circle or revolve around another object.\n[v.] To move around the general vicinity of something.\n[v.] To place an object into an orbit around a planet.","ex":"The Moon's orbit around the Earth takes nearly one month to complete."},"ORAL":{"p":"/ˈɒɹəl/","s":"n./adj.","e":"[n.] A spoken test or examination, particularly in a language class.\n[n.] A physical examination of the mouth.\n[n.] Oral sex.\n[adj.] Relating to the mouth.\n[adj.] Spoken rather than written.","ex":"We've got our Spanish oral tomorrow."},"ORATE":{"p":"/ɒɹˈeɪt/","s":"v./adj.","e":"[v.] To speak formally; to give a speech.\n[v.] To speak passionately; to preach for or against something.\n[adj.] Competent in oracy; having good speaking skills.","ex":""},"ORDER":{"p":"/ˈɔːdə/","s":"n./v.","e":"[n.] Arrangement, disposition, or sequence.\n[n.] A position in an arrangement, disposition, or sequence.\n[n.] The state of being well arranged.\n[v.] To set in some sort of order.\n[v.] To arrange, set in proper order.\n[v.] To issue a command to.","ex":"The house is in order; the machinery is out of order."},"ORGAN":{"p":"/ˈɔː.ɡən/","s":"n./v.","e":"[n.] A larger part of an organism, composed of tissues that perform similar functions.\n[n.] (by extension) A body of an organization dedicated to the performing of certain functions.\n[n.] A musical instrument that has multiple pipes which play when a key is pressed (the pipe organ), or an electronic instrument designed to replicate such.\n[v.] To supply with an organ or organs; to fit with organs.","ex":"bodily organs"},"ORGANIC":{"p":"/ɔːˈɡænɪk/","s":"n./adj.","e":"[n.] An organic compound.\n[n.] An organic food.\n[n.] A living organism, as opposed to a robot or hologram.\n[adj.] Pertaining to or derived from living organisms.\n[adj.] Pertaining to an organ of the body of a living organism.\n[adj.] Relating to the compounds of carbon, relating to natural products.","ex":""},"ORIGIN":{"p":"/ˈɒɹ.ə.dʒən/","s":"n.","e":"[n.] The beginning of something.\n[n.] The source of a river, information, goods, etc.\n[n.] The point at which the axes of a coordinate system intersect.","ex":""},"OTHER":{"p":"/ˈɐðə/","s":"n./v./adj./adv.","e":"[n.] An other, another (person, etc), more often rendered as another.\n[n.] The other one; the second of two.\n[v.] To regard, label or treat as an \"other\", as not part of the same group; to view as different and alien.\n[v.] To treat as different or separate; segregate; ostracise.\n[adj.] See other (determiner) below\n[adj.] Second.","ex":"I'm afraid little Robbie does not always play well with others."},"OTTER":{"p":"/ˈɒt.ə/","s":"n.","e":"[n.] An aquatic or marine carnivorous mammal in the subfamily Lutrinae of the family Mustelidae, which also includes weasels, polecats, badgers, and others.\n[n.] A hairy man with a slender physique, in contrast with a bear, who is more thickset.","ex":""},"OUNCE":{"p":"/aʊns/","s":"n.","e":"[n.] An avoirdupois ounce, weighing 1/16 of an avoirdupois pound, or 28.3495 grams.\n[n.] A troy ounce, weighing 1/12 of a troy pound, or 480 grains, or 31.1035 grams.\n[n.] A US fluid ounce, with a volume of 1/16 of a US pint, 1.8047 cubic inches or 29.5735 millilitres.","ex":""},"OURS":{"p":"/ɑːz/","s":"pron.","e":"[pron.] That which belongs to us; the possessive case of we, used without a following noun.","ex":""},"OUTDO":{"p":"/aʊtˈdu/","s":"v.","e":"[v.] To excel; go beyond in performance; surpass.","ex":""},"OUTER":{"p":"/ˈaʊtə/","s":"n./adj.","e":"[n.] An outer part.\n[n.] The 4th circle on a target, outside the inner and magpie.\n[n.] A shot which strikes the outer of a target.\n[adj.] Outside; external.\n[adj.] Farther from the centre of the inside.","ex":""},"OUGHT":{"p":"","s":"n.","e":"[n.] Property; possession\n[n.] Duty; place; office","ex":""},"OUTGO":{"p":"/aʊtˈɡəʊ/","s":"n./v.","e":"[n.] The act or process of going out.\n[n.] A quantity of a substance or thing that has flowed out; an outflow.\n[n.] An expenditure, cost or outlay.\n[v.] To go out, to set forth.\n[v.] To go further; to exceed or surpass; go beyond.\n[v.] To overtake; to travel faster than.","ex":""},"OUTFIT":{"p":"/ˈaʊtfɪt/","s":"n./v.","e":"[n.] A set of clothing (with accessories).\n[n.] Gear consisting of a set of articles or tools for a specified purpose.\n[n.] Any cohesive group of people; a unit; such as a military company.\n[v.] To provide with, usually for a specific purpose.","ex":"She wore a fashionable outfit with matching purse and shoes."},"OUTLINE":{"p":"/ˈaʊtlaɪn/","s":"n./v.","e":"[n.] A line marking the boundary of an object figure.\n[n.] The outer shape of an object or figure.\n[n.] A sketch or drawing in which objects are delineated in contours without shading.\n[v.] To draw an outline of.\n[v.] To summarize.","ex":"Wikipedia items featuring books usually outline them after giving their background."},"OUTLOOK":{"p":"/ˈaʊtˌlʊk/","s":"n./v.","e":"[n.] A place from which something can be viewed.\n[n.] The view from such a place.\n[n.] An attitude or point of view.\n[v.] To face or look in an outward direction.\n[v.] To look at (someone) so long or intently that they look away; to win or prevail over (someone or something).\n[v.] To be more attractive than (someone or something).","ex":"Perched on the edge of the cliff was a hidden outlook."},"OUTSIDE":{"p":"","s":"n./adj./adv./prep.","e":"[n.] The part of something that faces out; the outer surface.\n[n.] The external appearance of someone or something.\n[n.] The space beyond some limit or boundary.\n[adj.] Of or pertaining to the outer surface, limit or boundary.\n[adj.] Of, pertaining to or originating from beyond the outer surface, limit or boundary.\n[adj.] Away from the interior or center of something.","ex":"He's repainting the outside of his house."},"OUTPUT":{"p":"/ˈaʊtpʊt/","s":"n./v.","e":"[n.] Production; quantity produced, created, or completed.\n[n.] Data sent out of the computer, as to output device such as a monitor or printer, or data sent from one program on the computer to another.\n[n.] The flow rate of body liquids such as blood and urine.\n[v.] To produce, create, or complete.\n[v.] To send data out of a computer, as to an output device such as a monitor or printer, or to send data from one program on the computer to another.","ex":"The factory increased its output this year."},"OUTRE":{"p":"","s":"adj.","e":"[adj.] Beyond what is customary or proper; extravagant.\n[adj.] Very unconventional.","ex":""},"OVATE":{"p":"/ˈəʊveɪt/","s":"adj.","e":"[adj.] Shaped like an egg.\n[adj.] (of leaves) With the broadest extremity near the base.","ex":""},"OVARY":{"p":"/ˈəʊvəɹi/","s":"n.","e":"[n.] A female reproductive organ, often paired, that produces ova and in mammals secretes the hormones estrogen and progesterone.\n[n.] The lower part of a pistil or carpel that bears ovules and ripens into fruit.","ex":"The male testicles are homologous to the female ovaries."},"OVER":{"p":"/ˈəʊ.və(ɹ)/","s":"n./v./adj./adv./prep./int.","e":"[n.] A set of six legal balls bowled.\n[n.] Any surplus amount of money, goods delivered, etc.\n[v.] To go over, or jump over.\n[v.] To run about.\n[adj.] Discontinued; ended or concluded.\n[adv.] Thoroughly; completely; from beginning to end.","ex":"He overed the fence in good style."},"OVERALL":{"p":"","s":"n./adj./adv.","e":"[n.] A garment worn over other clothing to protect it; a coverall or boiler suit. A garment, for manual labor or for casual wear, often made of a single piece of fabric, with long legs and a bib upper, supported from the shoulders with straps, and having several large pockets and loops for carrying tools.\n[n.] (in the plural) A garment, worn for manual labor, with an integral covering extending to the chest, supported by straps.\n[adj.] All-encompassing, all around.\n[adv.] Generally; with everything considered.","ex":"Overall, there is not enough evidence to form a clear conclusion."},"OVERT":{"p":"/ə(ʊ)ˈvɜːt/","s":"adj.","e":"[adj.] Open and not concealed or secret.","ex":""},"OWING":{"p":"/ˈəʊ.ɪŋ/","s":"v./adj.","e":"[v.] To be under an obligation to give something back to someone or to perform some action for someone.\n[v.] To have debt; to be in debt.\n[adj.] Still to be paid; owed as a debt.","ex":"These seven subscriptions remain owing."},"OXFORD":{"p":"/ˈɒksfəd/","s":"n.","e":"[n.] A variety of shoe, typically made of heavy leather.\n[n.] (by ellipsis) An Oxford Dictionary.","ex":""},"OVOID":{"p":"","s":"n./adj.","e":"[n.] Something that is oval in shape.\n[adj.] Shaped like an oval.\n[adj.] Egg-shaped; shaped like an oval, but more tapered at one end; ovate.","ex":""},"OWNER":{"p":"/ˈəʊnə/","s":"n.","e":"[n.] One who owns something.\n[n.] The captain of a ship.","ex":"The police recovered the stolen car and returned it to its owner."},"OXIDE":{"p":"/ˈɒksaɪd/","s":"n.","e":"[n.] A binary chemical compound of oxygen with another chemical element.","ex":""},"OVINE":{"p":"/ˈoʊvaɪn/","s":"n./adj.","e":"[n.] A sheep.\n[adj.] Of, pertaining to, resembling, or being a sheep\n[adj.] (by extension) resembling a sheep in character; passive, of low intelligence and acquiescent","ex":""},"PACKAGE":{"p":"/ˈpækɪdʒ/","s":"n./v.","e":"[n.] Something which is packed, a parcel, a box, an envelope.\n[n.] Something which consists of various components, such as a piece of computer software.\n[n.] A piece of software which has been prepared in such a way that it can be installed with a package manager.\n[v.] To pack or bundle something.\n[v.] To travel on a package holiday.\n[v.] To prepare (a book, a television series, etc.), including all stages from research to production, in order to sell the result to a publisher or broadcaster.","ex":"Did you test the software package to ensure completeness?"},"PACK":{"p":"/pæk/","s":"n.","e":"[n.] A bundle made up and prepared to be carried; especially, a bundle to be carried on the back, but also a load for an animal, a bale.\n[n.] A number or quantity equal to the contents of a pack\n[n.] A multitude.","ex":"The horses carried the packs across the plain."},"PACKED":{"p":"/pækt/","s":"v./adj.","e":"[v.] (physical) To put or bring things together in a limited or confined space, especially for storage or transport.\n[v.] (social) To cheat.\n[v.] To load with a pack\n[adj.] Put into a package.\n[adj.] Filled with a large number or large quantity of something.\n[adj.] Filled to capacity with people.","ex":"to pack a horse"},"PADDY":{"p":"/ˈpædi/","s":"n.","e":"[n.] Rough or unhusked rice, either before it is milled or as a crop to be harvested.\n[n.] A paddy field, a rice paddy; an irrigated or flooded field where rice is grown.","ex":""},"PACE":{"p":"/peɪs/","s":"n./v./adj.","e":"[n.] Step.\n[n.] Way of stepping.\n[n.] Speed or velocity in general.\n[v.] To walk back and forth in a small distance.\n[v.] To set the speed in a race.\n[v.] To measure by walking.","ex":""},"PAGAN":{"p":"/ˈpeɪɡən/","s":"n./adj.","e":"[n.] A person not adhering to a main world religion; a follower of a pantheistic or nature-worshipping religion.\n[n.] (by extension) An uncivilized or unsocialized person.\n[n.] (by extension) An unruly, badly educated child.\n[adj.] Relating to, characteristic of religions that differ from main world religions.\n[adj.] (by extension) Savage, immoral, uncivilized, wild.","ex":"This community has a surprising number of pagans."},"PAGE":{"p":"/peɪd͡ʒ/","s":"n./v.","e":"[n.] One of the many pieces of paper bound together within a book or similar document.\n[n.] One side of a paper leaf on which one has written or printed.\n[n.] Any record or writing; a collective memory.\n[v.] To mark or number the pages of, as a book or manuscript.\n[v.] (often with “through”) To turn several pages of a publication.\n[v.] To furnish with folios.","ex":"the page of history"},"PAID":{"p":"/ˈpeɪd/","s":"v.","e":"[v.] To give money or other compensation to in exchange for goods or services.\n[v.] To discharge, as a debt or other obligation, by giving or doing what is due or required.\n[v.] To be profitable for.","ex":"he paid her off the books and in kind where possible"},"PAIN":{"p":"/peɪn/","s":"n./v.","e":"[n.] An ache or bodily suffering, or an instance of this; an unpleasant sensation, resulting from a derangement of functions, disease, or injury by violence; hurt.\n[n.] The condition or fact of suffering or anguish especially mental, as opposed to pleasure; torment; distress\n[n.] (from pain in the neck) An annoying person or thing.\n[v.] To hurt; to put to bodily uneasiness or anguish; to afflict with uneasy sensations of any degree of intensity; to torment; to torture.\n[v.] To render uneasy in mind; to disquiet; to distress; to grieve.\n[v.] To inflict suffering upon as a penalty; to punish.","ex":"I had to stop running when I started getting pains in my feet."},"PALACE":{"p":"/ˈpæləs/","s":"n./v.","e":"[n.] Official residence of a head of state or other dignitary, especially in a monarchical or imperial governmental system.\n[n.] A large and lavishly ornate residence.\n[n.] A large, ornate public building used for entertainment or exhibitions.\n[v.] To decorate or ornate.","ex":""},"PALE":{"p":"/peɪl/","s":"n./v./adj.","e":"[n.] Paleness; pallor.\n[v.] To turn pale; to lose colour.\n[v.] To become insignificant.\n[v.] To make pale; to diminish the brightness of.\n[adj.] Light in color.\n[adj.] (of human skin) Having a pallor (a light color, especially due to sickness, shock, fright etc.).","ex":"I have pale yellow wallpaper."},"PACIFIC":{"p":"/pəˈsɪfɪk/","s":"adj.","e":"[adj.] Calm, peaceful.\n[adj.] Preferring peace by nature; avoiding violence.","ex":""},"PAINTED":{"p":"/ˈpeɪntɪd/","s":"v./adj.","e":"[v.] To apply paint to.\n[v.] To apply in the manner that paint is applied.\n[v.] To cover (something) with spots of colour, like paint.\n[adj.] Coated with paint.\n[adj.] Depicted in paint.\n[adj.] Colorful, as if painted","ex":"The painted desert, painted turtle"},"PALM":{"p":"/ˈpæm/","s":"n.","e":"[n.] Any of various evergreen trees from the family Palmae or Arecaceae, which are mainly found in the tropics.\n[n.] A branch or leaf of the palm, anciently borne or worn as a symbol of victory or rejoicing.\n[n.] (by extension) Triumph; victory.","ex":""},"PALSY":{"p":"/ˈpɔːlzi/","s":"n./v.","e":"[n.] Complete or partial muscle paralysis of a body part, often accompanied by a loss of feeling and uncontrolled body movements such as shaking.\n[v.] To paralyse, either completely or partially.","ex":""},"PANEL":{"p":"/ˈpænəl/","s":"n./v.","e":"[n.] A (usually) rectangular section of a surface, or of a covering or of a wall, fence etc.\n[n.] A group of people gathered to judge, interview, discuss etc. as on a television or radio broadcast for example.\n[n.] An individual frame or drawing in a comic.\n[v.] To fit with panels.","ex":"Behind the picture was a panel on the wall."},"PAINT":{"p":"/peɪnt/","s":"n./v.","e":"[n.] A substance that is applied as a liquid or paste, and dries into a solid coating that protects or adds color/colour to an object or surface to which it has been applied.\n[n.] (in the plural) A set of containers or blocks of paint of different colors/colours, used for painting pictures.\n[n.] The free-throw lane, construed with the.\n[v.] To apply paint to.\n[v.] To apply in the manner that paint is applied.\n[v.] To cover (something) with spots of colour, like paint.","ex":"The Nimrods are strong on the outside, but not very good in the paint."},"OZONE":{"p":"/ˈoʊzoʊn/","s":"n./v.","e":"[n.] An allotrope of oxygen (symbol O₃) having three atoms in the molecule instead of the usual two; it is a blue gas, generated from oxygen by electrical discharge.\n[n.] Fresh air, especially that breathed at the seaside and smelling of seaweed.\n[v.] To treat with ozone.","ex":""},"PANSY":{"p":"/ˈpæn.zi/","s":"n./v./adj.","e":"[n.] A cultivated flowering plant, derived by hybridization within species Viola tricolor.\n[n.] A deep purple colour, like that of the pansy.\n[n.] Any of various nymphalid butterflies of the genus Junonia. Also called arguses.\n[v.] (usually with \"around\" or \"about\") To mess about; to fail to get things done.\n[adj.] Wimpy; spineless; feeble.\n[adj.] Of a deep purple colour, like that of the pansy.","ex":""},"PANTHER":{"p":"/ˈpænθə/","s":"n.","e":"[n.] Any of various big cats with black fur; most especially, the black-coated leopard of India.\n[n.] Any big cat of the genus Panthera.\n[n.] A cougar; especially the Florida panther.","ex":""},"PANTO":{"p":"/pæn.təʊ/","s":"n.","e":"[n.] A mechanical linkage based on parallelograms causing two objects to move in parallel; notably as a drawing aid.\n[n.] By extension, a structure of crosswise bars linked in such a way that it can extend and compress like an accordion, such as in a pantograph mirror or a scissor lift.\n[n.] A pattern printed on a document to reduce the ease of photocopying.\n[n.] A Classical comic actor, especially one who works mainly through gesture and mime.\n[n.] The drama in ancient Greece and Rome featuring such performers; or (later) any of various kinds of performance modelled on such work.\n[n.] A traditional theatrical entertainment, originally based on the commedia dell'arte, but later aimed mostly at children and involving physical comedy, topical jokes, call and response, and fairy-tale plots.","ex":"A pantograph can be adjusted to make either scaled or exact copies."},"PANTS":{"p":"/pænts/","s":"n./adj.","e":"[n.] (Manchester) An outer garment that covers the body from the waist downwards, covering each leg separately, usually as far as the ankles; trousers.\n[n.] An undergarment that covers the genitals and often the buttocks and the neighbouring parts of the body; underpants.\n[n.] Rubbish; something worthless.\n[adj.] Of inferior quality, rubbish.","ex":"The film was a load [or pile] of pants."},"PAPAL":{"p":"/ˈpeɪpəl/","s":"adj.","e":"[adj.] Having to do with the pope or the papacy.","ex":""},"PARENT":{"p":"/ˈpɛəɹənt/","s":"n./v.","e":"[n.] One of the two persons from whom one is immediately biologically descended; a mother or father.\n[n.] A surrogate mother\n[n.] A third person who has provided DNA samples in an IVF procedure in order to alter faulty genetic material\n[v.] To act as parent, to raise or rear.","ex":""},"PANT":{"p":"/pænt/","s":"n./v.","e":"[n.] A quick breathing; a catching of the breath; a gasp.\n[n.] Eager longing.\n[n.] A violent palpitation of the heart.\n[v.] To breathe quickly or in a labored manner, as after exertion or from eagerness or excitement; to respire with heaving of the breast; to gasp.\n[v.] To long eagerly; to desire earnestly.\n[v.] To long for (something); to be eager for (something).","ex":""},"PARSE":{"p":"/pɑːz/","s":"n./v.","e":"[n.] An act of parsing.\n[n.] The result of such an act.\n[v.] To resolve (a sentence, etc.) into its elements, pointing out the several parts of speech, and their relation to each other by agreement or government; to analyze and describe grammatically.\n[v.] To examine closely; to scrutinize.\n[v.] To split (a file or other input) into pieces of data that can be easily manipulated or stored.","ex":"The parse will fail if the program contains an unrecognised keyword."},"PARK":{"p":"[paːk]","s":"n./v.","e":"[n.] An area of land set aside for environment preservation or recreation.\n[n.] A wide, flat-bottomed valley in a mountainous region.\n[n.] An area used for specific purposes.\n[v.] To bring (something such as a vehicle) to a halt or store in a specified place.\n[v.] To defer (a matter) until a later date.\n[v.] To bring together in a park, or compact body.","ex":"I parked the drive heads of my hard disk before travelling with my laptop."},"PART":{"p":"/pɐːt/","s":"n./v./adj./adv.","e":"[n.] A portion; a component.\n[n.] Duty; responsibility.\n[n.] The dividing line formed by combing the hair in different directions.\n[v.] To leave the company of.\n[v.] To cut hair with a parting; shed.\n[v.] To divide in two.","ex":"to do one’s part"},"PARKA":{"p":"/ˈpɑːkə/","s":"n.","e":"[n.] A long jacket with a hood which protects the wearer against rain and wind.","ex":""},"PARTLY":{"p":"/ˈpɑːtli/","s":"adv.","e":"[adv.] In part, or to some degree, but not completely.","ex":"they partly finished the house so they could move in before winter;  the car was partly visible in the garage"},"PARTNER":{"p":"/ˈpɐːtnə/","s":"n./v.","e":"[n.] Someone who is associated with another in a common activity or interest.\n[n.] One of the pieces of wood comprising the framework which strengthens the deck of a wooden ship around the holes through which the mast and other fittings pass.\n[n.] A group financial arrangement in which each member contributes a set amount of money over a set period.\n[v.] To join as a partner.\n[v.] (often with with) To work or perform as a partner.","ex":""},"PASS":{"p":"[pʰäːs]","s":"v.","e":"[v.] To change place.\n[v.] To change in state or status\n[v.] To move through time.","ex":""},"PASSAGE":{"p":"/ˈpæsɪd͡ʒ/","s":"n./v./adj.","e":"[n.] A paragraph or section of text or music with particular meaning.\n[n.] Part of a path or journey.\n[n.] An incident or episode.\n[v.] To pass something, such as a pathogen or stem cell, through a host or medium\n[v.] To make a passage, especially by sea; to cross\n[adj.] Describing a bird that has left the nest, is living on its own, but is less than a year old. (commonly used in falconry)","ex":"She struggled to play the difficult passages."},"PASSIVE":{"p":"/ˈpæs.ɪv/","s":"n./adj.","e":"[n.] (grammar) The passive voice of verbs.\n[n.] (grammar) A form of a verb that is in the passive voice.\n[n.] A customer who is satisfied with a product or service, but not keen enough to promote it by word of mouth.\n[adj.] Being subjected to an action without producing a reaction.\n[adj.] Taking no action.\n[adj.] (grammar) Being in the passive voice.","ex":"He remained passive during the protest."},"PARTIAL":{"p":"/ˈpɑːʃəl/","s":"n./v./adj.","e":"[n.] A partial derivative: a derivative with respect to one independent variable of a function in multiple variables while holding the other variables constant.\n[n.] Any of the sine waves which make up a complex tone; often an overtone or harmonic of the fundamental.\n[n.] Dentures that replace only some of the natural teeth\n[v.] To take the partial regression coefficient.\n[adj.] Existing as a part or portion; incomplete\n[adj.] Describing a property that holds only when an algorithm terminates","ex":"So far, I have only pieced together a partial account of the incident."},"PASTA":{"p":"/ˈpɐːstə/","s":"n.","e":"[n.] Dough made from wheat and water and sometimes mixed with egg and formed into various shapes; often sold in dried form and typically boiled for eating.\n[n.] A dish or serving of pasta.\n[n.] A type of pasta.","ex":""},"PATCH":{"p":"/pætʃ/","s":"n./v.","e":"[n.] A piece of cloth, or other suitable material, sewed or otherwise fixed upon a garment to repair or strengthen it, especially upon an old garment to cover a hole.\n[n.] A small piece of anything used to repair damage or a breach; as, a patch on a kettle, a roof, etc.\n[n.] A piece of any size, used to repair something for a temporary period only, or that it is temporary because it is not meant to last long or will be removed as soon as a proper repair can be made, which will happen in the near future.\n[v.] To mend by sewing on a piece or pieces of cloth, leather, or the like\n[v.] To mend with pieces; to repair by fastening pieces on.\n[v.] To make out of pieces or patches, like a quilt.","ex":"His sleeves had patches on the elbows where different fabric had been sewn on to replace material that had worn away."},"PARKING":{"p":"/ˈpɑːkɪŋ/","s":"v./n.","e":"[v.] To bring (something such as a vehicle) to a halt or store in a specified place.\n[v.] To defer (a matter) until a later date.\n[v.] To bring together in a park, or compact body.\n[n.] The action of the verb to park.\n[n.] Space in which to park a car or other vehicle.","ex":"I parked the drive heads of my hard disk before travelling with my laptop."},"PARRY":{"p":"/ˈpæɹi/","s":"n./v.","e":"[n.] A defensive or deflective action; an act of parrying.\n[n.] A simple defensive action designed to deflect an attack, performed with the forte of the blade.\n[n.] (combat sports and martial arts) A defensive move intended to change the direction of an incoming strike to make it miss its intended target, rather than block and absorb it; and typically performed with an open hand in a downward or sideways slapping motion.\n[v.] To avoid, deflect, or ward off (an attack, a blow, an argument, etc.).","ex":""},"PATER":{"p":"/ˈpeɪtə/","s":"n.","e":"[n.] Father","ex":""},"PATROL":{"p":"/pəˈtɹəʊl/","s":"n.","e":"[n.] A going of the rounds along the chain of sentinels and between the posts, by a guard, usually consisting of three or four men, to insure greater security from attacks on the outposts.\n[n.] A movement, by a small body of troops beyond the line of outposts, to explore the country and gain intelligence of the enemy's whereabouts.\n[n.] The guards who go the rounds for observation; a detachment whose duty it is to patrol.","ex":""},"PATENT":{"p":"/ˈpeɪtənt/","s":"n./v.","e":"[n.] A declaration issued by a government agency declaring someone the inventor of a new invention and having the privilege of stopping others from making, using or selling the claimed invention; a letter patent.\n[n.] A specific grant of ownership of a piece of property; a land patent.\n[n.] License; formal permission.\n[v.] To successfully register an invention with a government agency; to secure a letter patent.","ex":""},"PATH":{"p":"[pʰäːθ]","s":"n./v.","e":"[n.] A trail for the use of, or worn by, pedestrians.\n[n.] A course taken.\n[n.] A Pagan tradition, for example witchcraft, Wicca, druidism, Heathenry.\n[v.] To make a path in, or on (something), or for (someone).","ex":"the path of a meteor, of a caravan, or of a storm"},"PARTY":{"p":"/ˈpɑ(ː)ɾi/","s":"n./v.","e":"[n.] A person or group of people constituting a particular side in a contract or legal action.\n[n.] A person.\n[n.] A group of people forming one side in a given dispute, contest etc.\n[v.] To celebrate at a party, to have fun, to enjoy oneself.\n[v.] To take recreational drugs.\n[v.] To engage in flings, to have one-night stands, to sow one's wild oats.","ex":"The contract requires that the party of the first part pay the fee."},"PATIENT":{"p":"/ˈpeɪʃənt/","s":"n./adj.","e":"[n.] A person or animal who receives treatment from a doctor or other medically educated person.\n[n.] (grammar) The noun or noun phrase that is semantically on the receiving end of a verb's action.\n[n.] One who, or that which, is passively affected; a passive recipient.\n[adj.] (of a person) Willing to wait if necessary; not losing one's temper while waiting.\n[adj.] Constant in pursuit or exertion; persevering; calmly diligent.\n[adj.] Physically able to suffer or bear.","ex":"The subject of a passive verb is usually a patient."},"PATTERN":{"p":"/ˈpat(ə)n/","s":"n./v.","e":"[n.] Model, example.\n[n.] A design, motif or decoration, especially formed from regular repeated elements.\n[n.] A naturally-occurring or random arrangement of shapes, colours etc. which have a regular or decorative effect.\n[v.] To apply a pattern.\n[v.] To make or design (anything) by, from, or after, something that serves as a pattern; to copy; to model; to imitate.\n[v.] To follow an example.","ex":""},"PAYING":{"p":"/ˈpeɪ.ɪŋ/","s":"v./n.","e":"[v.] To give money or other compensation to in exchange for goods or services.\n[v.] To discharge, as a debt or other obligation, by giving or doing what is due or required.\n[v.] To be profitable for.\n[v.] To cover (the bottom of a vessel, a seam, a spar, etc.) with tar or pitch, or a waterproof composition of tallow, resin, etc.; to smear.\n[n.] Payment","ex":"he paid her off the books and in kind where possible"},"PATTY":{"p":"/ˈpæti/","s":"n.","e":"[n.] (US, Australia, New Zealand) A flattened portion of ground meat or a vegetarian equivalent, usually round but sometimes square in shape.\n[n.] A pastry with various fillings and spices baked inside a flaky shell, often tinted golden yellow with an egg yolk mixture or turmeric.","ex":""},"PEACE":{"p":"/piːs/","s":"n./v./int.","e":"[n.] A state of tranquility, quiet, and harmony; absence of violence. For instance, a state free from civil disturbance.\n[n.] A state free of oppressive and unpleasant thoughts and emotions.\n[n.] Harmony in personal relations.\n[v.] To make peace; to put at peace; to be at peace.\n[v.] To peace out.\n[int.] Shut up!, silence!; be quiet, be silent.","ex":"Our lounge strives to maintain an environment of peace for the comfort of our customers."},"PEAK":{"p":"/piːk/","s":"n./v./adj.","e":"[n.] A point; the sharp end or top of anything that terminates in a point; as, the peak, or front, of a cap.\n[n.] The highest value reached by some quantity in a time period.\n[n.] The top, or one of the tops, of a hill, mountain, or range, ending in a point.\n[v.] To reach a highest degree or maximum.\n[v.] To rise or extend into a peak or point; to form, or appear as, a peak.\n[v.] To raise the point of (a gaff) closer to perpendicular.","ex":"The stock market reached a peak in September 1929."},"PEACH":{"p":"/piːt͡ʃ/","s":"n./adj.","e":"[n.] A tree (Prunus persica), native to China and now widely cultivated throughout temperate regions, having pink flowers and edible fruit.\n[n.] The soft juicy stone fruit of the peach tree, having yellow flesh, downy, red-tinted yellow skin, and a deeply sculptured pit or stone containing a single seed.\n[n.] A light moderate to strong yellowish pink to light orange color.\n[adj.] Of or pertaining to the color peach.\n[adj.] Particularly pleasing or agreeable.","ex":""},"PAYEE":{"p":"","s":"n.","e":"[n.] One to whom money is paid.","ex":""},"PECKS":{"p":"/pɛks/","s":"n./v.","e":"[n.] An act of striking with a beak.\n[n.] A small kiss.\n[v.] To strike or pierce with the beak or bill (of a bird).\n[v.] To form by striking with the beak or a pointed instrument.\n[v.] To strike, pick, thrust against, or dig into, with a pointed instrument, especially with repeated quick movements.\n[n.] One quarter of a bushel; a dry measure of eight quarts.","ex":"The birds pecked at their food."},"PEEL":{"p":"/piːl/","s":"n./v.","e":"[n.] (usually uncountable) The skin or outer layer of a fruit, vegetable, etc.\n[n.] The action of peeling away from a formation.\n[n.] A cosmetic preparation designed to remove dead skin or to exfoliate.\n[v.] To remove the skin or outer covering of.\n[v.] To remove something from the outer or top layer of.\n[v.] To become detached, come away, especially in flakes or strips; to shed skin in such a way.","ex":"I sat by my sister's bed, peeling oranges for her."},"PENAL":{"p":"/ˈpiːnəl/","s":"adj.","e":"[adj.] Of or relating to punishment.\n[adj.] Subject to punishment; punishable.\n[adj.] Serving as a place of punishment.","ex":"penal servitude"},"PATIO":{"p":"/ˈpæti.əʊ/","s":"n.","e":"[n.] A paved outside area, adjoining a house, used for dining or recreation.\n[n.] An inner courtyard typical of traditional houses in some regions of Spain.","ex":""},"PAYER":{"p":"/ˈpeɪ.ɚ/","s":"n.","e":"[n.] One who pays; specifically, the person by whom a bill or note has been, or should be, paid.\n[n.] A swaption which gives its holder the option to enter into a swap in which they pay the fixed leg and receive the floating leg.","ex":""},"PEER":{"p":"/pɪə/","s":"n./v.","e":"[n.] A look; a glance.\n[v.] To look with difficulty, or as if searching for something.\n[v.] To come in sight; to appear.","ex":""},"PEARL":{"p":"/pɜːl/","s":"n./v.","e":"[n.] A shelly concretion, usually rounded, and having a brilliant luster, with varying tints, found in the mantle, or between the mantle and shell, of certain bivalve mollusks, especially in the pearl oysters and river mussels, and sometimes in certain univalves. It is usually due to a secretion of shelly substance around some irritating foreign particle. Its substance is the same as nacre, or mother-of-pearl. Round lustrous pearls are used in jewellery.\n[n.] Something precious.\n[n.] A capsule of gelatin or similar substance containing liquid for e.g. medicinal application.\n[v.] (sometimes figurative) To set or adorn with pearls, or with mother-of-pearl.\n[v.] To cause to resemble pearls in shape; to make into small round grains.\n[v.] To cause to resemble pearls in lustre or iridescence.","ex":"to pearl barley"},"PENALTY":{"p":"/ˈpɛnəlti/","s":"n.","e":"[n.] A legal sentence.\n[n.] A punishment for violating rules of procedure.\n[n.] A payment forfeited for an early withdrawal from an account or an investment.","ex":"The penalty for his crime was to do hard labor."},"PENNE":{"p":"","s":"n.","e":"[n.] A type of short, diagonally cut pasta.","ex":""},"PENCE":{"p":"/pəns/","s":"n.","e":"[n.] In the United Kingdom and Ireland, a copper coin worth 1/240 of a pound sterling or Irish pound before decimalisation. Abbreviation: d.\n[n.] In the United Kingdom, a copper coin worth 1/100 of a pound sterling. Abbreviation: p.\n[n.] In Ireland, a coin worth 1/100 of an Irish pound before the introduction of the euro. Abbreviation: p.","ex":""},"PENSION":{"p":"/ˈpɛnʃ(ə)n/","s":"n./v.","e":"[n.] An annuity paid regularly as benefit due to a retired employee, serviceman etc. in consideration of past services, originally and chiefly by a government but also by various private pension schemes.\n[n.] A boarding house or small hotel, especially in continental Europe, which typically offers lodging and certain meals and services.\n[n.] A wage or fee.\n[v.] To grant a pension to.\n[v.] To force (someone) to retire on a pension.","ex":"Many old people depend on their pension to pay the bills."},"PEONY":{"p":"/ˈpiːəni/","s":"n.","e":"[n.] A flowering plant of the genus Paeonia with large fragrant flowers.\n[n.] A dark red colour.","ex":""},"PEOPLE":{"p":"/ˈpiːpəl/","s":"n./v.","e":"[n.] Used as plural of person; a body of human beings considered generally or collectively; a group of two or more persons.\n[n.] Persons forming or belonging to a particular group, such as a nation, class, ethnic group, country, family, etc.\n[n.] A group of persons regarded as being employees, followers, companions or subjects of a ruler.\n[v.] To stock with people or inhabitants; to fill as with people; to populate.\n[v.] To become populous or populated.\n[v.] To inhabit; to occupy; to populate.","ex":"There were so many people at the restaurant last night."},"PERFORM":{"p":"/pəˈfɔːm/","s":"v.","e":"[v.] To do something; to execute.\n[v.] To do (something) in front of an audience, such as acting or music, often in order to entertain.","ex":"It took him only twenty minutes to perform the task."},"PERCH":{"p":"/pɜːtʃ/","s":"n.","e":"[n.] Any of the three species of spiny-finned freshwater fish in the genus Perca.\n[n.] Any of the about 200 related species of fish in the taxonomic family Percidae, especially:\n[n.] Several similar species in the order Perciformes, such as the grouper.\n[n.] A rod, staff, or branch of a tree etc used as a roost by a bird\n[n.] A pole connecting the fore gear and hind gear of a spring carriage; a reach.\n[n.] A position that is secure and advantageous, especially one which is prominent or elevated","ex":""},"PERHAPS":{"p":"/pəˈhæps/","s":"n./adv.","e":"[n.] An uncertainty.\n[adv.] Modifies a verb, indicating a lack of certainty.\n[adv.] By chance.","ex":"Perhaps John will come over for dinner."},"PEDAL":{"p":"","s":"n./v./adj.","e":"[n.] A lever operated by one's foot that is used to control or power a machine or mechanism, such as a bicycle or piano\n[n.] A foot or footlike part.\n[n.] An effects unit, especially one designed to be activated by being stepped on.\n[v.] To operate a pedal attached to a wheel in a continuous circular motion.\n[v.] To operate a bicycle.\n[adj.] Of or relating to the foot.","ex":"A piano usually has two or three pedals."},"PAUSE":{"p":"/pɔːz/","s":"n./v.","e":"[n.] A button whose functions are pausing and resuming something, such as a DVD player, a video game or a computer.\n[n.] A temporary stop or rest; an intermission of action; interruption; suspension; cessation.\n[n.] A short time for relaxing and doing something else.\n[n.] Hesitation; suspense; doubt.\n[v.] To take a temporary rest, take a break for a short period after an effort.\n[v.] To interrupt an activity and wait.","ex":"When telling the scary story, he paused for effect."},"PERIL":{"p":"/ˈpɛɹəl/","s":"n./v.","e":"[n.] A situation of serious and immediate danger.\n[n.] Something that causes, contains, or presents danger.\n[n.] An event which causes a loss, or the risk of a specific such event.\n[v.] To cause to be in danger; to imperil; to risk.","ex":"The perils of the jungle (animals and insects, weather, etc)"},"PERKY":{"p":"/ˈpɝki/","s":"adj.","e":"[adj.] Lively or enthusiastic.\n[adj.] Standing upright; firm.","ex":"She answered with a perky smile and bounced off."},"PERMIT":{"p":"","s":"n./v.","e":"[n.] An artifact or document rendering something allowed or legal.\n[n.] Formal permission.\n[v.] To allow (something) to happen, to give permission for.\n[v.] To allow (someone) to do something; to give permission to.\n[v.] To allow for, to make something possible.","ex":"A construction permit can be obtained from the town offices."},"PESTO":{"p":"/ˈpɛstəʊ/","s":"n.","e":"[n.] A sauce, especially for pasta, originating from the Genoa region in Italy, made from basil, garlic, pine nuts, olive oil and cheese (usually pecorino)","ex":""},"PERSON":{"p":"/ˈpɜːsən/","s":"n./v.","e":"[n.] An individual; usually a human being.\n[n.] The physical body of a being seen as distinct from the mind, character, etc.\n[n.] Any individual or formal organization with standing before the courts.\n[v.] To represent as a person; to personify; to impersonate.\n[v.] (gender-neutral) To man.","ex":"Each person is unique, both mentally and physically."},"PERIOD":{"p":"/ˈpɪəɹɪəd/","s":"n./v./adj./int.","e":"[n.] A length of time.\n[n.] A period of time in history seen as a single coherent entity; an epoch, era.\n[n.] The punctuation mark “.” (indicating the ending of a sentence or marking an abbreviation).\n[v.] To come to a period; to conclude.\n[v.] To put an end to.\n[adj.] Designating anything from a given historical era.","ex":"There was a period of confusion following the announcement."},"PETTY":{"p":"/ˈpɛti/","s":"n./adj.","e":"[n.] (usually in the plural) A little schoolboy, either in grade or size.\n[n.] A class or school for young schoolboys.\n[n.] An outhouse: an outbuilding used as a lavatory.\n[adj.] Little, small, secondary in rank or importance.\n[adj.] Insignificant, trifling, or inconsiderable.\n[adj.] Narrow-minded, small-minded.","ex":"a petty fault"},"PETAL":{"p":"/ˈpɛtl̩/","s":"n.","e":"[n.] One of the component parts of the corolla of a flower. It applies particularly, but not necessarily only, when the corolla consists of separate parts, that is when the petals are not connately fused. Petals are often brightly colored.\n[n.] Term of endearment.","ex":""},"PHOTO":{"p":"/ˈfəʊ.təʊ/","s":"n./v.","e":"[n.] A photograph.\n[n.] A photo finish.\n[v.] To take a photograph of.","ex":""},"PHRASE":{"p":"/fɹeɪz/","s":"n./v.","e":"[n.] A short written or spoken expression.\n[n.] (grammar) A word or group of words that functions as a single unit in the syntax of a sentence, usually consisting of a head, or central word, and elaborating words.\n[n.] A small section of music in a larger piece.\n[v.] To express (an action, thought or idea) by means of particular words.\n[v.] To perform a passage with the correct phrasing.\n[v.] To divide into melodic phrases.","ex":"I wasn't sure how to phrase my condolences without sounding patronising."},"PIANO":{"p":"/piˈænoʊ/","s":"n./adj.","e":"[n.] A percussive keyboard musical instrument, usually ranging over seven octaves, with white and black colored keys, played by pressing these keys, causing hammers to strike strings\n[adj.] Soft, quiet\n[adj.] In extended use; quiet, subdued","ex":"He can play \"Happy Birthday\" on the piano."},"PICKY":{"p":"/ˈpɪki/","s":"n./adj.","e":"[n.] A picture.\n[adj.] Fussy; particular; demanding to have things just right.","ex":"I am very picky about the way my kitchen is laid out."},"PICK":{"p":"/pɪk/","s":"n./v.","e":"[n.] A tool used for digging; a pickaxe.\n[n.] A tool for unlocking a lock without the original key; a lock pick, picklock.\n[n.] A comb with long widely spaced teeth, for use with tightly curled hair.\n[v.] To grasp and pull with the fingers or fingernails.\n[v.] To harvest a fruit or vegetable for consumption by removing it from the plant to which it is attached; to harvest an entire plant by removing it from the ground.\n[v.] To pull apart or away, especially with the fingers; to pluck.","ex":"Don't pick at that scab."},"PICKUP":{"p":"","s":"n.","e":"[n.] An electronic device for detecting sound, vibration, etc., such as one fitted to an electric guitar or record player.\n[n.] A pickup truck.\n[n.] (usually attributive) Impromptu or ad hoc, especially of sports games and teams made up of randomly selected players.","ex":"At lunch we had a game of pickup hockey."},"PIECE":{"p":"/piːs/","s":"n./v.","e":"[n.] A part of a larger whole, usually in such a form that it is able to be separated from other parts.\n[n.] A single item belonging to a class of similar items\n[n.] One of the figures used in playing chess, specifically a higher-value figure as distinguished from a pawn; by extension, a similar counter etc. in other games.\n[v.] (usually with together) To assemble (something real or figurative).\n[v.] To make, enlarge, or repair, by the addition of a piece or pieces; to patch; often with out.\n[v.] To produce a work of graffiti more complex than a tag.","ex":"I’d like another piece of pie."},"PIETY":{"p":"/ˈpaɪ.ɪ.ti/","s":"n.","e":"[n.] Reverence and devotion to God.\n[n.] Similar reverence to one's parents and family or to one's country.\n[n.] A devout act or thought.","ex":"Colleen's piety led her to make sacrifices that most people would not have made."},"PIGGY":{"p":"/ˈpɪɡi/","s":"n./adj.","e":"[n.] (hypocoristic) A pig (the animal).\n[n.] (hypocoristic) A guinea pig.\n[n.] (hypocoristic) A toe.\n[adj.] Greedy\n[adj.] Slovenly, dirty","ex":"This little piggy went to market."},"PINCH":{"p":"/pɪntʃ/","s":"n./v.","e":"[n.] The action of squeezing a small amount of a person's skin and flesh, making it hurt.\n[n.] A close compression of anything with the fingers.\n[n.] A small amount of powder or granules, such that the amount could be held between fingertip and thumb tip.\n[v.] To squeeze a small amount of a person's skin and flesh, making it hurt.\n[v.] To squeeze between the thumb and forefinger.\n[v.] To squeeze between two objects.","ex":"I gave the leather of the sofa a pinch, gauging the texture."},"PILOT":{"p":"/ˈpaɪlət/","s":"n./v./adj.","e":"[n.] A person who steers a ship, a helmsman.\n[n.] A person who knows well the depths and currents of a harbor or coastal area, who is hired by a vessel to help navigate the harbor or coast.\n[n.] A guide book for maritime navigation.\n[v.] To control (an aircraft or watercraft).\n[v.] To guide (a vessel) through coastal waters.\n[v.] To test or have a preliminary trial of (an idea, a new product, etc.)","ex":"The pilot plant showed the need for major process changes."},"PINEY":{"p":"","s":"adj.","e":"[adj.] Of, pertaining to, or having many pines","ex":"a piny fragrance"},"PINTO":{"p":"/ˈpɪntəʊ/","s":"n./adj.","e":"[n.] A horse with a patchy coloration that includes white.\n[adj.] Pied, mottled.","ex":""},"PINK":{"p":"/pɪŋk/","s":"n.","e":"[n.] The common minnow, Phoxinus phoxinus.\n[n.] A young Atlantic salmon, Salmo salar, before it becomes a smolt; a parr.","ex":""},"PIONEER":{"p":"/ˌpaɪəˈnɪəɹ/","s":"n./v.","e":"[n.] One who goes before, as into the wilderness, preparing the way for others to follow.\n[n.] A person or other entity who is first or among the earliest in any field of inquiry, enterprise, or progress.\n[n.] A soldier detailed or employed to form roads, dig trenches, and make bridges, as an army advances; a sapper.\n[v.] To be the first to do or achieve (something), preparing the way for others to follow.","ex":"Certain politicians can be considered as pioneers of reform."},"PIPE":{"p":"/paɪp/","s":"n./v.","e":"[n.] Meanings relating to a wind instrument.\n[n.] Meanings relating to a hollow conduit.\n[n.] Meanings relating to a container.\n[v.] To play (music) on a pipe instrument, such as a bagpipe or a flute.\n[v.] To shout loudly and at high pitch.\n[v.] To emit or have a shrill sound like that of a pipe; to whistle.","ex":""},"PIQUE":{"p":"/piːk/","s":"n./v.","e":"[n.] A feeling of enmity; ill-feeling, animosity; a transient feeling of wounded pride.\n[n.] A feeling of irritation or resentment, awakened by a social slight or injury; offence, especially taken in an emotional sense with little thought or consideration.\n[n.] Keenly felt desire; a longing.\n[v.] To wound the pride of; to excite to anger.\n[v.] To take pride in; to pride oneself on.\n[v.] To stimulate (a feeling, emotion); to offend by slighting; to excite (someone) to action by causing resentment or jealousy.","ex":"I believe this will pique your interest."},"PIRATE":{"p":"/ˈpaɪ̯(ə)ɹət/","s":"n./v./adj.","e":"[n.] A criminal who plunders at sea; commonly attacking merchant vessels, though often pillaging port towns.\n[n.] An armed ship or vessel that sails for the purpose of plundering other vessels.\n[n.] One who breaks intellectual property laws by reproducing protected works without permission\n[v.] To appropriate by piracy, plunder at sea.\n[v.] (intellectual property) To create and/or sell an unauthorized copy of\n[v.] (intellectual property) To knowingly obtain an unauthorized copy of","ex":"You should be cautious due to the Somali pirates."},"PITCH":{"p":"/pɪtʃ/","s":"n./v.","e":"[n.] A sticky, gummy substance secreted by trees; sap.\n[n.] A dark, extremely viscous material remaining in still after distilling crude oil and tar.\n[n.] Pitchstone.\n[v.] To cover or smear with pitch.\n[v.] To darken; to blacken; to obscure.","ex":"It is hard to get this pitch off my hand."},"PIPER":{"p":"/ˈpaɪ.pə/","s":"n.","e":"[n.] A musician who plays a pipe.\n[n.] A bagpiper.\n[n.] A baby pigeon.","ex":""},"PITHY":{"p":"/ˈpɪθi/","s":"adj.","e":"[adj.] Concise and meaningful.\n[adj.] Of, like, or abounding in pith.","ex":""},"PIXIE":{"p":"/ˈpɪksi/","s":"n.","e":"[n.] (fantasy literature, fairy tales) A playful sprite or elflike or fairy-like creature.\n[n.] A cute, petite woman with short hair.\n[n.] An upper-atmospheric optical phenomenon associated with thunderstorms, a short-lasting pinpoint of light on the surface of convective domes that produces a gnome.","ex":""},"PIXEL":{"p":"/ˈpɪksəl/","s":"n./v.","e":"[n.] One of the tiny dots that make up the representation of an image in a computer's memory.\n[n.] One of the squares that make up a pixel art work or a zoomed in image in a computer.\n[v.] To create computer graphics by editing individual pixels.","ex":""},"PIZZA":{"p":"/ˈpiːt.sə/","s":"n.","e":"[n.] A baked Italian dish of a thinly rolled bread dough crust typically topped before baking with tomato sauce, cheese and other ingredients such as meat, vegetables or fruit\n[n.] A single instance of this dish","ex":"Want to go out for pizza tonight?"},"PIVOT":{"p":"/ˈpɪvət/","s":"n./v.","e":"[n.] A thing on which something turns; specifically a metal pointed pin or short shaft in machinery, such as the end of an axle or spindle.\n[n.] (by extension) Something or someone having a paramount significance in a certain situation.\n[n.] Act of turning on one foot.\n[v.] To turn on an exact spot.\n[v.] To make a sudden or swift change in strategy, policy, etc.","ex":""},"PLACE":{"p":"/pleɪs/","s":"n.","e":"[n.] (physical) An area; somewhere within an area.\n[n.] A location or position in space.\n[n.] A particular location in a book or document, particularly the current location of a reader.","ex":""},"PLAID":{"p":"/plad/","s":"n./adj.","e":"[n.] A type of twilled woollen cloth, often with a tartan or chequered pattern.\n[n.] A length of such material used as a piece of clothing, formerly worn in the Scottish Highlands and other parts of northern Britain and remaining as an item of ceremonial dress worn by members of Scottish pipe bands.\n[n.] The typical chequered pattern of a plaid; tartan.\n[adj.] Having a pattern or colors which resemble a Scottish tartan; checkered or marked with bars or stripes at right angles to one another.","ex":""},"PLACING":{"p":"/ˈpleɪsɪŋ/","s":"v./n.","e":"[v.] To put (an object or person) in a specific location.\n[v.] To earn a given spot in a competition.\n[v.] To remember where and when (an object or person) has been previously encountered.\n[n.] The action by which something is placed; placement; positioning.\n[n.] The condition of being placed.\n[n.] The position of a competitor at the end of a race.","ex":"He placed the glass on the table."},"PLAIT":{"p":"/pleɪt/","s":"n./v.","e":"[n.] A flat fold; a doubling, as of cloth; a pleat.\n[n.] A braid, as of hair or straw; a plat.\n[v.] To fold; to double in narrow folds; to pleat\n[v.] To interweave the strands or locks of; to braid","ex":"a box plait"},"PLANE":{"p":"/pleɪn/","s":"n./adj.","e":"[n.] A level or flat surface.\n[n.] A flat surface extending infinitely in all directions (e.g. horizontal or vertical plane).\n[n.] A level of existence or development. (eg, astral plane)\n[adj.] Of a surface: flat or level.","ex":""},"PLAN":{"p":"/plæn/","s":"n./v.","e":"[n.] A drawing showing technical details of a building, machine, etc., with unwanted details omitted, and often using symbols rather than detailed drawing to represent doors, valves, etc.\n[n.] A set of intended actions, usually mutually related, through which one expects to achieve a goal.\n[n.] A two-dimensional drawing of a building as seen from above with obscuring or irrelevant details such as roof removed, or of a floor of a building, revealing the internal layout; as distinct from the elevation.\n[v.] To design (a building, machine, etc.).\n[v.] To create a plan for.\n[v.] To intend.","ex":"The plans for many important buildings were once publicly available."},"PLANT":{"p":"/plænt/","s":"n./v.","e":"[n.] An organism that is not an animal, especially an organism capable of photosynthesis. Typically a small or herbaceous organism of this kind, rather than a tree.\n[n.] An organism of the kingdom Plantae; now specifically, a living organism of the Embryophyta (land plants) or of the Chlorophyta (green algae), a eukaryote that includes double-membraned chloroplasts in its cells containing chlorophyll a and b, or any organism closely related to such an organism.\n[n.] Now specifically, a multicellular eukaryote that includes chloroplasts in its cells, which have a cell wall.\n[v.] To place (a seed or plant) in soil or other substrate in order that it may live and grow.\n[v.] To place (an object, or sometimes a person), often with the implication of intending deceit.\n[v.] To place or set something firmly or with conviction.","ex":"The garden had a couple of trees, and a cluster of colourful plants around the border."},"PLEAD":{"p":"","s":"v.","e":"[v.] To present (an argument or a plea), especially in a legal case.\n[v.] To beg, beseech, or implore.\n[v.] To offer by way of excuse.","ex":"The defendant has decided to plead not guilty."},"PLANK":{"p":"/plæŋk/","s":"n./v.","e":"[n.] A long, broad and thick piece of timber, as opposed to a board which is less thick.\n[n.] A political issue that is of concern to a faction or a party of the people and the political position that is taken on that issue.\n[n.] Physical exercise in which one holds a pushup position for a measured length of time.\n[v.] To cover something with planking.\n[v.] To bake (fish, etc.) on a piece of cedar lumber.\n[v.] To lay down, as on a plank or table; to stake or pay cash.","ex":"Germanization was a central plank of German conservative thinking in the 19th and 20th centuries."},"PLEASED":{"p":"/pliːzd/","s":"v./adj.","e":"[v.] To make happy or satisfy; to give pleasure to.\n[v.] To desire; to will; to be pleased by.\n[adj.] Happy, content","ex":"Her presentation pleased the executives."},"PLUG":{"p":"/plʌɡ/","s":"n./v.","e":"[n.] A pronged connecting device which fits into a mating socket, especially an electrical one.\n[n.] Any piece of wood, metal, or other substance used to stop or fill a hole.\n[n.] A flat oblong cake of pressed tobacco.\n[v.] To stop with a plug; to make tight by stopping a hole.\n[v.] To blatantly mention a particular product or service as if advertising it.\n[v.] To persist or continue with something.","ex":"I pushed the plug back into the electrical socket and the lamp began to glow again."},"PLOWS":{"p":"","s":"n./v.","e":"[n.] The notional area of land able to be farmed in a year by a team of 8 oxen pulling a carruca plow, usually reckoned at 120 acres.\n[n.] A device pulled through the ground in order to break it open into furrows for planting.\n[n.] The use of a plough; tillage.\n[n.] Alternative form of Plough (Synonym of Ursa Major)\n[v.] To use a plough on to prepare for planting.\n[v.] To use a plough.","ex":"The horse-drawn plough had a tremendous impact on agriculture."},"PLIED":{"p":"/plaɪd/","s":"v.","e":"[v.] To bend; to fold; to mould; to adapt, to modify; to change (a person's) mind, to cause (a person) to submit.\n[v.] To bend, to flex; to be bent by something, to give way or yield (to a force, etc.).\n[v.] To work at (something) diligently.\n[v.] To wield or use (a tool, a weapon, etc.) steadily or vigorously.\n[v.] To press upon; to urge persistently.","ex":"He plied his trade as carpenter for forty-three years."},"PLUME":{"p":"/ˈpljuːm/","s":"n.","e":"[n.] A feather of a bird, especially a large or showy one used as a decoration.\n[n.] A cluster of feathers worn as an ornament, especially on a helmet; a hackle.\n[n.] A token of honour or prowess; that on which one prides oneself; a prize or reward.","ex":""},"PLUMB":{"p":"/plʌm/","s":"n./v./adj./adv.","e":"[n.] A little mass of lead, or the like, attached to a line, and used by builders, etc., to indicate a vertical direction.\n[n.] A weight on the end of a long line, used by sailors to determine the depth of water.\n[n.] The perpendicular direction or position.\n[v.] To determine the depth, generally of a liquid; to sound.\n[v.] To attach to a water supply and drain.\n[v.] To think about or explore in depth, to get to the bottom of, especially to plumb the depths of.","ex":"It hit him plumb in the middle of his face."},"PLUMP":{"p":"/plʌmp/","s":"v./adj.","e":"[v.] To grow plump; to swell out.\n[v.] To make plump; to fill (out) or support; often with up.\n[v.] To cast or let drop all at once, suddenly and heavily.\n[adj.] Having a full and rounded shape; chubby, somewhat overweight.\n[adj.] Fat.\n[adj.] Sudden and without reservation; blunt; direct; downright.","ex":"Her cheeks have plumped."},"PLAZA":{"p":"/ˈplæzə/","s":"n.","e":"[n.] A town's public square.\n[n.] An open area used for gathering in a city, often having small trees and sitting benches.\n[n.] A strip mall.","ex":""},"PLEASE":{"p":"/pliːz/","s":"v.","e":"[v.] To make happy or satisfy; to give pleasure to.\n[v.] To desire; to will; to be pleased by.","ex":"Her presentation pleased the executives."},"POACH":{"p":"/ˈpoʊtʃ/","s":"n./v.","e":"[n.] The act of cooking in simmering liquid.\n[v.] To cook something in simmering liquid.\n[v.] To be cooked in simmering liquid\n[v.] To become soft or muddy.","ex":""},"POETRY":{"p":"/ˈpəʊɪtɹi/","s":"n.","e":"[n.] Literature composed in verse or language exhibiting conscious attention to patterns and rhythm.\n[n.] A poet's literary production.\n[n.] An artistic quality that appeals to or evokes the emotions, in any medium; something having such a quality.","ex":"That 'Swan Lake' choreography is poetry in motion, fitting the musical poetry of Tchaikovski's divine score well beyond the literary inspiration."},"POCKET":{"p":"/ˈpɒkɪt/","s":"n./v./adj.","e":"[n.] A bag stitched to an item of clothing, used for carrying small items.\n[n.] Such a receptacle seen as housing someone's money; hence, financial resources.\n[n.] An indention and cavity with a net sack or similar structure (into which the balls are to be struck) at each corner and one centered on each side of a pool or snooker table.\n[v.] To put (something) into a pocket.\n[v.] To cause a ball to go into one of the pockets of the table; to complete a shot.\n[v.] To take and keep (something, especially money that is not one's own).","ex":"I paid for it out of my own pocket."},"POISE":{"p":"/pɔɪz/","s":"n./v.","e":"[n.] A state of balance, equilibrium or stability.\n[n.] Composure; freedom from embarrassment or affectation.\n[n.] Mien; bearing or deportment of the head or body.\n[v.] To hang in equilibrium; to be balanced or suspended; hence, to be in suspense or doubt.\n[v.] To counterpoise; to counterbalance.\n[v.] To be of a given weight; to weigh.","ex":""},"POINT":{"p":"/pɔɪnt/","s":"n.","e":"[n.] A discrete division of something.\n[n.] A sharp extremity.\n[n.] One of the several different parts of the escutcheon.","ex":""},"POKEY":{"p":"/ˈpoʊ.ki/","s":"n./adj.","e":"[n.] (with \"the\") prison.\n[adj.] (of a room, house) of small volume, cramped\n[adj.] Slow\n[adj.] (of a car) fast","ex":""},"POLE":{"p":"/pɔːl/","s":"n./v.","e":"[n.] Originally, a stick; now specifically, a long and slender piece of metal or (especially) wood, used for various construction or support purposes.\n[n.] A type of basic fishing rod.\n[n.] A long sports implement used for pole-vaulting; now made of glassfiber or carbon fiber, formerly also metal, bamboo and wood have been used.\n[v.] To propel by pushing with poles, to push with a pole.\n[v.] To identify something quite precisely using a telescope.\n[v.] To furnish with poles for support.","ex":"Huck Finn poled that raft southward down the Mississippi because going northward against the current was too much work."},"POLICY":{"p":"/ˈpɒləsi/","s":"n./v.","e":"[n.] A principle of behaviour, conduct etc. thought to be desirable or necessary, especially as formally expressed by a government or other authoritative body.\n[n.] Wise or advantageous conduct; prudence, formerly also with connotations of craftiness.\n[n.] Specifically, political shrewdness or (formerly) cunning; statecraft.\n[v.] To regulate by laws; to reduce to order.","ex":"The Communist Party has a policy of returning power to the workers."},"POLL":{"p":"/pɔl/","s":"n./v./adj.","e":"[n.] A survey of people, usually statistically analyzed to gauge wider public opinion.\n[n.] A formal election.\n[n.] A polling place (usually as plural, polling places)\n[v.] To take, record the votes of (an electorate).\n[v.] To solicit mock votes from (a person or group).\n[v.] To vote at an election.","ex":"The student council had a poll to see what people want served in the cafeteria."},"POLYP":{"p":"","s":"n.","e":"[n.] An abnormal growth protruding from a mucous membrane\n[n.] A cylindrical coelenterate, such as the hydra, having a mouth surrounded with tentacles","ex":""},"POLICE":{"p":"[pəˈliːs]","s":"n./v.","e":"[n.] A civil force granted the legal authority for law enforcement and maintaining public order.\n[n.] A police officer.\n[n.] People who seek to enforce norms or standards.\n[v.] To enforce the law and keep order among (a group).\n[v.] To clean up an area.\n[v.] To enforce norms or standards upon.","ex":"Call the police!"},"POOL":{"p":"/pul/","s":"n./v.","e":"[n.] A small and rather deep collection of (usually) fresh water, as one supplied by a spring, or occurring in the course of a stream; a reservoir for water.\n[n.] A small body of standing or stagnant water; a puddle.\n[n.] A supply of resources.\n[v.] (of a liquid) To form a pool.\n[n.] A pool of water used for swimming, usually one which has been artificially constructed.","ex":"the pools of Solomon"},"POOR":{"p":"/poː/","s":"n./adj.","e":"[n.] (with \"the\") Those who have little or no possessions or money, taken as a group.\n[adj.] With no or few possessions or money, particularly in relation to contemporaries who do have them.\n[adj.] Of low quality.\n[adj.] Used to express pity.","ex":"The poor are always with us."},"POPE":{"p":"/pəʊp/","s":"n./v.","e":"[n.] An honorary title of the Roman Catholic bishop of Rome as father and head of his church, a sovereign of the Vatican city state.\n[n.] (Coptic Church) An honorary title of the Coptic bishop of Alexandria as father and head of his church.\n[n.] An honorary title of the Orthodox bishop of Alexandria as father and head of his autocephalous church.\n[v.] To act as or like a pope.\n[v.] To convert to Roman Catholicism.","ex":""},"PORCH":{"p":"/pɔːtʃ/","s":"n.","e":"[n.] A covered and enclosed entrance to a building, whether taken from the interior, and forming a sort of vestibule within the main wall, or projecting without and with a separate roof.\n[n.] A portico; a covered walk.\n[n.] The platform outside the external hatch of a spacecraft.","ex":""},"PORTION":{"p":"/ˈpoəɹʃən/","s":"n./v.","e":"[n.] An allocated amount.\n[n.] That which is divided off or separated, as a part from a whole; a separated part of anything.\n[n.] One's fate; lot.\n[v.] To divide into amounts, as for allocation to specific purposes.\n[v.] To endow with a portion or inheritance.","ex":""},"POOCH":{"p":"/puːt͡ʃ/","s":"n.","e":"[n.] A dog.\n[n.] A dog of mixed breed; a mongrel.","ex":""},"POSED":{"p":"/pəʊzd/","s":"v./adj.","e":"[v.] To place in an attitude or fixed position, for the sake of effect.\n[v.] To ask; to set (a test, quiz, riddle, etc.).\n[v.] To constitute (a danger, a threat, a risk, etc.).\n[v.] To ask (someone) questions; to interrogate.\n[v.] To puzzle, non-plus, or embarrass with difficult questions.\n[v.] To perplex or confuse (someone).","ex":"To pose a model for a picture."},"POPULAR":{"p":"/ˈpɒpjʊlə/","s":"n./adj.","e":"[n.] A person who is popular, especially at a school.\n[n.] (chiefly in the plural) An inexpensive newspaper with wide circulation.\n[n.] A member of the Populares\n[adj.] Common among the general public; generally accepted.\n[adj.] Concerning the people; public.\n[adj.] Pertaining to or deriving from the people or general public.","ex":""},"POSTAL":{"p":"[ˈpəʊstl̩]","s":"adj.","e":"[adj.] Relating to the collection, sorting and delivery of mail.","ex":"for all your postal needs"},"POST":{"p":"/pəʊst/","s":"n./v.","e":"[n.] A long dowel or plank protruding from the ground; a fencepost; a lightpost.\n[n.] A stud; a two-by-four.\n[n.] A pole in a battery.\n[v.] To hang (a notice) in a conspicuous manner for general review.\n[v.] To hold up to public blame or reproach; to advertise opprobriously; to denounce by public proclamation.\n[v.] To carry (an account) from the journal to the ledger.","ex":"ram a post into the ground"},"POUCH":{"p":"/paʊt͡ʃ/","s":"n./v.","e":"[n.] A small bag usually closed with a drawstring.\n[n.] A pocket in which a marsupial carries its young.\n[n.] Any pocket or bag-shaped object, such as a cheek pouch.\n[v.] To enclose within a pouch.\n[v.] To transport within a pouch, especially a diplomatic pouch.\n[v.] (of fowls and fish) To swallow.","ex":"The beggar pouched the coin."},"POWER":{"p":"/ˈpaʊ.ə(ɹ)/","s":"n./v./adj.","e":"[n.] Ability to do or undergo something.\n[n.] (social) Ability to coerce, influence or control.\n[n.] (physical) Effectiveness.\n[v.] To provide power for (a mechanical or electronic device).\n[v.] To hit or kick something forcefully.\n[v.] To enable or provide the impetus for.","ex":"This CD player is powered by batteries."},"PRAWN":{"p":"/pɹoːn/","s":"n./v.","e":"[n.] A crustacean of the suborder Dendrobranchiata.\n[n.] A crustacean sometimes confused with shrimp.\n[n.] A woman with a very toned body, but an unattractive face.\n[v.] To fish for prawns.","ex":"She's a prawn!"},"POSES":{"p":"","s":"n./v.","e":"[n.] Common cold, head cold; catarrh.\n[n.] Position, posture, arrangement (especially of the human body).\n[n.] Affectation.\n[v.] To place in an attitude or fixed position, for the sake of effect.\n[v.] To ask; to set (a test, quiz, riddle, etc.).\n[v.] To constitute (a danger, a threat, a risk, etc.).","ex":"Please adopt a more graceful pose for my camera."},"PREMIUM":{"p":"/ˈpɹimiəm/","s":"n./adj.","e":"[n.] A prize or award.\n[n.] Something offered at a reduced price as an inducement to buy something else.\n[n.] A bonus paid in addition to normal payments.\n[adj.] Superior in quality; higher in price or value.\n[adj.] High-end; belonging to the market segment between mid-market and luxury.","ex":""},"PREVIEW":{"p":"/ˈpɹiːvjʉː/","s":"n./v.","e":"[n.] An experience of something in advance.\n[n.] An advance showing of a film, exhibition etc.\n[n.] Something seen in advance.\n[v.] To show or watch something, or part of it, before it is complete.","ex":""},"PRICE":{"p":"/pɹaɪs/","s":"n./v.","e":"[n.] The cost required to gain possession of something.\n[n.] The cost of an action or deed.\n[n.] Value; estimation; excellence; worth.\n[v.] To determine the monetary value of (an item); to put a price on.\n[v.] To pay the price of; to make reparation for.\n[v.] To set a price on; to value; to prize.","ex":"I paid a high price for my folly."},"PRINT":{"p":"/pɹɪnt/","s":"n./v./adj.","e":"[n.] Books and other material created by printing presses, considered collectively or as a medium.\n[n.] Clear handwriting, especially, writing without connected letters as in cursive.\n[n.] The letters forming the text of a document.\n[v.] To produce one or more copies of a text or image on a surface, especially by machine; often used with out or off: print out, print off.\n[v.] To produce a microchip (an integrated circuit) in a process resembling the printing of an image.\n[v.] To write very clearly, especially, to write without connecting the letters as in cursive.","ex":"TV and the internet haven't killed print."},"PRIME":{"p":"/pɹaɪ̯m/","s":"n./adj.","e":"[n.] The first hour of daylight; the first canonical hour.\n[n.] The religious service appointed to this hour.\n[n.] The early morning generally.\n[adj.] First in importance, degree, or rank.\n[adj.] First in time, order, or sequence.\n[adj.] First in excellence, quality, or value.","ex":"Our prime concern here is to keep the community safe."},"PRINCE":{"p":"/pɹɪns/","s":"n.","e":"[n.] A (male) ruler, a sovereign; a king, monarch.\n[n.] A female monarch.\n[n.] Someone who is preeminent in their field; a great person.","ex":"He is a prince among men."},"PRISM":{"p":"/ˈpɹɪzəm/","s":"n.","e":"[n.] A polyhedron with parallel ends of the same size and shape, the other faces being parallelogram-shaped sides.\n[n.] A transparent block in the shape of a prism (typically with triangular ends), used to split or reflect light.\n[n.] A crystal in which the faces are parallel to the vertical axis.","ex":""},"PREFER":{"p":"/pɹɪˈfɜː/","s":"v.","e":"[v.] To be in the habit of choosing something rather than something else; to favor; to like better.\n[v.] To advance, promote (someone or something).\n[v.] To present or submit (something) to an authority (now usually in \"to prefer charges\").","ex":"I prefer tea to coffee."},"PRION":{"p":"/ˈpɹaɪən/","s":"n.","e":"[n.] A self-propagating misfolded conformer of a protein that is responsible for a number of diseases that affect the brain and other neural tissue.","ex":""},"PROBLEM":{"p":"/ˈpɹɒbləm/","s":"n./adj.","e":"[n.] A difficulty that has to be resolved or dealt with.\n[n.] A question to be answered, schoolwork exercise.\n[n.] A puzzling circumstance.\n[adj.] (of a person or an animal) Difficult to train or guide; unruly.\n[adj.] Causing a problem; problematic; troublesome.","ex":"She's leaving because she faced numerous problems to do with racism."},"PRIVY":{"p":"/ˈpɹɪv.i/","s":"n./adj.","e":"[n.] An outdoor facility for urination and defecation, whether open (latrine) or enclosed (outhouse).\n[n.] A lavatory: a room with a toilet.\n[n.] A toilet: a fixture used for urination and defecation.\n[adj.] Private, exclusive; not public; one's own.\n[adj.] Secret, hidden, concealed.\n[adj.] With knowledge of; party to; let in on.","ex":"The king retreated to his privy chamber."},"PROFILE":{"p":"/ˈpɹəʊfaɪl/","s":"n./v.","e":"[n.] The outermost shape, view, or edge of an object.\n[n.] The shape, view, or shadow of a person's head from the side; a side view.\n[n.] A summary or collection of information, especially about a person\n[v.] To create a summary or collection of information about (a person, etc.).\n[v.] To act based on such a summary, especially one that is a stereotype; to engage in profiling.\n[v.] To draw in profile or outline.","ex":"His fingers traced the profile of the handle."},"PROPER":{"p":"/ˈpɹɔp.ə/","s":"n./adj./adv.","e":"[n.] Something set apart for a special use.\n[adj.] (heading) Suitable.\n[adj.] (heading) Possessed, related.\n[adj.] (heading) Accurate, strictly applied.\n[adv.] Properly; thoroughly; completely.\n[adv.] Properly.","ex":""},"PROBE":{"p":"/pɹəʊb/","s":"n./v.","e":"[n.] Any of various medical instruments used to explore wounds, organs, etc.\n[n.] Something which penetrates something else, as though to explore; something which obtains information.\n[n.] An act of probing; a prod, a poke.\n[v.] To explore, investigate, or question\n[v.] To insert a probe into.","ex":"If you probe further, you may discover different reasons."},"PROTEIN":{"p":"/ˈpɹəʊti.ɪn/","s":"n.","e":"[n.] Any of numerous large, complex naturally-produced molecules composed of one or more long chains of amino acids, in which the amino acid groups are held together by peptide bonds.\n[n.] (nutrition) One of three major classes of food or source of food energy (4 kcal/gram) abundant in animal-derived foods (i.e. meat) and some vegetables, such as legumes.\n[n.] (nutrition) A food rich in protein, often a meat or meat substitute.","ex":""},"PROMISE":{"p":"/ˈpɹɒmɪs/","s":"n./v.","e":"[n.] An oath or affirmation; a vow\n[n.] A transaction between two persons whereby the first person undertakes in the future to render some service or gift to the second person or devotes something valuable now and here to his use\n[n.] Reason to expect improvement or success; potential\n[v.] To commit to (some action or outcome), or to assure (a person) of such commitment; to make an oath or vow.\n[v.] To give grounds for expectation, especially of something good.","ex":"if I make a promise, I always stick to it;  he broke his promise"},"PROWL":{"p":"/pɹaʊl/","s":"n./v.","e":"[n.] The act of prowling.\n[v.] To rove over, through, or about in a stealthy manner; especially, to search in, as for prey or booty.\n[v.] To idle; to go about aimlessly.\n[v.] To collect by plunder.","ex":"I'm going on a midnight prowl."},"PROPOSE":{"p":"/pɹəˈpəʊz/","s":"n./v.","e":"[n.] An objective or aim.\n[v.] To suggest a plan, course of action, etc.\n[v.] (sometimes followed by to) To ask for a person's hand in marriage.\n[v.] To intend.","ex":"I propose going to see a film."},"PROTEST":{"p":"/ˈpɹəʊ.tɛst/","s":"n./v.","e":"[n.] A formal objection, especially one by a group.\n[n.] A collective gesture of disapproval; a demonstration.\n[n.] The noting by a notary public of an unpaid or unaccepted bill.\n[v.] To make a strong objection.\n[v.] To affirm (something).\n[v.] To object to.","ex":"They lodged a protest with the authorities."},"PROUD":{"p":"/pɹaʊd/","s":"adj.","e":"[adj.] Feeling honoured (by something); feeling happy or satisfied about an event or fact; gratified.\n[adj.] Possessed of a due sense of what one deserves or is worth.\n[adj.] Having too high an opinion of oneself; arrogant, supercilious.","ex":"I am proud of Sivu’s schoolwork."},"PROTECT":{"p":"/pɹəˈtɛkt/","s":"v.","e":"[v.] To keep safe; to defend; to guard; to prevent harm coming to.\n[v.] (travel) To book a passenger on a later flight if there is a chance they will not be able to board their earlier reserved flight.","ex":"Condoms are designed to protect against sexually-transmitted diseases."},"PROPS":{"p":"","s":"n./v.","e":"[n.] An object placed against or under another, to support it; anything that supports.\n[n.] The player on either side of the hooker in a scrum.\n[n.] One of the seashells in the game of props.\n[v.] (sometimes figurative) To support or shore up something.\n[v.] To play rugby in the prop position\n[v.] (usually with \"up\" - see prop up) To position the feet of (a person) while sitting, lying down, or reclining so that the knees are elevated at a higher level.","ex":"They stuck a block of wood under it as a prop."},"PUFFY":{"p":"/ˈpʌfi/","s":"adj.","e":"[adj.] Swollen or inflated in shape, as if filled with air; pillow-like.\n[adj.] Coming or exhaling in puffs.\n[adj.] Speaking or writing in an exaggeratedly eloquent and self-important manner.","ex":"A puffy fat man in a tracksuit came jogging around the corner."},"PROVE":{"p":"/pɹuːv/","s":"v./n.","e":"[v.] To proofread.\n[v.] To make resistant, especially to water.\n[v.] To allow yeast-containing dough to rise.\n[n.] The process of dough proofing.\n[v.] To demonstrate that something is true or viable; to give proof for.\n[v.] To turn out; to manifest.","ex":"I will prove that my method is more effective than yours."},"PUNTS":{"p":"/pʌnts/","s":"n./v.","e":"[n.] A pontoon; a narrow shallow boat propelled by a pole.\n[v.] To propel a punt or similar craft by means of a pole.\n[n.] A kick made by a player who drops the ball and kicks it before it hits the ground.\n[v.] To dropkick; to kick something a considerable distance.\n[v.] To equivocate and delay or put off (answering a question, addressing an issue, etc).\n[v.] To retreat from one's objective; to abandon an effort one still notionally supports.","ex":""},"PROVIDE":{"p":"/pɹəˈvaɪd/","s":"v.","e":"[v.] To make a living; earn money for necessities.\n[v.] To act to prepare for something.\n[v.] To establish as a previous condition; to stipulate.","ex":"It is difficult to provide for my family working on minimum wage."},"PUPIL":{"p":"/ˈpjuːpəl/","s":"n.","e":"[n.] A learner under the supervision of a teacher or professor.\n[n.] An orphan who is a minor and under the protection of the state.","ex":""},"PUPPY":{"p":"/ˈpʌpi/","s":"n./v.","e":"[n.] A young dog, especially before sexual maturity (12-18 months)\n[n.] A young rat.\n[n.] A young seal.\n[v.] To bring forth whelps or give birth to pups.","ex":""},"PURE":{"p":"/ˈpjɔː/","s":"n./v./adj./adv.","e":"[n.] One who, or that which, is pure.\n[v.] To hit (the ball) completely cleanly and accurately\n[v.] To cleanse; to refine.\n[adj.] Free of flaws or imperfections; unsullied.\n[adj.] Free of foreign material or pollutants.\n[adj.] Free of immoral behavior or qualities; clean.","ex":"Tiger Woods pured his first drive straight down the middle of the fairway."},"PURGE":{"p":"/pɜːdʒ/","s":"n./v.","e":"[n.] An act of purging.\n[n.] An evacuation of the bowels or a vomiting.\n[n.] A cleansing of pipes.\n[v.] To clean thoroughly; to cleanse; to rid of impurities.\n[v.] To free from sin, guilt, or the burden or responsibility of misdeeds\n[v.] To remove by cleansing; to wash away.","ex":""},"PUDGY":{"p":"/ˈpʌdʒi/","s":"adj.","e":"[adj.] Fat, overweight (pertaining particularly to children), plump; chubby.","ex":"The pudgy child had a difficult time running the mile."},"PURPOSE":{"p":"/ˈpɜːpəs/","s":"n.","e":"[n.] An objective to be reached; a target; an aim; a goal.\n[n.] A result that is desired; an intention.\n[n.] The act of intending to do something; resolution; determination.","ex":""},"PURRS":{"p":"","s":"n./v.","e":"[n.] The vibrating sound made by a cat in its throat when contented.\n[n.] A throaty, seductive sound of pleasure made by a person.\n[n.] The low consistent rumble made by an engine at slow speed\n[v.] Of a cat, to make a vibrating sound in its throat when contented.\n[v.] To say (something) in a throaty, seductive manner.\n[v.] To make a vibrating throaty sound, as from pleasure.","ex":"He purred like a kitten when she massaged his neck."},"PUTTY":{"p":"/ˈpʌti/","s":"n./v./adj.","e":"[n.] A form of cement, made from linseed oil and whiting, used to fix panes of glass.\n[n.] Any of a range of similar substances.\n[n.] A golf ball made of composition and not gutta-percha.\n[v.] To fix or fill using putty.\n[adj.] Of, pertaining to, or resembling putty.","ex":""},"PYGMY":{"p":"/pɪɡmiː/","s":"n./adj.","e":"[n.] (often capitalized) A member of one of various Ancient Equatorial African tribal peoples, notable for their very short stature.\n[n.] A member of a race of dwarfs.\n[n.] Any dwarfish person or thing.\n[adj.] Relating or belonging to the Pygmy people.\n[adj.] Like a pygmy; unusually short or small for its kind.","ex":""},"PUSSY":{"p":"/ˈpʊsɪ/","s":"n.","e":"[n.] A cat.\n[n.] An affectionate term for a woman or girl, seen as having characteristics associated with cats such as sweetness.\n[n.] The female genitalia; the vulva and/or vagina.","ex":"You have a lovely pussy!"},"PURSE":{"p":"/pɜːs/","s":"n./v.","e":"[n.] A small bag for carrying money.\n[n.] A handbag (small bag usually used by women for carrying various small personal items)\n[n.] A quantity of money given for a particular purpose.\n[v.] To press (one's lips) in and together so that they protrude.\n[v.] To draw up or contract into folds or wrinkles; to pucker; to knit.\n[v.] To put into a purse.","ex":""},"QUAKE":{"p":"/kweɪk/","s":"n./v.","e":"[n.] A trembling or shaking.\n[n.] An earthquake, a trembling of the ground with force.\n[v.] To tremble or shake.\n[v.] To be in a state of fear, shock, amazement, etc., such as might cause one to tremble.","ex":"We felt a quake in the apartment every time the train went by."},"PURSUE":{"p":"/pəˈʃu/","s":"v.","e":"[v.] To follow urgently, originally with intent to capture or harm; to chase.\n[v.] To follow, travel down (a particular way, course of action etc.).\n[v.] To aim for, go after (a specified objective, situation etc.).","ex":"Her rival pursued a quite different course."},"PUSHING":{"p":"/ˈpʊʃɪŋ/","s":"v./n./adj.","e":"[v.] To apply a force to (an object) such that it moves away from the person or thing applying the force.\n[v.] To continually attempt to persuade (a person) into a particular course of action.\n[v.] To press or urge forward; to drive.\n[n.] The act by which something is pushed.\n[adj.] That pushes forward; pressing, driving.\n[adj.] Aggressively assertive; pushy.","ex":"In his anger he pushed me against the wall and threatened me."},"QUAIL":{"p":"/ˈkweɪl/","s":"v.","e":"[v.] To waste away; to fade, to wither\n[v.] To daunt or frighten (someone)\n[v.] To lose heart or courage; to be daunted or fearful.","ex":""},"QUALIFY":{"p":"/ˈkwɒl.ɪ.faɪ/","s":"n./v.","e":"[n.] An instance of throwing and catching each prop at least twice.\n[v.] To describe or characterize something by listing its qualities.\n[v.] To make someone, or to become competent or eligible for some position or task.\n[v.] To certify or license someone for something.","ex":""},"QUACK":{"p":"/kwæk/","s":"n./v.","e":"[n.] The sound made by a duck.\n[v.] To make a noise like a duck.","ex":"Did you hear that duck make a quack?"},"QUALM":{"p":"/kwɑːm/","s":"n./v.","e":"[n.] A feeling of apprehension, doubt, fear etc.\n[n.] A sudden sickly feeling; queasiness.\n[n.] A prick of the conscience; a moral scruple, a pang of guilt. (Now often in negative constructions.)\n[v.] To have a sickly feeling.","ex":"This lawyer has no qualms about saving people who are on the wrong side of the law."},"QUALITY":{"p":"/ˈkwɒlɪti/","s":"n./adj.","e":"[n.] Level of excellence.\n[n.] A property or an attribute that differentiates a thing or person.\n[n.] High social position. (See also the quality.)\n[adj.] Being of good worth, well made, fit for purpose.","ex":"Quality of life is usually determined by health, education, and income."},"QUARK":{"p":"/kwɑːk/","s":"n.","e":"[n.] In the Standard Model, an elementary subatomic particle that forms matter. They combine to form hadrons, such as protons and neutrons.\n[n.] (X Window System) An integer that uniquely identifies a text string.","ex":""},"QUART":{"p":"/kwɔːt/","s":"n.","e":"[n.] A unit of liquid capacity equal to two pints; one-fourth (quarter) of a gallon. Equivalent to 1.136 liters in the UK and 0.946 liter (liquid quart) or 1.101 liters (dry quart) in the U.S.\n[n.] Four successive cards of the same suit.\n[n.] A fourth; a quarter; hence, a region of the earth.","ex":""},"QUARTER":{"p":"/ˈkoː.tɘ/","s":"n./v./adj.","e":"[n.] A fourth part of something.\n[n.] Place or position.\n[n.] Technical or specialized senses.\n[v.] To divide into quarters; to divide by four.\n[v.] To provide housing for military personnel or other equipment.\n[v.] To lodge; to have a temporary residence.","ex":"Quarter the horses in the third stable."},"QUASH":{"p":"/kwɒʃ/","s":"v.","e":"[v.] To defeat decisively.\n[v.] To crush or dash to pieces.\n[v.] To void or suppress (a subpoena, decision, etc.).","ex":"The army quashed the rebellion."},"QUAYS":{"p":"","s":"n.","e":"[n.] A stone or concrete structure on navigable water used for loading and unloading vessels; a wharf.","ex":""},"QUEEN":{"p":"/kwiːn/","s":"n./v.","e":"[n.] A female monarch. Example: Queen Victoria.\n[n.] The wife or widow of a king.\n[n.] The most powerful piece, able to move any number of spaces horizontally, vertically, or diagonally.\n[v.] To make a queen.\n[v.] To act the part of a queen; to queen it.\n[v.] To promote a pawn, usually to a queen.","ex":""},"QUASI":{"p":"/ˈkweɪ.zaɪ/","s":"adj.","e":"[adj.] Resembling or having a likeness to something","ex":""},"QUEER":{"p":"/kwɪə/","s":"n./v./adj./adv.","e":"[n.] (sometimes derogatory) A person who is or appears homosexual, or who has homosexual qualities.\n[n.] (sometimes derogatory) A person of any non-heterosexual sexuality or sexual identity.\n[n.] (sometimes derogatory) A person of any genderqueer identity.\n[v.] To render an endeavor or agreement ineffective or null.\n[v.] To puzzle.\n[v.] To ridicule; to banter; to rally.","ex":""},"PUSH":{"p":"[pʷʊʃ]","s":"n./v.","e":"[n.] A short, directed application of force; an act of pushing.\n[n.] An act of tensing the muscles of the abdomen in order to expel its contents.\n[n.] A great effort (to do something).\n[v.] To apply a force to (an object) such that it moves away from the person or thing applying the force.\n[v.] To continually attempt to persuade (a person) into a particular course of action.\n[v.] To press or urge forward; to drive.","ex":"Give the door a hard push if it sticks."},"PUSHY":{"p":"/ˈpʊ.ʃi/","s":"adj.","e":"[adj.] Aggressively ambitious; overly assertive, bold or determined.","ex":"Parents are ruining school sports days by being pushy and overbearing, a survey suggests. BBC"},"QUELL":{"p":"/kwɛl/","s":"n./v.","e":"[n.] A subduing.\n[v.] To subdue, to put down; to silence or force (someone) to submit.\n[v.] To suppress, to put an end to (something); to extinguish.\n[v.] To kill.","ex":"to quell grief"},"QUERY":{"p":"/ˈkwɪə.ɹi/","s":"n./v.","e":"[n.] A question, an inquiry (US), an enquiry (UK).\n[n.] A question mark.\n[n.] A set of instructions passed to a database.\n[v.] To ask a question.\n[v.] To ask, inquire.\n[v.] To question or call into doubt.","ex":"The teacher answered the student’s query concerning biosynthesis."},"QUEST":{"p":"/kwɛst/","s":"n./v.","e":"[n.] A journey or effort in pursuit of a goal (often lengthy, ambitious, or fervent); a mission.\n[n.] The act of seeking, or looking after anything; attempt to find or obtain; search; pursuit.\n[n.] Request; desire; solicitation.\n[v.] To seek or pursue a goal; to undertake a mission or job.\n[v.] To search for; to examine.\n[v.] (of a tick) To locate and attach to a host animal.","ex":"to rove in quest of game, of a lost child, of property, etc."},"QUEUE":{"p":"/kjuː/","s":"n./v.","e":"[n.] An animal's tail.\n[n.] A men's hairstyle whose primary attribute is a braid or ponytail at the back of the head, such as that worn by men in Imperial China.\n[n.] A line of people, vehicles or other objects, in which one at the front end is dealt with first, the one behind is dealt with next, and so on, and which newcomers join at the opposite end (the back).\n[v.] To put oneself or itself at the end of a waiting line.\n[v.] To arrange themselves into a physical waiting queue.\n[v.] To add to a queue data structure.","ex":""},"QUICK":{"p":"/kwɪk/","s":"n./v./adj./adv.","e":"[n.] Raw or sensitive flesh, especially that underneath finger and toe nails.\n[n.] Plants used in making a quickset hedge\n[n.] The life; the mortal point; a vital part; a part susceptible to serious injury or keen feeling.\n[v.] To amalgamate surfaces prior to gilding or silvering by dipping them into a solution of mercury in nitric acid.\n[v.] To quicken.\n[adj.] Moving with speed, rapidity or swiftness, or capable of doing so; rapid; fast.","ex":"He's a quick runner."},"QUIDS":{"p":"","s":"n.","e":"[n.] The inherent nature of something.\n[n.] A section of the Democratic-Republican Party between 1805 and 1811 (from tertium quid).\n[n.] A sovereign or guinea.\n[n.] Pound sterling.\n[n.] Pound (before the 1966 currency change)\n[n.] A piece of chewing tobacco.","ex":"Four quid for a toastie? You're joking aren't you?!"},"QUIETLY":{"p":"/ˈkwaɪ.ɪt.li/","s":"adv.","e":"[adv.] In a quiet manner.","ex":""},"QUIET":{"p":"/ˈkwaɪ.ət/","s":"n./v./adj./int.","e":"[n.] The absence of sound; quietness.\n[n.] The absence of movement; stillness, tranquility\n[v.] To become quiet, silent, still, tranquil, calm.\n[v.] To cause someone to become quiet.\n[adj.] With little or no sound; free of disturbing noise.\n[adj.] Having little motion or activity; calm.","ex":"There was a strange quiet in the normally very lively plaza."},"QUIFF":{"p":"/kwɪf/","s":"n.","e":"[n.] (British dialect) A puff or whiff, especially of tobacco smoke.","ex":""},"QUILL":{"p":"/kwɪl/","s":"n./v.","e":"[n.] The lower shaft of a feather, specifically the region lacking barbs.\n[n.] A pen made from a feather.\n[n.] Any pen.\n[v.] To pierce or be pierced with quills.\n[v.] To write.\n[v.] To form fabric into small, rounded folds.","ex":"He picked up his quill and wrote a poem."},"QUILT":{"p":"/kwɪlt/","s":"n./v.","e":"[n.] A bed covering consisting of two layers of fabric stitched together, with insulation between, often having a decorative design.\n[n.] A roll of material with sound-absorbing properties, used in soundproofing.\n[n.] A quilted skirt worn by women.\n[v.] To construct a quilt.\n[v.] To construct something, such as clothing, using the same technique.","ex":"My grandmother is going to sew a quilt."},"QUINT":{"p":"/kwɛ̃/","s":"n.","e":"[n.] An interval of one fifth.\n[n.] The E string of a violin.\n[n.] In piquet, a sequence of five playing cards of the same suit; equivalent to a straight flush in poker","ex":""},"QUIP":{"p":"/kwɪp/","s":"n./v.","e":"[n.] A smart, sarcastic turn or jest; a taunt; a severe retort or comeback; a gibe.\n[v.] To make a quip.\n[v.] To taunt; to treat with quips.","ex":""},"QUIRE":{"p":"/ˈkwaɪ.ə(ɹ)/","s":"n./v.","e":"[n.] One-twentieth of a ream of paper; a collection of twenty-four or twenty-five sheets of paper of the same size and quality, unfolded or having a single fold.\n[n.] A set of leaves which are stitched together, originally a set of four pieces of paper (eight leaves, sixteen pages). This is most often a single signature (i.e. group of four), but may be several nested signatures.\n[n.] A book, poem, or pamphlet.\n[v.] To prepare quires by stitching together leaves of paper.","ex":""},"QUIT":{"p":"/kwɪt/","s":"v./adj.","e":"[v.] To pay (a debt, fine etc.).\n[v.] To repay (someone) for (something).\n[v.] To repay, pay back (a good deed, injury etc.).\n[adj.] (usually followed by of) Released from obligation, penalty, etc; free, clear, or rid.","ex":""},"QUIRK":{"p":"/kwɜːk/","s":"n./v.","e":"[n.] An idiosyncrasy; a slight glitch, mannerism; something unusual about the manner or style of something or someone\n[n.] An acute angle dividing a molding; a groove that runs lengthwise between the upper part of a moulding and a soffit\n[n.] A quibble, evasion, or subterfuge.\n[v.] To move with a wry jerk.\n[v.] To furnish with a quirk or channel.\n[v.] To use verbal tricks or quibbles","ex":"The car steers cleanly, but the gearshift has a few quirks."},"QUIRT":{"p":"/kwɜːt/","s":"n./v.","e":"[n.] A rawhide whip plaited with two thongs of buffalo hide.\n[v.] To strike with a quirt.","ex":""},"QUIPS":{"p":"","s":"n./v.","e":"[n.] A smart, sarcastic turn or jest; a taunt; a severe retort or comeback; a gibe.\n[v.] To make a quip.\n[v.] To taunt; to treat with quips.","ex":""},"QUITE":{"p":"/kwaɪt/","s":"adv./int.","e":"[adv.] (heading) To the greatest extent or degree; completely, entirely.\n[adv.] (heading) In a fully justified sense; truly, perfectly, actually.\n[adv.] To a moderate extent or degree; somewhat, rather.\n[int.] Indicates agreement; \"exactly so\".","ex":""},"QUITS":{"p":"/kwɪts/","s":"v./adj.","e":"[v.] To pay (a debt, fine etc.).\n[v.] To repay (someone) for (something).\n[v.] To repay, pay back (a good deed, injury etc.).\n[adj.] On equal monetary terms; neither owing or being owed.","ex":"Here's the last of the money you lent me. We're quits now, right?"},"QUIZ":{"p":"/kwɪz/","s":"n./v.","e":"[n.] An odd, puzzling or absurd person or thing.\n[n.] A competition in the answering of questions.\n[n.] A school examination of less importance, or of greater brevity, than others given in the same course.\n[v.] To hoax; to chaff or mock with pretended seriousness of discourse; to make sport of, as by obscure questions.\n[v.] To peer at; to eye suspiciously or mockingly.\n[v.] To question closely, to interrogate.","ex":"We came second in the pub quiz."},"QUOTA":{"p":"/ˈkwoʊtə/","s":"n.","e":"[n.] A proportional part or share; the share or proportion assigned to each in a division.\n[n.] A prescribed number or percentage that may serve as, for example, a maximum, a minimum, or a goal.\n[n.] A restriction on the import of something to a specific quantity.","ex":""},"QUOTH":{"p":"/kwəʊθ/","s":"v.","e":"[v.] To say or declare.\n[v.] (defective, modal, auxiliary) to say","ex":""},"QUOTE":{"p":"/kwəʊt/","s":"n./v.","e":"[n.] A quotation; a statement attributed to a person.\n[n.] A quotation mark.\n[n.] A summary of work to be done with a set price.\n[v.] To repeat the exact words of (a person).\n[v.] To repeat (the exact words of a person).\n[v.] To prepare a summary of work to be done and set a price.","ex":"After going over the hefty quotes, the board decided it was cheaper to have the project executed by its own staff."},"RABBI":{"p":"/ˈɹæ.baɪ/","s":"n.","e":"[n.] A Jewish scholar or teacher of halacha (Jewish law), capable of making halachic decisions.\n[n.] A Jew who is or is qualified to be the leader of a Jewish congregation.\n[n.] (police) A senior officer who acts as a mentor.","ex":""},"RABID":{"p":"/ˈɹeɪbɪd/","s":"n./adj.","e":"[n.] A human or animal infected with rabies.\n[n.] Someone who is fanatical in opinion.\n[adj.] Affected with rabies.\n[adj.] Of or pertaining to rabies, or hydrophobia.\n[adj.] Furious; raging; extremely violent.","ex":""},"RACED":{"p":"","s":"v./adj.","e":"[v.] To take part in a race (in the sense of a contest).\n[v.] To compete against in such a race.\n[v.] To move or drive at high speed; to hurry or speed.\n[v.] To assign a race to; to perceive as having a (usually specified) race.\n[adj.] (social studies) Belonging to a certain race of people.\n[v.] To demolish; to level to the ground.","ex":"The drivers were racing around the track."},"RACER":{"p":"/ˈɹeɪsə/","s":"n.","e":"[n.] Someone who takes part in a race.\n[n.] A racehorse.\n[n.] An animal known for its fast speed, or suitable for racing; applied especially to a number of North American snakes, certain kinds of lake trout, etc.","ex":""},"RACE":{"p":"/ɹeɪs/","s":"n./v.","e":"[n.] A contest between people, animals, vehicles, etc. where the goal is to be the first to reach some objective. Example: Several horses run in a horse race, and the first one to reach the finishing post wins\n[n.] Swift progress; rapid motion; an instance of moving or driving at high speed.\n[n.] A race condition.\n[v.] To take part in a race (in the sense of a contest).\n[v.] To compete against in such a race.\n[v.] To move or drive at high speed; to hurry or speed.","ex":"The race around the park was won by Johnny, who ran faster than the others."},"RACON":{"p":"","s":"n.","e":"[n.] A beacon that, on detecting a radar signal, responds by transmitting a coded navigation signal.","ex":""},"RACKS":{"p":"/ɹæks/","s":"n./v.","e":"[n.] A series of one or more shelves, stacked one above the other\n[n.] Any of various kinds of frame for holding luggage or other objects on a vehicle or vessel.\n[n.] A device, incorporating a ratchet, used to torture victims by stretching them beyond their natural limits.\n[v.] To place in or hang on a rack.\n[v.] To torture (someone) on the rack.\n[v.] To cause (someone) to suffer pain.","ex":""},"RACES":{"p":"/ˈɹeɪsɪz/","s":"n./v.","e":"[n.] A contest between people, animals, vehicles, etc. where the goal is to be the first to reach some objective. Example: Several horses run in a horse race, and the first one to reach the finishing post wins\n[n.] Swift progress; rapid motion; an instance of moving or driving at high speed.\n[n.] A race condition.\n[v.] To take part in a race (in the sense of a contest).\n[v.] To compete against in such a race.\n[v.] To move or drive at high speed; to hurry or speed.","ex":"The race around the park was won by Johnny, who ran faster than the others."},"RADAR":{"p":"/ˈɹeɪdɑː(ɹ)/","s":"n./v.","e":"[n.] A method of detecting distant objects and determining their position, velocity, or other characteristics by analysis of sent radio waves (usually microwaves) reflected from their surfaces\n[n.] A type of system using such method, differentiated by platform, configuration, frequency, power, and other technical attributes.\n[n.] An installation of such a system or of the transmitting and receiving apparatus.\n[v.] To scan with radar, or as if with radar.","ex":""},"RADII":{"p":"/ˈɹeɪ.diˌaɪ/","s":"n.","e":"[n.] The long bone in the forearm, on the side of the thumb.\n[n.] The lighter bone (or fused portion of bone) in the forelimb of an animal.\n[n.] One of the major veins of the insect wing, between the subcosta and the media; the vein running along the costal edge of the discal cell.","ex":""},"RADICAL":{"p":"/ˈɹædɪkəl/","s":"n./adj.","e":"[n.] (historical: 19th-century Britain) A member of the most progressive wing of the Liberal Party; someone favouring social reform (but generally stopping short of socialism).\n[n.] (historical: early 20th-century France) A member of an influential, centrist political party favouring moderate social reform, a republican constitution, and secular politics.\n[n.] A person with radical opinions.\n[adj.] Favoring fundamental change, or change at the root cause of a matter.\n[adj.] Pertaining to a root (of a plant).\n[adj.] Pertaining to the basic or intrinsic nature of something.","ex":"His beliefs are radical."},"RADIO":{"p":"/ˈɹeɪdiˌəʊ/","s":"n./v.","e":"[n.] The technology that allows for the transmission of sound or other signals by modulation of electromagnetic waves.\n[n.] A device that can capture (receive) the signal sent over radio waves and render the modulated signal as sound.\n[n.] On-board entertainment system in a car, usually including a radio receiver as well as the capability to play audio from recorded media.\n[v.] To use two-way radio to transmit (a message) (to another radio or other radio operator).\n[v.] To order or assist (to a location), using telecommunications.","ex":"I think the boat is sinking; we'd better radio for help. / I radioed him already. / Radio the coordinates this time. / OK. I radioed them the coordinates."},"RADON":{"p":"/ˈɹeɪdɒn/","s":"n.","e":"[n.] The chemical element (symbol Rn, formerly Ro) with atomic number 86. It is an odorless, colorless, chemically inert but radioactive noble gas.","ex":""},"RAFT":{"p":"/ɹɑːft/","s":"n./v.","e":"[n.] A flat-bottomed craft able to float and drift on water, used for transport or as a waterborne platform.\n[n.] (by extension) Any flattish thing, usually wooden, used in a similar fashion.\n[n.] A thick crowd of seabirds or sea mammals, particularly a group of penguins when in the water.\n[v.] To convey on a raft.\n[v.] To make into a raft.\n[v.] To travel by raft.","ex":"An inflatable raft. A log raft."},"RAGED":{"p":"","s":"v.","e":"[v.] To act or speak in heightened anger.\n[v.] (sometimes figurative) To move with great violence, as a storm etc.\n[v.] To enrage.","ex":""},"RAGE":{"p":"/ɹeɪdʒ/","s":"n./v.","e":"[n.] Violent uncontrolled anger.\n[n.] A current fashion or fad.\n[n.] Any vehement passion.\n[v.] To act or speak in heightened anger.\n[v.] (sometimes figurative) To move with great violence, as a storm etc.\n[v.] To enrage.","ex":"Miniskirts were all the rage back then."},"RAFTS":{"p":"","s":"n./v.","e":"[n.] A flat-bottomed craft able to float and drift on water, used for transport or as a waterborne platform.\n[n.] (by extension) Any flattish thing, usually wooden, used in a similar fashion.\n[n.] A thick crowd of seabirds or sea mammals, particularly a group of penguins when in the water.\n[v.] To convey on a raft.\n[v.] To make into a raft.\n[v.] To travel by raft.","ex":"An inflatable raft. A log raft."},"RAID":{"p":"/ɹeɪd/","s":"n./v.","e":"[n.] A quick hostile or predatory incursion or invasion in a battle.\n[n.] An attack or invasion for the purpose of making arrests, seizing property, or plundering\n[n.] An attacking movement.\n[v.] To engage in a raid against.\n[v.] To lure from another; to entice away from.\n[v.] To indulge oneself by taking from.","ex":"a police raid of a narcotics factory"},"RAGES":{"p":"","s":"n./v.","e":"[n.] Violent uncontrolled anger.\n[n.] A current fashion or fad.\n[n.] Any vehement passion.\n[v.] To act or speak in heightened anger.\n[v.] (sometimes figurative) To move with great violence, as a storm etc.\n[v.] To enrage.","ex":"Miniskirts were all the rage back then."},"RAILS":{"p":"/ɹeɪlz/","s":"n./v.","e":"[n.] A horizontal bar extending between supports and used for support or as a barrier; a railing.\n[n.] The metal bar that makes the track for a railroad.\n[n.] A railroad; a railway, as a means of transportation.\n[v.] To travel by railway.\n[v.] To enclose with rails or a railing.\n[v.] To range in a line.","ex":"We travelled to the seaside by rail."},"RAINY":{"p":"/ˈɹeɪni/","s":"adj.","e":"[adj.] Pouring with rain; wet; showery","ex":"Due to the rainy weather, we decided not to play in the park."},"RAIN":{"p":"/ɹeɪn/","s":"n./v.","e":"[n.] Condensed water falling from a cloud.\n[n.] Any matter moving or falling, usually through air, and especially if liquid or otherwise figuratively identifiable with raindrops.\n[n.] An instance of particles or larger pieces of matter moving or falling through air.\n[v.] To have rain fall from the sky.\n[v.] To fall as or like rain.\n[v.] To issue (something) in large quantities.","ex":"The rains came late that year."},"RAIL":{"p":"/ɹeɪl/","s":"n./v.","e":"[n.] A horizontal bar extending between supports and used for support or as a barrier; a railing.\n[n.] The metal bar that makes the track for a railroad.\n[n.] A railroad; a railway, as a means of transportation.\n[v.] To travel by railway.\n[v.] To enclose with rails or a railing.\n[v.] To range in a line.","ex":"We travelled to the seaside by rail."},"RAINS":{"p":"/ɹeɪnz/","s":"n./v.","e":"[n.] Condensed water falling from a cloud.\n[n.] Any matter moving or falling, usually through air, and especially if liquid or otherwise figuratively identifiable with raindrops.\n[n.] An instance of particles or larger pieces of matter moving or falling through air.\n[v.] To have rain fall from the sky.\n[v.] To fall as or like rain.\n[v.] To issue (something) in large quantities.","ex":"The rains came late that year."},"RAISE":{"p":"/ɹeɪz/","s":"n./v.","e":"[n.] An increase in wages or salary; a rise (UK).\n[n.] A shoulder exercise in which the arms are elevated against resistance.\n[n.] A shot in which the delivered stone bumps another stone forward.\n[v.] (physical) To cause to rise; to lift or elevate.\n[v.] To create, increase or develop.\n[v.] To establish contact with (e.g., by telephone or radio).","ex":"The boss gave me a raise."},"RAISED":{"p":"/ɹeɪzd/","s":"v./adj.","e":"[v.] (physical) To cause to rise; to lift or elevate.\n[v.] To create, increase or develop.\n[v.] To establish contact with (e.g., by telephone or radio).\n[adj.] Embossed, in relief.","ex":"to raise your hand if you want to say something; to raise your walking stick to defend yourself"},"RALLY":{"p":"/ˈɹæ.li/","s":"n./v.","e":"[n.] A public gathering or mass meeting that is not mainly a protest and is organized to inspire enthusiasm for a cause.\n[n.] A protest or demonstration for or against something, but often with speeches and often without marching, especially in North America.\n[n.] A sequence of strokes between serving and scoring a point.\n[v.] To collect, and reduce to order, as troops dispersed or thrown into confusion; to gather again; to reunite.\n[v.] To come into orderly arrangement; to renew order, or united effort, as troops scattered or put to flight; to assemble; to unite.\n[v.] To collect one's vital powers or forces; to regain health or consciousness; to recuperate.","ex":"a campaign rally"},"RAKED":{"p":"/ɹeɪkt/","s":"v./adj.","e":"[v.] To walk; to roam, to wander.\n[v.] Of animals (especially sheep): to graze.\n[v.] To roam or wander through (somewhere).\n[v.] To act upon with a rake, or as if with a rake.\n[v.] To move swiftly; to proceed rapidly.\n[v.] Of a bird of prey: to fly after a quarry; also, to fly away from the falconer, to go wide of the quarry being pursued.","ex":"She is raking the gravel path to keep it even."},"RAJAH":{"p":"","s":"n.","e":"[n.] A Hindu prince or ruler in India.\n[n.] Any of various nymphalid butterflies of the genus Charaxes.","ex":""},"RAKES":{"p":"/ɹeɪks/","s":"n./v.","e":"[n.] A walk, or a journey taken (especially on foot); the act of taking a walk or journey.\n[n.] The movement of animals while grazing.\n[n.] The pastureland over which animals graze; a range, a stray.\n[v.] To walk; to roam, to wander.\n[v.] Of animals (especially sheep): to graze.\n[v.] To roam or wander through (somewhere).","ex":"She is raking the gravel path to keep it even."},"RALPH":{"p":"/ɹælf/","s":"v.","e":"[v.] To vomit.","ex":""},"RAMEN":{"p":"","s":"n./adv.","e":"[n.] Soup noodles of wheat, with various ingredients (Japanese style)\n[n.] A type of instant noodles.\n[adv.] (Pastafarianism) amen","ex":""},"RAMPS":{"p":"","s":"n./v.","e":"[n.] An inclined surface that connects two levels; an incline.\n[n.] A road that connects a freeway to a surface street or another freeway.\n[n.] A mobile staircase that is attached to the doors of an aircraft at an airport\n[v.] To behave violently; to rage.\n[v.] To spring; to leap; to bound, rear, or prance; to move swiftly or violently.\n[v.] To climb, like a plant; to creep up.","ex":""},"RANCH":{"p":"/ɹɑːntʃ/","s":"n./v.","e":"[n.] A large plot of land used for raising cattle, sheep or other livestock.\n[n.] A small farm that cultivates vegetables and/or livestock, especially one in the Southwestern United States.\n[n.] A house or property on a plot of ranch land.\n[v.] To operate a ranch; engage in ranching.\n[v.] To work on a ranch","ex":"Formally the widow still ranches, but in fact she leaves all ranching to the foreman."},"RANGE":{"p":"/ɹeɪndʒ/","s":"n./v.","e":"[n.] A line or series of mountains, buildings, etc.\n[n.] A fireplace; a fire or other cooking apparatus; now specifically, a large cooking stove with many hotplates.\n[n.] Selection, array.\n[v.] To travel over (an area, etc); to roam, wander.\n[v.] To rove over or through.\n[v.] To exercise the power of something over something else; to cause to submit to, over.","ex":"We sell a wide range of cars."},"RANDOM":{"p":"/ˈɹændəm/","s":"n./adj.","e":"[n.] A roving motion; course without definite direction; lack of rule or method; chance.\n[n.] Speed, full speed; impetuosity, force.\n[n.] The full range of a bullet or other projectile; hence, the angle at which a weapon is tilted to allow the greatest range.\n[adj.] Having unpredictable outcomes and, in the ideal case, all outcomes equally probable; resulting from such selection; lacking statistical correlation.\n[adj.] Of or relating to probability distribution.\n[adj.] Pseudorandom; mimicking the result of random selection.","ex":"The flip of a fair coin is purely random."},"RANEE":{"p":"","s":"n.","e":"[n.] The wife of a rajah.\n[n.] A Hindu princess or female ruler in India.","ex":""},"RANGING":{"p":"","s":"v./n.","e":"[v.] To travel over (an area, etc); to roam, wander.\n[v.] To rove over or through.\n[v.] To exercise the power of something over something else; to cause to submit to, over.\n[n.] Act of one who ranges.\n[n.] A back-and-forth movement","ex":"to range the fields"},"RANGY":{"p":"/ˈɹeɪndʒi/","s":"adj.","e":"[adj.] Slender and long of limb; lanky\n[adj.] Prone to roaming around.\n[adj.] Having or permitting range or scope; roomy; commodious.","ex":"For an accountant, Robert had a rangy appearance."},"RANKS":{"p":"/ɹæŋks/","s":"n./v.","e":"[n.] A row of people or things organized in a grid pattern, often soldiers [the corresponding term for the perpendicular columns in such a pattern is \"file\"].\n[n.] In a pipe organ, a set of pipes of a certain quality for which each pipe corresponds to one key or pedal.\n[n.] One's position in a list sorted by a shared property such as physical location, population, or quality\n[v.] To place abreast, or in a line.\n[v.] To have a ranking.\n[v.] To assign a suitable place in a class or order; to classify.","ex":"The front rank kneeled to reload while the second rank fired over their heads."},"RANK":{"p":"/ɹæŋk/","s":"adj./adv.","e":"[adj.] Strong of its kind or in character; unmitigated; virulent; thorough; utter (used of negative things).\n[adj.] Strong in growth; growing with vigour or rapidity, hence, coarse or gross.\n[adj.] Suffering from overgrowth or hypertrophy; plethoric.\n[adv.] Quickly, eagerly, impetuously.","ex":"rank nonsense"},"RANDS":{"p":"","s":"n.","e":"[n.] The border of an area of land, especially marshland.\n[n.] A strip of meat; a long fleshy piece of beef, cut from the flank or leg; a sort of steak.\n[n.] A border, edge or rim.\n[n.] A rocky slope, especially the area over a river valley; specifically, the Rand\n[n.] The currency of South Africa, divided into 100 cents.","ex":"At the wald's rand."},"RANSOM":{"p":"/ˈɹænsəm/","s":"n./v.","e":"[n.] Money paid for the freeing of a hostage.\n[n.] The release of a captive, or of captured property, by payment of a consideration.\n[n.] A sum paid for the pardon of some great offence and the discharge of the offender; also, a fine paid in lieu of corporal punishment.\n[v.] (14th century) To deliver, especially in context of sin or relevant penalties.\n[v.] To pay a price to set someone free from captivity or punishment.\n[v.] To exact a ransom for, or a payment on.","ex":"They were held for two million dollars ransom."},"RANTS":{"p":"/ˈɹænts/","s":"n./v.","e":"[n.] A criticism done by ranting.\n[n.] A wild, emotional, and sometimes incoherent articulation.\n[n.] A type of dance step usually performed in clogs, and particularly (but not exclusively) associated with the English North West Morris tradition. The rant step consists of alternately bringing one foot across and in front of the other and striking the ground, with the other foot making a little hop.\n[v.] To speak or shout at length in uncontrollable anger.\n[v.] To criticize by ranting.\n[v.] To speak extravagantly, as in merriment.","ex":""},"RAPID":{"p":"/ˈɹæpɪd/","s":"n./adj./adv.","e":"[n.] (often in the plural) a rough section of a river or stream which is difficult to navigate due to the swift and turbulent motion of the water.\n[n.] A burst of rapid fire.\n[adj.] Very swift or quick.\n[adj.] Steep, changing altitude quickly. (of a slope)\n[adj.] Needing only a brief exposure time. (of a lens, plate, film, etc.)\n[adv.] (archaic or colloquial) Rapidly.","ex":"a rapid stream"},"RARELY":{"p":"/ˈɹɛːli/","s":"adv.","e":"[adv.] Not occurring at a regular interval; seldom; not often.\n[adv.] Unusually well; excellently.\n[adv.] To a rare degree; very.","ex":"Rarely do you ever find an eagle this far up the river."},"RASPS":{"p":"","s":"n./v.","e":"[n.] A coarse file, on which the cutting prominences are distinct points raised by the oblique stroke of a sharp punch, instead of lines raised by a chisel, as on the true file.\n[n.] The sound made by this tool when used, or any similar sound.\n[v.] To use a rasp.\n[v.] To make a noise similar to the one a rasp makes in use; to utter rasps.\n[v.] To work something with a rasp.\n[n.] The raspberry.","ex":"the rasp of her perpetual cough"},"RATE":{"p":"/ɹeɪt/","s":"n./v.","e":"[n.] The worth of something; value.\n[n.] The proportional relationship between one amount, value etc. and another.\n[n.] Speed.\n[v.] To assign or be assigned a particular rank or level.\n[v.] To evaluate or estimate the value of.\n[v.] To consider or regard.","ex":"At the height of his powers, he was producing pictures at the rate of four a year."},"RATED":{"p":"/ˈɹeɪtɪd/","s":"v./adj.","e":"[v.] To assign or be assigned a particular rank or level.\n[v.] To evaluate or estimate the value of.\n[v.] To consider or regard.\n[v.] To berate, scold.\n[adj.] Scolded, rebuked.\n[adj.] Maximum (load, voltage, etc.) under which a device can function properly","ex":"She is rated fourth in the country."},"RATES":{"p":"/ɹeɪts/","s":"n./v.","e":"[n.] The worth of something; value.\n[n.] The proportional relationship between one amount, value etc. and another.\n[n.] Speed.\n[v.] To assign or be assigned a particular rank or level.\n[v.] To evaluate or estimate the value of.\n[v.] To consider or regard.","ex":"At the height of his powers, he was producing pictures at the rate of four a year."},"RARE":{"p":"[ɹɜɹ]","s":"n./adj.","e":"[n.] A scarce or uncommon item.\n[adj.] Very uncommon; scarce.\n[adj.] (of a gas) Thin; of low density.\n[adj.] Good; enjoyable.","ex":"Black pearls are very rare and therefore very valuable."},"RATHER":{"p":"/ˈɹɑːðə/","s":"v./adj./adv./int.","e":"[v.] To prefer; to prefer to.\n[adj.] Prior; earlier; former.\n[adv.] More quickly; sooner, earlier.\n[adv.] Used to specify a choice or preference; preferably, in preference to. (Now usually followed by than)\n[adv.] Used to introduce a contradiction; on the contrary.\n[int.] An enthusiastic affirmation.","ex":"I'd like this one rather than the other one."},"RATHE":{"p":"/ɹeɪð/","s":"adj.","e":"[adj.] Ripening or blooming early.","ex":""},"RAVED":{"p":"","s":"v.","e":"[v.] To wander in mind or intellect; to be delirious; to talk or act irrationally; to be wild, furious, or raging.\n[v.] To speak or write wildly or incoherently.\n[v.] To talk with unreasonable enthusiasm or excessive passion or excitement; followed by about, of, or (formerly) on.","ex":"He raved about her beauty."},"RATING":{"p":"/ˈɹeɪtɪŋ/","s":"v./n.","e":"[v.] To assign or be assigned a particular rank or level.\n[v.] To evaluate or estimate the value of.\n[v.] To consider or regard.\n[v.] To berate, scold.\n[n.] A position on a scale\n[n.] An evaluation of status, especially of financial status","ex":"She is rated fourth in the country."},"RAVER":{"p":"","s":"n.","e":"[n.] A person who attends rave parties, or who belongs to that subculture.\n[n.] A person who raves or rants.","ex":""},"RATTY":{"p":"/ˈɹati/","s":"adj.","e":"[adj.] Similar to a rat; ratlike.\n[adj.] Infested with rats.\n[adj.] In poor condition or repair","ex":""},"RAVES":{"p":"/ɹeɪvz/","s":"n./v.","e":"[n.] An enthusiastic review (such as of a play).\n[n.] An all-night dance party with electronic dance music (techno, trance, drum and bass etc.) and possibly drug use.\n[n.] The genres of electronic dance music usually associated with rave parties.\n[v.] To wander in mind or intellect; to be delirious; to talk or act irrationally; to be wild, furious, or raging.\n[v.] To speak or write wildly or incoherently.\n[v.] To talk with unreasonable enthusiasm or excessive passion or excitement; followed by about, of, or (formerly) on.","ex":"He raved about her beauty."},"RAYED":{"p":"","s":"v.","e":"[v.] To emit something as if in rays.\n[v.] To radiate as if in rays.\n[v.] To arrange.\n[v.] To dress, array (someone).\n[v.] To stain or soil; to defile.","ex":""},"RAYON":{"p":"","s":"n.","e":"[n.] A manufactured regenerated cellulosic fiber.","ex":""},"RAZOR":{"p":"/ˈɹeɪzə/","s":"n./v.","e":"[n.] A keen-edged knife of peculiar shape, used in shaving the hair from the face or other parts of the body.\n[n.] Any tool or instrument designed for shaving.\n[n.] The sharp tusk of a wild boar.\n[v.] To shave with a razor.","ex":""},"REACH":{"p":"/ɹiːt͡ʃ/","s":"n./v.","e":"[n.] The act of stretching or extending; extension.\n[n.] The ability to reach or touch with the person, a limb, or something held or thrown.\n[n.] The power of stretching out or extending action, influence, or the like; power of attainment or management; extent of force or capacity.\n[v.] To extend, stretch, or thrust out (for example a limb or object held in the hand).\n[v.] To give to someone by stretching out a limb, especially the hand; to give with the hand; to pass to another person; to hand over.\n[v.] To stretch out the hand.","ex":"The fruit is beyond my reach."},"READING":{"p":"/ˈɹidiŋ/","s":"v./n.","e":"[v.] To look at and interpret letters or other information that is written.\n[v.] To speak aloud words or other information that is written. Often construed with a to phrase or an indirect object.\n[v.] To read work(s) written by (a named author).\n[n.] The process of interpreting written language.\n[n.] The process of interpreting a symbol, a sign or a measuring device.\n[n.] A value indicated by a measuring device.","ex":"Have you read this book?"},"READILY":{"p":"/ˈɹɛdɪli/","s":"adv.","e":"[adv.] Without unwillingness or hesitation; showing readiness.\n[adv.] Without impediment, easily.","ex":"The suspect readily answered all questions the police officers asked him."},"RATIO":{"p":"/ˈɹeɪ.ʃi.əʊ/","s":"n./v.","e":"[n.] A number representing a comparison between two named things.\n[n.] The relative magnitudes of two quantities (usually expressed as a quotient).\n[n.] Short for ratio decidendi.\n[v.] (social media) To respond to a post or message on social media in a greater number than the number of likes the post receives.","ex":"The schoolchildren ganged up to ratio the school catering over its shamefully undemocratic inclusion of vegetables in meals."},"RAZED":{"p":"","s":"v./adj.","e":"[v.] To demolish; to level to the ground.\n[v.] To scrape as if with a razor.\n[adj.] Slashed or striped in patterns.","ex":""},"REALIZE":{"p":"/ˈɹɪə.laɪz/","s":"v.","e":"[v.] To make real; to convert from the imaginary or fictitious into reality; to bring into real existence\n[v.] To become aware of (a fact or situation, especially of something that has been true for a long time).\n[v.] To cause to seem real; to sense vividly or strongly; to make one's own in thought or experience.","ex":"The objectives of the project were never fully realized."},"REACT":{"p":"/ɹiːˈækt/","s":"n./v.","e":"[n.] An emoji used to express a reaction to a post on social media.\n[v.] To act or perform a second time; to do over again; to reenact.\n[v.] To return an impulse or impression; to resist the action of another body by an opposite force\n[v.] To act upon each other; to exercise a reciprocal or a reverse effect, as two or more chemical agents; to act in opposition.","ex":"Sad reacts only"},"READS":{"p":"/ɹiːdz/","s":"n./v.","e":"[n.] A reading or an act of reading, especially an actor's part of a play.\n[n.] (in combination) Something to be read; a written work.\n[n.] A person's interpretation or impression of something.\n[v.] To look at and interpret letters or other information that is written.\n[v.] To speak aloud words or other information that is written. Often construed with a to phrase or an indirect object.\n[v.] To read work(s) written by (a named author).","ex":"His thrillers are always a gripping read."},"READ":{"p":"/ɹiːd/","s":"n./v.","e":"[n.] A reading or an act of reading, especially an actor's part of a play.\n[n.] (in combination) Something to be read; a written work.\n[n.] A person's interpretation or impression of something.\n[v.] To look at and interpret letters or other information that is written.\n[v.] To speak aloud words or other information that is written. Often construed with a to phrase or an indirect object.\n[v.] To read work(s) written by (a named author).","ex":"His thrillers are always a gripping read."},"REAL":{"p":"/ɹiːl/","s":"n./adj./adv.","e":"[n.] A commodity; see realty.\n[n.] (grammar) One of the three genders that the common gender can be separated into in the Scandinavian languages.\n[n.] A real number.\n[adj.] True, genuine, not merely nominal or apparent.\n[adj.] Genuine, not artificial, counterfeit, or fake.\n[adj.] Genuine, unfeigned, sincere.","ex":"This is real leather."},"READY":{"p":"/ˈɹɛdi/","s":"n./v./adj.","e":"[n.] Ready money; cash\n[v.] To prepare; to make ready for action.\n[adj.] Prepared for immediate action or use.\n[adj.] Inclined; apt to happen.\n[adj.] Liable at any moment.","ex":"The porridge is ready to serve."},"REAR":{"p":"/ɹɪə/","s":"v.","e":"[v.] To bring up to maturity, as offspring; to educate; to instruct; to foster.\n[v.] (said of people towards animals) To breed and raise.\n[v.] To rise up on the hind legs","ex":"The family has been rearing cattle for 200 years."},"REALITY":{"p":"/ɹiˈæləti/","s":"n.","e":"[n.] The state of being actual or real.\n[n.] A real entity, event or other fact.\n[n.] The entirety of all that is real.","ex":"The reality of the crash scene on TV dawned upon him only when he saw the victim was no actor but his friend."},"REALM":{"p":"/ɹɛlm/","s":"n.","e":"[n.] An abstract sphere of influence, real or imagined.\n[n.] The domain of a certain abstraction.\n[n.] A scope of operation in networking or security.","ex":""},"REARS":{"p":"","s":"v./n.","e":"[v.] To bring up to maturity, as offspring; to educate; to instruct; to foster.\n[v.] (said of people towards animals) To breed and raise.\n[v.] To rise up on the hind legs\n[v.] To move; stir.\n[v.] (of geese) To carve.\n[v.] (regional, obsolete) To revive, bring to life, quicken. (only in the phrase, to rear to life)","ex":"The family has been rearing cattle for 200 years."},"REBEL":{"p":"/ˈɹɛbəl/","s":"n.","e":"[n.] A person who resists an established authority, often violently\n[n.] A person from the Confederate States of America","ex":""},"REBUS":{"p":"/ˈɹiːbəs/","s":"n./v.","e":"[n.] A kind of word puzzle which uses pictures to represent words or parts of words.\n[n.] A pictorial suggestion on a coat of arms of the name of the person to whom it belongs.\n[v.] To mark or indicate by a rebus.","ex":""},"REAMS":{"p":"/ɹiːmz/","s":"v./n.","e":"[v.] To cream; mantle; foam; froth.\n[v.] To enlarge a hole, especially using a reamer; to bore a hole wider.\n[v.] To shape or form, especially using a reamer.\n[v.] To remove (material) by reaming.\n[n.] A bundle, package, or quantity of paper, nowadays usually containing 500 sheets.\n[n.] (chiefly in the plural) An abstract large amount of something.","ex":"I can't go – I still have reams of work left."},"REBAR":{"p":"/ˈɹiː.bɑː(ɹ)/","s":"n./v.","e":"[n.] A steel reinforcing bar in a reinforced concrete structure.\n[n.] A grid-shaped system of such bars.\n[v.] To reinforce with bars of this kind.","ex":""},"REBUT":{"p":"/ɹɪ.ˈbʌt/","s":"v.","e":"[v.] To drive back or beat back; to repulse.\n[v.] To deny the truth of something, especially by presenting arguments that disprove it.","ex":""},"RECAP":{"p":"/ɹiːˈkæp/","s":"n./v.","e":"[n.] A tire that has had new tread glued on.\n[v.] To seal (something) again with a cap.\n[v.] To replace the worn tread on a tire by gluing a new outer portion. (US English only - Retread in UK English)","ex":""},"REARM":{"p":"","s":"v.","e":"[v.] To replace or restore the weapons or arms of a previously defeated, or disarmed army, country, person or other body.","ex":""},"REASON":{"p":"/ˈɹiːzən/","s":"n./v.","e":"[n.] A cause:\n[n.] Rational thinking (or the capacity for it); the cognitive faculties, collectively, of conception, judgment, deduction and intuition.\n[n.] Something reasonable, in accordance with thought; justice.\n[v.] To deduce or come to a conclusion by being rational\n[v.] To perform a process of deduction or of induction, in order to convince or to confute; to argue.\n[v.] To converse; to compare opinions.","ex":"Mankind should develop reason above all other virtues."},"RECALL":{"p":"","s":"n./v.","e":"[n.] The action or fact of calling someone or something back.\n[n.] Memory; the ability to remember.\n[n.] (information retrieval) the fraction of (all) relevant material that is returned by a search\n[v.] To withdraw, retract (one's words etc.); to revoke (an order).\n[v.] To call back, bring back or summon (someone) to a specific place, station etc.\n[v.] To bring back (someone) to or from a particular mental or physical state, activity etc.","ex":"He was recalled to service after his retirement."},"RECON":{"p":"/ɹɪˈkɒn/","s":"n./v.","e":"[n.] Reconnaissance.\n[v.] Reconnoiter.","ex":""},"RECOVER":{"p":"/ɹɪˈkʌvə/","s":"n./v.","e":"[n.] Recovery.\n[n.] A position of holding a firearm during exercises, whereby the lock is at shoulder height and the sling facing out.\n[n.] The forward movement in rowing, after one stroke to take another (recovery)\n[v.] To get back, to regain (a physical thing; in astronomy and navigation, sight of a thing or a signal).\n[v.] To salvage, to extricate, to rescue (a thing or person)\n[v.] To replenish to, resume (a good state of mind or body).","ex":"After days of inquiries, he finally recovered his lost wallet."},"RECORD":{"p":"/ˈɹɛkɔːd/","s":"n.","e":"[n.] A disk, usually made of a polymer, used to record sound for playback on a phonograph.\n[n.] An item of information put into a temporary or permanent physical medium.\n[n.] Any instance of a physical medium on which information was put for the purpose of preserving it and making it available for future reference.\n[n.] A set of data relating to a single individual or item.","ex":"The person had a record of the interview so she could review her notes."},"RECUR":{"p":"/ɹɪˈkɜː(ɹ)/","s":"v.","e":"[v.] To have recourse (to) someone or something for assistance, support etc.\n[v.] To happen again.\n[v.] To recurse.","ex":"The theme of the prodigal son recurs later in the third act."},"RECEIVE":{"p":"/ɹɪˈsiːv/","s":"n./v.","e":"[n.] An operation in which data is received.\n[v.] To take, as something that is offered, given, committed, sent, paid, etc.; to accept; to be given something.\n[v.] To take goods knowing them to be stolen.\n[v.] To act as a host for guests; to give admittance to; to permit to enter, as into one's house, presence, company, etc.","ex":"She received many presents for her birthday."},"REDUCED":{"p":"/ɹɪˈdjuːst/","s":"v./adj.","e":"[v.] To bring down the size, quantity, quality, value or intensity of something; to diminish, to lower.\n[v.] To lose weight.\n[v.] To bring to an inferior rank; to degrade, to demote.\n[adj.] Made smaller or less; having undergone reduction.\n[adj.] Discounted in price.\n[adj.] Of a sauce etc.: made more concentrated.","ex":"to reduce weight, speed, heat, expenses, price, personnel etc."},"REDID":{"p":"/ɹi.dɪd/","s":"v.","e":"[v.] To do again.","ex":""},"REEDY":{"p":"/ˈɹiː.di/","s":"adj.","e":"[adj.] Full of, or edged with, reeds.\n[adj.] (of a sound or voice) High and thin in tone.\n[adj.] (of a person) Tall and thin.","ex":""},"REDUCE":{"p":"/ɹɪˈdjuːs/","s":"v.","e":"[v.] To bring down the size, quantity, quality, value or intensity of something; to diminish, to lower.\n[v.] To lose weight.\n[v.] To bring to an inferior rank; to degrade, to demote.","ex":"to reduce weight, speed, heat, expenses, price, personnel etc."},"REEFS":{"p":"","s":"n./v.","e":"[n.] A chain or range of rocks, sand, or coral lying at or near the surface of the water.\n[n.] A large vein of auriferous quartz; hence, any body of rock yielding valuable ore.\n[n.] A portion of a sail rolled and tied down to lessen the area exposed in a high wind.\n[v.] To take in part of a sail in order to adapt the size of the sail to the force of the wind.\n[v.] To pull or yank strongly, especially in relation to horse riding.\n[v.] (of paddles) To move the floats of a paddle wheel toward its center so that they will not dip so deeply.","ex":"Reef the paddles."},"RECENT":{"p":"/ˈɹiːsənt/","s":"adj.","e":"[adj.] Having happened a short while ago.\n[adj.] Up-to-date; not old-fashioned or dated.\n[adj.] Having done something a short while ago that distinguishes them as what they are called.","ex":"I met three recent graduates at the conference."},"REEDS":{"p":"","s":"n./v.","e":"[n.] Any of various types of tall stiff perennial grass-like plants growing together in groups near water.\n[n.] The hollow stem of these plants.\n[n.] Part of the mouthpiece of certain woodwind instruments, comprising a thin piece of wood or metal which shakes very quickly to produce sound when a musician blows over it.\n[v.] To thatch.\n[v.] To mill or mint with reeding.\n[n.] The fourth stomach of a ruminant; rennet.","ex":""},"RECTO":{"p":"/ˈɹɛk.toʊ/","s":"n.","e":"[n.] The front side of a flat object which is to be examined visually, as for reading, such as a sheet, leaf, coin or medal.\n[n.] The right-hand page of a book of a script which reads from left to right, usually having an odd page number.\n[n.] A writ of right.","ex":""},"RECUT":{"p":"","s":"v.","e":"[v.] To cut again","ex":""},"REFORM":{"p":"/ɹɪˈfɔːm/","s":"n./v.","e":"[n.] The change of something that is defective, broken, inefficient or otherwise negative, in order to correct or improve it\n[v.] To put into a new and improved form or condition; to restore to a former good state, or bring from bad to good; to change from worse to better\n[v.] To return to a good state; to amend or correct one's own character or habits\n[v.] To form again or in a new configuration.","ex":"A major reform is needed to improve the efficiency in the factory."},"REFLECT":{"p":"/ɹɪˈflɛkt/","s":"v.","e":"[v.] To bend back (light, etc.) from a surface.\n[v.] To be bent back (light, etc.) from a surface.\n[v.] To mirror, or show the image of something.","ex":"A mirror reflects the light that shines on it."},"RECYCLE":{"p":"/ɹiˈsaɪkəl/","s":"n./v.","e":"[n.] An act of recycling.\n[v.] To break down and reuse component materials.\n[v.] To reuse as a whole.\n[v.] To collect or place in a bin for recycling.","ex":"Both paper and plastic can be recycled."},"REDOS":{"p":"","s":"n.","e":"[n.] A repeated action; a doing again, refurbishment, etc.","ex":""},"REFUSED":{"p":"/ɹɪˈfjuːzd/","s":"v.","e":"[v.] To decline (a request or demand).\n[v.] To decline a request or demand, forbear; to withhold permission.\n[v.] To throw back, or cause to keep back (as the centre, a wing, or a flank), out of the regular alignment when troops are about to engage the enemy.\n[v.] To melt again.","ex":"My request for a pay rise was refused."},"REFER":{"p":"/ɹɪˈfɜː/","s":"v.","e":"[v.] To direct the attention of.\n[v.] To submit to (another person or group) for consideration; to send or direct elsewhere.\n[v.] To place in or under by a mental or rational process; to assign to, as a class, a cause, source, a motive, reason, or ground of explanation.","ex":""},"REGAL":{"p":"/ˈɹiːɡəl/","s":"adj.","e":"[adj.] Of or relating to royalty.\n[adj.] Befitting a king, queen, emperor, or empress.","ex":"regal authority;   the regal title"},"REGULAR":{"p":"/ˈɹɛɡjʊlə/","s":"n./adj./adv.","e":"[n.] A member of the British Army (as opposed to a member of the Territorial Army or Reserve).\n[n.] A frequent, routine visitor to an establishment.\n[n.] A frequent customer, client or business partner.\n[adj.] Bound by religious rule; belonging to a monastic or religious order (often as opposed to secular).\n[adj.] Having a constant pattern; showing evenness of form or appearance.\n[adj.] (of a polygon) Both equilateral and equiangular; having all sides of the same length, and all (corresponding) angles of the same size","ex":"Bartenders usually know their regulars by name."},"REIGN":{"p":"[ɹeɪn]","s":"n./v.","e":"[n.] The exercise of sovereign power.\n[n.] The period during which a monarch rules.\n[n.] The territory or sphere over which a kingdom; empire; realm; dominion, etc. is ruled.\n[v.] To exercise sovereign power, to rule as a monarch.\n[v.] To reign over (a country)\n[v.] To be the winner of the most recent iteration of a competition.","ex":"England prospered under Elizabeth I's reign."},"REFIT":{"p":"","s":"n./v.","e":"[n.] The process of having something fitted again, repaired or restored.\n[v.] To fit again; to put back into its place.\n[v.] To prepare for use again; to repair or restore.\n[v.] To fit out or supply again (with something).","ex":"The ship required a refit before setting out again."},"RELATE":{"p":"/ɹiˈleɪt/","s":"v.","e":"[v.] To tell in a descriptive way.\n[v.] To bring into a relation, association, or connection (between one thing and another).\n[v.] To have a connection.","ex":"Please relate the circumstances of your journey here today."},"REJECT":{"p":"","s":"n./v.","e":"[n.] Something that is rejected.\n[n.] An unpopular person.\n[n.] A rejected defective product in a production line\n[v.] To refuse to accept.\n[v.] To block a shot, especially if it sends the ball off the court.\n[v.] To refuse a romantic advance.","ex":"She even rejected my improved offer."},"RELATED":{"p":"/ɹɪˈleɪtɪd/","s":"v./adj.","e":"[v.] To tell in a descriptive way.\n[v.] To bring into a relation, association, or connection (between one thing and another).\n[v.] To have a connection.\n[adj.] Standing in relation or connection.\n[adj.] Being a relative of.\n[adj.] Narrated; told.","ex":"Please relate the circumstances of your journey here today."},"RELIC":{"p":"/ˈɹɛlɪk/","s":"n./v.","e":"[n.] That which remains; that which is left after loss or decay; a remaining portion.\n[n.] Something old and outdated, possibly kept for sentimental reasons.\n[n.] A part of the body of a saint, or an ancient religious object, kept for veneration.\n[v.] (often of guitars) To cause (an object) to appear old or worn, to distress.","ex":""},"RELAY":{"p":"","s":"n./v.","e":"[n.] A new set of hounds.\n[n.] A new set of horses kept along a specific route so that they can replace animals that are tired.\n[n.] (by extension) A new set of anything.\n[v.] To release a new set of hounds.\n[v.] To place (people or horses) in relays, such that one can take over from another.\n[v.] To take on a new relay of horses; to change horses.","ex":""},"RELEASE":{"p":"/ɹɪˈliːs/","s":"n./v.","e":"[n.] The event of setting (someone or something) free (e.g. hostages, slaves, prisoners, caged animals, hooked or stuck mechanisms).\n[n.] The distribution of an initial or new and upgraded version of a computer software product; the distribution can be either public or private.\n[n.] Anything recently released or made available (as for sale).\n[v.] To let go (of); to cease to hold or contain.\n[v.] To make available to the public.\n[v.] To free or liberate; to set free.","ex":"The video store advertised that it had all the latest releases."},"REMAINS":{"p":"/ɹɪˈmeɪnz/","s":"n./v.","e":"[n.] (chiefly in the plural) That which is left; relic; remainder.\n[n.] (in the plural) That which is left of a human being after the life is gone; relics; a dead body.\n[n.] Posthumous works or productions, especially literary works.\n[v.] To stay behind while others withdraw; to be left after others have been removed or destroyed; to be left after a number or quantity has been subtracted or cut off; to be left as not included or comprised.\n[v.] To continue unchanged in place, form, or condition, or undiminished in quantity; to abide; to stay; to endure; to last.\n[v.] To await; to be left to.","ex":"There was no food in the house, so I had to remain hungry."},"RELY":{"p":"/ɹɪˈlaɪ/","s":"v.","e":"[v.] (with on or upon, formerly also with in) to trust; to have confidence in; to depend.","ex":""},"RELIEF":{"p":"/ɹɪˈliːf/","s":"n.","e":"[n.] The removal of stress or discomfort.\n[n.] The feeling associated with the removal of stress or discomfort.\n[n.] Release from a post or duty, as when replaced by another.","ex":"I sighed with relief when I found out that my daughter hadn't got lost, but was waiting for me at home."},"REMIT":{"p":"/ɹɪˈmɪt/","s":"n./v.","e":"[n.] Terms of reference; set of responsibilities; scope.\n[n.] A communication from a superior court to a subordinate court.\n[v.] To transmit or send (e.g. money in payment); to supply.\n[v.] To forgive, pardon (a wrong, offence, etc.).\n[v.] To refrain from exacting or enforcing.","ex":"to remit the performance of an obligation"},"RENAL":{"p":"/ˈɹiːnəl/","s":"adj.","e":"[adj.] Pertaining to the kidneys.","ex":""},"REMOVE":{"p":"/ɹɪˈmuːv/","s":"n./v.","e":"[n.] The act of removing something.\n[n.] (archaic) Removing a dish at a meal in order to replace it with the next course, a dish thus replaced, or the replacement.\n[n.] (at some public schools) A division of the school, especially the form prior to last\n[v.] To move something from one place to another, especially to take away.\n[v.] To murder.\n[v.] To dismiss a batsman.","ex":"He removed the marbles from the bag."},"REMOVED":{"p":"/ɹɪˈmuːvd/","s":"v./adj.","e":"[v.] To move something from one place to another, especially to take away.\n[v.] To murder.\n[v.] To dismiss a batsman.\n[adj.] Separated in time, space, or degree.\n[adj.] Of a different generation, older or younger","ex":"He removed the marbles from the bag."},"REMIX":{"p":"/ɹiˈmɪks/","s":"n./v.","e":"[n.] A rearrangement of an older piece of music, possibly including various cosmetic changes.\n[n.] A piece of music formed by combining existing pieces of music together, possibly including various other cosmetic changes\n[v.] To mix again.\n[v.] To create a remix.\n[v.] To rearrange or radically alter (a particular piece of music).","ex":""},"RELAX":{"p":"/ɹɪˈlæks/","s":"v.","e":"[v.] To calm down.\n[v.] To make something loose.\n[v.] To become loose.","ex":"to relax a rope or cord"},"RENIN":{"p":"/ˈɹiː.nɪn/","s":"n.","e":"[n.] A circulating enzyme released by mammalian kidneys that converts angiotensinogen to angiotensin-I. Because its activity ultimately leads to formation of angiotensin-II and aldosterone, this hormone plays a role in maintaining blood pressure.","ex":""},"REMAIN":{"p":"/ɹɪˈmeɪn/","s":"n./v.","e":"[n.] (chiefly in the plural) That which is left; relic; remainder.\n[n.] (in the plural) That which is left of a human being after the life is gone; relics; a dead body.\n[n.] Posthumous works or productions, especially literary works.\n[v.] To stay behind while others withdraw; to be left after others have been removed or destroyed; to be left after a number or quantity has been subtracted or cut off; to be left as not included or comprised.\n[v.] To continue unchanged in place, form, or condition, or undiminished in quantity; to abide; to stay; to endure; to last.\n[v.] To await; to be left to.","ex":"There was no food in the house, so I had to remain hungry."},"RENTING":{"p":"","s":"v./n.","e":"[v.] To occupy premises in exchange for rent.\n[v.] To grant occupation in return for rent.\n[v.] To obtain or have temporary possession of an object (e.g. a movie) in exchange for money.\n[n.] The act by which something is rented; a rental.","ex":"I rented a house from my friend's parents for a year."},"RENT":{"p":"/ɹɛnt/","s":"n./v.","e":"[n.] A payment made by a tenant at intervals in order to occupy a property.\n[n.] A similar payment for the use of equipment or a service.\n[n.] A profit from possession of a valuable right, as a restricted license to engage in a trade or business.\n[v.] To occupy premises in exchange for rent.\n[v.] To grant occupation in return for rent.\n[v.] To obtain or have temporary possession of an object (e.g. a movie) in exchange for money.","ex":"A New York city taxicab license earns more than $10,000 a year in rent."},"REMOTE":{"p":"[ɹəˈməʊt]","s":"n./v./adj.","e":"[n.] An element of broadcast programming originating away from the station's or show's control room.\n[v.] To connect to a computer from a remote location.\n[adj.] At a distance; disconnected.\n[adj.] Distant or otherwise inaccessible.\n[adj.] (especially with respect to likelihood) Slight.\n[n.] A device used to operate an appliance (such as a television), vehicle or mechanical toy from a short distance away.","ex":"A remote operator may control the vehicle with a wireless handset."},"REPAIR":{"p":"/ɹɪˈpɛə/","s":"n./v.","e":"[n.] The act of repairing something.\n[n.] The result of repairing something.\n[n.] The condition of something, in respect of need for repair.\n[v.] To restore to good working order, fix, or improve damaged condition; to mend; to remedy.\n[v.] To make amends for, as for an injury, by an equivalent; to indemnify for.","ex":"I took the car to the workshop for repair."},"REGION":{"p":"/ˈɹiːd͡ʒn̩/","s":"n.","e":"[n.] Any considerable and connected part of a space or surface; specifically, a tract of land or sea of considerable but indefinite extent; a country; a district; in a broad sense, a place without special reference to location or extent but viewed as an entity for geographical, social or cultural reasons.\n[n.] An administrative subdivision of a city, a territory, a country.\n[n.] The inhabitants of a region or district of a country.","ex":"the equatorial regions"},"REPAY":{"p":"/ɹiˈpeɪ/","s":"v.","e":"[v.] To pay back.","ex":"I finally repaid my student loans, just before sending my kids to college."},"REINS":{"p":"/ɹeɪnz/","s":"n./v.","e":"[n.] A strap or rope attached to a bridle or bit, used to control a horse, animal or young child.\n[n.] An instrument or means of curbing, restraining, or governing.\n[v.] To direct or stop a horse by using reins.\n[v.] To restrain; to control; to check.\n[v.] To obey directions given with the reins.\n[n.] (chiefly in plural) A kidney.","ex":""},"REPEL":{"p":"/ɹɪˈpɛl/","s":"v.","e":"[v.] To turn (someone) away from a privilege, right, job, etc.\n[v.] To reject, put off (a request, demand etc.).\n[v.] To ward off (a malignant influence, attack etc.).","ex":""},"RENEW":{"p":"/ɹɪˈnjuː/","s":"v./n.","e":"[v.] To make (something) new again; to restore to freshness or original condition.\n[v.] To replace (something which has broken etc.); to replenish (something which has been exhausted), to keep up a required supply of.\n[v.] To make new spiritually; to regenerate.\n[n.] The act of renewing.\n[n.] An offensive action made immediately after a parried one.","ex":""},"REPLACE":{"p":"/ɹɪˈpleɪs/","s":"v.","e":"[v.] To restore to a former place, position, condition, etc.; to put back\n[v.] To refund; to repay; to pay back\n[v.] To supply or substitute an equivalent for","ex":"When you've finished using the telephone, please replace the handset."},"REPLY":{"p":"/ɹɪˈplaɪ/","s":"n./v.","e":"[n.] A written or spoken response; part of a conversation.\n[n.] Something given in reply.\n[n.] A counterattack.\n[v.] To give a written or spoken response, especially to a question, request, accusation or criticism; to answer.\n[v.] To act or gesture in response.\n[v.] To repeat something back; to echo.","ex":"Joanne replied to Pete's insult with a slap to his face."},"RENTAL":{"p":"/ˈɹɛntəl/","s":"n./adj.","e":"[n.] Something that is rented.\n[n.] The payment made to rent something.\n[n.] A business that rents out something to its customers.\n[adj.] Relating to rent.\n[adj.] Relating to renting.","ex":"It's just a rental, so I don't need to take very good care of it."},"REQUEST":{"p":"/ɹɪˈkwɛst/","s":"n./v.","e":"[n.] Act of requesting (with the adposition at in the presence of possessives, and on in their absence).\n[n.] A formal message requesting something.\n[n.] Condition of being sought after.\n[v.] To ask for (something).\n[v.] To ask (somebody) to do something.","ex":"I have requested that the furniture be moved back to its original position."},"REPORT":{"p":"/ɹəˈpoːt/","s":"n./v.","e":"[n.] A piece of information describing, or an account of certain events given or presented to someone, with the most common adpositions being by (referring to creator of the report) and on (referring to the subject).\n[n.] Reputation.\n[n.] The sharp, loud sound from a gun or explosion.\n[v.] To relate details of (an event or incident); to recount, describe (something).\n[v.] To repeat (something one has heard), to retell; to pass on, convey (a message, information etc.).\n[v.] To take oneself (to someone or something) for guidance or support; to appeal.","ex":"A report by the telecommunications ministry on the phone network revealed a severe capacity problem."},"RENTS":{"p":"","s":"n./v.","e":"[n.] A payment made by a tenant at intervals in order to occupy a property.\n[n.] A similar payment for the use of equipment or a service.\n[n.] A profit from possession of a valuable right, as a restricted license to engage in a trade or business.\n[v.] To occupy premises in exchange for rent.\n[v.] To grant occupation in return for rent.\n[v.] To obtain or have temporary possession of an object (e.g. a movie) in exchange for money.","ex":"A New York city taxicab license earns more than $10,000 a year in rent."},"RERAN":{"p":"/ˈɹiːɹæn/","s":"v.","e":"[v.] To run (a previously broadcast television program) again.\n[v.] To run (a race) again.\n[v.] To run (a computer program) again.","ex":""},"RESERVE":{"p":"/ɹɪˈzɜːv/","s":"n./v.","e":"[n.] (behaviour) Restriction.\n[n.] That which is reserved or kept back, as for future use.\n[n.] (social) Something initially kept back for later use in a recreation.\n[v.] To keep back; to retain.\n[v.] To keep in store for future or special use.\n[v.] To book in advance; to make a reservation.","ex":"We reserve the right to make modifications."},"RESET":{"p":"/ɹiːˈsɛt/","s":"v.","e":"[v.] To set back to the initial state.\n[v.] To set to zero.\n[v.] To adjust; to set or position differently.","ex":""},"RESIN":{"p":"/ˈɹɛzɪn/","s":"n./v.","e":"[n.] A viscous hydrocarbon secretion of many plants, particularly coniferous trees.\n[n.] Any of various yellowish viscous liquids or soft solids of plant origin; used in lacquers, varnishes and many other applications; chemically they are mostly hydrocarbons, often polycyclic.\n[n.] Any synthetic compound of similar properties.\n[v.] To apply resin to.","ex":""},"RESIST":{"p":"/ɹəˈzɪst/","s":"n./v.","e":"[n.] A protective coating or covering.\n[v.] To attempt to counter the actions or effects of.\n[v.] To withstand the actions of.\n[v.] To oppose.","ex":""},"RESORT":{"p":"/ɹɨˈzɔ(ɹ)t/","s":"n./v.","e":"[n.] A place where people go for recreation, especially one with facilities such as lodgings, entertainment, and a relaxing environment.\n[n.] Recourse, refuge (something or someone turned to for safety).\n[n.] A place where one goes habitually; a haunt.\n[v.] To have recourse (to), now especially from necessity or frustration.\n[v.] To fall back; to revert.\n[v.] To make one's way, go (to).","ex":"to have resort to violence"},"RESPECT":{"p":"/ɹɪˈspɛkt/","s":"n./v./int.","e":"[n.] An attitude of consideration or high regard\n[n.] Good opinion, honor, or admiration\n[n.] (always plural) Polite greetings, often offered as condolences after a death.\n[v.] To have respect for.\n[v.] To have regard for something, to observe a custom, practice, rule or right.\n[v.] To abide by an agreement.","ex":"He is an intellectual giant, and I have great respect for him."},"RESPOND":{"p":"","s":"n./v.","e":"[n.] A response.\n[n.] A versicle or short anthem chanted at intervals during the reading of a lection.\n[n.] A half-pillar, pilaster, or any corresponding device engaged in a wall to receive the impost of an arch.\n[v.] To say something in return; to answer; to reply.\n[v.] To act in return; to carry out an action or in return to a force or stimulus; to do something in response.\n[v.] To correspond with; to suit.","ex":"to respond to a question or an argument"},"RESTORE":{"p":"/ɹɪˈstɔː/","s":"n./v.","e":"[n.] The act of recovering data or a system from a backup.\n[v.] To reestablish, or bring back into existence.\n[v.] To bring back to good condition from a state of decay or ruin.\n[v.] To give or bring back (that which has been lost or taken); to bring back to the owner; to replace.","ex":"We backed up the data successfully, but the restore failed."},"RESULT":{"p":"/ɹɪˈzʌlt/","s":"n./v./int.","e":"[n.] That which results; the conclusion or end to which any course or condition of things leads, or which is obtained by any process or operation; consequence or effect.\n[n.] The fruit, beneficial or tangible effect(s) achieved by effort.\n[n.] The decision or determination of a council or deliberative assembly; a resolve; a decree.\n[v.] To proceed, spring up or rise, as a consequence, from facts, arguments, premises, combination of circumstances, consultation, thought or endeavor.\n[v.] (followed by \"in\") To have as a consequence; to lead to; to bring about\n[v.] To return to the proprietor (or heirs) after a reversion.","ex":"the result of a course of action;  the result of a mathematical operation"},"RETAIN":{"p":"/ɹɪˈteɪn/","s":"v.","e":"[v.] To keep in possession or use.\n[v.] To keep in one's pay or service.\n[v.] To employ by paying a retainer.","ex":""},"RESIGN":{"p":"/ɹɪˈzaɪn/","s":"v.","e":"[v.] To give up; to relinquish ownership of.\n[v.] To hand over (something to someone), place into the care or control of another.\n[v.] To quit (a job or position).","ex":"He resigned the crown to follow his heart."},"RETAIL":{"p":"/ˈɹiˌteɪl/","s":"n./v./adj./adv.","e":"[n.] The sale of goods directly to the consumer, encompassing the storefronts, mail-order, websites, etc., and the corporate mechanisms, branding, advertising, etc. that support them.\n[n.] Retail price; full price; an abbreviated expression, meaning the full suggested price of a particular good or service, before any sale, discount, or other deal.\n[v.] To sell at retail, or in small quantities directly to customers.\n[v.] To sell secondhand, or in broken parts.\n[v.] To repeat or circulate (news or rumours) to others.\n[adj.] Of or relating to the (actual or figurative) sale of goods or services directly to individuals.","ex":"She works in retail."},"REPEAT":{"p":"","s":"n./v.","e":"[n.] An iteration; a repetition.\n[n.] A television program shown after its initial presentation; a rerun.\n[n.] A refill of a prescription.\n[v.] To do or say again (and again).\n[v.] To refill (a prescription).\n[v.] To happen again; recur.","ex":"We gave up after the third repeat because it got boring."},"RESOLVE":{"p":"/ɹiːˈzɒlv/","s":"n./v.","e":"[n.] Determination; will power.\n[n.] A determination to do something; a fixed decision.\n[n.] An act of resolving something; resolution.\n[v.] To find a solution to (a problem).\n[v.] To reduce to simple or intelligible notions; to make clear or certain; to unravel; to explain.\n[v.] To make a firm decision to do something.","ex":"It took all my resolve to go through with the surgery."},"RETCH":{"p":"/ɹɛtʃ/","s":"n./v.","e":"[n.] An unsuccessful effort to vomit.\n[v.] To make an unsuccessful effort to vomit; to strain, as in vomiting.","ex":""},"RETIRE":{"p":"/ɹəˈtaɪə(ɹ)/","s":"n./v.","e":"[n.] The act of retiring, or the state of being retired.\n[n.] A place to which one retires.\n[n.] A call sounded on a bugle, announcing to skirmishers that they are to retire, or fall back.\n[v.] To stop working on a permanent basis, usually because of old age or illness.\n[v.] (sometimes reflexive) To withdraw; to take away.\n[v.] To cease use or production of something.","ex":"At the retire, the cavalry fell back."},"RETIRED":{"p":"/ɹɪˈtʌɪəd/","s":"v./adj.","e":"[v.] To stop working on a permanent basis, usually because of old age or illness.\n[v.] (sometimes reflexive) To withdraw; to take away.\n[v.] To cease use or production of something.\n[v.] To fit (a vehicle) with new tires.\n[adj.] Secluded from society (of a lifestyle, activity etc.); private, quiet.\n[adj.] Of a place: far from civilisation, not able to be easily seen or accessed; secluded.","ex":"Having made a large fortune, he retired."},"RETREAT":{"p":"/ɹəˈtɹiːt/","s":"n./v.","e":"[n.] The act of pulling back or withdrawing, as from something dangerous, or unpleasant.\n[n.] The act of reversing direction and receding from a forward position.\n[n.] A peaceful, quiet place affording privacy or security.\n[v.] To withdraw from a position, go back.\n[v.] (of a glacier) To shrink back due to generally warmer temperatures.\n[v.] To slope back.","ex":"a retreating forehead"},"REST":{"p":"/ɹɛst/","s":"n.","e":"[n.] (of a person or animal) Relief from work or activity by sleeping; sleep.\n[n.] Any relief from exertion; a state of quiet and relaxation.\n[n.] Peace; freedom from worry, anxiety, annoyances; tranquility.","ex":"I need to get a good rest tonight; I was up late last night."},"RETURN":{"p":"/ɹɪˈtɜːn/","s":"n./v.","e":"[n.] The act of returning.\n[n.] A return ticket.\n[n.] An item that is returned, e.g. due to a defect, or the act of returning it.\n[v.] To come or go back (to a place or person).\n[v.] To go back in thought, narration, or argument.\n[v.] To turn back, retreat.","ex":"I expect the house to be spotless upon my return."},"RETRY":{"p":"/riˈtɹaɪ/","s":"n./v.","e":"[n.] Another attempt.\n[v.] To try or attempt again.\n[v.] To try judicially a second time.","ex":"to retry connecting to the Internet after an error"},"RETRO":{"p":"/ˈɹɛ.tɹoʊ/","s":"n./adj.","e":"[n.] Past fashions or trends.\n[adj.] Of, or relating to, the past, past times, or the way things were.\n[adj.] Affecting things past; retroactive, ex post facto.\n[n.] A small rocket engine on a larger rocket or spacecraft, designed to slow or reverse its motion.\n[n.] An exhibition of works from an extended period of an artist's activity.","ex":""},"REVEAL":{"p":"/ɹəˈviːl/","s":"n./v.","e":"[n.] The outer side of a window or door frame; the jamb.\n[n.] A revelation; an uncovering of what was hidden.\n[n.] (obsolete in the US) The side of an opening for a window, doorway, or the like, between the door frame or window frame and the outer surface of the wall; or, where the opening is not filled with a door, etc., the whole thickness of the wall; the jamb.\n[v.] To uncover; to show and display that which was hidden.\n[v.] To communicate that which could not be known or discovered without divine or supernatural instruction.","ex":"The comedian had been telling us about his sleep being disturbed by noise. Then came the reveal: he was sleeping on a bed in a department store."},"REUSE":{"p":"/ɹiːˈjuːs/","s":"n./v.","e":"[n.] The act of salvaging or in some manner restoring a discarded item to yield something usable.\n[n.] The act of using again, or in another place.\n[v.] To use again something that is considered past its usefulness (usually for something else).\n[v.] To use again, or in another place.","ex":"Code reuse can save programmers a lot of typing."},"REQUIRE":{"p":"/ɹɪˈkwaɪə/","s":"v.","e":"[v.] To ask (someone) for something; to request.\n[v.] To demand, to insist upon (having); to call for authoritatively.\n[v.] Naturally to demand (something) as indispensable; to need, to call for as necessary.","ex":""},"REVEL":{"p":"/ˈɹɛv.əl/","s":"n./v.","e":"[n.] An instance of merrymaking; a celebration.\n[n.] A kind of dance.\n[n.] A wake for the dead.\n[v.] To make merry; to have a happy, lively time.\n[v.] To take delight (in something).","ex":""},"REVERSE":{"p":"/ɹɪˈvɜːs/","s":"n./v./adj./adv.","e":"[n.] The opposite of something.\n[n.] The act of going backwards; a reversal.\n[n.] A piece of misfortune; a setback.\n[v.] To turn something around so that it faces the opposite direction or runs in the opposite sequence.\n[v.] To turn something inside out or upside down.\n[v.] To transpose the positions of two things.","ex":"We believed the Chinese weren't ready for us. In fact, the reverse was true."},"REVENUE":{"p":"/ˈɹɛvənjuː/","s":"n./v.","e":"[n.] The income returned by an investment.\n[n.] The total income received from a given source.\n[n.] All income generated for some political entity's treasury by taxation and other means.\n[v.] To generate revenue.\n[v.] To supply with revenue.","ex":""},"RERUN":{"p":"/ˈɹiːɹʌn/","s":"n./v.","e":"[n.] A television program shown after its initial presentation — particularly many weeks after its initial presentation; a repeat.\n[n.] Another printing run (impression; batch of copies of a given edition) of a book, cartoon, etc.\n[n.] A political candidate who holds the same political agenda or doctrine as a past or incumbent holder of a given political office.\n[v.] To run (a previously broadcast television program) again.\n[v.] To run (a race) again.\n[v.] To run (a computer program) again.","ex":""},"REVIVAL":{"p":"/ɹɪˈvaɪvəl/","s":"n.","e":"[n.] The act of reviving, or the state of being revived\n[n.] Renewed attention to something, as to letters or literature.\n[n.] Renewed performance of, or interest in, something, such as drama or literature.","ex":""},"REVIEW":{"p":"/ɹɪˈvjuː/","s":"n./v.","e":"[n.] A second or subsequent reading of a text or artifact in an attempt to gain new insights.\n[n.] An account intended as a critical evaluation of a text or a piece of work.\n[n.] A judicial reassessment of a case or an event.\n[v.] To survey; to look broadly over.\n[v.] To write a critical evaluation of a new art work etc.; to write a review.\n[v.] To look back over in order to correct or edit; to revise.","ex":"I need to make a review of the book before I can understand it."},"REVUE":{"p":"/ɹəˈvjuː/","s":"n.","e":"[n.] A form of theatrical entertainment in which recent events, popular fads, etc., are parodied. Any entertainment featuring skits, dances, and songs.","ex":""},"REWARD":{"p":"/ɹəˈwɔːd/","s":"n.","e":"[n.] Something of value given in return for an act.\n[n.] A prize promised for a certain deed or catch\n[n.] The result of an action, whether good or bad.","ex":"For catching the thief, you'll get a nice reward."},"RHINO":{"p":"/ˈɹaɪ.nəʊ/","s":"n.","e":"[n.] A rhinoceros.","ex":""},"RHEUM":{"p":"/ɹuːm/","s":"n.","e":"[n.] Watery or thin discharge of serum or mucus, especially from the eyes or nose, formerly thought to cause disease.\n[n.] Illness or disease thought to be caused by such secretions; a catarrh, a cold; rheumatism.\n[n.] Tears.","ex":""},"RHUMB":{"p":"/ɹʌm/","s":"n.","e":"[n.] A line which crosses successive meridians at a constant angle\n[n.] One of the 32 points of the compass (compass points)\n[n.] A unit of angular measure equal to 1/32 of a circle or 11.25°","ex":""},"RHYME":{"p":"/ɹaɪm/","s":"n./v.","e":"[n.] Rhyming verse (poetic form)\n[n.] A thought expressed in verse; a verse; a poem; a tale told in verse.\n[n.] A word that rhymes with another.\n[v.] To compose or treat in verse; versify.\n[v.] (followed by with) Of a word, to be pronounced identically with another from the vowel in its stressed syllable to the end.\n[v.] Of two or more words, to be pronounced identically from the vowel in the stressed syllable of each to the end of each.","ex":"Many editors say they don't want stories written in rhyme."},"RICER":{"p":"","s":"n.","e":"[n.] A person, especially a Native American, who cultivates and harvests rice.\n[n.] A utensil used to extrude soft foods (such as, and especially, cooked potato) through holes about the diameter of a grain of rice.\n[n.] An imported automobile from an Oriental country, deemed inferior because it is low-powered and/or cheap.","ex":""},"RICES":{"p":"","s":"n./v.","e":"[n.] Cereal plants, Oryza sativa of the grass family whose seeds are used as food.\n[n.] A specific variety of this plant.\n[n.] The seeds of this plant used as food.\n[v.] To squeeze through a ricer; to mash or make into rice-sized pieces (especially potatoes).\n[v.] To harvest wild rice (Zizania sp.)\n[v.] To throw rice at a person (usually at a wedding).","ex":""},"RIALS":{"p":"","s":"n.","e":"[n.] The official currencies of Iran, Oman, and Yemen.\n[n.] An old gold coin of England.","ex":""},"RICH":{"p":"/ɹɪt͡ʃ/","s":"v./adj.","e":"[v.] To enrich.\n[v.] To become rich.\n[adj.] Wealthy: having a lot of money and possessions.\n[adj.] Having an intense fatty or sugary flavour.\n[adj.] Plentiful, abounding, abundant, fulfilling.","ex":"a rich dish; rich cream or soup; rich pastry"},"RIDES":{"p":"/ɹaɪdz/","s":"n./v.","e":"[n.] An instance of riding.\n[n.] A vehicle.\n[n.] An amusement ridden at a fair or amusement park.\n[v.] To transport oneself by sitting on and directing a horse, later also a bicycle etc.\n[v.] To be transported in a vehicle; to travel as a passenger.\n[v.] (chiefly US and South Africa) To transport (someone) in a vehicle.","ex":"Can I have a ride on your bike?"},"RIGHT":{"p":"/ˈɹaɪt/","s":"adj.","e":"[adj.] Straight, not bent.\n[adj.] Of an angle, having a size of 90 degrees, or one quarter of a complete rotation; the angle between two perpendicular lines.\n[adj.] Of a geometric figure, incorporating a right angle between edges, faces, axes, etc.","ex":"a right line"},"RIDGE":{"p":"/ɹɪdʒ/","s":"n./v.","e":"[n.] The back of any animal; especially the upper or projecting part of the back of a quadruped.\n[n.] Any extended protuberance; a projecting line or strip.\n[n.] The line along which two sloping surfaces meet which diverge towards the ground.\n[v.] To form into a ridge\n[v.] To extend in ridges","ex":"The plough threw up ridges of earth between the furrows."},"RIGID":{"p":"/ˈɹɪdʒɪd/","s":"n./adj.","e":"[n.] A bicycle with no suspension system.\n[adj.] Stiff, rather than flexible.\n[adj.] Fixed, rather than moving.\n[adj.] Rigorous and unbending.","ex":""},"RILLS":{"p":"","s":"n.","e":"[n.] A very small brook; a streamlet.\n[n.] A long, narrow depression that resembles a channel, found on the surface of various lunar and planetary bodies.","ex":""},"RILED":{"p":"","s":"v.","e":"[v.] To make angry\n[v.] To stir or move from a state of calm or order","ex":"It riles me that she never closes the door after she leaves."},"RIMED":{"p":"","s":"v./adj.","e":"[v.] To compose or treat in verse; versify.\n[v.] (followed by with) Of a word, to be pronounced identically with another from the vowel in its stressed syllable to the end.\n[v.] Of two or more words, to be pronounced identically from the vowel in the stressed syllable of each to the end of each.\n[v.] To freeze or congeal into hoarfrost.\n[adj.] Covered in frost","ex":"\"Creation\" rhymes with \"integration\" and \"station\"."},"RICED":{"p":"","s":"v./adj.","e":"[v.] To squeeze through a ricer; to mash or make into rice-sized pieces (especially potatoes).\n[v.] To harvest wild rice (Zizania sp.)\n[v.] To throw rice at a person (usually at a wedding).\n[adj.] Made into or consisting of finely minced pieces resembling rice","ex":"riced cauliflower"},"RIDER":{"p":"/ˈɹaɪ.də(ɹ)/","s":"n.","e":"[n.] One who rides, often on a horse or a motorcycle.\n[n.] A provision annexed to a bill under the consideration of a legislature, having little connection with the subject matter of the bill.\n[n.] (by extension) Something extra or burdensome that is imposed.","ex":""},"RINDS":{"p":"/ɹaɪndz/","s":"n./v.","e":"[n.] Tree bark\n[n.] A hard, tough outer layer, particularly on food such as fruit, cheese, etc\n[n.] (usually \"the\") The gall, the crust, the insolence; often as \"the immortal rind\"\n[v.] To remove the rind from.\n[n.] An iron support fitting used on the upper millstone of a grist mill.","ex":""},"RIFLE":{"p":"/ˈɹaɪfəl/","s":"n./v.","e":"[n.] A shouldered firearm with a long, rifled barrel to improve range and accuracy.\n[n.] (usually plural) A rifleman.\n[n.] An artillery piece with a rifled barrel.\n[v.] To quickly search through many items (such as papers, the contents of a drawer, a pile of clothing). (See also rifflehttp//verbmall.blogspot.com/2008/05/riffle-or-rifle.html)\n[v.] To commit robbery or theft.\n[v.] To search with intent to steal; to ransack, pillage or plunder.","ex":"She made a mess when she rifled through the stack of papers, looking for the title document."},"RING":{"p":"/ɹɪŋ/","s":"n./v.","e":"[n.] (physical) A solid object in the shape of a circle.\n[n.] (physical) A group of objects arranged in a circle.\n[n.] A piece of food in the shape of a ring.\n[v.] To enclose or surround.\n[v.] To make an incision around; to girdle.\n[v.] To attach a ring to, especially for identification.","ex":"onion rings"},"RINGS":{"p":"/ɹɪŋz/","s":"n./v.","e":"[n.] (physical) A solid object in the shape of a circle.\n[n.] (physical) A group of objects arranged in a circle.\n[n.] A piece of food in the shape of a ring.\n[v.] To enclose or surround.\n[v.] To make an incision around; to girdle.\n[v.] To attach a ring to, especially for identification.","ex":"onion rings"},"RINKS":{"p":"","s":"n.","e":"[n.] A man, especially a warrior or hero.\n[n.] A ring; a circle.\n[n.] A sheet of ice prepared for playing certain sports, such as hockey or curling.\n[n.] A surface for roller skating.","ex":"We played hockey all winter until the rink melted."},"RISER":{"p":"/ˈɹaɪ.zə(ɹ)/","s":"n.","e":"[n.] Someone or something which rises.\n[n.] A platform or stand used to lift or elevate something.\n[n.] The vertical part of a step on a staircase.","ex":"The choir stood on risers for the performance."},"RIPER":{"p":"","s":"adj.","e":"[adj.] (of fruits, vegetables, seeds etc.) Ready for reaping or gathering; having attained perfection; mature\n[adj.] (of foods) Advanced to the state of fitness for use; mellow\n[adj.] Having attained its full development; mature; perfected","ex":"ripe apples"},"RISEN":{"p":"/ˈɹɪzən/","s":"v.","e":"[v.] To move, or appear to move, physically upwards relative to the ground.\n[v.] To increase in value or standing.\n[v.] To begin; to develop.","ex":""},"RISKS":{"p":"","s":"n./v.","e":"[n.] A possible adverse event or outcome\n[n.] The probability of a negative outcome to a decision or event.\n[n.] The magnitude of possible loss consequent to a decision or event.\n[v.] To incur risk of (something).\n[v.] To incur risk of harming or jeopardizing.\n[v.] To incur risk as a result of (doing something).","ex":"2006, Trever Ramsey on BBC News website, Exercise 'cuts skin cancer risk' read at http//news.bbc.co.uk/1/hi/health/4764535.stm on 14 May 2006"},"RISES":{"p":"/ˈɹaɪzɪz/","s":"v.","e":"[v.] To move, or appear to move, physically upwards relative to the ground.\n[v.] To increase in value or standing.\n[v.] To begin; to develop.","ex":""},"RITZY":{"p":"/ˈɹɪ.t͡si/","s":"adj.","e":"[adj.] Elegant and luxurious.","ex":""},"RIVAL":{"p":"/ˈɹaɪvəl/","s":"n./v./adj.","e":"[n.] A competitor (person, team, company, etc.) with the same goal as another, or striving to attain the same thing. Defeating a rival may be a primary or necessary goal of a competitor.\n[n.] Someone or something with similar claims of quality or distinction as another.\n[n.] One having a common right or privilege with another; a partner.\n[v.] To oppose or compete with.\n[v.] To be equal to, or match, or to surpass another.\n[v.] To strive to equal or excel; to emulate.","ex":"Chris is my biggest rival in the 400-metre race."},"RINSE":{"p":"/ɹɛns/","s":"n./v.","e":"[n.] The action of rinsing.\n[n.] A liquid used to rinse, now particularly a hair dye.\n[v.] To wash (something) quickly using water and no soap.\n[v.] To remove soap from (something) using water.\n[v.] To thoroughly defeat in an argument, fight or other competition.","ex":"I'll just give this knife a quick rinse."},"RIDE":{"p":"/ɹaɪd/","s":"n./v.","e":"[n.] An instance of riding.\n[n.] A vehicle.\n[n.] An amusement ridden at a fair or amusement park.\n[v.] To transport oneself by sitting on and directing a horse, later also a bicycle etc.\n[v.] To be transported in a vehicle; to travel as a passenger.\n[v.] (chiefly US and South Africa) To transport (someone) in a vehicle.","ex":"Can I have a ride on your bike?"},"RIVEN":{"p":"/ˈɹɪvən/","s":"v./adj.","e":"[v.] To tear apart by force; to rend; to split; to cleave.\n[v.] To pierce or cleave with a weapon.\n[adj.] Torn apart.\n[adj.] Broken into pieces; split asunder.","ex":""},"ROAD":{"p":"/ɹəʊd/","s":"n./adj.","e":"[n.] A way used for travelling between places, originally one wide enough to allow foot passengers and horses to travel, now (US) usually one surfaced with asphalt or concrete and designed to accommodate many vehicles travelling in both directions. In the UK both senses are heard: a country road is the same as a country lane.\n[n.] A road; or particularly a car, as a means of transportation.\n[n.] A path chosen in life or career.\n[adj.] At the venue of the opposing team or competitor; on the road.\n[adj.] (Slang) Having attributes, primarily masculine, suggesting a tendency towards minor crime. Usually used by youths endearingly; glorifying crime.","ex":"We travelled to the seaside by road."},"ROACH":{"p":"/ɹəʊtʃ/","s":"n.","e":"[n.] Certain members of the fish family Cyprinidae, including:","ex":""},"ROADS":{"p":"/ɹəʊdz/","s":"n.","e":"[n.] A way used for travelling between places, originally one wide enough to allow foot passengers and horses to travel, now (US) usually one surfaced with asphalt or concrete and designed to accommodate many vehicles travelling in both directions. In the UK both senses are heard: a country road is the same as a country lane.\n[n.] A road; or particularly a car, as a means of transportation.\n[n.] A path chosen in life or career.\n[n.] (occasionally in the singular) A roadstead.","ex":"We travelled to the seaside by road."},"ROAMS":{"p":"","s":"v.","e":"[v.] To wander or travel freely and with no specific destination.\n[v.] To use a network or service from different locations or devices.\n[v.] To transmit (resources) between different locations or devices, to allow comparable usage from any of them.","ex":""},"RIVET":{"p":"/ˈɹɪvət/","s":"n./v.","e":"[n.] A cylindrical mechanical fastener that attaches multiple parts together by fitting through a hole and deforming the head(s) at either end.\n[n.] Any fixed point or certain basis.\n[n.] A light kind of footman's armour.\n[v.] To attach or fasten parts by using rivets.\n[v.] To install rivets.\n[v.] To command the attention of.","ex":""},"ROANS":{"p":"","s":"n.","e":"[n.] An animal such as a horse that has a coat of a dark base color with individual white hairs mixed in.\n[n.] The color of such an animal.\n[n.] A kind of leather used for slippers, bookbinding, etc., made from sheepskin, tanned with sumac and colored to imitate ungrained morocco.\n[n.] Sorbus aucuparia, the European rowan.\n[n.] Any of various small deciduous trees or shrubs of genus Sorbus, belonging to the rose family, with pinnate leaves, corymbs of white flowers, and usually with orange-red berries.","ex":""},"ROCKS":{"p":"/ɹɒks/","s":"n./v.","e":"[n.] An enormous mythical bird in Eastern legend.\n[n.] Rocuronium.\n[n.] A formation of minerals, specifically:\n[n.] A large hill or island having no vegetation.\n[n.] Something that is strong, stable, and dependable; a person who provides security or support to another.\n[n.] An act of rocking; a rocking motion; a sway.","ex":"Pearl Rock near Cape Cod is so named because the morning sun makes it gleam like a pearl."},"RODE":{"p":"/ˈɹəʊd/","s":"v.","e":"[v.] To transport oneself by sitting on and directing a horse, later also a bicycle etc.\n[v.] To be transported in a vehicle; to travel as a passenger.\n[v.] (chiefly US and South Africa) To transport (someone) in a vehicle.","ex":"The cab rode him downtown."},"ROGER":{"p":"/ˈɹɒdʒə/","s":"int.","e":"[int.] (radio telecommunications) Received (used in radio communications to acknowledge that a message has been received and understood)","ex":""},"ROBOT":{"p":"/ˈɹoʊbət/","s":"n.","e":"[n.] A machine built to carry out some complex task or group of tasks by physically moving, especially one which can be programmed.\n[n.] An intelligent mechanical being designed to look like a human or other creature, and usually made from metal.\n[n.] A person who does not seem to have any emotions.","ex":""},"ROBES":{"p":"/ɹəʊbz/","s":"n.","e":"[n.] A long loose outer garment, often signifying honorary stature.\n[n.] The skin of an animal, especially the bison, dressed with the fur on, and used as a wrap.\n[n.] A wardrobe, especially one built into a bedroom.","ex":""},"ROGUE":{"p":"/ˈɹəʊ̯ɡ/","s":"n./v./adj.","e":"[n.] A scoundrel, rascal or unprincipled, deceitful, and unreliable person.\n[n.] A mischievous scamp.\n[n.] A vagrant.\n[v.] To cull; to destroy plants not meeting a required standard, especially when saving seed, rogue or unwanted plants are removed before pollination.\n[v.] To cheat.\n[v.] To give the name or designation of rogue to; to decry.","ex":""},"ROOF":{"p":"/ɹuːf/","s":"n.","e":"[n.] The external covering at the top of a building.\n[n.] The top external level of a building.\n[n.] The upper part of a cavity.","ex":"The roof was blown off by the tornado."},"ROOKS":{"p":"/ɹʊks/","s":"n./v.","e":"[n.] A European bird, Corvus frugilegus, of the crow family.\n[n.] A cheat or swindler; someone who betrays.\n[n.] A type of firecracker used by farmers to scare birds of the same name.\n[v.] To cheat or swindle.\n[n.] A piece shaped like a castle tower, that can be moved only up, down, left or right (but not diagonally) or in castling.\n[n.] A castle or other fortification.","ex":""},"ROCK":{"p":"/ɹɒk/","s":"n.","e":"[n.] A formation of minerals, specifically:\n[n.] A large hill or island having no vegetation.\n[n.] Something that is strong, stable, and dependable; a person who provides security or support to another.","ex":"Pearl Rock near Cape Cod is so named because the morning sun makes it gleam like a pearl."},"ROOM":{"p":"/ɹuːm/","s":"n./v.","e":"[n.] Opportunity or scope (to do something).\n[n.] Space for something, or to carry out an activity.\n[n.] A particular portion of space.\n[v.] To reside, especially as a boarder or tenant.\n[v.] To assign to a room; to allocate a room to.","ex":"Doctor Watson roomed with Sherlock Holmes at Baker Street."},"ROPED":{"p":"","s":"v.","e":"[v.] To tie (something) with rope.\n[v.] To throw a rope (or something similar, e.g. a lasso, cable, wire, etc.) around (something).\n[v.] To be formed into rope; to draw out or extend into a filament or thread.","ex":"The robber roped the victims."},"ROPES":{"p":"/ɹəʊps/","s":"n./v.","e":"[n.] Thick strings, yarn, monofilaments, metal wires, or strands of other cordage that are twisted together to form a stronger line.\n[n.] An individual length of such material.\n[n.] A cohesive strand of something.\n[v.] To tie (something) with rope.\n[v.] To throw a rope (or something similar, e.g. a lasso, cable, wire, etc.) around (something).\n[v.] To be formed into rope; to draw out or extend into a filament or thread.","ex":"Nylon rope is usually stronger than similar rope made of plant fibers."},"ROSE":{"p":"/ɹəʊz/","s":"n./v./adj.","e":"[n.] A shrub of the genus Rosa, with red, pink, white or yellow flowers.\n[n.] A flower of the rose plant.\n[n.] A plant or species in the rose family. (Rosaceae)\n[v.] To make rose-coloured; to redden or flush.\n[v.] To perfume, as with roses.\n[adj.] Having a purplish-red or pink colour. See rosy.","ex":""},"ROUGE":{"p":"/ɹuːʒ/","s":"n./v./adj.","e":"[n.] Red or pink makeup to add colour to the cheeks; blusher.\n[n.] Any reddish pink colour.\n[n.] A single point awarded when a team kicks the ball out of its opponent's end zone, or when a kicked ball becomes dead within the non-kicking team's end zone. Etymology uncertain; it is thought that in the early years of the sport, a red flag indicated that a single had been scored. (This scoring term is not often used in Canada, with the term single being more commonly used.)\n[v.] To apply rouge (makeup).\n[adj.] Of a reddish pink colour.","ex":"She rouged her face before setting out for the party."},"ROPE":{"p":"/ɹəʊp/","s":"n./v.","e":"[n.] Thick strings, yarn, monofilaments, metal wires, or strands of other cordage that are twisted together to form a stronger line.\n[n.] An individual length of such material.\n[n.] A cohesive strand of something.\n[v.] To tie (something) with rope.\n[v.] To throw a rope (or something similar, e.g. a lasso, cable, wire, etc.) around (something).\n[v.] To be formed into rope; to draw out or extend into a filament or thread.","ex":"Nylon rope is usually stronger than similar rope made of plant fibers."},"ROUSE":{"p":"/ˈɹaʊz/","s":"n./v.","e":"[n.] An arousal.\n[n.] The sounding of a bugle in the morning after reveille, to signal that soldiers are to rise from bed, often the rouse.\n[v.] To wake (someone) or be awoken from sleep, or from apathy.\n[v.] To cause, stir up, excite (a feeling, thought, etc.).\n[v.] To provoke (someone) to action or anger.","ex":"to rouse the faculties, passions, or emotions"},"ROPEY":{"p":"","s":"adj.","e":"[adj.] Resembling rope in appearance or texture, used especially of muscles that are thick or hard to the touch.\n[adj.] Capable of forming rope-like or thread-like structures.\n[adj.] Of poor quality; in poor health.","ex":""},"ROWAN":{"p":"/ˈɹaʊ.ən/","s":"n.","e":"[n.] Sorbus aucuparia, the European rowan.\n[n.] Any of various small deciduous trees or shrubs of genus Sorbus, belonging to the rose family, with pinnate leaves, corymbs of white flowers, and usually with orange-red berries.","ex":""},"ROUND":{"p":"/ˈɹaʊnd/","s":"adv./prep./n./v./adj.","e":"[adv.] So as to form a circle or trace a circular path, or approximation thereof.\n[adv.] So as to surround or be near.\n[adv.] Nearly; approximately; about.\n[prep.] Defining a circle or closed curve containing a thing.\n[prep.] (of abstract things) Centred upon; surrounding.\n[prep.] Following the perimeter of a specified area and returning to the starting point.","ex":"High above, vultures circled around."},"ROWED":{"p":"/ɹəʊd/","s":"v.","e":"[v.] To propel (a boat or other craft) over water using oars.\n[v.] To transport in a boat propelled with oars.\n[v.] To be moved by oars.\n[v.] To argue noisily","ex":"to row the captain ashore in his barge"},"RUBLE":{"p":"/ɹuːbəl/","s":"n.","e":"[n.] The monetary unit of Russia, Belarus and Transnistria equal to 100 kopeks (Russian: копе́йка, Belarusian: капе́йка). The Russian ruble's symbol is ₽.","ex":""},"RUFFS":{"p":"","s":"n./v.","e":"[n.] A circular frill or ruffle on a garment, especially a starched, fluted frill at the neck in Elizabethan and Jacobean England (1560s–1620s).\n[n.] Anything formed with plaits or flutings like a frill.\n[n.] Senses relating to animals.\n[v.] To shape (fabric, etc.) into a ruff; to adorn (a garment, etc.) with a ruff.\n[v.] Of a falcon, hawk, etc.: to hit (the prey) without fixing or grabbing hold of it.\n[v.] To ruffle; to disorder.","ex":""},"ROUTE":{"p":"/ɹʉːt/","s":"n./v.","e":"[n.] A course or way which is traveled or passed.\n[n.] A regular itinerary of stops, or the path followed between these stops, such as for delivery or passenger transportation.\n[n.] A road or path; often specifically a highway.\n[v.] To direct or divert along a particular course.\n[v.] To connect two local area networks, thereby forming an internet.\n[v.] To send (information) through a router.","ex":"The route was used so much that it formed a rut."},"RULER":{"p":"/ˈɹuːlə(ɹ)/","s":"n./v.","e":"[n.] A (usually rigid), flat, rectangular measuring or drawing device with graduations in units of measurement; a straightedge with markings.\n[n.] A person who rules or governs; someone or something that exercises dominion or controlling power over others.\n[v.] To beat with a ruler (as a traditional school punishment).","ex":""},"ROYAL":{"p":"/ˈɹɔɪəl/","s":"n./adj.","e":"[n.] A royal person; a member of a royal family.\n[n.] A standard size of printing paper, measuring 25 by 20 inches.\n[n.] A standard size of writing paper, measuring 24 by 19 inches.\n[adj.] Of or relating to a monarch or their family.\n[adj.] Having the air or demeanour of a monarch; illustrious; magnanimous; of more than common size or excellence.\n[adj.] In large sailing ships, of a mast right above the topgallant mast and its sails.","ex":"royal mast;  royal sail"},"RUMBA":{"p":"","s":"n./v.","e":"[n.] A slow-paced Cuban partner dance in 4:4 time.\n[v.] To dance the rumba","ex":""},"ROVES":{"p":"","s":"v.","e":"[v.] To shoot with arrows (at).\n[v.] To roam, or wander about at random, especially over a wide area.\n[v.] To roam or wander through.","ex":""},"RUNGS":{"p":"","s":"n.","e":"[n.] A crosspiece forming a step of a ladder; a round.\n[n.] A crosspiece between legs of a chair.\n[n.] A position in a hierarchy.","ex":"the lowest rung of the society"},"RUNNING":{"p":"/ˈɹʌnɪŋ/","s":"v./n./adj./adv./prep.","e":"[v.] To move swiftly.\n[v.] (fluids) To flow.\n[v.] (of a vessel) To sail before the wind, in distinction from reaching or sailing close-hauled.\n[n.] The action of the verb to run.\n[n.] The activity of running as a form of exercise, as a sport, or for any other reason\n[n.] That which runs or flows; the quantity of a liquid which flows in a certain time or during a certain operation.","ex":"His running of the business leaves something to be desired."},"RUSES":{"p":"","s":"n.","e":"[n.] A turning or doubling back, especially of animals to get out of the way of hunting dogs.\n[n.] (by extension) An action intended to deceive; a trick.\n[n.] Cunning, guile, trickery.","ex":""},"RULES":{"p":"/ˈɹuːlz/","s":"n./v.","e":"[n.] A regulation, law, guideline.\n[n.] A ruler; device for measuring, a straightedge, a measure.\n[n.] A straight line (continuous mark, as made by a pen or the like), especially one lying across a paper as a guide for writing.\n[v.] To regulate, be in charge of, make decisions for, reign over.\n[v.] To excel.\n[v.] To mark (paper or the like) with rules (lines).","ex":"All participants must adhere to the rules."},"RULING":{"p":"/ˈɹuːlɪŋ/","s":"v./n./adj.","e":"[v.] To regulate, be in charge of, make decisions for, reign over.\n[v.] To excel.\n[v.] To mark (paper or the like) with rules (lines).\n[v.] To revel.\n[n.] An order or a decision on a point of law from someone in authority.\n[adj.] That rules; predominant; chief; reigning; controlling.","ex":"This game rules!"},"ROWS":{"p":"","s":"n./v.","e":"[n.] A line of objects, often regularly spaced, such as seats in a theatre, vegetable plants in a garden etc.\n[n.] A line of entries in a table, etc., going from left to right, as opposed to a column going from top to bottom.\n[n.] An act or instance of rowing.\n[n.] An exercise performed with a pulling motion of the arms towards the back.\n[v.] To propel (a boat or other craft) over water using oars.\n[v.] To transport in a boat propelled with oars.","ex":"I went for an early-morning row."},"SABLE":{"p":"/ˈseɪbəl/","s":"n./adj.","e":"[n.] A small carnivorous mammal of the Old World that resembles a weasel, Martes zibellina, from cold regions in Eurasia and the North Pacific islands, valued for its dark brown fur (Wikipedia).\n[n.] The marten, especially Martes americana (syn. Mustela americana).\n[n.] The fur or pelt of the sable or other species of martens; a coat made from this fur.\n[adj.] Of the black colour sable.\n[adj.] : In blazon, of the colour black.\n[adj.] Made of sable fur.","ex":""},"SACRA":{"p":"","s":"n.","e":"[n.] Sacral artery\n[n.] A large triangular bone at the base of the spine, located between the two ilia (wings of the pelvis) and formed from vertebrae that fuse in adulthood.","ex":""},"RULE":{"p":"/ɹuːl/","s":"n.","e":"[n.] A regulation, law, guideline.\n[n.] A ruler; device for measuring, a straightedge, a measure.\n[n.] A straight line (continuous mark, as made by a pen or the like), especially one lying across a paper as a guide for writing.","ex":"All participants must adhere to the rules."},"RUGBY":{"p":"/ˈɹʌɡbi/","s":"n.","e":"[n.] (usually uncountable) A form of football in which players can hold or kick an ovoid ball. The ball cannot be handled forwards and points are scored by touching the ball to the ground in the area past their opponent’s territory or kicking the ball between goalposts and over a crossbar.\n[n.] A loose fitting shirt with a collar, as worn by rugby players.","ex":"The scrum is a distinctive element of rugby."},"RUSH":{"p":"/ɹʌʃ/","s":"n.","e":"[n.] Any of several stiff plants of the genus Juncus, or the family Juncaceae, having hollow or pithy stems and small flowers, and often growing in marshes or near water.\n[n.] The stem of such plants used in making baskets, mats, the seats of chairs, etc.\n[n.] The merest trifle; a straw.","ex":""},"SAKES":{"p":"/seɪks/","s":"n.","e":"[n.] An alcoholic beverage made from fermenting various forms of rice, usually with an ABV similar to wine.\n[n.] Cause, interest or account\n[n.] Purpose or end; reason\n[n.] The benefit or regard of someone or something\n[n.] A class of Japanese rice wines made from polished rice and typically about 20% alcohol by volume.","ex":"For the sake of argument"},"SAFE":{"p":"/seɪf/","s":"n./v./adj.","e":"[n.] A box, usually made of metal, in which valuables can be locked for safekeeping.\n[n.] A condom.\n[n.] A ventilated or refrigerated chest or closet for securing provisions from noxious animals or insects.\n[v.] To make something safe.\n[adj.] Not in danger; out of harm's reach.\n[adj.] Free from risk.","ex":"You’ll be safe here."},"RUSTS":{"p":"/ɹʌsts/","s":"n./v.","e":"[n.] The deteriorated state of iron or steel as a result of moisture and oxidation.\n[n.] A similar substance based on another metal (usually with qualification, such as \"copper rust\").\n[n.] A reddish-brown color.\n[v.] To oxidize, especially of iron or steel.\n[v.] To cause to oxidize.\n[v.] To be affected with the parasitic fungus called rust.","ex":"The rust on my bicycle chain made cycling to work very dangerous."},"SALON":{"p":"/səˈlɒn/","s":"n.","e":"[n.] A large room, especially one used to receive and entertain guests.\n[n.] A gathering of people for a social or intellectual meeting.\n[n.] An art gallery or exhibition; especially the Paris salon or autumn salon.","ex":""},"SALTS":{"p":"","s":"n./v.","e":"[n.] A common substance, chemically consisting mainly of sodium chloride (NaCl), used extensively as a condiment and preservative.\n[n.] One of the compounds formed from the reaction of an acid with a base, where a positive ion replaces a hydrogen of the acid.\n[n.] A salt marsh, a saline marsh at the shore of a sea.\n[v.] To add salt to.\n[v.] To deposit salt as a saline solution.\n[v.] To fill with salt between the timbers and planks, as a ship, for the preservation of the timber.","ex":"to salt fish, beef, or pork; to salt the city streets in the winter"},"SAMBA":{"p":"/ˈsɑmbə/","s":"n./v.","e":"[n.] A Brazilian ballroom dance or dance style.\n[n.] A Brazilian musical genre, to which the aforementioned dance is danced, which has its roots in West Africa via the slave trade.\n[v.] To dance the samba.","ex":""},"SANDY":{"p":"/ˈsændi/","s":"adj.","e":"[adj.] Covered with sand.\n[adj.] Sprinkled with sand.\n[adj.] Containing sand.","ex":"Some plants grow best in sandy soil."},"SANER":{"p":"","s":"adj.","e":"[adj.] Being in a healthy condition; not deranged; thinking rationally.\n[adj.] Mentally sound; possessing a rational mind; having the mental faculties in such condition as to be able to anticipate and judge the effect of one's actions in an ordinary manner.\n[adj.] Rational; reasonable; sensible.","ex":"a sane mind"},"SARIS":{"p":"","s":"n.","e":"[n.] The traditional dress of women in the Indian Subcontinent; an outer garment consisting of a single length of cotton or silk, most often with one end wrapped around the waist to form a skirt, the other draped over the shoulder or head.","ex":""},"SATAY":{"p":"/ˈsæt.eɪ/","s":"n.","e":"[n.] A dish made from small pieces of meat or fish grilled on a skewer and served with a spicy peanut sauce, originating from Indonesia and Malaysia.","ex":""},"SARGE":{"p":"/sɑːd͡ʒ/","s":"n.","e":"[n.] Sergeant","ex":""},"SAUNA":{"p":"/ˈsaʊ.nə/","s":"n./v.","e":"[n.] A room or a house designed for heat sessions.\n[n.] The act of using a sauna.\n[n.] A public sauna; a front for a brothel in some countries.\n[v.] To use a sauna.","ex":"The hotel has a sauna in the basement."},"SAVOY":{"p":"","s":"n.","e":"[n.] Savoy cabbage\n[n.] An Italian noble family, which became the ruling (hereditary) dynasty of Sardinia and later of Italy\n[n.] A member of the Savoy noble family","ex":""},"SAVVY":{"p":"/ˈsæ.vi/","s":"n./v./adj.","e":"[n.] Shrewdness.\n[v.] To understand.\n[adj.] Shrewd, well-informed and perceptive.","ex":""},"SAVE":{"p":"/seɪv/","s":"n./v./prep./conj.","e":"[n.] In various sports, a block that prevents an opponent from scoring.\n[n.] When a relief pitcher comes into a game leading by 3 points (runs) or less, and his team wins while continually being ahead.\n[n.] A point in a professional wrestling match when one or more wrestlers run to the ring to aid a fellow wrestler who is being beaten.\n[v.] To prevent harm or difficulty.\n[v.] To put aside, to avoid.\n[prep.] Except; with the exception of.","ex":"The goaltender made a great save."},"SCADS":{"p":"","s":"n.","e":"[n.] Any of several fish, of the family Carangidae, from the western Atlantic.\n[n.] (in the plural) A large number or quantity.","ex":""},"SCALD":{"p":"/skɒld/","s":"n./v.","e":"[n.] A burn, or injury to the skin or flesh, by hot liquid or steam.\n[v.] To burn with hot liquid.\n[v.] To heat almost to boiling.","ex":"to scald the hand"},"SCALY":{"p":"/ˈskeɪli/","s":"n./adj.","e":"[n.] The scaly yellowfish, Labeobarbus natalensis.\n[adj.] Covered or abounding with scales.\n[adj.] Composed of scales lying over each other.\n[adj.] Resembling scales, laminae, or layers.","ex":"a scaly fish  a scaly stem"},"SCABS":{"p":"","s":"n./v.","e":"[n.] An incrustation over a sore, wound, vesicle, or pustule, formed during healing.\n[n.] The scabies.\n[n.] The mange, especially when it appears on sheep.\n[v.] To become covered by a scab or scabs.\n[v.] To form into scabs and be shed, as damaged or diseased skin.\n[v.] To remove part of a surface (from).","ex":""},"SCAMP":{"p":"/skamp/","s":"n.","e":"[n.] A rascal, swindler, or rogue; a ne'er-do-well.\n[n.] A mischievous person, especially a playful, impish youngster.","ex":"My nephew is a little scamp who likes to leave lighted firecrackers under the lawnchairs of his dozing elders."},"SCANS":{"p":"","s":"n./v.","e":"[n.] Close investigation.\n[n.] An instance of scanning.\n[n.] The result or output of a scanning process.\n[v.] To examine sequentially, carefully, or critically; to scrutinize; to behold closely.\n[v.] To look about for; to look over quickly.\n[v.] To create a digital copy of an image using a scanner.","ex":"The operators vacated the room during the scan."},"SCARP":{"p":"/skɑːp/","s":"n./v.","e":"[n.] The steep artificial slope below a fort's parapet\n[n.] A cliff at the edge of a plateau or ridge caused by erosion or faulting; the steeper side of an escarpment\n[v.] (earth science) to cut, scrape, erode, or otherwise make into a scarp or escarpment","ex":"to scarp the face of a ditch or a rock"},"SCATS":{"p":"","s":"n./v.","e":"[n.] A tax; tribute.\n[n.] A land-tax paid in the Shetland Islands.\n[n.] Scat singing.\n[v.] To sing an improvised melodic solo using nonsense syllables, often onomatopoeic or imitative of musical instruments.\n[v.] To leave quickly (often used in the imperative).\n[v.] An imperative demand, often understood by speaker and listener as impertinent.","ex":"Here comes the principal; we'd better scat."},"SCARS":{"p":"/skɑɹz/","s":"n./v.","e":"[n.] A permanent mark on the skin, sometimes caused by the healing of a wound.\n[n.] (by extension) A permanent negative effect on someone's mind, caused by a traumatic experience.\n[n.] Any permanent mark resulting from damage.\n[v.] To mark the skin permanently.\n[v.] To form a scar.\n[v.] To affect deeply in a traumatic manner.","ex":"Seeing his parents die in a car crash scarred him for life."},"SCARY":{"p":"/ˈskɛəɹi/","s":"adj.","e":"[adj.] Causing or able to cause fright.\n[adj.] Uncannily striking or surprising.\n[adj.] Subject to sudden alarm; easily frightened.","ex":"She was hiding behind her pillow during the scary parts of the film."},"SCATTER":{"p":"/ˈskætə/","s":"n./v.","e":"[n.] The act of scattering or dispersing.\n[n.] A collection of dispersed objects.\n[v.] To (cause to) separate and go in different directions; to disperse.\n[v.] To distribute loosely as by sprinkling.\n[v.] To deflect (radiation or particles).","ex":"The crowd scattered in terror."},"SCANT":{"p":"/skænt/","s":"adj.","e":"[adj.] Very little, very few.\n[adj.] Not full, large, or plentiful; scarcely sufficient; scanty; meager; not enough.\n[adj.] Sparing; parsimonious; chary.","ex":"After his previous escapades, Mary had scant reason to believe John."},"SCHWA":{"p":"/ʃwɑ/","s":"n.","e":"[n.] An indeterminate central vowel sound as the \"a\" in \"about\", represented as /ə/ in IPA.\n[n.] The character ə.","ex":""},"SCHOOL":{"p":"/skuːl/","s":"n./v.","e":"[n.] (collective) A group of fish or a group of marine mammals such as porpoises, dolphins, or whales.\n[n.] A multitude.\n[v.] (of fish) To form into, or travel in a school.","ex":"The divers encountered a huge school of mackerel."},"SCOLD":{"p":"/skəʊld/","s":"v./n.","e":"[v.] To burn with hot liquid.\n[v.] To heat almost to boiling.\n[n.] A person who habitually scolds, in particular a troublesome and angry woman.\n[v.] To rebuke angrily.","ex":"to scald the hand"},"SCENE":{"p":"/siːn/","s":"n./v.","e":"[n.] The location of an event that attracts attention.\n[n.] The stage.\n[n.] The decorations; furnishings and backgrounds of a stage, representing the place in which the action of a play is set\n[v.] To exhibit as a scene; to make a scene of; to display.","ex":"the scene of the crime"},"SCION":{"p":"/ˈsaɪən/","s":"n.","e":"[n.] A descendant, especially a first-generation descendant of a distinguished family.\n[n.] The heir to a throne.\n[n.] A guardian.","ex":""},"SCOFF":{"p":"/skɒf/","s":"n./v.","e":"[n.] Derision; ridicule; a derisive or mocking expression of scorn, contempt, or reproach.\n[n.] An object of scorn, mockery, or derision.\n[v.] To jeer; to laugh with contempt and derision.\n[v.] To mock; to treat with scorn.","ex":""},"SCONE":{"p":"/skɒn/","s":"n./v.","e":"[n.] A small, rich, pastry or quick bread, sometimes baked on a griddle.\n[n.] (Utah) Frybread served with honey butter spread on it.\n[n.] The head.\n[v.] To hit on the head.","ex":"2004 December 3, \"Sconed by a space rock - and then the headaches started\", The Sydney Morning Herald"},"SCOPE":{"p":"/ˈskoʊp/","s":"n./v.","e":"[n.] The breadth, depth or reach of a subject; a domain.\n[n.] A device used in aiming a projectile, through which the person aiming looks at the intended target.\n[n.] Opportunity; broad range; degree of freedom.\n[v.] To perform a cursory investigation of; scope out.\n[v.] To perform any medical procedure that ends in the suffix -scopy, such as endoscopy, colonoscopy, bronchoscopy, etc.\n[v.] To limit (an object or variable) to a certain region of program source code.","ex":"The surgeon will scope the football player's knee to repair damage to a ligament."},"SCORN":{"p":"/skɔːn/","s":"n./v.","e":"[n.] Contempt or disdain.\n[n.] A display of disdain; a slight.\n[n.] An object of disdain, contempt, or derision.\n[v.] To feel or display contempt or disdain for something or somebody; to despise.\n[v.] To reject, turn down.\n[v.] To refuse to do something, as beneath oneself.","ex":"He scorned her romantic advances."},"SCOOT":{"p":"","s":"n./v.","e":"[n.] A dollar.\n[n.] A scooter.\n[n.] A sideways shuffling or sliding motion.\n[v.] To walk fast; to go quickly; to run away hastily.\n[v.] To ride on a scooter.\n[v.] (of an animal) To move with the forelegs while sitting, so that the floor rubs against its rear end.","ex":"They scooted over to the window."},"SCORE":{"p":"/skɔː/","s":"n./v./int.","e":"[n.] The total number of goals, points, runs, etc. earned by a participant in a game.\n[n.] The number of points accrued by each of the participants in a game, expressed as a ratio or a series of numbers.\n[n.] The performance of an individual or group on an examination or test, expressed by a number, letter, or other symbol; a grade.\n[v.] To cut a notch or a groove in a surface.\n[v.] To record the tally of points for a game, a match, or an examination.\n[v.] To obtain something desired.","ex":"The player with the highest score is the winner."},"SCOUR":{"p":"/ˈskaʊə/","s":"n./v.","e":"[n.] The removal of sediment caused by swiftly moving water.\n[n.] A place scoured out by running water, as in the bed of a stream below a waterfall.\n[n.] A place where wool is washed to remove grease and impurities prior to processing.\n[v.] To clean, polish, or wash something by rubbing and scrubbing it vigorously, frequently with an abrasive or cleaning agent.\n[v.] To remove debris and dirt by purging; to sweep along or off (by a current of water).\n[v.] To clear the digestive tract by administering medication that induces defecation or vomiting; to purge.","ex":"Bridge scour may scoop out scour holes and compromise the integrity of the structure."},"SCOWL":{"p":"/skaʊl/","s":"n./v.","e":"[n.] The wrinkling of the brows or face in frowning; the expression of displeasure, sullenness, or discontent in the countenance; an angry frown.\n[n.] (by extension) Gloom; dark or threatening aspect.\n[v.] To wrinkle the brows, as in frowning or displeasure; to put on a frowning look; to look sour, sullen, severe, or angry.\n[v.] (by extension) To look gloomy, dark, or threatening; to lower.\n[v.] To look at or repel with a scowl or a frown.","ex":"to scowl a rival into submission"},"SCRAM":{"p":"/skɹæm/","s":"v.","e":"[v.] Leave in a hurry, go away.","ex":"What are you kids doing on my lawn? Scram!"},"SCOUT":{"p":"[skʌʊt]","s":"n./v.","e":"[n.] A person sent out to gain and bring in tidings; especially, one employed in war to gain information about the enemy and ground.\n[n.] An act of scouting or reconnoitering.\n[n.] A member of any number of youth organizations belonging to the international scout movement, such as the Boy Scouts of America or Girl Scouts of the United States.\n[v.] To explore a wide terrain, as if on a search; to reconnoiter.\n[v.] To observe, watch, or look for, as a scout; to follow for the purpose of observation, as a scout.","ex":""},"SCRAP":{"p":"/skɹæp/","s":"n./v.","e":"[n.] A (small) piece; a fragment; a detached, incomplete portion.\n[n.] (usually in the plural) Leftover food.\n[n.] The crisp substance that remains after drying out animal fat.\n[v.] To discard.\n[v.] (of a project or plan) To stop working on indefinitely.\n[v.] To scrapbook; to create scrapbooks.","ex":"I found a scrap of cloth to patch the hole."},"SCRATCH":{"p":"/skɹætʃ/","s":"n./v./adj.","e":"[n.] A disruption, mark or shallow cut on a surface made by scratching.\n[n.] An act of scratching the skin to alleviate an itch or irritation.\n[n.] A starting line (originally and simply, a line scratched in the ground), as in boxing.\n[v.] To rub a surface with a sharp object, especially by a living creature to remove itching with nails, claws, etc.\n[v.] To rub the skin with rough material causing a sensation of irritation; to cause itching.\n[v.] To mark a surface with a sharp object, thereby leaving a scratch (noun).","ex":"Her skin was covered with tiny scratches."},"SCREEN":{"p":"/skɹiːn/","s":"n./v.","e":"[n.] A physical divider intended to block an area from view, or provide shelter from something dangerous.\n[n.] A material woven from fine wires intended to block animals or large particles from passing while allowing gasses, liquids and finer particles to pass.\n[n.] (by analogy) Searching through a sample for a target; an act of screening\n[v.] To filter by passing through a screen.\n[v.] To shelter or conceal.\n[v.] To remove information, or censor intellectual material from viewing.","ex":"a fire screen"},"SCRUB":{"p":"/skɹʌb/","s":"n./adj.","e":"[n.] One who labors hard and lives meanly; a mean fellow.\n[n.] One who is incompetent or unable to complete easy tasks.\n[n.] A thicket or jungle, often specified by the name of the prevailing plant\n[adj.] Mean; dirty; contemptible; scrubby.","ex":"What a scrub! Instead of washing the dishes she put the used food on her face!"},"SCREW":{"p":"/skɹuː/","s":"n./v.","e":"[n.] A device that has a helical function.\n[n.] The motion of screwing something; a turn or twist to one side.\n[n.] A prison guard.\n[v.] To connect or assemble pieces using a screw.\n[v.] To have sexual intercourse with.\n[v.] To cheat someone or ruin their chances in a game or other situation.","ex":""},"SCRIM":{"p":"","s":"n./v.","e":"[n.] A kind of light cotton or linen fabric, often woven in openwork patterns, -- used for curtains, etc,.\n[n.] A large military scarf, usually camouflage coloured and used for concealment when not used as a scarf.\n[n.] A woven, nonwoven or knitted fabric composed of continuous strands of material used for reinforcing or strengthening membranes.\n[v.] To use a scrim.","ex":""},"SCRIP":{"p":"/skɹɪp/","s":"n.","e":"[n.] A small medieval bag used to carry food, money, utensils etc.\n[n.] Small change.","ex":""},"SCROD":{"p":"/skɹɒd/","s":"n./v.","e":"[n.] (sometimes New York) Any cod, pollock, haddock, or other whitefish.\n[v.] To shred.","ex":""},"SCRUM":{"p":"/skɹʌm/","s":"n.","e":"[n.] A tightly-packed and disorderly crowd of people.\n[n.] Specifically used in the Canadian media to describe a tightly-packed group of reporters surrounding a member of the Canadian House of Commons while in the Parliament Buildings.\n[n.] In rugby union or rugby league, all the forwards joined together in an organised way. Also known as a scrummage.","ex":"A scrum developed around the bar when free beer was announced."},"SCUBA":{"p":"/ˈskuːbə/","s":"n./v.","e":"[n.] (underwater diving) An apparatus carried by a diver, which includes a tank holding compressed, filtered air and a regulator which delivers the air to the diver at ambient pressure which can be used underwater.\n[v.] To perform scuba diving.","ex":""},"SCUFF":{"p":"/skʌf/","s":"n./v.","e":"[n.] (sometimes attributive) A mark left by scuffing or scraping.\n[v.] To scrape the feet while walking.\n[v.] To hit lightly, to brush against.\n[v.] To mishit (a shot on a ball) due to poor contact with the ball.","ex":"Someone left scuff marks in the sand."},"SCULL":{"p":"/skʌl/","s":"n./v.","e":"[n.] A single oar mounted at the stern of a boat and moved from side to side to propel the boat forward.\n[n.] One of a pair of oars handled by a single rower.\n[n.] A small rowing boat, for one person.\n[v.] To row a boat using a scull or sculls.\n[v.] To skate while keeping both feet in contact with the ground or ice.","ex":""},"SEAL":{"p":"/siːl/","s":"n./v.","e":"[n.] A pinniped (Pinnipedia), particularly an earless seal (true seal) or eared seal.\n[n.] A bearing representing a creature something like a walrus.\n[v.] To hunt seals.","ex":"The seals in the harbor looked better than they smelled."},"SEAMS":{"p":"/siːmz/","s":"n./v.","e":"[n.] A folded-back and stitched piece of fabric; especially, the stitching that joins two or more pieces of fabric.\n[n.] A suture.\n[n.] A thin stratum, especially of an economically viable material such as coal or mineral.\n[v.] To put together with a seam.\n[v.] To make the appearance of a seam in, as in knitting a stocking; hence, to knit with a certain stitch, like that in such knitting.\n[v.] To mark with a seam or line; to scar.","ex":""},"SEALS":{"p":"/siːlz/","s":"n./v.","e":"[n.] A pinniped (Pinnipedia), particularly an earless seal (true seal) or eared seal.\n[n.] A bearing representing a creature something like a walrus.\n[v.] To hunt seals.\n[n.] A stamp used to impress a design on a soft substance such as wax.\n[n.] An impression of such stamp on wax, paper or other material used for sealing.\n[n.] A design or insignia usually associated with an organization or an official role.","ex":"The seals in the harbor looked better than they smelled."},"SEARCH":{"p":"/sɜːt͡ʃ/","s":"n./v.","e":"[n.] An attempt to find something.\n[n.] The act of searching in general.\n[v.] To look in (a place) for something.\n[v.] (followed by \"for\") To look thoroughly.\n[v.] To look for, seek.","ex":"With only five minutes until we were meant to leave, the search for the keys started in earnest."},"SEAMY":{"p":"/ˈsiːmi/","s":"adj.","e":"[adj.] Sordid, squalid or corrupt.\n[adj.] Having or showing a seam.","ex":""},"SEARS":{"p":"","s":"v.","e":"[v.] To char, scorch, or burn the surface of (something) with a hot instrument.\n[v.] To wither; to dry up.\n[v.] To make callous or insensible.","ex":""},"SEAT":{"p":"/siːt/","s":"n./v.","e":"[n.] Something to be sat upon.\n[n.] A location or site.\n[n.] The starting point of a fire.\n[v.] To put an object into a place where it will rest; to fix; to set firm.\n[v.] To provide with places to sit.\n[v.] To request or direct one or more persons to sit.","ex":"Be sure to seat the gasket properly before attaching the cover."},"SECOND":{"p":"/ˈsɛkɪnd/","s":"n./v./adj./adv.","e":"[n.] Something that is number two in a series.\n[n.] Something that is next in rank, quality, precedence, position, status, or authority.\n[n.] The place that is next below or after first in a race or contest.\n[v.] To agree as a second person to (a proposal), usually to reach a necessary quorum of two. (See under #Etymology 3 for translations.)\n[v.] To follow in the next place; to succeed.\n[v.] To climb after a lead climber.","ex":"I second the motion."},"SECTOR":{"p":"/ˈsɛk.təɹ/","s":"n.","e":"[n.] Section\n[n.] Zone (designated area).\n[n.] Part of a circle, extending to the center","ex":""},"SECTION":{"p":"/ˈsɛkʃən/","s":"n./v.","e":"[n.] A cutting; a part cut out from the rest of something.\n[n.] A part, piece, subdivision of anything.\n[n.] A part of a document.\n[v.] To cut, divide or separate into pieces.\n[v.] To reduce to the degree of thinness required for study with the microscope.\n[v.] To commit (a person, to a hospital, with or without their consent), as for mental health reasons. So called after various sections of legal acts regarding mental health.","ex":""},"SECURE":{"p":"/səˈkjɔː(ɹ)/","s":"v./adj.","e":"[v.] To make safe; to relieve from apprehensions of, or exposure to, danger; to guard; to protect.\n[v.] To put beyond hazard of losing or of not receiving; to make certain; to assure; frequently with against or from, or formerly with of.\n[v.] To make fast; to close or confine effectually; to render incapable of getting loose or escaping.\n[adj.] Free from attack or danger; protected.\n[adj.] Free from the danger of theft; safe.\n[adj.] Free from the risk of eavesdropping, interception or discovery; secret.","ex":"to secure a creditor against loss; to secure a debt by a mortgage"},"SEDAN":{"p":"/səˈdæn/","s":"n.","e":"[n.] An enclosed windowed chair suitable for a single occupant, carried by at least two porters, in equal numbers in front and behind, using wooden rails that passed through metal brackets on the sides of the chair.\n[n.] An automobile designed in a configuration with separate compartments for engine space, driver/passenger space and luggage space.","ex":""},"SEDER":{"p":"/ˈseɪdə/","s":"n.","e":"[n.] The ceremonial meal held on the first night or two nights of Passover.\n[n.] One of the 54 parts into which the Torah is divided.","ex":""},"SEEKS":{"p":"/siːks/","s":"v.","e":"[v.] To try to find; to look for; to search for.\n[v.] To ask for; to solicit; to beseech.\n[v.] To try to acquire or gain; to strive after; to aim at.","ex":"I seek wisdom."},"SEED":{"p":"/siːd/","s":"n./v.","e":"[n.] A fertilized and ripened ovule, containing an embryonic plant.\n[n.] Any small seed-like fruit.\n[n.] Any propagative portion of a plant which may be sown, such as true seeds, seed-like fruits, tubers, or bulbs.\n[v.] To plant or sow an area with seeds.\n[v.] To cover thinly with something scattered; to ornament with seedlike decorations.\n[v.] To start; to provide, assign or determine the initial resources for, position of, state of.","ex":"If you plant a seed in the spring, you may have a pleasant surprise in the autumn."},"SEEDY":{"p":"/ˈsiːdi/","s":"adj.","e":"[adj.] Full of seeds.\n[adj.] Disreputable, run-down.\n[adj.] Untidy; unkempt.","ex":"Pomegranates are as seedy as any fruit you are likely to see."},"SEASON":{"p":"/ˈsiːzən/","s":"n./v.","e":"[n.] Each of the four divisions of a year: spring, summer, autumn (fall) and winter\n[n.] A part of a year when something particular happens\n[n.] That which gives relish; seasoning.\n[v.] To make fit for any use by time or habit; to habituate; to accustom; to inure.\n[v.] (by extension) To prepare by drying or hardening, or removal of natural juices.\n[v.] To become mature; to grow fit for use; to become adapted to a climate.","ex":"mating season"},"SEEING":{"p":"/ˈsiːɪŋ/","s":"v./n./adj.","e":"[v.] (stative) To perceive or detect with the eyes, or as if by sight.\n[v.] To form a mental picture of.\n[v.] (social) To meet, to visit.\n[n.] The action of the verb to see; eyesight.\n[n.] The movement or distortion of a telescopic image as a result of turbulence in the Earth's atmosphere.\n[adj.] Having vision; not blind.","ex":""},"SEATS":{"p":"/siːts/","s":"n./v.","e":"[n.] Something to be sat upon.\n[n.] A location or site.\n[n.] The starting point of a fire.\n[v.] To put an object into a place where it will rest; to fix; to set firm.\n[v.] To provide with places to sit.\n[v.] To request or direct one or more persons to sit.","ex":"Be sure to seat the gasket properly before attaching the cover."},"SECRET":{"p":"/ˈsiːkɹət/","s":"n./v./adj.","e":"[n.] A piece of knowledge that is hidden and intended to be kept hidden.\n[n.] The key or principle by which something is made clear; the knack.\n[n.] Something not understood or known.\n[v.] To make or keep secret.\n[v.] To hide secretly.\n[adj.] Being or kept hidden.","ex":"\"Can you keep a secret?\" \"Yes.\" \"So can I.\""},"SEEN":{"p":"/ˈsiːn/","s":"v.","e":"[v.] (stative) To perceive or detect with the eyes, or as if by sight.\n[v.] To form a mental picture of.\n[v.] (social) To meet, to visit.","ex":""},"SCREE":{"p":"/skɹiː/","s":"n./v.","e":"[n.] Loose stony debris on a slope.\n[n.] (by extension) Similar debris made up of broken building material such as bricks, concrete, etc.\n[n.] A slope made up of loose stony debris at the base of a cliff, mountain, etc.\n[v.] To traverse scree downhill.","ex":""},"SEEPS":{"p":"","s":"n./v.","e":"[n.] A small spring, pool, or other spot where liquid from the ground (e.g. water, petroleum or tar) has oozed to the surface; a place of seeping.\n[n.] Moisture, liquid, gas, etc. that seeps out; a seepage.\n[n.] The seeping away of a liquid, etc.\n[v.] To ooze or pass slowly through pores or other small openings, and in overly small quantities; said of liquids, etc.\n[v.] To enter or penetrate slowly; to spread or diffuse.\n[v.] To diminish or wane away slowly.","ex":"The water steadily seeped in through the thirl."},"SELDOM":{"p":"/ˈsɛldəm/","s":"adj./adv.","e":"[adj.] Rare; infrequent.\n[adv.] Infrequently, rarely.","ex":"They seldom come here now."},"SELECT":{"p":"/sɪˈlɛkt/","s":"v./adj.","e":"[v.] To choose one or more elements of a set, especially a set of options.\n[v.] To obtain a set of data from a database using a query.\n[adj.] Privileged, specially selected.\n[adj.] Of high quality; top-notch.","ex":"He looked over the menu, and selected the roast beef."},"SELL":{"p":"/sɛl/","s":"n./v.","e":"[n.] An act of selling.\n[n.] An easy task.\n[n.] An imposition, a cheat; a hoax; a disappointment; anything occasioning a loss of pride or dignity.\n[v.] (ditransitive) To transfer goods or provide services in exchange for money.\n[v.] To be sold.\n[v.] To promote a product or service.","ex":"This is going to be a tough sell."},"SEEK":{"p":"/siːk/","s":"n./v.","e":"[n.] The operation of navigating through a stream.\n[v.] To try to find; to look for; to search for.\n[v.] To ask for; to solicit; to beseech.\n[v.] To try to acquire or gain; to strive after; to aim at.","ex":"I seek wisdom."},"SELF":{"p":"/sɛlf/","s":"n./v./adj./pron.","e":"[n.] One individual's personality, character, demeanor, or disposition.\n[n.] The subject of one's own experience of phenomena: perception, emotions, thoughts.\n[n.] An individual person as the object of his own reflective consciousness (plural selves).\n[v.] To fertilise by the same individual; to self-fertilise or self-pollinate.\n[v.] To fertilise by the same strain; to inbreed.\n[adj.] Having its own or a single nature or character throughout, as in colour, composition, etc., without addition or change; of the same kind; unmixed.","ex":"one's true self; one's better self; one's former self"},"SELLING":{"p":"/ˈsɛlɪŋ/","s":"v./n.","e":"[v.] (ditransitive) To transfer goods or provide services in exchange for money.\n[v.] To be sold.\n[v.] To promote a product or service.\n[n.] Action of the verb to sell.\n[n.] Skill at salesmanship.","ex":"I'll sell you all three for a hundred dollars."},"SEEMS":{"p":"/siːmz/","s":"v.","e":"[v.] To appear; to look outwardly; to be perceived as.\n[v.] To befit; to beseem.","ex":"He seems to be ill.   Her eyes seem blue.   It seems like it is going to rain later.   How did she seem to you?"},"SENDER":{"p":"/ˈsɛndɚ/","s":"n.","e":"[n.] Someone who sends.\n[n.] A device or component that transmits, as in telegraphy or computer networks.","ex":"The package was addressed to someone we didn't know, so we returned it to the sender."},"SENIOR":{"p":"/ˈsiːnjə(r)/","s":"n./adj.","e":"[n.] An old person.\n[n.] Someone older than someone else (with possessive).\n[n.] Someone seen as deserving respect or reverence because of their age.\n[adj.] Older; superior\n[adj.] Higher in rank, dignity, or office.\n[adj.] Of or pertaining to a student's final academic year at a high school (twelfth grade) or university.","ex":"He was four years her senior."},"SELLS":{"p":"/sɛlz/","s":"n./v.","e":"[n.] An act of selling.\n[n.] An easy task.\n[n.] An imposition, a cheat; a hoax; a disappointment; anything occasioning a loss of pride or dignity.\n[v.] (ditransitive) To transfer goods or provide services in exchange for money.\n[v.] To be sold.\n[v.] To promote a product or service.","ex":"This is going to be a tough sell."},"SEINE":{"p":"/seɪn/","s":"n./v.","e":"[n.] A long net having floats attached at the top and sinkers (weights) at the bottom, used in shallow water for catching fish.\n[v.] To use a seine, to fish with a seine.","ex":""},"SEERS":{"p":"","s":"n.","e":"[n.] One who sees something; an eyewitness.\n[n.] One who foretells the future; a clairvoyant, prophet, soothsayer or diviner.\n[n.] Unit of mass or volume in the Middle East and Indian subcontinent.","ex":""},"SEPAL":{"p":"/ˈsiːp(ə)l/","s":"n.","e":"[n.] One of the component parts of the calyx, particularly when the sepals in a plant's calyx are not fused into a single structure.","ex":""},"SEPTA":{"p":"","s":"n.","e":"[n.] A wall separating two cavities; a partition\n[n.] A partition that separates the cells of a fruit.\n[n.] A partition that separates the cells of a (septated) fungus.\n[n.] A nose piercing that goes through the nasal septum.","ex":""},"SERIF":{"p":"","s":"n./adj.","e":"[n.] A short line added to the end of a stroke in traditional typefaces, such as Times New Roman.\n[adj.] Of a typeface, provided with serifs.","ex":""},"SEPT":{"p":"/sɛpt/","s":"n.","e":"[n.] A clan, tribe, or family, proceeding from a common progenitor (used especially of the ancient clans in Ireland).\n[n.] An enclosure; a railing.","ex":""},"SENSE":{"p":"/sɛn(t)s/","s":"n./v.","e":"[n.] Any of the manners by which living beings perceive the physical world: for humans sight, smell, hearing, touch, taste.\n[n.] Perception through the intellect; apprehension; awareness.\n[n.] Sound practical or moral judgment.\n[v.] To use biological senses: to either see, hear, smell, taste, or feel.\n[v.] To instinctively be aware.\n[v.] To comprehend.","ex":"a sense of security"},"SERIOUS":{"p":"/ˈsɪə.ɹi.əs/","s":"adj./adv.","e":"[adj.] Without humor or expression of happiness; grave in manner or disposition\n[adj.] Important; weighty; not insignificant\n[adj.] Really intending what is said (or planned, etc); in earnest; not jocular or deceiving\n[adv.] In a serious manner; seriously.","ex":"It was a surprise to see the captain, who had always seemed so serious, laugh so heartily."},"SENT":{"p":"/sɛnt/","s":"n.","e":"[n.] A subdivision of currency, equal to one hundredth of an Estonian kroon.","ex":""},"SERGE":{"p":"/sɜːdʒ/","s":"n./v.","e":"[n.] A type of worsted cloth.\n[n.] (by metonymy) A garment made of this fabric.\n[v.] To overlock.","ex":""},"SERIES":{"p":"/ˈsɪə.ɹiːz/","s":"n./adj.","e":"[n.] A number of things that follow on one after the other or are connected one after the other.\n[n.] A television or radio program which consists of several episodes that are broadcast in regular intervals\n[n.] The sequence of partial sums \\sum_{i=1}^n{a_i} of a given sequence ai.\n[adj.] Connected one after the other in a circuit.","ex":"A series of seemingly inconsequential events led cumulatively to the fall of the company."},"SETTLED":{"p":"/ˈsɛtl̩d/","s":"v./adj.","e":"[v.] To conclude or resolve (something):\n[v.] To place or arrange in(to) a desired (especially: calm) state, or make final disposition of (something).\n[v.] To become calm, quiet, or orderly; to stop being agitated.\n[adj.] Comfortable and at ease, especially after a period of change or unrest.","ex":"to settle her estate"},"SERUM":{"p":"/ˈsiɹəm/","s":"n.","e":"[n.] The clear yellowish liquid obtained upon separating whole blood into its solid and liquid components after it has been allowed to clot.\n[n.] Blood serum from the tissues of immunized animals, containing antibodies and used to transfer immunity to another individual, called antiserum.\n[n.] A watery liquid from animal tissue, especially one that moistens the surface of serous membranes or that is exuded by such membranes when they become inflamed, such as in edema or a blister.","ex":""},"SEVEN":{"p":"/ˈsɛv.ən/","s":"n./num.","e":"[n.] The digit/figure 7 or an occurrence thereof.\n[n.] A card bearing seven pips.\n[num.] A numerical value equal to 7; the number following six and preceding eight. This many dots: (•••••••).\n[num.] Describing a group or set with seven elements.","ex":"He wrote three sevens on the paper."},"SETTLER":{"p":"/ˈsɛt.lə/","s":"n.","e":"[n.] Someone who settles in a new location, especially one who takes up residence in a previously uninhabited place; a colonist.\n[n.] Someone who decides or settles something, such as a dispute.\n[n.] That which settles or finishes, such as a blow that decides a contest.","ex":"the first settlers of New England"},"SERFS":{"p":"","s":"n.","e":"[n.] A partially free peasant of a low hereditary class, attached like a slave to the land owned by a feudal lord and required to perform labour, enjoying minimal legal or customary rights\n[n.] A similar agricultural labourer in 18th and 19th century Europe\n[n.] (strategy games) a worker unit","ex":""},"SETTLE":{"p":"/ˈsɛtəl/","s":"v.","e":"[v.] To conclude or resolve (something):\n[v.] To place or arrange in(to) a desired (especially: calm) state, or make final disposition of (something).\n[v.] To become calm, quiet, or orderly; to stop being agitated.","ex":"to settle her estate"},"SEVERAL":{"p":"/ˈsɛv(ə)ɹəl/","s":"n./adv.","e":"[n.] An area of land in private ownership (as opposed to common land).\n[n.] Each particular taken singly; an item; a detail; an individual.\n[n.] An enclosed or separate place; enclosure.\n[adv.] By itself; severally.","ex":""},"SESSION":{"p":"/ˈsɛʃən/","s":"n./v.","e":"[n.] An informal gathering of musicians to play music, especially improvised jazz or a similar genre.\n[n.] A period devoted to a particular activity, e.g. the annual or semiannual periods of a legislative body (that together comprise the legislative term) whose individual meetings are also called sessions.\n[n.] A meeting of a council, court, school, or legislative body to conduct its business.\n[n.] The sequence of interactions between client and server, or between user and system; the period during which a user is logged in or connected.\n[v.] To hold or participate in a jam session with other musicians.","ex":"\"Are we having a recording session?\" / \"Yes. We've even got some session musicians to provide some brass.\""},"SEWED":{"p":"/ˈsəʊd/","s":"v.","e":"[v.] To use a needle to pass thread repeatedly through (pieces of fabric) in order to join them together.\n[v.] To use a needle to pass thread repeatedly through pieces of fabric in order to join them together.\n[v.] Followed by into: to enclose by sewing.\n[v.] To drain the water from.\n[v.] Of a ship, to be grounded.","ex":"Balls were first made of grass or leaves held together by strings, and later of pieces of animal skin sewn together and stuffed with feathers or hay."},"SEVERE":{"p":"/sɪˈvɪə/","s":"adj.","e":"[adj.] Very bad or intense.\n[adj.] Strict or harsh.\n[adj.] Sober, plain in appearance, austere.","ex":"a severe taskmaster"},"SEXED":{"p":"/sɛkst/","s":"v./adj.","e":"[v.] To determine the sex of an animal.\n[v.] To have sex with.\n[adj.] Having a sex; being male or female.\n[adj.] (in combination) Having a quantifiable libido or particular sex drive.","ex":"highly-sexed"},"SEWER":{"p":"/ˈs(j)uːə/","s":"n./v.","e":"[n.] A pipe or system of pipes used to remove human waste and to provide drainage.\n[v.] To provide (a place) with a system of sewers.","ex":""},"SHADOW":{"p":"/ˈʃædəʊ/","s":"n./v./adj.","e":"[n.] A dark image projected onto a surface where light (or other radiation) is blocked by the shade of an object.\n[n.] Relative darkness, especially as caused by the interruption of light; gloom, obscurity.\n[n.] A area protected by an obstacle (likened to an object blocking out sunlight).\n[v.] To shade, cloud or darken.\n[v.] To block light or radio transmission from.\n[v.] To secretly or discreetly track or follow another, to keep under surveillance.","ex":"My shadow lengthened as the sun began to set."},"SEVER":{"p":"/ˈsɛv.ɚ/","s":"v.","e":"[v.] To cut free.\n[v.] To suffer disjunction; to be parted or separated.\n[v.] To make a separation or distinction; to distinguish.","ex":"After he graduated, he severed all links to his family."},"SERVE":{"p":"/sɜːv/","s":"n./v.","e":"[n.] An act of putting the ball or shuttlecock in play in various games.\n[n.] A portion of food or drink, a serving.\n[v.] (personal) To provide a service (or, by extension, a product, especially food or drink).\n[v.] To treat (someone) in a given manner.\n[v.] To be suitor to; to be the lover of.","ex":"Whose serve is it?"},"SHADY":{"p":"/ˈʃeɪdi/","s":"adj.","e":"[adj.] Abounding in shades.\n[adj.] Causing shade.\n[adj.] Overspread with shade; sheltered from the glare of light or sultry heat.","ex":""},"SETTING":{"p":"/ˈsɛtɪŋ/","s":"v./n./adj.","e":"[v.] To put (something) down, to rest.\n[v.] To attach or affix (something) to something else, or in or upon a certain place.\n[v.] To put in a specified condition or state; to cause to be.\n[v.] To divide a class group in a subject according to ability\n[n.] The time, place and circumstance in which something (such as a story or picture) is set; context; scenario.\n[n.] The act of setting.","ex":"Set the tray there."},"SHAHS":{"p":"","s":"n.","e":"[n.] A king of Persia or Iran.\n[n.] A supreme ruler in some Middle Eastern or South Asian nations.\n[n.] A Ukrainian monetary unit.","ex":""},"SEXES":{"p":"/ˈsɛksɪz/","s":"n./v.","e":"[n.] An offshoot of a larger religion; a group sharing particular (often unorthodox) political and/or religious beliefs.\n[n.] A group following a specific ideal or a leader.\n[n.] A cutting; a scion.\n[n.] A category into which sexually-reproducing organisms are divided on the basis of their reproductive roles in their species.\n[n.] Another category, especially of humans and especially based on sexuality or gender roles.\n[n.] The members of such a category, taken collectively.","ex":"A religious sect."},"SHACK":{"p":"/ʃæk/","s":"n./v.","e":"[n.] A crude, roughly built hut or cabin.\n[n.] Any poorly constructed or poorly furnished building.\n[n.] The room from which a ham radio operator transmits.\n[v.] To live (in or with); to shack up.","ex":""},"SHADE":{"p":"/ʃeɪd/","s":"n.","e":"[n.] Darkness where light, particularly sunlight, is blocked.\n[n.] Something that blocks light, particularly in a window.\n[n.] A variety of a colour/color, in particular one obtained by adding black (compare tint).","ex":"The old oak tree gave shade in the heat of the day."},"SHAFT":{"p":"/ʃɑːft/","s":"n./v.","e":"[n.] The entire body of a long weapon, such as an arrow.\n[n.] The long, narrow, central body of a spear, arrow, or javelin.\n[n.] (by extension) Anything cast or thrown as a spear or javelin.\n[v.] To fuck over; to cause harm to, especially through deceit or treachery.\n[v.] To equip with a shaft.\n[v.] To fuck; to have sexual intercourse with.","ex":"Her hand slipped off the javelin's shaft towards the spearpoint and that's why her score was lowered."},"SHALL":{"p":"/ˈʃæl/","s":"v.","e":"[v.] (modal, auxiliary verb, defective) Used before a verb to indicate the simple future tense in the first person singular or plural.\n[v.] Used similarly to indicate determination or obligation in the second and third persons singular or plural.\n[v.] Used in questions with the first person singular or plural to suggest a possible future action.","ex":"I hope that we shall win the game."},"SHALT":{"p":"/ʃælt/","s":"v.","e":"[v.] (modal, auxiliary verb, defective) Used before a verb to indicate the simple future tense in the first person singular or plural.\n[v.] Used similarly to indicate determination or obligation in the second and third persons singular or plural.\n[v.] Used in questions with the first person singular or plural to suggest a possible future action.","ex":"I hope that we shall win the game."},"SHAME":{"p":"/ʃeɪm/","s":"n./int.","e":"[n.] Uncomfortable or painful feeling due to recognition or consciousness of one's own impropriety or dishonor or something being exposed that should have been kept private.\n[n.] Something to regret.\n[n.] Reproach incurred or suffered; dishonour; ignominy; derision.\n[int.] A cry of admonition for the subject of a speech, either to denounce the speaker or to agree with the speaker's denunciation of some person or matter; often used reduplicated, especially in political debates.\n[int.] Expressing sympathy.","ex":"The teenager couldn’t bear the shame of introducing his parents."},"SHAKO":{"p":"/ˈʃeɪkəʊ/","s":"n.","e":"[n.] A stiff, cylindrical military dress hat with a metal plate in front, a short visor, and a plume.\n[n.] A bearskin or busby.\n[n.] The squilla or mantis shrimp.","ex":""},"SHAKE":{"p":"/ˈʃeɪk/","s":"n./v.","e":"[n.] The act of shaking or being shaken; tremulous or back-and-forth motion.\n[n.] A milkshake.\n[n.] A beverage made by adding ice cream to a (usually carbonated) drink; a float.\n[v.] To cause (something) to move rapidly in opposite directions alternatingly.\n[v.] To move (one's head) from side to side, especially to indicate refusal, reluctance or disapproval.\n[v.] To move or remove by agitating; to throw off by a jolting or vibrating motion.","ex":"She replied in the negative, with a shake of her head."},"SHANK":{"p":"/ʃæŋk/","s":"n./v./adj.","e":"[n.] The part of the leg between the knee and the ankle.\n[n.] Meat from that part of an animal.\n[n.] A redshank or greenshank, various species of Old World wading birds in the genus Tringa having distinctly colored legs.\n[v.] To travel on foot.\n[v.] To stab, especially with an improvised blade.\n[v.] To remove another's trousers, especially in jest; to depants.","ex":""},"SHAGS":{"p":"","s":"n.","e":"[n.] Matted material; rough massed hair, fibres etc.\n[n.] Coarse shredded tobacco.\n[n.] A type of rough carpet pile.\n[n.] Several species of sea birds in the family Phalacrocoracidae (cormorant family), especially the common shag or European shag, Phalacrocorax aristotelis, found on European and African coasts.\n[n.] A swing dance.\n[n.] An act of sexual intercourse.","ex":""},"SHAPE":{"p":"/ʃeɪp/","s":"n./v.","e":"[n.] The status or condition of something\n[n.] Condition of personal health, especially muscular health.\n[n.] The appearance of something in terms of its arrangement in space, especially its outline; often a basic geometric two-dimensional figure.\n[v.] To create or make.\n[v.] To give something a shape and definition.\n[v.] To form or manipulate something into a certain shape.","ex":"The used bookshop wouldn't offer much due to the poor shape of the book."},"SHAMS":{"p":"","s":"n.","e":"[n.] A fake; an imitation that purports to be genuine.\n[n.] Trickery, hoaxing.\n[n.] A false front, or removable ornamental covering.","ex":"The time-share deal was a sham."},"SERVICE":{"p":"/ˈsɜːvɪs/","s":"n./v.","e":"[n.] An act of being of assistance to someone.\n[n.] The practice of providing such a service as economic activity.\n[n.] A department in a company, an organization, a government department, etc.\n[v.] To serve.\n[v.] To perform maintenance.\n[v.] To inseminate through sexual intercourse","ex":"I say I did him a service by ending our relationship – now he can freely pursue his career."},"SHAKY":{"p":"/ˈʃeɪki/","s":"adj.","e":"[adj.] Shaking or trembling.\n[adj.] Nervous, anxious.\n[adj.] (of wood) Full of shakes or cracks; cracked.","ex":"a shaky hand"},"SHARD":{"p":"/ʃaːd/","s":"n./v.","e":"[n.] A piece of broken glass or pottery, especially one found in an archaeological dig.\n[n.] (by extension) A piece of material, especially rock and similar materials, reminding of a broken piece of glass or pottery.\n[n.] A tough scale, sheath, or shell; especially an elytron of a beetle.\n[v.] To fall apart into shards, usually as the result of impact or explosion.\n[v.] To break (something) into shards.\n[v.] To divide (an MMORPG) into several shards, or to establish a shard of one.","ex":""},"SHARE":{"p":"/ʃɛə/","s":"n./v.","e":"[n.] A portion of something, especially a portion given or allotted to someone.\n[n.] A financial instrument that shows that one owns a part of a company that provides the benefit of limited liability.\n[n.] A configuration enabling a resource to be shared over a network.\n[v.] To give part of what one has to somebody else to use or consume.\n[v.] To have or use in common.\n[v.] To divide and distribute.","ex":"Upload media from the browser or directly to the file share."},"SHALE":{"p":"/ʃeɪl/","s":"n./v.","e":"[n.] A shell or husk; a cod or pod.\n[n.] A fine-grained sedimentary rock of a thin, laminated, and often friable, structure.\n[v.] To take off the shell or coat of.","ex":""},"SHARK":{"p":"/ʃɑːk/","s":"n./v.","e":"[n.] A scaleless, predatory fish of the superorder Selachimorpha, with a cartilaginous skeleton and 5 to 7 gill slits on each side of its head.\n[v.] To fish for sharks.","ex":""},"SHARED":{"p":"/ˈʃɛə(ɹ)d/","s":"v./adj.","e":"[v.] To give part of what one has to somebody else to use or consume.\n[v.] To have or use in common.\n[v.] To divide and distribute.\n[v.] To cut; to shear; to cleave; to divide.\n[adj.] Used by multiple entities or for multiple purposes or in multiple ways.","ex":"to share a shelter with another;  They share a language."},"SHARP":{"p":"/ʃɑːp/","s":"n./v./adj./adv.","e":"[n.] The symbol ♯, placed after the name of a note in the key signature or before a note on the staff to indicate that the note is to be played a semitone higher.\n[n.] A note that is played a semitone higher than usual; denoted by the name of the note that is followed by the symbol ♯.\n[n.] A note that is sharp in a particular key.\n[v.] To raise the pitch of a note half a step making a natural note a sharp.\n[v.] To play tricks in bargaining; to act the sharper.\n[v.] To sharpen.","ex":"The pitch pipe sounded out a perfect F♯ (F sharp)."},"SHEAR":{"p":"/ʃɪə(ɹ)/","s":"n./v.","e":"[n.] A cutting tool similar to scissors, but often larger.\n[n.] The act of shearing, or something removed by shearing.\n[n.] Forces that push in opposite directions.\n[v.] To cut, originally with a sword or other bladed weapon, now usually with shears, or as if using shears.\n[v.] To remove the fleece from a sheep etc by clipping.\n[v.] To deform because of forces pushing in opposite directions.","ex":""},"SHAVE":{"p":"/ʃeɪv/","s":"v.","e":"[v.] To make bald or shorter by using a tool such as a razor or pair of electric clippers to cut the hair close to the skin.\n[v.] To cut anything in this fashion.\n[v.] To remove hair from one's face by this means.","ex":"The labourer with the bending scythe is seen / Shaving the surface of the waving green."},"SHAWL":{"p":"","s":"n./v.","e":"[n.] A square or rectangular piece of cloth worn as a covering for the head, neck, and shoulders, typically by women.\n[n.] A fold of wrinkled flesh under the lips and neck of a bloodhound, used in scenting.\n[v.] To wrap in a shawl.","ex":"She wears her shawl when it's cold outside."},"SHEAF":{"p":"/ʃiːf/","s":"n./v.","e":"[n.] A quantity of the stalks and ears of wheat, rye, or other grain, bound together; a bundle of grain or straw.\n[n.] Any collection of things bound together; a bundle.\n[n.] A bundle of arrows sufficient to fill a quiver, or the allowance of each archer.\n[v.] To gather and bind into a sheaf; to make into sheaves\n[v.] To collect and bind cut grain, or the like; to make sheaves.","ex":"a sheaf of paper"},"SHED":{"p":"/ʃɛd/","s":"v.","e":"[v.] To part, separate or divide.\n[v.] To part with, separate from, leave off; cast off, let fall, be divested of.\n[v.] To pour; to make flow.","ex":"A metal comb shed her golden hair."},"SHEEN":{"p":"/ʃiːn/","s":"n./v./adj.","e":"[n.] Splendor; radiance; shininess.\n[n.] A thin layer of a substance (such as oil) spread on a solid or liquid surface.\n[v.] To shine; to glisten.\n[adj.] Beautiful, good-looking, attractive; radiant; shiny.","ex":"oil sheen"},"SHEER":{"p":"/ˈʃɪə/","s":"n./adj./adv.","e":"[n.] A sheer curtain or fabric.\n[adj.] Very thin or transparent.\n[adj.] Pure in composition; unmixed; unadulterated.\n[adj.] (by extension) Downright; complete; pure.\n[adv.] Clean; quite; at once.","ex":"Use sheers to maximize natural light."},"SHEEP":{"p":"/ʃiːp/","s":"n.","e":"[n.] A woolly ruminant of the genus Ovis.\n[n.] A timid, shy person who is easily led by others.\n[n.] (chiefly plural) A religious adherent, a member of a congregation or religious community (compare flock).","ex":""},"SHEET":{"p":"/ʃiːt/","s":"n./v.","e":"[n.] A thin bed cloth used as a covering for a mattress or as a layer over the sleeper.\n[n.] A piece of paper, usually rectangular, that has been prepared for writing, artwork, drafting, wrapping, manufacture of packaging (boxes, envelopes, etc.), and for other uses. The word does not include scraps and irregular small pieces destined to be recycled, used for stuffing or cushioning or paper mache, etc.\n[n.] A flat metal pan, often without raised edge, used for baking.\n[v.] To cover or wrap with cloth, or paper, or other similar material.\n[v.] To form into sheets.\n[v.] Of rain, or other precipitation, to pour heavily.","ex":"Use the sheets in the hall closet to make the bed."},"SHEIK":{"p":"/ʃeɪk/","s":"n.","e":"[n.] The leader of an Arab village, family or small tribe.\n[n.] An Islamic religious cleric; the leader of an Islamic religious order.\n[n.] (some Arab Gulf countries) An official title for members of the royal family as well as some prominent families.","ex":""},"SHELL":{"p":"/ʃɛl/","s":"n./v.","e":"[n.] A hard external covering of an animal.\n[n.] The hard calcareous covering of a bird egg.\n[n.] One of the outer layers of skin of an onion.\n[v.] To remove the outer covering or shell of something.\n[v.] To bombard, to fire projectiles at, especially with artillery.\n[v.] To disburse or give up money, to pay. (Often used with out).","ex":"The restaurant served caramelized onion shells."},"SHELF":{"p":"/ʃɛlf/","s":"n.","e":"[n.] A flat, rigid structure, fixed at right angles to a wall or forming a part of a cabinet, desk etc., and used to support, store or display objects.\n[n.] The capacity of such an object\n[n.] A projecting ledge that resembles such an object.","ex":"a shelf of videos"},"SHELTER":{"p":"/ˈʃɛltə/","s":"n./v.","e":"[n.] A refuge, haven or other cover or protection from something.\n[n.] An institution that provides temporary housing for homeless people, battered women etc.\n[v.] To provide cover from damage or harassment; to shield; to protect.\n[v.] To take cover.","ex":"During the rainstorm, we sheltered under a tree."},"SHIED":{"p":"/ʃaɪd/","s":"v.","e":"[v.] To avoid due to timidness or caution.\n[v.] To jump back in fear.\n[v.] To throw sideways with a jerk; to fling","ex":"I shy away from investment opportunities I don't understand."},"SHIELD":{"p":"/ʃiːld/","s":"n.","e":"[n.] Anything that protects or defends; defense; shelter; protection.\n[n.] A shape like that of a shield; usually, an inverted triangle with sides that curve inward to form a pointed bottom, commonly used for police identifications and company logos.\n[n.] A large expanse of exposed stable Precambrian rock.","ex":""},"SHIFT":{"p":"/ʃɪft/","s":"n./v.","e":"[n.] A modifier key whose main function is shifting between two or more functions of any of certain other keys (usually by pressing Shift and the other button simultaneously).\n[n.] A type of women's undergarment, a slip.\n[n.] A change of workers, now specifically a set group of workers or period of working time.\n[n.] An act of shifting; a slight movement or change.\n[v.] (sometimes figurative) To move from one place to another; to redistribute.\n[v.] To change in form or character; swap.","ex":"Just last week she bought a new shift at the market."},"SHIES":{"p":"","s":"n./v.","e":"[n.] An act of throwing.\n[n.] A place for throwing.\n[n.] A sudden start aside, as by a horse.\n[v.] To avoid due to timidness or caution.\n[v.] To jump back in fear.\n[v.] To throw sideways with a jerk; to fling","ex":"coconut shy"},"SHINS":{"p":"","s":"n./v.","e":"[n.] The front part of the leg below the knee; the front edge of the shin bone: Shinbone\n[n.] A fishplate for a railway.\n[v.] (as \"shin up\") To climb a mast, tree, rope, or the like, by embracing it alternately with the arms and legs, without help of steps, spurs, or the like.\n[v.] To strike with the shin.\n[v.] To run about borrowing money hastily and temporarily, as when trying to make a payment.\n[n.] The twenty-first letter of many Semitic alphabets/abjads (Phoenician, Aramaic, Hebrew, Syriac, Arabic and others): Shin (letter)","ex":"to shin up a mast"},"SHINE":{"p":"/ʃaɪn/","s":"n./v.","e":"[n.] Brightness from a source of light.\n[n.] Brightness from reflected light.\n[n.] Excellence in quality or appearance; splendour.\n[v.] To emit light.\n[v.] To reflect light.\n[v.] To distinguish oneself; to excel.","ex":"My nephew tried other sports before deciding on football, which he shone at right away, quickly becoming the star of his school team."},"SHIMS":{"p":"","s":"n./v.","e":"[n.] A wedge.\n[n.] A thin piece of material, sometimes tapered, used for alignment or support.\n[n.] A small library that transparently intercepts and modifies calls to an API, usually for compatibility purposes.\n[v.] To fit one or more shims to a piece of machinery.\n[v.] To adjust something by using shims.\n[v.] To intercept and modify calls to (an API), usually for compatibility purposes.","ex":""},"SHINY":{"p":"/ˈʃaɪni/","s":"n./adj.","e":"[n.] Anything shiny; a trinket.\n[n.] Contraction of disparaging term \"shiny arses\", originating during World War Two, to describe a desk worker.https//books.google.co.uk/books?id=mAdUqLrKw4YC&pg=PA1717\n[adj.] Reflecting light.\n[adj.] Emitting light.\n[adj.] Excellent; remarkable.","ex":""},"SHILL":{"p":"/ʃɪl/","s":"n./v.","e":"[n.] A person paid to endorse a product favourably, while pretending to be impartial.\n[n.] An accomplice at a confidence trick during an auction or gambling game.\n[n.] A house player in a casino.\n[v.] To promote or endorse in return for payment, especially dishonestly.\n[v.] To put under cover; to sheal.\n[v.] To shell.","ex":""},"SHIPS":{"p":"/ʃɪps/","s":"n./v.","e":"[n.] A water-borne vessel generally larger than a boat.\n[n.] (chiefly in combination) A vessel which travels through any medium other than across land, such as an airship or spaceship.\n[n.] A sailing vessel with three or more square-rigged masts.\n[v.] To send by water-borne transport.\n[v.] To send (a parcel or container) to a recipient (by any means of transport).\n[v.] To release a product to vendors; to launch.","ex":"to ship freight by railroad"},"SHIP":{"p":"/ʃɪp/","s":"n.","e":"[n.] A water-borne vessel generally larger than a boat.\n[n.] (chiefly in combination) A vessel which travels through any medium other than across land, such as an airship or spaceship.\n[n.] A sailing vessel with three or more square-rigged masts.","ex":""},"SHIRE":{"p":"/ʃaɪə(ɹ)/","s":"n./v.","e":"[n.] Physical area administered by a sheriff.\n[n.] Former administrative area of Britain; a county.\n[n.] The general area in which a person lives or comes from, used in the context of travel within the United Kingdom.\n[v.] To (re)constitute as one or more shires or counties.","ex":"Yorkshire is the largest shire in England."},"SHIRK":{"p":"/ʃɜːk/","s":"n./v.","e":"[n.] One who shirks, who avoids a duty or responsibility.\n[v.] To avoid, especially a duty, responsibility, etc.; to stay away from.\n[v.] To evade an obligation; to avoid the performance of duty, as by running away.\n[v.] To procure by petty fraud and trickery; to obtain by mean solicitation.","ex":"If you have a job, don't shirk from it by staying off work."},"SHIRR":{"p":"/ʃɜː/","s":"n./v.","e":"[n.] A shirring.\n[v.] To make gathers in textiles by drawing together parallel threads.\n[v.] To bake (a raw egg removed from its shell) in a baking dish.","ex":""},"SHIVE":{"p":"/ʃaɪv/","s":"n.","e":"[n.] A slice, especially of bread.\n[n.] A sheave.\n[n.] A beam or plank of split wood.","ex":""},"SHOCK":{"p":"/ʃɒk/","s":"n./v.","e":"[n.] A sudden, heavy impact.\n[n.] A discontinuity arising in the solution of a partial differential equation.\n[v.] To cause to be emotionally shocked, to cause (someone) to feel surprised and upset.\n[v.] To give an electric shock to.\n[v.] To meet with a shock; to collide in a violent encounter.","ex":"The train hit the buffers with a great shock."},"SHOAL":{"p":"/ʃɒʊl/","s":"n./v./adj.","e":"[n.] A sandbank or sandbar creating a shallow.\n[n.] A shallow in a body of water.\n[v.] To arrive at a shallow (or less deep) area.\n[v.] To cause a shallowing; to come to a more shallow part of.\n[v.] To become shallow.\n[adj.] Shallow.","ex":"The colour of the water shows where it shoals."},"SHIVA":{"p":"","s":"n.","e":"[n.] A weeklong period of formal mourning for a close relative.","ex":""},"SHOES":{"p":"/ʃuːz/","s":"n./v.","e":"[n.] A protective covering for the foot, with a bottom part composed of thick leather or plastic sole and often a thicker heel, and a softer upper part made of leather or synthetic material. Shoes generally do not extend above the ankle, as opposed to boots, which do.\n[n.] A piece of metal designed to be attached to a horse's foot as a means of protection; a horseshoe.\n[n.] A device for holding multiple decks of playing cards, allowing more games to be played by reducing the time between shuffles.\n[v.] To put shoes on one's feet.\n[v.] To put horseshoes on a horse.\n[v.] To equip an object with a protection against wear.","ex":"Get your shoes on now, or you'll be late for school."},"SHIRT":{"p":"/ʃɜːt/","s":"n.","e":"[n.] An article of clothing that is worn on the upper part of the body, and often has sleeves, either long or short, that cover the arms.\n[n.] An interior lining in a blast furnace.\n[n.] A member of the shirt-wearing team in a shirts and skins game.","ex":"It can take a while to learn how to iron a shirt properly."},"SHONE":{"p":"/ʃɒn/","s":"v.","e":"[v.] To emit light.\n[v.] To reflect light.\n[v.] To distinguish oneself; to excel.","ex":"My nephew tried other sports before deciding on football, which he shone at right away, quickly becoming the star of his school team."},"SHOOK":{"p":"/ʃʊk/","s":"n./v.","e":"[n.] A set of pieces for making a cask or box, usually wood.\n[n.] The parts of a piece of house furniture, as a bedstead, packed together.\n[v.] To pack (staves, etc.) in a shook.","ex":""},"SHOOT":{"p":"/ʃuːt/","s":"n./v.","e":"[n.] The emerging stem and embryonic leaves of a new plant.\n[n.] A photography session.\n[n.] A hunt or shooting competition.\n[v.] To launch a projectile.\n[v.] To move or act quickly or suddenly.\n[v.] To act or achieve.","ex":""},"SHOOS":{"p":"","s":"v.","e":"[v.] To induce someone or something to leave.\n[v.] To leave under inducement.\n[v.] To usher someone.","ex":"Don't just shoo away mosquitoes, kill them!"},"SHOP":{"p":"/ʃɒp/","s":"n./v./int.","e":"[n.] An establishment that sells goods or services to the public; originally only a physical location, but now a virtual establishment as well.\n[n.] A place where things are manufactured or crafted; a workshop.\n[n.] A large garage where vehicle mechanics work.\n[v.] To visit stores or shops to browse or explore merchandise, especially with the intention of buying such merchandise.\n[v.] To purchase products from (a range or catalogue, etc.).\n[v.] To report the criminal activities or whereabouts of someone to an authority.","ex":"He’s shopping for clothes."},"SHORE":{"p":"/ʃɔː/","s":"n./v.","e":"[n.] Land adjoining a non-flowing body of water, such as an ocean, lake or pond.\n[n.] (from the perspective of one on a body of water) Land, usually near a port.\n[v.] To set on shore.","ex":"lake shore;  bay shore;  gulf shore;  island shore;  mainland shore;  river shore;  estuary shore;  pond shore;  sandy shore;  rocky shore"},"SHOT":{"p":"/ʃɒt/","s":"v./n./adj.","e":"[v.] To launch a projectile.\n[v.] To move or act quickly or suddenly.\n[v.] To act or achieve.\n[n.] The result of launching a projectile or bullet.\n[n.] The act of launching a ball or similar object toward a goal.\n[n.] The heavy iron ball used for the shot put.","ex":"The shot was wide off the mark."},"SHORN":{"p":"/ʃɔːn/","s":"v.","e":"[v.] To cut, originally with a sword or other bladed weapon, now usually with shears, or as if using shears.\n[v.] To remove the fleece from a sheep etc by clipping.\n[v.] To deform because of forces pushing in opposite directions.","ex":""},"SHORT":{"p":"/ʃoːt/","s":"n./v./adj./adv./prep.","e":"[n.] A short circuit.\n[n.] A short film.\n[n.] A short version of a garment in a particular size.\n[v.] To cause a short circuit in (something).\n[v.] Of an electrical circuit, to short circuit.\n[v.] To shortchange.","ex":"38 short suits fit me right off the rack."},"SHORTLY":{"p":"/ʃɔːɹtli/","s":"adv.","e":"[adv.] In a short or brief time or manner; quickly.\n[adv.] In or after a short time; soon.\n[adv.] In few words","ex":"Ideas are generally expressed more shortly in verse than in prose"},"SHOTS":{"p":"","s":"n./v.","e":"[n.] The result of launching a projectile or bullet.\n[n.] The act of launching a ball or similar object toward a goal.\n[n.] The heavy iron ball used for the shot put.\n[v.] To load (a gun) with shot.\n[n.] A charge to be paid, a scot or shout.","ex":"The shot was wide off the mark."},"SHOULD":{"p":"/ʃʊd/","s":"v./n.","e":"[v.] (modal, auxiliary verb, defective) Used before a verb to indicate the simple future tense in the first person singular or plural.\n[v.] Used similarly to indicate determination or obligation in the second and third persons singular or plural.\n[v.] Used in questions with the first person singular or plural to suggest a possible future action.\n[n.] A statement of what ought to be the case as opposed to what is the case.\n[v.] To make a statement of what ought to be true, as opposed to reality.\n[v.] (auxiliary) Be obliged to; have an obligation to; indicates that the subject of the sentence has some obligation to execute the sentence predicate or that the speaker has some strong advice but has no authority to enforce it.","ex":"I hope that we shall win the game."},"SHOVE":{"p":"/ʃʌv/","s":"n./v.","e":"[n.] A rough push.\n[n.] An all-in bet.\n[n.] A forward movement of packed river-ice.\n[v.] To push, especially roughly or with force.\n[v.] To move off or along by an act of pushing, as with an oar or pole used in a boat; sometimes with off.\n[v.] (by ellipsis) To make an all-in bet.","ex":""},"SHOW":{"p":"/ʃəʊ/","s":"n./v.","e":"[n.] A play, dance, or other entertainment.\n[n.] An exhibition of items.\n[n.] A broadcast program/programme.\n[v.] To display, to have somebody see (something).\n[v.] To bestow; to confer.\n[v.] To indicate (a fact) to be true; to demonstrate.","ex":"art show;  dog show"},"SHOWING":{"p":"/ˈʃəʊɪŋ/","s":"v./n.","e":"[v.] To display, to have somebody see (something).\n[v.] To bestow; to confer.\n[v.] To indicate (a fact) to be true; to demonstrate.\n[n.] An occasion when something is shown.\n[n.] A result, a judgement.","ex":"All he had to show for four years of attendance at college was a framed piece of paper."},"SHOUT":{"p":"/ʃaʊt/","s":"n./v.","e":"[n.] A loud burst of voice or voices; a violent and sudden outcry, especially that of a multitude expressing joy, triumph, exultation, anger, or animated courage.\n[n.] A round of drinks in a pub; the turn to pay the shot or scot; an act of paying for a round of drinks.\n[n.] A call-out for an emergency services team.\n[v.] To utter a sudden and loud cry, as in joy, triumph, exultation or anger, or to attract attention, to animate others, etc.\n[v.] To utter with a shout; to cry; to shout out\n[v.] To pay for food, drink or entertainment for others.","ex":"They shouted his name to get his attention."},"SHOPS":{"p":"/ʃɒps/","s":"n./v.","e":"[n.] An establishment that sells goods or services to the public; originally only a physical location, but now a virtual establishment as well.\n[n.] A place where things are manufactured or crafted; a workshop.\n[n.] A large garage where vehicle mechanics work.\n[v.] To visit stores or shops to browse or explore merchandise, especially with the intention of buying such merchandise.\n[v.] To purchase products from (a range or catalogue, etc.).\n[v.] To report the criminal activities or whereabouts of someone to an authority.","ex":"He’s shopping for clothes."},"SHOWS":{"p":"/ʃəʊz/","s":"n./v.","e":"[n.] A play, dance, or other entertainment.\n[n.] An exhibition of items.\n[n.] A broadcast program/programme.\n[v.] To display, to have somebody see (something).\n[v.] To bestow; to confer.\n[v.] To indicate (a fact) to be true; to demonstrate.","ex":"art show;  dog show"},"SHRED":{"p":"/ʃɹɛd/","s":"n.","e":"[n.] A long, narrow piece cut or torn off; a strip.\n[n.] In general, a fragment; a piece; a particle; a very small amount.","ex":"There isn't a shred of evidence to support his claims."},"SHUCK":{"p":"/ʃʌk/","s":"n./v.","e":"[n.] The shell or husk, especially of grains (e.g. corn/maize) or nuts (e.g. walnuts).\n[n.] A fraud; a scam.\n[n.] A phony.\n[v.] To remove the shuck from (walnuts, oysters, etc.).\n[v.] To remove (any outer covering).\n[v.] To fool; to hoax.","ex":"Shall we shuck walnuts?"},"SHOWN":{"p":"/ˈʃəʊn/","s":"v.","e":"[v.] To display, to have somebody see (something).\n[v.] To bestow; to confer.\n[v.] To indicate (a fact) to be true; to demonstrate.","ex":"All he had to show for four years of attendance at college was a framed piece of paper."},"SHUSH":{"p":"/ʃʊʃ/","s":"v.","e":"[v.] To be quiet; to keep quiet.\n[v.] To ask someone to be quiet, especially by saying shh.","ex":"He wouldn't shush so I kicked him."},"SHOWY":{"p":"/ˈʃəʊ.i/","s":"adj.","e":"[adj.] (sometimes derogatory) calling attention; flashy; standing out to the eye","ex":""},"SHUTS":{"p":"/ʃʌts/","s":"n./v.","e":"[n.] The act or time of shutting; close.\n[n.] A door or cover; a shutter.\n[n.] The line or place where two pieces of metal are welded together.\n[v.] To close, to stop from being open.\n[v.] To close, to stop being open.\n[v.] To close a business temporarily, or (of a business) to be closed.","ex":"the shut of a door"},"SHRINK":{"p":"/ˈʃɹɪŋk/","s":"n./v.","e":"[n.] Shrinkage; contraction; recoil.\n[n.] (sometimes derogatory) A psychiatrist or psychotherapist.\n[n.] Loss of inventory, for example due to shoplifting or not selling items before their expiration date.\n[v.] To cause to become smaller.\n[v.] To become smaller; to contract.\n[v.] To cower or flinch.","ex":"My shrink said that he was an enabler, bad for me."},"SHUT":{"p":"/ʃʌt/","s":"adj./n./v.","e":"[adj.] Closed, shut.\n[adj.] Narrow; confined.\n[adj.] At a little distance; near.\n[n.] The act or time of shutting; close.\n[n.] A door or cover; a shutter.\n[n.] The line or place where two pieces of metal are welded together.","ex":"a close alley; close quarters"},"SHYLY":{"p":"","s":"adv.","e":"[adv.] In a shy manner.","ex":""},"SIDE":{"p":"/saɪd/","s":"n./v./adj.","e":"[n.] A bounding straight edge of a two-dimensional shape.\n[n.] A flat surface of a three-dimensional object; a face.\n[n.] One half (left or right, top or bottom, front or back, etc.) of something or someone.\n[v.] To ally oneself, be in an alliance, usually with \"with\" or rarely \"in with\"\n[v.] To lean on one side.\n[v.] To be or stand at the side of; to be on the side toward.","ex":"A square has four sides."},"SIDES":{"p":"/saɪdz/","s":"n./v.","e":"[n.] A bounding straight edge of a two-dimensional shape.\n[n.] A flat surface of a three-dimensional object; a face.\n[n.] One half (left or right, top or bottom, front or back, etc.) of something or someone.\n[v.] To ally oneself, be in an alliance, usually with \"with\" or rarely \"in with\"\n[v.] To lean on one side.\n[v.] To be or stand at the side of; to be on the side toward.","ex":"A square has four sides."},"SIEGE":{"p":"/siːdʒ/","s":"n./v.","e":"[n.] (heading) Military action.\n[n.] (heading) A seat.\n[n.] A place with a toilet seat: an outhouse; a lavatory.\n[v.] To assault a blockade of a city or fortress with the intent of conquering by force or attrition; to besiege.","ex":""},"SHUNT":{"p":"/ʃʌnt/","s":"n./v.","e":"[n.] An act of moving (suddenly), as due to a push or shove.\n[n.] A connection used as an alternative path between parts of an electrical circuit.\n[n.] The shifting of the studs on a projectile from the deep to the shallow sides of the grooves in its discharge from a shunt gun.\n[v.] To cause to move (suddenly), as by pushing or shoving; to give a (sudden) start to.\n[v.] To divert to a less important place, position, or state.\n[v.] To provide with a shunt.","ex":"to shunt a galvanometer"},"SIGHT":{"p":"/saɪt/","s":"n./v.","e":"[n.] (in the singular) The ability to see.\n[n.] The act of seeing; perception of objects by the eye; view.\n[n.] Something seen.\n[v.] To register visually.\n[v.] To get sight of (something).\n[v.] To apply sights to; to adjust the sights of; also, to give the proper elevation and direction to by means of a sight.","ex":"He is losing his sight and now can barely read."},"SHREW":{"p":"/ʃɹuː/","s":"n.","e":"[n.] Any of numerous small, mouselike, chiefly nocturnal, mammals of the family Soricidae (order Soricomorpha).\n[n.] Certain other small mammals that resemble true shrews (order Soricomorpha).\n[n.] An ill-tempered, nagging woman: a scold.","ex":""},"SHRUB":{"p":"/ʃɹʌb/","s":"n./v.","e":"[n.] A woody plant smaller than a tree, and usually with several stems from the same base.\n[v.] To lop; to prune.\n[v.] (Kenyan English) To mispronounce a word by replacing its consonant sound(s) with another or others of a similar place of articulation.","ex":""},"SHRUG":{"p":"/ʃɹʌɡ/","s":"n./v.","e":"[n.] A lifting of the shoulders to signal indifference or a casual lack of knowledge.\n[n.] A cropped, cardigan-like garment with short or long sleeves, typically knitted.\n[v.] To raise (the shoulders) to express uncertainty, lack of concern, (formerly) dread, etc.","ex":"He dismissed my comment with a shrug."},"SIDLE":{"p":"/ˈsaɪdl/","s":"n./v.","e":"[n.] An act of sidling.\n[v.] To (cause something to) move sideways.\n[v.] In the intransitive sense often followed by up: to (cause something to) advance in a coy, furtive, or unobtrusive manner.","ex":""},"SIGMA":{"p":"/ˈsɪɡmə/","s":"n.","e":"[n.] The eighteenth letter of the Classical and Modern Greek alphabets, the twentieth letter of Old and Ancient.\n[n.] The symbol Σ, used to indicate summation of a set or series.\n[n.] The symbol σ, used to indicate one standard deviation from the mean, particularly in a normal distribution.","ex":""},"SIEVE":{"p":"/sɪv/","s":"n./v.","e":"[n.] A device with a mesh bottom to separate, in a granular material, larger particles from smaller ones, or to separate solid objects from a liquid.\n[n.] A process, physical or abstract, that arrives at a final result by filtering out unwanted pieces of input from a larger starting set of input.\n[n.] A kind of coarse basket.\n[v.] To strain, sift or sort using a sieve.\n[v.] To concede; let in","ex":"Use the sieve to get the pasta from the water."},"SIGNS":{"p":"/saɪnz/","s":"n./v.","e":"[n.] (sometimes also used uncountably) A visible indication.\n[n.] Physical evidence left by an animal.\n[n.] A clearly visible object, generally flat, bearing a short message in words or pictures.\n[v.] To make a mark\n[v.] To make the sign of the cross\n[v.] To indicate","ex":"I gave them a thumbs-up sign."},"SILL":{"p":"/sɪl/","s":"n.","e":"[n.] (also window sill) A horizontal slat which forms the base of a window.\n[n.] A horizontal, structural member of a building near ground level on a foundation or pilings or lying on the ground in earth-fast construction and bearing the upright portion of a frame. Also called a ground plate, groundsill, sole, sole-plate, mudsill. An interrupted sill fits between posts instead of being below and supporting the posts in timber framing.\n[n.] A horizontal layer of igneous rock between older rock beds.","ex":""},"SIDED":{"p":"","s":"v.","e":"[v.] To ally oneself, be in an alliance, usually with \"with\" or rarely \"in with\"\n[v.] To lean on one side.\n[v.] To be or stand at the side of; to be on the side toward.\n[v.] To clear, tidy or sort.","ex":"Which will you side with, good or evil?"},"SIGN":{"p":"/saɪn/","s":"n.","e":"[n.] (sometimes also used uncountably) A visible indication.\n[n.] Physical evidence left by an animal.\n[n.] A clearly visible object, generally flat, bearing a short message in words or pictures.","ex":"I gave them a thumbs-up sign."},"SILENT":{"p":"/ˈsaɪlənt/","s":"n./adj.","e":"[n.] That which is silent; a time of silence.\n[n.] A silent movie\n[adj.] Free from sound or noise; absolutely still; perfectly quiet.\n[adj.] Not speaking; indisposed to talk; speechless; mute; taciturn; not loquacious; not talkative.\n[adj.] Keeping at rest; inactive; calm; undisturbed.","ex":"The wind is silent."},"SIGHS":{"p":"/saɪz/","s":"n./v.","e":"[n.] A deep, prolonged audible inhale and exhale of breath; as when fatigued, frustrated, grieved, or relieved; the act of sighing.\n[n.] Figuratively, a manifestation of grief; a lament.\n[n.] A person who is bored.\n[v.] To inhale a larger quantity of air than usual, and immediately expel it; to make a deep single audible respiration, especially as the result or involuntary expression of fatigue, exhaustion, grief, sorrow, frustration, or the like.\n[v.] To lament; to grieve.\n[v.] To utter sighs over; to lament or mourn over.","ex":"He sighed over the lost opportunity."},"SILKY":{"p":"/ˈsɪlki/","s":"n./adj.","e":"[n.] A seal which can magically transform into a human by shedding its skin.\n[n.] A chicken of a certain breed with very fine, silk-like feathers.\n[adj.] Similar in appearance or texture (especially in softness and smoothness) to silk.\n[adj.] Smooth and pleasant; seductive.\n[adj.] Covered in long, slender, glistening hairs pressed close to the surface; sericeous.","ex":"cloth with a silky lustre"},"SILLS":{"p":"","s":"n.","e":"[n.] (also window sill) A horizontal slat which forms the base of a window.\n[n.] A horizontal, structural member of a building near ground level on a foundation or pilings or lying on the ground in earth-fast construction and bearing the upright portion of a frame. Also called a ground plate, groundsill, sole, sole-plate, mudsill. An interrupted sill fits between posts instead of being below and supporting the posts in timber framing.\n[n.] A horizontal layer of igneous rock between older rock beds.\n[n.] A young herring.\n[n.] The shaft or thill of a carriage.","ex":""},"SINEW":{"p":"/ˈsɪnjuː/","s":"n./v.","e":"[n.] A cord or tendon of the body.\n[n.] A cord or string, particularly as of a musical instrument.\n[n.] Muscular power, muscle; nerve, nervous energy; vigor, vigorous strength.\n[v.] To knit together or make strong with, or as if with, sinews.","ex":""},"SILTS":{"p":"/sɪlts/","s":"v.","e":"[v.] To clog or fill with silt.\n[v.] To become clogged with silt.\n[v.] To flow through crevices; to percolate.","ex":""},"SING":{"p":"/sɪŋ/","s":"n./v.","e":"[n.] A gathering at which people sing songs.\n[v.] To produce musical or harmonious sounds with one’s voice.\n[v.] To express audibly by means of a harmonious vocalization.\n[v.] To soothe with singing.","ex":"\"I really want to sing in the school choir,\" said Vera."},"SINGE":{"p":"/sɪnd͡ʒ/","s":"n./v.","e":"[n.] A burning of the surface; a slight burn.\n[v.] To burn slightly.\n[v.] To remove the nap of (cloth), by passing it rapidly over a red-hot bar, or over a flame, preliminary to dyeing it.\n[v.] To remove the hair or down from (a plucked chicken, etc.) by passing it over a flame.","ex":""},"SIMPLE":{"p":"/ˈsɪmpəl/","s":"n./v./adj.","e":"[n.] A herbal preparation made from one plant, as opposed to something made from more than one plant.\n[n.] (by extension) A physician.\n[n.] A simple or atomic proposition.\n[v.] To gather simples, i.e. medicinal herbs.\n[adj.] Uncomplicated; taken by itself, with nothing added.\n[adj.] Without ornamentation; plain.","ex":""},"SINCE":{"p":"/sɪns/","s":"adv./prep./conj.","e":"[adv.] From a specified time in the past.\n[prep.] From: referring to a period of time ending in the present and defining it by the point in time at which it started, or the period in which its starting point occurred.\n[conj.] From the time that.\n[conj.] Because.\n[conj.] When or that.","ex":"A short/long time since"},"SINUS":{"p":"/ˈsaɪnəs/","s":"n.","e":"[n.] A pouch or cavity in any organ or tissue, especially the paranasal sinus.\n[n.] A channel for transmitting venous blood.\n[n.] A notch or depression between two lobes or teeth in the margin of an organ.","ex":""},"SIREN":{"p":"/ˈsaɪəɹən/","s":"n./v./adj.","e":"[n.] One of a group of nymphs who lured mariners to their death on the rocks.\n[n.] One who sings sweetly and charms.\n[n.] A dangerously seductive woman.\n[v.] To make a noise with, or as if with, a siren.\n[adj.] Relating to or like a siren.","ex":""},"SINGER":{"p":"/ˈsɪŋə/","s":"n.","e":"[n.] A person who sings, often professionally.\n[n.] (square dance) dance figure with a fixed structure, sung by a caller, or a piece of music with that structure.","ex":""},"SITAR":{"p":"","s":"n.","e":"[n.] A Hindustani/Indian classical stringed instrument, typically having a gourd as its resonating chamber.","ex":""},"SITED":{"p":"","s":"v.","e":"[v.] To situate or place a building.","ex":""},"SINKS":{"p":"/sɪŋks/","s":"n./v.","e":"[n.] A basin used for holding water for washing.\n[n.] A drain for carrying off wastewater.\n[n.] A sinkhole.\n[v.] (heading, physical) To move or be moved into something.\n[v.] (heading, social) To diminish or be diminished.\n[v.] To conceal and appropriate.","ex":""},"SIXES":{"p":"","s":"n.","e":"[n.] The digit or figure 6.\n[n.] (by ellipsis of six o'clock) Rear, behind (rear side of something).\n[n.] An event whereby a batsman hits a ball which does not bounce before passing over a boundary in the air, resulting in an award of 6 runs for the batting team.\n[n.] A pair of sixes.\n[n.] Short for six of one, half a dozen of the other.","ex":"cover my six"},"SIXTH":{"p":"/sɪk(s)θ/","s":"n./v./adj.","e":"[n.] (not used in the plural) The person or thing in the sixth position.\n[n.] One of six equal parts of a whole.\n[n.] The interval between one note and another, five notes higher in the scale, for example C to A, a major sixth, or C to A flat, a minor sixth. (Note that the interval covers six notes counting inclusively, for example C-D-E-F-G-A.)\n[v.] To divide by six, which also means multiplying a denominator by six\n[adj.] The ordinal form of the number six.","ex":""},"SIRES":{"p":"","s":"n./v.","e":"[n.] A lord, master, or other person in authority, most commonly used vocatively: formerly in speaking to elders and superiors, later only when addressing a sovereign.\n[n.] A male animal; a stud, especially a horse or dog, that has fathered another.\n[n.] A father; the head of a family; the husband.\n[v.] (of a male) to procreate; to father, beget, impregnate.","ex":""},"SITE":{"p":"/saɪt/","s":"n.","e":"[n.] Sorrow, grief.","ex":""},"SITTING":{"p":"/ˈsɪtɪŋ/","s":"n.","e":"[n.] A period during which one is seated for a specific purpose.\n[n.] A special seat allotted to a seat-holder, at church, etc.\n[n.] The part of the year in which judicial business is transacted.","ex":"Due to the sheer volume of guests, we had to have two sittings for the meal."},"SIZE":{"p":"/saɪz/","s":"n./v.","e":"[n.] (obsolete outside dialectal) An assize.\n[n.] A regulation determining the amount of money paid in fees, taxes etc.\n[n.] A fixed standard for the magnitude, quality, quantity etc. of goods, especially food and drink.\n[v.] To adjust the size of; to make a certain size.\n[v.] To classify or arrange by size.\n[v.] To approximate the dimensions, estimate the size of.","ex":""},"SITES":{"p":"/saɪts/","s":"n./v.","e":"[n.] Sorrow, grief.\n[n.] The place where anything is fixed; situation; local position\n[n.] A place fitted or chosen for any certain permanent use or occupation\n[n.] The posture or position of a thing.\n[v.] To situate or place a building.","ex":"the site of a city or of a house"},"SINGS":{"p":"/sɪŋz/","s":"n./v.","e":"[n.] A gathering at which people sing songs.\n[v.] To produce musical or harmonious sounds with one’s voice.\n[v.] To express audibly by means of a harmonious vocalization.\n[v.] To soothe with singing.","ex":"\"I really want to sing in the school choir,\" said Vera."},"SIZED":{"p":"","s":"v./adj.","e":"[v.] To adjust the size of; to make a certain size.\n[v.] To classify or arrange by size.\n[v.] To approximate the dimensions, estimate the size of.\n[v.] To apply glue or other primer to a surface which is to be painted.\n[adj.] Having a certain size. Usually used in combination with an adverb.","ex":"A badly-sized pair of shoes."},"SIZES":{"p":"","s":"n./v.","e":"[n.] (obsolete outside dialectal) An assize.\n[n.] A regulation determining the amount of money paid in fees, taxes etc.\n[n.] A fixed standard for the magnitude, quality, quantity etc. of goods, especially food and drink.\n[v.] To adjust the size of; to make a certain size.\n[v.] To classify or arrange by size.\n[v.] To approximate the dimensions, estimate the size of.","ex":""},"SKEET":{"p":"","s":"n./v.","e":"[n.] A form of trapshooting using clay targets to simulate birds in flight.\n[n.] A hand consisting of a 9, a 5, a 2, and two other cards lower than 9.\n[n.] The ejaculation of semen.\n[v.] To shoot or spray (used of fluids).\n[v.] To ejaculate.","ex":""},"SIRED":{"p":"","s":"v.","e":"[v.] (of a male) to procreate; to father, beget, impregnate.","ex":""},"SKIDS":{"p":"/skɪdz/","s":"n./v.","e":"[n.] An out-of-control sliding motion as would result from applying the brakes too hard in a car.\n[n.] A shoe or clog, as of iron, attached to a chain, and placed under the wheel of a wagon to prevent its turning when descending a steep hill; a drag; a skidpan.\n[n.] (by extension) A hook attached to a chain, used for the same purpose.\n[v.] To slide in an uncontrolled manner as in a car with the brakes applied too hard.\n[v.] To protect or support with a skid or skids.\n[v.] To cause to move on skids.","ex":"Just before hitting the guardrail the driver was able to regain control and pull out of the skid."},"SKIFF":{"p":"/skɪf/","s":"n./v.","e":"[n.] Term used in tea gardens and denotes the act of cutting/pruning the bushes as per the specific norms. Various types of skiff are used viz Light Skiff (LS), Medium Skiff (MS), Deep Skiff (DS) and Level Of Skiff (LOS).\n[n.] A small flat-bottomed open boat with a pointed bow and square stern.\n[n.] Any of various types of boats small enough for sailing or rowing by one person.\n[n.] A light wind/rain/snow, etc.\n[v.] To navigate in a skiff.\n[v.] To cut (a tea bush) to maintain the plucking table","ex":"A skiff of rain blew into the shed and the two men moved their chairs back."},"SKIED":{"p":"/skiːd/","s":"v.","e":"[v.] To move on skis\n[v.] To travel over (a slope etc.) on skis; to travel on skis at (a place), (especially as a sport)","ex":""},"SKILLED":{"p":"/skɪld/","s":"adj.","e":"[adj.] Having or showing skill; skillful.\n[adj.] Requiring special abilities or training.","ex":""},"SKEIN":{"p":"/skeɪn/","s":"n./v.","e":"[n.] A quantity of yarn, thread, or the like, put up together, after it is taken from the reel. A skein of cotton yarn is formed by eighty turns of the thread around a fifty-four inch reel.\n[n.] A web, a weave, a tangle.\n[n.] The membrane of a fish ovary.\n[v.] To wind or weave into a skein.","ex":""},"SKILL":{"p":"/skɪl/","s":"n./adj.","e":"[n.] Capacity to do something well; technique, ability. Skills are usually acquired or learned, as opposed to abilities, which are often thought of as innate.\n[n.] Discrimination; judgment; propriety; reason; cause.\n[n.] Knowledge; understanding.\n[adj.] Great, excellent.","ex":""},"SIXTY":{"p":"/ˈsɪkstɪ/","s":"num.","e":"[num.] The cardinal number occurring after fifty-nine and before sixty-one, represented in Roman numerals as LX and in Arabic numerals as 60.","ex":""},"SKINS":{"p":"/skɪnz/","s":"n./v.","e":"[n.] The outer protective layer of the body of any animal, including of a human.\n[n.] The outer protective layer of the fruit of a plant.\n[n.] The skin and fur of an individual animal used by humans for clothing, upholstery, etc.\n[v.] To injure the skin of.\n[v.] To remove the skin and/or fur of an animal or a human.\n[v.] To high five.","ex":"He is so disgusting he makes my skin crawl."},"SKIMP":{"p":"/skɪmp/","s":"v.","e":"[v.] To mock, deride, scorn, scold, make fun of.","ex":"I thought Adie was only skimpin' me."},"SKIP":{"p":"/skɪp/","s":"n./v.","e":"[n.] A leaping, jumping or skipping movement.\n[n.] The act of passing over an interval from one thing to another; an omission of a part.\n[n.] A passage from one sound to another by more than a degree at once.\n[v.] To move by hopping on alternate feet.\n[v.] To leap about lightly.\n[v.] To skim, ricochet or bounce over a surface.","ex":"She will skip from one end of the sidewalk to the other."},"SKITS":{"p":"","s":"n.","e":"[n.] A short comic performance.\n[n.] A jeer or sally; a brief satire.\n[n.] A wanton girl; a wench.","ex":""},"SKULL":{"p":"/skʌl/","s":"n./v.","e":"[n.] The main bones of the head considered as a unit; including the cranium, facial bones, and mandible.\n[n.] A symbol for death; death's-head\n[n.] The mind or brain.\n[v.] To hit in the head with a fist, a weapon, or a thrown object.\n[v.] To strike the top of (the ball).","ex":""},"SKULK":{"p":"/skʌlk/","s":"n./v.","e":"[n.] A group of foxes.\n[n.] A group of people seen as being fox-like (e.g. cunning, dishonest, or having nefarious plans).\n[n.] The act of skulking.\n[v.] To stay where one cannot be seen, conceal oneself (often in a cowardly way or with the intent of doing harm).\n[v.] To move in a stealthy or furtive way; to come or go while trying to avoid detection.\n[v.] To avoid an obligation or responsibility.","ex":""},"SKUNK":{"p":"/skʌŋk/","s":"n./v.","e":"[n.] Any of various small mammals, of the family Mephitidae, native to North and Central America, having a glossy black with a white coat and two musk glands at the base of the tail for emitting a noxious smell as a defensive measure.\n[n.] A despicable person.\n[n.] A walkover victory in sports or board games, as when the opposing side is unable to score. Compare shutout.\n[v.] To defeat so badly as to prevent any opposing points.\n[v.] To win by 30 or more points.\n[v.] (of beer) To go bad, to spoil.","ex":"I skunked him at cards."},"SLAGS":{"p":"","s":"n./v.","e":"[n.] Waste material from a coal mine\n[n.] Scum that forms on the surface of molten metal\n[n.] Impurities formed and separated out when a metal is smelted from ore; vitrified cinders\n[v.] To produce slag\n[v.] To become slag; to agglomerate when heated below the fusion point\n[v.] To reduce to slag","ex":""},"SLAKE":{"p":"/sleɪk/","s":"v.","e":"[v.] To satisfy (thirst, or other desires).\n[v.] To cool (something) with water or another liquid.\n[v.] To become mixed with water, so that a true chemical combination takes place.","ex":"The lime slakes."},"SLACK":{"p":"/slæk/","s":"n./adj./adv.","e":"[n.] The part of anything that hangs loose, having no strain upon it.\n[n.] A tidal marsh or shallow that periodically fills and drains.\n[adj.] (normally said of a rope) Lax; not tense; not firmly extended.\n[adj.] Weak; not holding fast.\n[adj.] Lacking diligence or care; not earnest or eager.\n[adv.] Slackly.","ex":"take in the slack"},"SLAIN":{"p":"/sleɪn/","s":"n./v.","e":"[n.] (with \"the\") Those who have been killed.\n[v.] To kill, murder.\n[v.] To eradicate or stamp out.\n[v.] (by extension) To defeat, overcome (in a competition or contest).","ex":"Our foes must all be slain."},"SLAMS":{"p":"","s":"v.","e":"[v.] To shut with sudden force so as to produce a shock and noise.\n[v.] To put in or on a particular place with force and loud noise. (Often followed by a preposition such as down, against or into.)\n[v.] To strike forcefully with some implement.\n[v.] To defeat by winning all the tricks of a deal or a hand.","ex":"Don't slam the door!"},"SLANG":{"p":"/sleɪŋ/","s":"n./v.","e":"[n.] Language outside of conventional usage and in the informal register.\n[n.] Language that is unique to a particular profession or subject; jargon.\n[n.] The specialized language of a social group, sometimes used to make what is said unintelligible to those not members of the group; cant.\n[v.] To vocally abuse, or shout at.","ex":""},"SLATS":{"p":"","s":"n./v.","e":"[n.] A thin, narrow strip or bar of wood (lath) or metal.\n[n.] (aeronautical) A movable control surface at the leading edge of a wing that when moved, changes the chord line of the airfoil, affecting the angle of attack. Employed in conjunction with flaps to allow for a lower stall speed in the landing attitude, facilitating slow flight.\n[n.] A ski.\n[v.] To construct or provide with slats.\n[v.] To slap; to strike; to beat; to throw down violently.\n[v.] To split; to crack.","ex":"slats of a window blind"},"SLATE":{"p":"/sleɪt/","s":"n./adj.","e":"[n.] A fine-grained homogeneous sedimentary rock composed of clay or volcanic ash which has been metamorphosed so that it cleaves easily into thin layers.\n[n.] The bluish-grey colour of most slate.\n[n.] A chalkboard, sheet of slate for writing on with chalk or with a thin rod of slate (a slate pencil) formerly commonly used by both students and teachers in schools\n[adj.] Having the bluish-grey/gray colour of slate.","ex":""},"SLAPS":{"p":"","s":"n./v.","e":"[n.] A blow, especially one given with the open hand, or with something broad and flat.\n[n.] The sound of such a blow.\n[n.] Makeup; cosmetics.\n[v.] To give a slap to.\n[v.] To cause something to strike soundly.\n[v.] To strike soundly against something.","ex":"She slapped him in response to the insult."},"SLAVE":{"p":"/sleɪv/","s":"n./v.","e":"[n.] A person who is held in servitude as the property of another person, and whose labor (and often also whose body and life) is subject to the owner's volition and control.\n[n.] A drudge; one who labors or is obliged (e.g. by prior contract) to labor like a slave with limited rights, e.g. an indentured servant.\n[n.] An abject person.\n[v.] To work as a slaver, to enslave people.\n[v.] To work hard.\n[v.] To place a device under the control of another.","ex":"I was slaving all day over a hot stove."},"SLEEK":{"p":"/sliːk/","s":"n./v./adj./adv.","e":"[n.] That which makes smooth; varnish.\n[v.] To make smooth or glossy; to polish or cause to be attractive.\n[adj.] Having an even, smooth surface; smooth\n[adj.] Glossy\n[adj.] Not rough or harsh.\n[adv.] With ease and dexterity.","ex":"sleek hair"},"SLEEVE":{"p":"/sliːv/","s":"n./v.","e":"[n.] The part of a garment that covers the arm.\n[n.] A (usually tubular) covering or lining to protect a piece of machinery etc.\n[n.] A protective jacket or case, especially for a record, containing art and information about the contents; also the analogous leaflet found in a packaged CD.\n[v.] To fit a sleeve to\n[v.] (magic tricks) To hide something up one's sleeve.","ex":""},"SLEDS":{"p":"","s":"n./v.","e":"[n.] A small, light vehicle with runners, used recreationally, mostly by children, for sliding down snow-covered hills. (A \"sled\" in this sense is not pulled by an animal as a \"sleigh\" is.)\n[n.] A vehicle on runners, used for conveying loads over the snow or ice. (contrast \"sleigh\", which is larger)\n[n.] A snowmobile.\n[v.] To ride a sled.\n[v.] To convey on a sled.","ex":"The child zoomed down the hill on his sled."},"SLASH":{"p":"/slaʃ/","s":"n./v./adv./conj.","e":"[n.] A slashing action or motion, particularly:\n[n.] A mark made by a slashing motion, particularly:\n[n.] Something resembling such a mark, particularly:\n[v.] To cut or attempt to cut, particularly:\n[v.] To strike violently and randomly, particularly:\n[v.] To move quickly and violently.","ex":""},"SLEPT":{"p":"/slɛpt/","s":"v.","e":"[v.] To rest in a state of reduced consciousness.\n[v.] (of a spinning top or yo-yo) To spin on its axis with no other perceptible motion.\n[v.] To cause (a spinning top or yo-yo) to spin on its axis with no other perceptible motion.","ex":"You should sleep 8 hours a day."},"SLING":{"p":"/ˈslɪŋ/","s":"n./v.","e":"[n.] An instrument for throwing stones or other missiles, consisting of a short strap with two strings fastened to its ends, or with a string fastened to one end and a light stick to the other.\n[n.] A kind of hanging bandage put around the neck, in which a wounded arm or hand is supported.\n[n.] A loop of cloth, worn around the neck, for supporting a baby or other such load.\n[v.] To throw with a circular or arcing motion.\n[v.] To throw with a sling.\n[v.] To pass a rope around (a cask, gun, etc.) preparatory to attaching a hoisting or lowering tackle.","ex":""},"SLICE":{"p":"/slaɪs/","s":"n./v./adj.","e":"[n.] That which is thin and broad.\n[n.] A thin, broad piece cut off.\n[n.] An amount of anything.\n[v.] To cut into slices.\n[v.] To cut with an edge utilizing a drawing motion.\n[v.] To clear (e.g. a fire, or the grate bars of a furnace) by means of a slice bar.","ex":"Jim was munching on a slice of toast."},"SLIDE":{"p":"/slaɪd/","s":"n./v.","e":"[n.] An item of play equipment that children can climb up and then slide down again.\n[n.] A surface of ice, snow, butter, etc. on which someone can slide for amusement or as a practical joke.\n[n.] The falling of large amounts of rubble, earth and stones down the slope of a hill or mountain; avalanche.\n[v.] To (cause to) move in continuous contact with a surface\n[v.] To move on a low-friction surface.\n[v.] To drop down and skid into a base.","ex":"The long, red slide was great fun for the kids."},"SLINK":{"p":"/slɪŋk/","s":"n./v./adj.","e":"[n.] A furtive sneaking motion.\n[n.] The young of an animal when born prematurely, especially a calf.\n[n.] The meat of such a prematurely born animal.\n[v.] To sneak about furtively.\n[v.] To give birth to an animal prematurely.\n[adj.] Thin; lean","ex":"a cow that slinks her calf"},"SLITS":{"p":"/ˈslɪts/","s":"n./v.","e":"[n.] A narrow cut or opening; a slot.\n[n.] The opening of the vagina.\n[n.] A woman, usually a sexually loose woman; a prostitute.\n[v.] To cut a narrow opening.\n[v.] To split into strips by lengthwise cuts.\n[v.] To cut; to sever; to divide.","ex":"He slit the bag open and the rice began pouring out."},"SLIPS":{"p":"/slɪps/","s":"n./v.","e":"[n.] A thin, slippery mix of clay and water.\n[n.] Mud, slime.\n[n.] A twig or shoot; a cutting.\n[n.] A descendant, a scion.\n[n.] A young person (now usually with of introducing descriptive qualifier).\n[n.] An act or instance of slipping.","ex":"She couldn't hurt a fly, young slip of a girl that she is."},"SLIMS":{"p":"","s":"n./v.","e":"[n.] A type of cigarette substantially longer and thinner than normal cigarettes.\n[n.] A potato farl.\n[n.] AIDS, or the chronic wasting associated with its later stages.\n[v.] To lose weight in order to achieve slimness.\n[v.] To make slimmer; to reduce in size.","ex":"I only smoke slims."},"SLOPE":{"p":"/sləʊp/","s":"n./v./adj./adv.","e":"[n.] An area of ground that tends evenly upward or downward.\n[n.] The degree to which a surface tends upward or downward.\n[n.] The ratio of the vertical and horizontal distances between two points on a line; zero if the line is horizontal, undefined if it is vertical.\n[v.] To tend steadily upward or downward.\n[v.] To form with a slope; to give an oblique or slanting direction to; to incline or slant.\n[v.] (usually followed by a preposition) To try to move surreptitiously.","ex":"I had to climb a small slope to get to the site."},"SLOW":{"p":"/sləʊ/","s":"n./v./adj./adv.","e":"[n.] Someone who is slow; a sluggard.\n[n.] A slow song.\n[v.] To make (something) run, move, etc. less quickly; to reduce the speed of.\n[v.] To keep from going quickly; to hinder the progress of.\n[v.] To become slow; to slacken in speed; to decelerate.\n[adj.] Taking a long time to move or go a short distance, or to perform an action; not quick in motion; proceeding at a low speed.","ex":"a slow train;  a slow computer"},"SLOES":{"p":"","s":"n.","e":"[n.] The small, bitter, wild fruit of the blackthorn (Prunus spinosa).\n[n.] The tree Prunus spinosa.\n[n.] Any of various other plants of the genus Prunus, as a shrub or small tree, Prunus alleghaniensis, bearing dark-purple fruit.","ex":""},"SLYER":{"p":"","s":"adj.","e":"[adj.] Artfully cunning; secretly mischievous; wily.\n[adj.] (having a positive sense) Dexterous in performing an action, so as to escape notice\n[adj.] Done with, and marked by, artful and dexterous secrecy; subtle","ex":"a sly trick"},"SLUNG":{"p":"/ˈslʌŋ/","s":"v.","e":"[v.] To throw with a circular or arcing motion.\n[v.] To throw with a sling.\n[v.] To pass a rope around (a cask, gun, etc.) preparatory to attaching a hoisting or lowering tackle.","ex":""},"SLOPS":{"p":"","s":"n.","e":"[n.] A loose outer garment; a jacket or overall.\n[n.] (chiefly in the plural) A rubber thong sandal.\n[n.] (in the plural) See slops.\n[n.] Liquid or semi-solid; goo, paste, mud.\n[n.] (sometimes in the plural) Scraps used as food for animals, especially pigs or hogs.\n[n.] (chiefly in the plural) Inferior, weak drink or liquid food.","ex":""},"SLURP":{"p":"/slɝp/","s":"n./v.","e":"[n.] A loud sucking noise made in eating or drinking\n[n.] A mouthful of liquid\n[v.] To eat or drink noisily.\n[v.] To make a loud sucking noise.","ex":"They sat in the kitchen slurping their spaghetti."},"SLEWS":{"p":"","s":"v.","e":"[v.] To rotate or turn something about its axis.\n[v.] To veer a vehicle.\n[v.] To insert extra ticks or skip some ticks of a clock to slowly correct its time.","ex":""},"SLYLY":{"p":"/ˈslaɪli/","s":"adv.","e":"[adv.] In a sly manner, cunningly.","ex":""},"SMALL":{"p":"/smoːl/","s":"n./v./adj./adv.","e":"[n.] Any part of something that is smaller or slimmer than the rest, now usually with anatomical reference to the back.\n[v.] To make little or less.\n[v.] To become small; to dwindle.\n[adj.] Not large or big; insignificant; few in number.\n[adj.] Young, as a child.\n[adj.] (writing, incomparable) Minuscule or lowercase, referring to written or printed letters.","ex":"A small group."},"SMASH":{"p":"/smæʃ/","s":"n./v.","e":"[n.] The sound of a violent impact; a violent striking together.\n[n.] A traffic collision.\n[n.] Something very successful or popular (as music, food, fashion, etc); a hit.\n[v.] To break (something brittle) violently.\n[v.] To be destroyed by being smashed.\n[v.] To hit extremely hard.","ex":"I could hear the screech of the brakes, then the horrible smash of cars colliding."},"SMEAR":{"p":"/smɪə/","s":"n./v.","e":"[n.] A mark made by smearing.\n[n.] Any of various forms of distortion that make a signal harder to see or hear.\n[n.] A Pap smear.\n[v.] To spread (a substance, especially one that colours or is dirty) across a surface by rubbing.\n[v.] To have a substance smeared on (a surface).\n[v.] To damage someone's reputation by slandering, misrepresenting, or otherwise making false accusations about an individual, their statements, or their actions.","ex":"This detergent cleans windows without leaving smears."},"SMILE":{"p":"/ˈsmaɪ.əl/","s":"n./v.","e":"[n.] A facial expression comprised by flexing the muscles of both ends of one's mouth, often showing the front teeth, without vocalisation, and in humans is a common involuntary or voluntary expression of happiness, pleasure, amusement or anxiety.\n[n.] Favour; propitious regard.\n[n.] A drink bought by one person for another.\n[v.] To have (a smile) on one's face.\n[v.] To express by smiling.\n[v.] To express amusement, pleasure, or love and kindness.","ex":"He always puts a smile on my face."},"SLOSH":{"p":"","s":"n./v.","e":"[n.] A quantity of a liquid; more than a splash.\n[n.] A sloshing sound or motion.\n[n.] Slush.\n[v.] (of a liquid) To shift chaotically; to splash noisily.\n[v.] (of a liquid) To cause to slosh\n[v.] To make a sloshing sound.","ex":"We added a slosh of white wine to the sauce."},"SMOCK":{"p":"/smɒk/","s":"n./v./adj.","e":"[n.] A type of undergarment worn by women; a shift or slip.\n[n.] A blouse; a smock frock.\n[n.] A loose garment worn as protection by a painter, etc.\n[v.] To provide with, or clothe in, a smock or a smock frock.\n[v.] To apply smocking.\n[adj.] Of or pertaining to a smock; resembling a smock","ex":""},"SMOGS":{"p":"","s":"n./v.","e":"[n.] A noxious mixture of particulates and gases that is the result of urban air pollution.\n[v.] To get a smog check; to check a vehicle or have it checked for emissions.","ex":"If the car is more than five years old, you'll have to have it smogged before you can register it."},"SMOKE":{"p":"/sməʊk/","s":"n./adj.","e":"[n.] The visible vapor/vapour, gases, and fine particles given off by burning or smoldering material.\n[n.] A cigarette.\n[n.] Anything to smoke (e.g. cigarettes, marijuana, etc.)\n[adj.] Of the colour known as smoke.\n[adj.] Made of or with smoke.","ex":"Can I bum a smoke off you?;  I need to go buy some smokes."},"SMACK":{"p":"/smæk/","s":"n./v.","e":"[n.] A distinct flavor, especially if slight.\n[n.] A slight trace of something; a smattering.\n[n.] Heroin.\n[v.] To get the flavor of.\n[v.] To indicate or suggest something; used with of.\n[v.] To have a particular taste; used with of.","ex":"rice pudding with a smack of cinnamon"},"SMUTS":{"p":"","s":"n.","e":"[n.] Soot.\n[n.] A flake of ash or soot.\n[n.] Sexually vulgar material; something that is sexual in a dirty way; pornographic material.","ex":""},"SMITH":{"p":"/smɪθ/","s":"n.","e":"[n.] A craftsperson who works metal into desired forms using a hammer and other tools, sometimes heating the metal to make it more workable, especially a blacksmith.\n[n.] (by extension) One who makes anything; wright.\n[n.] An artist.","ex":""},"SMITE":{"p":"/smaɪt/","s":"v.","e":"[v.] To hit, to strike.\n[v.] To strike down or kill with godly force.\n[v.] To injure with divine power.","ex":""},"SNAPS":{"p":"","s":"n./v.","e":"[n.] A quick breaking or cracking sound or the action of producing such a sound.\n[n.] A sudden break.\n[n.] An attempt to seize, bite, attack, or grab.\n[v.] To fracture or break apart suddenly.\n[v.] To give forth or produce a sharp cracking noise; to crack.\n[v.] To attempt to seize with the teeth or bite.","ex":"He snapped his stick in anger."},"SNARL":{"p":"/ˈsnɑː(ɹ)l/","s":"n./v.","e":"[n.] A knot or complication of hair, thread, or the like, difficult to disentangle.\n[n.] An intricate complication; a problematic difficulty; a knotty or tangled situation.\n[n.] A slow-moving traffic jam.\n[v.] To entangle; to complicate; to involve in knots.\n[v.] To become entangled.\n[v.] To place in an embarrassing situation; to ensnare; to make overly complicated.","ex":"to snarl a skein of thread"},"SNARE":{"p":"/snɛə/","s":"n./v.","e":"[n.] A trap (especially one made from a loop of wire, string, or leather).\n[n.] A mental or psychological trap.\n[n.] A loop of cord used in obstetric cases, to hold or to pull a fetus from the mother animal.\n[v.] To catch or hold, especially with a loop.\n[v.] To ensnare.","ex":""},"SMOOTH":{"p":"/smuːð/","s":"n./v./adj./adv.","e":"[n.] Something that is smooth, or that goes smoothly and easily.\n[n.] A smoothing action.\n[n.] A domestic animal having a smooth coat.\n[v.] To make smooth or even.\n[v.] To make straightforward or easy.\n[v.] To calm or palliate.","ex":"to smooth a person's temper"},"SNEER":{"p":"/snɪə̯/","s":"n./v.","e":"[n.] A facial expression where one slightly raises one corner of the upper lip, generally indicating scorn.\n[n.] A display of contempt; scorn.\n[v.] To raise a corner of the upper lip slightly, especially in scorn\n[v.] To utter with a grimace or contemptuous expression; to say sneeringly.","ex":"\"Now here's someone who should attend privilege workshops,\" sneered she."},"SNACK":{"p":"/snæk/","s":"n./v.","e":"[n.] A light meal.\n[n.] An item of food eaten between meals.\n[n.] A very sexy and attractive person.\n[v.] To eat a light meal.\n[v.] To eat between meals.","ex":""},"SNOTS":{"p":"","s":"n.","e":"[n.] Mucus, especially mucus from the nose.\n[n.] A contemptible child.\n[n.] A mean fellow.","ex":""},"SNOOK":{"p":"/snuːk/","s":"n./v.","e":"[n.] A freshwater and marine fish of the family Centropomidae in the order Perciformes.\n[n.] Any of various other ray-finned fishes in several families.\n[v.] To fish for snook.","ex":""},"SNUFF":{"p":"/snʌf/","s":"n./v.","e":"[n.] Finely ground or pulverized tobacco intended for use by being sniffed or snorted into the nose.\n[n.] Fine-ground or minced tobacco, dry or moistened, intended for use by placing a pinch behind the lip or beneath the tongue; see also snus.\n[n.] A snort or sniff of fine-ground, powdered, or pulverized tobacco.\n[v.] To inhale through the nose.\n[v.] To turn up the nose and inhale air, as an expression of contempt; hence, to take offence.","ex":""},"SNOWY":{"p":"/snəʊi/","s":"adj./n.","e":"[adj.] Marked by snow, characterized by snow.\n[adj.] Covered with snow, snow-covered, besnowed.\n[adj.] Snow-white in color, white as snow.\n[n.] A large, white, nomadic Arctic owl, Bubo scandiacus.","ex":"snowy day"},"SNAGS":{"p":"","s":"n./v.","e":"[n.] A stump or base of a branch that has been lopped off; a short branch, or a sharp or rough branch.\n[n.] A dead tree that remains standing.\n[n.] A tree, or a branch of a tree, fixed in the bottom of a river or other navigable water, and rising nearly or quite to the surface, by which boats are sometimes pierced and sunk.\n[v.] To catch or tear (e.g. fabric) upon a rough surface or projection.\n[v.] To damage or sink (a vessel) by collision; said of a tree or branch fixed to the bottom of a navigable body of water and partially submerged or rising to just beneath the surface.\n[v.] To fish by means of dragging a large hook or hooks on a line, intending to impale the body (rather than the mouth) of the target.","ex":"Be careful not to snag your stockings on that concrete bench!"},"SMART":{"p":"/smɑːt/","s":"v.","e":"[v.] To hurt or sting.\n[v.] To cause a smart or sting in.\n[v.] To feel a pungent pain of mind; to feel sharp pain or grief; be punished severely; to feel the sting of evil.","ex":"After being hit with a pitch, the batter exclaimed \"Ouch, my arm smarts!\""},"SOAKS":{"p":"","s":"n./v.","e":"[n.] An immersion in water etc.\n[n.] A drunkard.\n[n.] A carouse; a drinking session.\n[v.] To be saturated with liquid by being immersed in it.\n[v.] To immerse in liquid to the point of saturation or thorough permeation.\n[v.] To penetrate or permeate by saturation.","ex":"After the strenuous climb, I had a nice long soak in a bath."},"SNUGS":{"p":"","s":"n./v.","e":"[n.] A small, comfortable back room in a pub.\n[n.] A lug.\n[v.] To make secure or snug.\n[v.] To snuggle or nestle.\n[v.] To make smooth.","ex":""},"SOAPS":{"p":"","s":"n./v.","e":"[n.] A substance able to mix with both oil and water, used for cleaning, often in the form of a solid bar or in liquid form, derived from fats or made synthetically.\n[n.] A metallic salt derived from a fatty acid\n[n.] Flattery or excessively complacent conversation.\n[v.] To apply soap to in washing.\n[v.] To cover, lather or in any other form treat with soap, often as a prank.\n[v.] To be discreet about (a topic).","ex":"I tried washing my hands with soap, but the stain wouldn't go away."},"SNEAK":{"p":"/sniːk/","s":"n./v./adj.","e":"[n.] One who sneaks; one who moves stealthily to acquire an item or information.\n[n.] A cheat; a con artist.\n[n.] An informer; a tell-tale.\n[v.] To creep or go stealthily; to come or go while trying to avoid detection, as a person who does not wish to be seen.\n[v.] To take something stealthily without permission.\n[v.] (ditransitive) To stealthily bring someone something.","ex":"My little brother is such a sneak; yesterday I caught him trying to look through my diary."},"SOAPY":{"p":"/ˈsəʊpi/","s":"adj.","e":"[adj.] Resembling soap.\n[adj.] Resembling a soap opera.\n[adj.] Full of soap.","ex":"a soapy taste"},"SNOOD":{"p":"/snuːd/","s":"n./v.","e":"[n.] A band or ribbon for keeping the hair in place, including the hair-band formerly worn in Scotland and northern England by young unmarried women.\n[n.] A small hairnet or cap worn by women to keep their hair in place.\n[n.] The flap of erectile red skin on the beak of a male turkey.\n[v.] To keep the hair in place with a snood.","ex":""},"SOBER":{"p":"/ˈsəʊ.bə(ɹ)/","s":"v./adj.","e":"[v.] (often with up) To make or become sober.\n[v.] (often with up) To overcome or lose a state of intoxication.\n[v.] To moderate one's feelings\n[adj.] Not drunk; not intoxicated\n[adj.] Not given to excessive drinking of alcohol\n[adj.] Moderate; realistic; serious; not playful; not passionate; cool; self-controlled","ex":"It took him hours to sober up."},"SOCIETY":{"p":"/səˈsaɪ.ə.ti/","s":"n.","e":"[n.] A long-standing group of people sharing cultural aspects such as language, dress, norms of behavior and artistic forms.\n[n.] A group of people who meet from time to time to engage in a common interest; an association or organization.\n[n.] The sum total of all voluntary interrelations between individuals.","ex":"This society has been known for centuries for its colorful clothing and tight-knit family structure."},"SOCCER":{"p":"/ˈsɒk.ə/","s":"n./v.","e":"[n.] Association football\n[v.] To kick the football directly off the ground, without using one's hands.","ex":""},"SOFAS":{"p":"","s":"n./v.","e":"[n.] A raised area of a building's floor, usually covered with carpeting, used for sitting.\n[n.] (furniture) An upholstered seat with a raised back and one or two raised ends, long enough to comfortably accommodate two or more people.\n[v.] To furnish with one or more sofas.\n[v.] To seat or lay down on a sofa.","ex":""},"SOGGY":{"p":"/ˈsɒɡi/","s":"adj.","e":"[adj.] Soaked with moisture or other liquid.","ex":""},"SOLD":{"p":"/ˈsəʊld/","s":"v.","e":"[v.] (ditransitive) To transfer goods or provide services in exchange for money.\n[v.] To be sold.\n[v.] To promote a product or service.","ex":"I'll sell you all three for a hundred dollars."},"SOLDIER":{"p":"/ˈsɒld͡ʒə/","s":"n./v.","e":"[n.] A member of an army, of any rank.\n[n.] A private in military service, as distinguished from an officer.\n[n.] A guardsman.\n[v.] To continue steadfast; to keep striving.\n[v.] To serve as a soldier.\n[v.] To intentionally restrict labor productivity; to work at the slowest rate that goes unpunished.","ex":""},"SOLE":{"p":"/səʊl/","s":"n.","e":"[n.] A wooden band or yoke put around the neck of an ox or cow in the stall.","ex":""},"SONAR":{"p":"","s":"n.","e":"[n.] Echolocation\n[n.] A device that uses hydrophones (in the same manner as radar) to locate objects underwater.","ex":""},"SONGS":{"p":"/sɔŋz/","s":"n.","e":"[n.] A musical composition with lyrics for voice or voices, performed by singing.\n[n.] (by extension) Any musical composition.\n[n.] Poetical composition; poetry; verse.","ex":"Thomas listened to his favorite song on the radio yesterday."},"SOLID":{"p":"/ˈsɒlɪd/","s":"n./adj./adv.","e":"[n.] A substance in the fundamental state of matter that retains its size and shape without need of a container (as opposed to a liquid or gas).\n[n.] A three-dimensional figure (as opposed to a surface, an area, or a curve).\n[n.] A favor.\n[adj.] (of an object or substance) That can be picked up or held, having a texture, and usually firm. Unlike a liquid or a gas.\n[adj.] Large in size, quantity, or value.\n[adj.] Lacking holes, hollows or admixtures of other materials.","ex":"I owe him; he did me a solid last year."},"SORES":{"p":"","s":"n.","e":"[n.] An injured, infected, inflamed or diseased patch of skin.\n[n.] Grief; affliction; trouble; difficulty.\n[n.] A group of ducks on land.\n[n.] A young hawk or falcon in its first year.\n[n.] A young buck in its fourth year.","ex":"They put ointment and a bandage on the sore."},"SODAS":{"p":"","s":"n.","e":"[n.] Sodium bicarbonate (usually baking soda).\n[n.] Sodium carbonate (usually washing soda).\n[n.] Sodium in chemical combination.","ex":""},"SOUL":{"p":"/səʊl/","s":"n./v.","e":"[n.] The spirit or essence of a person usually thought to consist of one's thoughts and personality. Often believed to live on after the person's death.\n[n.] The spirit or essence of anything.\n[n.] Life, energy, vigor.\n[v.] To endow with a soul; to furnish with a soul or mind.\n[v.] To beg on All Soul's Day.","ex":""},"SOUND":{"p":"/saʊnd/","s":"adj./adv./int.","e":"[adj.] Healthy.\n[adj.] Complete, solid, or secure.\n[adj.] Having the property of soundness.\n[adv.] Soundly.\n[int.] Yes; used to show agreement or understanding, generally without much enthusiasm.","ex":"He was safe and sound."},"SOUPY":{"p":"/ˈsupi/","s":"adj.","e":"[adj.] Resembling soup; creamy.\n[adj.] Extravagant sentimental; slushy.","ex":""},"SOURCE":{"p":"/sɔːs/","s":"n./v.","e":"[n.] The person, place or thing from which something (information, goods, etc.) comes or is acquired.\n[n.] Spring; fountainhead; wellhead; any collection of water on or under the surface of the ground in which a stream originates.\n[n.] A reporter's informant.\n[v.] To obtain or procure: used especially of a business resource.\n[v.] To find information about (a quotation)'s source (from which it comes): to find a citation for.","ex":"The accused refused to reveal the source of the illegal drugs she was selling."},"SNUBS":{"p":"","s":"n./v.","e":"[n.] A deliberate affront or slight.\n[n.] A sudden checking of a cable or rope.\n[n.] A knot; a protuberance; a snag.\n[v.] To slight, ignore or behave coldly toward someone.\n[v.] To turn down; to dismiss.\n[v.] To check; to reprimand.","ex":"I hope the people we couldn't invite don't see it as a snub."},"SOUSE":{"p":"/saʊs/","s":"n./v.","e":"[n.] Something kept or steeped in brine\n[n.] The act of sousing; a plunging into water.\n[n.] A person suffering from alcoholism.\n[v.] To immerse in liquid; to steep or drench.\n[v.] To steep in brine; to pickle.","ex":""},"SPAKE":{"p":"/speɪk/","s":"adj.","e":"[adj.] Quiet; tame.\n[adj.] Ready; prompt.","ex":""},"SPAWN":{"p":"/ˈspɔːn/","s":"v.","e":"[v.] To produce or deposit (eggs) in water.\n[v.] To generate, bring into being, especially non-mammalian beings in very large numbers.\n[v.] To bring forth in general.","ex":"The Web server spawns a new process to handle each client's request."},"SOOTY":{"p":"/ˈsʊti/","s":"v./adj.","e":"[v.] To blacken or make dirty with soot.\n[adj.] Of, relating to, or producing soot.\n[adj.] Soiled with soot\n[adj.] Of the color of soot.","ex":""},"SPANS":{"p":"","s":"n./v.","e":"[n.] The space from the thumb to the end of the little finger when extended; nine inches; an eighth of a fathom.\n[n.] (by extension) A small space or a brief portion of time.\n[n.] A portion of something by length; a subsequence.\n[v.] To extend through the distance between or across.\n[v.] To extend through (a time period).\n[v.] To measure by the span of the hand with the fingers extended, or with the fingers encompassing the object.","ex":"He has a short attention span and gets bored within minutes."},"SOWED":{"p":"/səʊd/","s":"v.","e":"[v.] To scatter, disperse, or plant (seeds).\n[v.] To spread abroad; to propagate.\n[v.] To scatter over; to besprinkle.","ex":"As you sow, so shall you reap."},"SPEAKER":{"p":"/ˈspiːkə/","s":"n.","e":"[n.] One who speaks.\n[n.] Loudspeaker.\n[n.] Speakerphone.","ex":""},"SPECK":{"p":"/spɛk/","s":"n./v.","e":"[n.] A tiny spot, especially of dirt etc.\n[n.] A very small thing; a particle; a whit.\n[n.] A small etheostomoid fish, Etheostoma stigmaeum, common in the eastern United States.\n[v.] To mark with specks; to speckle.","ex":"a tiny speck of soot"},"SPEED":{"p":"/spiːd/","s":"n.","e":"[n.] The state of moving quickly or the capacity for rapid motion; rapidity.\n[n.] The rate of motion or action, specifically / the magnitude of the velocity; the rate distance is traversed in a given time.\n[n.] The sensitivity to light of film, plates or sensor.","ex":"How does Usain Bolt run at that speed?"},"SPAN":{"p":"/spæn/","s":"n.","e":"[n.] The space from the thumb to the end of the little finger when extended; nine inches; an eighth of a fathom.\n[n.] (by extension) A small space or a brief portion of time.\n[n.] A portion of something by length; a subsequence.","ex":"He has a short attention span and gets bored within minutes."},"SPENT":{"p":"/ˈspɛnt/","s":"v./adj.","e":"[v.] To pay out (money).\n[v.] To bestow; to employ; often with on or upon.\n[v.] To squander.\n[adj.] Consumed, used up, exhausted, depleted.\n[adj.] Of fish: exhausted as a result of having spawned.","ex":"He spends far more on gambling than he does on living proper."},"SPIKY":{"p":"/ˈspaɪ.ki/","s":"adj.","e":"[adj.] Having spikes, spiny.\n[adj.] Hostile; standoffish\n[adj.] Of hair, erect, resembling spikes.","ex":"a spiky personality"},"SPIEL":{"p":"/spiːl/","s":"n./v.","e":"[n.] A lengthy and extravagant speech or argument usually intended to persuade.\n[n.] An early form of rap music.\n[v.] To talk at length.\n[v.] To give a sales pitch; to promote by speaking.","ex":""},"SPILL":{"p":"/spɪl/","s":"n./v.","e":"[n.] A mess of something that has been dropped.\n[n.] A fall or stumble.\n[n.] A small stick or piece of paper used to light a candle, cigarette etc by the transfer of a flame from a fire.\n[v.] To drop something so that it spreads out or makes a mess; to accidentally pour.\n[v.] To spread out or fall out, as above.\n[v.] To drop something that was intended to be caught.","ex":"The bruise is from a bad spill he had last week."},"SPILT":{"p":"/spɪlt/","s":"v./adj.","e":"[v.] To drop something so that it spreads out or makes a mess; to accidentally pour.\n[v.] To spread out or fall out, as above.\n[v.] To drop something that was intended to be caught.\n[adj.] That has been spilt.","ex":"I spilled some sticky juice on the kitchen floor."},"SPINS":{"p":"/spɪnz/","s":"n./v.","e":"[n.] Rapid circular motion.\n[n.] A quantum angular momentum associated with subatomic particles, which also creates a magnetic moment.\n[n.] A favourable comment or interpretation intended to bias opinion on an otherwise unpleasant situation.\n[v.] To rotate, revolve, gyrate (usually quickly); to partially or completely rotate to face another direction.\n[v.] To make yarn by twisting and winding fibers together.\n[v.] To present, describe, or interpret, or to introduce a bias or slant, so as to give something a favorable or advantageous appearance.","ex":"He put some spin on the cue ball."},"SPINE":{"p":"/spaɪn/","s":"n.","e":"[n.] The series of bones situated at the back from the head to the pelvis of a person, or from the head to the tail of an animal; backbone, vertebral column.\n[n.] Something resembling a backbone, such as a ridge, or a long, central structure from which other structures radiate.\n[n.] A pointed, fairly rigid protuberance or needle-like structure on an animal, shell, or plant.","ex":""},"SPIED":{"p":"","s":"v.","e":"[v.] To act as a spy.\n[v.] To spot; to catch sight of.\n[v.] To search narrowly; to scrutinize.","ex":"During the Cold War, Russia and America would each spy on each other for recon."},"SPIRE":{"p":"/spaɪə/","s":"n./v.","e":"[n.] The stalk or stem of a plant.\n[n.] A young shoot of a plant; a spear.\n[n.] Any of various tall grasses, rushes, or sedges, such as the marram, the reed canary-grass, etc.\n[v.] (of a seed, plant etc.) to sprout, to send forth the early shoots of growth; to germinate.\n[v.] To grow upwards rather than develop horizontally.\n[v.] To furnish with a spire.","ex":""},"SPIRIT":{"p":"/ˈspɪɹɪt/","s":"n./v.","e":"[n.] The soul of a person or other creature. What moves through experience into self-definition as souls purpose.\n[n.] A supernatural being, often but not exclusively without physical form; ghost, fairy, angel.\n[n.] Enthusiasm.\n[v.] To carry off, especially in haste, secrecy, or mystery.\n[v.] To animate with vigor; to excite; to encourage; to inspirit; sometimes followed by up.","ex":"A wandering spirit haunts the island."},"SPERM":{"p":"/spɜːm/","s":"n./v.","e":"[n.] The reproductive cell or gamete of the male; a spermatozoon.\n[n.] Semen; the generative substance of male animals.\n[n.] Sperm oil; whale oil from a sperm whale; spermaceti.\n[v.] To ejaculate.\n[v.] To ejaculate on or into.","ex":""},"SPIN":{"p":"/spɪn/","s":"n./v.","e":"[n.] Rapid circular motion.\n[n.] A quantum angular momentum associated with subatomic particles, which also creates a magnetic moment.\n[n.] A favourable comment or interpretation intended to bias opinion on an otherwise unpleasant situation.\n[v.] To rotate, revolve, gyrate (usually quickly); to partially or completely rotate to face another direction.\n[v.] To make yarn by twisting and winding fibers together.\n[v.] To present, describe, or interpret, or to introduce a bias or slant, so as to give something a favorable or advantageous appearance.","ex":"He put some spin on the cue ball."},"SPLIT":{"p":"/splɪt/","s":"n./v./adj.","e":"[n.] A crack or longitudinal fissure.\n[n.] A breach or separation, as in a political party; a division.\n[n.] A piece that is split off, or made thin, by splitting; a splinter; a fragment.\n[v.] Of something solid, to divide fully or partly along a more or less straight line.\n[v.] Of something solid, particularly wood, to break along the grain fully or partly along a more or less straight line.\n[v.] To share; to divide.","ex":"He has split his lip."},"SPOIL":{"p":"/spɔɪl/","s":"n./v.","e":"[n.] (Also in plural: spoils) Plunder taken from an enemy or victim.\n[n.] Material (such as rock or earth) removed in the course of an excavation, or in mining or dredging. Tailings.\n[v.] To strip (someone who has been killed or defeated) of their arms or armour.\n[v.] To strip or deprive (someone) of their possessions; to rob, despoil.\n[v.] To plunder, pillage (a city, country etc.).","ex":""},"SPLAT":{"p":"/splæt/","s":"n.","e":"[n.] The narrow wooden centre piece of a chair back.","ex":""},"SPOKE":{"p":"/spəʊk/","s":"n./v.","e":"[n.] A support structure that connects the axle or the hub of a wheel to the rim.\n[n.] A projecting handle of a steering wheel.\n[n.] A rung of a ladder.\n[v.] To furnish (a wheel) with spokes.","ex":""},"SPONSOR":{"p":"/ˈspɒn.sə/","s":"n./v.","e":"[n.] A person or organisation with some sort of responsibility for another person or organisation, especially where the responsibility has a religious, legal, or financial aspect.\n[n.] One that pays all or part of the cost of an event, a publication, or a media program, usually in exchange for advertising time.\n[v.] To be a sponsor for.","ex":"He was my sponsor when I applied to join the club."},"SPOOK":{"p":"/spuːk/","s":"n./v.","e":"[n.] A ghost or phantom.\n[n.] A hobgoblin.\n[n.] A scare or fright.\n[v.] To frighten or make nervous (especially by startling).\n[v.] To become frightened (by something startling).\n[v.] To haunt.","ex":"The building was haunted by a couple of spooks."},"SPOOL":{"p":"/spuːl/","s":"n./v.","e":"[n.] A reel; a device around which thread, wire or cable is wound, especially a cylinder or spindle.\n[n.] A temporary storage area for electronic mail, etc.\n[v.] To wind on a spool or spools.\n[v.] To send files to a device or a program (a spooler or a daemon that puts them in a queue for processing at a later time).","ex":""},"SPORE":{"p":"/spɔː/","s":"n./v.","e":"[n.] A reproductive particle, usually a single cell, released by a fungus, alga, or plant that may germinate into another.\n[n.] A thick resistant particle produced by a bacterium or protist to survive in harsh or unfavorable conditions.\n[v.] To produce spores.","ex":""},"SPITE":{"p":"/spaɪt/","s":"n./v.","e":"[n.] Ill will or hatred toward another, accompanied with the desire to irritate, annoy, or thwart; a want to disturb or put out another; mild malice\n[n.] Vexation; chagrin; mortification.\n[v.] To treat maliciously; to try to injure or thwart.\n[v.] To be angry at; to hate.\n[v.] To fill with spite; to offend; to vex.","ex":"He was so filled with spite for his ex-wife, he could not hold down a job."},"SPOOR":{"p":"/spʊə/","s":"n./v.","e":"[n.] The track, trail, droppings or scent of an animal\n[v.] To track an animal by following its spoor","ex":""},"SPOON":{"p":"/spuːn/","s":"n./v.","e":"[n.] An implement for eating or serving; a scooped utensil whose long handle is straight, in contrast to a ladle.\n[n.] An implement for stirring food while being prepared; a wooden spoon.\n[n.] A measure that will fit into a spoon; a spoonful.\n[v.] To serve using a spoon; to transfer (something) with a spoon.\n[v.] To flirt; to make advances; to court, to interact romantically or amorously.\n[v.] (of persons) To lie nestled front-to-back, following the contours of the bodies, in a manner reminiscent of stacked spoons.","ex":"Sarah spooned some apple sauce onto her plate."},"SPIFF":{"p":"","s":"n./v.","e":"[n.] Attractiveness or charm in dress, appearance, or manner.\n[n.] A well-dressed man.\n[n.] A bonus or other remuneration, given for reaching a sales goal or promoting the goods of a particular manufacturer. Originally from textile retailing, a percentage given for selling off surplus or out-of-fashion stock, of which the sales person could offer part as a discount to a customer.\n[v.] (usually with up or out) To make spiffy (attractive, polished, or up-to-date)\n[v.] To reward (a salesperson) with a spiff or bonus.\n[v.] To attach a spiff or bonus to the selling of (a product)","ex":"Without a diploma, he relies on spiff alone to climb the corporate ladder."},"SPORT":{"p":"/spɔːt/","s":"n./v.","e":"[n.] Any activity that uses physical exertion or skills competitively under a set of rules that is not based on aesthetics.\n[n.] Something done for fun, regardless of its design or intended purpose.\n[n.] A person who exhibits either good or bad sportsmanship.\n[v.] To amuse oneself, to play.\n[v.] To mock or tease, treat lightly, toy with.\n[v.] To display; to have as a notable feature.","ex":"Joe was banned from getting legal help. He seemed to view lawsuits as a sport."},"SPREE":{"p":"/spɹiː/","s":"n./v.","e":"[n.] A merry frolic; especially, a drinking frolic.\n[n.] Uninhibited activity.\n[v.] To engage in a spree.","ex":""},"SPRIG":{"p":"/spɹɪɡ/","s":"n./v.","e":"[n.] A small shoot or twig of a tree or other plant; a spray.\n[n.] An ornament resembling a small shoot or twig.\n[n.] One of the separate pieces of lace fastened on a ground in applique lace.\n[v.] To decorate with sprigs, or with representations of sprigs, as in embroidery or pottery.","ex":"a sprig of laurel or of parsley"},"SPOT":{"p":"/spɒt/","s":"n./v./adj.","e":"[n.] A round or irregular patch on the surface of a thing having a different color, texture etc. and generally round in shape.\n[n.] A stain or disfiguring mark.\n[n.] A pimple, papule or pustule.\n[v.] To see, find; to pick out, notice, locate, distinguish or identify.\n[v.] To loan a small amount of money to someone.\n[v.] To stain; to leave a spot (on).","ex":"The leopard is noted for the spots of color in its fur."},"SPRING":{"p":"/spɹɪŋ/","s":"v./n.","e":"[v.] To weaken, as a joint, ligament, or muscle, by sudden and excessive exertion, as by wrenching; to overstrain, or stretch injuriously, but without luxation\n[n.] An act of springing: a leap, a jump.\n[n.] The season of the year in temperate regions in which plants spring from the ground and into bloom and dormant animals spring to life, variously reckoned as\n[n.] The time of something's growth; the early stages of some process.\n[v.] To burst forth.\n[v.] (of beards) To grow.","ex":"to sprain one's ankle"},"SPOTS":{"p":"/spɒts/","s":"n./v.","e":"[n.] A round or irregular patch on the surface of a thing having a different color, texture etc. and generally round in shape.\n[n.] A stain or disfiguring mark.\n[n.] A pimple, papule or pustule.\n[v.] To see, find; to pick out, notice, locate, distinguish or identify.\n[v.] To loan a small amount of money to someone.\n[v.] To stain; to leave a spot (on).","ex":"The leopard is noted for the spots of color in its fur."},"SPOTTER":{"p":"/ˈspɒt.ə/","s":"n.","e":"[n.] A person who observes something.\n[n.] A member of a sniper team who in addition to this function is responsible for providing additional information about targets from a different point of view.\n[n.] One who supervises a person performing an activity, in order to help them should they be unable to complete it.","ex":""},"SPUME":{"p":"/spjum/","s":"n./v.","e":"[n.] Foam or froth of liquid, particularly that of seawater.\n[v.] To froth.","ex":""},"SPRAT":{"p":"/spɹæt/","s":"n.","e":"[n.] Any of various small, herring-like, marine fish in the genus Sprattus, in the family Clupeidae.","ex":""},"SPREAD":{"p":"/spɹɛd/","s":"n./v.","e":"[n.] The act of spreading.\n[n.] Something that has been spread.\n[n.] A layout, pattern or design of cards arranged for a reading.\n[v.] To stretch out, open out (a material etc.) so that it more fully covers a given area of space.\n[v.] To extend (individual rays, limbs etc.); to stretch out in varying or opposing directions.\n[v.] To disperse, to scatter or distribute over a given area.","ex":"He spread his newspaper on the table."},"SPOUT":{"p":"/spaʊt/","s":"n./v.","e":"[n.] A tube or lip through which liquid or steam is poured or discharged.\n[n.] A stream of liquid.\n[n.] The mixture of air and water thrown up from the blowhole of a whale.\n[v.] To gush forth in a jet or stream\n[v.] To eject water or liquid in a jet.\n[v.] To speak tediously or pompously.","ex":"I dropped my china teapot, and its spout broke."},"SPRAY":{"p":"/spɹeɪ/","s":"n./v.","e":"[n.] A fine, gentle, dispersed mist of liquid.\n[n.] A pressurized container; an atomizer.\n[n.] Any of numerous commercial products, including paints, cosmetics, and insecticides, that are dispensed from containers in this manner.\n[v.] To project a liquid in a dispersive manner toward something.\n[v.] To project in a dispersive manner.\n[v.] To project many small items dispersively.","ex":"The sailor could feel the spray from the waves."},"SPUDS":{"p":"","s":"n.","e":"[n.] A potato.\n[n.] A hole in a sock.\n[n.] A type of short nut (fastener) threaded on both ends.","ex":""},"SPURS":{"p":"","s":"v./n.","e":"[v.] To ask, to inquire\n[n.] A rigid implement, often roughly y-shaped, that is fixed to one's heel for the purpose of prodding a horse. Often worn by, and emblematic of, the cowboy or the knight.\n[n.] A jab given with the spurs.\n[n.] Anything that inspires or motivates, as a spur does a horse.\n[v.] To prod (especially a horse) on the side or flank, with the intent to urge motion or haste, to gig.\n[v.] To urge or encourage to action, or to a more vigorous pursuit of an object","ex":"to spur boots"},"SPUNK":{"p":"/spʌŋk/","s":"n./v.","e":"[n.] A spark.\n[n.] Touchwood; tinder.\n[n.] A piece of tinder, sometimes impregnated with sulphur; a match.\n[v.] To catch fire; flame up.\n[v.] To ejaculate.","ex":"He spunked into the condom."},"SPURT":{"p":"/spɜː(r)t/","s":"n./v.","e":"[n.] A brief gush, as of liquid spurting from an orifice or a cut/wound.\n[n.] Ejaculation of semen.\n[n.] A shoot; a bud.\n[v.] To cause to gush out suddenly or violently in a stream or jet.\n[v.] To rush from a confined place in a small stream or jet.","ex":"a spurt of water; a spurt of blood"},"SQUAT":{"p":"/skwɒt/","s":"n./v./adj.","e":"[n.] Nothing; nothing whatsoever.\n[n.] A position assumed by bending deeply at the knees while resting on one's feet.\n[n.] (exercise) Any of various modes of callisthenic exercises performed by moving the body and bending at least one knee.\n[n.] A building occupied without permission, as practiced by a squatter.\n[v.] To bend deeply at the knees while resting on one's feet.\n[v.] (exercise) To perform one or more callisthenic exercises by moving the body and bending at least one knee.","ex":""},"SQUAD":{"p":"/ˈskwɒd/","s":"n./v.","e":"[n.] A group of people organized for some common purpose, usually of about ten members.\n[n.] One's friend group, taken collectively; one's peeps.\n[v.] To act as part of, or on behalf of, a squad.","ex":"We squad on the fifth of the month."},"SQUARE":{"p":"/skwɛə(ɹ)/","s":"n./v./adj.","e":"[n.] A polygon with four sides of equal length and four right angles; an equilateral rectangle; a regular quadrilateral.\n[n.] Something characterized by a square, or nearly square, form.\n[n.] An L- or T-shaped tool used to place objects or draw lines at right angles.\n[v.] To adjust so as to align with or place at a right angle to something else; in particular:\n[v.] To resolve or reconcile; to suit or fit.\n[v.] To adjust or adapt so as to bring into harmony with something.","ex":"The casting was mounted on a milling machine so that its sides could be squared."},"SQUID":{"p":"/skwɪd/","s":"n./v.","e":"[n.] Any of several carnivorous marine cephalopod mollusks, of the order Teuthida, having a mantle, eight arms, and a pair of tentacles\n[n.] A fishhook with a piece of bright lead, bone, or other substance fastened on its shank to imitate a squid.\n[n.] (mildly) A sailor in the Navy.\n[v.] To fish with the kind of hook called a squid.\n[v.] (parachuting) To cause squidding (an improper, partial, parachute inflation, that results in the sides of the parachute folding in on the center, and pulsating back and forth).","ex":""},"STABLE":{"p":"/ˈsteɪ.bəɫ/","s":"n./v.","e":"[n.] A building, wing or dependency set apart and adapted for lodging and feeding (and training) animals with hoofs, especially horses.\n[n.] (metonymy) All the racehorses of a particular stable, i.e. belonging to a given owner.\n[n.] A set of advocates; a barristers' chambers.\n[v.] To put or keep (an animal) in a stable.\n[v.] To dwell in a stable.\n[v.] To park (a rail vehicle).","ex":"There were stalls for fourteen horses in the squire's stables."},"STABS":{"p":"","s":"n./v.","e":"[n.] An act of stabbing or thrusting with an object.\n[n.] A wound made by stabbing.\n[n.] Pain inflicted on a person's feelings.\n[v.] To pierce or to wound (somebody) with a pointed tool or weapon, especially a knife or dagger.\n[v.] To thrust in a stabbing motion.\n[v.] To recklessly hit with the tip of a pointed object, such as a weapon or finger (often used with at).","ex":"If you stab him in the heart he won't live long enough to retaliate."},"STAFF":{"p":"/ˈstæf/","s":"n./v.","e":"[n.] (plural staffs or staves) A long, straight, thick wooden rod or stick, especially one used to assist in walking.\n[n.] (plural staves) A series of horizontal lines on which musical notes are written; a stave.\n[n.] (plural staff or staffs) The employees of a business.\n[v.] To supply (a business, volunteer organization, etc.) with employees or staff members.","ex":"The company employed 10 new members of staff this month."},"STAGE":{"p":"/steɪd͡ʒ/","s":"n./v.","e":"[n.] A phase.\n[n.] A platform; a surface, generally elevated, upon which show performances or other public events are given.\n[n.] A floor or storey of a house.\n[v.] To produce on a stage, to perform a play.\n[v.] To demonstrate in a deceptive manner.\n[v.] To orchestrate; to carry out.","ex":"Completion of an identifiable stage of maintenance such as removing an aircraft engine for repair or storage."},"STAGS":{"p":"","s":"n.","e":"[n.] An adult male deer.\n[n.] A colt, or filly.\n[n.] (by extension) A romping girl; a tomboy.","ex":""},"STAIR":{"p":"/stɛə/","s":"n.","e":"[n.] A single step in a staircase.\n[n.] A series of steps; a staircase.","ex":""},"STALK":{"p":"/stɔːk/","s":"n.","e":"[n.] The stem or main axis of a plant, which supports the seed-carrying parts.\n[n.] The petiole, pedicel, or peduncle of a plant.\n[n.] Something resembling the stalk of a plant, such as the stem of a quill.","ex":"a stalk of wheat, rye, or oats;  the stalks of maize or hemp"},"STAKE":{"p":"/steɪk/","s":"n./v.","e":"[n.] A piece of wood or other material, usually long and slender, pointed at one end so as to be easily driven into the ground as a marker or a support or stay.\n[n.] A piece of wood driven in the ground, placed in the middle of the court, that is used as the finishing point after scoring 12 hoops in croquet.\n[n.] A stick inserted upright in a lop, eye, or mortise, at the side or end of a cart, flat car, flatbed trailer, or the like, to prevent goods from falling off.\n[v.] To fasten, support, defend, or delineate with stakes.\n[v.] To pierce or wound with a stake.\n[v.] To put at risk upon success in competition, or upon a future contingency.","ex":"We have surveyor's stakes at all four corners of this field, to mark exactly its borders."},"SQUIB":{"p":"/skwɪb/","s":"n./v.","e":"[n.] A small firework that is intended to spew sparks rather than explode.\n[n.] A similar device used to ignite an explosive or launch a rocket, etc.\n[n.] A kind of slow match or safety fuse.\n[v.] To make a sound like a small explosion.\n[v.] To throw squibs; to utter sarcastic or severe reflections; to contend in petty dispute.","ex":"English Navy squibs set fire to two dozen enemy ships in a Dutch harbor during the 16th-century battle against the Spanish Armada."},"STACK":{"p":"/stæk/","s":"n./v.","e":"[n.] (heading) A pile.\n[n.] A smokestack.\n[n.] (heading) In computing.\n[v.] To arrange in a stack, or to add to an existing stack.\n[v.] To arrange the cards in a deck in a particular manner.\n[v.] To take all the money another player currently has on the table.","ex":"Please stack those chairs in the corner."},"STALL":{"p":"/stɔːl/","s":"n./v.","e":"[n.] A compartment for a single animal in a stable or cattle shed.\n[n.] A stable; a place for cattle.\n[n.] A bench or table on which small articles of merchandise are exposed for sale.\n[v.] To put (an animal, etc.) in a stall.\n[v.] To fatten.\n[v.] To come to a standstill.","ex":"to stall an ox"},"STALE":{"p":"/steɪl/","s":"n./v./adj.","e":"[n.] Something stale; a loaf of bread or the like that is no longer fresh.\n[v.] (of alcohol) To make stale; to age in order to clear and strengthen (a drink, especially beer).\n[v.] To make stale; to cause to go out of fashion or currency; to diminish the novelty or interest of, particularly by excessive exposure or consumption.\n[v.] To become stale; to grow odious from excessive exposure or consumption.\n[adj.] (alcohol) Clear, free of dregs and lees; old and strong.\n[adj.] No longer fresh, in reference to food, urine, straw, wounds, etc.","ex":""},"STAMP":{"p":"/stæmp/","s":"n./v.","e":"[n.] An act of stamping the foot, paw or hoof.\n[n.] An indentation, imprint, or mark made by stamping.\n[n.] A device for stamping designs.\n[v.] To step quickly and heavily, once or repeatedly.\n[v.] To move (the foot or feet) quickly and heavily, once or repeatedly.\n[v.] To strike, beat, or press forcibly with the bottom of the foot, or by thrusting the foot downward.","ex":"The horse gave two quick stamps and rose up on its hind legs."},"STAND":{"p":"/stænd/","s":"n./v.","e":"[n.] The act of standing.\n[n.] A defensive position or effort.\n[n.] A resolute, unwavering position; firm opinion; action for a purpose in the face of opposition.\n[v.] (heading) To position or be positioned physically.\n[v.] (heading) To position or be positioned mentally.\n[v.] (heading) To position or be positioned socially.","ex":"The Commander says we will make our stand here."},"STAPH":{"p":"","s":"n.","e":"[n.] Staphylococcus bacteria and the infection it causes.","ex":""},"STAIN":{"p":"/steɪn/","s":"n./v.","e":"[n.] A discoloured spot or area.\n[n.] A blemish on one's character or reputation.\n[n.] A substance used to soak into a surface and colour it.\n[v.] To discolour.\n[v.] To taint or tarnish someone's character or reputation\n[v.] To coat a surface with a stain","ex":"armour stained with blood"},"STAR":{"p":"/stɑː(ɹ)/","s":"n./v.","e":"[n.] Any small luminous dot appearing in the cloudless portion of the night sky, especially with a fixed location relative to other such dots.\n[n.] A luminous celestial body, made up of plasma (particularly hydrogen and helium) and having a spherical shape. Depending on context the sun may or may not be included.\n[n.] A concave polygon with regular, pointy protrusions and indentations, generally with five or six points.\n[v.] To appear as a featured performer or headliner, especially in an entertainment program.\n[v.] To feature (a performer or a headliner), especially in a movie or an entertainment program.\n[v.] To mark with a star or asterisk.","ex":""},"STAID":{"p":"/sted/","s":"adj.","e":"[adj.] Not capricious or impulsive; sedate, serious, sober.\n[adj.] Always fixed in the same location; stationary.","ex":""},"STARE":{"p":"/stɛə(ɹ)/","s":"n./v.","e":"[n.] A persistent gaze.\n[v.] (construed with at) To look fixedly (at something).\n[v.] To influence in some way by looking fixedly.\n[v.] To be very conspicuous on account of size, prominence, colour, or brilliancy.","ex":"the stares of astonished passers-by"},"STARK":{"p":"/stɑːk/","s":"adj./adv.","e":"[adj.] Hard, firm; obdurate.\n[adj.] Severe; violent; fierce (now usually in describing the weather).\n[adj.] Strong; vigorous; powerful.\n[adv.] Starkly; entirely, absolutely","ex":"He's gone stark, staring mad."},"START":{"p":"/stɑːt/","s":"n.","e":"[n.] The beginning of an activity.\n[n.] A sudden involuntary movement.\n[n.] The beginning point of a race, a board game, etc.","ex":"The movie was entertaining from start to finish."},"STARTUP":{"p":"/ˈstɑɹtˌʌp/","s":"n.","e":"[n.] The act or process of starting a process or machine.\n[n.] A new company or organization or business venture designed for rapid growth.","ex":""},"STASH":{"p":"/stæʃ/","s":"n./v.","e":"[n.] A collection, sometimes hidden; a reserve.\n[n.] A place where drugs are stored.\n[v.] To hide or store away for later use.","ex":"They had quite a stash of food saved up for emergencies."},"STARTED":{"p":"/ˈstɑːtɪd/","s":"v.","e":"[v.] To begin, commence, initiate.\n[v.] To begin an activity.\n[v.] To have its origin (at), begin.","ex":"The rain started at 9:00."},"STATE":{"p":"/steɪt/","s":"n./v./adj.","e":"[n.] A condition; a set of circumstances applying at any given time.\n[n.] High social standing or circumstance.\n[n.] A polity.\n[v.] To declare to be a fact.\n[v.] To make known.\n[adj.] Stately.","ex":"He stated that he was willing to help."},"STATION":{"p":"/ˈsteɪʃən/","s":"n./v.","e":"[n.] A stopping place.\n[n.] A place where workers are stationed.\n[n.] Any of the Stations of the Cross.\n[v.] (usually passive) To put in place to perform a task.\n[v.] To put in place to perform military duty.","ex":"I was stationed on the pier."},"STANK":{"p":"/stæŋk/","s":"v.","e":"[v.] To have a strong bad smell.\n[v.] To be greatly inferior; to perform badly.\n[v.] To give an impression of dishonesty or untruth.","ex":"That movie stinks. I didn't even stay for the end."},"STAYS":{"p":"/steɪz/","s":"n./v.","e":"[n.] Continuance or a period of time spent in a place; abode for an indefinite time; sojourn.\n[n.] A postponement, especially of an execution or other punishment.\n[n.] A stop; a halt; a break or cessation of action, motion, or progress.\n[v.] To prop; support; sustain; hold up; steady.\n[v.] To support from sinking; to sustain with strength; to satisfy in part or for the time.\n[v.] To stop; detain; keep back; delay; hinder.","ex":"I hope you enjoyed your stay in Hawaii."},"STAY":{"p":"/steɪ/","s":"n./v.","e":"[n.] Continuance or a period of time spent in a place; abode for an indefinite time; sojourn.\n[n.] A postponement, especially of an execution or other punishment.\n[n.] A stop; a halt; a break or cessation of action, motion, or progress.\n[v.] To prop; support; sustain; hold up; steady.\n[v.] To support from sinking; to sustain with strength; to satisfy in part or for the time.\n[v.] To stop; detain; keep back; delay; hinder.","ex":"I hope you enjoyed your stay in Hawaii."},"STAVE":{"p":"/steɪv/","s":"n./v.","e":"[n.] One of a number of narrow strips of wood, or narrow iron plates, placed edge to edge to form the sides, covering, or lining of a vessel or structure; especially, one of the strips which form the sides of a cask, a pail, etc.\n[n.] One of the bars or rounds of a rack, rungs of a ladder, etc; one of the cylindrical bars of a lantern wheel\n[n.] A metrical portion; a stanza; a staff.\n[v.] To fit or furnish with staves or rundles.\n[v.] (usually with 'in') To break in the staves of; to break a hole in; to burst.\n[v.] (with 'off') To push, or keep off, as with a staff.","ex":"to stave in a cask"},"SQUAW":{"p":"/skwɔː/","s":"n.","e":"[n.] A woman, wife; especially a Native American woman.","ex":""},"STEAM":{"p":"/stiːm/","s":"n./v./adj.","e":"[n.] The vapor formed when water changes from liquid phase to gas phase.\n[n.] Pressurized water vapour used for heating, cooking, or to provide mechanical energy.\n[n.] Internal energy for motive power.\n[v.] To cook with steam.\n[v.] To expose to the action of steam; to apply steam to for softening, dressing, or preparing.\n[v.] To produce or vent steam.","ex":"After three weeks in bed he was finally able to sit up under his own steam."},"STEED":{"p":"/stiːd/","s":"n.","e":"[n.] A stallion, especially in the sense of mount.\n[n.] A bicycle.","ex":"And govern'd him in strength, though not in lust. — Shakespeare, \"Venus and Adonis\"."},"STEEL":{"p":"/stiːl/","s":"n./v./adj.","e":"[n.] An artificial metal produced from iron, harder and more elastic than elemental iron; used figuratively as a symbol of hardness.\n[n.] Any item made of this metal, particularly including:\n[n.] Medicinal consumption of this metal; chalybeate medicine; (eventually) any iron or iron-treated water consumed as a medical treatment.\n[v.] To edge, cover, or point with steel.\n[v.] To harden or strengthen; to nerve or make obdurate; to fortify against.\n[v.] (of mirrors) To back with steel.","ex":""},"STATUS":{"p":"/ˈstæt.əs/","s":"n.","e":"[n.] A person’s condition, position or standing relative to that of others.\n[n.] Prestige or high standing.\n[n.] A situation or state of affairs.","ex":"Superstition is highly correlated with economic status."},"STEER":{"p":"/stɪə(ɹ)/","s":"n./v.","e":"[n.] A suggestion about a course of action.\n[n.] A helmsman; a pilot.\n[v.] To guide the course of a vessel, vehicle, aircraft etc. (by means of a device such as a rudder, paddle, or steering wheel).\n[v.] To be directed and governed; to take a direction, or course; to obey the helm.","ex":"I steered homeward."},"STEM":{"p":"/stɛm/","s":"n./v.","e":"[n.] The stock of a family; a race or generation of progenitors.\n[n.] A branch of a family.\n[n.] An advanced or leading position; the lookout.\n[v.] To remove the stem from.\n[v.] To be caused or derived; to originate.\n[v.] To descend in a family line.","ex":"to stem cherries; to stem tobacco leaves"},"STEAL":{"p":"/stiːl/","s":"n./v.","e":"[n.] The act of stealing.\n[n.] A piece of merchandise available at a very attractive price.\n[n.] A situation in which a defensive player actively takes possession of the ball or puck from the opponent's team.\n[v.] To take illegally, or without the owner's permission, something owned by someone else.\n[v.] (of ideas, words, music, a look, credit, etc.) To appropriate without giving credit or acknowledgement.\n[v.] To get or effect surreptitiously or artfully.","ex":"At this price, this car is a steal."},"STARS":{"p":"/stɑːz/","s":"n./v.","e":"[n.] Any small luminous dot appearing in the cloudless portion of the night sky, especially with a fixed location relative to other such dots.\n[n.] A luminous celestial body, made up of plasma (particularly hydrogen and helium) and having a spherical shape. Depending on context the sun may or may not be included.\n[n.] A concave polygon with regular, pointy protrusions and indentations, generally with five or six points.\n[v.] To appear as a featured performer or headliner, especially in an entertainment program.\n[v.] To feature (a performer or a headliner), especially in a movie or an entertainment program.\n[v.] To mark with a star or asterisk.","ex":""},"STERN":{"p":"/stɜːn/","s":"adj.","e":"[adj.] Having a hardness and severity of nature or manner.\n[adj.] Grim and forbidding in appearance.","ex":""},"STEPS":{"p":"/stɛps/","s":"n./v.","e":"[n.] An advance or movement made from one foot to the other; a pace.\n[n.] A rest, or one of a set of rests, for the foot in ascending or descending, as a stair, or a rung of a ladder.\n[n.] A distinct part of a process; stage; phase.\n[v.] To move the foot in walking; to advance or recede by raising and moving one of the feet to another resting place, or by moving both feet in succession.\n[v.] To walk; to go on foot; especially, to walk a little distance.\n[v.] To walk slowly, gravely, or resolutely.","ex":"He improved step by step, or by steps."},"STEEP":{"p":"/stiːp/","s":"n./adj.","e":"[n.] The steep side of a mountain etc.; a slope or acclivity.\n[adj.] Of a near-vertical gradient; of a slope, surface, curve, etc. that proceeds upward at an angle near vertical.\n[adj.] Expensive\n[adj.] Difficult to access; not easy reached; lofty; elevated; high.","ex":"a steep hill or mountain; a steep roof; a steep ascent; a steep barometric gradient"},"STEIN":{"p":"/staɪn/","s":"n.","e":"[n.] A beer mug, usually made of ceramic or glass.","ex":""},"STEAD":{"p":"/stɛd/","s":"n./v.","e":"[n.] A place, or spot, in general.\n[n.] A place where a person normally rests; a seat.\n[n.] An inhabited place; a settlement, city, town etc.\n[v.] To help, support, benefit or assist; to be helpful or noteful.\n[v.] To fill stead or place of.","ex":""},"STEWS":{"p":"","s":"n./v.","e":"[n.] A cooking-dish used for boiling; a cauldron.\n[n.] A heated bath-room or steam-room; also, a hot bath.\n[n.] A brothel.\n[v.] To cook (food) by slowly boiling or simmering.\n[v.] To brew (tea) for too long, so that the flavour becomes too strong.\n[v.] To suffer under uncomfortably hot conditions.","ex":"I'm going to stew some meat for the casserole."},"STIFF":{"p":"/stɪf/","s":"n./v./adj.","e":"[n.] An average person, usually male, of no particular distinction, skill, or education, often a working stiff or lucky stiff.\n[n.] A person who is deceived, as a mark or pigeon in a swindle.\n[n.] A cadaver; a dead person.\n[v.] To fail to pay that which one owes (implicitly or explicitly) to another, especially by departing hastily.\n[v.] To cheat someone\n[v.] To tip ungenerously","ex":"A Working Stiff's Manifesto: A Memoir of Thirty Jobs I Quit, Nine That Fired Me, and Three I Can't Remember was published in 2003."},"STILE":{"p":"/staɪl/","s":"n./v.","e":"[n.] A set of one or more steps surmounting a fence or wall, or a narrow gate or contrived passage through a fence or wall, which in either case allows people but not livestock to pass.\n[n.] A vertical component of a frame or panel, such as that of a door, window, or ladder.\n[n.] Senses relating to a thin, pointed object.\n[n.] (by extension from sense 1.1) A particular manner of expression in writing or speech, especially one regarded as good.\n[n.] A particular manner of creating, doing, or presenting something, especially a work of architecture or art.\n[v.] To design, fashion, make, or arrange in a certain way or form (style)","ex":""},"STEMS":{"p":"","s":"n./v.","e":"[n.] Acronym of science, technology, engineering, (and) mathematics.\n[n.] An electron microscope that transmits a very narrow beam of electrons through a sample; it can detect individual large or heavy atoms.\n[n.] A gleam of light; a flame.\n[n.] The stock of a family; a race or generation of progenitors.\n[n.] A branch of a family.\n[n.] An advanced or leading position; the lookout.","ex":"to stem cherries; to stem tobacco leaves"},"STILL":{"p":"/stɪl/","s":"n./adj./adv.","e":"[n.] A period of calm or silence.\n[n.] A photograph, as opposed to movie footage.\n[n.] A resident of the Falkland Islands.\n[adj.] Not moving; calm.\n[adj.] Not effervescing; not sparkling.\n[adj.] Uttering no sound; silent.","ex":"the still of the night"},"STIR":{"p":"/stɜː/","s":"n./v.","e":"[n.] The act or result of stirring (moving around the particles of a liquid etc.)\n[n.] Agitation; tumult; bustle; noise or various movements.\n[n.] Public disturbance or commotion; tumultuous disorder; seditious uproar.\n[v.] To incite to action\n[v.] To disturb the relative position of the particles of, as of a liquid, by passing something through it; to agitate.\n[v.] To agitate the content of (a container), by passing something through it.","ex":"Can you give the soup a little stir?"},"STIRS":{"p":"","s":"n./v.","e":"[n.] The act or result of stirring (moving around the particles of a liquid etc.)\n[n.] Agitation; tumult; bustle; noise or various movements.\n[n.] Public disturbance or commotion; tumultuous disorder; seditious uproar.\n[v.] To incite to action\n[v.] To disturb the relative position of the particles of, as of a liquid, by passing something through it; to agitate.\n[v.] To agitate the content of (a container), by passing something through it.","ex":"Can you give the soup a little stir?"},"STOAT":{"p":"/ˈstəʊt/","s":"n.","e":"[n.] Mustela erminea, the ermine or short-tailed weasel, a mustelid native to Eurasia and North America, distinguished from the least weasel by its larger size and longer tail with a prominent black tip.","ex":""},"STOIC":{"p":"/ˈstəʊɪk/","s":"n./adj.","e":"[n.] Proponent of stoicism, a school of thought, from in 300 B.C.E. up to about the time of Marcus Aurelius, who holds that by cultivating an understanding of the logos, or natural law, one can be free of suffering.\n[n.] A person indifferent to pleasure or pain.\n[adj.] Of or relating to the Stoics or their ideas.\n[adj.] Not affected by pain or distress.\n[adj.] Not displaying any external signs of being affected by pain or distress.","ex":""},"STILT":{"p":"/stɪlt/","s":"n./v.","e":"[n.] Either of two poles with footrests that allow someone to stand or walk above the ground; used mostly by entertainers.\n[n.] A tall pillar or post used to support some structure; often above water.\n[n.] Any of various wading birds of the genera Himantopus and Cladorhynchus, related to the avocet, that have extremely long legs and long thin bills.\n[v.] To raise on stilts, or as if on stilts","ex":""},"STINT":{"p":"/stɪnt/","s":"n./v.","e":"[n.] A period of time spent doing or being something; a spell.\n[n.] Limit; bound; restraint; extent.\n[n.] Quantity or task assigned; proportion allotted.\n[v.] To stop (an action); cease, desist.\n[v.] To stop speaking or talking (of a subject).\n[v.] To be sparing or mean.","ex":"He had a stint in jail."},"STOKE":{"p":"/stəʊk/","s":"v.","e":"[v.] To poke, pierce, thrust.","ex":""},"STINK":{"p":"/stɪŋk/","s":"n./v./adj.","e":"[n.] A strong bad smell.\n[n.] A complaint or objection.\n[v.] To have a strong bad smell.\n[v.] To be greatly inferior; to perform badly.\n[v.] To give an impression of dishonesty or untruth.\n[adj.] Bad; inferior; worthless.","ex":"If you don't make a stink about the problem, nothing will be done."},"STING":{"p":"/stɪŋ/","s":"n.","e":"[n.] A bump left on the skin after having been stung.\n[n.] A bite by an insect.\n[n.] A pointed portion of an insect or arachnid used for attack.","ex":""},"STEP":{"p":"/stɛp/","s":"n./v.","e":"[n.] An advance or movement made from one foot to the other; a pace.\n[n.] A rest, or one of a set of rests, for the foot in ascending or descending, as a stair, or a rung of a ladder.\n[n.] A distinct part of a process; stage; phase.\n[v.] To move the foot in walking; to advance or recede by raising and moving one of the feet to another resting place, or by moving both feet in succession.\n[v.] To walk; to go on foot; especially, to walk a little distance.\n[v.] To walk slowly, gravely, or resolutely.","ex":"He improved step by step, or by steps."},"STOLEN":{"p":"/ˈstəʊlən/","s":"v./adj.","e":"[v.] To take illegally, or without the owner's permission, something owned by someone else.\n[v.] (of ideas, words, music, a look, credit, etc.) To appropriate without giving credit or acknowledgement.\n[v.] To get or effect surreptitiously or artfully.\n[adj.] That has been stolen.","ex":"Three irreplaceable paintings were stolen from the gallery."},"STICK":{"p":"/stɪk/","s":"n./v.","e":"[n.] An elongated piece of wood or similar material, typically put to some use, for example as a wand or baton.\n[n.] Any roughly cylindrical (or rectangular) unit of a substance.\n[n.] Material or objects attached to a stick or the like.\n[v.] To cut a piece of wood to be the stick member of a cope-and-stick joint.\n[v.] To compose; to set, or arrange, in a composing stick.\n[v.] To furnish or set with sticks.","ex":"Sealing wax is available as a cylindrical or rectangular stick."},"STOMACH":{"p":"/ˈstʌmək/","s":"n./v.","e":"[n.] An organ in animals that stores food in the process of digestion.\n[n.] The belly.\n[n.] Pride, haughtiness.\n[v.] To tolerate (something), emotionally, physically, or mentally; to stand or handle something.\n[v.] To be angry.\n[v.] To resent; to remember with anger; to dislike.","ex":"I can't stomach her cooking."},"STOOD":{"p":"/stʊd/","s":"v.","e":"[v.] (heading) To position or be positioned physically.\n[v.] (heading) To position or be positioned mentally.\n[v.] (heading) To position or be positioned socially.","ex":""},"STONE":{"p":"/stɐʉn/","s":"n./v./adj./adv.","e":"[n.] A hard earthen substance that can form large rocks.\n[n.] A small piece of stone, a pebble.\n[n.] A gemstone, a jewel, especially a diamond.\n[v.] To pelt with stones, especially to kill by pelting with stones.\n[v.] To wall with stones.\n[v.] To remove a stone from (fruit etc.).","ex":"She got stoned to death after they found her."},"STONY":{"p":"/ˈstəʊni/","s":"adj.","e":"[adj.] As hard as stone.\n[adj.] Containing or made up of stones.\n[adj.] Of a person, lacking warmth and emotion.","ex":"a stony path"},"STIES":{"p":"","s":"n./v.","e":"[n.] A pen or enclosure for swine.\n[n.] A messy, dirty or debauched place.\n[v.] To place in, or as if in, a sty\n[v.] To live in a sty, or any messy or dirty place\n[n.] A ladder.\n[v.] To ascend, rise up, climb.","ex":""},"STOCK":{"p":"/stɒk/","s":"n./v./adj.","e":"[n.] A store or supply.\n[n.] The capital raised by a company through the issue of shares. The total of shares held by an individual shareholder.\n[n.] The raw material from which things are made; feedstock.\n[v.] To have on hand for sale.\n[v.] To provide with material requisites; to store; to fill; to supply.\n[v.] To allow (cows) to retain milk for twenty-four hours or more prior to sale.","ex":"The store stocks all kinds of dried vegetables."},"STOMP":{"p":"/stɒmp/","s":"n./v.","e":"[n.] A deliberate heavy footfall; a stamp.\n[n.] A dance having a heavy, rhythmic step.\n[n.] The jazz music for this dance.\n[v.] To trample heavily.\n[v.] To severely beat someone physically or figuratively.","ex":"She obliterated the cockroach with one stomp."},"STOOL":{"p":"/stuːl/","s":"n./v.","e":"[n.] A seat, especially for one person and without armrests.\n[n.] A close-stool; a seat used for urination and defecation: a chamber pot, commode, outhouse seat, or toilet.\n[n.] A plant that has been cut down until its main stem is close to the ground, resembling a stool, to promote new growth.\n[v.] To produce stool: to defecate.\n[v.] To cut down (a plant) until its main stem is close to the ground, resembling a stool, to promote new growth.","ex":""},"STORE":{"p":"/stɔː/","s":"n./v.","e":"[n.] A place where items may be accumulated or routinely kept.\n[n.] A supply held in storage.\n[n.] (mainly North American) A place where items may be purchased; a shop.\n[v.] To keep (something) while not in use, generally in a place meant for that purpose.\n[v.] To write (something) into memory or registers.","ex":"This building used to be a store for old tires."},"STOOP":{"p":"/stuːp/","s":"n.","e":"[n.] The staircase and landing or porch leading to the entrance of a residence.\n[n.] The threshold of a doorway, a doorstep.","ex":""},"STORED":{"p":"","s":"v.","e":"[v.] To keep (something) while not in use, generally in a place meant for that purpose.\n[v.] To write (something) into memory or registers.","ex":"I'll store these books in the attic."},"STOP":{"p":"/stɒp/","s":"n./v.","e":"[n.] A (usually marked) place where buses, trams or trains halt to let passengers get on and off, usually smaller than a station.\n[n.] An action of stopping; interruption of travel.\n[n.] That which stops, impedes, or obstructs; an obstacle; an impediment.\n[v.] To cease moving.\n[v.] To not continue.\n[v.] To cause (something) to cease moving or progressing.","ex":"They agreed to meet at the bus stop."},"STORM":{"p":"/stɔːm/","s":"n.","e":"[n.] Any disturbed state of the atmosphere, especially as affecting the earth's surface, and strongly implying destructive or unpleasant weather.\n[n.] A violent agitation of human society; a civil, political, or domestic commotion; violent outbreak.\n[n.] A wind scale for very strong wind, stronger than a gale, less than a hurricane (10 or higher on the Beaufort scale).","ex":"The proposed reforms have led to a political storm."},"STORK":{"p":"/stɔːk/","s":"n.","e":"[n.] A large wading bird with long legs and a long beak of the family Ciconiidae.\n[n.] (children's folklore) The mythical bringer of babies to families, or good news.\n[n.] The seventeenth Lenormand card.","ex":""},"STOLE":{"p":"/ˈstəʊl/","s":"v.","e":"[v.] To take illegally, or without the owner's permission, something owned by someone else.\n[v.] (of ideas, words, music, a look, credit, etc.) To appropriate without giving credit or acknowledgement.\n[v.] To get or effect surreptitiously or artfully.","ex":"Three irreplaceable paintings were stolen from the gallery."},"STORY":{"p":"/ˈstɔː.ɹi/","s":"n./v.","e":"[n.] A sequence of real or fictional events; or, an account of such a sequence.\n[n.] A lie, fiction.\n[n.] (usually pluralized) A soap opera.\n[v.] To tell as a story; to relate or narrate about.","ex":"The book tells the story of two roommates."},"STOUT":{"p":"/stʌʊt/","s":"n./adj.","e":"[n.] A dark and strong malt brew made with toasted grain.\n[n.] An obese person.\n[n.] A large clothing size.\n[adj.] Large; bulky.\n[adj.] Bold, strong-minded.\n[adj.] Proud; haughty.","ex":"Stout is darker, stronger and sweeter than porter beer."},"STOVE":{"p":"/stəʊv/","s":"n./v.","e":"[n.] A heater, a closed apparatus to burn fuel for the warming of a room.\n[n.] A device for heating food, (UK) a cooker.\n[n.] A hothouse (heated greenhouse).\n[v.] To heat or dry, as in a stove.\n[v.] To keep warm, in a house or room, by artificial heat.","ex":"to stove feathers"},"STRANGE":{"p":"/ˈstɹeɪnd͡ʒ/","s":"n./v./adj.","e":"[n.] Vagina\n[v.] To alienate; to estrange.\n[v.] To be estranged or alienated.\n[v.] To wonder; to be astonished (at something).\n[adj.] Not normal; odd, unusual, surprising, out of the ordinary.\n[adj.] Unfamiliar, not yet part of one's experience.","ex":"He thought it strange that his girlfriend wore shorts in the winter."},"STRAW":{"p":"/stɹɔː/","s":"n./v./adj.","e":"[n.] A dried stalk of a cereal plant.\n[n.] Such dried stalks considered collectively.\n[n.] A drinking straw.\n[v.] To lay straw around plants to protect them from frost.\n[v.] To sell straws on the streets in order to cover the giving to the purchaser of things usually banned, such as pornography.\n[adj.] Made of straw.","ex":"straw hat"},"STOWS":{"p":"","s":"v.","e":"[v.] To put something away in a compact and tidy manner, in its proper place, or in a suitable place.\n[v.] To store or pack something in a space-saving manner and over a long time.\n[v.] To arrange, pack, or fill something tightly or closely.","ex":""},"STRAIN":{"p":"/stɹeɪ̯n/","s":"n.","e":"[n.] Treasure.\n[n.] The blood-vessel in the yolk of an egg.\n[n.] Race; lineage, pedigree.","ex":""},"STRAP":{"p":"/stɹæp/","s":"n./v.","e":"[n.] A long, narrow, pliable strip of leather, cloth, or the like.\n[n.] A strip of thick leather used in flogging.\n[n.] Something made of such a strip, or of a part of one, or a combination of two or more for a particular use.\n[v.] To beat or chastise with a strap; to whip, to lash.\n[v.] To fasten or bind with a strap.\n[v.] To sharpen by rubbing on a strap, or strop","ex":"to strap a razor"},"STRAY":{"p":"/stɹeɪ/","s":"n.","e":"[n.] Any domestic animal that has no enclosure, or its proper place and company, and wanders at large, or is lost; an estray.\n[n.] One who is lost, either literally or metaphorically.\n[n.] The act of wandering or going astray.","ex":""},"STREAM":{"p":"/stɹiːm/","s":"n./v.","e":"[n.] A small river; a large creek; a body of moving water confined by banks.\n[n.] A thin connected passing of a liquid through a lighter gas (e.g. air).\n[n.] Any steady flow or succession of material, such as water, air, radio signal or words.\n[v.] To flow in a continuous or steady manner, like a liquid.\n[v.] To extend; to stretch out with a wavy motion; to float in the wind.\n[v.] To discharge in a stream.","ex":"He poured the milk in a thin stream from the jug to the glass."},"STREET":{"p":"/stɹiːt/","s":"n./v./adj.","e":"[n.] A paved part of road, usually in a village or a town.\n[n.] A road as above but including the sidewalks (pavements) and buildings.\n[n.] The people who live in such a road, as a neighborhood.\n[v.] To build or equip with streets.\n[v.] To eject; to throw onto the streets.\n[v.] (by extension) To heavily defeat.","ex":"Walk down the street until you see a hotel on the right."},"STRESS":{"p":"/stɹɛs/","s":"n./v.","e":"[n.] (Cause of) discomfort.\n[n.] Serious danger.\n[n.] An aversive state of stress to which a person cannot fully adapt.\n[n.] A physical, chemical, infective agent aggressing an organism.\n[n.] Aggression toward an organism resulting in a response in an attempt to restore previous conditions.\n[n.] The internal distribution of force across a small boundary per unit area of that boundary (pressure) within a body. It causes strain or deformation and is typically symbolised by σ or τ.","ex":""},"STROKE":{"p":"/stɹəʊk/","s":"n.","e":"[n.] An act of stroking (moving one's hand over a surface).\n[n.] A blow or hit.\n[n.] A single movement with a tool.","ex":"She gave the cat a stroke."},"STREW":{"p":"/stɹuː/","s":"v.","e":"[v.] (archaic except strewn) To distribute objects or pieces of something over an area, especially in a random manner.\n[v.] (archaic except strewn) To cover, or lie upon, by having been scattered.\n[v.] To spread abroad; to disseminate.","ex":"to strew sand over a floor"},"STRIP":{"p":"/stɹɪp/","s":"n.","e":"[n.] A long, thin piece of land; any long, thin area.\n[n.] (usually countable, sometimes uncountable) A long, thin piece of any material; any such material collectively.\n[n.] A comic strip.","ex":"The countries were in dispute over the ownership of a strip of desert about 100 metres wide."},"STRUM":{"p":"","s":"n./v.","e":"[n.] The sound made by playing various strings of a stringed instrument simultaneously.\n[n.] The act of strumming.\n[v.] To play (a guitar or other stringed instrument) using various strings simultaneously.","ex":""},"STUDENT":{"p":"/ˈstjuː.dənt/","s":"n.","e":"[n.] A person who studies or learns about a particular subject.\n[n.] A person who is formally enrolled at a school, a college or university, or another educational institution.","ex":"He is a student of life."},"STRUT":{"p":"/stɹʌt/","s":"n./v.","e":"[n.] Protuberance, air pressure\n[v.] To swell; protuberate; bulge or spread out.\n[v.] (originally said of fowl) To stand or walk stiffly, with the tail erect and spread out.\n[v.] To walk proudly or haughtily.","ex":"He strutted about the yard, thinking himself master of all he surveyed."},"STUDIED":{"p":"/ˈstʌdid/","s":"adj./v.","e":"[adj.] Practiced; self-conscious; careful.\n[adj.] Qualified by, or versed in, study; learned.\n[v.] (usually academic) To review materials already learned in order to make sure one does not forget them, usually in preparation for an examination.\n[v.] (academic) To take a course or courses on a subject.\n[v.] To acquire knowledge on a subject with the intention of applying it in practice.","ex":"She gave a studied reply."},"STRICT":{"p":"/stɹɪkt/","s":"adj.","e":"[adj.] Strained; drawn close; tight.\n[adj.] Tense; not relaxed.\n[adj.] Exact; accurate; precise; rigorously particular.","ex":"strict embrace"},"STUDIES":{"p":"/ˈstʌdiz/","s":"n./v.","e":"[n.] An academic field of study concerning the given subject.\n[v.] (usually academic) To review materials already learned in order to make sure one does not forget them, usually in preparation for an examination.\n[v.] (academic) To take a course or courses on a subject.\n[v.] To acquire knowledge on a subject with the intention of applying it in practice.\n[n.] Mental effort to acquire knowledge or learning.\n[n.] The act of studying or examining; examination.","ex":"I need to study my biology notes."},"STROP":{"p":"/stɹɒp/","s":"n./v.","e":"[n.] A strap; more specifically a piece of leather or a substitute (notably canvas), or strip of wood covered with a suitable material, for honing a razor, in this sense also called razor strop.\n[n.] A bad mood or temper (see stroppy.)\n[n.] A piece of rope spliced into a circular wreath, and put round a block for hanging it.\n[v.] To strap.\n[v.] (recorded since 1842; now most used) To hone (a razor) with a strop.","ex":"One should strop the razor before each shave."},"STOPS":{"p":"/stɑps/","s":"n./v.","e":"[n.] A (usually marked) place where buses, trams or trains halt to let passengers get on and off, usually smaller than a station.\n[n.] An action of stopping; interruption of travel.\n[n.] That which stops, impedes, or obstructs; an obstacle; an impediment.\n[v.] To cease moving.\n[v.] To not continue.\n[v.] To cause (something) to cease moving or progressing.","ex":"They agreed to meet at the bus stop."},"STRONG":{"p":"/stɹɑŋ/","s":"adj./adv.","e":"[adj.] Capable of producing great physical force.\n[adj.] Capable of withstanding great physical force.\n[adj.] (of water, wind, etc.) Having a lot of power.\n[adv.] In a strong manner.","ex":"a big strong man; Jake was tall and strong"},"STUDIO":{"p":"/ˈstjuːdiəʊ/","s":"n.","e":"[n.] An artist’s or photographer’s workshop or the room in which an artist works.\n[n.] An establishment where an art is taught.\n[n.] A place where radio or television programs, records or films are made.","ex":"His studio was cramped when he began as an artist."},"STUDS":{"p":"","s":"n.","e":"[n.] A male animal, especially a stud horse (stallion), kept for breeding.\n[n.] A female animal, especially a studmare (broodmare), kept for breeding.\n[n.] (also by extension) A group of such animals.\n[n.] A small object that protrudes from something; an ornamental knob.\n[n.] (jewelry) A small round earring.\n[n.] A vertical post, especially one of the small uprights in the framing for lath and plaster partitions, and furring, and upon which the laths are nailed.","ex":"a collar with studs"},"STUDY":{"p":"/ˈstʌdi/","s":"v.","e":"[v.] (usually academic) To review materials already learned in order to make sure one does not forget them, usually in preparation for an examination.\n[v.] (academic) To take a course or courses on a subject.\n[v.] To acquire knowledge on a subject with the intention of applying it in practice.","ex":"I need to study my biology notes."},"STUBS":{"p":"","s":"n./v.","e":"[n.] Something blunted, stunted, or cut short, such as stubble or a stump.\n[n.] A piece of certain paper items, designed to be torn off and kept for record or identification purposes.\n[n.] A placeholder procedure that has the signature of the planned procedure but does not yet implement the intended behavior.\n[v.] To remove most of a tree, bush, or other rooted plant by cutting it close to the ground.\n[v.] To remove a plant by pulling it out by the roots.\n[v.] To jam, hit, or bump, especially a toe.","ex":"check stub, ticket stub, payment stub"},"STUCK":{"p":"/ˈstʌk/","s":"v./adj.","e":"[v.] To become or remain attached; to adhere.\n[v.] To jam; to stop moving.\n[v.] To tolerate, to endure, to stick with.\n[adj.] Unable to move.\n[adj.] Unable to progress with a task.\n[adj.] No longer functioning, frozen up, frozen.","ex":"The tape will not stick if it melts."},"STUMP":{"p":"/stʌmp/","s":"n./v.","e":"[n.] The remains of something that has been cut off; especially the remains of a tree, the remains of a limb.\n[n.] The place or occasion at which a campaign takes place; the husting.\n[n.] A place or occasion at which a person harangues or otherwise addresses a group in a manner suggesting political oration.\n[v.] To stop, confuse, or puzzle.\n[v.] To baffle; to make unable to find an answer to a question or problem.\n[v.] To campaign.","ex":"This last question has me stumped."},"STUNG":{"p":"/stʌŋ/","s":"v.","e":"[v.] To hurt, usually by introducing poison or a sharp point, or both.\n[v.] (of an insect) To bite.\n[v.] (sometimes figurative) To hurt, to be in pain.","ex":"Right so came out an adder of a little heathbush, and it stung a knight in the foot."},"STUNS":{"p":"","s":"n./v.","e":"[n.] The condition of being stunned.\n[n.] That which stuns; a shock; a stupefying blow.\n[n.] A person who lacks intelligence.\n[v.] To incapacitate; especially by inducing disorientation or unconsciousness.\n[v.] To shock or surprise.\n[v.] To hit the cue ball so that it slides without topspin or backspin (and with or without sidespin) and continues at a natural angle after contact with the object ball","ex":"Bill tried to stun the snake by striking it on the head."},"STUNT":{"p":"/stʌnt/","s":"n./v.","e":"[n.] A daring or dangerous feat, often involving the display of gymnastic skills.\n[n.] Skill\n[n.] A special means of rushing the quarterback done to confuse the opposing team's offensive line.\n[v.] (cheerleading) To perform a stunt.\n[v.] To show off; to posture.","ex":""},"STREP":{"p":"/stɹɛp/","s":"n.","e":"[n.] A strep throat.\n[n.] A streptococcus.","ex":""},"STYLE":{"p":"/staɪl/","s":"n./v.","e":"[n.] Senses relating to a thin, pointed object.\n[n.] (by extension from sense 1.1) A particular manner of expression in writing or speech, especially one regarded as good.\n[n.] A particular manner of creating, doing, or presenting something, especially a work of architecture or art.\n[v.] To design, fashion, make, or arrange in a certain way or form (style)\n[v.] To call or give a name or title to.\n[v.] To create for, or give to, someone a style, fashion, or image, particularly one which is regarded as attractive, tasteful, or trendy.","ex":""},"SUAVE":{"p":"/swɑːv/","s":"n./adj.","e":"[n.] Sweet talk.\n[adj.] Charming, confident and elegant.","ex":""},"STUFF":{"p":"/stʌf/","s":"n./v.","e":"[n.] Miscellaneous items or objects; (with possessive) personal effects.\n[n.] Unspecified things or matters.\n[n.] The tangible substance that goes into the makeup of a physical object.\n[v.] To fill by packing or crowding something into; to cram with something; to load to excess.\n[v.] To fill a space with (something) in a compressed manner.\n[v.] To fill with seasoning.","ex":"What is all that stuff on your bedroom floor?  He didn't want his pockets to bulge so he was walking around with all his stuff in his hands."},"SUBMIT":{"p":"/səbˈmɪt/","s":"v.","e":"[v.] To yield or give way to another.\n[v.] To yield (something) to another, as when defeated.\n[v.] To enter or put forward for approval, consideration, marking etc.","ex":"They will not submit to the destruction of their rights."},"SUCCEED":{"p":"/səkˈsiːd/","s":"v.","e":"[v.] To follow in order; to come next after; hence, to take the place of.\n[v.] To obtain the object desired; to accomplish what is attempted or intended; to have a prosperous issue or termination; to be successful.\n[v.] To fall heir to; to inherit.","ex":"Autumn succeeds summer."},"SUBJECT":{"p":"/ˈsʌb.dʒɪkt/","s":"adj.","e":"[adj.] Likely to be affected by or to experience something.\n[adj.] Conditional upon.\n[adj.] Placed or situated under; lying below, or in a lower situation.","ex":"He's subject to sneezing fits."},"STUNK":{"p":"/stʌŋk/","s":"v.","e":"[v.] To have a strong bad smell.\n[v.] To be greatly inferior; to perform badly.\n[v.] To give an impression of dishonesty or untruth.","ex":"That movie stinks. I didn't even stay for the end."},"SUCCESS":{"p":"/səkˈsɛs/","s":"n.","e":"[n.] The achievement of one's aim or goal.\n[n.] Financial profitability.\n[n.] One who, or that which, achieves assumed goals.","ex":"His third attempt to pass the entrance exam was a success."},"STYLI":{"p":"/ˈstaɪlaɪ/","s":"n.","e":"[n.] Senses relating to a thin, pointed object.\n[n.] (by extension from sense 1.1) A particular manner of expression in writing or speech, especially one regarded as good.\n[n.] A particular manner of creating, doing, or presenting something, especially a work of architecture or art.\n[n.] A sharp stick used in ancient times for writing on clay tablets or other surfaces; a sharp tool for engraving.\n[n.] A tool for making small dots on a piece of heavy paper, used to produce Braille writing for the blind by hand.\n[n.] A phonograph needle.","ex":""},"SUCH":{"p":"/sʌt͡ʃ/","s":"n./pron.","e":"[n.] Something being indicated that is similar to something else.\n[pron.] A person, a thing, people or things like the one or ones already mentioned.","ex":""},"SUDDEN":{"p":"/ˈsʌdən/","s":"n./adj./adv.","e":"[n.] An unexpected occurrence; a surprise.\n[adj.] Happening quickly and with little or no warning.\n[adj.] Hastily prepared or employed; quick; rapid.\n[adj.] Hasty; violent; rash; precipitate.\n[adv.] Suddenly.","ex":"The sudden drop in temperature left everyone cold and confused."},"SUFFER":{"p":"/ˈsʌfə/","s":"v.","e":"[v.] To undergo hardship.\n[v.] To feel pain.\n[v.] To become worse.","ex":"Is anyone here afraid of suffering hardship?"},"SUEDE":{"p":"/sweɪd/","s":"n./v./adj.","e":"[n.] A type of soft leather, made from calfskin, with a brushed texture to resemble fabric, often used to make boots, clothing and fashion accessories.\n[v.] To make (leather) into suede.\n[adj.] Made of suede","ex":""},"SUGAR":{"p":"/ˈʃʊɡə(ɹ)/","s":"n./v./int.","e":"[n.] Sucrose in the form of small crystals, obtained from sugar cane or sugar beet and used to sweeten food and drink.\n[n.] A specific variety of sugar.\n[n.] Any of various small carbohydrates that are used by organisms to store energy.\n[v.] To add sugar to; to sweeten with sugar.\n[v.] To make (something unpleasant) seem less so.\n[v.] In making maple sugar, to complete the process of boiling down the syrup till it is thick enough to crystallize; to approach or reach the state of granulation; with the preposition off.","ex":"John heavily sugars his coffee."},"SUGGEST":{"p":"/səˈdʒɛst/","s":"v.","e":"[v.] To imply but stop short of saying explicitly.\n[v.] To make one suppose; cause one to suppose (something).\n[v.] To mention something as an idea, typically in order to recommend it","ex":"Are you suggesting that I killed my wife?"},"SUING":{"p":"","s":"v.","e":"[v.] To file a legal action against someone, generally a non-criminal action.\n[v.] To seek by request; to make application; to petition; to entreat; to plead.\n[v.] (of a hawk) To clean (the beak, etc.).","ex":""},"SUITE":{"p":"/swiːt/","s":"n.","e":"[n.] A retinue or company of attendants, as of a distinguished personage\n[n.] A connected series or succession of objects; a number of things used or classed together\n[n.] A group of connected rooms, usually separable from other rooms by means of access.","ex":"the ambassador's suite"},"SULKS":{"p":"","s":"n./v.","e":"[n.] A state of sulking.\n[v.] To express ill humor or offence by remaining sullenly silent or withdrawn.\n[n.] A furrow.","ex":"Leo has been in a sulk all morning."},"SULKY":{"p":"","s":"n./adj.","e":"[n.] A low two-wheeled cart, used in harness racing.\n[n.] Any carriage seating only the driver.\n[adj.] Silent and withdrawn after being upset","ex":"the sulky child"},"SULLY":{"p":"/ˈsʌli/","s":"n./v.","e":"[n.] A blemish.\n[v.] To soil or stain; to dirty.\n[v.] To corrupt or damage.\n[v.] (intransitive ) To become soiled or tarnished.","ex":"He did not wish to sully his hands with gardening."},"SUMAC":{"p":"/ˈs(j)uːmæk/","s":"n./v.","e":"[n.] Any of various shrubs or small trees of the genus Rhus and other genera in Anacardiaceae, particularly the elm-leaved sumac, Sicilian sumac, or tanner's sumac (Rhus coriaria).\n[n.] Dried and chopped-up leaves and stems of a plant of the genus Rhus, particularly the tanner's sumac (see sense 1), used for dyeing and tanning leather or for medicinal purposes.\n[n.] A sour spice popular in the Eastern Mediterranean, made from the berries of tanner's sumac.\n[v.] To apply a preparation of sumac to (an object), for example, to a piece of leather to tan it.","ex":""},"SUMMARY":{"p":"/ˈsʌməɹi/","s":"n./adj.","e":"[n.] An abstract or a condensed presentation of the substance of a body of material.\n[adj.] Concise, brief or presented in a condensed form\n[adj.] Performed speedily and without formal ceremony.\n[adj.] Performed by cutting the procedures of a standard and fair trial.","ex":"A summary review is in the appendix."},"SUCKS":{"p":"/sʌks/","s":"n./v.","e":"[n.] An instance of drawing something into one's mouth by inhaling.\n[n.] Milk drawn from the breast.\n[n.] A weak, self-pitying person; a person who refuses to go along with others, especially out of spite; a crybaby or sore loser.\n[v.] To use the mouth and lips to pull in (a liquid, especially milk from the breast).\n[v.] To perform such an action; to feed from a breast or teat.\n[v.] To put the mouth or lips to (a breast, a mother etc.) to draw in milk.","ex":""},"SUNG":{"p":"/sʌŋ/","s":"v.","e":"[v.] To produce musical or harmonious sounds with one’s voice.\n[v.] To express audibly by means of a harmonious vocalization.\n[v.] To soothe with singing.","ex":"\"I really want to sing in the school choir,\" said Vera."},"SUNNY":{"p":"/ˈsʌni/","s":"n./adj./adv.","e":"[n.] A sunfish.\n[adj.] (of weather or a day) Featuring a lot of sunshine.\n[adj.] (of a place) Receiving a lot of sunshine.\n[adj.] (of a person or a person's mood) cheerful\n[adv.] Sunny side up","ex":"Whilst it may be sunny today, the weather forecast is predicting rain."},"SUNUP":{"p":"/ˈsʌnʌp/","s":"n.","e":"[n.] The time of day when the sun appears above the eastern horizon.\n[n.] The change in color of the sky at sunup.","ex":""},"SUPER":{"p":"/ˈs(j)uːpə(ɹ)/","s":"adj./adv.","e":"[adj.] Of excellent quality, superfine.\n[adj.] Better than average, better than usual; wonderful.\n[adv.] Very; extremely (used like the prefix super-).","ex":"The party was super awesome."},"SUMMA":{"p":"","s":"n.","e":"[n.] A comprehensive summary of, or treatise on a subject, especially theology or philosophy.","ex":""},"SUPPLY":{"p":"/səˈplaɪ/","s":"n./v.","e":"[n.] The act of supplying.\n[n.] An amount of something supplied.\n[n.] (in the plural) provisions.\n[v.] To provide (something), to make (something) available for use.\n[v.] To furnish or equip with.\n[v.] To fill up, or keep full.","ex":"supply and demand"},"SUPPORT":{"p":"/səˈpɔːt/","s":"n./v.","e":"[n.] (sometimes attributive) Something which supports.\n[n.] Financial or other help.\n[n.] Answers to questions and resolution of problems regarding something sold.\n[v.] To keep from falling.\n[v.] To answer questions and resolve problems regarding something sold.\n[v.] To back a cause, party, etc., mentally or with concrete aid.","ex":"Don't move that beam! It's a support for the whole platform."},"SURE":{"p":"/ʃoː/","s":"adj./adv./int.","e":"[adj.] Physically secure and certain, non-failing, reliable.\n[adj.] Certain in one's knowledge or belief.\n[adj.] Certain to act or be a specified way.\n[adv.] (modal adverb) Without doubt, certainly.\n[int.] Yes. (Expresses noncommittal agreement or consent.)\n[int.] Yes; of course.","ex":"This investment is a sure thing.   The bailiff had a sure grip on the prisoner's arm."},"SURELY":{"p":"/ˈʃɔːli/","s":"adv.","e":"[adv.] Without fail.\n[adv.] Certainly, undoubtedly.\n[adv.] With confidence.","ex":"slowly but surely"},"SUMMIT":{"p":"/ˈsʌmɪt/","s":"n./v.","e":"[n.] A peak; the topmost point or surface, as of a mountain.\n[n.] A gathering or assembly of leaders.\n[v.] (hiking) To reach the summit of a mountain.","ex":"In summer, it is possible to hike to the summit of Mount Shasta."},"SURGE":{"p":"/sɜːdʒ/","s":"n./v.","e":"[n.] A sudden transient rush, flood or increase.\n[n.] The maximum amplitude of a vehicle's forward/backward oscillation\n[n.] A sudden electrical spike or increase of voltage and current.\n[v.] To rush, flood, or increase suddenly.\n[v.] To accelerate forwards, particularly suddenly.\n[v.] To slack off a line.","ex":"He felt a surge of excitement."},"SURLY":{"p":"/ˈsɜːli/","s":"adj./adv.","e":"[adj.] Irritated, bad-tempered, unfriendly.\n[adj.] Threatening, menacing, gloomy.\n[adj.] Lordly, arrogant, supercilious.\n[adv.] In an arrogant or supercilious manner.","ex":"The surly weather put us all in a bad mood."},"SUIT":{"p":"/s(j)uːt/","s":"n./v.","e":"[n.] A set of clothes to be worn together, now especially a man's matching jacket and trousers (also business suit or lounge suit), or a similar outfit for a woman.\n[n.] (by extension) A single garment that covers the whole body: space suit, boiler suit, protective suit.\n[n.] (metonym) A person who wears matching jacket and trousers, especially a boss or a supervisor.\n[v.] To make proper or suitable; to adapt or fit.\n[v.] (said of clothes, hairstyle or other fashion item) To be suitable or apt for one's image.\n[v.] To be appropriate or apt for.","ex":"Nick hired a navy-blue suit for the wedding."},"SURPLUS":{"p":"/ˈsɜːpləs/","s":"n./v./adj.","e":"[n.] That which remains when use or need is satisfied, or when a limit is reached; excess; overplus.\n[n.] Specifically, an amount in the public treasury at any time greater than is required for the ordinary purposes of the government.\n[n.] The remainder of a fund appropriated for a particular purpose.\n[v.] To treat as surplus to requirements, to sell off.\n[adj.] Being or constituting a surplus; more than sufficient","ex":"It is surplus to our needs"},"SURVEY":{"p":"","s":"n./v.","e":"[n.] The act of surveying; a general view.\n[n.] A particular view; an examination, especially an official examination, of a particular group of items, in order to ascertain the condition, quantity, or quality.\n[n.] The operation of finding the contour, dimensions, position, or other particulars of any part of the Earth's surface.\n[v.] To inspect, or take a view of; to view with attention, as from a high place; to overlook\n[v.] To view with a scrutinizing eye; to examine.\n[v.] To examine with reference to condition, situation, value, etc.; to examine and ascertain the state of","ex":"A survey of the stores of a ship; a survey of roads and bridges; a survey of buildings."},"SUSHI":{"p":"/ˈsuʃi/","s":"n.","e":"[n.] A Japanese dish made of small portions of sticky white rice flavored with vinegar, usually wrapped in seaweed and filled or topped with fish, vegetables or meat.\n[n.] Raw fish, especially as a Japanese dish.","ex":"For the vegetarians, she served cucumber sushi."},"SURVIVE":{"p":"/səˈvʌɪv/","s":"v.","e":"[v.] Of a person, to continue to live; to remain alive.\n[v.] Of an object or concept, to continue to exist.\n[v.] To live longer than; to outlive.","ex":"His children survived him; he was survived by his children."},"SUSPEND":{"p":"/səˈspɛnd/","s":"v.","e":"[v.] To halt something temporarily.\n[v.] To hold in an undetermined or undecided state.\n[v.] To discontinue or interrupt a function, task, position, or event.","ex":"The meeting was suspended for lunch."},"SWABS":{"p":"","s":"n./v.","e":"[n.] A small piece of soft, absorbent material, such as gauze, used to clean wounds, apply medicine, or take samples of body fluids. Often attached to a stick or wire to aid access.\n[n.] A sample taken with a swab (piece of absorbent material).\n[n.] A piece of material used for cleaning or sampling other items like musical instruments or guns.\n[v.] To use a swab on something, or clean something with a swab.","ex":"swab the deck of a ship"},"SURFACE":{"p":"/ˈsɜːfɪs/","s":"n./v.","e":"[n.] The overside or up-side of a flat object such as a table, or of a liquid.\n[n.] The outside hull of a tangible object.\n[n.] Outward or external appearance.\n[v.] To provide something with a surface.\n[v.] To apply a surface to something.\n[v.] To rise to the surface.","ex":"On the surface, the spy looked like a typical businessman."},"SWAIN":{"p":"/sweɪn/","s":"n.","e":"[n.] A young man or boy in service; a servant.\n[n.] A knight's servant; an attendant.\n[n.] A country labourer; a countryman, a rustic.","ex":""},"SWARD":{"p":"/swɔː(ɹ)d/","s":"n./v.","e":"[n.] A layer of earth into which grass has grown; turf; sod.\n[n.] An expanse of land covered in grass; a lawn or meadow.\n[n.] Skin; covering.\n[v.] To cover with sward.","ex":""},"SWATH":{"p":"/swɒθ/","s":"n.","e":"[n.] The track cut out by a scythe in mowing.\n[n.] A broad sweep or expanse, such as of land or of people.","ex":"A large swath of the population is opposed to this government policy."},"SWASH":{"p":"","s":"n./v./adj.","e":"[n.] The water that washes up on shore after an incoming wave has broken\n[n.] A long, protruding ornamental line or pen stroke found in some typefaces and styles of calligraphy.\n[n.] A narrow sound or channel of water lying within a sand bank, or between a sand bank and the shore, or a bar over which the sea washes.\n[v.] To swagger; to bluster and brag.\n[v.] To dash or flow noisily; to splash.\n[v.] To fall violently or noisily.","ex":""},"SWAYS":{"p":"","s":"n./v.","e":"[n.] The act of swaying; a swaying motion; a swing or sweep of a weapon.\n[n.] A rocking or swinging motion.\n[n.] Influence, weight, or authority that inclines to one side\n[v.] To move or swing from side to side; or backward and forward; to rock.\n[v.] To move or wield with the hand; to swing; to wield.\n[v.] To influence or direct by power, authority, persuasion, or by moral force; to rule; to govern; to guide. Compare persuade.","ex":"The old song caused a little sway in everyone in the room."},"SWAGS":{"p":"","s":"n./v.","e":"[n.] Initialism of scientific/speculative/sophisticated/stupid wild-ass guess.\n[n.] (window coverings) A loop of draped fabric.\n[n.] A low point or depression in land; especially, a place where water collects.\n[v.] To (cause to) sway.\n[v.] To droop; to sag.\n[v.] To decorate (something) with loops of draped fabric.","ex":""},"SWAGE":{"p":"/ˈsweɪdʒ/","s":"n./v.","e":"[n.] A tool, used by blacksmiths and other metalworkers, for cold shaping of a metal item.\n[v.] To bend or shape through use of a swage.","ex":""},"SWEAR":{"p":"/swɛə/","s":"v.","e":"[v.] To take an oath, to promise.\n[v.] To use offensive, profane, or obscene language.","ex":""},"SWEAT":{"p":"/swɛt/","s":"n.","e":"[n.] Fluid that exits the body through pores in the skin usually due to physical stress and/or high temperature for the purpose of regulating body temperature and removing certain compounds from the circulation.\n[n.] The state of one who sweats; diaphoresis.\n[n.] (especially WWI) A soldier (especially one who is old or experienced).","ex":"Just thinking about the interview tomorrow puts me into a nervous sweat."},"SWEEP":{"p":"/swiːp/","s":"n./v.","e":"[n.] A single action of sweeping.\n[n.] The person who steers a dragon boat.\n[n.] A person who stands at the stern of a surf boat, steering with a steering oar and commanding the crew.\n[v.] To clean (a surface) by means of a stroking motion of a broom or brush.\n[v.] To move through a (horizontal) arc or similar long stroke.\n[v.] To search (a place) methodically.","ex":"Give the front steps a quick sweep to get rid of those fallen leaves."},"SWATS":{"p":"","s":"n./v.","e":"[n.] A hard stroke, hit or blow, e.g., as part of a spanking.\n[n.] Alternate spelling of swot: vigorous study at an educational institution.\n[v.] To beat off, as insects; to bat, strike, or hit.\n[v.] To illegitimately provoke a SWAT assault upon (someone).","ex":"He swatted the mosquito that was buzzing around in his bedroom."},"SWAMP":{"p":"/swɒmp/","s":"n./v.","e":"[n.] A piece of wet, spongy land; low ground saturated with water; soft, wet ground which may have a growth of certain kinds of trees, but is unfit for agricultural or pastoral purposes.\n[n.] A type of wetland that stretches for vast distances, and is home to many creatures which have adapted specifically to that environment.\n[n.] A place or situation that is foul or where progress is difficult.\n[v.] To drench or fill with water.\n[v.] To overwhelm; to make too busy, or overrun the capacity of.\n[v.] To plunge into difficulties and perils; to overwhelm; to ruin; to wreck.","ex":"The boat was swamped in the storm."},"SWAPS":{"p":"","s":"v./n.","e":"[v.] To exchange or give (something) in an exchange (for something else).\n[v.] To hit, to strike.\n[v.] To beat the air, or ply the wings, with a sweeping motion or noise; to flap.\n[n.] An exchange of two comparable things.\n[n.] A financial derivative in which two parties agree to exchange one stream of cashflow against another stream.\n[n.] Space available in a swap file for use as auxiliary memory.","ex":"How much swap do you need?"},"SWEET":{"p":"/swiːt/","s":"n./v./adj./adv./int.","e":"[n.] The basic taste sensation induced by sugar.\n[n.] A confection made from sugar, or high in sugar content; a candy.\n[n.] A food eaten for dessert.\n[v.] To sweeten.\n[adj.] Having a pleasant taste, especially one relating to the basic taste sensation induced by sugar.\n[adj.] Having a taste of sugar.","ex":"Can we see the sweet menu, please?"},"SURER":{"p":"","s":"adj.","e":"[adj.] Physically secure and certain, non-failing, reliable.\n[adj.] Certain in one's knowledge or belief.\n[adj.] Certain to act or be a specified way.","ex":"This investment is a sure thing.   The bailiff had a sure grip on the prisoner's arm."},"SWEPT":{"p":"/ˈswɛpt/","s":"v.","e":"[v.] To clean (a surface) by means of a stroking motion of a broom or brush.\n[v.] To move through a (horizontal) arc or similar long stroke.\n[v.] To search (a place) methodically.","ex":"to sweep a floor, the street, or a chimney"},"SWIFT":{"p":"/swɪft/","s":"n./adj./adv.","e":"[n.] A small plain-colored bird of the family Apodidae that resembles a swallow and is noted for its rapid flight.\n[n.] Any of certain lizards of the genus Sceloporus.\n[n.] A moth of the family Hepialidae, swift moth, ghost moth.\n[adj.] Fast; quick; rapid.\n[adj.] Capable of moving at high speeds.\n[adv.] Swiftly.","ex":""},"SWIGS":{"p":"/swɪɡz/","s":"n./v.","e":"[n.] Drink, liquor.\n[n.] (by extension) A long draught from a drink.\n[n.] A person who drinks deeply.\n[v.] To drink (usually by gulping or in a greedy or unrefined manner); to quaff.\n[v.] To suck.\n[v.] To take up the last bit of slack in rigging by taking a single turn around a cleat, then hauling on the line above and below the cleat while keeping tension on the line.","ex":"That sailor can swig whisky with the best of 'em."},"SWILL":{"p":"/swɪl/","s":"n./v.","e":"[n.] (collective) A mixture of solid and liquid food scraps fed to pigs etc; especially kitchen waste for this purpose.\n[n.] (by extension) Any disgusting or distasteful liquid.\n[n.] (by extension) Anything disgusting or worthless.\n[v.] To drink (or, rarely, eat) greedily or to excess.\n[v.] To wash (something) by flooding with water.\n[v.] To move (a liquid or liquid-filled vessel) in a circular motion.","ex":"I cannot believe anyone could drink this swill."},"SWINE":{"p":"/swaɪn/","s":"n.","e":"[n.] (plural swine) A pig (the animal).\n[n.] A contemptible person (plural swines).\n[n.] A police officer; a \"pig\".","ex":""},"SWIPE":{"p":"/swaɪp/","s":"n./v.","e":"[n.] A quick grab, bat, or other motion with the hand or paw; a sweep.\n[n.] A strong blow given with a sweeping motion, as with a bat or club.\n[n.] An act of interacting with a touch screen by drawing the finger rapidly across it.\n[v.] To grab or bat quickly.\n[v.] To strike with a strong blow in a sweeping motion.\n[v.] To scan or register by sliding (a swipecard etc.) through a reader.","ex":"The cat swiped at the shoelace."},"SWING":{"p":"/ˈswɪŋ/","s":"n./v.","e":"[n.] The manner in which something is swung.\n[n.] The sweep or compass of a swinging body.\n[n.] A line, cord, or other thing suspended and hanging loose, upon which anything may swing.\n[v.] To rotate about an off-centre fixed point.\n[v.] To dance.\n[v.] To ride on a swing.","ex":"Door swing indicates direction the door opens."},"SWIMS":{"p":"","s":"n./v.","e":"[n.] An act or instance of swimming.\n[n.] The sound, or air bladder, of a fish.\n[n.] A part of a stream much frequented by fish.\n[v.] To move through the water, without touching the bottom; to propel oneself in water by natural means.\n[v.] To become immersed in, or as if in, or flooded with, or as if with, a liquid\n[v.] To move around freely because of excess space.","ex":"I'm going for a swim."},"SWISH":{"p":"/swɪʃ/","s":"n./v./adj./int.","e":"[n.] A short rustling, hissing or whistling sound, often made by friction.\n[n.] A hissing, sweeping movement through the air, as of an animal's tail.\n[n.] A sound of liquid flowing inside a container.\n[v.] To make a rustling sound while moving.\n[v.] To flourish with a swishing sound.\n[v.] To flog; to lash.","ex":"The cane swishes."},"SWISS":{"p":"/swɪs/","s":"v.","e":"[v.] To prepare (meat, fabric, etc.) by rolling or pounding in order to soften it.","ex":""},"SWORD":{"p":"/sɔːd/","s":"n.","e":"[n.] A long-bladed weapon with a hilt, and usually a pommel and cross-guard, which is designed to stab, slash, and/or hack.\n[n.] A suit in the minor arcana in tarot.\n[n.] A card of this suit.","ex":""},"SYRUP":{"p":"/ˈsɪ.ɹəp/","s":"n.","e":"[n.] Any thick liquid that has a high sugar content and which is added to or poured over food as a flavouring.\n[n.] (by extension) Any viscous liquid.\n[n.] (shortened from \"syrup of figs\") A wig.","ex":"maple syrup"},"SYMBOL":{"p":"/ˈsɪmbəl/","s":"n./v.","e":"[n.] A character or glyph representing an idea, concept or object.\n[n.] A thing considered the embodiment of a concept or object.\n[n.] A type of noun whereby the form refers to the same entity independently of the context; a symbol arbitrarily denotes a referent. See also icon and index.\n[v.] To symbolize.","ex":"$ is the symbol for dollars in the US and some other countries."},"TACIT":{"p":"/ˈtæsɪt/","s":"adj.","e":"[adj.] Expressed in silence; implied, but not made explicit; silent.\n[adj.] Not derived from formal principles of reasoning; based on induction rather than deduction.","ex":"tacit consent : consent by silence, or by not raising an objection"},"TABOO":{"p":"/tæˈbuː/","s":"n./v./adj.","e":"[n.] An inhibition or ban that results from social custom or emotional aversion.\n[n.] (in Polynesia) Something which may not be used, approached or mentioned because it is sacred.\n[v.] To mark as taboo.\n[v.] To ban.\n[v.] To avoid.\n[adj.] Excluded or forbidden from use, approach or mention.","ex":""},"TACKS":{"p":"/tæks/","s":"n./v.","e":"[n.] A small nail with a flat head.\n[n.] A thumbtack.\n[n.] A loose seam used to temporarily fasten pieces of cloth.\n[v.] To nail with a tack (small nail with a flat head).\n[v.] To sew/stich with a tack (loose seam used to temporarily fasten pieces of cloth).\n[v.] To maneuver a sailing vessel so that its bow turns through the wind, i.e. the wind changes from one side of the vessel to the other.","ex":"a musty tack"},"TACKY":{"p":"/ˈtæki/","s":"adj.","e":"[adj.] Of a substance, slightly sticky.","ex":"This paint isn't dry yet; it's still a bit tacky."},"TAIL":{"p":"/teɪl/","s":"n./v.","e":"[n.] The caudal appendage of an animal that is attached to its posterior and near the anus.\n[n.] An object or part of an object resembling a tail in shape, such as the thongs on a cat-o'-nine-tails.\n[n.] The back, last, lower, or inferior part of anything.\n[v.] To follow and observe surreptitiously.\n[v.] To hold by the end; said of a timber when it rests upon a wall or other support; with in or into\n[v.] To swing with the stern in a certain direction; said of a vessel at anchor.","ex":"Most primates have a tail and fangs."},"TAKES":{"p":"/teɪks/","s":"n./v.","e":"[n.] The or an act of taking.\n[n.] Something that is taken; a haul.\n[n.] An interpretation or view, opinion or assessment; perspective.\n[v.] To get into one's hands, possession or control, with or without force.\n[v.] To receive or accept (something) (especially something given or bestowed, awarded, etc).\n[v.] To remove.","ex":"What's your take on this issue, Fred?"},"TALCS":{"p":"/tælks/","s":"n./v.","e":"[n.] Originally a large range of transparent or glistening foliated minerals. Examples include mica, selenite and the hydrated magnesium silicate that the term talc generally has referred to in modern times (see below). Also an item made of such a mineral and depending for its function on the special nature of the mineral (see next). Mediaeval writers adopted the term from the Arabic.\n[n.] A microscope slide made of a plate of mica, generally in use from the start of modern microscopy until the early nineteenth century, after which glass slides became the standard medium.\n[n.] A soft mineral, composed of hydrated magnesium silicate, that has a soapy feel and a greenish, whitish, or grayish color, and usually occurs in foliated masses.\n[v.] To apply talc to.","ex":""},"SYSTEM":{"p":"/ˈsɪstəm/","s":"n.","e":"[n.] A collection of organized things; a whole composed of relationships among its members.\n[n.] A method or way of organizing or planning.","ex":"There are eight planets in the solar system."},"TALKS":{"p":"/ˈtɔːks/","s":"v./n.","e":"[v.] To communicate, usually by means of speech.\n[v.] To discuss; to talk about.\n[v.] To speak (a certain language).\n[n.] A conversation or discussion; usually serious, but informal.\n[n.] A lecture.\n[n.] Gossip; rumour.","ex":"Although I don't speak Chinese I managed to talk with the villagers using signs and gestures."},"TALLY":{"p":"/ˈtæli/","s":"int.","e":"[int.] Target sighted.","ex":"(Air Traffic Control): Speedbird 123, New York, traffic at two o’clock, seven miles, a Boeing 737, west-bound, at 4000 feet.”"},"TAINT":{"p":"/teɪnt/","s":"n./v.","e":"[n.] A contamination, decay or putrefaction, especially in food\n[n.] A mark of disgrace, especially on one's character; blemish\n[n.] Tincture; hue; colour\n[v.] To contaminate or corrupt (something) with an external agent, either physically or morally.\n[v.] To spoil (food) by contamination.\n[v.] To be infected or corrupted; to be touched by something corrupting.","ex":""},"TAMED":{"p":"","s":"v./adj.","e":"[v.] To make (an animal) tame; to domesticate.\n[v.] To become tame or domesticated.\n[v.] To make gentle or meek.\n[v.] To broach or enter upon; to taste, as a liquor; to divide; to distribute; to deal out.\n[adj.] Domesticated; made tame","ex":"He tamed the wild horse."},"TAKEN":{"p":"/ˈteɪkən/","s":"v./adj.","e":"[v.] To get into one's hands, possession or control, with or without force.\n[v.] To receive or accept (something) (especially something given or bestowed, awarded, etc).\n[v.] To remove.\n[adj.] Infatuated; fond of or attracted to.\n[adj.] In a serious romantic relationship.","ex":"I'll take that plate off the table."},"TANGO":{"p":"/ˈtæŋɡəʊ/","s":"n./v.","e":"[n.] A Standard ballroom dance in 4/4 time; or a social dance, the Argentine tango.\n[n.] A piece of music suited to such a dance.\n[n.] The letter T in the ICAO spelling alphabet.\n[v.] To dance the tango.\n[v.] To mingle or interact (with each other).","ex":""},"TANGY":{"p":"/ˈtæŋiː/","s":"adj.","e":"[adj.] Having a sharp, pungent flavor","ex":""},"TAPE":{"p":"/teɪ̯p/","s":"n./v.","e":"[n.] Flexible material in a roll with a sticky surface on one or both sides; adhesive tape.\n[n.] Thin and flat paper, plastic or similar flexible material, usually produced in the form of a roll.\n[n.] Finishing tape, stretched across a track to mark the end of a race.\n[v.] To bind with adhesive tape.\n[v.] To record, particularly onto magnetic tape.\n[v.] (passive) To understand, figure out.","ex":"Hand me some tape. I need to fix a tear in this paper."},"TAPER":{"p":"/ˈteɪpə/","s":"n./v./adj.","e":"[n.] A slender wax candle; a small lighted wax candle\n[n.] (by extension) a small light.\n[n.] A tapering form; gradual diminution of thickness and/or cross section in an elongated object\n[v.] To make thinner or narrower at one end.\n[v.] To diminish gradually.\n[adj.] Tapered; narrowing to a point.","ex":"The legs of the table had a slight taper to them."},"TABLE":{"p":"/ˈteɪbəl/","s":"n./v.","e":"[n.] Furniture with a top surface to accommodate a variety of uses.\n[n.] A two-dimensional presentation of data.\n[n.] The top of a stringed instrument, particularly a member of the violin family: the side of the instrument against which the strings vibrate.\n[v.] To tabulate; to put into a table or grid.\n[v.] To supply (a guest, client etc.) with food at a table; to feed.\n[v.] To delineate; to represent, as in a picture; to depict.","ex":"to table fines"},"TAPES":{"p":"","s":"n./v.","e":"[n.] Flexible material in a roll with a sticky surface on one or both sides; adhesive tape.\n[n.] Thin and flat paper, plastic or similar flexible material, usually produced in the form of a roll.\n[n.] Finishing tape, stretched across a track to mark the end of a race.\n[v.] To bind with adhesive tape.\n[v.] To record, particularly onto magnetic tape.\n[v.] (passive) To understand, figure out.","ex":"Hand me some tape. I need to fix a tear in this paper."},"TALKY":{"p":"","s":"adj.","e":"[adj.] (of a person) Talkative or loquacious\n[adj.] (of a book etc.) Containing a great deal of dialogue or talking in general","ex":""},"TANKS":{"p":"","s":"n./v.","e":"[n.] A closed container for liquids or gases.\n[n.] An open container or pool for storing water or other liquids.\n[n.] A pond, pool, or small lake, natural or artificial.\n[v.] To fail or fall (often used in describing the economy or the stock market); to degenerate or decline rapidly; to plummet.\n[v.] To attract the attacks of an enemy target in cooperative team-based combat, so that one's teammates can defeat the enemy in question more efficiently.\n[v.] To put (fuel, etc.) into a tank.","ex":""},"TAPIR":{"p":"/ˈteɪpiːə(ɹ)/","s":"n.","e":"[n.] Any one of the species of large odd-toed ungulates of the taxonomic family Tapiridae with a long prehensile upper lip, of which all four surviving species are in genus Tapirus.","ex":""},"TABBY":{"p":"/ˈtæb.i/","s":"n./v./adj.","e":"[n.] A kind of waved silk, usually called watered silk, manufactured like taffeta, but thicker and stronger. The watering is given to it by calendering.\n[n.] A mixture of lime with shells, gravel, or stones, in equal proportions, with an equal proportion of water. When dry, this becomes as hard as rock.\n[n.] A brindled cat.\n[v.] To give a wavy or watered appearance to (a textile).\n[adj.] Having a wavy or watered appearance\n[adj.] Brindled; diversified in color","ex":"a tabby waistcoat"},"TARRY":{"p":"/ˈtæ.ɹi/","s":"n./v.","e":"[n.] A sojourn.\n[v.] To delay; to be late or tardy in beginning or doing anything.\n[v.] To linger in expectation of something or until something is done or happens.\n[v.] To abide, stay or wait somewhere, especially if longer than planned.","ex":""},"TAPED":{"p":"","s":"v.","e":"[v.] To bind with adhesive tape.\n[v.] To record, particularly onto magnetic tape.\n[v.] (passive) To understand, figure out.","ex":"Be sure to tape your parcel securely before posting it."},"TALK":{"p":"/toːk/","s":"v.","e":"[v.] To communicate, usually by means of speech.\n[v.] To discuss; to talk about.\n[v.] To speak (a certain language).","ex":"Although I don't speak Chinese I managed to talk with the villagers using signs and gestures."},"TASTY":{"p":"/ˈteɪsti/","s":"adj.","e":"[adj.] Having a pleasant or satisfying flavor; delicious.\n[adj.] Having or showing good taste; tasteful.\n[adj.] Appealing; when applied to persons, sexually appealing.","ex":"You could make this tasty meal for breakfast."},"TARGET":{"p":"/tɑːɡɪt/","s":"n./v.","e":"[n.] A butt or mark to shoot at, as for practice, or to test the accuracy of a firearm, or the force of a projectile.\n[n.] A goal or objective.\n[n.] A kind of small shield or buckler, used as a defensive weapon in war.\n[v.] To aim something, especially a weapon, at (a target).\n[v.] To aim for as an audience or demographic.\n[v.] To produce code suitable for.","ex":"Take careful aim at the target."},"TARNS":{"p":"/tɑː(ɹ)nz/","s":"n.","e":"[n.] A small mountain lake, especially in Northern England.\n[n.] (chiefly Montana) One of many small mountain lakes or ponds.","ex":""},"TATER":{"p":"/ˈteɪtə/","s":"n.","e":"[n.] A potato.\n[n.] A home run","ex":"We ate them taters up real good."},"TASER":{"p":"/ˈteɪ.zə(ɹ)/","s":"n./v.","e":"[n.] A Taser, a handheld device made by Taser International intended to immobilize another by delivering an electric shock.\n[n.] (by extension) Any electroshock stun gun.\n[v.] To shock a person, thing, individual, or animal with a handheld device with the electric shock that it delivers; to stun with a stun gun.\n[v.] To strike verbally or gesturally with ill intents.","ex":"As I spoke too loudly during the solemn church service, my husband shot me a glance that emotionally tasered me to the point of silence until we returned home 2 hours later."},"TAWNY":{"p":"/ˈtɔːni/","s":"n./adj.","e":"[n.] A light brown to brownish orange colour.\n[adj.] Of a light brown to brownish orange color.\n[adj.] A sweet, fortified wine which is blended and matured in wood.","ex":""},"TAXIS":{"p":"/ˈtæksɪs/","s":"n.","e":"[n.] The directional movement of an organism in response to a stimulus.\n[n.] The manipulation of a body part into its normal position after injury.\n[n.] The arrangement of the parts of a topic.","ex":""},"TEACHER":{"p":"/ˈtiːt͡ʃə/","s":"n.","e":"[n.] A person who teaches, especially one employed in a school.\n[n.] The index finger; the forefinger.\n[n.] An indication; a lesson.","ex":""},"TEAM":{"p":"/tiːm/","s":"n./v.","e":"[n.] A set of draught animals, such as two horses in front of a carriage.\n[n.] Any group of people involved in the same activity, especially sports or work.\n[n.] A group of animals moving together, especially young ducks.\n[v.] To form a group, as for sports or work.\n[v.] (by extension) To go together well; to harmonize.\n[v.] To convey or haul with a team.","ex":"The IT manager leads a team of three software developers."},"TEAR":{"p":"","s":"n./v.","e":"[n.] A hole or break caused by tearing.\n[n.] A rampage.\n[v.] To rend (a solid material) by holding or restraining in two places and pulling apart, whether intentionally or not; to destroy or separate.\n[v.] To injure as if by pulling apart.\n[v.] To destroy or reduce abstract unity or coherence, such as social, political or emotional.","ex":"A small tear is easy to mend, if it is on the seam."},"TARGE":{"p":"/tɑːd͡ʒ/","s":"n.","e":"[n.] A small shield\n[n.] A tassel or pendant","ex":""},"TATTY":{"p":"/ˈtæti/","s":"n.","e":"[n.] Potato","ex":""},"TARES":{"p":"","s":"n./v.","e":"[n.] A vetch, or the seed of a vetch (genus Vicia, esp. Vicia sativa)\n[n.] Any of the tufted grasses of genus Lolium; darnel.\n[n.] A damaging weed growing in fields of grain.\n[n.] The empty weight of a container; the tare weight or unladen weight.\n[v.] To take into account the weight of the container, wrapping etc. in weighting merchandise.\n[v.] To set a zero value on an instrument (usually a balance) that discounts the starting point.","ex":""},"TEARS":{"p":"/tiːɹz/","s":"n./v.","e":"[n.] A hole or break caused by tearing.\n[n.] A rampage.\n[v.] To rend (a solid material) by holding or restraining in two places and pulling apart, whether intentionally or not; to destroy or separate.\n[v.] To injure as if by pulling apart.\n[v.] To destroy or reduce abstract unity or coherence, such as social, political or emotional.\n[n.] A drop of clear, salty liquid produced from the eyes by crying or irritation.","ex":"A small tear is easy to mend, if it is on the seam."},"TEDDY":{"p":"/ˈtɛdi/","s":"n.","e":"[n.] By extension, any stuffed toy.\n[n.] A type of all-in-one piece of women's underwear.\n[n.] A plush toy in the shape of a bear.\n[n.] A lovable, endearing, large, strong, hairy, or sweet man","ex":""},"TASKS":{"p":"/tæsks/","s":"n./v.","e":"[n.] A piece of work done as part of one’s duties.\n[n.] A difficult or tedious undertaking.\n[n.] An objective.\n[v.] To assign a task to, or impose a task on.\n[v.] To oppress with severe or excessive burdens; to tax.\n[v.] To charge, as with a fault.","ex":"On my first day in the office, I was tasked with sorting a pile of invoices."},"TEETH":{"p":"/tiːθ/","s":"n./v.","e":"[n.] The ability to be enforced, or to be enforced to any useful effect.\n[v.] To grow teeth.\n[v.] To bite on something to relieve discomfort caused by growing teeth.\n[n.] A hard, calcareous structure present in the mouth of many vertebrate animals, generally used for eating.\n[n.] A sharp projection on the blade of a saw or similar implement.\n[n.] A projection on the edge of a gear that meshes with similar projections on adjacent gears, or on the circumference of a cog that engages with a chain.","ex":"The international community's sanctions against the regime had some teeth to them this time around."},"TEENS":{"p":"/tiːnz/","s":"n.","e":"[n.] A teenager.\n[n.] Grief; sorrow; trouble.\n[n.] Vexation; anger; hate.\n[n.] The numbers between thirteen and nineteen.\n[n.] The time of life between thirteen and nineteen years old; the teenage years.\n[n.] The second decade of a century: the 1910s, 2010s, etc. The oneties, the tens.","ex":"The number of people at the meeting was in the teens."},"TELL":{"p":"/tɛl/","s":"n./v.","e":"[n.] A reflexive, often habitual behavior, especially one occurring in a context that often features attempts at deception by persons under psychological stress (such as a poker game or police interrogation), that reveals information that the person exhibiting the behavior is attempting to withhold.\n[n.] That which is told; a tale or account.\n[n.] A private message to an individual in a chat room; a whisper.\n[v.] (archaic outside of idioms) To count, reckon, or enumerate.\n[v.] To narrate.\n[v.] To convey by speech; to say.","ex":"All told, there were over a dozen.  Can you tell time on a clock?  He had untold wealth."},"TAXED":{"p":"","s":"v./adj.","e":"[v.] To impose and collect a tax from (a person or company).\n[v.] To impose and collect a tax on (something).\n[v.] To make excessive demands on.\n[adj.] Subject to taxation.","ex":"Some think to tax the wealthy is the fairest."},"TEMPI":{"p":"/ˈtɛmpiː/","s":"n.","e":"[n.] A frequency or rate.\n[n.] A move which is part of one's own plan or strategy and forces, e.g. by means of a check or attacking a piece, the opponent to make a move which is not bad but of no use for him (the player gains a tempo, the opponent loses a tempo), or equivalently a player achieves the same result in fewer moves by one approach rather than another.\n[n.] The timing advantage of being on lead, thus being first to initiate a strategy to develop tricks for one's side.","ex":""},"TEMPO":{"p":"/ˈtɛm.pəʊ/","s":"n.","e":"[n.] A frequency or rate.\n[n.] A move which is part of one's own plan or strategy and forces, e.g. by means of a check or attacking a piece, the opponent to make a move which is not bad but of no use for him (the player gains a tempo, the opponent loses a tempo), or equivalently a player achieves the same result in fewer moves by one approach rather than another.\n[n.] The timing advantage of being on lead, thus being first to initiate a strategy to develop tricks for one's side.","ex":""},"TEMPT":{"p":"/tɛmpt/","s":"v.","e":"[v.] To provoke someone to do wrong, especially by promising a reward; to entice.\n[v.] To attract; to allure.\n[v.] To provoke something; to court.","ex":"She tempted me to eat the apple."},"TENDER":{"p":"/ˈtɛn.də(ɹ)/","s":"n./adj.","e":"[n.] Care, kind concern, regard.\n[n.] The inner flight muscle (pectoralis minor) of poultry.\n[adj.] Sensitive or painful to the touch.\n[adj.] Easily bruised or injured; not firm or hard; delicate.\n[adj.] Physically weak; not able to endure hardship.","ex":"tender plants; tender flesh; tender fruit"},"TEEN":{"p":"/tiːn/","s":"n./adj.","e":"[n.] A teenager.\n[adj.] Of or having to do with teenagers; teenage","ex":"teen fashion"},"TEMPLE":{"p":"/ˈtɛmp(ə)l/","s":"n./v.","e":"[n.] A house of worship, especially:\n[n.] A meeting house of the Oddfellows fraternity; its members.\n[n.] Any place regarded as holding a religious presence.\n[v.] To build a temple for; to appropriate a temple to; to temple a god","ex":""},"TELIC":{"p":"/ˈtiːlɪk/","s":"adj.","e":"[adj.] Tending or directed towards a goal or specific end.\n[adj.] (grammar) That expresses an end or purpose.\n[adj.] That expresses the perfective aspect.","ex":""},"TEENY":{"p":"/ˈtiːni/","s":"adj.","e":"[adj.] Very small; tiny.","ex":""},"TEPID":{"p":"/ˈtɛpɪd/","s":"adj.","e":"[adj.] Lukewarm; neither warm nor cool.\n[adj.] Uninterested; exhibiting little passion or eagerness.","ex":"I'm drinking a cup of tepid water."},"TENDS":{"p":"/tɛndz/","s":"v.","e":"[v.] (Old English law) To make a tender of; to offer or tender.\n[v.] (followed by a to-infinitive) To be likely, or probable to do something, or to have a certain habit or leaning.\n[v.] To contribute to or toward some outcome.\n[v.] (with to) To look after (e.g. an ill person.)\n[v.] To accompany as an assistant or protector; to care for the wants of; to look after; to watch; to guard.\n[v.] To wait (upon), as attendants or servants; to serve; to attend.","ex":"It tends to snow here in winter."},"TENT":{"p":"/tɛnt/","s":"n./v.","e":"[n.] A pavilion or portable lodge consisting of skins, canvas, or some strong cloth, stretched and sustained by poles, used for sheltering people from the weather.\n[n.] The representation of a tent used as a bearing.\n[n.] A portable pulpit set up outside to accommodate worshippers who cannot fit into a church.\n[v.] To go camping.\n[v.] To prop up aluminum foil in an inverted \"V\" (reminiscent of a pop-up tent) over food to reduce splatter, before putting it in the oven.\n[v.] To form into a tent-like shape.","ex":"We were camping in a three-man tent."},"TENSE":{"p":"/tɛns/","s":"n./v.","e":"[n.] (grammar) Any of the forms of a verb which distinguish when an action or state of being occurs or exists.\n[n.] (grammar) An inflected form of a verb that indicates tense.\n[n.] The property of indicating the point in time at which an action or state of being occurs or exists.\n[v.] (grammar) To apply a tense to.","ex":"English only has a present tense and a past tense; it has no future tense."},"TELLING":{"p":"/ˈtɛlɪŋ/","s":"v./adj.","e":"[v.] (archaic outside of idioms) To count, reckon, or enumerate.\n[v.] To narrate.\n[v.] To convey by speech; to say.\n[adj.] Having force, or having a marked effect; weighty, effective.\n[adj.] Revealing information; bearing significance.\n[adj.] Serving to convince.","ex":"All told, there were over a dozen.  Can you tell time on a clock?  He had untold wealth."},"TERM":{"p":"/tɜːm/","s":"n./v./adj.","e":"[n.] That which limits the extent of anything; limit, extremity, bound, boundary.\n[n.] A chronological limitation or restriction.\n[n.] Any of the binding conditions or promises in a legal contract.\n[v.] To phrase a certain way; to name or call.\n[adj.] Born or delivered at term.","ex":"\"Alright, look...we can spend the holidays with your parents, but this time it will be on my terms.\""},"TEST":{"p":"/test/","s":"n./v.","e":"[n.] A challenge, trial.\n[n.] A cupel or cupelling hearth in which precious metals are melted for trial and refinement.\n[n.] (academia) An examination, given often during the academic term.\n[v.] To challenge.\n[v.] To refine (gold, silver, etc.) in a test or cupel; to subject to cupellation.\n[v.] To put to the proof; to prove the truth, genuineness, or quality of by experiment, or by some principle or standard; to try.","ex":"Climbing the mountain tested our stamina."},"TESTY":{"p":"/ˈtɛsti/","s":"adj.","e":"[adj.] Easily annoyed, irritable.\n[adj.] Marked by impatience or ill humor.","ex":"He made testy remarks."},"TERNS":{"p":"/ˈtɜː(ɹ)nz/","s":"n.","e":"[n.] Any of various sea birds of the family Sternidae that are similar to gulls but are smaller and have a forked tail.\n[n.] That which consists of, or pertains to, three things or numbers together.\n[n.] A lottery prize resulting from the favourable combination of three numbers in the draw.","ex":""},"TERRACE":{"p":"/ˈtɛɹəs/","s":"n./v.","e":"[n.] A platform that extends outwards from a building.\n[n.] A raised, flat-topped bank of earth with sloping sides, especially one of a series for farming or leisure; a similar natural area of ground, often next to a river.\n[n.] A row of residential houses with no gaps between them; a group of row houses.\n[v.] To provide something with a terrace.\n[v.] To form something into a terrace.","ex":""},"TENET":{"p":"/ˈtɛnət/","s":"n.","e":"[n.] An opinion, belief, or principle that is held as absolute truth by someone or especially an organization.","ex":""},"TENTH":{"p":"/tɛnθ/","s":"n./v./adj.","e":"[n.] The person or thing coming next after the ninth in a series; that which is in the tenth position.\n[n.] One of ten equal parts of a whole.\n[n.] The interval between any tone and the tone represented on the tenth degree of the staff above it, as between one of the scale and three of the octave above; the octave of the third.\n[v.] To divide by ten, into tenths.\n[adj.] The ordinal numeral form of ten; next in order after that which is ninth.\n[adj.] Being one of ten equal parts of a whole.","ex":""},"TENTS":{"p":"/tɛnts/","s":"n./v.","e":"[n.] A pavilion or portable lodge consisting of skins, canvas, or some strong cloth, stretched and sustained by poles, used for sheltering people from the weather.\n[n.] The representation of a tent used as a bearing.\n[n.] A portable pulpit set up outside to accommodate worshippers who cannot fit into a church.\n[v.] To go camping.\n[v.] To prop up aluminum foil in an inverted \"V\" (reminiscent of a pop-up tent) over food to reduce splatter, before putting it in the oven.\n[v.] To form into a tent-like shape.","ex":"We were camping in a three-man tent."},"THAT":{"p":"/ˈðæt/","s":"n./adv./pron./conj.","e":"[n.] Something being indicated that is there; one of those.\n[adv.] (degree) To a given extent or degree.\n[adv.] (degree) To a great extent or degree; very, particularly (in negative constructions).\n[adv.] To such an extent; so. (in positive constructions).\n[pron.] (demonstrative) The thing, person, idea, quality, event, action or time indicated or understood from context, especially if more remote geographically, temporally or mentally than one designated as \"this\", or if expressing distinction.\n[pron.] The known (thing); used to refer to something just said.","ex":"\"The ribbon was that thin.\" \"I disagree, I say it was not that thin, it was thicker... or maybe thinner...\""},"TEXTILE":{"p":"/ˈtɛks.taɪl/","s":"n./adj.","e":"[n.] (usually in the plural) Any material made of interlacing fibres, including carpeting and geotextiles.\n[n.] (naturism) A non-nudist.\n[adj.] (naturism) Clothing compulsive.","ex":"A textile beach"},"TEXT":{"p":"/tɛkst/","s":"n./v.","e":"[n.] A writing consisting of multiple glyphs, characters, symbols or sentences.\n[n.] A book, tome or other set of writings.\n[n.] A brief written message transmitted between mobile phones.\n[v.] To send a text message to; i.e. to transmit text using the Short Message Service (SMS), or a similar service, between communications devices, particularly mobile phones.\n[v.] To send and receive text messages.\n[v.] To write in large characters, as in text hand.","ex":"I'll text the address to you as soon as I find it."},"THEM":{"p":"/ðʌm/","s":"pron.","e":"[pron.] (plural) Those ones.\n[pron.] (singular) Him, her, or it; that one.","ex":""},"THEN":{"p":"/ðen/","s":"conj./n./adj./adv.","e":"[conj.] Used in comparisons, to introduce the basis of comparison.\n[conj.] (obsolete outside dialectal, usually used with for) Because; for.\n[n.] That time\n[adj.] Being so at that time.\n[adv.] (temporal location) At that time.\n[adv.] (temporal location) Soon afterward.","ex":"she's taller than I am;  she found his advice more witty than helpful;  we have less work today than we had yesterday;  We had no choice than to return home"},"THEFT":{"p":"/θɛft/","s":"n.","e":"[n.] The act of stealing property.","ex":""},"THEATER":{"p":"/ˈθi(ə)tɚ/","s":"n.","e":"[n.] A place or building, consisting of a stage and seating, in which an audience gathers to watch plays, musical performances, public ceremonies, and so on.\n[n.] A region where a particular action takes place; a specific field of action, usually with reference to war.\n[n.] A lecture theatre.","ex":"His grandfather was in the Pacific theater during the war."},"THAWS":{"p":"","s":"n./v.","e":"[n.] The melting of ice, snow, or other congealed matter; the resolution of ice, or the like, into the state of a fluid; liquefaction by heat of anything congealed by frost\n[n.] A warmth of weather sufficient to melt that which is frozen\n[v.] To gradually melt, dissolve, or become fluid; to soften from frozen\n[v.] To become so warm as to melt ice and snow — said in reference to the weather, and used impersonally.\n[v.] To grow gentle or genial.","ex":"the ice thaws"},"THERAPY":{"p":"/ˈθɛɹ.ə.pi/","s":"n./v.","e":"[n.] Attempted remediation of a health problem following a diagnosis, usually synonymous with treatment.\n[n.] Healing power or quality.\n[v.] To treat with a therapy.\n[v.] To undergo a therapy.","ex":""},"THIGH":{"p":"/θaɪ/","s":"n.","e":"[n.] The upper leg of a human, between the hip and the knee.\n[n.] That part of the leg of vertebrates (or sometimes other animals) which corresponds to the human thigh in position or function; the tibia of a horse, the tarsus of a bird; the third leg-section of an insect.","ex":""},"THIRD":{"p":"/θɜːd/","s":"n./v./adj.","e":"[n.] The person or thing in the third position.\n[n.] One of three equal parts of a whole.\n[n.] The third gear of a gearbox.\n[v.] To agree with a proposition or statement after it has already been seconded.\n[v.] To divide into three equal parts.\n[adj.] The ordinal form of the cardinal number three; Coming after the second.","ex":"Jones came in third."},"THINK":{"p":"/θɪŋk/","s":"n./v.","e":"[n.] An act of thinking; consideration (of something).\n[v.] To ponder, to go over in one's head.\n[v.] To communicate to oneself in one's mind, to try to find a solution to a problem.\n[v.] To conceive of something or someone (usually followed by of; infrequently, by on).","ex":"I'll have a think about that and let you know."},"THEME":{"p":"/θiːm/","s":"n./v.","e":"[n.] A subject of a talk or an artistic piece; a topic.\n[n.] A recurring idea; a motif.\n[n.] An essay written for school.\n[v.] To give a theme to.\n[v.] To apply a theme to; to change the visual appearance and/or layout of (software).","ex":"We themed the birthday party around superheroes."},"THIN":{"p":"/ˈθɪn/","s":"n./v./adj./adv.","e":"[n.] A loss or tearing of paper from the back of a stamp, although not sufficient to create a complete hole.\n[n.] Any food produced or served in thin slices.\n[v.] To make thin or thinner.\n[v.] To become thin or thinner.\n[v.] To dilute.\n[adj.] Having little thickness or extent from one surface to its opposite.","ex":"chocolate mint thins"},"TEXTS":{"p":"/tɛks/","s":"n./v.","e":"[n.] A writing consisting of multiple glyphs, characters, symbols or sentences.\n[n.] A book, tome or other set of writings.\n[n.] A brief written message transmitted between mobile phones.\n[v.] To send a text message to; i.e. to transmit text using the Short Message Service (SMS), or a similar service, between communications devices, particularly mobile phones.\n[v.] To send and receive text messages.\n[v.] To write in large characters, as in text hand.","ex":"I'll text the address to you as soon as I find it."},"THANE":{"p":"/θeɪn/","s":"n.","e":"[n.] A rank of nobility in pre-Norman England, roughly equivalent to baron.","ex":""},"THIS":{"p":"/ðəs/","s":"n./adv./pron./int.","e":"[n.] Something being indicated that is here; one of these.\n[n.] Referring to the current context in a programming environment in C-like languages.\n[adv.] To the degree or extent indicated.\n[pron.] The thing, item, etc. being indicated.\n[int.] Indicates the speaker's strong approval or agreement with the previous material.","ex":"Do we need this many recommendations?"},"THOSE":{"p":"/ðəʊz/","s":"pron.","e":"[pron.] (demonstrative) The thing, person, idea, quality, event, action or time indicated or understood from context, especially if more remote geographically, temporally or mentally than one designated as \"this\", or if expressing distinction.\n[pron.] The known (thing); used to refer to something just said.\n[pron.] (demonstrative) The aforementioned quality or proposition; used to emphatically affirm or deny a previous statement or question.","ex":"He went home, and after that I never saw him again."},"THROWN":{"p":"/θɹəʊn/","s":"v./adj.","e":"[v.] To change place.\n[v.] To change in state or status\n[v.] To move through time.\n[v.] To hurl; to cause an object to move rapidly through the air.\n[v.] To eject or cause to fall off.\n[v.] To move to another position or condition; to displace.","ex":"throw a shoe; throw a javelin; the horse threw its rider"},"THYME":{"p":"/taɪm/","s":"n.","e":"[n.] Any plant of the labiate genus Thymus, such as the garden thyme, Thymus vulgaris, a warm, pungent aromatic, that is much used to give a relish to seasoning and soups.","ex":""},"TIBIA":{"p":"","s":"n.","e":"[n.] The inner and usually the larger of the two bones of the leg or hind limb below the knee, the shinbone\n[n.] The second segment from the end of an insect's leg, between the femur and tarsus.\n[n.] The third segment from the end of an arachnid's leg, between the patella and metatarsus.","ex":""},"TICKS":{"p":"/tɪks/","s":"n./v.","e":"[n.] A tiny woodland arachnid of the suborder Ixodida.\n[n.] A relatively quiet but sharp sound generally made repeatedly by moving machinery.\n[n.] A mark on any scale of measurement; a unit of measurement.\n[n.] A jiffy (unit of time defined by basic timer frequency).\n[v.] To make a clicking noise similar to the movement of the hands in an analog clock.\n[v.] To make a tick or checkmark.","ex":"The steady tick of the clock provided a comforting background for the conversation."},"THONG":{"p":"/θɒŋ/","s":"n.","e":"[n.] A strip of leather.\n[n.] (usually in the plural) An item of footwear, usually of rubber, secured by two straps which join to pass between the big toe and its neighbour.\n[n.] An undergarment or swimwear consisting of very narrow strips designed to cover just the genitals and nothing more.","ex":"No! I won't buy you a thong. You're too young for that."},"TIED":{"p":"/taɪd/","s":"v./adj.","e":"[v.] To twist (a string, rope, or the like) around itself securely.\n[v.] To form (a knot or the like) in a string or the like.\n[v.] To attach or fasten (one thing to another) by string or the like.\n[adj.] Closely connected or associated.\n[adj.] Restricted.\n[adj.] Conditional on other agreements being upheld.","ex":"Tie the rope to this tree."},"THREW":{"p":"/θɹuː/","s":"v.","e":"[v.] To change place.\n[v.] To change in state or status\n[v.] To move through time.\n[v.] To hurl; to cause an object to move rapidly through the air.\n[v.] To eject or cause to fall off.\n[v.] To move to another position or condition; to displace.","ex":"throw a shoe; throw a javelin; the horse threw its rider"},"TILED":{"p":"","s":"v./adj.","e":"[v.] To cover with tiles.\n[v.] To arrange in a regular pattern, with adjoining edges (applied to tile-like objects, graphics, windows in a computer interface).\n[v.] To optimize (a loop in program code) by means of the tiling technique.\n[v.] To protect from the intrusion of the uninitiated.\n[adj.] Constructed from, or decorated with tiles","ex":"The handyman tiled the kitchen."},"TILL":{"p":"/tɪl/","s":"prep./conj.","e":"[prep.] Until; to, up to; as late as (a given time).\n[prep.] To, up to (physically).\n[prep.] To make it possible that.\n[conj.] Until, until the time that.","ex":"I have to work till eight o'clock tonight."},"TILTS":{"p":"","s":"n./v.","e":"[n.] A slope or inclination.\n[n.] The inclination of part of the body, such as backbone, pelvis, head, etc.\n[n.] The controlled vertical movement of a camera, or a device to achieve this.\n[v.] To slope or incline (something); to slant.\n[v.] (jousting) To charge (at someone) with a lance.\n[v.] To be at an angle.","ex":"Tilt the barrel to pour out its contents."},"TOADY":{"p":"","s":"n./v.","e":"[n.] A sycophant who flatters others to gain personal advantage or an obsequious lackey or minion\n[n.] A coarse, rustic woman.\n[v.] (construed with to) To behave like a toady (to someone).","ex":""},"THROW":{"p":"/θɹəʊ/","s":"v./n.","e":"[v.] To change place.\n[v.] To change in state or status\n[v.] To move through time.\n[n.] The flight of a thrown object.\n[n.] The act of throwing something.\n[n.] One's ability to throw.","ex":"What a great throw by the quarterback!"},"THUS":{"p":"/ˈðʌs/","s":"adv.","e":"[adv.] (manner) In this way or manner.\n[adv.] As a result.","ex":"If you throw the ball thus, as I’m showing you, you’ll have better luck hitting the target."},"TIMES":{"p":"/tɑemz/","s":"n./v./prep.","e":"[n.] The inevitable progression into the future with the passing of present and past events.\n[n.] A duration of time.\n[n.] An instant of time.\n[v.] To measure or record the time, duration, or rate of.\n[v.] To choose when something begins or how long it lasts.\n[v.] To keep or beat time; to proceed or move in time.","ex":"Time stops for nobody.   the ebb and flow of time"},"TITHE":{"p":"/taɪð/","s":"n./v./adj.","e":"[n.] A tenth.\n[n.] The tenth part of the increase arising from the profits of land and stock, allotted to the clergy for their support, as in England, or devoted to religious or charitable uses.\n[n.] A contribution to one's religious community or congregation of worship (notably to the LDS church)\n[v.] To give one-tenth or a tithe of something, particularly:\n[v.] To take one-tenth or a tithe of something, particularly:\n[v.] To compose the tenth part of something.","ex":""},"TISSUE":{"p":"/ˈtɪsjuː/","s":"n./v.","e":"[n.] Thin, woven, gauze-like fabric.\n[n.] A fine transparent silk material, used for veils, etc.; specifically, cloth interwoven with gold or silver threads, or embossed with figures.\n[n.] A sheet of absorbent paper, especially one that is made to be used as tissue paper, toilet paper or a handkerchief.\n[v.] To form tissue of; to interweave.","ex":""},"TIDED":{"p":"","s":"v./adj.","e":"[v.] To cause to float with the tide; to drive or carry with the tide or stream.\n[v.] To pour a tide or flood.\n[v.] To work into or out of a river or harbor by drifting with the tide and anchoring when it becomes adverse.\n[v.] To happen, occur.\n[adj.] Affected by the tide; having a tide.","ex":"The ocean tided most impressively."},"TODAY":{"p":"/təˈdeɪ/","s":"n./adv.","e":"[n.] A current day or date.\n[n.] From 6am to 6pm on the current day.\n[adv.] On the current day or date.\n[adv.] In the current era; nowadays.","ex":"Today is the day we'll fix this once and for all."},"TODDY":{"p":"","s":"n.","e":"[n.] A drink made from alcoholic liquor mixed with sugar, spice and hot water.\n[n.] The sweet sap from any of several tropical trees fermented to make an alcoholic drink.","ex":""},"TOGAS":{"p":"","s":"n.","e":"[n.] A loose outer garment worn by the citizens of Ancient Rome.\n[n.] A loose wrap gown.\n[n.] An academic gown.","ex":""},"TOES":{"p":"/təʊz/","s":"n./v.","e":"[n.] Each of the five digits on the end of the foot.\n[n.] An equivalent part in an animal.\n[n.] That part of a shoe or sock covering the toe.\n[v.] To furnish (a stocking, etc.) with a toe.\n[v.] To touch, tap or kick with the toes.\n[v.] To touch or reach with the toes; to come fully up to.","ex":"to toe the mark"},"TOFFY":{"p":"","s":"n.","e":"[n.] A type of confectionery made by boiling sugar (or treacle, etc) with butter or milk, then cooling the mixture so that it becomes hard\n[n.] A small, individual piece of toffee\n[n.] Any kind of sweets; candy","ex":"a box of toffees"},"TOILS":{"p":"","s":"n./v.","e":"[n.] Labour, work, especially of a grueling nature.\n[n.] Trouble, strife.\n[n.] (usually in plural) A net or snare; any thread, web, or string spread for taking prey.\n[v.] To labour; work.\n[v.] To struggle.\n[v.] To work (something); often with out.","ex":""},"TOKED":{"p":"","s":"v.","e":"[v.] To give a gratuity to.\n[v.] To smoke marijuana.\n[v.] To inhale a puff of marijuana","ex":"You have to toke the maitre d’ at least $50 if you want a really good table."},"TOKEN":{"p":"/ˈtəʊkən/","s":"n./v./adj.","e":"[n.] Something serving as an expression of something else.\n[n.] A keepsake.\n[n.] A piece of stamped metal or plastic, etc., used as a substitute for money; a voucher that can be exchanged for goods or services.\n[v.] To betoken, indicate, portend, designate, denote\n[v.] To betroth\n[v.] To symbolize, instantiate","ex":"According to the Bible, the rainbow is a token of God's covenant with Noah."},"TOKES":{"p":"","s":"n.","e":"[n.] (casinos) A gratuity.\n[n.] A puff of marijuana.\n[n.] A piece of bread.","ex":"I gave the maitre d’ a $10 toke and he just laughed."},"TOLD":{"p":"/tɔʊld/","s":"v.","e":"[v.] (archaic outside of idioms) To count, reckon, or enumerate.\n[v.] To narrate.\n[v.] To convey by speech; to say.","ex":"All told, there were over a dozen.  Can you tell time on a clock?  He had untold wealth."},"TONE":{"p":"/təʊn/","s":"n./v.","e":"[n.] A specific pitch.\n[n.] (in the diatonic scale) An interval of a major second.\n[n.] (in a Gregorian chant) A recitational melody.\n[v.] To give a particular tone to\n[v.] To change the colour of\n[v.] To make (something) firmer","ex":""},"TOBACCO":{"p":"/təˈbækoʊ/","s":"n./v.","e":"[n.] Any plant of the genus Nicotiana.\n[n.] Leaves of Nicotiana tabacum and some other species cultivated and harvested to make cigarettes, cigars, snuff, for smoking in pipes or for chewing.\n[n.] A variety of tobacco.\n[v.] To indulge in tobacco; to smoke.\n[v.] To treat with tobacco.","ex":"Tobaccos from the Connecticut Valley were used for wrapping cigars."},"TOMBS":{"p":"","s":"n./v.","e":"[n.] A small building (or \"vault\") for the remains of the dead, with walls, a roof, and (if it is to be used for more than one corpse) a door. It may be partly or wholly in the ground (except for its entrance) in a cemetery, or it may be inside a church proper or in its crypt. Single tombs may be permanently sealed; those for families (or other groups) have doors for access whenever needed.\n[n.] A pit in which the dead body of a human being is deposited; a grave.\n[n.] One who keeps secrets.\n[v.] To bury.","ex":""},"TONER":{"p":"/ˈtoʊnɚ/","s":"n.","e":"[n.] Powder used in laser printers and photocopiers to form the text and images on the printed paper.\n[n.] Cosmetic lotion designed to cleanse the skin and shrink pores, usually used on the face.\n[n.] A musician, particularly one that plays a wind instrument.","ex":""},"TONGS":{"p":"/tɑŋz/","s":"n.","e":"[n.] An instrument or tool used for picking things up without touching them with the hands or fingers, consisting of two slats or grips hinged at the end or in the middle, and sometimes including a spring to open the grips.\n[n.] (by extension) A large scissors-like two-piece center-hinged forged-iron implement with oval-loop handles and with pointed tips turned inward (in the same plane as and perpendicular to the handles) to facilitate lifting and carrying a block of ice. Often called ice tongs.","ex":""},"TONIC":{"p":"/ˈtɒnɪk/","s":"n./adj.","e":"[n.] A substance with medicinal properties intended to restore or invigorate.\n[n.] Tonic water.\n[n.] (Massachusetts) Any of various carbonated, non-alcoholic beverages; soda pop.\n[adj.] Pertaining to tension, especially of muscles.\n[adj.] Restorative, curative or invigorating.","ex":"We used to brew a tonic from a particular kind of root."},"TOOK":{"p":"/tuːk/","s":"v.","e":"[v.] To get into one's hands, possession or control, with or without force.\n[v.] To receive or accept (something) (especially something given or bestowed, awarded, etc).\n[v.] To remove.","ex":"I'll take that plate off the table."},"TONES":{"p":"/təʊnz/","s":"n./v.","e":"[n.] A specific pitch.\n[n.] (in the diatonic scale) An interval of a major second.\n[n.] (in a Gregorian chant) A recitational melody.\n[v.] To give a particular tone to\n[v.] To change the colour of\n[v.] To make (something) firmer","ex":""},"TOOLS":{"p":"/tuːlz/","s":"n./v.","e":"[n.] A mechanical device intended to make a task easier.\n[n.] Equipment used in a profession, e.g., tools of the trade.\n[n.] Something to perform an operation; an instrument; a means.\n[v.] To work on or shape with tools, e.g., hand-tooled leather.\n[v.] To equip with tools.\n[v.] To work very hard.","ex":"Hand me that tool, would you?   I don't have the right tools to start fiddling around with the engine."},"TOILE":{"p":"","s":"n.","e":"[n.] Plain or simple twilled fabric","ex":""},"TOPAZ":{"p":"/ˈtəʊpæz/","s":"n./adj.","e":"[n.] A silicate mineral of aluminium and fluorine, usually tinted by impurities.\n[n.] An often clear, yellowish-brown gemstone cut from this.\n[n.] A yellowish-brown color, like that of the gemstone.\n[adj.] Of a yellowish-brown color, like that of the gemstone.","ex":""},"TOOTS":{"p":"/ˈtuts/","s":"n./v.","e":"[n.] The noise of a horn or whistle.\n[n.] (by extension) A fart; flatus.\n[n.] Cocaine.\n[v.] To stand out, or be prominent.\n[v.] To peep; to look narrowly.\n[v.] To see; to spy.","ex":"He gave a little toot of the horn, to get their attention."},"TOOTH":{"p":"/tuːθ/","s":"n./v.","e":"[n.] A hard, calcareous structure present in the mouth of many vertebrate animals, generally used for eating.\n[n.] A sharp projection on the blade of a saw or similar implement.\n[n.] A projection on the edge of a gear that meshes with similar projections on adjacent gears, or on the circumference of a cog that engages with a chain.\n[v.] To provide or furnish with teeth.\n[v.] To indent; to jag.\n[v.] To lock into each other, like gear wheels.","ex":"to tooth a saw"},"TOPIC":{"p":"/ˈtɒpɪk/","s":"n./adj.","e":"[n.] Subject; theme; a category or general area of interest.\n[n.] Discussion thread.\n[n.] A musical sign intended to suggest a particular style or genre.\n[adj.] Topical","ex":"A society where a topic cannot be discussed, does not have free speech."},"TORE":{"p":"/tɔː/","s":"adj.","e":"[adj.] Hard, difficult; wearisome, tedious.\n[adj.] Strong, sturdy; great, massive.\n[adj.] Full; rich.","ex":""},"TORCH":{"p":"/tɔːtʃ/","s":"n./v.","e":"[n.] A stick with a flame on one end, used chiefly as a light source; a similarly shaped implement with a replaceable supply of flammable material.\n[n.] A portable light source powered by electricity; a flashlight.\n[n.] An arsonist.\n[v.] To set fire to, especially by use of a torch (flaming stick).","ex":"The mob of angry villagers carried torches and pitchforks to the vampire's castle."},"TOPS":{"p":"/tɒps/","s":"n./v./adj./adv.","e":"[n.] The highest or uppermost part of something.\n[n.] A child’s spinning toy; a spinning top.\n[n.] (heading) Someone who is eminent.\n[v.] To cover on the top or with a top.\n[v.] To cut or remove the top (as of a tree)\n[v.] To excel, to surpass, to beat.","ex":"His kite got caught at the top of the tree."},"TOTAL":{"p":"/ˈtəʊ.təl/","s":"n./v./adj.","e":"[n.] An amount obtained by the addition of smaller amounts.\n[n.] Sum.\n[v.] To add up; to calculate the sum of.\n[v.] To equal a total of; to amount to.\n[v.] To demolish; to wreck completely. (from total loss)\n[adj.] Entire; relating to the whole of something.","ex":"A total of £145 was raised by the bring-and-buy stall."},"TORES":{"p":"","s":"n.","e":"[n.] The surface described by the circumference of a circle revolving about a straight line in its own plane.\n[n.] The solid enclosed by such a surface; an anchor ring.\n[n.] A topological space which is a product of two circles.\n[n.] The standard representation of such a space in 3-dimensional Euclidean space: a shape consisting of a ring with a circular cross-section: the shape of an inner tube or hollow doughnut.\n[n.] (in combination, n-torus, 4-torus, etc.) The product of the specified number of circles.","ex":"A 4-variable Karnaugh map can be thought of, topologically, as being a torus."},"TORSO":{"p":"/ˈtɔː.səʊ/","s":"n.","e":"[n.] The main part of the (human) body that extends from the neck to the groin, excluding the head and limbs.","ex":""},"TOTED":{"p":"","s":"v.","e":"[v.] To carry or bear.\n[v.] To add up; to calculate a total.","ex":"to tote a child over a stream"},"TORUS":{"p":"/ˈtɔːɹəs/","s":"n.","e":"[n.] A topological space which is a product of two circles.\n[n.] The standard representation of such a space in 3-dimensional Euclidean space: a shape consisting of a ring with a circular cross-section: the shape of an inner tube or hollow doughnut.\n[n.] (in combination, n-torus, 4-torus, etc.) The product of the specified number of circles.","ex":"A 4-variable Karnaugh map can be thought of, topologically, as being a torus."},"TOTEM":{"p":"/ˈtəʊtəm/","s":"n.","e":"[n.] Any natural object or living creature that serves as an emblem of a tribe, clan or family.\n[n.] The representation of such object or creature.\n[n.] The clan whose kinship is defined in reference to such an object or creature.","ex":""},"TOTES":{"p":"","s":"n.","e":"[n.] A tote bag.\n[n.] A heavy burden.\n[n.] (logistics) A kind of plastic box used for transporting goods.\n[n.] A pari-mutuel machine; a totalizator.\n[n.] Pari-mutuel betting.","ex":""},"TOUGH":{"p":"/tʌf/","s":"n./v./adj./int.","e":"[n.] A person who obtains things by force; a thug or bully.\n[v.] To endure.\n[v.] To toughen.\n[adj.] Strong and resilient; sturdy.\n[adj.] (of food) Difficult to cut or chew.\n[adj.] Rugged or physically hardy.","ex":"They were doing fine until they encountered a bunch of toughs from the opposition."},"TOURS":{"p":"","s":"n./v.","e":"[n.] A journey through a particular building, estate, country, etc.\n[n.] A guided visit to a particular place, or virtual place.\n[n.] A journey through a given list of places, such as by an entertainer performing concerts.\n[v.] To make a journey\n[v.] To make a circuit of a place\n[n.] A tower.","ex":"On our last holiday to Spain we took a tour of the wine-growing regions."},"TOWARD":{"p":"/tɘ.ˈwoːd/","s":"adj./prep.","e":"[adj.] Yielding, pliant; docile; ready or apt to learn; not froward.\n[adj.] Future; to-come.\n[adj.] Approaching, coming near; impending; present, at hand.\n[prep.] In the direction of.\n[prep.] In relation to (someone or something).\n[prep.] For the purpose of attaining (an aim).","ex":"She moved toward the door."},"TOWER":{"p":"/ˈtaʊ.ə(ɹ)/","s":"n.","e":"[n.] A very tall iron-framed structure, usually painted red and white, on which microwave, radio, satellite, or other communication antennas are installed; mast.\n[n.] A similarly framed structure with a platform or enclosed area on top, used as a lookout for spotting fires, plane crashes, fugitives, etc.\n[n.] A water tower.","ex":""},"TORN":{"p":"/tɔːn/","s":"v.","e":"[v.] To rend (a solid material) by holding or restraining in two places and pulling apart, whether intentionally or not; to destroy or separate.\n[v.] To injure as if by pulling apart.\n[v.] To destroy or reduce abstract unity or coherence, such as social, political or emotional.","ex":"He tore his coat on the nail."},"TOXIC":{"p":"/ˈtɒk.sɪk/","s":"adj.","e":"[adj.] Having a chemical nature that is harmful to health or lethal if consumed or otherwise entering into the body in sufficient quantities.\n[adj.] Appearing grossly unwell; characterised by serious, potentially life-threatening compromise in the respiratory, circulatory or other body systems.\n[adj.] Severely negative or harmful.","ex":"Tobacco smoke contains many toxic substances."},"TOXIN":{"p":"/ˈtɒksɪn/","s":"n.","e":"[n.] A toxic or poisonous substance produced by the biological processes of biological organisms.","ex":""},"TRACE":{"p":"/tɹeɪs/","s":"n.","e":"[n.] An act of tracing.\n[n.] An enquiry sent out for a missing article, such as a letter or an express package.\n[n.] A mark left as a sign of passage of a person or animal.","ex":"Your cell phone company can put a trace on your line."},"TOUTS":{"p":"","s":"n./v.","e":"[n.] Someone advertising for customers in an aggressive way.\n[n.] A person, at a racecourse, who offers supposedly inside information on which horse is likely to win.\n[n.] A spy for a smuggler, thief, or similar.\n[v.] To flaunt, to publicize/publicise; to boast or brag; to promote.\n[v.] To look upon or watch.\n[v.] To spy out information about (a horse, a racing stable, etc.).","ex":"Be careful of the ticket touts outside the arena, they are famed for selling counterfeits."},"TOWEL":{"p":"/taʊl/","s":"n./v.","e":"[n.] A cloth used for wiping, especially one used for drying anything wet, as a person after a bath.\n[v.] To hit with a towel.\n[v.] To dry by using a towel.\n[v.] To block up (a door, etc.) with a towel, to conceal the fumes of a recreational drug.","ex":"He got out of the shower and toweled himself dry."},"TRADE":{"p":"/tɹeɪd/","s":"n./v.","e":"[n.] Buying and selling of goods and services on a market.\n[n.] A particular instance of buying or selling.\n[n.] An instance of bartering items in exchange for one another.\n[v.] To engage in trade.\n[v.] To be traded at a certain price or under certain conditions.\n[v.] To give (something) in exchange for.","ex":"I did no trades with them once the rumors started."},"TRADING":{"p":"/tɹeɪdɪŋ/","s":"v./n./adj.","e":"[v.] To engage in trade.\n[v.] To be traded at a certain price or under certain conditions.\n[v.] To give (something) in exchange for.\n[n.] The carrying on of trade.\n[adj.] Carrying on trade or commerce; engaged in trade.\n[adj.] Frequented by traders.","ex":"This company trades (in) precious metal."},"TRAFFIC":{"p":"/ˈtɹæfɪk/","s":"n./v.","e":"[n.] Pedestrians or vehicles on roads, or the flux or passage thereof.\n[n.] Commercial transportation or exchange of goods, or the movement of passengers or people.\n[n.] Illegal trade or exchange of goods, often drugs.\n[v.] To pass goods and commodities from one person to another for an equivalent in goods or money; to buy or sell goods\n[v.] To trade meanly or mercenarily; to bargain.\n[v.] To exchange in traffic; to effect by a bargain or for a consideration.","ex":"The traffic is slow during rush hour."},"TOYED":{"p":"","s":"v.","e":"[v.] To play (with) in an idle or desultory way.\n[v.] To ponder or consider.\n[v.] To stimulate with a sex toy.","ex":"Figo is toying with the English defence."},"TRAINED":{"p":"/tɹeɪnd/","s":"v./adj.","e":"[v.] To practice an ability.\n[v.] To teach and form (someone) by practice; to educate (someone).\n[v.] To improve one's fitness.\n[adj.] Having undergone a course of training (sometimes in combination).\n[adj.] Manipulated in shape or habit.","ex":"She trained seven hours a day to prepare for the Olympics."},"TRACK":{"p":"/tɹæk/","s":"n./v.","e":"[n.] A mark left by something that has passed along.\n[n.] A mark or impression left by the foot, either of man or animal.\n[n.] The entire lower surface of the foot; said of birds, etc.\n[v.] To continue over time.\n[v.] To follow the tracks of.\n[v.] To make tracks on.","ex":"Can you see any tracks in the snow?"},"TRACT":{"p":"/tɹækt/","s":"n.","e":"[n.] An area or expanse.\n[n.] A series of connected body organs, as in the digestive tract.\n[n.] A small booklet such as a pamphlet, often for promotional or informational uses.","ex":"an unexplored tract of sea"},"TRAMP":{"p":"/tɹæmp/","s":"n./v.","e":"[n.] (sometimes derogatory) A homeless person; a vagabond.\n[n.] A disreputable, promiscuous woman; a slut.\n[n.] Any ship which does not have a fixed schedule or published ports of call.\n[v.] To walk with heavy footsteps.\n[v.] To walk for a long time (usually through difficult terrain).\n[v.] To hitchhike.","ex":"\"Claudia is such a tramp; making out with all those men when she has a boyfriend.\""},"TRAPS":{"p":"/tɹæps/","s":"n./v.","e":"[n.] A machine or other device designed to catch (and sometimes kill) animals, either by holding them in a container, or by catching hold of part of the body.\n[n.] A trick or arrangement designed to catch someone in a more general sense; a snare.\n[n.] A covering over a hole or opening; a trapdoor.\n[v.] To physically capture, to catch in a trap or traps, or something like a trap.\n[v.] To ensnare; to take by stratagem; to entrap.\n[v.] To provide with a trap.","ex":"I put down some traps in my apartment to try and deal with the mouse problem."},"TOUR":{"p":"/tɔː(ɹ)/","s":"n./v.","e":"[n.] A journey through a particular building, estate, country, etc.\n[n.] A guided visit to a particular place, or virtual place.\n[n.] A journey through a given list of places, such as by an entertainer performing concerts.\n[v.] To make a journey\n[v.] To make a circuit of a place","ex":"On our last holiday to Spain we took a tour of the wine-growing regions."},"TRAWL":{"p":"/tɹɔːl/","s":"n./v.","e":"[n.] A net or dragnet used for trawling.\n[n.] A long fishing line having many short lines bearing hooks attached to it; a setline.\n[v.] To take (fish or other marine animals) with a trawl.\n[v.] To fish from a slow-moving boat.\n[v.] To make an exhaustive search for something within a defined area.","ex":""},"TRAIL":{"p":"/tɹeɪl/","s":"n./v.","e":"[n.] The track or indication marking the route followed by something that has passed, such as the footprints of animal on land or the contrail of an airplane in the sky.\n[n.] A route for travel over land, especially a narrow, unpaved pathway for use by hikers, horseback riders, etc.\n[n.] A trailer broadcast on television for a forthcoming film or programme.\n[v.] To follow behind (someone or something); to tail (someone or something).\n[v.] To drag (something) behind on the ground.\n[v.] To leave (a trail of).","ex":"The hunters trailed their prey deep into the woods."},"TREAD":{"p":"/tɹɛd/","s":"v.","e":"[v.] To step or walk (on or over something); to trample.\n[v.] To step or walk upon.\n[v.] To beat or press with the feet.","ex":"Don't tread on the lawn."},"TREAT":{"p":"/tɹiːt/","s":"n./v.","e":"[n.] An entertainment, outing, food, drink, or other indulgence provided by someone for the enjoyment of others.\n[n.] An unexpected gift, event etc., which provides great pleasure.\n[n.] A snack food item designed to be given to pets.\n[v.] To negotiate, discuss terms, bargain (for or with).\n[v.] To discourse; to handle a subject in writing or speaking; to conduct a discussion.\n[v.] To discourse on; to represent or deal with in a particular way, in writing or speaking.","ex":"Here are some healthy Halloween treats for ghouls and witches of all ages."},"TREE":{"p":"/tɹiː/","s":"n./v.","e":"[n.] Fast growing function based on Kruskal's tree theorem.\n[n.] A perennial woody plant, not exactly defined, but differentiated from a shrub by its larger size (typically over a few meters in height) or growth habit, usually having a single (or few) main axis or trunk unbranched for some distance above the ground and a head of branches and foliage.\n[n.] Any plant that is reminiscent of the above but not classified as a tree (in any botanical sense).\n[n.] An object made from a tree trunk and having multiple hooks or storage platforms.\n[v.] To chase (an animal or person) up a tree.\n[v.] To place in a tree.","ex":"Birds have a nest in a tree in the garden."},"TREED":{"p":"","s":"v./adj.","e":"[v.] To chase (an animal or person) up a tree.\n[v.] To place in a tree.\n[v.] To place upon a tree; to fit with a tree; to stretch upon a tree.\n[adj.] Planted or covered with trees.","ex":"The dog treed the cat."},"TREKS":{"p":"","s":"n./v.","e":"[n.] A journey by ox wagon.\n[n.] The Boer migration of 1835-1837.\n[n.] A slow or difficult journey.\n[v.] To make a slow or arduous journey.\n[v.] To journey on foot, especially to hike through mountainous areas.\n[v.] To travel by ox wagon.","ex":"We're planning a trek up Kilimanjaro."},"TREES":{"p":"/tɹiːz/","s":"n./v.","e":"[n.] Fast growing function based on Kruskal's tree theorem.\n[n.] A perennial woody plant, not exactly defined, but differentiated from a shrub by its larger size (typically over a few meters in height) or growth habit, usually having a single (or few) main axis or trunk unbranched for some distance above the ground and a head of branches and foliage.\n[n.] Any plant that is reminiscent of the above but not classified as a tree (in any botanical sense).\n[n.] An object made from a tree trunk and having multiple hooks or storage platforms.\n[v.] To chase (an animal or person) up a tree.\n[v.] To place in a tree.","ex":"Birds have a nest in a tree in the garden."},"TRAP":{"p":"/tɹæp/","s":"n./v.","e":"[n.] A machine or other device designed to catch (and sometimes kill) animals, either by holding them in a container, or by catching hold of part of the body.\n[n.] A trick or arrangement designed to catch someone in a more general sense; a snare.\n[n.] A covering over a hole or opening; a trapdoor.\n[v.] To physically capture, to catch in a trap or traps, or something like a trap.\n[v.] To ensnare; to take by stratagem; to entrap.\n[v.] To provide with a trap.","ex":"I put down some traps in my apartment to try and deal with the mouse problem."},"TREND":{"p":"/tɹɛnd/","s":"n./v.","e":"[n.] An inclination in a particular direction.\n[n.] A tendency.\n[n.] A fad or fashion style.\n[v.] To have a particular direction; to run; to stretch; to tend.\n[v.] To cause to turn; to bend.\n[v.] To be the subject of a trend; to be currently popular, relevant or interesting.","ex":"the trend of a coastline"},"TRESS":{"p":"/tɹɛs/","s":"n./v.","e":"[n.] A braid, knot, or curl, of hair; a ringlet.\n[n.] A long lock of hair\n[n.] (by extension) A knot or festoon, as of flowers.\n[v.] To braid or knot hair.","ex":""},"TREYS":{"p":"/tɹeɪz/","s":"n.","e":"[n.] A playing card or die with the rank of three.\n[n.] A score of three in cards, dice, or dominoes.\n[n.] A three-pointer.","ex":""},"TRAYS":{"p":"","s":"n./v.","e":"[n.] A small, typically rectangular or round, flat, and rigid object upon which things are carried.\n[n.] A flat carrier for items being transported.\n[n.] The items on a full tray.\n[v.] To place (items) on a tray\n[v.] To slide down a snow-covered hill on a tray from a cafeteria.\n[n.] Trouble; annoyance; anger","ex":"I carefully arranged the dishes on the tray and brought it upstairs."},"TRIAD":{"p":"/ˈtɹaɪ.æd/","s":"n.","e":"[n.] A grouping of three.\n[n.] A word of three syllables.\n[n.] A branch of a Chinese underground criminal society, mostly based in Hong Kong.","ex":""},"TRIAL":{"p":"/ˈtɹaɪəl/","s":"n./v./adj.","e":"[n.] An opportunity to test something out; a test.\n[n.] Appearance at judicial court in order to be examined.\n[n.] A difficult or annoying experience.\n[v.] To carry out a series of tests on (a new product, procedure etc.) before marketing or implementing it.\n[v.] To try out (a new player) in a sports team.\n[adj.] Pertaining to a trial or test.","ex":"They will perform the trials for the new equipment next week."},"TRICK":{"p":"/tɹɪk/","s":"n./v./adj.","e":"[n.] Something designed to fool or swindle.\n[n.] A single element of a magician's (or any variety entertainer's) act; a magic trick.\n[n.] An entertaining difficult physical action.\n[v.] To fool; to cause to believe something untrue; to deceive.\n[v.] To draw (as opposed to blazon - to describe in words).\n[v.] To dress; to decorate; to adorn fantastically; often followed by up, off, or out.","ex":"It was just a trick to say that the house was underpriced."},"TRICE":{"p":"/tɹaɪs/","s":"v.","e":"[v.] To pull, to pull out or away, to pull sharply.\n[v.] To drag or haul, especially with a rope; specifically to haul or hoist and tie up by means of a rope.","ex":""},"TRIBE":{"p":"/tɹaɪb/","s":"n./v.","e":"[n.] A socially, ethnically, or politically cohesive group of people.\n[n.] A society larger than a band but smaller than a state.\n[n.] A group of apes who live and work together.\n[v.] To distribute into tribes or classes; to categorize.","ex":""},"TRIED":{"p":"/tɹaɪd/","s":"adj./v.","e":"[adj.] Tested, hence, proven to be firm or reliable.\n[adj.] Put on trial, taken before a lawcourt.\n[v.] To attempt; to endeavour. Followed by infinitive.\n[v.] To divide; to separate.\n[v.] To test, to work out.","ex":"I tried to rollerblade, but I couldn’t."},"TREATY":{"p":"/ˈtɹiːti/","s":"n.","e":"[n.] A binding agreement concluded by subjects of international law, namely states and international organizations.\n[n.] A formal agreement between two or more states.","ex":""},"TRIER":{"p":"","s":"n.","e":"[n.] One who tries; one who makes experiments or examines anything by a test or standard.\n[n.] An instrument used for sampling something.\n[n.] One who tries judicially.","ex":""},"TRIES":{"p":"/tɹaɪz/","s":"n./v.","e":"[n.] An ordered tree data structure that is used to store an associative array where the keys are usually strings.\n[n.] An attempt.\n[n.] An act of tasting or sampling.\n[n.] A score in rugby league and rugby union, analogous to a touchdown in American football.\n[v.] To attempt; to endeavour. Followed by infinitive.\n[v.] To divide; to separate.","ex":"I gave unicycling a try but I couldn’t do it."},"TRIKE":{"p":"","s":"n./v.","e":"[n.] A tricycle.\n[n.] A three-wheeled motorbike.\n[n.] A kind of railroad maintenance vehicle: a speeder or jigger.\n[v.] To tricycle; to travel by tricycle.","ex":""},"TRIP":{"p":"/tɹɪp/","s":"n./v./adj.","e":"[n.] A journey; an excursion or jaunt\n[n.] A stumble or misstep\n[n.] An error; a failure; a mistake\n[v.] To fall over or stumble over an object as a result of striking it with one's foot\n[v.] (sometimes followed by \"up\") to cause (a person or animal) to fall or stumble by knocking their feet from under them\n[v.] To be guilty of a misstep or mistake; to commit an offence against morality, propriety, etc","ex":"We made a trip to the beach."},"TRIO":{"p":"/ˈtɹi.əʊ/","s":"n.","e":"[n.] A group of three people or things.\n[n.] A group of three musicians.\n[n.] A piece of music written for three musicians.","ex":""},"TRIOS":{"p":"","s":"n.","e":"[n.] A group of three people or things.\n[n.] A group of three musicians.\n[n.] A piece of music written for three musicians.","ex":""},"TRIMS":{"p":"","s":"n./v.","e":"[n.] Decoration; especially, decoration placed along edges or borders.\n[n.] A haircut, especially a moderate one to touch up an existing style.\n[n.] Dress; gear; ornaments.\n[v.] To reduce slightly; to cut; especially, to remove excess.\n[v.] To decorate or adorn; especially of a Christmas tree.\n[v.] (of an aircraft) To adjust pitch using trim tabs.","ex":"Paint the house white with blue trim."},"TRAVEL":{"p":"/ˈtɹævəl/","s":"n./v.","e":"[n.] The act of traveling; passage from place to place.\n[n.] (in the plural) A series of journeys.\n[n.] (in the plural) An account of one's travels.\n[v.] To be on a journey, often for pleasure or business and with luggage; to go from one place to another.\n[v.] To pass from here to there; to move or transmit; to go from one place to another.\n[v.] To move illegally by walking or running without dribbling the ball.","ex":"space travel"},"TRIPLE":{"p":"/ˈtɹɪpl/","s":"n./v./adj.","e":"[n.] Three times or thrice the number, amount, size, etc\n[n.] A drink with three portions of alcohol.\n[n.] A hamburger with three patties.\n[v.] To multiply by three\n[v.] To get a three-base hit\n[v.] To become three times as large","ex":"I've had a hard day; make that a triple."},"TRIPS":{"p":"/tɹɪps/","s":"n./v.","e":"[n.] A journey; an excursion or jaunt\n[n.] A stumble or misstep\n[n.] An error; a failure; a mistake\n[v.] To fall over or stumble over an object as a result of striking it with one's foot\n[v.] (sometimes followed by \"up\") to cause (a person or animal) to fall or stumble by knocking their feet from under them\n[v.] To be guilty of a misstep or mistake; to commit an offence against morality, propriety, etc","ex":"We made a trip to the beach."},"TROPE":{"p":"/tɹəʊp/","s":"n./v.","e":"[n.] Something recurring across a genre or type of art or literature, such as the ‘mad scientist’ of horror movies or the use of the phrase ‘once upon a time’ as an introduction to fairy tales; a motif.\n[n.] A figure of speech in which words or phrases are used with a nonliteral or figurative meaning, such as a metaphor.\n[n.] Mathematical senses.\n[v.] To use, or embellish something with, a trope.\n[v.] Senses relating chiefly to art or literature.\n[v.] To think or write in terms of tropes.","ex":""},"TROLL":{"p":"/tɹɒl/","s":"n.","e":"[n.] A supernatural being of varying size, now especially a grotesque humanoid creature living in caves or hills or under bridges.\n[n.] An ugly person of either sex, especially one seeking sexual experiences.\n[n.] Optical ejections from the top of the electrically active core regions of thunderstorms that are red in color that seem to occur after tendrils of vigorous sprites extend downward toward the cloud tops.","ex":""},"TROTH":{"p":"/tɹɒθ/","s":"n./v.","e":"[n.] An oath, pledge, or promise.\n[n.] Truth; something true.\n[v.] To pledge to marry somebody.","ex":""},"TROTS":{"p":"","s":"n./v.","e":"[n.] A supporter of Trotskyism.\n[n.] Any of several animals related to Equus ferus caballus.\n[n.] Equipment with legs.\n[n.] Type of equipment.\n[n.] Heroin (drug).\n[n.] An ugly old woman, a hag.","ex":"Alright, mate, got any horse?"},"TROUT":{"p":"/tɹʌʊt/","s":"n./v.","e":"[n.] Any of several species of fish in Salmonidae, closely related to salmon, and distinguished by spawning more than once.\n[n.] An objectionable elderly woman.\n[v.] To (figuratively) slap someone with a slimy, stinky, wet trout; to admonish jocularly.","ex":"Many anglers consider trout to be the archetypical quarry."},"TRIPE":{"p":"/tɹaɪp/","s":"n./int.","e":"[n.] The lining of the large stomach of ruminating animals, when prepared for food.\n[n.] The entrails; hence, humorously or in contempt, the belly; -- generally used in the plural.\n[n.] (chiefly plural) Something disparaged as valueless, especially written works and popular entertainment (movies, television).\n[int.] That (what has just been said) is untrue.","ex":""},"TRITE":{"p":"/tɹaɪt/","s":"adj.","e":"[adj.] Often in reference to a word or phrase: used so many times that it is commonplace, or no longer interesting or effective; worn out, hackneyed.\n[adj.] So well established as to be beyond debate: trite law.","ex":""},"TRUCE":{"p":"/tɹuːs/","s":"n.","e":"[n.] A period of time in which no fighting takes place due to an agreement between the opposed parties\n[n.] An agreement between opposed parties in which they pledge to cease fighting for a limited time","ex":""},"TRUE":{"p":"/tɹuː/","s":"n./v./adj./adv.","e":"[n.] The state of being in alignment.\n[n.] Truth.\n[n.] A pledge or truce.\n[v.] To straighten.\n[v.] To make even, level, symmetrical, or accurate, align; adjust.\n[adj.] (of a statement) Conforming to the actual state of reality or fact; factually correct.","ex":"He trued the spokes of the bicycle wheel."},"TRUES":{"p":"","s":"v.","e":"[v.] To straighten.\n[v.] To make even, level, symmetrical, or accurate, align; adjust.","ex":"He trued the spokes of the bicycle wheel."},"TRULY":{"p":"/ˈtɹuːli/","s":"adv.","e":"[adv.] (manner) In accordance with the facts; truthfully, accurately.\n[adv.] (modal) Honestly, genuinely, in fact, really.\n[adv.] (degree) Very.","ex":"That is truly all I know."},"TROVE":{"p":"/tɹəʊv/","s":"n.","e":"[n.] A treasure trove; a collection of treasure.\n[n.] A collection of things.","ex":""},"TRUMP":{"p":"/tɹʌmp/","s":"n./v.","e":"[n.] The suit, in a game of cards, that outranks all others.\n[n.] A playing card of that suit.\n[n.] Something that gives one an advantage, especially one held in reserve.\n[v.] To play on (a card of another suit) with a trump.\n[v.] To play a trump, or to take a trick with a trump.\n[v.] To get the better of, or finesse, a competitor.","ex":"Diamonds were declared trump(s)."},"TRUNK":{"p":"/tɹʌŋk/","s":"n./v.","e":"[n.] (heading, biological) Part of a body.\n[n.] (heading) A container.\n[n.] (heading) A channel for flow of some kind.\n[v.] To lop off; to curtail; to truncate.\n[v.] To extract (ores) from the slimes in which they are contained, by means of a trunk.","ex":""},"TRUCK":{"p":"/tɹʌk/","s":"n./v.","e":"[n.] A small wheel or roller, specifically the wheel of a gun carriage.\n[n.] The ball on top of a flagpole.\n[n.] On a wooden mast, a circular disc (or sometimes a rectangle) of wood near or at the top of the mast, usually with holes or sheaves to reeve signal halyards; also a temporary or emergency place for a lookout. \"Main\" refers to the mainmast, whereas a truck on another mast may be called (on the mizzenmast, for example) \"mizzen-truck\".\n[v.] To drive a truck: Generally a truck driver's slang.\n[v.] To convey by truck.\n[v.] To travel or live contentedly.","ex":"Last week, Cletus trucked 100 pounds of lumber up to Dubuque."},"TRUER":{"p":"","s":"adj.","e":"[adj.] (of a statement) Conforming to the actual state of reality or fact; factually correct.\n[adj.] Conforming to a rule or pattern; exact; accurate.\n[adj.] Of the state in Boolean logic that indicates an affirmative or positive result.","ex":"This is a true story."},"TRUSTED":{"p":"/ˈtɹʌstɪd/","s":"v.","e":"[v.] To place confidence in; to rely on, to confide, or have faith, in.\n[v.] To give credence to; to believe; to credit.\n[v.] To hope confidently; to believe (usually with a phrase or infinitive clause as the object)","ex":"We cannot trust anyone who deceives us."},"TRUTH":{"p":"/tɹuːθ/","s":"n./v.","e":"[n.] True facts, genuine depiction or statements of reality.\n[n.] Conformity to fact or reality; correctness, accuracy.\n[n.] The state or quality of being true to someone or something.\n[v.] To assert as true; to declare; to speak truthfully.\n[v.] To make exact; to correct for inaccuracy.\n[v.] To tell the truth.","ex":"The truth is that our leaders knew a lot more than they were letting on."},"TRYST":{"p":"/tɹaɪst/","s":"n./v.","e":"[n.] A prearranged meeting or assignation, now especially between lovers to meet at a specific place and time.\n[n.] A mutual agreement, a covenant.\n[v.] To make a tryst; to agree to meet at a place.\n[v.] To arrange or appoint (a meeting time etc.).\n[v.] To keep a tryst, to meet at an agreed place and time.","ex":""},"TROOP":{"p":"/tɹuːp/","s":"n./v.","e":"[n.] (collective) A collection of people; a number; a multitude (in general).\n[n.] A small unit of cavalry or armour commanded by a captain, corresponding to a platoon or company of infantry.\n[n.] A detachment of soldiers or police, especially horse artillery, armour, or state troopers.\n[v.] To move in numbers; to come or gather in crowds or troops.\n[v.] To march on; to go forward in haste.\n[v.] To move or march as if in a crowd.","ex":"The children trooped into the room."},"TUBAS":{"p":"","s":"n.","e":"[n.] A large brass musical instrument, usually in the bass range, played through a vibration of the lips upon the mouthpiece and fingering of the keys.\n[n.] A type of Roman military trumpet, distinct from the modern tuba.\n[n.] A large reed stop in organs.\n[n.] A reddish palm wine made from coconut or nipa sap.\n[n.] A tube or tubular organ.","ex":""},"TUBED":{"p":"","s":"v./adj.","e":"[v.] To supply with, or enclose in, a tube.\n[v.] To ride an inner tube.\n[v.] To intubate.\n[adj.] Possessing a tube or tubes.","ex":"She tubes lipstick in the cosmetics factory."},"TUBER":{"p":"/tjuːbə(ɹ)/","s":"n.","e":"[n.] A fleshy, thickened underground stem of a plant, usually containing stored starch, for example a potato or arrowroot.\n[n.] A thickened rootstock.\n[n.] A rounded, protuberant structure in a human or animal body.","ex":""},"TRUST":{"p":"/trʊst/","s":"n./v./adj.","e":"[n.] Confidence in or reliance on some person or quality.\n[n.] Dependence upon something in the future; hope.\n[n.] Confidence in the future payment for goods or services supplied; credit.\n[v.] To place confidence in; to rely on, to confide, or have faith, in.\n[v.] To give credence to; to believe; to credit.\n[v.] To hope confidently; to believe (usually with a phrase or infinitive clause as the object)","ex":"He needs to regain her trust if he is ever going to win her back."},"TUBBY":{"p":"/ˈtʌbi/","s":"n./adj.","e":"[n.] (often used teasingly) An overweight person.\n[adj.] Stout, rotund\n[adj.] Resembling a tub; sounding dull and without resonance or freedom of sound.","ex":"a tubby violin"},"TUCK":{"p":"/tʌk/","s":"n./v.","e":"[n.] An act of tucking; a pleat or fold.\n[n.] A fold in fabric that has been stitched in place from end to end, as to reduce the overall dimension of the fabric piece.\n[n.] A curled position.\n[v.] To pull or gather up (an item of fabric).\n[v.] To push into a snug position; to place somewhere safe or somewhat hidden.\n[v.] (often with \"in\" or \"into\") To eat; to consume.","ex":"Tuck in your shirt.  I tucked in the sheet.  He tucked the $10 bill into his shirt pocket."},"TUMID":{"p":"","s":"adj.","e":"[adj.] Swollen, enlarged, bulging\n[adj.] Cancerous, unhealthy\n[adj.] Pompous, bombastic","ex":""},"TUBES":{"p":"/tjuːbz/","s":"n./v.","e":"[n.] Anything that is hollow and cylindrical in shape.\n[n.] An approximately cylindrical container, usually with a crimped end and a screw top, used to contain and dispense semiliquid substances.\n[n.] (often capitalized as Tube) The London Underground railway system, originally referred to the lower level lines that ran in tubular tunnels as opposed to the higher ones which ran in rectangular section tunnels. (Often the tube.)\n[v.] To supply with, or enclose in, a tube.\n[v.] To ride an inner tube.\n[v.] To intubate.","ex":"A tube of toothpaste."},"TUFTS":{"p":"","s":"n./v.","e":"[n.] A bunch of feathers, grass or hair, etc., held together at the base.\n[n.] A cluster of threads drawn tightly through upholstery, a mattress or a quilt, etc., to secure and strengthen the padding.\n[n.] A small clump of trees or bushes.\n[v.] To provide or decorate with a tuft or tufts.\n[v.] To form into tufts.\n[v.] To secure and strengthen (a mattress, quilt, etc.) with tufts.","ex":""},"TUCKS":{"p":"","s":"n./v.","e":"[n.] An act of tucking; a pleat or fold.\n[n.] A fold in fabric that has been stitched in place from end to end, as to reduce the overall dimension of the fabric piece.\n[n.] A curled position.\n[v.] To pull or gather up (an item of fabric).\n[v.] To push into a snug position; to place somewhere safe or somewhat hidden.\n[v.] (often with \"in\" or \"into\") To eat; to consume.","ex":"Tuck in your shirt.  I tucked in the sheet.  He tucked the $10 bill into his shirt pocket."},"TRUSS":{"p":"/tɹʌs/","s":"n./v.","e":"[n.] A bandage and belt used to hold a hernia in place.\n[n.] A structure made up of one or more triangular units made from straight beams of wood or metal, which is used to support a structure as in a roof or bridge.\n[n.] A triangular bracket.\n[v.] To tie up a bird before cooking it.\n[v.] To secure or bind with ropes.\n[v.] To support.","ex":""},"TULIP":{"p":"/ˈt(j)uːlɪp/","s":"n.","e":"[n.] A type of flowering plant, genus Tulipa.\n[n.] The flower of this plant.","ex":""},"TUMMY":{"p":"/ˈtʌm.i/","s":"n.","e":"[n.] (often childish) Stomach or belly.\n[n.] Protruding belly, paunch.","ex":""},"TULLE":{"p":"/tuːl/","s":"n.","e":"[n.] A kind of silk lace or light netting, used for clothing, veils, etc.","ex":""},"TUNED":{"p":"/tjuːnd/","s":"v./adj.","e":"[v.] To adjust (a musical instrument) so that it produces the correct pitches.\n[v.] To adjust or modify (esp. a mechanical or electrical device) so that it functions optimally.\n[v.] To adjust the frequency on a radio or TV set, so as to receive the desired channel.\n[adj.] Adjusted in pitch or resonance.","ex":"to tune a piano or a violin"},"TUNER":{"p":"/ˈtjuː.nɚ/","s":"n.","e":"[n.] A person who tunes a piano or organ.\n[n.] A device, electronic or mechanical, that helps a person tune a musical instrument by showing the deviation of the played pitch from the desired pitch.\n[n.] On a musical instrument, a peg or mechanical device that changes the tension, and hence pitch, of a string.","ex":""},"TUNES":{"p":"/tjuːns/","s":"n./v.","e":"[n.] A melody.\n[n.] A song, or short musical composition.\n[n.] The act of tuning or maintenance.\n[v.] To adjust (a musical instrument) so that it produces the correct pitches.\n[v.] To adjust or modify (esp. a mechanical or electrical device) so that it functions optimally.\n[v.] To adjust the frequency on a radio or TV set, so as to receive the desired channel.","ex":"Your engine needs a good tune."},"TURFY":{"p":"","s":"adj.","e":"[adj.] Of, pertaining to, or constructed of turf.\n[adj.] Relating to or involved with horses or horse-racing.","ex":""},"TUNE":{"p":"/tjuːn/","s":"n./v./int.","e":"[n.] A melody.\n[n.] A song, or short musical composition.\n[n.] The act of tuning or maintenance.\n[v.] To adjust (a musical instrument) so that it produces the correct pitches.\n[v.] To adjust or modify (esp. a mechanical or electrical device) so that it functions optimally.\n[v.] To adjust the frequency on a radio or TV set, so as to receive the desired channel.","ex":"Your engine needs a good tune."},"TUMOR":{"p":"/tjuː.mə/","s":"n.","e":"[n.] An abnormal growth; differential diagnosis includes abscess, metaplasia, and neoplasia.","ex":""},"TUSKS":{"p":"","s":"n.","e":"[n.] One of a pair of elongated pointed teeth that extend outside the mouth of an animal such as walrus, elephant or wild boar.\n[n.] A small projection on a (tusk) tenon.\n[n.] A tusk shell.\n[n.] A fish, the torsk (Brosme brosme).","ex":"Until the CITES sales ban, elephant tusks were the 'backbone' of the legal ivory trade."},"TUTEE":{"p":"","s":"n.","e":"[n.] A student of a tutor.","ex":""},"TURFS":{"p":"/tɜː(ɹ)fs/","s":"n./v.","e":"[n.] A layer of earth covered with grass; sod.\n[n.] A piece of such a layer cut from the soil. May be used as sod to make a lawn, dried for peat, stacked to form earthen structures, etc.\n[n.] A sod of peat used as fuel.\n[v.] To cover with turf; to create a lawn by laying turfs.\n[v.] (Ultimate Frisbee) To throw a frisbee well short of its intended target, usually causing it to hit the ground within 10 yards of its release.\n[v.] To fire from a job or dismiss from a task.","ex":"Eight managers were turfed after the merger of the two companies."},"TURN":{"p":"/tɜːn/","s":"v.","e":"[v.] (heading) to make a non-linear physical movement.\n[v.] (heading) To change condition or attitude.\n[v.] To change one's course of action; to take a new approach.","ex":""},"TURNS":{"p":"/tɜːnz/","s":"v./n.","e":"[v.] (heading) to make a non-linear physical movement.\n[v.] (heading) To change condition or attitude.\n[v.] To change one's course of action; to take a new approach.\n[n.] A change of direction or orientation.\n[n.] A movement of an object about its own axis in one direction that continues until the object returns to its initial orientation.\n[n.] A walk to and fro.","ex":"Give the handle a turn, then pull it."},"TURNING":{"p":"[ˈtɜː.nɪŋ]","s":"v./n.","e":"[v.] (heading) to make a non-linear physical movement.\n[v.] (heading) To change condition or attitude.\n[v.] To change one's course of action; to take a new approach.\n[n.] A turn or deviation from a straight course.\n[n.] At hockey, a foul committed by a player attempting to hit the ball who interposes their body between the ball and an opposing player trying to do the same.\n[n.] The shaping of wood or metal on a lathe.","ex":"Take the second turning on the left."},"TWAIN":{"p":"/tweɪn/","s":"n./adj./num.","e":"[n.] Pair, couple\n[adj.] Twofold\n[num.] Two","ex":"Bring me these twain cups of wine and water, and let us drink from the one we feel more befitting of this day."},"TWEAK":{"p":"/twiːk/","s":"n./v.","e":"[n.] A sharp pinch or jerk; a twist or twitch.\n[n.] A slight adjustment or modification.\n[n.] Trouble; distress; tweag.\n[v.] To pinch and pull with a sudden jerk and twist; to twitch.\n[v.] To adjust slightly; to fine-tune.\n[v.] To twit or tease.","ex":"a tweak of the nose"},"TWENTY":{"p":"/ˈtwɛnti/","s":"n./num.","e":"[n.] A banknote with a denomination of 20.\n[n.] 10-20 (location).\n[n.] An old English division of infantry.\n[num.] The cardinal number 20, occurring after nineteen and before twenty-one.","ex":"The waiter’s face lit up when I gave him a twenty."},"TWERP":{"p":"/twɜːp/","s":"n.","e":"[n.] A fool, a twit.\n[n.] A small or puny person; one regarded as insignificant, contemptible.\n[n.] A person who can be bullied playfully, or easily teased. Sometimes used as a pet-name (often for a younger sibling).","ex":"Now you've broken it, you twerp!"},"TUTUS":{"p":"","s":"n.","e":"[n.] A ballet skirt made of layered stiff but light netting.\n[n.] Any of the genus Coriaria of shrubs and trees found in New Zealand.","ex":"The ballet dancer representing the swan wore a white tutu."},"TURBO":{"p":"/ˈtɜːbəʊ/","s":"n./v./adj.","e":"[n.] Turbocharger.\n[n.] Turbojet.\n[n.] Turbomolecular pump.\n[v.] To autofire.\n[adj.] With rapidly-increasing blind levels.\n[adj.] Causing or relating to increased speed.","ex":"This is a turbo tournament: the blinds increase every 5 minutes! Level 1 = 150/300; level 2 = 200/400; etc."},"TWICE":{"p":"/twaɪs/","s":"adv.","e":"[adv.] Two times.\n[adv.] (usually with \"as\", of a specified quality) Doubled in quantity, intensity, or degree.","ex":""},"TWANG":{"p":"/twæŋ/","s":"n./v.","e":"[n.] The sharp, quick sound of a vibrating tight string, for example, of a bow or a musical instrument.\n[n.] A particular sharp vibrating sound characteristic of electric guitars.\n[n.] A trace of a regional or foreign accent in someone's voice.\n[v.] To produce or cause to produce a sharp vibrating sound, like a tense string pulled and suddenly let go.\n[v.] To have a nasal sound.\n[v.] To have a trace of a regional or foreign accent.","ex":"Despite having lived in Canada for 20 years, he still has that Eastern-European twang in his voice."},"TWEED":{"p":"/twiːd/","s":"n.","e":"[n.] A coarse woolen fabric used for clothing.","ex":""},"TWEET":{"p":"/twiːt/","s":"n./v./int.","e":"[n.] The sound of a bird; any short high-pitched sound or whistle.\n[n.] An entry posted on the microblogging service Twitter.\n[v.] To make a short high-pitched sound, like that of certain birds.\n[v.] To post an update to Twitter.\n[int.] An onomatopoeic of bird singing.","ex":""},"TWIGS":{"p":"","s":"n./v.","e":"[n.] A small thin branch of a tree or bush.\n[v.] To beat with twigs.\n[v.] To realise something; to catch on; to recognize someone or something.\n[v.] To understand the meaning of (a person); to comprehend.\n[v.] To observe slyly; also, to perceive; to discover.\n[v.] To twitch; to pull; to tweak.","ex":"They used twigs and leaves as a base to start the fire."},"TWELVE":{"p":"/twɛlv/","s":"n./num.","e":"[n.] A group of twelve items.\n[n.] A twelve-bore gun.\n[n.] A jury (normally composed of twelve persons).\n[num.] The cardinal number occurring after eleven and before thirteen, represented in Arabic numerals as 12 and in Roman numerals as XII.\n[num.] Law enforcement; the police","ex":"Fractions would be a little easier if we counted by twelves."},"TWIN":{"p":"/twɪn/","s":"n./v.","e":"[n.] Either of two people (or, less commonly, animals) who shared the same uterus at the same time; one who was born at the same birth as a sibling.\n[n.] Either of two similar or closely related objects, entities etc.\n[n.] A room in a hotel, guesthouse, etc. with two beds; a twin room.\n[v.] (obsolete outside Scotland) To separate, divide.\n[v.] (obsolete outside Scotland) To split, part; to go away, depart.\n[v.] (usually in the passive) To join, unite; to form links between (now especially of two places in different countries).","ex":"Coventry twinned with Dresden as an act of peace and reconciliation, both cities having been heavily bombed during the war."},"TWILL":{"p":"/twɪl/","s":"n./v.","e":"[n.] A pattern, characterised by diagonal ridges, created by the regular interlacing of threads of the warp and weft during weaving.\n[n.] A cloth or portion of cloth woven in such a pattern.\n[v.] To weave (cloth, etc.) so as to produce the appearance of diagonal lines or ribs on the surface.","ex":""},"TWINE":{"p":"/twaɪn/","s":"n.","e":"[n.] A twist; a convolution.\n[n.] A strong thread composed of two or three smaller threads or strands twisted together, and used for various purposes, as for binding small parcels, making nets, and the like; a small cord or string.\n[n.] The act of twining or winding round.","ex":""},"TWINS":{"p":"/twɪnz/","s":"n./v.","e":"[n.] Either of two people (or, less commonly, animals) who shared the same uterus at the same time; one who was born at the same birth as a sibling.\n[n.] Either of two similar or closely related objects, entities etc.\n[n.] A room in a hotel, guesthouse, etc. with two beds; a twin room.\n[v.] (obsolete outside Scotland) To separate, divide.\n[v.] (obsolete outside Scotland) To split, part; to go away, depart.\n[v.] (usually in the passive) To join, unite; to form links between (now especially of two places in different countries).","ex":"Coventry twinned with Dresden as an act of peace and reconciliation, both cities having been heavily bombed during the war."},"TUTOR":{"p":"/ˈtjuːtə/","s":"n./v.","e":"[n.] One who teaches another (usually called a student, learner, or tutee) in a one-on-one or small-group interaction.\n[n.] A university officer responsible for students in a particular hall.\n[n.] One who has the charge of a child or pupil and his estate; a guardian.\n[v.] To instruct or teach, especially an individual or small group.\n[v.] To treat with authority or sternness.","ex":"He passed the difficult class with help from his tutor."},"TWITS":{"p":"","s":"n./v.","e":"[n.] A reproach, gibe or taunt.\n[n.] A foolish or annoying person.\n[n.] A euphemism for \"twat\", a contemptible or stupid person.\n[v.] To reproach, blame; to ridicule or tease.\n[v.] To ignore or killfile (a user on a bulletin board system).","ex":""},"TYPE":{"p":"/taɪp/","s":"n./v.","e":"[n.] A grouping based on shared characteristics; a class.\n[n.] An individual considered typical of its class, one regarded as typifying a certain profession, environment, etc.\n[n.] An individual that represents the ideal for its class; an embodiment.\n[v.] To put text on paper using a typewriter.\n[v.] To enter text or commands into a computer using a keyboard.\n[v.] To determine the blood type of.","ex":"This type of plane can handle rough weather more easily than that type of plane."},"TYING":{"p":"/ˈtaɪ.ɪŋ/","s":"v./n.","e":"[v.] To twist (a string, rope, or the like) around itself securely.\n[v.] To form (a knot or the like) in a string or the like.\n[v.] To attach or fasten (one thing to another) by string or the like.\n[n.] Action of the verb to tie; ligature.\n[n.] The act or process of washing ores in a buddle.","ex":"Tie the rope to this tree."},"TYPED":{"p":"","s":"v./adj.","e":"[v.] To put text on paper using a typewriter.\n[v.] To enter text or commands into a computer using a keyboard.\n[v.] To determine the blood type of.\n[adj.] Typewritten\n[adj.] (of a variable, expression, or value) Having a specific data type.\n[adj.] (of a programming language) In which variables are typed.","ex":"The doctor ordered the lab to type the patient for a blood transfusion."},"TYPES":{"p":"/taɪps/","s":"n./v.","e":"[n.] A grouping based on shared characteristics; a class.\n[n.] An individual considered typical of its class, one regarded as typifying a certain profession, environment, etc.\n[n.] An individual that represents the ideal for its class; an embodiment.\n[v.] To put text on paper using a typewriter.\n[v.] To enter text or commands into a computer using a keyboard.\n[v.] To determine the blood type of.","ex":"This type of plane can handle rough weather more easily than that type of plane."},"TYPOS":{"p":"/ˈtaɪ.pəʊz/","s":"n.","e":"[n.] A typographical error.\n[n.] A compositor; a typographer.","ex":""},"TWIRL":{"p":"/ˈtwɜː(ɹ)l/","s":"n./v.","e":"[n.] A movement where a person spins round elegantly; a pirouette.\n[n.] Any rotating movement; a spin.\n[n.] A little twist of some substance; a swirl.\n[v.] To perform a twirl.\n[v.] To rotate rapidly.\n[v.] To twist round.","ex":"The conductor gave his baton a twirl, and the orchestra began to play."},"TYRES":{"p":"/ˈtaɪə(ɹ)z/","s":"n./v.","e":"[n.] The ring-shaped protective covering around a wheel which is usually made of rubber or plastic composite and is either pneumatic or solid.\n[n.] The metal rim of a wheel, especially that of a railway vehicle.\n[v.] To fit tyres to (a vehicle).\n[v.] To adorn.","ex":""},"TWIST":{"p":"/twɪst/","s":"n./v.","e":"[n.] A twisting force.\n[n.] Anything twisted, or the act of twisting.\n[n.] The form given in twisting.\n[v.] To turn the ends of something, usually thread, rope etc., in opposite directions, often using force.\n[v.] To join together by twining one part around another.\n[v.] To contort; to writhe; to complicate; to crook spirally; to convolve.","ex":""},"TZARS":{"p":"","s":"n.","e":"[n.] An emperor of Russia (1547 to 1917) and of some South Slavic states.\n[n.] A person with great power; an autocrat.","ex":""},"UDDER":{"p":"/ˈʌdə/","s":"n.","e":"[n.] An organ formed of the mammary glands of female quadruped mammals, particularly ruminants such as cattle, goats, sheep and deer.\n[n.] (impolite) A woman's breast.","ex":""},"TYKES":{"p":"","s":"n.","e":"[n.] A mongrel dog.\n[n.] A small child, especially a cheeky or mischievous one\n[n.] A crude uncouth ill-bred person lacking culture or refinement","ex":""},"ULTRA":{"p":"/ˈʌltɹə/","s":"n./adj.","e":"[n.] An ultraroyalist in France.\n[n.] An extremist, especially an ultranationalist.\n[n.] An especially devoted football fan, typically associated with the intimidating use of extremist slogans, pyrotechnics and sometimes hooligan violence.\n[adj.] Extreme; far beyond the norm; fanatical; uncompromising.","ex":"an ultra reformer; ultra measures"},"UNCLE":{"p":"/ˈʌŋ.kəl/","s":"n./v./int.","e":"[n.] The brother or brother-in-law of one’s parent.\n[n.] The male cousin of one’s parent.\n[n.] A companion to one's (usually unmarried) mother.\n[v.] To address somebody by the term uncle.\n[v.] To act like, or as, an uncle.\n[int.] A cry used to indicate surrender.","ex":""},"UGLY":{"p":"/ˈʌɡli/","s":"n./v./adj.","e":"[n.] Ugliness.\n[n.] An ugly person or thing.\n[n.] A shade for the face, projecting from a bonnet.\n[v.] To make ugly (sometimes with up).\n[adj.] Displeasing to the eye; not aesthetically pleasing.\n[adj.] Displeasing to the ear or some other sense.","ex":"He played an ugly trick on us."},"TYPICAL":{"p":"/ˈtɪpɪkl̩/","s":"n./adj.","e":"[n.] Anything that is typical, normal, or standard.\n[adj.] Capturing the overall sense of a thing.\n[adj.] Characteristically representing something by form, group, idea or type.\n[adj.] Normal, average; to be expected.","ex":"Among the moths, typicals were more common than melanics."},"ULCER":{"p":"/ʌlsə/","s":"n.","e":"[n.] An open sore of the skin, eyes or mucous membrane, often caused by an initial abrasion and generally maintained by an inflammation and/or an infection.\n[n.] Peptic ulcer\n[n.] Anything that festers and corrupts like an open sore; a vice in character.","ex":""},"UNDER":{"p":"/ˈʊndə/","s":"adj./adv./prep.","e":"[adj.] Being lower; being beneath something.\n[adj.] Under anesthesia, especially general anesthesia; sedated.\n[adv.] In a way lower or less than.\n[adv.] In a way inferior to.\n[adv.] In an unconscious state.\n[prep.] In or at a lower level than.","ex":"Ensure the patient is sufficiently under."},"UNFIT":{"p":"/ʌnˈfɪt/","s":"v./adj.","e":"[v.] To make unfit; to render unsuitable, spoil, disqualify.\n[adj.] Not fit; not having the correct requirements.\n[adj.] Not fit, not having a good physical demeanor.","ex":"Jack cannot run, making him unfit for the track team."},"UNFED":{"p":"","s":"n./adj.","e":"[n.] A mosquito that has not had a blood meal.\n[adj.] Not fed.\n[adj.] Unsupported.","ex":"The captured mosquitos were divided into feds and unfeds."},"UNDUE":{"p":"/ʌnˈdjuː/","s":"adj.","e":"[adj.] Excessive; going beyond that what is natural or sufficient.\n[adj.] That which ought not to be done; illegal; unjustified.\n[adj.] (of a payment etc) Not owing or payable.","ex":"To individuals who despise killings in any form, death penalty is undue punishment."},"UMBRA":{"p":"/ˈʌmbɹə/","s":"n.","e":"[n.] The fully shaded inner region of a shadow cast by an opaque object.\n[n.] The central region of a sunspot.\n[n.] A shadow.","ex":""},"UNHIP":{"p":"","s":"adj.","e":"[adj.] Not hip; uncool, unfashionable.","ex":""},"UNIFIED":{"p":"/ˈjuː.nɪ.faɪd/","s":"adj./v.","e":"[adj.] United into a whole\n[adj.] That operates as a single entity\n[adj.] (of a school district) that serves all grade levels between kindergarten and twelfth grade.\n[v.] Cause to become one; make into a unit; consolidate; merge; combine.\n[v.] Become one.","ex":""},"UNIFY":{"p":"/ˈjuːnɪfaɪ/","s":"v.","e":"[v.] Cause to become one; make into a unit; consolidate; merge; combine.\n[v.] Become one.","ex":""},"UNCUT":{"p":"","s":"adj.","e":"[adj.] Not cut.\n[adj.] (of a gemstone) Not cut or ground to the desired shape.\n[adj.] (of a book) Not having the page edges trimmed.","ex":""},"UNION":{"p":"/ˈjuːnjən/","s":"n./v.","e":"[n.] The act of uniting or joining two or more things into one.\n[n.] The state of being united or joined; a state of unity or harmony.\n[n.] That which is united, or made one; something formed by a combination or coalition of parts or members; a confederation; a consolidated body; a league.\n[v.] To combine sets using the union operation.","ex":""},"UNIQUE":{"p":"/juːˈniːk/","s":"n./adj.","e":"[n.] A thing without a like; something unequalled or unparallelled.\n[adj.] Being the only one of its kind; unequaled, unparalleled or unmatched.\n[adj.] Of a feature, such that only one holder has it.\n[adj.] Particular, characteristic.","ex":"Every person has a unique life, therefore every person has a unique journey. ― Gary Cook"},"UNIT":{"p":"/ˈjuː.nɪt/","s":"n./adj.","e":"[n.] A particular, minute unit of mass, defined differently for different substances, but so that varying substances of the same general type have the property that one international unit of the one has the same effect on the human body as one international unit of the other.\n[n.] Oneness, singularity, seen as a component of a whole number; a magnitude of one.\n[n.] A standard measure of a quantity.\n[n.] The number one.\n[adj.] For each unit.\n[adj.] Having a size or magnitude of one.","ex":"The centimetre is a unit of length."},"UNITE":{"p":"/juˈnaɪt/","s":"n./v.","e":"[n.] A British gold coin worth 20 shillings, first produced during the reign of King James I, and bearing a legend indicating the king's intention of uniting the kingdoms of England and Scotland.\n[v.] To bring together as one.\n[v.] To come together as one.","ex":"I hope this song can unite people from all different cultures."},"UNITS":{"p":"","s":"n.","e":"[n.] A particular, minute unit of mass, defined differently for different substances, but so that varying substances of the same general type have the property that one international unit of the one has the same effect on the human body as one international unit of the other.\n[n.] Oneness, singularity, seen as a component of a whole number; a magnitude of one.\n[n.] A standard measure of a quantity.\n[n.] The number one.","ex":"The centimetre is a unit of length."},"UNLESS":{"p":"/ənˈlɛs/","s":"conj.","e":"[conj.] Except on a specified condition; if not.\n[conj.] If not; used with counterfactual conditionals.\n[conj.] Except if; used with hypothetical conditionals.","ex":"I’m leaving unless I get a pay rise (AmE: raise)."},"UNITY":{"p":"/ˈjuːnɪtɪ/","s":"n.","e":"[n.] Oneness; the state or fact of being one undivided entity.\n[n.] Agreement; harmony.\n[n.] A single undivided thing, seen as complete in itself.","ex":""},"UNKNOWN":{"p":"/ʌnˈnəʊn/","s":"v./n./adj.","e":"[v.] To undo the process of knowing, to lose knowledge of something.\n[n.] A variable (usually x, y or z) whose value is to be found.\n[n.] Any thing, place, or situation about which nothing is known; an unknown fact or piece of information.\n[n.] A person of no identity; a nonentity\n[adj.] (sometimes postpositive) Not known; unidentified; not well known.","ex":""},"UNLIKE":{"p":"/ʌnˈlaɪk/","s":"n./adj./prep.","e":"[n.] Something that is not like something else; something different.\n[adj.] Not like; dissimilar (to); having no resemblance.\n[adj.] Unequal.\n[adj.] Not likely; improbable; unlikely.\n[prep.] Differently from; not in a like or similar manner.\n[prep.] In contrast with; as opposed to.","ex":"The brothers are quite unlike each other."},"UNMAN":{"p":"","s":"v.","e":"[v.] To castrate; to remove the manhood of.\n[v.] To sap (a person) of the strength, whether physical or emotional, required to deal with a situation.\n[v.] To deprive of men.","ex":"His fear unmanned him."},"UNLIT":{"p":"","s":"adj.","e":"[adj.] Not lit","ex":""},"UNSET":{"p":"","s":"v./adj.","e":"[v.] To make not set.\n[adj.] Not set; not fixed or appointed.\n[adj.] Not mounted or placed in a setting.\n[adj.] Not set, as a broken limb.","ex":"to unset a single bit in a binary pattern"},"UNTIL":{"p":"/ənˈtɪl/","s":"prep./conj.","e":"[prep.] Up to the time of (something happening).\n[prep.] Up to (a certain place)\n[prep.] Before (a time).\n[conj.] Up to the time that (a condition becomes true).\n[conj.] Before (a condition becoming true).","ex":"If you can wait until after my meeting with her, we'll talk then."},"UNUSUAL":{"p":"/ʌnˈjuːʒuəl/","s":"n./adj.","e":"[n.] Something that is unusual; an anomaly.\n[adj.] Not usual, out of the ordinary","ex":"Every once in a while, though, Idol comes across an unusual talent who just blows everyone away."},"UNTIE":{"p":"/ʌnˈtaɪ/","s":"v.","e":"[v.] To loosen, as something interlaced or knotted; to disengage the parts of.\n[v.] To free from fastening or from restraint; to let loose; to unbind.\n[v.] To resolve; to unfold; to clear.","ex":"to untie a knot"},"UPDATE":{"p":"","s":"n./v.","e":"[n.] An advisement providing more up-to-date information than currently known.\n[n.] A change in information, a modification of existing or known data.\n[n.] An additional piece of information. An addition to existing information.\n[v.] To bring (a thing) up to date.\n[v.] To bring (a person) up to date: to inform (a person) about recent developments.","ex":"He gave me an update on the situation in New York."},"UPGRADE":{"p":"/ˈʌp.ɡɹeɪd/","s":"n./v./adv.","e":"[n.] An upward grade or slope.\n[n.] An improved component or replacement item, usually applied to technology\n[n.] An improvement\n[v.] To improve, usually applied to technology, generally by complete replacement of one or more components\n[v.] To replace with something better.\n[v.] To improve the equipment or furnishings of or services rendered to","ex":"With my phone company, I get a free upgrade every twelve months if I keep topping up 10 pounds a month."},"UPON":{"p":"/əˈpɒn/","s":"adv./prep.","e":"[adv.] Being the target of an action.\n[prep.] Physically above and in contact with.\n[prep.] Physically directly supported by.\n[prep.] Being followed by another so as to form a series.","ex":"He was set upon by the agitated dogs"},"UPPED":{"p":"/ʌpt/","s":"v.","e":"[v.] To increase or raise.\n[v.] To promote.\n[v.] (usually in combination with another verb) To act suddenly.","ex":"If we up the volume, we may be able to hear what he says."},"UNDID":{"p":"/ʌnˈdɪd/","s":"v.","e":"[v.] To reverse the effects of an action.\n[v.] To unfasten.\n[v.] To impoverish or ruin, as in reputation; to cause the downfall of.","ex":"Fortunately, we can undo most of the damage to the system by the war."},"UNMET":{"p":"","s":"adj.","e":"[adj.] Not met; unfulfilled; not achieved","ex":""},"URBAN":{"p":"/ˈɜːbən/","s":"adj.","e":"[adj.] Related to the (or any) city.\n[adj.] Characteristic of city life.\n[adj.] Relating to contemporary African American culture.","ex":""},"UNWED":{"p":"","s":"n./v./adj.","e":"[n.] One who is not married; a bachelor or a spinster.\n[v.] To annul the marriage of.\n[v.] To separate.\n[adj.] Not married.","ex":"Should unweds living together receive the same social benefits as married couples?"},"URGER":{"p":"","s":"n.","e":"[n.] One who urges.","ex":""},"UPEND":{"p":"/ʌpˈɛnd/","s":"v.","e":"[v.] To end up; to set on end.\n[v.] To tip or turn over.\n[v.] To destroy, invalidate, overthrow, or defeat.","ex":"When he upended the bottle of water over his sleeping sister, the lid popped off and surprised them both."},"UNZIP":{"p":"","s":"v.","e":"[v.] To open something using a zipper.\n[v.] To come open by means of a zipper.\n[v.] To decompress (a zip file).","ex":""},"URGED":{"p":"/ɜːdʒd/","s":"v.","e":"[v.] To press; to push; to drive; to impel; to force onward.\n[v.] To press the mind or will of; to ply with motives, arguments, persuasion, or importunity.\n[v.] To provoke; to exasperate.","ex":""},"URINE":{"p":"/ˈjʉːəɹɪn/","s":"n./v.","e":"[n.] Liquid waste consisting of water, salts and urea, which is made in the kidneys, stored in the bladder, then released through the urethra.\n[v.] To urinate.","ex":""},"USAGE":{"p":"/ˈjuːsɪd͡ʒ/","s":"n.","e":"[n.] The manner or the amount of using; use.\n[n.] Habit or accepted practice.\n[n.] The ways and contexts in which spoken and written words are used, determined by a lexicographer's intuition or from corpus analysis.","ex":""},"USEFUL":{"p":"/ˈjuːsfəl/","s":"adj.","e":"[adj.] Having a practical or beneficial use.","ex":""},"USER":{"p":"/ˈjuːzə/","s":"n.","e":"[n.] One who uses or makes use of something, a consumer/client or an express or implied licensee (free user) or a trespasser.\n[n.] A person who uses drugs, especially illegal drugs.\n[n.] A person who uses a computer or a computing network, especially a person who has received a user account.","ex":""},"UPSET":{"p":"","s":"n./v./adj.","e":"[n.] Disturbance or disruption.\n[n.] An unexpected victory of a competitor or candidate that was not favored to win.\n[n.] (automobile insurance) An overturn.\n[v.] To make (a person) angry, distressed, or unhappy.\n[v.] To disturb, disrupt or adversely alter (something).\n[v.] To tip or overturn (something).","ex":"My late arrival caused the professor considerable upset."},"USUAL":{"p":"/ˈjuːʒʊəl/","s":"n./adj.","e":"[n.] The typical state of something, or something that is typical.\n[n.] A specific good or service (e.g. a drink) that someone typically orders.\n[adj.] Most commonly occurring; typical.","ex":"I'll just have the usual."},"USHER":{"p":"[ˈaʃ.ə(ɹ)]","s":"n./v.","e":"[n.] A person, in a church, cinema etc., who escorts people to their seats.\n[n.] A male escort at a wedding.\n[n.] A doorkeeper in a courtroom.\n[v.] To guide people to their seats.\n[v.] To accompany or escort (someone).\n[v.] To precede; to act as a forerunner or herald.","ex":""},"USING":{"p":"/ˈjuːzɪŋ/","s":"v./n.","e":"[v.] To utilize or employ.\n[v.] To accustom; to habituate. (Now common only in participial form. Uses the same pronunciation as the noun; see usage notes.)\n[v.] (except in past tense) To habitually do; to be wont to do. (Now chiefly in past-tense forms; see used to.)\n[n.] Use; utilization","ex":"soldiers who are used to hardships and danger"},"USERS":{"p":"","s":"n.","e":"[n.] One who uses or makes use of something, a consumer/client or an express or implied licensee (free user) or a trespasser.\n[n.] A person who uses drugs, especially illegal drugs.\n[n.] A person who uses a computer or a computing network, especially a person who has received a user account.","ex":""},"USURY":{"p":"/ˈjuːʒəɹi/","s":"n.","e":"[n.] An exorbitant rate of interest, in excess of any legal rates or at least immorally.\n[n.] The practice of lending money at such rates.\n[n.] The practice of lending money at interest.","ex":""},"UTERI":{"p":"/ˈjuːtəɹaɪ/","s":"n.","e":"[n.] The womb, an organ of the female reproductive system in which the young are conceived and develop until birth.","ex":""},"URGES":{"p":"","s":"n./v.","e":"[n.] A strong desire; an itch to do something.\n[v.] To press; to push; to drive; to impel; to force onward.\n[v.] To press the mind or will of; to ply with motives, arguments, persuasion, or importunity.\n[v.] To provoke; to exasperate.","ex":""},"UTILE":{"p":"/ˈjuː.taɪl/","s":"n./adj.","e":"[n.] A theoretical unit of measure of utility, for indicating a supposed quantity of satisfaction derived from an economic transaction.\n[adj.] Useful.","ex":""},"UTILITY":{"p":"/juːˈtɪl.ɪ.ti/","s":"n./adj.","e":"[n.] The state or condition of being useful; usefulness.\n[n.] Something that is useful.\n[n.] The ability of a commodity to satisfy needs or wants; the satisfaction experienced by the consumer of that commodity.\n[adj.] Having to do with, or owned by, a service provider.\n[adj.] Designating of a room in a house or building where mechanical equipment is installed; such as a furnace, water tank/heater, circuit breaker, and/or air conditioning unit; and often equipped with hookups for laundry equipment (washer/dryer).","ex":"utility line; utility bill"},"VAGUE":{"p":"/veɪɡ/","s":"n./v./adj.","e":"[n.] A wandering; a vagary.\n[n.] An indefinite expanse.\n[v.] To wander; to roam; to stray.\n[v.] To become vague or act in a vague manner.\n[adj.] Not clearly expressed; stated in indefinite terms.\n[adj.] Not having a precise meaning.","ex":"a vague term of abuse"},"UVULA":{"p":"/ˈjuːv.jʊ.lə/","s":"n.","e":"[n.] The fleshy appendage that hangs from the back of the palate, that closes the nasopharynx during swallowing.\n[n.] The slight elevation in the mucous membrane immediately behind the internal urethral orifice of the urinary bladder, caused by the middle lobe of the prostate.\n[n.] An object so suspended inside a bell that it may hit the bell and cause it to ring; a clapper.","ex":""},"UTTER":{"p":"/ˈʌtə/","s":"adj.","e":"[adj.] Outer; furthest out, most remote.\n[adj.] Outward.\n[adj.] Absolute, unconditional, total, complete.","ex":"utter ruin; utter darkness"},"VALE":{"p":"/veɪl/","s":"n.","e":"[n.] A valley.","ex":""},"VALID":{"p":"/ˈvælɪd/","s":"adj.","e":"[adj.] Well grounded or justifiable, pertinent.\n[adj.] Acceptable, proper or correct; in accordance with the rules.\n[adj.] Related to the current topic, or presented within context, relevant.","ex":"I will believe him as soon as he offers a valid answer."},"VALUE":{"p":"/ˈvæljuː/","s":"n./v.","e":"[n.] The quality (positive or negative) that renders something desirable or valuable.\n[n.] The degree of importance given to something.\n[n.] That which is valued or highly esteemed, such as one's morals, morality, or belief system.\n[v.] To estimate the value of; judge the worth of something.\n[v.] To fix or determine the value of; assign a value to, as of jewelry or art work.\n[v.] To regard highly; think much of; place importance upon.","ex":"The Shakespearean Shylock is of dubious value in the modern world."},"VANES":{"p":"/veɪnz/","s":"n.","e":"[n.] A weather vane\n[n.] Any of several usually relatively thin, rigid, flat, or sometimes curved surfaces radially mounted along an axis, as a blade in a turbine or a sail on a windmill, that is turned by or used to turn a fluid\n[n.] The flattened, web-like part of a feather, consisting of a series of barbs on either side of the shaft","ex":""},"VAPID":{"p":"/ˈveɪp.ɪd/","s":"adj.","e":"[adj.] Offering nothing that is stimulating or challenging.\n[adj.] Lifeless, dull, or banal.\n[adj.] Tasteless, bland, or insipid.","ex":""},"VARIOUS":{"p":"/ˈvɛə.ɹi.əs/","s":"adj.","e":"[adj.] Having a broad range (of different elements).\n[adj.] That varies or differs from others; variant; different.","ex":"The reasons are various."},"VALES":{"p":"","s":"n.","e":"[n.] A valley.","ex":""},"VARY":{"p":"/ˈvɛəɹi/","s":"n./v.","e":"[n.] Alteration; change.\n[v.] To change with time or a similar parameter.\n[v.] To institute a change in, from a current state; to modify.\n[v.] Not to remain constant: to change with time or a similar parameter.","ex":"He varies his magic tricks so as to minimize the possibility that any given audience member will see the same trick twice."},"VALOR":{"p":"/ˈvælɚ/","s":"n.","e":"[n.] Value; worth.\n[n.] Strength of mind in regard to danger; that quality which enables a person to encounter danger with firmness","ex":""},"VEGAN":{"p":"/ˈviːɡən/","s":"n./adj.","e":"[n.] A person who does not eat, drink or otherwise consume any animal products\n[n.] A person committed to avoiding products and practices that inherently involve animal use, including all foods containing animal products, and to abstaining from direct and intentional harm to animals as far as possible; an adherent to veganism.\n[adj.] (of a product or practice, especially food) Not containing animal products (meat, eggs, milk, leather, etc) or inherently involving animal use.\n[adj.] (of a person) Committed to avoiding any product or practice that inherently involves animal use.\n[adj.] Relating to vegans or veganism.","ex":"Our vegan-friendly shaving brush is made with synthetic bristles instead of badger hair."},"VELDT":{"p":"","s":"n.","e":"[n.] The open pasture land or grassland of South Africa and neighboring countries.","ex":""},"VENAL":{"p":"/ˈviːnəl/","s":"adj.","e":"[adj.] Venous; pertaining to veins.","ex":""},"VASES":{"p":"","s":"n.","e":"[n.] An upright open container used mainly for displaying fresh, dried, or artificial flowers.\n[n.] The body of the Corinthian capital.","ex":""},"VAST":{"p":"/vɑːst/","s":"n./adj.","e":"[n.] A vast space.\n[adj.] Very large or wide (literally or figuratively).\n[adj.] Very great in size, amount, degree, intensity, or especially extent.\n[adj.] Waste; desert; desolate; lonely.","ex":"The Sahara desert is vast."},"VENOM":{"p":"/ˈvɛnəm/","s":"n./v./adj.","e":"[n.] A poison carried by an animal, usually injected into an enemy or prey by biting or stinging.\n[n.] Feeling or speech marked by spite or malice; vitriol.\n[v.] To infect with venom; to envenom; to poison.\n[adj.] Poisonous, poisoned; (figuratively) pernicious.","ex":""},"VERSION":{"p":"/ˈvɜːʃən/","s":"n./v.","e":"[n.] A specific form or variation of something.\n[n.] A translation from one language to another.\n[n.] A school exercise, generally of composition in a foreign language.\n[v.] To keep track of (a file, document, etc.) in a versioning system.","ex":"It's only in the King James Version of the Bible."},"VENTURE":{"p":"/ˈvɛn.t͡ʃə/","s":"n./v.","e":"[n.] A risky or daring undertaking or journey.\n[n.] An event that is not, or cannot be, foreseen.\n[n.] The thing risked; especially, something sent to sea in trade.\n[v.] To undertake a risky or daring journey.\n[v.] To risk or offer.\n[v.] To dare to engage in; to attempt without any certainty of success. Used with at or on","ex":"Nothing ventured, nothing gained."},"VESTS":{"p":"","s":"n./v.","e":"[n.] A loose robe or outer garment worn historically by men in Arab or Middle Eastern countries.\n[n.] A sleeveless garment that buttons down the front, worn over a shirt, and often as part of a suit; a waistcoat.\n[n.] A sleeveless garment, often with a low-cut neck, usually worn under a shirt or blouse.\n[v.] To clothe with, or as with, a vestment, or garment; to dress; to robe; to cover, surround, or encompass closely.\n[v.] To clothe with authority, power, etc.; to put in possession; to invest; to furnish; to endow; followed by with and the thing conferred.\n[v.] To place or give into the possession or discretion of some person or authority; to commit to another; with in before the possessor.","ex":"to vest a court with power to try cases of life and death"},"VENTS":{"p":"","s":"n./v.","e":"[n.] An opening through which gases, especially air, can pass.\n[n.] A small aperture.\n[n.] The opening of a volcano from which lava flows.\n[v.] To allow gases to escape.\n[v.] To allow to escape through a vent.\n[v.] To express a strong emotion.","ex":"the vent of a cask; the vent of a mould"},"VIBES":{"p":"/vaɪbz/","s":"n./v.","e":"[n.] A vibraphone.\n[n.] Vibration.\n[n.] A vibrator (sex toy).\n[v.] To stimulate with a vibrator.\n[v.] To relax and enjoy oneself.\n[v.] To agree.","ex":""},"VIAND":{"p":"","s":"n.","e":"[n.] An item of food eaten with rice.","ex":""},"VEST":{"p":"/vɛst/","s":"n./v.","e":"[n.] A loose robe or outer garment worn historically by men in Arab or Middle Eastern countries.\n[n.] A sleeveless garment that buttons down the front, worn over a shirt, and often as part of a suit; a waistcoat.\n[n.] A sleeveless garment, often with a low-cut neck, usually worn under a shirt or blouse.\n[v.] To clothe with, or as with, a vestment, or garment; to dress; to robe; to cover, surround, or encompass closely.\n[v.] To clothe with authority, power, etc.; to put in possession; to invest; to furnish; to endow; followed by with and the thing conferred.\n[v.] To place or give into the possession or discretion of some person or authority; to commit to another; with in before the possessor.","ex":"to vest a court with power to try cases of life and death"},"VEINS":{"p":"/veɪnz/","s":"n./v.","e":"[n.] A blood vessel that transports blood from the capillaries back to the heart.\n[n.] (in plural) The entrails of a shrimp.\n[n.] In leaves, a thickened portion of the leaf containing the vascular bundle.\n[v.] To mark with veins or a vein-like pattern.","ex":""},"VICES":{"p":"","s":"n.","e":"[n.] A bad habit.\n[n.] Any of various crimes related (depending on jurisdiction) to prostitution, pornography, gambling, alcohol, or drugs.\n[n.] A defect in the temper or behaviour of a horse, such as to make the animal dangerous, to injure its health, or to diminish its usefulness.\n[n.] A mechanical screw apparatus used for clamping or holding (also spelled vise).\n[n.] A tool for drawing lead into cames, or flat grooved rods, for casements.\n[n.] A grip or grasp.","ex":"Gluttony is a vice, not a virtue."},"VETERAN":{"p":"[ˈvɛ.t̬ə.ɹən]","s":"n./adj.","e":"[n.] A person with long experience of a particular activity.\n[n.] A group, animal, etc. with long experience of a particular activity.\n[n.] A person who has served in the armed forces, especially an old soldier who has seen long service; also called a war veteran to distinguish from veterans that weren't in armed conflict.\n[adj.] Having had long experience, practice, or service.\n[adj.] Of or relating to former members of the military armed forces, especially those who served during wartime.","ex":""},"VIGIL":{"p":"/ˈvɪdʒəl/","s":"n.","e":"[n.] An instance of keeping awake during normal sleeping hours, especially to keep watch or pray.\n[n.] A period of observation or surveillance at any hour.\n[n.] The eve of a religious festival in which staying awake is part of the ritual devotions.","ex":"His dog kept vigil outside the hospital for eight days while he was recovering from an accident."},"VIEWS":{"p":"/vjuːz/","s":"n./v.","e":"[n.] (physical) Visual perception.\n[n.] A picture, drawn or painted; a sketch.\n[n.] (psychological) Opinion, judgement, imagination.\n[v.] To look at.\n[v.] To regard in a stated way.","ex":"a fine view of Lake George"},"VINYL":{"p":"/ˈvaɪ.nəl/","s":"n./adj.","e":"[n.] The univalent radical CH2=CH−, derived from ethylene.\n[n.] Any of various compounds and substances containing the vinyl radical, especially various tough, flexible, shiny plastics.\n[n.] Phonograph records as a medium.\n[adj.] Containing the vinyl radical.\n[adj.] Made of polyvinyl chloride.\n[adj.] Pertaining to a phonograph record.","ex":"Many DJs prefer vinyl to CDs."},"VILLA":{"p":"/ˈvɪlə/","s":"n.","e":"[n.] (plural \"villas\") A house, often larger and more expensive than average, in the countryside or on the coast, often used as a retreat.\n[n.] (plural \"villas\") A family house, often semi-detached, in a middle class street.\n[n.] (plural \"villae\") A country house, with farm buildings around a courtyard.","ex":""},"VILER":{"p":"","s":"adj.","e":"[adj.] Morally low; base; despicable.\n[adj.] Causing physical or mental repulsion; horrid.","ex":"I glimpsed a vile squid-like creature in the depths."},"VIOLS":{"p":"","s":"n.","e":"[n.] A stringed instrument related to the violin family, but held in the lap between the legs like a cello, usually with C-holes, a flat back, a fretted neck and six strings, played with an underhanded bow hold.","ex":""},"VIPER":{"p":"/ˈvaɪpɚ/","s":"n.","e":"[n.] A venomous snake in the family Viperidae.\n[n.] A dangerous, treacherous, or malignant person.\n[n.] A person who smokes marijuana.","ex":""},"VILLAGE":{"p":"/ˈvɪlɪd͡ʒ/","s":"n.","e":"[n.] A rural habitation of size between a hamlet and a town.\n[n.] A rural habitation that has a church, but no market.\n[n.] A planned community such as a retirement community or shopping district.","ex":"There are 2 churches and 3 shops in our village."},"VIRAL":{"p":"/ˈvaɪɹəl/","s":"n./adj.","e":"[n.] A video, image or text spread by \"word of mouth\" on the internet or by e-mail for humorous, political or marketing purposes.\n[adj.] Of or relating to a biological virus.\n[adj.] Caused by a virus.\n[adj.] Of the nature of an informatic virus; able to spread copies of itself to other computers.","ex":"viral DNA"},"VISION":{"p":"/ˈvɪ.ʒ(ə)n/","s":"n./v.","e":"[n.] The sense or ability of sight.\n[n.] Something seen; an object perceived visually.\n[n.] Something imaginary one thinks one sees.\n[v.] To imagine something as if it were to be true.\n[v.] To present as in a vision.\n[v.] To provide with a vision.","ex":"He tried drinking from the pool of water, but realized it was only a vision."},"VOGUE":{"p":"/vəʊɡ/","s":"n./v.","e":"[n.] The prevailing fashion or style.\n[n.] Popularity or a current craze.\n[n.] A highly stylized modern dance that evolved out of the Harlem ballroom scene in the 1960s.\n[v.] To dance in the vogue dance style.\n[v.] To light a cigarette.","ex":"Miniskirts were the vogue in the '60s."},"VISIT":{"p":"/ˈvɪzɪt/","s":"n./v.","e":"[n.] A single act of visiting.\n[n.] A meeting with a doctor at their surgery or the doctor's at one's home.\n[v.] To habitually go to (someone in distress, sickness etc.) to comfort them. (Now generally merged into later senses, below.)\n[v.] To go and meet (a person) as an act of friendliness or sociability.\n[v.] Of God: to appear to (someone) to comfort, bless, or chastise or punish them. (Now generally merged into later senses, below.)","ex":""},"VINES":{"p":"/vaɪnz/","s":"n.","e":"[n.] The climbing plant that produces grapes.\n[n.] Any plant of the genus Vitis.\n[n.] (by extension) Any similar climbing or trailing plant.","ex":""},"VOID":{"p":"/vɔɪd/","s":"n./v./adj.","e":"[n.] An empty space; a vacuum.\n[n.] An extended region of space containing no galaxies\n[n.] A collection of adjacent vacancies inside a crystal lattice.\n[v.] To make invalid or worthless.\n[v.] To empty.\n[v.] To throw or send out; to evacuate; to emit; to discharge.","ex":"Nobody has crossed the void since one man died trying three hundred years ago; it's high time we had another go."},"VOLES":{"p":"","s":"n.","e":"[n.] Any of a large number of species of small rodents of the subfamily Arvicolinae of the family Cricetidae which are not lemmings or muskrats.\n[n.] A deal in a card game, écarté, that draws all the tricks.","ex":""},"VOLTS":{"p":"","s":"n.","e":"[n.] In the International System of Units, the derived unit of electrical potential and electromotive force (voltage); the potential difference across a conductor when a current of one ampere uses one watt of power. Symbol: V\n[n.] A circular tread; a gait by which a horse going sideways round a centre makes two concentric tracks.\n[n.] A sudden movement to avoid a thrust.","ex":""},"VOTE":{"p":"/vəʊt/","s":"n./v.","e":"[n.] A formalized choice on matters of administration or other democratic activities\n[n.] An act or instance of participating in such a choice, e.g., by submitting a ballot\n[n.] An ardent wish or desire; a vow; a prayer\n[v.] To cast a vote; to assert a formalized choice in an election\n[v.] To choose or grant by means of a vote, or by general consent","ex":"One occasion indicative votes were used was in 2003 when MPs were presented with seven different options on how to reform the House of Lords."},"VOTED":{"p":"","s":"v.","e":"[v.] To cast a vote; to assert a formalized choice in an election\n[v.] To choose or grant by means of a vote, or by general consent","ex":"Did you vote last month?"},"VOTES":{"p":"/vəʊts/","s":"n./v.","e":"[n.] A formalized choice on matters of administration or other democratic activities\n[n.] An act or instance of participating in such a choice, e.g., by submitting a ballot\n[n.] An ardent wish or desire; a vow; a prayer\n[v.] To cast a vote; to assert a formalized choice in an election\n[v.] To choose or grant by means of a vote, or by general consent","ex":"One occasion indicative votes were used was in 2003 when MPs were presented with seven different options on how to reform the House of Lords."},"VOICE":{"p":"/vɔɪs/","s":"n.","e":"[n.] Sound uttered by the mouth, especially by human beings in speech or song; sound thus uttered considered as possessing some special quality or character\n[n.] Sound made through vibration of the vocal cords; sonant, or intonated, utterance; tone; — distinguished from mere breath sound as heard in whispering and voiceless consonants.\n[n.] The tone or sound emitted by an object","ex":"His low voice allowed him to become a bass in the choir."},"VROOM":{"p":"/vɹuːm/","s":"n./v./int.","e":"[n.] The sound of an engine revving up.\n[v.] To move with great speed; to zoom.\n[int.] The sound of an engine revving up.","ex":"I never saw my uncle’s Ferrari, but I could always hear it going vroom as it flew past by my house."},"VOWED":{"p":"/vaʊd/","s":"v./adj.","e":"[v.] To make a vow; to promise.\n[v.] To make a vow regarding (something).\n[v.] To declare publicly that one has made a vow, usually to show one's determination or to announce an act of retaliation.\n[adj.] Undertaken in accordance with a vow; solemnly promised.","ex":"The wronged woman vowed revenge."},"WAGER":{"p":"/ˈweɪdʒɚ/","s":"n./v.","e":"[n.] Something deposited, laid, or hazarded on the event of a contest or an unsettled question; a bet; a stake; a pledge.\n[n.] That on which bets are laid; the subject of a bet.\n[n.] A contract by which two parties or more agree that a certain sum of money, or other thing, shall be paid or delivered to one of them, on the happening or not happening of an uncertain event.\n[v.] To bet something; to put it up as collateral\n[v.] To suppose; to dare say.","ex":"I'd wager my boots on it."},"VOWEL":{"p":"/vaʊl/","s":"n./v.","e":"[n.] A sound produced by the vocal cords with relatively little restriction of the oral cavity, forming the prominent sound of a syllable.\n[n.] A letter representing the sound of vowel; in English, the vowels are a, e, i, o, u, and sometimes y.\n[v.] To add vowel points to a consonantal script (e.g. niqqud in Hebrew or harakat in Arabic)","ex":""},"VYING":{"p":"/ˈvaɪ.ɪŋ/","s":"v./n.","e":"[v.] To fight for superiority; to contend; to compete eagerly so as to gain something.\n[v.] To rival (something), etc.\n[v.] To do or produce in emulation, competition, or rivalry; to put in competition; to bandy.\n[n.] The act of one who vies; rivalry.","ex":"Her suitors were all vying for her attention."},"WAIFS":{"p":"","s":"n.","e":"[n.] A castaway; a homeless child.\n[n.] (of a plant outside its native range) A plant that has been introduced but is not persistently naturalized.\n[n.] Goods found of which the owner is not known; originally, such goods as a pursued thief threw away to prevent being apprehended, which belonged to the king unless the owner made pursuit of the felon, took him, and brought him to justice.","ex":""},"WACKY":{"p":"/ˈwæk.iː/","s":"adj.","e":"[adj.] Zany; eccentric","ex":""},"WAILS":{"p":"","s":"n./v.","e":"[n.] A prolonged cry, usually high-pitched, especially as of grief or anguish.\n[n.] Any similar sound as of lamentation; a howl.\n[n.] A sound made by emergency vehicle sirens, contrasted with \"yelp\" which is higher-pitched and faster.\n[v.] To cry out, as in sorrow or anguish.\n[v.] To weep, lament persistently or bitterly.\n[v.] To make a noise like mourning or crying.","ex":"She let out a loud, doleful wail."},"WAIST":{"p":"/weɪst/","s":"n.","e":"[n.] The part of the body between the pelvis and the stomach.\n[n.] A part of a piece of clothing that covers the waist.\n[n.] The narrow connection between the thorax and abdomen in certain insects (e.g., bees, ants and wasps).","ex":""},"WAFER":{"p":"/ˈweɪfə/","s":"n./v.","e":"[n.] A light, thin, flat biscuit/cookie.\n[n.] (christianity) A thin disk of consecrated unleavened bread used in communion.\n[n.] A soft disk originally made of flour, and later of gelatin or a similar substance, used to seal letters, attach papers etc.\n[v.] To seal or fasten with a wafer.","ex":""},"WAIT":{"p":"/weɪt/","s":"n./v.","e":"[n.] A delay.\n[n.] An ambush.\n[n.] One who watches; a watchman.\n[v.] To delay movement or action until the arrival or occurrence of; to await. (Now generally superseded by “wait for”.)\n[v.] To delay movement or action until some event or time; to remain neglected or in readiness.\n[v.] To wait tables; to serve customers in a restaurant or other eating establishment.","ex":"I had a very long wait at the airport security check."},"WAGES":{"p":"/ˈweɪd͡ʒɪz/","s":"n./v.","e":"[n.] (often in plural) An amount of money paid to a worker for a specified quantity of work, usually calculated on an hourly basis and expressed in an amount of money per hour.\n[v.] To wager, bet.\n[v.] To expose oneself to, as a risk; to incur, as a danger; to venture; to hazard.\n[v.] To employ for wages; to hire.","ex":"Before her promotion, her wages were 20% less."},"WAGED":{"p":"/weɪdʒd/","s":"v.","e":"[v.] To wager, bet.\n[v.] To expose oneself to, as a risk; to incur, as a danger; to venture; to hazard.\n[v.] To employ for wages; to hire.","ex":""},"WAITING":{"p":"[ˈweɪ̯ɾɪŋ]","s":"v./n.","e":"[v.] To delay movement or action until the arrival or occurrence of; to await. (Now generally superseded by “wait for”.)\n[v.] To delay movement or action until some event or time; to remain neglected or in readiness.\n[v.] To wait tables; to serve customers in a restaurant or other eating establishment.\n[n.] Watching.\n[n.] The act of staying or remaining in expectation.\n[n.] Attendance, service.","ex":"Wait here until your car arrives."},"WAKED":{"p":"/ˈweɪkt/","s":"v.","e":"[v.] (often followed by up) To stop sleeping.\n[v.] (often followed by up) To make somebody stop sleeping; to rouse from sleep.\n[v.] To put in motion or action; to arouse; to excite.","ex":"I woke up at four o'clock this morning."},"WAKEN":{"p":"/ˈweɪkən/","s":"v.","e":"[v.] To wake or rouse from sleep.\n[v.] To awaken; to cease to sleep; to be awakened; to stir.","ex":""},"WAITS":{"p":"","s":"n./v.","e":"[n.] A delay.\n[n.] An ambush.\n[n.] One who watches; a watchman.\n[v.] To delay movement or action until the arrival or occurrence of; to await. (Now generally superseded by “wait for”.)\n[v.] To delay movement or action until some event or time; to remain neglected or in readiness.\n[v.] To wait tables; to serve customers in a restaurant or other eating establishment.","ex":"I had a very long wait at the airport security check."},"WALKING":{"p":"/ˈwɔːkɪŋ/","s":"v./adj.","e":"[v.] To move on the feet by alternately setting each foot (or pair or group of feet, in the case of animals with four or more feet) forward, with at least one foot on the ground at all times. Compare run.\n[v.] To \"walk free\", i.e. to win, or avoid, a criminal court case, particularly when actually guilty.\n[v.] Of an object, to go missing or be stolen.\n[adj.] Incarnate as a human; living.\n[adj.] Able to walk in spite of injury or sickness.\n[adj.] Characterized by or suitable for walking.","ex":"To walk briskly for an hour every day is to keep fit."},"WALL":{"p":"/wɔːl/","s":"n./v.","e":"[n.] A rampart of earth, stones etc. built up for defensive purposes.\n[n.] A structure built for defense surrounding a city, castle etc.\n[n.] Each of the substantial structures acting either as the exterior of or divisions within a structure.\n[v.] To enclose with, or as if with, a wall or walls.","ex":"The town wall was surrounded by a moat."},"WALLET":{"p":"/ˈwɒlɪt/","s":"n.","e":"[n.] A small case, often flat and often made of leather, for keeping money (especially paper money), credit cards, etc.\n[n.] (by extension) A person's bank account or assets.\n[n.] A thick case or folder with plastic sleeves in which compact discs may be stored.","ex":"The thief stole all the money and credit cards out of the old man's wallet."},"WALTZ":{"p":"/wɔːlts/","s":"n./v.","e":"[n.] A ballroom dance in 3/4 time.\n[n.] A piece of music for this dance (or in triple time).\n[n.] A simple task.\n[v.] To dance the waltz (with).\n[v.] (usually with in, into, around, etc.) To move briskly and unhesitatingly, especially in an inappropriately casual manner, or when unannounced or uninvited.\n[v.] To accomplish a task with little effort.","ex":"They waltzed for twenty-one hours and seventeen minutes straight, setting a record."},"WANTS":{"p":"/wɒnts/","s":"n./v.","e":"[n.] A desire, wish, longing.\n[n.] (often followed by of) Lack, absence.\n[n.] Poverty.\n[v.] To wish for or desire (something); to feel a need or desire for; to crave or demand.\n[v.] (in particular) To wish, desire or demand to see, have the presence of or do business with.\n[v.] To desire (to experience desire); to wish.","ex":"What do you want to eat?  I want you to leave.  I never wanted to go back to live with my mother."},"WANT":{"p":"/wɔnt/","s":"n./v.","e":"[n.] A desire, wish, longing.\n[n.] (often followed by of) Lack, absence.\n[n.] Poverty.\n[v.] To wish for or desire (something); to feel a need or desire for; to crave or demand.\n[v.] (in particular) To wish, desire or demand to see, have the presence of or do business with.\n[v.] To desire (to experience desire); to wish.","ex":"What do you want to eat?  I want you to leave.  I never wanted to go back to live with my mother."},"WARES":{"p":"/wɛəz/","s":"n.","e":"[n.] (usually in combination) Goods or a type of goods offered for sale or use.\n[n.] (in the plural) See wares.\n[n.] Pottery or metal goods.\n[n.] Goods or services that are for sale.","ex":"damascene ware, tole ware"},"WARD":{"p":"/wɔːd/","s":"n.","e":"[n.] A warden; a guard; a guardian or watchman.","ex":""},"WADDY":{"p":"/ˈwɒdi/","s":"n.","e":"[n.] A cowboy.","ex":""},"WARMS":{"p":"","s":"n./v.","e":"[n.] The act of warming, or the state of being warmed; a heating.\n[v.] To make or keep warm.\n[v.] To become warm, to heat up.\n[v.] To favour increasingly.","ex":"Shall I give your coffee a warm in the microwave?"},"WARMTH":{"p":"/wɔːmθ/","s":"n.","e":"[n.] A moderate degree of heat; the sensation of being warm.\n[n.] Friendliness, kindness or affection.\n[n.] Fervor, intensity of emotion or expression.","ex":""},"WARNS":{"p":"","s":"v.","e":"[v.] To make (someone) aware of (something impending); especially:\n[v.] To caution or admonish (someone) against unwise or unacceptable behaviour.\n[v.] (chiefly with \"off\", \"away\", and similar words) To advise or order to go or stay away.","ex":"Don't let me catch you running in the corridor again, I warn you."},"WARNING":{"p":"/ˈwɔːnɪŋ/","s":"v./n./int.","e":"[v.] To make (someone) aware of (something impending); especially:\n[v.] To caution or admonish (someone) against unwise or unacceptable behaviour.\n[v.] (chiefly with \"off\", \"away\", and similar words) To advise or order to go or stay away.\n[n.] The action of the verb warn; an instance of warning someone.\n[n.] Something spoken or written that is intended to warn.\n[int.] Used to warn of danger in signs and notices.","ex":"Don't let me catch you running in the corridor again, I warn you."},"WASTE":{"p":"/weɪst/","s":"n.","e":"[n.] Excess of material, useless by-products or damaged, unsaleable products; garbage; rubbish.\n[n.] Excrement or urine.\n[n.] A waste land; an uninhabited desolate region; a wilderness or desert.","ex":"The cage was littered with animal waste"},"WATCH":{"p":"/wɒt͡ʃ/","s":"n.","e":"[n.] A portable or wearable timepiece.\n[n.] The act of guarding and observing someone or something.\n[n.] A particular time period when guarding is kept.","ex":"More people today carry a watch on their wrists than in their pockets."},"WATTS":{"p":"","s":"n.","e":"[n.] In the International System of Units, the derived unit of power; the power of a system in which one joule of energy is transferred per second. Symbol: W","ex":""},"WAVE":{"p":"/weɪv/","s":"v.","e":"[v.] To move back and forth repeatedly and somewhat loosely.\n[v.] To move one’s hand back and forth (generally above the shoulders) in greeting or departure.\n[v.] (metonymic) To call attention to, or give a direction or command to, by a waving motion, as of the hand; to signify by waving; to beckon; to signal; to indicate.","ex":"The flag waved in the gentle breeze."},"WATER":{"p":"/ˈwoːtə/","s":"n.","e":"[n.] A substance (of molecular formula H₂O) found at room temperature and pressure as a clear liquid; it is present naturally as rain, and found in rivers, lakes and seas; its solid form is ice and its gaseous form is steam.\n[n.] The aforementioned liquid, considered one of the Classical elements or basic elements of alchemy.\n[n.] Water in a body; an area of open water.","ex":"By the action of electricity, the water was resolved into its two parts, oxygen and hydrogen."},"WAXEN":{"p":"","s":"adj.","e":"[adj.] Grown.","ex":""},"WAVER":{"p":"/ˈweɪ.və(ɹ)/","s":"n./v.","e":"[n.] An act of wavering, vacillating, etc.\n[n.] Someone who waves, enjoys waving, etc.\n[n.] Someone who specializes in waving (hair treatment).\n[v.] To sway back and forth; to totter or reel.\n[v.] To flicker, glimmer, quiver, as a weak light.\n[v.] To fluctuate or vary, as commodity prices or a poorly sustained musical pitch.","ex":"I felt encouraged by all the enthusiastic wavers in the crowd."},"WAYS":{"p":"/weɪz/","s":"n.","e":"[n.] (heading) To do with a place or places.\n[n.] A method or manner of doing something; a mannerism.\n[n.] A state or condition\n[n.] The letter for the w sound in Pitman shorthand.\n[n.] (usually preceded by a) A distance.","ex":"You're going about it the wrong way.  He's known for his quirky ways.  I don't like the way she looks at me."},"WEARY":{"p":"/ˈwiːɹi/","s":"v./adj.","e":"[v.] To make or to become weary.\n[adj.] Having the strength exhausted by toil or exertion; tired; fatigued.\n[adj.] Having one's patience, relish, or contentment exhausted; tired; sick.\n[adj.] Expressive of fatigue.","ex":"A weary traveller knocked at the door."},"WEARS":{"p":"/wɛəz/","s":"v./n.","e":"[v.] To carry or have equipped on or about one's body, as an item of clothing, equipment, decoration, etc.\n[v.] To have or carry on one's person habitually, consistently; or, to maintain in a particular fashion or manner.\n[v.] To bear or display in one's aspect or appearance.\n[v.] To guard; watch; keep watch, especially from entry or invasion.\n[v.] To defend; protect.\n[v.] To ward off; prevent from approaching or entering; drive off; repel.","ex":"He's wearing some nice pants today.  She wore her medals with pride.  Please wear your seatbelt.  Can you wear makeup and sunscreen at the same time?  He was wearing his lunch after tripping and falling into the buffet."},"WEAPON":{"p":"/ˈwɛ.pən/","s":"n.","e":"[n.] An instrument of attack or defense in combat or hunting, e.g. most guns, missiles, or swords.\n[n.] An instrument or other means of harming or exerting control over another.\n[n.] A tool of any kind.","ex":"The club that is now mostly used for golf was once a common weapon."},"WEAR":{"p":"/wɛə/","s":"n./v.","e":"[n.] (in combination) clothing\n[n.] Damage to the appearance and/or strength of an item caused by use over time\n[n.] Fashion\n[v.] To carry or have equipped on or about one's body, as an item of clothing, equipment, decoration, etc.\n[v.] To have or carry on one's person habitually, consistently; or, to maintain in a particular fashion or manner.\n[v.] To bear or display in one's aspect or appearance.","ex":"footwear; outdoor wear; maternity wear"},"WEATHER":{"p":"/ˈwɛðə/","s":"n./v./adj.","e":"[n.] The short term state of the atmosphere at a specific time and place, including the temperature, relative humidity, cloud cover, precipitation, wind, etc.\n[n.] Unpleasant or destructive atmospheric conditions, and their effects.\n[n.] The direction from which the wind is blowing; used attributively to indicate the windward side.\n[v.] To expose to the weather, or show the effects of such exposure, or to withstand such effects.\n[v.] (by extension) To sustain the trying effect of; to bear up against and overcome; to endure; to resist.\n[v.] To break down, of rocks and other materials, under the effects of exposure to rain, sunlight, temperature, and air.","ex":"Wooden garden furniture must be well oiled as it is continuously exposed to weather."},"WEAVE":{"p":"/wiːv/","s":"n./v.","e":"[n.] A type or way of weaving.\n[n.] Human or artificial hair worn to alter one's appearance, either to supplement or to cover the natural hair.\n[v.] To form something by passing lengths or strands of material over and under one another.\n[v.] To spin a cocoon or a web.\n[v.] To unite by close connection or intermixture.","ex":"That rug has a very tight weave."},"WEDDING":{"p":"/ˈwɛdɪŋ/","s":"v./n.","e":"[v.] To perform the marriage ceremony for; to join in matrimony.\n[v.] To take as one's spouse.\n[v.] To take a spouse.\n[n.] Marriage ceremony; ritual officially celebrating the beginning of a marriage.\n[n.] Joining of two or more parts.","ex":"The priest wed the couple."},"WEBSITE":{"p":"/ˈwɛbˌsaɪt/","s":"n.","e":"[n.] A collection of interlinked web pages on the World Wide Web that are typically accessible from the same base URL and reside on the same server.","ex":""},"WEDGE":{"p":"/wɛdʒ/","s":"n./v.","e":"[n.] One of the simple machines; a piece of material, such as metal or wood, thick at one edge and tapered to a thin edge at the other for insertion in a narrow crevice, used for splitting, tightening, securing, or levering.\n[n.] A piece (of food, metal, wood etc.) having this shape.\n[n.] A five-sided polyhedron with a rectangular base, two rectangular or trapezoidal sides meeting in an edge, and two triangular ends.\n[v.] To support or secure using a wedge.\n[v.] To force into a narrow gap.\n[v.] To work wet clay by cutting or kneading for the purpose of homogenizing the mass and expelling air bubbles.","ex":"Stick a wedge under the door, will you? It keeps blowing shut."},"WEEK":{"p":"/wiːk/","s":"n.","e":"[n.] Any period of seven consecutive days.\n[n.] A period of seven days beginning with Sunday or Monday.\n[n.] A period of five days beginning with Monday.","ex":""},"WEEKLY":{"p":"/wiːk.li/","s":"n./adj./adv.","e":"[n.] A publication that is published once a week.\n[adj.] Of or relating to a week.\n[adj.] Happening once a week, or every week.\n[adv.] Once every week.\n[adv.] Every week.","ex":"He's going for his weekly check-up at the hospital."},"WEEPS":{"p":"","s":"v.","e":"[v.] To cry; shed tears.\n[v.] To lament; to complain.\n[v.] (of a wound or sore) To produce secretions.","ex":""},"WEFTS":{"p":"","s":"n.","e":"[n.] The horizontal threads that are interlaced through the warp in a woven fabric.\n[n.] The yarn used for the weft; the fill.\n[n.] (hairdressing) A hair extension that is glued directly to a person′s natural hair.\n[n.] Something cast away; a waif.","ex":""},"WEEPY":{"p":"/ˈwiːpi/","s":"n./adj.","e":"[n.] A sad or sentimental film, often portraying troubled romance, designed to elicit a tearfully emotional response from its audience.\n[adj.] Inclined to weep; tearful or lachrymose.","ex":""},"WEIRD":{"p":"/ˈwiːəd/","s":"n./v./adj.","e":"[n.] Fate; destiny; luck.\n[n.] A prediction.\n[n.] A spell or charm.\n[v.] To destine; doom; change by witchcraft or sorcery.\n[v.] To warn solemnly; adjure.\n[adj.] Having an unusually strange character or behaviour.","ex":"There are lots of weird people in this place."},"WELLS":{"p":"/wɛlz/","s":"n./v.","e":"[n.] A hole sunk into the ground as a source of water, oil, natural gas or other fluids.\n[n.] A place where a liquid such as water surfaces naturally; a spring.\n[n.] A small depression suitable for holding liquid or other objects.\n[v.] To issue forth, as water from the earth; to flow; to spring.\n[v.] To have something seep out of the surface.","ex":"Make a well in the dough mixture and pour in the milk."},"WENDS":{"p":"","s":"v.","e":"[v.] To turn; change.\n[v.] To direct (one's way or course); pursue one's way; proceed upon some course or way.\n[v.] To turn; make a turn; go round; veer.","ex":"We wended our weary way westward."},"WELDS":{"p":"","s":"n./v.","e":"[n.] The joint made by welding.\n[v.] To join two materials (especially two metals) together by applying heat, pressure and filler, either separately or in any combination.\n[v.] To bind together inseparably; to unite closely or intimately.\n[v.] To wield.","ex":""},"WENT":{"p":"/went/","s":"v./n.","e":"[v.] To move:\n[v.] (chiefly of a machine) To work or function (properly); to move or perform (as required).\n[v.] To start; to begin (an action or process).\n[v.] To turn; change.\n[v.] To direct (one's way or course); pursue one's way; proceed upon some course or way.\n[v.] To turn; make a turn; go round; veer.","ex":"The engine just won't go anymore."},"WERE":{"p":"","s":"n.","e":"[n.] A man, a husband\n[n.] A fine for slaying a man; weregild.\n[n.] The collective name for any kind of person that changes into another form under certain conditions, including the werewolf.","ex":""},"WEST":{"p":"/wɛst/","s":"n./v./adj./adv.","e":"[n.] One of the four principal compass points, specifically 270°, conventionally directed to the left on maps; the direction of the setting sun at an equinox, abbreviated as W.\n[v.] To move to the west; (of the sun) to set.\n[adj.] Situated or lying in or toward the west; westward.\n[adj.] Of wind: from the west.\n[adj.] Of or pertaining to the west; western.\n[adv.] Towards the west; westwards.","ex":""},"WHACK":{"p":"/wæk/","s":"adj./n./v.","e":"[adj.] Egregious.\n[adj.] Bad (not good), inauthentic, of an inferior quality, contemptible, lacking integrity, lame, or strange.\n[adj.] Crazy, mad, insane.\n[n.] The sound of a heavy strike.\n[n.] The strike itself.\n[n.] The stroke itself, regardless of its successful impact.","ex":"Every record they ever made was straight-up wack."},"WHALE":{"p":"/weɪl/","s":"n./v.","e":"[n.] Any of several species of large sea mammals of the infraorder Cetacea.\n[n.] Something, or someone, that is very large.\n[n.] Something, or someone, that is excellent.\n[v.] To hunt for whales.","ex":""},"WHAMS":{"p":"","s":"n./v.","e":"[n.] A forceful blow\n[n.] The sound of such a blow; a thud\n[v.] To strike or smash (into) something with great force or impact","ex":""},"WHANG":{"p":"","s":"n./v.","e":"[n.] A blow; a whack.\n[n.] A large piece or slice; a chunk.\n[n.] A house-cleaning party.\n[v.] (chiefly of an object) To make a noise like something moving quickly through the air.\n[v.] To throw with a rapid slamming motion.\n[v.] To whack or beat.","ex":"I ought to have whanged him one in the eye."},"WELTS":{"p":"","s":"v./n.","e":"[v.] To roll; revolve\n[n.] A ridge or lump on the skin, as caused by a blow; a wheal or weal.\n[n.] (shoemaking) A strip of leather set into the seam between the outsole of a shoe and the upper, through which these parts are joined by stitching or stapling.\n[n.] A strip of material or covered cord applied to a seam or garment edge to strengthen or cover it.\n[v.] To cause to have welts, to beat.\n[v.] To install welt (a welt or welts) to reinforce.","ex":""},"WHARF":{"p":"/wɔːf/","s":"n./v.","e":"[n.] A man-made landing place for ships on a shore or river bank.\n[n.] The bank of a river, or the shore of the sea.\n[v.] To secure by a wharf.\n[v.] To place on a wharf.","ex":""},"WHEELS":{"p":"/wiːlz/","s":"n./v.","e":"[n.] A circular device capable of rotating on its axis, facilitating movement or transportation or performing labour in machines.\n[n.] The breaking wheel, an old instrument of torture.\n[n.] A person with a great deal of power or influence; a big wheel.\n[v.] To roll along on wheels.\n[v.] To transport something or someone using any wheeled mechanism, such as a wheelchair.\n[v.] To ride a bicycle or tricycle.","ex":"Wheel that trolley over here, would you?"},"WHAT":{"p":"/wɔt/","s":"adv./n./pron./int.","e":"[adv.] (Singlish) Used to contradict an underlying assumption held by the interlocutor.\n[n.] Something; thing; stuff.\n[n.] The identity of a thing, as an answer to a question of what.\n[n.] Something that is addressed by what, as opposed to a person, addressed by who.\n[adv.] (usually followed by \"with,\" but also sometimes \"would\" or \"might,\" especially in finance) In some manner or degree; in part; partly. See also what with\n[adv.] Such.","ex":"The market will calculate these higher risks in their funding costs what might result in higher lending rates."},"WHEEL":{"p":"/ʍiːl/","s":"n./v.","e":"[n.] A circular device capable of rotating on its axis, facilitating movement or transportation or performing labour in machines.\n[n.] The breaking wheel, an old instrument of torture.\n[n.] A person with a great deal of power or influence; a big wheel.\n[v.] To roll along on wheels.\n[v.] To transport something or someone using any wheeled mechanism, such as a wheelchair.\n[v.] To ride a bicycle or tricycle.","ex":"Wheel that trolley over here, would you?"},"WHEAT":{"p":"/wiːt/","s":"n./adj.","e":"[n.] Any of several cereal grains, of the genus Triticum, that yields flour as used in bakery.\n[n.] A light brown colour, like that of wheat.\n[adj.] Wheaten, of a light brown colour, like that of wheat.","ex":""},"WESTERN":{"p":"/ˈwɛstən/","s":"n./adj.","e":"[n.] A film, or some other dramatic work, set in, the historic (c. 1850-1910) American West (west of the Mississippi river) focusing on conflict between whites and Indians, lawmen and outlaws, ranchers and farmers, or industry (railroads, mining) and agriculture.\n[adj.] Of, facing, situated in, or related to the west.\n[adj.] (of a wind) Blowing from the west; westerly.\n[adj.] Occidental.","ex":"the western approaches"},"WHERE":{"p":"/wɛə(ɹ)/","s":"n./adv./pron./conj.","e":"[n.] The place in which something happens.\n[adv.] Interrogative adverb, used in either a direct or indirect question: at what place; to what place; what place.\n[adv.] In what situation.\n[adv.] (relative) At which, on which.\n[pron.] The place in which.\n[conj.] While on the contrary; although; whereas.","ex":"A good article will cover the who, the what, the when, the where, the why and the how."},"WHEN":{"p":"/ʍɛn/","s":"n./adv./pron./conj./int.","e":"[n.] The time at which something happens.\n[adv.] (interrogative) At what time? At which time? Upon which occasion or circumstance? Used to introduce direct or indirect questions about time.\n[adv.] At an earlier time and under different, usually less favorable, circumstances.\n[adv.] (relative) At which, on which, during which: often omitted or replaced with that.\n[pron.] (interrogative) What time; which time.\n[pron.] The time that.","ex":"A good article will cover the who, the what, the when, the where, the why and the how."},"WHETHER":{"p":"/ˈwɛðə(ɹ)/","s":"pron./conj.","e":"[pron.] Which of two.\n[conj.] Introducing a direct interrogative question (often with correlative or) which indicates doubt between alternatives.\n[conj.] Used to introduce an indirect interrogative question that consists of multiple alternative possibilities (usually with correlative or).\n[conj.] Without a correlative, used to introduce a simple indirect question.","ex":"He chose the correct answer, but I don't know whether it was by luck or (whether it was) by skill."},"WHELP":{"p":"/wɛlp/","s":"n.","e":"[n.] A young offspring of a canid (ursid, felid, pinniped), especially of a dog or a wolf, the young of a bear or similar mammal (lion, tiger, seal); a pup, wolf cub.\n[n.] An insolent youth; a mere child.\n[n.] A kind of ship.","ex":""},"WHETS":{"p":"","s":"v.","e":"[v.] To hone or rub on with some substance, as a piece of stone, for the purpose of sharpening – see whetstone.\n[v.] To stimulate or make more keen.\n[v.] To preen.","ex":"to whet one's appetite or one's courage"},"WHICH":{"p":"/wɪt͡ʃ/","s":"pron.","e":"[pron.] (interrogative) What one or ones (of those mentioned or implied).\n[pron.] The/Any ones that; whichever.\n[pron.] (relative) Introduces a relative clause giving further information about something previously mentioned.","ex":"By now, you must surely know which is which."},"WHILE":{"p":"/waɪl/","s":"n./v./prep./conj.","e":"[n.] An uncertain duration of time, a period of time.\n[v.] To pass (time) idly.\n[v.] To occupy or entertain (someone) in order to let time pass.\n[v.] To loiter.\n[prep.] Until.\n[conj.] During the same time that.","ex":"He lectured for quite a long while."},"WHIPS":{"p":"","s":"n./v.","e":"[n.] A lash; a pliant, flexible instrument, such as a rod (commonly of cane or rattan) or a plaited or braided rope or thong (commonly of leather) used to create a sharp \"crack\" sound for directing or herding animals.\n[n.] A blow administered with a whip.\n[n.] A whipper-in.\n[v.] To hit with a whip.\n[v.] (by extension) To hit with any flexible object.\n[v.] To defeat, as in a contest or game.","ex":"I had to use the whip to get the sheep's attention."},"WHIRL":{"p":"/ʍɪɾ(ə̯)l/","s":"n./v.","e":"[n.] An act of whirling.\n[n.] Something that whirls.\n[n.] A confused tumult.\n[v.] To rotate, revolve, spin or turn rapidly.\n[v.] To have a sensation of spinning or reeling.\n[v.] To make something or someone whirl.","ex":"She gave the top a whirl and it spun across the floor."},"WHELM":{"p":"/wɛlm/","s":"n./v.","e":"[n.] A surge of water.\n[v.] To bury, to cover; to engulf, to submerge.\n[v.] To throw (something) over a thing so as to cover it.\n[v.] To ruin or destroy.","ex":"the whelm of the tide"},"WHIRR":{"p":"/wɜː/","s":"n./v.","e":"[n.] A sibilant buzz or vibration; the sound of something in rapid motion.\n[n.] A bustle of noise and excitement.\n[v.] To move or vibrate (something) with a buzzing sound.\n[v.] To make a sibilant buzzing or droning sound.\n[v.] To cause (something) to make such a sound.","ex":""},"WHIRS":{"p":"","s":"n.","e":"[n.] A sibilant buzz or vibration; the sound of something in rapid motion.\n[n.] A bustle of noise and excitement.","ex":""},"WHIST":{"p":"/wɪst/","s":"n.","e":"[n.] Any of several four-player card games, similar to bridge.\n[n.] A session of playing this card game.","ex":""},"WHISK":{"p":"/(h)wɪsk/","s":"n./v.","e":"[n.] A quick, light sweeping motion.\n[n.] A kitchen utensil, made from stiff wire loops fixed to a handle, used for whipping (or a mechanical device with the same function).\n[n.] A bunch of twigs or hair etc, used as a brush.\n[v.] To move something with quick light sweeping motions.\n[v.] In cooking, to whip e.g. eggs or cream.\n[v.] To move something rapidly and with no warning.","ex":"With a quick whisk, she swept the cat from the pantry with her broom."},"WHITS":{"p":"","s":"n.","e":"[n.] The smallest part or particle imaginable; an iota.","ex":"He worked tirelessly to collect and wind a ball of string eight feet around, and it matters not one whit."},"WHIZZ":{"p":"","s":"n./v.","e":"[n.] A whirring or hissing sound (as above).\n[n.] Someone who is remarkably skilled at something.\n[n.] (especially with the verb \"take\") An act of urination.\n[v.] To make a whirring or hissing sound, similar to that of an object speeding through the air.\n[v.] To rush or move swiftly with such a sound.\n[v.] To throw or spin rapidly.","ex":"I have to take a whiz."},"WHOM":{"p":"/huːm/","s":"pron.","e":"[pron.] (interrogative) What person or people; which person or people.\n[pron.] (relative) Used to refer to a previously mentioned person or people.\n[pron.] (fused relative, archaic outside set patterns) The person(s) whom; whomever.","ex":"He's a person with whom I work. (defining)"},"WHOLLY":{"p":"/ˈhəʊli/","s":"adv.","e":"[adv.] Completely and entirely; to the fullest extent.\n[adv.] Exclusively and solely.","ex":"A creature wholly given to brawls and wine."},"WHOMP":{"p":"/ʍɒmp/","s":"v.","e":"[v.] Hit extremely hard.","ex":"If you don’t cut that out, I’m going to whomp you so hard your head will spin!"},"WHIFF":{"p":"","s":"n./v./adj.","e":"[n.] A waft; a brief, gentle breeze; a light gust of air\n[n.] An odour carried briefly through the air\n[n.] A short inhalation or exhalation of breath, especially of smoke from a cigarette or pipe.\n[v.] To waft.\n[v.] To sniff.\n[v.] To strike out.","ex":""},"WHOOP":{"p":"/huːp/","s":"n./v.","e":"[n.] A loud, eager cry, usually of joy.\n[n.] A gasp, characteristic of whooping cough.\n[n.] A bump on a racetrack.\n[v.] To make a whoop.\n[v.] To shout, to yell.\n[v.] To cough or breathe with a sonorous inspiration, as in whooping cough.","ex":""},"WIDE":{"p":"/wɑed/","s":"n./adj./adv.","e":"[n.] A ball that passes so far from the batsman that the umpire deems it unplayable; the arm signal used by an umpire to signal a wide; the extra run added to the batting side's score\n[adj.] Having a large physical extent from side to side.\n[adj.] Large in scope.\n[adj.] Operating at the side of the playing area.\n[adv.] Extensively\n[adv.] Completely","ex":"We walked down a wide corridor."},"WHORL":{"p":"/wɜː(ɹ)l/","s":"n./v.","e":"[n.] A pattern of concentric circles.\n[n.] A circle of three or more leaves, flowers, or other organs, about the same part or joint of a stem.\n[n.] A volution, or turn, of the spire of a univalve shell.\n[v.] To form a pattern of concentric circles.","ex":""},"WICKS":{"p":"","s":"n./v.","e":"[n.] A bundle, twist, braid, or woven strip of cord, fabric, fibre/fiber, or other porous material in a candle, oil lamp, kerosene heater, or the like, that draws up liquid fuel, such as melted tallow, wax, or the oil, delivering it to the base of the flame for conversion to gases and burning; any other length of material burned for illumination in small successive portions.\n[n.] Any piece of porous material that conveys liquid by capillary action, such as a strip of gauze placed in a wound to serve as a drain.\n[n.] A narrow opening in the field, flanked by other players' stones.\n[v.] To convey or draw off (liquid) by capillary action.\n[v.] (of a liquid) To traverse (i.e. be conveyed by capillary action) through a wick or other porous material, as water through a sponge. Usually followed by through.\n[v.] To strike (a stone) obliquely; to strike (a stationary stone) just enough that the played stone changes direction.","ex":"Trim the wick fairly short, so that the flame does not smoke."},"WHOLE":{"p":"/həʊl/","s":"n./adj./adv.","e":"[n.] Something complete, without any parts missing.\n[n.] An entirety.\n[adj.] Entire, undivided.\n[adj.] Sound, uninjured, healthy.\n[adj.] (of food) From which none of its constituents has been removed.\n[adv.] In entirety; entirely; wholly.","ex":"This variety of fascinating details didn't fall together into an enjoyable, coherent whole."},"WIFE":{"p":"/waɪf/","s":"n./v.","e":"[n.] A married woman, especially in relation to her spouse.\n[n.] The female of a pair of mated animals.\n[v.] (said of men) to marry\n[n.] An adult female human.\n[n.] (collective) All females collectively; womankind.\n[n.] A female person, usually an adult; a (generally adult) female sentient being, whether human, supernatural, elf, alien, etc.","ex":"A new wife for the gander is introduced into the pen."},"WIDEN":{"p":"/ˈwaɪdən/","s":"v.","e":"[v.] To become wide or wider.\n[v.] To make wide or wider.\n[v.] To let out clothes to a larger size.","ex":"His eyes widened as her negligee fell to the floor."},"WIDES":{"p":"","s":"n.","e":"[n.] A ball that passes so far from the batsman that the umpire deems it unplayable; the arm signal used by an umpire to signal a wide; the extra run added to the batting side's score","ex":""},"WIGHT":{"p":"/waɪt/","s":"n.","e":"[n.] A living creature, especially a human being.\n[n.] A being of one of the Nine Worlds of Heathen belief, especially a nature spirit, elf or ancestor.\n[n.] A ghost, deity or other supernatural entity.","ex":""},"WIDOW":{"p":"/ˈwɪ.dəʊ/","s":"n./v.","e":"[n.] A woman whose spouse has died (and who has not remarried); feminine of widower.\n[n.] A person whose spouse has died (and who has not remarried).\n[n.] (in combination) A woman whose husband is often away pursuing a sport, etc.\n[v.] To make a widow or widower of someone; to cause the death of the spouse of.\n[v.] To strip of anything valued.\n[v.] To endow with a widow's right.","ex":""},"WIELD":{"p":"/wiːld/","s":"v.","e":"[v.] To command, rule over; to possess or own.\n[v.] To control, to guide or manage.\n[v.] To handle with skill and ease, especially a weapon or tool.","ex":""},"WILD":{"p":"/waɪld/","s":"n./v./adj./adv.","e":"[n.] The undomesticated state of a wild animal\n[n.] (chiefly in the plural) a wilderness\n[v.] To commit random acts of assault, robbery, and rape in an urban setting, especially as a gang.\n[adj.] Untamed; not domesticated; specifically, in an unbroken line of undomesticated animals (as opposed to feral, referring to undomesticated animals whose ancestors were domesticated).\n[adj.] From or relating to wild creatures.\n[adj.] Unrestrained or uninhibited.","ex":"After mending the lion's leg, we returned him to the wild."},"WILL":{"p":"/wɪl/","s":"v.","e":"[v.] (now uncommon or literary) To wish, desire (something).\n[v.] (nowadays rare) To wish or desire (that something happen); to intend (that).\n[v.] (auxiliary) To habitually do (a given action).","ex":"Do what you will."},"WHOSE":{"p":"/huːz/","s":"pron.","e":"[pron.] (interrogative) That or those of whom or belonging to whom.\n[pron.] (relative) That or those of whom or belonging to whom.","ex":"Several people have lost their suitcases. Whose have you found?"},"WILLS":{"p":"/wɪlz/","s":"n./v.","e":"[n.] One's independent faculty of choice; the ability to be able to exercise one's choice or intention.\n[n.] One's intention or decision; someone's orders or commands.\n[n.] The act of choosing to do something; a person’s conscious intent or volition.\n[v.] To wish, desire.\n[v.] To instruct (that something be done) in one's will.\n[v.] To try to make (something) happen by using one's will (intention).","ex":"Of course, man's will is often regulated by his reason."},"WIMPS":{"p":"","s":"n.","e":"[n.] Acronym of window, icon, menu, pointer. (a graphical interface paradigm)\n[n.] Acronym of window-icon-mouse program.\n[n.] A hypothetical class of particle, proposed to explain the dark matter problem.\n[n.] Someone who lacks confidence or courage, is weak, ineffectual, irresolute and wishy-washy","ex":""},"WILTS":{"p":"","s":"n./v.","e":"[n.] The act of wilting or the state of being wilted.\n[n.] Any of various plant diseases characterized by wilting.\n[v.] To droop or become limp and flaccid (as a dying leaf or flower).\n[v.] To fatigue; to lose strength.\n[v.] To cause to droop or become limp and flaccid (as a flower).","ex":""},"WINCH":{"p":"/wɪntʃ/","s":"n./v.","e":"[n.] A machine consisting of a drum on an axle, a friction brake or ratchet and pawl, and a crank handle or prime mover (often an electric or hydraulic motor), with or without gearing, to give increased mechanical advantage when hauling on a rope or cable.\n[n.] A hoisting machine used for loading or discharging cargo, or for hauling in lines. (FM 55-501).\n[n.] A wince (machine used in dyeing or steeping cloth).\n[v.] To use a winch","ex":"Winch in those sails, lad!"},"WINCE":{"p":"/wɪns/","s":"n./v.","e":"[n.] A sudden movement or gesture of shrinking away.\n[n.] A reel used in dyeing, steeping, or washing cloth; a winch. It is placed over the division wall between two wince pits so as to allow the cloth to descend into either compartment at will.\n[v.] To flinch as if in pain or distress.\n[v.] To wash (cloth), dip it in dye, etc., with the use of a wince.\n[v.] To kick or flounce when unsteady or impatient.","ex":"A horse winces."},"WINDS":{"p":"/wɪndz/","s":"n.","e":"[n.] Real or perceived movement of atmospheric air usually caused by convection or differences in air pressure.\n[n.] Air artificially put in motion by any force or action.\n[n.] The ability to breathe easily.\n[n.] The act of winding or turning; a turn; a bend; a twist.","ex":"As they accelerated onto the motorway, the wind tore the plywood off the car's roof-rack."},"WINE":{"p":"/waɪn/","s":"n./v.","e":"[n.] An alcoholic beverage made by fermenting the juice of grapes.\n[n.] An alcoholic beverage made by fermenting the juice of fruits or vegetables other than grapes, usually preceded by the type of the fruit or vegetable; for example, \"dandelion wine\".\n[n.] A serving of wine.\n[v.] To entertain with wine.\n[v.] To drink wine.","ex":"She ordered some wine for the meal."},"WINDY":{"p":"/ˈwɪndi/","s":"n./adj.","e":"[n.] Fart\n[adj.] Accompanied by wind.\n[adj.] Unsheltered and open to the wind.\n[adj.] Empty and lacking substance.","ex":"It was a long and windy night."},"WILLING":{"p":"/ˈwɪlɪŋ/","s":"v./n./adj.","e":"[v.] To wish, desire.\n[v.] To instruct (that something be done) in one's will.\n[v.] To try to make (something) happen by using one's will (intention).\n[n.] The execution of a will.\n[adj.] Ready to do something that is not (can't be expected as) a matter of course.","ex":"All the fans were willing their team to win the game."},"WILLY":{"p":"/ˈwɪli/","s":"adj.","e":"[adj.] Willing; favourable; ready; eager.\n[adj.] Self-willed; willful.","ex":""},"WINED":{"p":"/waɪnd/","s":"v.","e":"[v.] To entertain with wine.\n[v.] To drink wine.","ex":""},"WINKS":{"p":"","s":"n./v.","e":"[n.] An act of winking (a blinking of only one eye), or a message sent by winking.\n[n.] A brief period of sleep; especially forty winks.\n[n.] A brief time; an instant.\n[v.] To close one's eyes in sleep.\n[v.] To close one's eyes.\n[v.] Usually followed by at: to look the other way, to turn a blind eye.","ex":""},"WIMPY":{"p":"","s":"adj.","e":"[adj.] Having the characteristics of a wimp; feeble, indecisive, cowardly.","ex":""},"WINDOW":{"p":"/ˈwɪndəʊ/","s":"n./v.","e":"[n.] The inedible parts of a grain-producing plant.\n[n.] Straw or hay cut up fine for the food of cattle.\n[n.] Any excess or unwanted material, resource, or person; anything worthless.\n[n.] An opening, usually covered by one or more panes of clear glass, to allow light and air from outside to enter a building or vehicle.\n[n.] An opening, usually covered by glass, in a shop which allows people to view the shop and its products from outside; a shop window.\n[n.] The shutter, casement, sash with its fittings, or other framework, which closes a window opening.","ex":"To separate out the chaff, early cultures tossed baskets of grain into the air and let the wind blow away the lighter chaff."},"WINNING":{"p":"/ˈwɪnɪŋ/","s":"v./n./adj.","e":"[v.] To conquer, defeat.\n[v.] To reach some destination or object, despite difficulty or toil (now usually intransitive, with preposition or locative adverb).\n[v.] To triumph or achieve victory in (a game, a war, etc.).\n[n.] The act of obtaining something, as in a contest or by competition.\n[n.] (chiefly in the plural) The money, etc., gained by success in competition or contest, especially in gambling.\n[n.] A new opening.","ex":"the winning entry in the competition"},"WING":{"p":"/wɪŋ/","s":"n./v.","e":"[n.] An appendage of an animal's (bird, bat, insect) body that enables it to fly; a similar fin at the side of a ray or similar fish\n[n.] Human arm.\n[n.] Part of an aircraft that produces the lift for rising into the air.\n[v.] To injure slightly (as with a gunshot), especially in the wing or arm.\n[v.] To fly.\n[v.] (of a building) To add a wing (extra part) to.","ex":""},"WINOS":{"p":"","s":"n.","e":"[n.] A chronic or heavy drinker of cheap wine or other alcohol; a drunk or drunkard.\n[n.] A wine enthusiast; an oenophile.\n[n.] A hypothetical particle that is the superpartner of the W boson.","ex":""},"WINES":{"p":"/waɪnz/","s":"n./v.","e":"[n.] An alcoholic beverage made by fermenting the juice of grapes.\n[n.] An alcoholic beverage made by fermenting the juice of fruits or vegetables other than grapes, usually preceded by the type of the fruit or vegetable; for example, \"dandelion wine\".\n[n.] A serving of wine.\n[v.] To entertain with wine.\n[v.] To drink wine.","ex":"She ordered some wine for the meal."},"WINTER":{"p":"/ˈwɪntɚ/","s":"n./v.","e":"[n.] Traditionally the fourth of the four seasons, typically regarded as being from December 23 to March 20 in continental regions of the Northern Hemisphere or the months of June, July and August in the Southern Hemisphere. It is the time when the sun is lowest in the sky, resulting in short days, and the time of year with the lowest atmospheric temperatures for the region.\n[n.] The period of decay, old age, death, or the like.\n[n.] Someone with dark skin, eyes and hair, seen as best suited to certain colors of clothing.\n[v.] To spend the winter (in a particular place).\n[v.] To store something (for instance animals) somewhere over winter to protect it from cold.","ex":"When they retired, they hoped to winter in Florida."},"WIPED":{"p":"/waɪpt/","s":"v.","e":"[v.] To move an object over, maintaining contact, with the intention of removing some substance from the surface. (Compare rub.)\n[v.] To remove by rubbing; to rub off; to obliterate; usually followed by away, off, or out.\n[v.] To cheat; to defraud; to trick; usually followed by out.\n[v.] To have all members of a party die in a single campaign, event, or battle; to be wiped out.","ex":"I wiped the sweat from my brow with the back of my hand."},"WINGS":{"p":"/wɪŋz/","s":"n./v.","e":"[n.] An appendage of an animal's (bird, bat, insect) body that enables it to fly; a similar fin at the side of a ray or similar fish\n[n.] Human arm.\n[n.] Part of an aircraft that produces the lift for rising into the air.\n[v.] To injure slightly (as with a gunshot), especially in the wing or arm.\n[v.] To fly.\n[v.] (of a building) To add a wing (extra part) to.","ex":""},"WIRE":{"p":"/waɪə(ɹ)/","s":"n./v.","e":"[n.] Metal formed into a thin, even thread, now usually by being drawn through a hole in a steel die.\n[n.] A piece of such material; a thread or slender rod of metal, a cable.\n[n.] A metal conductor that carries electricity.\n[v.] To fasten with wire, especially with reference to wine bottles, corks, or fencing.\n[v.] To string on a wire.\n[v.] To equip with wires for use with electricity.","ex":"We need to wire that hole in the fence."},"WIPES":{"p":"/waɪps/","s":"n./v.","e":"[n.] The act of wiping something.\n[n.] A soft piece of cloth or cloth-like material used for wiping.\n[n.] A kind of film transition where one shot replaces another by travelling from one side of the frame to another or with a special shape.\n[v.] To move an object over, maintaining contact, with the intention of removing some substance from the surface. (Compare rub.)\n[v.] To remove by rubbing; to rub off; to obliterate; usually followed by away, off, or out.\n[v.] To cheat; to defraud; to trick; usually followed by out.","ex":"multiple wipes of a computer's hard disk"},"WIRES":{"p":"/waɪəz/","s":"n./v.","e":"[n.] Metal formed into a thin, even thread, now usually by being drawn through a hole in a steel die.\n[n.] A piece of such material; a thread or slender rod of metal, a cable.\n[n.] A metal conductor that carries electricity.\n[v.] To fasten with wire, especially with reference to wine bottles, corks, or fencing.\n[v.] To string on a wire.\n[v.] To equip with wires for use with electricity.","ex":"We need to wire that hole in the fence."},"WINKY":{"p":"","s":"n./adj.","e":"[n.] An emoticon or smiley that shows a winking face.\n[adj.] Tending to wink; winking","ex":""},"WIPER":{"p":"/ˈwaɪpɚ/","s":"n.","e":"[n.] Someone who wipes.\n[n.] Something, such as a towel, that is used for wiping.\n[n.] Something, such as a windscreen wiper, that is designed for wiping.","ex":""},"WISDOM":{"p":"/ˈwɪzdəm/","s":"n.","e":"[n.] An element of personal character that enables one to distinguish the wise from the unwise.\n[n.] A piece of wise advice.\n[n.] The discretionary use of knowledge for the greatest good.","ex":""},"WISE":{"p":"/waɪz/","s":"v./adj.","e":"[v.] To become wise.\n[v.] Usually with \"up\", to inform or learn.\n[adj.] Showing good judgement or the benefit of experience.\n[adj.] Disrespectful.\n[adj.] Aware, informed.","ex":"After Mo had a word with him, he wised up."},"WIRED":{"p":"/waɪəd/","s":"v./adj.","e":"[v.] To fasten with wire, especially with reference to wine bottles, corks, or fencing.\n[v.] To string on a wire.\n[v.] To equip with wires for use with electricity.\n[adj.] Equipped with wires, so as to connect to a power source or to other electric or electronic equipment; connected by wires.\n[adj.] Equipped with hidden electronic eavesdropping devices.\n[adj.] Reinforced, supported, tied or bound with wire.","ex":"We need to wire that hole in the fence."},"WISES":{"p":"","s":"n.","e":"[n.] Way, manner, method.","ex":""},"WISER":{"p":"/ˈwaɪzə/","s":"adj.","e":"[adj.] Showing good judgement or the benefit of experience.\n[adj.] Disrespectful.\n[adj.] Aware, informed.","ex":"\"It is a profitable thing, if one is wise, to seem foolish\" - Aeschylus"},"WISH":{"p":"/wɪʃ/","s":"n./v.","e":"[n.] A desire, hope, or longing for something or for something to happen.\n[n.] An expression of such a desire, often connected with ideas of magic and supernatural power.\n[n.] The thing desired or longed for.\n[v.] To desire; to want.\n[v.] To hope (+ object clause with may or in present subjunctive).\n[v.] (followed by for) To hope (for a particular outcome).","ex":"My dearest wish is to see them happily married."},"WISPS":{"p":"","s":"n.","e":"[n.] A small bundle, as of straw or other like substance; any slender, flexible structure or group.\n[n.] A whisk, or small broom.\n[n.] A will o' the wisp, or ignis fatuus.","ex":"A wisp of hair escaped her barrette and whipped wildly in the wind."},"WISPY":{"p":"/ˈwɪspi/","s":"adj.","e":"[adj.] Consisting of or resembling a wisp; like a slender, flexible strand or bundle.","ex":"The wispy smoke rose from chimneys all around town."},"WITCH":{"p":"/wɪtʃ/","s":"n./v.","e":"[n.] A person who practices witchcraft; a woman or man who practices witchcraft.\n[n.] An ugly or unpleasant woman.\n[n.] One who exercises more-than-common power of attraction; a charming or bewitching person.\n[v.] To practise witchcraft.\n[v.] To bewitch.\n[v.] To dowse for water.","ex":"I hate that old witch."},"WITHE":{"p":"/waɪð/","s":"n./v.","e":"[n.] A flexible, slender twig or shoot, especially when used as a band or for binding; a withy.\n[n.] A band of twisted twigs.\n[n.] An elastic handle to a tool to save the hand from the shock of blows.\n[v.] To bind with withes.\n[v.] To beat with withes.","ex":""},"WITTY":{"p":"/ˈwɪti/","s":"adj.","e":"[adj.] Wise, having good judgement.\n[adj.] Possessing a strong intellect or intellectual capacity; intelligent, skilful, ingenious.\n[adj.] Clever; amusingly ingenious.","ex":"His speech was both witty and informative."},"WITH":{"p":"","s":"adv./prep.","e":"[adv.] Along, together with others, in a group, etc.\n[prep.] Against.\n[prep.] In the company of; alongside, close to; near to.\n[prep.] In addition to; as an accessory to.","ex":"Do you want to come with?"},"WITHIN":{"p":"/wɪˈθɪn/","s":"adj./adv./prep.","e":"[adj.] In the context of which the present document or ruling is made.\n[adv.] In or into the interior; inside.\n[prep.] In the inner part, spatially; physically inside.\n[prep.] In the scope or range of.\n[prep.] Before the specified duration ends.","ex":"the within appeal"},"WITHOUT":{"p":"/wɪθˈʌʊt/","s":"adv./prep./conj.","e":"[adv.] Outside, externally. This is still used in the names of some civil parishes in England, e.g. St Cuthbert Without.\n[adv.] Lacking something.\n[adv.] In prostitution: without a condom being worn.\n[prep.] Outside of, beyond.\n[prep.] Not having, containing, characteristic of, etc.\n[prep.] Not doing or not having done something.","ex":"Being from a large, poor family, he learned to live without."},"WIVES":{"p":"/waɪvz/","s":"n.","e":"[n.] A married woman, especially in relation to her spouse.\n[n.] The female of a pair of mated animals.\n[n.] An adult female human.\n[n.] (collective) All females collectively; womankind.\n[n.] A female person, usually an adult; a (generally adult) female sentient being, whether human, supernatural, elf, alien, etc.","ex":"A new wife for the gander is introduced into the pen."},"WOKE":{"p":"/wəʊk/","s":"adj.","e":"[adj.] Awake: conscious and not asleep.\n[adj.] Alert and aware of what is going on, especially in social justice contexts. Well-informed.","ex":""},"WOKEN":{"p":"/ˈwəʊkən/","s":"v.","e":"[v.] (often followed by up) To stop sleeping.\n[v.] (often followed by up) To make somebody stop sleeping; to rouse from sleep.\n[v.] To put in motion or action; to arouse; to excite.","ex":"I woke up at four o'clock this morning."},"WOLF":{"p":"/wʊlf/","s":"n./v.","e":"[n.] The gray wolf, specifically all subspecies of the gray wolf (Canis lupus) that are not dingoes or dogs.\n[n.] A man who makes amorous advances to many women.\n[n.] A wolf tone or wolf note.\n[v.] To devour; to gobble; to eat (something) voraciously.\n[v.] To make amorous advances to many women; to hit on women; to cruise for sex.\n[v.] To hunt for wolves.","ex":"Check out my pet. He's a wolf."},"WOLFS":{"p":"","s":"v.","e":"[v.] To devour; to gobble; to eat (something) voraciously.\n[v.] To make amorous advances to many women; to hit on women; to cruise for sex.\n[v.] To hunt for wolves.","ex":""},"WOMAN":{"p":"/ˈwʊmɘn/","s":"n./v.","e":"[n.] An adult female human.\n[n.] (collective) All females collectively; womankind.\n[n.] A female person, usually an adult; a (generally adult) female sentient being, whether human, supernatural, elf, alien, etc.\n[v.] To staff with female labor.\n[v.] To make effeminate or womanish.\n[v.] To furnish with, or unite to, a woman.","ex":""},"WOMEN":{"p":"/ˈwɪmən/","s":"n.","e":"[n.] An adult female human.\n[n.] (collective) All females collectively; womankind.\n[n.] A female person, usually an adult; a (generally adult) female sentient being, whether human, supernatural, elf, alien, etc.","ex":""},"WOMBS":{"p":"","s":"n.","e":"[n.] In female mammals, the organ in which the young are conceived and grow until birth; the uterus.\n[n.] The abdomen or stomach.\n[n.] The stomach of a person or creature.","ex":""},"WOOD":{"p":"/wʊd/","s":"n./v.","e":"[n.] The substance making up the central part of the trunk and branches of a tree. Used as a material for construction, to manufacture various items, etc. or as fuel.\n[n.] The wood of a particular species of tree.\n[n.] A forested or wooded area.\n[v.] To cover or plant with trees.\n[v.] To hide behind trees.\n[v.] To supply with wood, or get supplies of wood for.","ex":"There was lots of wood on the beach."},"WONDER":{"p":"/ˈwʌndə/","s":"n./v.","e":"[n.] Something that causes amazement or awe; a marvel.\n[n.] Something astonishing and seemingly inexplicable.\n[n.] Someone very talented at something, a genius.\n[v.] To be affected with surprise or admiration; to be struck with astonishment; to be amazed; to marvel; often followed by at.\n[v.] To ponder; to feel doubt and curiosity; to query in the mind.","ex":"Wonders of the World seem to come in sevens."},"WOODY":{"p":"/ˈwʊdi/","s":"n./adj.","e":"[n.] An early station wagon or estate car in which the rear portion of the car's bodywork is made of wood, often associated with Southern California surfing culture.\n[n.] A wooden rollercoaster; an amusement ride whose rails are overlaid upon a wooden track.\n[n.] An erection of the penis.\n[adj.] Covered in woods; wooded.\n[adj.] Belonging to the woods; sylvan.\n[adj.] Made of wood, or having wood-like properties.","ex":""},"WOOED":{"p":"","s":"v.","e":"[v.] To endeavor to gain someone's support.\n[v.] (often of a man) To try to persuade (someone) to be in an amorous relationship with\n[v.] To court solicitously; to invite with importunity.","ex":""},"WOODEN":{"p":"/ˈwʊdən/","s":"adj.","e":"[adj.] Made of wood.\n[adj.] As if made of wood; moving awkwardly, or speaking with dull lack of emotion.","ex":"On a recent windy day, hundreds of visitors climbed wooden stairs to take pictures in front of the glacier."},"WOOLY":{"p":"","s":"n./adj.","e":"[n.] A sweater or similar garment made of wool.\n[n.] A sheep not yet shorn.\n[n.] A piece of woolwork.\n[adj.] Made of wool.\n[adj.] Having a thick, soft texture, as if made of wool.\n[adj.] (of thinking, principles, etc.) Based on emotions rather than logic.","ex":"Put on a woolly jumper and turn down the thermostat."},"WOOFS":{"p":"/wʊfs/","s":"v.","e":"[v.] To make a woofing sound.","ex":""},"WOOZY":{"p":"/ˈwuːzi/","s":"adj.","e":"[adj.] Queasy, dizzy, or disoriented\n[adj.] Intoxicated by drink or drugs","ex":"I got off the rollercoaster feeling a bit woozy."},"WORDY":{"p":"/ˈwɝdi/","s":"adj.","e":"[adj.] Using an excessive number of words.","ex":"The story was long and very wordy."},"WORD":{"p":"/wɜːd/","s":"n./v./int.","e":"[n.] The smallest unit of language that has a particular meaning and can be expressed by itself; the smallest discrete, meaningful unit of language. (contrast morpheme.)\n[n.] Something like such a unit of language:\n[n.] The fact or act of speaking, as opposed to taking action. .\n[v.] To say or write (something) using particular words; to phrase (something).\n[v.] To flatter with words, to cajole.\n[v.] To ply or overpower with words.","ex":"I’m not sure how to word this letter to the council."},"WORE":{"p":"/wɔː/","s":"v.","e":"[v.] To carry or have equipped on or about one's body, as an item of clothing, equipment, decoration, etc.\n[v.] To have or carry on one's person habitually, consistently; or, to maintain in a particular fashion or manner.\n[v.] To bear or display in one's aspect or appearance.\n[v.] To guard; watch; keep watch, especially from entry or invasion.\n[v.] To defend; protect.\n[v.] To ward off; prevent from approaching or entering; drive off; repel.","ex":"He's wearing some nice pants today.  She wore her medals with pride.  Please wear your seatbelt.  Can you wear makeup and sunscreen at the same time?  He was wearing his lunch after tripping and falling into the buffet."},"WORK":{"p":"/wɜːk/","s":"n.","e":"[n.] (heading) Employment.\n[n.] (heading) Effort.\n[n.] Sustained effort to achieve a goal or result, especially overcoming obstacles.","ex":"We don't have much time. Let's get to work piling up those sandbags."},"WORKER":{"p":"/ˈwɜː.kə/","s":"n.","e":"[n.] A person who performs labor for a living, especially manual labor.\n[n.] A nonreproductive social insect, such as ant, bee, termite, or wasp.\n[n.] A thread performing one instance of a particular task within a program.","ex":"This FTP client spawns a separate worker for each file to be uploaded."},"WORKING":{"p":"/ˈwɜːkɪŋ/","s":"n.","e":"[n.] (usually in the plural) Operation; action.\n[n.] Method of operation.\n[n.] The incidental or subsidiary calculations performed in solving an overall problem.","ex":"Be sure to check your working."},"WORLD":{"p":"/wɝld/","s":"n./v.","e":"[n.] (with \"the\") Human collective existence; existence in general.\n[n.] The Universe.\n[n.] (with \"the\") The Earth.\n[v.] To consider or cause to be considered from a global perspective; to consider as a global whole, rather than making or focussing on national or other distinctions; compare globalise.\n[v.] To make real; to make worldly.","ex":"There will always be lovers, till the world’s end."},"WORM":{"p":"/wɜːm/","s":"n./v.","e":"[n.] A generally tubular invertebrate of the annelid phylum; an earthworm.\n[n.] More loosely, any of various tubular invertebrates resembling annelids but not closely related to them, such as velvet worms, acorn worms, flatworms, or roundworms.\n[n.] A type of wingless \"dragon\", especially a gigantic sea serpent.\n[v.] To make (one's way) with a crawling motion.\n[v.] To move with one's body dragging the ground.\n[v.] To work one's way by artful or devious means.","ex":"We wormed our way through the underbrush."},"WORN":{"p":"/wɔːn/","s":"v./adj.","e":"[v.] To carry or have equipped on or about one's body, as an item of clothing, equipment, decoration, etc.\n[v.] To have or carry on one's person habitually, consistently; or, to maintain in a particular fashion or manner.\n[v.] To bear or display in one's aspect or appearance.\n[v.] To guard; watch; keep watch, especially from entry or invasion.\n[v.] To defend; protect.\n[v.] To ward off; prevent from approaching or entering; drive off; repel.","ex":"He's wearing some nice pants today.  She wore her medals with pride.  Please wear your seatbelt.  Can you wear makeup and sunscreen at the same time?  He was wearing his lunch after tripping and falling into the buffet."},"WORST":{"p":"/wɜːst/","s":"adj./n./v./adv.","e":"[adj.] Unfavorable; negative; not good.\n[adj.] Not suitable or fitting.\n[adj.] Not appropriate, of manners etc.\n[adj.] Evil; wicked (of people).\n[adj.] Morally reprehensible (of behaviour etc.); blameworthy.\n[adj.] Indicative of unkind or malevolent intentions; harsh, cruel.","ex":"Abducting children is bad for mothers."},"WORRY":{"p":"/ˈwɒɹi/","s":"n./v.","e":"[n.] A strong feeling of anxiety.\n[n.] An instance or cause of such a feeling.\n[v.] To be troubled; to give way to mental anxiety or doubt.\n[v.] Disturb the peace of mind of; afflict with mental agitation or distress.\n[v.] To harass; to irritate or distress.","ex":"I'm afflicted by worry throughout the night."},"WORSE":{"p":"/wɜːs/","s":"adj./adv./n./v.","e":"[adj.] Unfavorable; negative; not good.\n[adj.] Not suitable or fitting.\n[adj.] Not appropriate, of manners etc.\n[adv.] In a bad manner.\n[adv.] Very much; to a great degree.\n[adj.] Evil; wicked (of people).","ex":"Abducting children is bad for mothers."},"WORTH":{"p":"/wɜːθ/","s":"n./adj.","e":"[n.] Value.\n[n.] Merit, excellence.\n[n.] Wealth, fortune, riches, property, possessions.\n[adj.] Having a value of; proper to be exchanged for.\n[adj.] Deserving of.\n[adj.] (except in Scots) Valuable, worth while.","ex":"I’ll have a dollar's worth of candy, please."},"WOULD":{"p":"/wʊd/","s":"n.","e":"[n.] Something that would happen, or would be the case, under different circumstances; a potentiality.","ex":""},"WOVEN":{"p":"/ˈwəʊvən/","s":"v./n./adj.","e":"[v.] To form something by passing lengths or strands of material over and under one another.\n[v.] To spin a cocoon or a web.\n[v.] To unite by close connection or intermixture.\n[n.] A cloth formed by weaving. It only stretches in the bias directions (between the warp and weft directions), unless the threads are elastic.\n[adj.] Fabricated by weaving.\n[adj.] Interlaced","ex":"This loom weaves yarn into sweaters."},"WRACK":{"p":"/ɹæk/","s":"n./v.","e":"[n.] Vengeance; revenge; persecution; punishment; consequence; trouble.\n[n.] (except in dialects) Ruin; destruction.\n[n.] The remains; a wreck.\n[v.] To execute vengeance; avenge.\n[v.] To worry; tease; torment.","ex":""},"WOUND":{"p":"/wuːnd/","s":"n./v.","e":"[n.] An injury, such as a cut, stab, or tear, to a (usually external) part of the body.\n[n.] A hurt to a person's feelings, reputation, prospects, etc.\n[n.] An injury to a person by which the skin is divided or its continuity broken.\n[v.] To hurt or injure (someone) by cutting, piercing, or tearing the skin.\n[v.] To hurt (a person's feelings).","ex":"It took a long time to get over the wound of that insult."},"WRAP":{"p":"/ɹæp/","s":"v.","e":"[v.] To enclose (an object) completely in any flexible, thin material such as fabric or paper.\n[v.] To enclose or coil around an object or organism, as a form of grasping.\n[v.] To conceal by enveloping or enfolding; to hide.","ex":"A snake wraps itself around its prey."},"WRAPS":{"p":"","s":"n./v.","e":"[n.] A sharp blow with something hard.\n[n.] Blame for something.\n[n.] A charge, whether or not it results in a conviction.\n[n.] A lay or skein containing 120 yards of yarn.\n[n.] Any of the tokens that passed current for a halfpenny in Ireland in the early part of the eighteenth century; any coin of trifling value.\n[n.] A whit; a jot.","ex":"The teacher gave the wayward pupil a rap across the knuckles with her ruler."},"WRATH":{"p":"/ɹæθ/","s":"n./v./adj.","e":"[n.] Great anger.\n[n.] Punishment.\n[v.] To anger; to enrage.\n[adj.] Wrathful; wroth; very angry.","ex":"Homer relates an episode in the Trojan War that reveals the tragic consequences of the wrath of Achilles."},"WRECK":{"p":"/ˈɹɛk/","s":"n./v.","e":"[n.] Something or someone that has been ruined.\n[n.] The remains of something that has been severely damaged or worn down.\n[n.] An event in which something is damaged through collision.\n[v.] To destroy violently; to cause severe damage to something, to a point where it no longer works, or is useless.\n[v.] To ruin or dilapidate.\n[v.] To dismantle wrecked vehicles or other objects, to reclaim any useful parts.","ex":"He was an emotional wreck after the death of his wife."},"WREAK":{"p":"/ɹik/","s":"v.","e":"[v.] To cause something harmful; to afflict; to inflict; to harm or injury; to let out something harmful; .\n[v.] To chasten, or chastise/chastize, or castigate, or punish, or smite.\n[v.] To inflict or take vengeance on.","ex":"She wreaked her anger on his car."},"WREST":{"p":"/ɹɛst/","s":"n./v.","e":"[n.] The act of wresting; a wrench or twist; distortion.\n[n.] A key to tune a stringed instrument.\n[n.] Active or motive power.\n[v.] To pull or twist violently.\n[v.] To obtain by pulling or violent force.\n[v.] To seize.","ex":"He wrested the remote control from my grasp and changed the channel."},"WRING":{"p":"/ɹɪŋ/","s":"n./v.","e":"[n.] A powerful squeezing or twisting action.\n[n.] Pain or distress.\n[v.] To squeeze or twist (something) tightly so that liquid is forced out. See also wring out.\n[v.] To extract (a liquid) from something wet, especially cloth, by squeezing and twisting it.\n[v.] To obtain (something from or out of someone or something) by force.","ex":"I grasped his hand and gave it a grateful wring."},"WRENS":{"p":"","s":"n.","e":"[n.] Any member of a mainly New World passerine bird family Troglodytidae; true wren.\n[n.] Small bird of similar appearance to a true wren.","ex":""},"WRITING":{"p":"/ˈɹaɪtɪŋ/","s":"n.","e":"[n.] Graphism of symbols such as letters that express some meaning.\n[n.] Something written, such as a document, article or book.\n[n.] The process of representing a language with symbols or letters.","ex":""},"WRIST":{"p":"/ɹɪst/","s":"n./v.","e":"[n.] The complex joint between forearm bones, carpus, and metacarpals where the hand is attached to the arm; the carpus in a narrow sense.\n[n.] A stud or pin which forms a journal.\n[v.] To hit a wrist shot","ex":""},"WRITE":{"p":"/ɹaɪt/","s":"n./v.","e":"[n.] The act or style of writing.\n[n.] The operation of storing data, as in memory or onto disk.\n[v.] To form letters, words or symbols on a surface in order to communicate.\n[v.] To be the author of (a book, article, poem, etc.).\n[v.] To send written information to.","ex":"How many writes per second can this hard disk handle?"},"WRITS":{"p":"","s":"n.","e":"[n.] A written order, issued by a court, ordering someone to do (or stop doing) something.\n[n.] Authority, power to enforce compliance.\n[n.] That which is written; writing.","ex":""},"WRITTEN":{"p":"/ˈɹɪtn̩/","s":"v./adj.","e":"[v.] To form letters, words or symbols on a surface in order to communicate.\n[v.] To be the author of (a book, article, poem, etc.).\n[v.] To send written information to.\n[adj.] Of, relating, or characteristic of writing (i.e., of that which has been written).\n[adj.] Having been written.","ex":"The pupil wrote his name on the paper."},"WROTH":{"p":"/ɹɒθ/","s":"adj.","e":"[adj.] Full of anger; wrathful.","ex":""},"WRONG":{"p":"/ɹɒŋ/","s":"n./v./adj./adv.","e":"[n.] Something that is immoral or not good.\n[n.] An instance of wronging someone (sometimes with possessive to indicate the wrongdoer).\n[n.] The incorrect or unjust position or opinion.\n[v.] To treat unjustly; to injure or harm.\n[v.] To deprive of some right, or to withhold some act of justice.\n[v.] To slander; to impute evil to unjustly.","ex":"Injustice is a heinous wrong."},"WROTE":{"p":"/ɹəʊt/","s":"v.","e":"[v.] To form letters, words or symbols on a surface in order to communicate.\n[v.] To be the author of (a book, article, poem, etc.).\n[v.] To send written information to.","ex":"The pupil wrote his name on the paper."},"WRUNG":{"p":"/ˈɹʌŋ/","s":"v.","e":"[v.] To squeeze or twist (something) tightly so that liquid is forced out. See also wring out.\n[v.] To extract (a liquid) from something wet, especially cloth, by squeezing and twisting it.\n[v.] To obtain (something from or out of someone or something) by force.","ex":"I didn’t have a towel so I just wrung my hair dry."},"WRYLY":{"p":"/ˈɹaɪli/","s":"adv.","e":"[adv.] In a wry manner.","ex":"1966: The sins of the father, she thought wryly. Well, they had visited Tony, all right — only he didn't know it. — Jacqueline Susann, Valley of the Dolls (Grove Press 1997, p. 206)"},"XENON":{"p":"/zenɔn/","s":"n.","e":"[n.] The chemical element (symbol Xe) with an atomic number of 54. It is a colorless, odorless, unreactive noble gas, used notably in camera flash technology.","ex":""},"YACHT":{"p":"/jɒt/","s":"n./v.","e":"[n.] A slick and light ship for making pleasure trips or racing on water, having sails but often motor-powered. At times used as a residence offshore on a dock.\n[n.] Any vessel used for private, noncommercial purposes.\n[v.] To sail, voyage, or race in a yacht.","ex":"Would you like to go sailing on my uncle’s yacht?"},"YANKS":{"p":"","s":"n./v.","e":"[n.] A sudden, vigorous pull (sometimes defined as mass times jerk, or rate of change of force).\n[n.] A masturbation session.\n[v.] To pull (something) with a quick, strong action.\n[v.] To remove from distribution.\n[n.] A Yankee.","ex":"They yanked the product as soon as they learned it was unsafe."},"YARD":{"p":"/jɑːd/","s":"n./v.","e":"[n.] A small, usually uncultivated area adjoining or (now especially) within the precincts of a house or other building.\n[n.] The property surrounding one's house, typically dominated by one's lawn.\n[n.] An enclosed area designated for a specific purpose, e.g. on farms, railways etc.\n[v.] To confine to a yard.","ex":""},"YARDS":{"p":"/jɑːdz/","s":"n./v.","e":"[n.] A small, usually uncultivated area adjoining or (now especially) within the precincts of a house or other building.\n[n.] The property surrounding one's house, typically dominated by one's lawn.\n[n.] An enclosed area designated for a specific purpose, e.g. on farms, railways etc.\n[v.] To confine to a yard.\n[n.] A unit of length equal to 3 feet in the US customary and British imperial systems of measurement, equal to precisely 0.9144 m since 1959 (US) or 1963 (UK).\n[n.] Units of similar composition or length in other systems.","ex":"I need to hedge a yard of yen."},"YARNS":{"p":"","s":"n./v.","e":"[n.] A twisted strand of fiber used for knitting or weaving.\n[n.] Bundles of fibers twisted together, and which in turn are twisted in bundles to form strands, which in their turn are twisted or plaited to form rope.\n[n.] A story, a tale, especially one that is incredible.\n[v.] To tell a story or stories.","ex":""},"YEAH":{"p":"/ˈjæ.ə/","s":"int.","e":"[int.] Expressing joy, celebration, glee, etc.","ex":"Yeah! We did it!"},"YEAR":{"p":"/jɪə/","s":"n.","e":"[n.] A solar year, the time it takes the Earth to complete one revolution of the Sun (between 365.24 and 365.26 days depending on the point of reference).\n[n.] (by extension) The time it takes for any astronomical object (such as a planet, dwarf planet, small Solar System body, or comet) in direct orbit around a star (such as the Sun) to make one revolution around the star.\n[n.] A period between set dates that mark a year, from January 1 to December 31 by the Gregorian calendar, from Tishiri 1 to Elul 29 by the Jewish calendar, and from Muharram 1 to Dhu al-Hijjah 29 or 30 by the Islamic calendar.","ex":"we moved to this town a year ago;  I quit smoking exactly one year ago"},"YAWLS":{"p":"","s":"n.","e":"[n.] A small ship's boat, usually rowed by four or six oars.\n[n.] A fore-and-aft rigged sailing vessel with two masts, main and mizzen, the mizzen stepped abaft the rudder post.","ex":""},"YEAST":{"p":"/iːst/","s":"n./v.","e":"[n.] An often humid, yellowish froth produced by fermenting malt worts, and used to brew beer, leaven bread, and also used in certain medicines.\n[n.] A single-celled fungus of a wide variety of taxonomic families.\n[n.] A frothy foam.\n[v.] To ferment.\n[v.] (of something prepared with a yeasted dough) To rise.\n[v.] To exaggerate","ex":""},"YAWNS":{"p":"","s":"n./v.","e":"[n.] The action of yawning; opening the mouth widely and taking a long, rather deep breath, often because one is tired or bored.\n[n.] A particularly boring event.\n[v.] To open the mouth widely and take a long, rather deep breath, often because one is tired or bored, and sometimes accompanied by pandiculation.\n[v.] To say while yawning.\n[v.] To present a wide opening.","ex":"The slideshow we sat through was such a yawn. I was glad when it finished."},"YEARN":{"p":"/jɜːn/","s":"v.","e":"[v.] To long, have a strong desire (for something).\n[v.] To long for something in the past with melancholy, nostalgically.\n[v.] To have strong feelings of love, sympathy, affection, etc. (toward someone).","ex":"All I yearn for is a simple life."},"YEARS":{"p":"/ji.ə(ɹ)z/","s":"n.","e":"[n.] A solar year, the time it takes the Earth to complete one revolution of the Sun (between 365.24 and 365.26 days depending on the point of reference).\n[n.] (by extension) The time it takes for any astronomical object (such as a planet, dwarf planet, small Solar System body, or comet) in direct orbit around a star (such as the Sun) to make one revolution around the star.\n[n.] A period between set dates that mark a year, from January 1 to December 31 by the Gregorian calendar, from Tishiri 1 to Elul 29 by the Jewish calendar, and from Muharram 1 to Dhu al-Hijjah 29 or 30 by the Islamic calendar.\n[n.] A very long time.","ex":"we moved to this town a year ago;  I quit smoking exactly one year ago"},"YELL":{"p":"/jɛl/","s":"n./v.","e":"[n.] A shout.\n[n.] A phrase to be shouted.\n[v.] Shout; holler; make a loud sound with the voice.\n[v.] To convey by shouting\n[v.] To tell someone off (in a loud and angry manner)","ex":"He yelled directions to the party from the car."},"YELLOW":{"p":"/jɛlə/","s":"n./v./adj.","e":"[n.] The colour of gold, butter, or a lemon; the colour obtained by mixing green and red light, or by subtracting blue from white light.\n[n.] The intermediate light in a set of three traffic lights, the illumination of which indicates that drivers should stop short of the intersection if it is safe to do so.\n[n.] One of the colour balls used in snooker, with a value of 2 points.\n[v.] To become yellow or more yellow.\n[v.] To make (something) yellow or more yellow.\n[adj.] Having yellow as its colour.","ex":""},"YELLS":{"p":"","s":"n./v.","e":"[n.] A shout.\n[n.] A phrase to be shouted.\n[v.] Shout; holler; make a loud sound with the voice.\n[v.] To convey by shouting\n[v.] To tell someone off (in a loud and angry manner)","ex":"He yelled directions to the party from the car."},"YELPS":{"p":"/jɛlps/","s":"n./v.","e":"[n.] An abrupt, high-pitched noise or utterance.\n[n.] A type of emergency vehicle siren sounding quicker and more intense than the wail.\n[v.] To utter an abrupt, high-pitched noise.","ex":"The puppy let out a yelp when I stepped on her tail."},"YIPES":{"p":"","s":"int.","e":"[int.] Expression of shock and alarm.\n[int.] Expression of empathy with unpleasant or undesirable circumstances.","ex":"Then she told me I was ‘beautiful, for a black girl’. —Yikes!"},"YODEL":{"p":"/ˈjəʊ.dəl/","s":"n./v.","e":"[n.] A song incorporating yodelling.\n[v.] To sing (a song) in such a way that the voice fluctuates rapidly between the normal chest voice and falsetto.","ex":""},"YIELD":{"p":"/jiːld/","s":"v.","e":"[v.] To pay, give in payment; repay, recompense; reward; requite.\n[v.] To furnish; to afford; to render; to give forth.\n[v.] To give way; to allow another to pass first.","ex":"Yield the right of way to pedestrians."},"YOGIS":{"p":"","s":"n./v.","e":"[n.] A devotee or adherent of yoga.\n[v.] To turn (someone) into a yogi; to lead into practicing yoga.\n[v.] (thru-hiker slang) To persuade someone to give you food or other favors without actually begging.","ex":"Gurdjieff connects this type of breathing with yogi breathing."},"YOKES":{"p":"","s":"n./v.","e":"[n.] Frame around the neck, and related senses.\n[n.] Pair of harnessed draught animals, and related senses.\n[n.] Extended uses and quantities.\n[v.] To link or to join.\n[v.] To unite, to connect.\n[v.] To enslave; to bring into bondage; to restrain; to confine.","ex":""},"YOKEL":{"p":"/ˈjəʊ.kəl/","s":"n.","e":"[n.] An unsophisticated person.\n[n.] A person of rural background.","ex":""},"YOKED":{"p":"","s":"v./adj.","e":"[v.] To link or to join.\n[v.] To unite, to connect.\n[v.] To enslave; to bring into bondage; to restrain; to confine.\n[adj.] Wearing a yoke.\n[adj.] Having large and well-defined muscles particularly at the neck and the trapezii (forming thus the “yoke“).\n[adj.] Married.","ex":"The yoked oxen stood ready."},"YOLKS":{"p":"/jəʊks/","s":"n.","e":"[n.] The yellow, spherical part of an egg that is surrounded by the white albumen, and serves as nutriment for the growing young.\n[n.] The grease in a sheep's fleece.","ex":""},"YESES":{"p":"/jɛsɪz/","s":"n./v.","e":"[n.] An affirmative expression; an answer that shows agreement or acceptance.\n[n.] A vote of support or in favor/favour of something.\n[v.] To agree with, affirm, approve.\n[v.] To attempt to flatter someone by habitually agreeing","ex":"Was that a yes?"},"YOURS":{"p":"/jɔː(ɹ)z/","s":"pron.","e":"[pron.] That which belongs to you (singular); the possessive second-person singular pronoun used without a following noun.\n[pron.] That which belongs to you (plural); the possessive second-person plural pronoun used without a following noun.\n[pron.] Written at the end of a letter, before the signature.","ex":"If this edit is mine, the other must be yours.  Their encyclopedia is good, but yours is even better.  It’s all yours."},"YOUTH":{"p":"/juθ/","s":"n.","e":"[n.] The quality or state of being young.\n[n.] The part of life following childhood; the period of existence preceding maturity or age; the whole early part of life, from childhood, or, sometimes, from infancy, to adulthood.\n[n.] A young person.","ex":"Her youth and beauty attracted him to her."},"YOWLS":{"p":"","s":"n./v.","e":"[n.] A prolonged, loud cry, like the sound of an animal; a wail; a howl.\n[v.] Utter a yowl.\n[v.] Express by yowling; utter with a yowl.","ex":""},"YOYOS":{"p":"","s":"n.","e":"[n.] A toy consisting of a spheroidal or cylindrical spindle having a circular groove in which string is wound; it is used by holding the string in the fingers and reeling the spindle up and down by movements of the wrist.\n[n.] A volatile market that moves up and down.\n[n.] Someone who vacillates.","ex":"I bought a yo-yo from the toy store yesterday."},"YUCCA":{"p":"/ˈjʌkə/","s":"n.","e":"[n.] Any of several evergreen plants of the genus Yucca, having long, pointed, and rigid leaves at the top of a woody stem, and bearing a large panicle of showy white blossoms.\n[n.] The yuca (cassava).","ex":""},"YOUNG":{"p":"/jʌŋ/","s":"n./v./adj.","e":"[n.] People who are young; young people, collectively; youth.\n[n.] Young or immature offspring (especially of an animal).\n[n.] (possibly nonstandard) An individual offspring; a single recently born or hatched organism.\n[v.] To become or seem to become younger.\n[v.] To cause to appear younger.\n[v.] To exhibit younging.","ex":"The young of today are well-educated."},"YUPPY":{"p":"","s":"n.","e":"[n.] A young upwardly mobile urban professional person with an affluent lifestyle.","ex":""},"ZAPPY":{"p":"","s":"adj.","e":"[adj.] Lively or energetic.","ex":""},"YUMMY":{"p":"/ˈjʌm.i/","s":"adj./n.","e":"[adj.] (lighthearted) Delicious.\n[n.] A mother who is sexually attractive.","ex":""},"ZAIRE":{"p":"","s":"n.","e":"[n.] The unit of currency of Zaire.","ex":""},"ZILCH":{"p":"/zɪltʃ/","s":"n./v./adj.","e":"[n.] A nobody: a person who is worthless in importance or character.\n[n.] Nothing, zero.\n[v.] To cause to score nothing, to thoroughly defeat.\n[adj.] No, zero, non-existent.","ex":"Her search for decent home-made winter clothes came up with zilch, so she had to get imported stuff."},"ZEROS":{"p":"","s":"n.","e":"[n.] The numeric symbol that represents the cardinal number zero.\n[n.] The digit 0 in the decimal, binary, and all other base numbering systems.\n[n.] Nothing, or none.","ex":"In unary and k-adic notation in general, zero is the empty string."},"ZINGS":{"p":"","s":"n./v.","e":"[n.] A short high-pitched humming sound, such as that made by a bullet or vibrating string.\n[n.] A witty insult or derogatory remark.\n[n.] Zest or vitality.\n[v.] To move very quickly, especially while making a high-pitched hum.","ex":""},"YUCKS":{"p":"","s":"n./v.","e":"[n.] Something disgusting.\n[n.] The sound made by a laugh.\n[v.] To itch.","ex":""},"ZONAL":{"p":"/ˈzəʊnəl/","s":"adj.","e":"[adj.] Divided into zones.\n[adj.] Related to, associated with, or similar to zones.\n[adj.] (of air or ocean currents) roughly longitudinal (east to west, or west to east)","ex":""},"ZEBRA":{"p":"/ˈziːbɹə/","s":"n.","e":"[n.] Any of three species of genus Equus: E. grevyi, E. quagga, or E. zebra, all with black and white stripes and native to Africa.\n[n.] A referee.\n[n.] An unlikely diagnosis, especially for symptoms probably caused by a common ailment. (Originates in the advice often given to medical students: \"when you hear hoofbeats, think of horses, not zebras\".)","ex":""},"ZINCS":{"p":"","s":"n./v.","e":"[n.] A chemical element (symbol Zn) with an atomic number of 30, a slightly brittle blue-silvery metal.\n[n.] A single atom of this element.\n[n.] A zinc countertop.\n[v.] To electroplate with zinc.\n[v.] To coat with sunblock incorporating zinc oxide.","ex":""},"ZONED":{"p":"","s":"v.","e":"[v.] To divide into or assign sections or areas.\n[v.] To define the property use classification of an area.\n[v.] To enter a daydream state temporarily, for instance as a result of boredom, fatigue, or intoxication; to doze off.","ex":"Please zone off our staging area, a section for each group."},"ZONES":{"p":"","s":"n./v.","e":"[n.] Each of the five regions of the earth's surface into which it was divided by climatic differences, namely the torrid zone (between the tropics), two temperate zones (between the tropics and the polar circles), and two frigid zones (within the polar circles).\n[n.] Any given region or area of the world.\n[n.] A given area distinguished on the basis of a particular characteristic, use, restriction, etc.\n[v.] To divide into or assign sections or areas.\n[v.] To define the property use classification of an area.\n[v.] To enter a daydream state temporarily, for instance as a result of boredom, fatigue, or intoxication; to doze off.","ex":"Files in the Internet zone are blocked by default, as a security measure."},"ZONE":{"p":"/zəʊn/","s":"n./v.","e":"[n.] Each of the five regions of the earth's surface into which it was divided by climatic differences, namely the torrid zone (between the tropics), two temperate zones (between the tropics and the polar circles), and two frigid zones (within the polar circles).\n[n.] Any given region or area of the world.\n[n.] A given area distinguished on the basis of a particular characteristic, use, restriction, etc.\n[v.] To divide into or assign sections or areas.\n[v.] To define the property use classification of an area.\n[v.] To enter a daydream state temporarily, for instance as a result of boredom, fatigue, or intoxication; to doze off.","ex":"Files in the Internet zone are blocked by default, as a security measure."},"ANNEX":{"p":"/ˈænɛks/","s":"n.","e":"[n.] An addition, an extension.\n[n.] An appendix to a book or document.\n[n.] An addition or extension to a building.","ex":""},"ANODE":{"p":"/ˈæn.əʊd/","s":"n.","e":"[n.] An electrode, of a cell or other electrically polarized device, through which a positive current of electricity flows inwards (and thus, electrons flow outwards). It can have either a negative or a positive voltage.\n[n.] (by extension) The electrode at which chemical oxidation of anions takes place, usually resulting in the erosion of metal from the electrode.\n[n.] The electrode which collects electrons emitted by the cathode in a vacuum tube or gas-filled tube.","ex":""},"ANYWAY":{"p":"/ˈɛniweɪ/","s":"adv.","e":"[adv.] Regardless; anyhow.\n[adv.] Used to indicate that a statement explains or supports a previous statement. See anyhow and at least.\n[adv.] Used to indicate a change of subject.","ex":"He didn't enjoy washing his car, but it was so dirty that he did it anyway."},"APPEAR":{"p":"/əˈpiːɹ/","s":"v.","e":"[v.] To come or be in sight; to be in view; to become visible.\n[v.] To come before the public.\n[v.] To stand in presence of some authority, tribunal, or superior person, to answer a charge, plead a cause, etc.; to present oneself as a party or advocate before a court, or as a person to be tried.","ex":"A great writer appeared at that time."},"ARMY":{"p":"/ˈɑː.miː/","s":"n.","e":"[n.] A large, highly organized military force, concerned mainly with ground (rather than air or naval) operations.\n[n.] The governmental agency in charge of a state's army.\n[n.] A large group of people working toward the same purpose.","ex":"The army was sent in to quell the uprising."},"ASSET":{"p":"/ˈæsɪt/","s":"n.","e":"[n.] Something or someone of any value; any portion of one's property or effects so considered.\n[n.] Any component, model, process or framework of value that can be leveraged or reused.\n[n.] An intelligence asset.","ex":"These shares are a valuable asset."},"AVOID":{"p":"/əˈvɔɪd/","s":"v.","e":"[v.] To try not to meet or communicate with (a person); to shun\n[v.] To keep away from; to keep clear of; to stay away from\n[v.] To try not to do something or to have something happen","ex":"I try to avoid the company of gamblers."},"AWAKE":{"p":"/əˈweɪk/","s":"adj.","e":"[adj.] Not asleep; conscious.\n[adj.] (by extension) Alert, aware.","ex":"They were awake to the possibility of a decline in sales."},"AWARD":{"p":"/əˈwɔːd/","s":"n./v.","e":"[n.] A judgment, sentence, or final decision. Specifically: The decision of arbitrators in a case submitted.\n[n.] The paper containing the decision of arbitrators; that which is warded.\n[n.] A trophy or medal; something that denotes an accomplishment, especially in a competition. A prize or honor based on merit.\n[v.] To give by sentence or judicial determination; to assign or apportion, after careful regard to the nature of the case; to adjudge\n[v.] To determine; to make or grant an award.\n[v.] To give (an award).","ex":"the arbitrators awarded damages to the complainant"},"BACK":{"p":"/bæk/","s":"n./v./adj./adv.","e":"[n.] The rear of the body, especially the part between the neck and the end of the spine and opposite the chest and belly.\n[n.] That which is farthest away from the front.\n[n.] Upper part of a natural object which is considered to resemble an animal's back.\n[v.] To go in the reverse direction.\n[v.] To support.\n[v.] (of the wind) To change direction contrary to the normal pattern; that is, to shift anticlockwise in the northern hemisphere, or clockwise in the southern hemisphere.","ex":"Could you please scratch my back?"},"BADLY":{"p":"/ˈbæd.li/","s":"adj./adv.","e":"[adj.] Ill, unwell.\n[adv.] In a bad manner.\n[adv.] Very much; to a great degree.","ex":"He's never badly."},"BALL":{"p":"/bɔːl/","s":"n./v./int.","e":"[n.] A solid or hollow sphere, or roughly spherical mass.\n[n.] A round or ellipsoidal object.\n[n.] (mildly, usually in the plural) A testicle.\n[v.] To form or wind into a ball.\n[v.] To heat in a furnace and form into balls for rolling.\n[v.] To have sexual intercourse with.","ex":"a ball of spittle; a fecal ball"},"BATCH":{"p":"/bæt͡ʃ/","s":"n./v./adj.","e":"[n.] The quantity of bread or other baked goods baked at one time.\n[n.] (by extension) A quantity of anything produced at one operation.\n[n.] A group or collection of things of the same kind, such as a batch of letters or the next batch of business.\n[v.] To aggregate things together into a batch.\n[v.] To handle a set of input data or requests as a batch process.\n[adj.] Of a process, operating for a defined set of conditions, and then halting.","ex":"We made a batch of cookies to take to the party."},"BATHE":{"p":"/beɪð/","s":"n./v.","e":"[n.] The act of swimming or bathing, especially in the sea, a lake, or a river; a swimming bath.\n[v.] To clean oneself by immersion in water or using water; to take a bath, have a bath.\n[v.] To immerse oneself, or part of the body, in water for pleasure or refreshment; to swim.\n[v.] To clean a person by immersion in water or using water; to give someone a bath.","ex":"I'm going to have a midnight bathe tonight."},"BATIK":{"p":"/bəˈtiːk/","s":"n./v.","e":"[n.] A wax-resist method of dyeing fabric.\n[v.] To dye fabric using the wax-resist method.","ex":""},"BEACH":{"p":"/biːt͡ʃ/","s":"n./v.","e":"[n.] The shore of a body of water, especially when sandy or pebbly.\n[n.] A horizontal strip of land, usually sandy, adjoining water.\n[n.] The loose pebbles of the seashore, especially worn by waves; shingle.\n[v.] To run aground on a beach.\n[v.] To run (something) aground on a beach.\n[v.] (of a vehicle) To run into an obstacle or rough or soft ground, so that the floor of the vehicle rests on the ground and the wheels cannot gain traction.","ex":""},"BEAR":{"p":"/bɛə(ɹ)/","s":"n./v./adj.","e":"[n.] A large omnivorous mammal, related to the dog and raccoon, having shaggy hair, a very small tail, and flat feet; a member of family Ursidae.\n[n.] A rough, unmannerly, uncouth person.\n[n.] An investor who sells commodities, securities or futures in anticipation of a fall in prices.\n[v.] To endeavour to depress the price of, or prices in.\n[adj.] (investments) Characterized by declining prices in securities markets or by belief that the prices will fall.","ex":"to bear a railroad stock"},"BEAST":{"p":"/biːst/","s":"n./v./adj.","e":"[n.] Any animal other than a human; usually only applied to land vertebrates, especially large or dangerous four-footed ones.\n[n.] (more specific) A domestic animal, especially a bovine farm animal.\n[n.] A person who behaves in a violent, antisocial or uncivilized manner.\n[v.] To impose arduous exercises, either as training or as punishment.\n[adj.] (chiefly Midwestern and northeastern US) great; excellent; powerful","ex":""},"BEFORE":{"p":"/bɪˈfɔː/","s":"adv./prep./conj.","e":"[adv.] At an earlier time.\n[adv.] In advance.\n[adv.] At the front end.\n[prep.] Earlier than (in time).\n[prep.] In front of in space.\n[prep.] In the presence of.","ex":"I've never done this before."},"BEGAT":{"p":"/biˈɡæt/","s":"n./v.","e":"[n.] An element of a lineage, especially of a lineage given in the Bible\n[v.] To father; to sire; to produce (a child).\n[v.] To cause; to produce.\n[v.] To bring forth.","ex":""},"BEGIN":{"p":"/biˈɡɪn/","s":"n./v.","e":"[n.] Beginning; start.\n[v.] To start, to initiate or take the first step into something.\n[v.] To be in the first stage of some situation\n[v.] To come into existence.","ex":"I began playing the piano at the age of five.   Now that everyone is here, we should begin the presentation."},"BELONG":{"p":"/bɪˈlɒŋ/","s":"v.","e":"[v.] To have its proper place.\n[v.] (followed by to) To be part of, or the property of.\n[v.] (followed by to) To be the spouse or partner of.","ex":"Where does this document belong?"},"BETTER":{"p":"[ˈbeɾə]","s":"n./adj./adv.","e":"[n.] An entity, usually animate, deemed superior to another; one who has a claim to precedence; a superior.\n[adj.] Greater in amount or quantity\n[adj.] (of people)\n[adj.] (of capabilities)\n[adj.] (properties and qualities)\n[adj.] In good health.","ex":"He quickly found Ali his better in the ring."},"BIBLE":{"p":"/ˈbaɪbəl/","s":"n.","e":"[n.] An exemplar of the Bible.\n[n.] A comprehensive manual that describes something. (e.g., handyman’s bible).\n[n.] (at certain US universities) A compilation of problems and solutions from previous years of a given course, used by some students to cheat on tests or assignments.\n[n.] A piece of soft sandstone used for scouring the wooden decks of ships, usually with sand and seawater.\n[n.] A stone with a naturally-formed hole, used by Yorkshiremen for good luck.","ex":""},"BILLY":{"p":"","s":"n.","e":"[n.] A billy club.\n[n.] A billy goat.\n[n.] A good friend.","ex":""},"BIRTH":{"p":"/bɜːθ/","s":"n./v./adj.","e":"[n.] The process of childbearing; the beginning of life.\n[n.] An instance of childbirth.\n[n.] A beginning or start; a point of origin.\n[v.] To bear or give birth to (a child).\n[v.] To produce, give rise to.\n[adj.] A familial relationship established by childbirth.","ex":"Intersex babies account for roughly one per cent of all births."},"BITTER":{"p":"/ˈbɪtə/","s":"n./v./adj.","e":"[n.] (usually in the plural bitters) A liquid or powder, made from bitter herbs, used in mixed drinks or as a tonic.\n[n.] A type of beer heavily flavored with hops.\n[n.] A turn of a cable about the bitts.\n[v.] To make bitter.\n[adj.] Having an acrid taste (usually from a basic substance).\n[adj.] Harsh, piercing or stinging.","ex":"The coffee tasted bitter."},"BLADE":{"p":"/bleɪd/","s":"n./v.","e":"[n.] The sharp cutting edge of a knife, chisel, or other tool, a razor blade/sword.\n[n.] The flat functional end of a propeller, oar, hockey stick, screwdriver, skate, etc.\n[n.] The narrow leaf of a grass or cereal.\n[v.] To skate on rollerblades.\n[v.] To furnish with a blade.\n[v.] To put forth or have a blade.","ex":"Want to go blading with me later in the park?"},"BLAME":{"p":"/bleɪm/","s":"n.","e":"[n.] Censure.\n[n.] Culpability for something negative or undesirable.\n[n.] Responsibility for something meriting censure.","ex":"Blame came from all directions."},"BLANCH":{"p":"/blæntʃ/","s":"v.","e":"[v.] To grow or become white\n[v.] To take the color out of, and make white; to bleach\n[v.] To cook by dipping briefly into boiling water, then directly into cold water.","ex":"His cheek blanched with fear."},"BLANK":{"p":"/blæŋk/","s":"n./v./adj.","e":"[n.] A small French coin, originally of silver, afterwards of copper, worth 5 deniers; also a silver coin of Henry V current in the parts of France then held by the English, worth about 8 pence .\n[n.] A nonplus .\n[n.] The white spot in the centre of a target; hence the object to which anything is directed or aimed, the range of such aim .\n[v.] To make void; to erase.\n[v.] To ignore (a person) deliberately.\n[v.] To prevent from scoring, for example in a sporting event.","ex":"I blanked out my previous entry."},"BLAST":{"p":"/blɑːst/","s":"n.","e":"[n.] A violent gust of wind.\n[n.] A forcible stream of gas or liquid from an orifice, for example from a bellows, the mouth, etc.\n[n.] A hit from a pipe.","ex":""},"BLESS":{"p":"/blɛs/","s":"v.","e":"[v.] To make something holy by religious rite, sanctify.\n[v.] To make the sign of the cross upon, so as to sanctify.\n[v.] To invoke divine favor upon.","ex":""},"BLIND":{"p":"/blaɪnd/","s":"n./v./adj./adv.","e":"[n.] A covering for a window to keep out light. The covering may be made of cloth or of narrow slats that can block light or allow it to pass.\n[n.] A destination sign mounted on a public transport vehicle displaying the route destination, number, name and/or via points, etc.\n[n.] Any device intended to conceal or hide.\n[v.] To make temporarily or permanently blind.\n[v.] To curse.\n[v.] To darken; to obscure to the eye or understanding; to conceal.","ex":"a duck blind"},"BLINK":{"p":"/blɪŋk/","s":"n./v.","e":"[n.] The act of very quickly closing both eyes and opening them again.\n[n.] The time needed to close and reopen one's eyes.\n[n.] A text formatting feature that causes text to disappear and reappear as a form of visual emphasis.\n[v.] To close and reopen both eyes quickly.\n[v.] To flash on and off at regular intervals.\n[v.] To perform the smallest action that could solicit a response.","ex":"The loser in the staring game is the person who blinks first."},"BLOCK":{"p":"/blɒk/","s":"n./v.","e":"[n.] A substantial, often approximately cuboid, piece of any substance.\n[n.] A chopping block; cuboid base for cutting or beheading.\n[n.] A group of urban lots of property, several acres in extent, not crossed by public streets.\n[v.] To fill (something) so that it is not possible to pass.\n[v.] To prevent (something or someone) from passing.\n[v.] To prevent (something from happening or someone from doing something).","ex":"a block of ice"},"BLOOD":{"p":"/blʊd/","s":"n./v.","e":"[n.] A member of the Los Angeles gang The Bloods.\n[n.] A vital liquid flowing in the bodies of many types of animals that usually conveys nutrients and oxygen. In vertebrates, it is colored red by hemoglobin, is conveyed by arteries and veins, is pumped by the heart and is usually generated in bone marrow.\n[n.] A family relationship due to birth, such as that between siblings; contrasted with relationships due to marriage or adoption (see blood relative, blood relation, by blood).\n[n.] One of the four humours in the human body.\n[v.] To cause something to be covered with blood; to bloody.\n[v.] To let blood (from); to bleed.","ex":"The cultists gathered around a chalice of blood."},"BLOWN":{"p":"/bləʊn/","s":"v./adj.","e":"[v.] To produce an air current.\n[v.] To propel by an air current.\n[v.] To be propelled by an air current.\n[v.] To blossom; to cause to bloom or blossom.\n[adj.] Distended, swollen or inflated\n[adj.] Panting and out of breath","ex":"Blow the dust off that book and open it up."},"BLUE":{"p":"/bluː/","s":"n./v./adj.","e":"[n.] The colour of the clear sky or the deep sea, between green and violet in the visible spectrum, and one of the primary additive colours for transmitted light; the colour obtained by subtracting red and green from white light using magenta and cyan filters; or any colour resembling this.\n[n.] A blue dye or pigment.\n[n.] Any of several processes to protect metal against rust.\n[v.] To make or become blue.\n[v.] To treat the surface of steel so that it is passivated chemically and becomes more resistant to rust.\n[v.] (laundry) To brighten by treating with blue (laundry aid)","ex":"the deep blue sea"},"BLUNT":{"p":"/blʌnt/","s":"n./adj.","e":"[n.] A fencer's practice foil with a soft tip.\n[n.] A short needle with a strong point.\n[n.] (smoking) A marijuana cigar.\n[adj.] Having a thick edge or point; not sharp.\n[adj.] Dull in understanding; slow of discernment; opposed to acute.\n[adj.] Abrupt in address; plain; unceremonious; wanting the forms of civility; rough in manners or speech.","ex":"2005: to make his point, lead rapper B-Real fired up a blunt in front of the cameras and several hundred thousand people and announced, “I'm taking a hit for every one of y'all!” — Martin Torgoff, Can't Find My Way Home (Simon & Schuster 2005, p. 461)"},"BLURB":{"p":"/blɝ(ː)b/","s":"n./v.","e":"[n.] A short description of a book, film, or other work, written and used for promotional purposes.\n[v.] To write or quote in a blurb.\n[v.] To supply with a blurb.","ex":""},"BOARD":{"p":"/bɔːd/","s":"n./v.","e":"[n.] A relatively long, wide and thin piece of any material, usually wood or similar, often for use in construction or furniture-making.\n[n.] A device (e.g., switchboard) containing electrical switches and other controls and designed to control lights, sound, telephone connections, etc.\n[n.] A flat surface with markings for playing a board game.\n[v.] To step or climb onto or otherwise enter a ship, aircraft, train or other conveyance.\n[v.] To provide someone with meals and lodging, usually in exchange for money.\n[v.] To receive meals and lodging in exchange for money.","ex":"Each player starts the game with four counters on the board."},"BODY":{"p":"/ˈbɒdi/","s":"n./v.","e":"[n.] Physical frame.\n[n.] Main section.\n[n.] Coherent group.\n[v.] To give body or shape to something.\n[v.] To construct the bodywork of a car.\n[v.] To embody.","ex":""},"BOGUS":{"p":"/ˈbəʊ.ɡəs/","s":"n./adj.","e":"[n.] A liquor made of rum and molasses.\n[adj.] Counterfeit or fake; not genuine.\n[adj.] Undesirable or harmful.\n[adj.] Incorrect, useless, or broken.","ex":""},"BOND":{"p":"/bɒnd/","s":"n./v.","e":"[n.] Evidence of a long-term debt, by which the bond issuer (the borrower) is obliged to pay interest when due, and repay the principal at maturity, as specified on the face of the bond certificate. The rights of the holder are specified in the bond indenture, which contains the legal terms and conditions under which the bond was issued. Bonds are available in two forms: registered bonds, and bearer bonds.\n[n.] A documentary obligation to pay a sum or to perform a contract; a debenture.\n[n.] A partial payment made to show a provider that the customer is sincere about buying a product or a service. If the product or service is not purchased the customer then forfeits the bond.\n[v.] To connect, secure or tie with a bond; to bind.\n[v.] To cause to adhere (one material with another).\n[v.] To form a chemical compound with.","ex":"Investors face a quandary. Cash offers a return of virtually zero in many developed countries; government-bond yields may have risen in recent weeks but they are still unattractive. Equities have suffered two big bear markets since 2000 and are wobbling again. It is hardly surprising that pension funds, insurers and endowments are searching for new sources of return."},"BONUS":{"p":"/ˈbəʊ.nəs/","s":"n./v.","e":"[n.] Something extra that is good; an added benefit.\n[n.] An extra sum given as a premium, e.g. to an employee or to a shareholder.\n[n.] An addition to the player's score based on performance, e.g. for time remaining.\n[v.] To pay a bonus, premium","ex":"The employee of the week receives a bonus for his excellent work."},"BORDER":{"p":"/ˈbɔədə/","s":"n./v.","e":"[n.] The outer edge of something.\n[n.] A decorative strip around the edge of something.\n[n.] A strip of ground in which ornamental plants are grown.\n[v.] To put a border on something.\n[v.] To form a border around; to bound.\n[v.] To lie on, or adjacent to, a border of.","ex":"the borders of the garden"},"BOTTOM":{"p":"/ˈbɒtəm/","s":"n./v./adj.","e":"[n.] The lowest part of anything.\n[n.] Character, reliability, staying power, dignity, integrity or sound judgment.\n[n.] Low-lying land; a valley or hollow.\n[v.] To furnish (something) with a bottom.\n[v.] To wind (like a ball of thread etc.).\n[v.] To establish or found (something) on or upon.","ex":"Footers appear at the bottoms of pages."},"BOULE":{"p":"","s":"n./v.","e":"[n.] One of the bowls used in the French game of boules.\n[n.] A single-crystal ingot produced by synthetic means.\n[n.] A round loaf of bread.\n[v.] To shape (a piece of dough) into a ball.","ex":""},"BOWL":{"p":"/bəʊɫ/","s":"n.","e":"[n.] A roughly hemispherical container used to hold, mix or present food, such as salad, fruit or soup, or other items.\n[n.] As much as is held by a bowl.\n[n.] A dish comprising a mix of different foods, not all of which need be cooked, served in a bowl.","ex":"You can’t have any more soup – you’ve had three bowls already."},"BOXER":{"p":"/ˈbɒksə/","s":"n.","e":"[n.] A participant (fighter) in a boxing match.\n[n.] A breed of stocky, medium-sized, short-haired dog with a square-jawed muzzle.\n[n.] A type of internal combustion engine in which cylinders are arranged in two banks on either side of a single crankshaft.","ex":"You can tell she's a boxer by looking at her nose."},"BRAIN":{"p":"/bɹeɪn/","s":"n./v.","e":"[n.] The control center of the central nervous system of an animal located in the skull which is responsible for perception, cognition, attention, memory, emotion, and action.\n[n.] An intelligent person.\n[n.] (in the plural) Intellect.\n[v.] To dash out the brains of; to kill by smashing the skull.\n[v.] To strike (someone) on the head.\n[v.] To destroy; to put an end to.","ex":"She was a total brain."},"BRAKE":{"p":"/bɹeɪk/","s":"n.","e":"[n.] A fern; bracken.","ex":""},"BRANCH":{"p":"/bɹæntʃ/","s":"n./v.","e":"[n.] The woody part of a tree arising from the trunk and usually dividing.\n[n.] Any of the parts of something that divides like the branch of a tree.\n[n.] A creek or stream which flows into a larger river. (compare Ohio, Pennsylvania and West Virginia run, and New York and New England brook.)\n[v.] To arise from the trunk or a larger branch of a tree.\n[v.] To produce branches.\n[v.] To (cause to) divide into separate parts or subdivisions.","ex":"the branch of an antler, a chandelier, or a railway"},"BREAK":{"p":"/bɹeɪk/","s":"n./v.","e":"[n.] An instance of breaking something into two or more pieces.\n[n.] A physical space that opens up in something or between two things.\n[n.] A rest or pause, usually from work.\n[v.] To separate into two or more pieces, to fracture or crack, by a process that cannot easily be reversed for reassembly.\n[v.] To divide (something, often money) into smaller units.\n[v.] To cause (a person or animal) to lose spirit or will; to crush the spirits of.","ex":"The femur has a clean break and so should heal easily."},"BREED":{"p":"/bɹiːd/","s":"n./v.","e":"[n.] All animals or plants of the same species or subspecies.\n[n.] A race or lineage; offspring or issue.\n[n.] A group of people with shared characteristics.\n[v.] To produce offspring sexually; to bear young.\n[v.] To give birth to; to be the native place of.\n[v.] Of animals, to mate.","ex":"a breed of animal"},"BRICK":{"p":"/bɹɪk/","s":"n./v./adj.","e":"[n.] A hardened rectangular block of mud, clay etc., used for building.\n[n.] Such hardened mud, clay, etc. considered collectively, as a building material.\n[n.] Something shaped like a brick.\n[v.] To build with bricks.\n[v.] To make into bricks.\n[v.] To hit someone or something with a brick.","ex":"This wall is made of bricks."},"BRIDGE":{"p":"/bɹɪd͡ʒ/","s":"n./v.","e":"[n.] A construction or natural feature that spans a divide.\n[n.] An arch or superstructure.\n[n.] A connection, real or abstract.\n[v.] To be or make a bridge over something.\n[v.] To span as if with a bridge.\n[v.] To transition from one piece or section of music to another without stopping.","ex":"With enough cable, we can bridge this gorge."},"BRIEF":{"p":"/bɹiːf/","s":"n./v./adj./adv.","e":"[n.] A writ summoning one to answer to any action.\n[n.] An answer to any action.\n[n.] A memorandum of points of fact or of law for use in conducting a case.\n[v.] To summarize a recent development to some person with decision-making power.\n[v.] To write a legal argument and submit it to a court.\n[adj.] Of short duration; happening quickly.","ex":"The U.S. president was briefed on the military coup and its implications on African stability."},"BRIGHT":{"p":"/bɹaɪt/","s":"n./adj.","e":"[n.] An artist's brush used in oil and acrylic painting with a long ferrule and a flat, somewhat tapering bristle head.\n[n.] Splendour; brightness\n[n.] A person with a naturalistic worldview with no supernatural or mystical elements.\n[adj.] Visually dazzling; luminous, lucent, clear, radiant; not dark.\n[adj.] Having a clear, quick intellect; intelligent.\n[adj.] Vivid, colourful, brilliant.","ex":"Could you please dim the light? It's far too bright."},"BRING":{"p":"/ˈbɹɪŋ/","s":"v.","e":"[v.] (ditransitive) To transport toward somebody/somewhere.\n[v.] To supply or contribute.\n[v.] To occasion or bring about.","ex":"Waiter, please bring me a single malt whiskey."},"BROAD":{"p":"/bɹɑd/","s":"n./adj.","e":"[n.] A shallow lake, one of a number of bodies of water in eastern Norfolk and Suffolk.\n[n.] A lathe tool for turning down the insides and bottoms of cylinders.\n[n.] A British gold coin worth 20 shillings, issued by the Commonwealth of England in 1656.\n[adj.] Wide in extent or scope.\n[adj.] Extended, in the sense of diffused; open; clear; full.\n[adj.] Having a large measure of any thing or quality; unlimited; unrestrained.","ex":"the broad expanse of ocean"},"BROKE":{"p":"/bɹəʊk/","s":"v./adj.","e":"[v.] To separate into two or more pieces, to fracture or crack, by a process that cannot easily be reversed for reassembly.\n[v.] To divide (something, often money) into smaller units.\n[v.] To cause (a person or animal) to lose spirit or will; to crush the spirits of.\n[adj.] Financially ruined, bankrupt.\n[adj.] Without any money, penniless.\n[adj.] Broken.","ex":"If the vase falls to the floor, it might break."},"BROOD":{"p":"/bɹuːd/","s":"n./v./adj.","e":"[n.] The young of certain animals, especially a group of young birds or fowl hatched at one time by the same mother.\n[n.] The young of any egg-laying creature, especially if produced at the same time.\n[n.] The eggs and larvae of social insects such as bees, ants and some wasps, especially when gathered together in special brood chambers or combs within the colony.\n[v.] To keep an egg warm to make it hatch.\n[v.] To protect (something that is gradually maturing); to foster.\n[v.] (typically with about or over) To dwell upon moodily and at length, mainly alone.","ex":"In some species of birds, both the mother and father brood the eggs."},"BROWN":{"p":"/bɹaʊn/","s":"n./v./adj.","e":"[n.] A colour like that of chocolate or coffee.\n[n.] One of the colour balls used in snooker, with a value of 4 points.\n[n.] Black tar heroin.\n[v.] To become brown.\n[v.] To cook something until it becomes brown.\n[v.] To tan.","ex":"The browns and greens in this painting give it a nice woodsy feel."},"BRUSH":{"p":"/bɹʌʃ/","s":"n./v.","e":"[n.] An implement consisting of multiple more or less flexible bristles or other filaments attached to a handle, used for any of various purposes including cleaning, painting, and arranging hair.\n[n.] The act of brushing something.\n[n.] A piece of conductive material, usually carbon, serving to maintain electrical contact between the stationary and rotating parts of a machine.\n[v.] To clean with a brush.\n[v.] To untangle or arrange with a brush.\n[v.] To apply with a brush.","ex":"She gave her hair a quick brush."},"BUDDY":{"p":"/bʌd.i/","s":"n./v.","e":"[n.] A friend or casual acquaintance.\n[n.] A partner for a particular activity.\n[n.] An informal and friendly address to a stranger; a friendly (or occasionally antagonistic) placeholder name for a person one does not know.\n[v.] To assign a buddy, or partner, to.","ex":"They have been buddies since they were in school."},"BUDGET":{"p":"/ˈbʌdʒ.ɪt/","s":"n./v./adj.","e":"[n.] The amount of money or resources earmarked for a particular institution, activity or time-frame.\n[n.] An itemized summary of intended expenditure; usually coupled with expected revenue.\n[n.] A wallet, purse or bag.\n[v.] To construct or draw up a budget.\n[v.] To provide funds, allow for in a budget.\n[v.] To plan for the use of in a budget.","ex":"Budgeting is even harder in times of recession"},"BUILD":{"p":"/bɪld/","s":"n./v.","e":"[n.] The physique of a human body; constitution or structure of a human body.\n[n.] Any of various versions of a software product as it is being developed for release to users.\n[n.] Any structure, such as a building, statue, pool or forest, created by the player.\n[v.] To form (something) by combining materials or parts.\n[v.] To develop or give form to (something) according to a plan or process.\n[v.] To increase or strengthen (something) by adding gradually to.","ex":"Rugby players are of sturdy build."},"BULKY":{"p":"/ˈbʌlki/","s":"adj.","e":"[adj.] Being large in size, mass, or volume.\n[adj.] Unwieldy.\n[adj.] Having excess body mass, especially muscle.","ex":""},"BURST":{"p":"/bɜːst/","s":"n./v.","e":"[n.] An act or instance of bursting.\n[n.] A sudden, often intense, expression, manifestation or display.\n[n.] A series of shots fired from an automatic firearm.\n[v.] To break from internal pressure.\n[v.] To cause to break from internal pressure.\n[v.] To cause to break by any means.","ex":"The bursts of the bombs could be heard miles away."},"BUTTON":{"p":"/ˈbʌtn̩/","s":"n.","e":"[n.] One who adjusts, especially for the insurance industry's employment title \"loss adjuster\" (or \"claims adjuster\" in the United States).\n[n.] A knob or disc that is passed through a loop or (buttonhole), serving as a fastener.\n[n.] A mechanical device meant to be pressed with a finger in order to open or close an electric circuit or to activate a mechanism.\n[n.] An on-screen control that can be selected as an activator of an attached function.\n[n.] In a violin-family instrument, the carved wooden plug which sits in the bottom block of the instrument.","ex":"April fastened the buttons of her overcoat to keep out the wind."},"CABAL":{"p":"/kəˈbæl/","s":"n./v.","e":"[n.] # A putative, secret organization of individuals gathered for a political purpose.\n[n.] A secret plot.\n[n.] An identifiable group within the tradition of Discordianism.\n[v.] To engage in the activities of a cabal.","ex":"The cabal is plotting to ruin the world."},"CABIN":{"p":"/ˈkæbɪn/","s":"n./v.","e":"[n.] A small dwelling characteristic of the frontier, especially when built from logs with simple tools and not constructed by professional builders, but by those who meant to live in it.\n[n.] A chalet or lodge, especially one that can hold large groups of people.\n[n.] A private room on a ship.\n[v.] To place in a cabin or other small space.\n[v.] (by extension) To limit the scope of.\n[v.] To live in, or as if in, a cabin; to lodge.","ex":"Abraham Lincoln was born in a log cabin."},"CABLE":{"p":"/keɪ.bl/","s":"n./v.","e":"[n.] (material) A long object used to make a physical connection.\n[n.] (communications) A system for transmitting television or Internet services over a network of coaxial or fibreoptic cables.\n[n.] A telegram, notably when sent by (submarine) telegraph cable.\n[v.] To provide with cable(s)\n[v.] To fasten (as if) with cable(s)\n[v.] To wrap wires to form a cable","ex":"I tried to watch the movie last night but my cable was out."},"CAFE":{"p":"/ˈkæfeɪ/","s":"n.","e":"[n.] A convenience store, originally one that sold coffee and similar basic items.\n[n.] A coffee shop; an establishment selling coffee and sometimes other non-alcoholic beverages, simple meals or snacks, with a facility to consume them on the premises.\n[n.] A small restaurant of any genre.","ex":"1982, Joni Mitchell, Chinese Café / Unchained Melody (song)"},"CAGEY":{"p":"/ˈkeɪdʒi/","s":"adj.","e":"[adj.] Wary, careful, shrewd.\n[adj.] Uncommunicative; unwilling or hesitant to give information.","ex":""},"CAIRN":{"p":"/kɛən/","s":"n.","e":"[n.] A rounded or conical heap of stones erected by early inhabitants of the British Isles, apparently as a sepulchral monument.\n[n.] A pile of stones heaped up as a landmark, to guide travelers on land or at sea, or to arrest attention, as in surveying, or in leaving traces of an exploring party, etc.\n[n.] A cairn terrier.","ex":""},"CALL":{"p":"/kɔːɫ/","s":"n./v.","e":"[n.] A telephone conversation.\n[n.] A short visit, usually for social purposes.\n[n.] A visit by a ship or boat to a port.\n[v.] (heading) To use one's voice.\n[v.] (heading) To visit.\n[v.] (heading) To name, identify or describe.","ex":"I received several calls today."},"CALM":{"p":"/kam/","s":"n./v./adj.","e":"[n.] (in a person) The state of being calm; peacefulness; absence of worry, anger, fear or other strong negative emotion.\n[n.] (in a place or situation) The state of being calm; absence of noise and disturbance.\n[n.] A period of time without wind.\n[v.] To make calm.\n[v.] To become calm.\n[adj.] (of a person) Peaceful, quiet, especially free from anger and anxiety.","ex":"to calm a crying baby"},"CAME":{"p":"/keɪm/","s":"prep./v.","e":"[prep.] Used to indicate that the following event, period, or change in state occurred in the past, after a time of waiting, enduring, or anticipation\n[v.] To move from further away to nearer to.\n[v.] To arrive.\n[v.] To appear, to manifest itself.\n[v.] To have an orgasm, to feel the sensation of an orgasm.\n[v.] To ejaculate.","ex":"She’ll be coming ’round the mountain when she comes [...]"},"CAMEL":{"p":"/ˈkæməl/","s":"n./adj.","e":"[n.] A beast of burden, much used in desert areas, of the genus Camelus.\n[n.] A light brownish color, like that of a camel (also called camel brown).\n[n.] Loaded vessels lashed tightly, one on each side of another vessel, and then emptied to reduce the draught of the ship in the middle.\n[adj.] Of a light brown color like that of a camel.","ex":""},"CAMEO":{"p":"/ˈkæm.iː.əʊ/","s":"n./v.","e":"[n.] A piece of jewelry, etc., carved in relief.\n[n.] A single very brief appearance, especially by a prominent celebrity in a movie or song.\n[v.] To appear in a cameo role.","ex":"Famous comic book writer Stan Lee had a cameo in the Spider-Man movie. He was on screen for perhaps ten seconds, but aficionados distinctly remember him."},"CAMERA":{"p":"/ˈkæməɹə/","s":"n.","e":"[n.] A device for taking still or moving pictures or photographs.\n[n.] The viewpoint in a three-dimensional game or simulation.\n[n.] A vaulted room.","ex":""},"CAMP":{"p":"[kʰɛəmp]","s":"n./v.","e":"[n.] An outdoor place acting as temporary accommodation in tents or other temporary structures.\n[n.] An organised event, often taking place in tents or temporary accommodation.\n[n.] A base of a military group, not necessarily temporary.\n[v.] To live in a tent or similar temporary accommodation.\n[v.] To set up a camp.\n[v.] To afford rest or lodging for.","ex":"We're planning to camp in the field until Sunday."},"CANAL":{"p":"/kəˈnɛl/","s":"n./v.","e":"[n.] An artificial waterway or artificially improved river used for travel, shipping, or irrigation.\n[n.] A tubular channel within the body.\n[n.] One of the faint, hazy markings resembling straight lines on early telescopic images of the surface of Mars.\n[v.] To dig an artificial waterway in or to (a place), especially for drainage\n[v.] To travel along a canal by boat","ex":""},"CANCER":{"p":"/ˈkæːnsə/","s":"n.","e":"[n.] A disease in which the cells of a tissue undergo uncontrolled (and often rapid) proliferation.\n[n.] Something damaging that spreads throughout something else.","ex":""},"CANDY":{"p":"/ˈkændi/","s":"n./v.","e":"[n.] Edible, sweet-tasting confectionery containing sugar, or sometimes artificial sweeteners, and often flavored with fruit, chocolate, nuts, herbs and spices, or artificial flavors.\n[n.] A piece of confectionery of this kind.\n[n.] (slang, chiefly US) crack cocaine.\n[v.] To cook in, or coat with, sugar syrup.\n[v.] To have sugar crystals form in or on.\n[v.] To be formed into candy; to solidify in a candylike form or mass.","ex":"Fruits preserved in sugar candy after a time."},"CANOE":{"p":"/kəˈnuː/","s":"n./v.","e":"[n.] A small long and narrow boat, propelled by one or more people (depending on the size of canoe), using single-bladed paddles. The paddlers face in the direction of travel, in either a seated position, or kneeling on the bottom of the boat. Canoes are open on top, and pointed at both ends.\n[n.] An oversize, usually older, luxury car.\n[n.] Any of the deflectors positioned around a roulette wheel, shaped like upside-down boats.\n[v.] To ride or paddle a canoe.","ex":""},"CANON":{"p":"/ˈkæn.ən/","s":"n.","e":"[n.] A generally accepted principle; a rule.\n[n.] A group of literary works that are generally accepted as representing a field.\n[n.] The works of a writer that have been accepted as authentic.","ex":"The trial must proceed according to the canons of law."},"CAPER":{"p":"/ˈkeɪpə/","s":"n./v.","e":"[n.] A playful leap or jump.\n[n.] A jump while dancing.\n[n.] A prank or practical joke.\n[v.] To leap or jump about in a sprightly or playful manner.\n[v.] To jump as part of a dance.\n[v.] To engage in playful behaviour.","ex":""},"CARGO":{"p":"/ˈkɑːɡəʊ/","s":"n.","e":"[n.] Freight carried by a ship, aircraft, or motor vehicle.\n[n.] (Papua New Guinea) Western material goods.","ex":""},"CAROL":{"p":"","s":"n.","e":"[n.] A small closet or enclosure built against a window on the inner side, to sit in for study.\n[n.] Hence, a partially partitioned space for studying or reading, often in a library.","ex":"He was busy writing his report in a small library carrel."},"CARRY":{"p":"/ˈkæ.ɹi/","s":"n./v.","e":"[n.] A manner of transporting or lifting something; the grip or position in which something is carried.\n[n.] A tract of land over which boats or goods are carried between two bodies of navigable water; a portage.\n[n.] The bit or digit that is carried in an addition operation.\n[v.] To lift (something) and take it to another place; to transport (something) by lifting.\n[v.] To transfer from one place (such as a country, book, or column) to another.\n[v.] To convey by extension or continuance; to extend.","ex":"Adjust your carry from time to time so that you don't tire too quickly."},"CASE":{"p":"/keɪs/","s":"n./v.","e":"[n.] An actual event, situation, or fact.\n[n.] A given condition or state.\n[n.] A piece of work, specifically defined within a profession.\n[v.] To propose hypothetical cases.","ex":"For a change, in this case, he was telling the truth."},"CASH":{"p":"/kæʃ/","s":"n./v./adj.","e":"[n.] Money in the form of notes/bills and coins, as opposed to cheques/checks or electronic transactions.\n[n.] Liquid assets, money that can be traded quickly, as distinct from assets that are invested and cannot be easily exchanged.\n[n.] Money.\n[v.] To exchange (a check/cheque) for money in the form of notes/bills.\n[v.] To obtain a payout from a tournament.\n[adj.] Great; excellent; cool.","ex":"After you bounced those checks last time, they want to be paid in cash."},"CATCH":{"p":"/kæt͡ʃ/","s":"n./v.","e":"[n.] The act of seizing or capturing.\n[n.] The act of catching an object in motion, especially a ball.\n[n.] The act of noticing, understanding or hearing.\n[v.] (heading) To capture, overtake.\n[v.] (heading) To seize hold of.\n[v.] (heading) To intercept.","ex":"The catch of the perpetrator was the product of a year of police work."},"CATER":{"p":"/ˈkeɪtə/","s":"n./v.","e":"[n.] Caterer\n[v.] To provide, particularly:\n[n.] A person employed to obtain and maintain the storage of provisions, especially food.\n[n.] A person or company hired to provide and serve food, usually for a large group and at a location separate from where the food is prepared.\n[n.] Someone who supplies what is needed, especially food.\n[n.] An officer who provided provisions for the king's household.","ex":"The merchants are the purveyors of fine selections."},"CEASE":{"p":"/siːs/","s":"n./v.","e":"[n.] Cessation; extinction (see without cease).\n[v.] To stop.\n[v.] To stop doing (something).\n[v.] To be wanting; to fail; to pass away.","ex":"And with that, his twitching ceased."},"CEDAR":{"p":"/ˈsiː.də/","s":"n.","e":"[n.] A coniferous tree of the genus Cedrus in the family Pinaceae.\n[n.] A coniferous tree of the family Cupressaceae, especially of the genera Juniperus, Cupressus, Calocedrus, or Thuja.\n[n.] A flowering tree of the family Meliaceae, especially of the genera Cedrela or Toona.","ex":""},"CHAFE":{"p":"/tʃeɪf/","s":"n./v.","e":"[n.] Heat excited by friction.\n[n.] Injury or wear caused by friction.\n[n.] Vexation; irritation of mind; rage.\n[v.] To excite heat in by friction; to rub in order to stimulate and make warm.\n[v.] To excite passion or anger in; to fret; to irritate.\n[v.] To fret and wear by rubbing.","ex":"to chafe a cable"},"CHAIN":{"p":"/ˈt͡ʃeɪn/","s":"n./v.","e":"[n.] A series of interconnected rings or links usually made of metal.\n[n.] A series of interconnected things.\n[n.] A series of stores or businesses with the same brand name.\n[v.] To fasten something with a chain.\n[v.] To link multiple items together.\n[v.] To secure someone with fetters.","ex":"He wore a gold chain around the neck."},"CHAIR":{"p":"/t͡ʃɛə(ɹ)/","s":"n./v.","e":"[n.] An item of furniture used to sit on or in, comprising a seat, legs, back, and sometimes arm rests, for use by one person. Compare stool, couch, sofa, settee, loveseat and bench.\n[n.] The seating position of a particular musician in an orchestra.\n[n.] An iron block used on railways to support the rails and secure them to the sleepers, and similar devices.\n[v.] To act as chairperson at; to preside over.\n[v.] To carry in a seated position upon one's shoulders, especially in celebration or victory.\n[v.] To award a chair to (a winning poet) at a Welsh eisteddfod.","ex":"All I need to weather a snowstorm is hot coffee, a warm fire, a good book and a comfortable chair."},"CHAOS":{"p":"/ˈkeɪ.ɒs/","s":"n.","e":"[n.] The unordered state of matter in classical accounts of cosmogony.\n[n.] Any state of disorder; a confused or amorphous mixture or conglomeration.\n[n.] A behaviour of iterative non-linear systems in which arbitrarily small variations in initial conditions become magnified over time.","ex":"After the earthquake, the local hospital was in chaos"},"CHARM":{"p":"/tʃɑːm/","s":"n./v.","e":"[n.] An object, act or words believed to have magic power (usually carries a positive connotation).\n[n.] The ability to persuade, delight or arouse admiration; often constructed in the plural.\n[n.] A small trinket on a bracelet or chain, etc., traditionally supposed to confer luck upon the wearer.\n[v.] To seduce, persuade or fascinate someone or something.\n[v.] To use a magical charm upon; to subdue, control, or summon by incantation or supernatural influence.\n[v.] To protect with, or make invulnerable by, spells, charms, or supernatural influences.","ex":"It works like a charm."},"CHAT":{"p":"/tʃæt/","s":"n./v.","e":"[n.] Informal conversation.\n[n.] A conversation to stop an argument or settle situations.\n[n.] (totum pro parte, typically with definite article) The entirety of users in a chatroom or a single member thereof.\n[v.] To be engaged in informal conversation.\n[v.] To talk more than a few words.\n[v.] To talk of; to discuss.","ex":"The Chat just made a joke about my skills."},"CHEAP":{"p":"/t͡ʃiːp/","s":"n./v./adj./adv.","e":"[n.] Trade; traffic; chaffer; chaffering.\n[n.] A market; marketplace.\n[n.] Price.\n[v.] To trade; traffic; bargain; chaffer; ask the price of goods; cheapen goods.\n[v.] To bargain for; chaffer for; ask the price of; offer a price for; cheapen.\n[v.] To buy; purchase.","ex":""},"CHEAT":{"p":"/tʃiːt/","s":"v.","e":"[v.] To violate rules in order to gain advantage from a situation.\n[v.] To be unfaithful to one's spouse or partner.\n[v.] To manage to avoid something even though it seemed unlikely.","ex":"My brother flunked biology because he cheated on his mid-term."},"CHECK":{"p":"/t͡ʃɛk/","s":"n.","e":"[n.] A situation in which the king is directly threatened by an opposing piece.\n[n.] An inspection or examination.\n[n.] A control; a limit or stop.","ex":"I don't know if she will be there, but it's worth a check."},"CHIEF":{"p":"/tʃiːf/","s":"n./v./adj.","e":"[n.] A leader or head of a group of people, organisation, etc.\n[n.] The top part of a shield or escutcheon; more specifically, an ordinary consisting of the upper part of the field cut off by a horizontal line, generally occupying the top third.\n[n.] The principal part or top of anything.\n[v.] To smoke cannabis.\n[adj.] Primary; principal.\n[adj.] Intimate, friendly.","ex":"All firefighters report to the fire chief."},"CHIP":{"p":"/tʃɪp/","s":"n.","e":"[n.] A small piece broken from a larger piece of solid material.\n[n.] A damaged area of a surface where a small piece has been broken off.\n[n.] (games) A token used in place of cash.","ex":"This cup has a chip in it."},"CHOCK":{"p":"/tʃɒk/","s":"n./v./adv.","e":"[n.] Any object used as a wedge or filler, especially when placed behind a wheel to prevent it from rolling.\n[n.] Any fitting or fixture used to restrict movement, especially movement of a line; traditionally was a fixture near a bulwark with two horns pointing towards each other, with a gap between where the line can be inserted.\n[v.] To stop or fasten, as with a wedge, or block; to scotch.\n[v.] To fill up, as a cavity.\n[v.] To insert a line in a chock.\n[adv.] Entirely; quite.","ex":""},"CHORE":{"p":"/tʃɔː/","s":"n./v.","e":"[n.] A task, especially a difficult, unpleasant, or routine one.\n[v.] To do chores.","ex":"Washing dishes is a chore, but we cannot just stop eating."},"CIRCA":{"p":"/ˈsɜːkə/","s":"prep.","e":"[prep.] Approximately, about, around (typically in relation to time)","ex":"Julius Caesar visited this area circa 50 BC."},"CLEAR":{"p":"/klɪə(ɹ)/","s":"n./v./adj./adv.","e":"[n.] Full extent; distance between extreme limits; especially; the distance between the nearest surfaces of two bodies, or the space between walls.\n[n.] The completion of a stage or challenge, or of the whole game.\n[n.] A person who is free from the influence of engrams.\n[v.] To remove obstructions, impediments or other unwanted items from.\n[v.] To remove (items or material) so as to leave something unobstructed or open.\n[v.] To become free from obstruction or obscurement; to become transparent.","ex":"a room ten feet square in the clear"},"COAST":{"p":"/kəʊst/","s":"n./v.","e":"[n.] The edge of the land where it meets an ocean, sea, gulf, bay, or large lake.\n[n.] The side or edge of something.\n[n.] A region of land; a district or country.\n[v.] To glide along without adding energy; to allow a vehicle to continue moving forward after disengaging the engine or ceasing to apply motive power.\n[v.] To sail along a coast.\n[v.] To make a minimal effort; to continue to do something in a routine way, without initiative or effort.","ex":"The rocky coast of Maine has few beaches."},"COCOA":{"p":"/ˈkəʊ.kəʊ/","s":"n./adj.","e":"[n.] The dried and partially fermented fatty seeds of the cacao tree from which chocolate is made.\n[n.] An unsweetened brown powder made from roasted, ground cocoa beans, used in making chocolate, and in cooking.\n[n.] A hot drink made with milk, cocoa powder, and sugar.\n[adj.] Of a light to medium brown colour, like that of cocoa powder.","ex":"Do you like cocoa?"},"COLIC":{"p":"/ˈkɒl.ɪk/","s":"n./adj.","e":"[n.] Severe pains that grip the abdomen or the disease that causes such pains (due to intestinal or bowel-related problems).\n[n.] A medicinal plant used to relieve such symptoms.\n[adj.] Relating to the colon; colonic.","ex":""},"COLOR":{"p":"/ˈkʌl.ə(ɹ)/","s":"n./v./adj.","e":"[n.] The spectral composition of visible light\n[n.] A subset thereof:\n[n.] A paint.\n[v.] To give something color.\n[v.] To apply colors to the areas within the boundaries of a line drawing using colored markers or crayons.\n[v.] (of a person or their face) To become red through increased blood flow.","ex":"Humans and birds can perceive color."},"COPSE":{"p":"/kɒps/","s":"n./v.","e":"[n.] A thicket of small trees or shrubs.\n[v.] To trim or cut.\n[v.] To plant and preserve.","ex":""},"CORAL":{"p":"/ˈkɒɹəl/","s":"n./adj.","e":"[n.] A hard substance made of the limestone skeletons of marine polyps.\n[n.] A colony of marine polyps.\n[n.] A somewhat yellowish pink colour, the colour of red coral.\n[adj.] Made of coral.\n[adj.] Having the yellowish pink colour of coral.","ex":""},"CORD":{"p":"/kɔːd/","s":"n./v.","e":"[n.] A harmonic set of three or more notes that is heard as if sounding simultaneously.\n[n.] A straight line between two points of a curve.\n[n.] A horizontal member of a truss.\n[n.] A long, thin, flexible length of twisted yarns (strands) of fiber (rope, for example); (uncountable) such a length of twisted strands considered as a commodity.\n[n.] A small flexible electrical conductor composed of wires insulated separately or in bundles and assembled together usually with an outer cover; the electrical cord of a lamp, sweeper ((US) vacuum cleaner), or other appliance.\n[n.] A unit of measurement for firewood, equal to 128 cubic feet (4 × 4 × 8 feet), composed of logs and/or split logs four feet long and none over eight inches diameter. It is usually seen as a stack four feet high by eight feet long.","ex":"He looped some cord around his fingers."},"CORNY":{"p":"/ˈkɔːni/","s":"adj.","e":"[adj.] Boring and unoriginal.\n[adj.] Hackneyed or excessively sentimental.\n[adj.] Producing corn or grain; furnished with grains of corn.","ex":"The duct tape and wire were a pretty corny solution."},"COUCH":{"p":"/kaʊtʃ/","s":"n.","e":"[n.] Couch grass, a species of persistent grass, Elymus repens, usually considered a weed.","ex":""},"COUGH":{"p":"/kɑf/","s":"n./v.","e":"[n.] A sudden, usually noisy expulsion of air from the lungs, often involuntary.\n[n.] A condition that causes one to cough; a tendency to cough.\n[n.] Used to focus attention on a following utterance, often a euphemism or an attribution of blame\n[v.] To push air from the lungs in a quick, noisy explosion.\n[v.] (sometimes followed by \"up\") To force something out of the throat or lungs by coughing.\n[v.] To make a noise like a cough.","ex":"Behind me, I heard a distinct, dry cough."},"COUNT":{"p":"/kaʊnt/","s":"n./v./adj.","e":"[n.] The act of counting or tallying a quantity.\n[n.] The result of a tally that reveals the number of items in a set; a quantity counted.\n[n.] A countdown.\n[v.] To recite numbers in sequence.\n[v.] To determine the number (of objects in a group).\n[v.] To be of significance; to matter.","ex":"Give the chairs a quick count to check if we have enough."},"COURT":{"p":"/kɔːt/","s":"n./v.","e":"[n.] An enclosed space; a courtyard; an uncovered area shut in by the walls of a building, or by different buildings; also, a space opening from a street and nearly surrounded by houses; a blind alley.\n[n.] (social) Royal society.\n[n.] Attention directed to a person in power; behaviour designed to gain favor; politeness of manner; civility towards someone\n[v.] To seek to achieve or win.\n[v.] To risk (a consequence, usually negative).\n[v.] To try to win a commitment to marry from.","ex":"The girls were playing in the court."},"COVEN":{"p":"/ˈkʌ.vən/","s":"n.","e":"[n.] A formal group or assembly of witches.\n[n.] A family, group or assembly of vampires.\n[n.] A clique that shares common interests or activities.","ex":""},"COVER":{"p":"/ˈkʌvə/","s":"n./v./adj.","e":"[n.] A lid.\n[n.] Area or situation which screens a person or thing from view.\n[n.] The front and back of a book, magazine, CD package, etc.\n[v.] To place something over or upon, as to conceal or protect.\n[v.] To be over or upon, as to conceal or protect.\n[v.] To be upon all of, so as to completely conceal.","ex":"The soldiers took cover behind a ruined building."},"CRACK":{"p":"/kɹæk/","s":"n./v.","e":"[n.] A thin and usually jagged space opened in a previously solid material.\n[n.] A narrow opening.\n[n.] A sharply humorous comment; a wisecrack.\n[v.] To form cracks.\n[v.] To break apart under pressure.\n[v.] To become debilitated by psychological pressure.","ex":"A large crack had formed in the roadway."},"CRAFT":{"p":"/kɹɑːft/","s":"n./v.","e":"[n.] Strength; power; might; force .\n[n.] Intellectual power; skill; art.\n[n.] (obsolete in the general sense) A work or product of art .\n[v.] To make by hand and with much skill.\n[v.] To construct, develop something (like a skilled craftsman).\n[v.] To combine multiple items to form a new item, such as armour or medicine.","ex":"state crafting; the process of crafting global policing"},"CRAMP":{"p":"/kɹæmp/","s":"n./v./adj.","e":"[n.] A painful contraction of a muscle which cannot be controlled.\n[n.] That which confines or contracts; a restraint; a shackle; a hindrance.\n[n.] A clamp for carpentry or masonry.\n[v.] (of a muscle) To contract painfully and uncontrollably.\n[v.] To affect with cramps or spasms.\n[v.] To prohibit movement or expression of.","ex":"You're cramping my style."},"CRANE":{"p":"/kɹeɪn/","s":"n./v.","e":"[n.] Any bird of the family Gruidae, large birds with long legs and a long neck which is extended during flight.\n[n.] Ardea herodias, the great blue heron.\n[n.] A mechanical lifting machine or device, often used for lifting heavy loads for industrial or construction purposes.\n[v.] To extend (one's neck).\n[v.] To raise or lower with, or as if with, a crane.\n[v.] To pull up before a jump.","ex":""},"CRANK":{"p":"/kɹæŋk/","s":"n./v./adj.","e":"[n.] A bent piece of an axle or shaft, or an attached arm perpendicular, or nearly so, to the end of a shaft or wheel, used to impart a rotation to a wheel or other mechanical device; also used to change circular into reciprocating motion, or reciprocating into circular motion.\n[n.] The act of converting power into motion, by turning a crankshaft.\n[n.] Any bend, turn, or winding, as of a passage.\n[v.] To turn by means of a crank.\n[v.] To turn a crank.\n[v.] (of a crank or similar) To turn.","ex":"I grind my coffee by hand with a coffee grinder with a crank handle."},"CRASH":{"p":"/kɹæʃ/","s":"n./v./adj.","e":"[n.] A sudden, intense, loud sound, as made for example by cymbals.\n[n.] An automobile, airplane, or other vehicle accident.\n[n.] A malfunction of computer software or hardware which causes it to shut down or become partially or totally inoperable.\n[v.] To collide with something destructively, fall or come down violently.\n[v.] To severely damage or destroy something by causing it to collide with something else.\n[v.] (via gatecrash) To attend a social event without invitation, usually with unfavorable intentions.","ex":"After the lightning came the crash of thunder."},"CRASS":{"p":"/kɹæs/","s":"adj.","e":"[adj.] Coarse; crude; unrefined or insensitive; lacking discrimination\n[adj.] Materialistic\n[adj.] Dense","ex":""},"CRATE":{"p":"/kɹeɪt/","s":"n./v.","e":"[n.] A large open box or basket, used especially to transport fragile goods.\n[n.] (mildly) A vehicle (car, aircraft, spacecraft, etc.) seen as unreliable.\n[n.] In the Rust programming language, a binary or library.\n[v.] To put into a crate.\n[v.] To keep in a crate.","ex":""},"CRAVE":{"p":"/kɹeɪv/","s":"n./v.","e":"[n.] A formal application to a court to make a particular order.\n[v.] To desire strongly, so as to satisfy an appetite; to long or yearn for.\n[v.] To ask for earnestly; to beg; to claim.\n[v.] To call for; to require as a course of action.","ex":"to crave after wealth"},"CRAWL":{"p":"/kɹɔl/","s":"n./v.","e":"[n.] The act of moving slowly on hands and knees etc, or with frequent stops.\n[n.] A rapid swimming stroke with alternate overarm strokes and a fluttering kick.\n[n.] A very slow pace.\n[v.] To creep; to move slowly on hands and knees, or by dragging the body along the ground.\n[v.] To move forward slowly, with frequent stops.\n[v.] To act in a servile manner.","ex":"My computer has slowed down to a crawl since I installed that software package."},"CRAZE":{"p":"/kɹeɪz/","s":"n./v.","e":"[n.] Craziness; insanity.\n[n.] A strong habitual desire or fancy.\n[n.] A temporary passion or infatuation, as for some new amusement, pursuit, or fashion; a fad\n[v.] To weaken; to impair; to render decrepit.\n[v.] To derange the intellect of; to render insane.\n[v.] To be crazed, or to act or appear as one that is crazed; to rave; to become insane.","ex":""},"CRAZY":{"p":"/ˈkɹeɪzi/","s":"n./adj./adv.","e":"[n.] An insane or eccentric person; a crackpot.\n[n.] Eccentric behaviour; lunacy.\n[adj.] Flawed or damaged; unsound, liable to break apart; ramshackle.\n[adj.] Sickly, frail; diseased.\n[adj.] Of unsound mind; insane, demented.\n[adv.] Very, extremely.","ex":"His ideas were both frightening and crazy."},"CREAK":{"p":"/kɹiːk/","s":"n./v.","e":"[n.] The sound produced by anything that creaks; a creaking.\n[v.] To make a prolonged sharp grating or squeaking sound, as by the friction of hard substances.\n[v.] To produce a creaking sound with.\n[v.] To suffer from strain or old age.","ex":""},"CREAM":{"p":"/kɹiːm/","s":"n./v./adj.","e":"[n.] The butterfat/milkfat part of milk which rises to the top; this part when separated from the remainder.\n[n.] A yellowish white colour; the colour of cream.\n[n.] Frosting, custard, creamer or another substance similar to the oily part of milk or to whipped cream.\n[v.] To puree, to blend with a liquifying process.\n[v.] To turn a yellowish white colour; to give something the color of cream.\n[v.] To obliterate, to defeat decisively.","ex":"Take 100 ml of cream and 50 grams of sugar…"},"CREDO":{"p":"/ˈkɹidoʊ/","s":"n.","e":"[n.] A belief system.\n[n.] The liturgical creed (usually the Nicene Creed), or a musical arrangement of it for use in church services.","ex":"Credo III is so beautiful!"},"CREED":{"p":"/kɹiːd/","s":"n./v.","e":"[n.] That which is believed; accepted doctrine, especially religious doctrine; a particular set of beliefs; any summary of principles or opinions professed or adhered to.\n[n.] (specifically) A reading or statement of belief that summarizes the faith it represents; a confession of faith for public use, especially one which is brief and comprehensive.\n[n.] The fact of believing; belief, faith.\n[v.] (only survives in \"creeded\") To believe; to credit.\n[v.] To provide with a creed.","ex":"A creed is a manifesto of religious or spiritual beliefs"},"CREEK":{"p":"/kɹiːk/","s":"n.","e":"[n.] A small inlet or bay, often saltwater, narrower and extending farther into the land than a cove; a recess in the shore of the sea, or of a river; the inner part of a port that is used as a dock for small boats.\n[n.] A stream of water (often freshwater) smaller than a river and larger than a brook.\n[n.] Any turn or winding.","ex":""},"CREEP":{"p":"/kɹiːp/","s":"v.","e":"[v.] To move slowly with the abdomen close to the ground.\n[v.] Of plants, to grow across a surface rather than upwards.\n[v.] To move slowly and quietly in a particular direction.","ex":""},"CREPE":{"p":"/kɹɛp/","s":"n./v.","e":"[n.] A flat round pancake-like pastry from Lower Brittany, made with wheat.\n[n.] A soft thin light fabric with a crinkled surface.\n[n.] Crepe paper; thin, crinkled tissue paper.\n[v.] To crease (paper) in such a way to make it look like crepe paper\n[v.] To frizz (the hair).","ex":""},"CREPT":{"p":"/ˈkɹɛpt/","s":"v.","e":"[v.] To move slowly with the abdomen close to the ground.\n[v.] Of plants, to grow across a surface rather than upwards.\n[v.] To move slowly and quietly in a particular direction.","ex":""},"CREST":{"p":"/kɹɛst/","s":"n./v.","e":"[n.] The summit of a hill or mountain ridge.\n[n.] A tuft, or other natural ornament, growing on an animal's head, for example the comb of a cockerel, the swelling on the head of a snake, the lengthened feathers of the crown or nape of bird, etc.\n[n.] The plume of feathers, or other decoration, worn on or displayed on a helmet; the distinctive ornament of a helmet.\n[v.] Particularly with reference to waves, to reach a peak.\n[v.] To reach the crest of (a hill or mountain)\n[v.] To furnish with, or surmount as, a crest; to serve as a crest for.","ex":""},"CREW":{"p":"","s":"v.","e":"[v.] To make the shrill sound characteristic of a rooster; to make a sound in this manner, either in gaiety, joy, pleasure, or defiance.\n[v.] To shout in exultation or defiance; to brag.\n[v.] To test the reed of a double reed instrument by placing the reed alone in the mouth and blowing it.","ex":"He’s been crowing all day about winning the game of cards."},"CRICK":{"p":"","s":"n./v.","e":"[n.] A painful muscular cramp or spasm of some part of the body, as of the neck or back, making it difficult to move the part affected. (Compare catch.)\n[n.] A small jackscrew.\n[v.] To develop a crick (cramp, spasm).\n[v.] To cause to develop a crick; to create a crick in.\n[v.] To twist, bend, or contort, especially in a way that produces strain.","ex":""},"CRIED":{"p":"/kɹaɪd/","s":"v.","e":"[v.] To shed tears; to weep.\n[v.] To utter loudly; to call out; to declare publicly.\n[v.] To shout, scream, yell.","ex":"That sad movie always makes me cry."},"CRIME":{"p":"/kɹaɪm/","s":"n./v.","e":"[n.] A specific act committed in violation of the law.\n[n.] Any great sin or wickedness; iniquity.\n[n.] That which occasions crime.\n[v.] To subject to disciplinary punishment.\n[v.] To commit crime(s).","ex":""},"CRISP":{"p":"/kɹɪsp/","s":"n./v./adj.","e":"[n.] A thin slice of fried potato eaten as a snack.\n[n.] A baked dessert made with fruit and crumb topping\n[n.] Anything baked or fried and eaten as a snack\n[v.] To make crisp.\n[v.] To become crisp.\n[v.] To cause to curl or wrinkle (of the leaves or petals of plants, for example); to form into ringlets or tight curls (of hair).","ex":"kale crisps"},"CROAK":{"p":"/kɹəʊk/","s":"n./v.","e":"[n.] A faint, harsh sound made in the throat.\n[n.] The cry of a frog or toad. (see also ribbit)\n[n.] The harsh cry of various birds, such as the raven or corncrake, or other creatures.\n[v.] To make a croak.\n[v.] To utter in a low, hoarse voice.\n[v.] (of a frog, toad, raven, or various other birds or animals) To make its cry.","ex":""},"CRONE":{"p":"/kɹəʊn/","s":"n.","e":"[n.] An old woman.\n[n.] An archetypal figure, a Wise Woman.\n[n.] An ugly, evil-looking, or frightening old woman; a hag.","ex":""},"CRONY":{"p":"/ˈkɹəʊni/","s":"n.","e":"[n.] (originally Cambridge University) Close friend.\n[n.] Trusted companion or partner in a criminal organization.","ex":""},"CROOK":{"p":"/kɹʊk/","s":"n./v.","e":"[n.] A bend; turn; curve; curvature; a flexure.\n[n.] A bending of the knee; a genuflection.\n[n.] A bent or curved part; a curving piece or portion (of anything).\n[v.] To bend, or form into a hook.\n[v.] To become bent or hooked.\n[v.] To turn from the path of rectitude; to pervert; to misapply; to twist.","ex":"She held the baby in the crook of her arm."},"CROSS":{"p":"/kɹɑs/","s":"n./v./adj./prep.","e":"[n.] A geometrical figure consisting of two straight lines or bars intersecting each other such that at least one of them is bisected by the other.\n[n.] Any geometric figure having this or a similar shape, such as a cross of Lorraine or a Maltese cross.\n[n.] A wooden post with a perpendicular beam attached and used (especially in the Roman Empire) to execute criminals (by crucifixion).\n[v.] To make or form a cross.\n[v.] To move relatively.\n[v.] (social) To oppose.","ex":"Put a cross for a wrong answer and a tick for a right one."},"CROUP":{"p":"/kɹuːp/","s":"n./v.","e":"[n.] An infectious illness of the larynx, especially in young children, causing respiratory difficulty.\n[v.] (obsolete outside dialectal) To croak, make a hoarse noise.","ex":""},"CROWD":{"p":"/kɹaʊd/","s":"n./v.","e":"[n.] A group of people congregated or collected into a close body without order.\n[n.] Several things collected or closely pressed together; also, some things adjacent to each other.\n[n.] (with definite article) The so-called lower orders of people; the populace, vulgar.\n[v.] To press forward; to advance by pushing.\n[v.] To press together or collect in numbers\n[v.] To press or drive together, especially into a small space; to cram.","ex":"After the movie let out, a crowd of people pushed through the exit doors."},"CROWN":{"p":"/kɹaʊn/","s":"n./v./adj.","e":"[n.] A royal, imperial or princely headdress; a diadem.\n[n.] A wreath or band for the head, especially one given as reward of victory or a mark of honor.\n[n.] (by extension) Any reward of victory or mark of honor.\n[v.] To place a crown on the head of.\n[v.] To formally declare (someone) a king, queen, emperor, etc.\n[v.] To bestow something upon as a mark of honour, dignity, or recompense; to adorn; to dignify.","ex":"the martyr's crown"},"CRUDE":{"p":"/kɹʉd/","s":"n./adj.","e":"[n.] Any substance in its natural state.\n[n.] Crude oil.\n[adj.] In a natural, untreated state.\n[adj.] Characterized by simplicity, especially something not carefully or expertly made.\n[adj.] Lacking concealing elements.","ex":"crude oil"},"CRUEL":{"p":"/kɹuː(ə)l/","s":"v./adj./adv.","e":"[v.] To spoil or ruin (one's chance of success)\n[v.] To violently provoke (a child) in the belief that this will make them more assertive.\n[adj.] Intentionally causing or reveling in pain and suffering; merciless, heartless.\n[adj.] Harsh; severe.\n[adj.] Cool; awesome; neat.\n[adv.] To a great degree; terribly.","ex":"The supervisor was very cruel to Josh, as he would always give Josh the hardest, most degrading work he could find."},"CRUMB":{"p":"/kɹʌm/","s":"n./v.","e":"[n.] A small piece which breaks off from baked food (such as cake, biscuit or bread).\n[n.] A small piece of other material, such as rubber.\n[n.] A bit, small amount.\n[v.] To cover with crumbs.\n[v.] To break into crumbs or small pieces with the fingers; to crumble.","ex":"The pigeons were happily pecking at crumbs of bread on the ground."},"CRUSH":{"p":"/kɹʌʃ/","s":"n./v.","e":"[n.] A violent collision or compression; a crash; destruction; ruin.\n[n.] Violent pressure, as of a moving crowd.\n[n.] A crowd that produces uncomfortable pressure.\n[v.] To press between two hard objects; to squeeze so as to alter the natural shape or integrity of it, or to force together into a mass.\n[v.] To reduce to fine particles by pounding or grinding\n[v.] To overwhelm by pressure or weight.","ex":"a crush at a reception"},"CRUST":{"p":"/kɹʌst/","s":"n./v.","e":"[n.] A more solid, dense or hard layer on a surface or boundary.\n[n.] The external, hardened layer of certain foodstuffs, including most types of bread, fried meat, etc.\n[n.] An outer layer composed of pastry\n[v.] To cover with a crust.\n[v.] To form a crust.\n[n.] A subgenre of punk rock, derived from hardcore punk with extreme metal elements, often with pessimistic lyrics about political and social ills.","ex":""},"CRYPT":{"p":"/kɹɪpt/","s":"n.","e":"[n.] A cave or cavern.\n[n.] An underground vault, especially one beneath a church that is used as a burial place.\n[n.] A small pit or cavity in the surface of an organ or other structure.","ex":""},"CUBIC":{"p":"/ˈkjuː.bɪk/","s":"n./adj.","e":"[n.] A cubic curve.\n[adj.] Used in the names of units of volume formed by multiplying a unit of length by itself twice.\n[adj.] Of a class of polynomial of the form ax^3 + bx^2 + cx + d\n[adj.] Having three equal axes and all angles 90°.","ex":"cubic foot"},"CURIO":{"p":"/ˈkjɔːɹiˌəʊ̯/","s":"n.","e":"[n.] A strange and interesting object; something that evokes curiosity.","ex":""},"CURLY":{"p":"/ˈkɜːli/","s":"n./adj.","e":"[n.] A person or animal with curly hair.\n[adj.] Having curls.\n[adj.] Curling in a direction, as opposed to straight (quotation marks or apostrophes)\n[adj.] Complicated and difficult; knotty.","ex":""},"CURRY":{"p":"/ˈkʌ.ɹi/","s":"n./v.","e":"[n.] One of a family of dishes originating from South Asian cuisine, flavoured by a spiced sauce.\n[n.] A spiced sauce or relish, especially one flavoured with curry powder.\n[n.] Curry powder.\n[v.] To cook or season with curry powder.","ex":""},"CURSE":{"p":"/kɜːs/","s":"n.","e":"[n.] A supernatural detriment or hindrance; a bane.\n[n.] A prayer or imprecation that harm may befall someone.\n[n.] The cause of great harm, evil, or misfortune; that which brings evil or severe affliction; torment.","ex":""},"CURVE":{"p":"/kɜːv/","s":"n./v./adj.","e":"[n.] A gentle bend, such as in a road.\n[n.] A simple figure containing no straight portions and no angles; a curved line.\n[n.] A grading system based on the scale of performance of a group used to normalize a right-skewed grade distribution (with more lower scores) into a bell curve, so that more can receive higher grades, regardless of their actual knowledge of the subject.\n[v.] To bend; to crook.\n[v.] To cause to swerve from a straight course.\n[v.] To bend or turn gradually from a given direction.","ex":"You should slow down when approaching a curve."},"CURVY":{"p":"/ˈkɜːvi/","s":"adj.","e":"[adj.] Having curves.\n[adj.] Buxom or curvaceous.","ex":"I love this woman and her curvy body."},"CUTIE":{"p":"/ˈkjuːti/","s":"n.","e":"[n.] A cute person or animal.","ex":""},"CYCLE":{"p":"/ˈsaɪkəl/","s":"n./v.","e":"[n.] An interval of space or time in which one set of events or phenomena is completed.\n[n.] A complete rotation of anything.\n[n.] A process that returns to its beginning and then repeats itself in the same sequence.\n[v.] To ride a bicycle or other cycle.\n[v.] To go through a cycle or to put through a cycle.\n[v.] To turn power off and back on","ex":"the cycle of the seasons, or of the year"},"CYNIC":{"p":"/ˈsɪnɪk/","s":"n./adj.","e":"[n.] A person who believes that all people are motivated by selfishness.\n[n.] A person whose outlook is scornfully negative.\n[adj.] Cynical (in all senses)\n[adj.] Relating to the Dog Star.","ex":"the cynic, or Sothic, year; cynic cycle"},"DADDY":{"p":"/ˈdædi/","s":"n./v.","e":"[n.] (usually childish) Father.\n[n.] A male lover.\n[n.] An informal term of address for a man.\n[v.] To father; to sire.","ex":"Rock 'n' roll is cool, daddy, and you know it!"},"DAFFY":{"p":"/ˈdæfi/","s":"adj.","e":"[adj.] Somewhat mad or eccentric.","ex":""},"DAIRY":{"p":"/ˈdɛəɹi/","s":"n./adj.","e":"[n.] (also dairy products or dairy produce) Products produced from milk.\n[n.] A place, often on a farm, where milk is processed and turned into products such as butter and cheese.\n[n.] A dairy farm.\n[n.] A shop selling dairy products.\n[adj.] Referring to products produced from milk.\n[adj.] Referring to the milk production and processing industries.","ex":""},"DANCE":{"p":"[dæːns]","s":"n./v.","e":"[n.] A sequence of rhythmic steps or movements usually performed to music, for pleasure or as a form of social interaction.\n[n.] A social gathering where dancing is the main activity.\n[n.] A normally horizontal stripe called a fess that has been modified to zig-zag across the center of a coat of arms from dexter to sinister.\n[v.] To move with rhythmic steps or movements, especially in time to music.\n[v.] To leap or move lightly and rapidly.\n[v.] To perform the steps to.","ex":"I danced with her all night long."},"DANDY":{"p":"/ˈdændi/","s":"n./adj.","e":"[n.] A man very concerned about his clothes and his appearance.\n[n.] A yawl, or a small after-sail on a yawl.\n[n.] A dandy roller.\n[adj.] Like a dandy, foppish.\n[adj.] Very good; better than expected but not as good as could be.\n[adj.] Excellent; first-rate.","ex":"That's all fine and dandy, but how much does it cost?"},"DATA":{"p":"/ˈdaetə/","s":"n.","e":"[n.] (plural: data) A measurement of something on a scale understood by both the recorder (a person or device) and the reader (another person or device). The scale is arbitrarily defined, such as from 1 to 10 by ones, 1 to 100 by 0.1, or simply true or false, on or off, yes, no, or maybe, etc.\n[n.] (plural: data) A fact known from direct observation.\n[n.] (plural: data) A premise from which conclusions are drawn.","ex":""},"DATED":{"p":"/ˈdeɪtɪd/","s":"v./adj.","e":"[v.] To note the time or place of writing or executing; to express in an instrument the time of its execution.\n[v.] To note or fix the time of (an event); to give the date of.\n[v.] To determine the age of something.\n[adj.] Marked with a date.\n[adj.] Outdated.\n[adj.] Anachronistic; being obviously inappropriate for its present context.","ex":"to date a letter, a bond, a deed, or a charter"},"DATUM":{"p":"/ˈdeɪtəm/","s":"n./v.","e":"[n.] (plural: data) A measurement of something on a scale understood by both the recorder (a person or device) and the reader (another person or device). The scale is arbitrarily defined, such as from 1 to 10 by ones, 1 to 100 by 0.1, or simply true or false, on or off, yes, no, or maybe, etc.\n[n.] (plural: data) A fact known from direct observation.\n[n.] (plural: data) A premise from which conclusions are drawn.\n[v.] To provide missing data points by using a mathematical model to extrapolate values that are outside the range of a measuring device.","ex":""},"DEAD":{"p":"/diːd/","s":"n./v./adj./adv.","e":"[n.] (with \"the\", a demonstrative, or a possessive) Those who have died.\n[n.] (often with \"the\") Time when coldness, darkness, or stillness is most intense.\n[n.] (usually plural) Sterile mining waste, often present as many large rocks stacked inside the workings.\n[v.] To prevent by disabling; stop.\n[v.] To make dead; to deaden; to deprive of life, force, or vigour.\n[v.] To kill.","ex":"Have respect for the dead."},"DEALT":{"p":"/ˈdɛlt/","s":"v.","e":"[v.] To distribute among a number of recipients, to give out as one’s portion or share.\n[v.] To administer or give out, as in small portions.\n[v.] To distribute cards to the players in a game.","ex":"The fighting is over; now we deal out the spoils of victory."},"DEBT":{"p":"/dɛt/","s":"n.","e":"[n.] An action, state of mind, or object one has an obligation to perform for another, adopt toward another, or give to another.\n[n.] The state or condition of owing something to another.\n[n.] Money that one person or entity owes or is required to pay to another, generally as a result of a loan or other financial transaction.","ex":"I am in your debt."},"DEBUT":{"p":"/dəˈbʉː/","s":"n./v.","e":"[n.] A performer's first performance to the public, in sport, the arts or some other area.\n[n.] The first public presentation of a theatrical play, motion picture, opera, musical composition, dance, or other performing arts piece.\n[n.] The first appearance of a debutante in society.\n[v.] To formally introduce, as to the public\n[v.] To make one's initial formal appearance","ex":"Since making its debut two years ago, the program has gained cult status."},"DECOR":{"p":"/ˈdeɪkɔː(ɹ)/","s":"n.","e":"[n.] The style of decoration of a room or building.\n[n.] A stage setting; scenery; set; backdrop.","ex":"Her living room had a lush Persian-style decor."},"DECOY":{"p":"/ˈdiːkɔɪ/","s":"n./v.","e":"[n.] A person or object meant to lure somebody into danger.\n[n.] A real or fake animal used by hunters to lure game.\n[v.] To lead into danger by artifice; to lure into a net or snare; to entrap.\n[v.] To act as, or use, a decoy.","ex":"to decoy troops into an ambush; to decoy ducks into a net"},"DEEP":{"p":"/diːp/","s":"n./adj./adv.","e":"[n.] (with \"the\") The deep part of a lake, sea, etc.\n[n.] (with \"the\") A silent time; quiet isolation.\n[n.] A deep shade of colour.\n[adj.] (of a physical distance) Extending far away from a point of reference, especially downwards.\n[adj.] (intellectual, social) Complex, involved.\n[adj.] (sound, voice) Low in pitch.","ex":"creatures of the deep"},"DEFER":{"p":"/dɪˈfɜː(ɹ)/","s":"v.","e":"[v.] To delay or postpone\n[v.] After winning the opening coin toss, to postpone until the start of the second half a team's choice of whether to kick off or receive (and to allow the opposing team to make this choice at the start of the first half).\n[v.] To delay, to wait.","ex":"We're going to defer the decision until we have all the facts."},"DEMUR":{"p":"/dɪˈmɜː/","s":"n./v.","e":"[n.] Stop; pause; hesitation as to proceeding; suspense of decision or action; scruple.\n[v.] To linger; to stay; to tarry\n[v.] To delay; to pause; to suspend proceedings or judgment in view of a doubt or difficulty; to hesitate; to put off the determination or conclusion of an affair.\n[v.] To scruple or object; to take exception; to oppose; to balk","ex":"I demur to that statement."},"DENIM":{"p":"/ˈdɛnɪm/","s":"n.","e":"[n.] A textile often made of cotton with a distinct diagonal pattern.","ex":""},"DENSE":{"p":"/dɛns/","s":"n./adj.","e":"[n.] A thicket.\n[adj.] Having relatively high density.\n[adj.] Compact; crowded together.\n[adj.] Thick; difficult to penetrate.","ex":""},"DEPOT":{"p":"/ˈdepɐʉ/","s":"n.","e":"[n.] A storage facility, in particular, a warehouse.\n[n.] A bus station or railway station.\n[n.] A place where recruits are assembled before being sent to active units.","ex":""},"DEPTH":{"p":"/dɛpθ/","s":"n.","e":"[n.] The vertical distance below a surface; the degree to which something is deep\n[n.] The distance between the front and the back, as the depth of a drawer or closet\n[n.] The intensity, complexity, strength, seriousness or importance of an emotion, situation, etc.","ex":"Measure the depth of the water in this part of the bay."},"DESK":{"p":"/dɛsk/","s":"n./v.","e":"[n.] A table, frame, or case, in past centuries usually with a sloping top but now usually with a flat top, for the use of writers and readers. It often has a drawer or repository underneath.\n[n.] A reading table or lectern to support the book from which the liturgical service is read, differing from the pulpit from which the sermon is preached; also (especially in the United States), a pulpit. Hence, used symbolically for the clerical profession.\n[n.] A department of a newspaper tasked with covering a particular geographical region or aspect of the news.\n[v.] To shut up, as in a desk; to treasure.\n[v.] To equip with a desk or desks.","ex":"city desk"},"DEVIL":{"p":"/ˈdɛvəl/","s":"n./v.","e":"[n.] An evil creature.\n[n.] (with article) The chief devil; Satan.\n[n.] A fictional image of a man, usually red or orange in skin color; with a set of horns on his head, a pointed goatee and a long tail and carrying a pitchfork; that represents evil and portrayed to children in an effort to discourage bad behavior.\n[v.] To make like a devil; to invest with the character of a devil.\n[v.] To annoy or bother.\n[v.] To work as a ‘devil’; to work for a lawyer or writer without fee or recognition.","ex":""},"DIAL":{"p":"/ˈdaɪəɫ/","s":"n./v.","e":"[n.] A graduated, circular scale over which a needle moves to show a measurement (such as speed).\n[n.] A clock face.\n[n.] A sundial.\n[v.] To control or select something with a dial, or (figuratively) as if with a dial.\n[v.] To select a number, or to call someone, on a telephone.\n[v.] To use a dial or a telephone.","ex":"President Trump has recently dialled down the rhetoric."},"DICE":{"p":"/daɪs/","s":"n./v.","e":"[n.] Gaming with one or more dice.\n[n.] A die.\n[n.] That which has been diced.\n[v.] To play dice.\n[v.] To cut into small cubes.\n[v.] To ornament with squares, diamonds, or cubes.","ex":"Cut onions, carrots and celery into medium dice."},"DIGIT":{"p":"/ˈdɪdʒɪt/","s":"n./v.","e":"[n.] A stage of proficiency or qualification in a course of study, now especially an award bestowed by a university or, in some countries, a college, as a certification of academic achievement. (In the United States, can include secondary schools.)\n[n.] A unit of measurement of angle equal to 1/360 of a circle's circumference.\n[n.] A unit of measurement of temperature on any of several scales, such as Celsius or Fahrenheit.\n[n.] The whole numbers from 0 to 9 and the Arabic numerals representing them, which are combined to represent base-ten numbers.\n[n.] A distinct symbol representing one of an arithmetic progression of numbers between 0 and the radix.\n[n.] 1/12 the apparent diameter of the sun or moon, as a measure of the totality of an eclipse.","ex":"She has two bachelor's degrees and is studying towards a master's degree."},"DILLY":{"p":"/ˈdɪli/","s":"adj.","e":"[adj.] Redolent of dill (the herb).","ex":""},"DIMLY":{"p":"/ˈdɪmli/","s":"adv.","e":"[adv.] In a dim manner.","ex":""},"DINER":{"p":"/ˈdaɪnə(ɹ)/","s":"n.","e":"[n.] One who dines.\n[n.] A dining car in a railroad train.\n[n.] A typically small restaurant, usually modeled after a railroad dining car, that serves lower-class fare, normally having a counter with stools along one side and booths on the other, and often decorated in 50s and 60s pop culture themes and playing popular music from those decades.","ex":""},"DIODE":{"p":"/ˈdaɪəʊd/","s":"n.","e":"[n.] An electronic device that allows current to flow in one direction only; used chiefly as a rectifier.","ex":""},"DIRGE":{"p":"/dɜːdʒ/","s":"n./v.","e":"[n.] A mournful poem or piece of music composed or performed as a memorial to a dead person.\n[n.] A song or piece of music that is considered too slow, bland or boring.\n[v.] To sing dirges","ex":""},"DIRT":{"p":"/dɜːt/","s":"n./v.","e":"[n.] Soil or earth.\n[n.] A stain or spot (on clothes etc); any foreign substance that worsens appearance.\n[n.] Previously unknown facts, or the invented \"facts\", about a person.\n[v.] To make foul or filthy; soil; befoul; dirty","ex":"The reporter uncovered the dirt on the businessman by going undercover."},"DISK":{"p":"/dɪsk/","s":"n./v.","e":"[n.] A thin, flat, circular plate or similar object.\n[n.] Something resembling a disk.\n[n.] An intervertebral disc\n[v.] To harrow\n[n.] A removable disk used for storing digital data, measuring between 2 and 8 inches diagonally and storing between 80 KB and 240 MB.","ex":"A coin is a disk of metal."},"DITCH":{"p":"/dɪtʃ/","s":"n./v.","e":"[n.] A trench; a long, shallow indentation, as for irrigation or drainage.\n[v.] To discard or abandon.\n[v.] To deliberately crash-land an airplane on water.\n[v.] To deliberately not attend classes; to play hookey.","ex":"Digging ditches has long been considered one of the most demanding forms of manual labor."},"DODGE":{"p":"/dɒdʒ/","s":"n./v./adj.","e":"[n.] An act of dodging.\n[n.] A trick, evasion or wile.\n[n.] A line of work.\n[v.] To avoid (something) by moving suddenly out of the way.\n[v.] To avoid; to sidestep.\n[v.] To go hither and thither.","ex":"He dodged traffic crossing the street."},"DODGY":{"p":"/ˈdɒdʒ.i/","s":"adj.","e":"[adj.] Evasive and shifty\n[adj.] Unsound and unreliable\n[adj.] Dishonest","ex":"Asked why, a spokesman gave a dodgy answer about legal ramifications."},"DONUT":{"p":"/ˈdoʊnət/","s":"n.","e":"[n.] A deep-fried piece of dough or batter, commonly made in a toroidal or ellipsoidal shape, and mixed with various sweeteners and flavors, sometimes filled with jelly, custard or cream.\n[n.] Anything in the shape of a torus.\n[n.] (automobile) A peel-out or skid-mark in the shape of donut; a 360-degree skid.","ex":""},"DOUGH":{"p":"/dʌf/","s":"n./v.","e":"[n.] A thick, malleable substance made by mixing flour with other ingredients such as water, eggs, and/or butter, that is made into a particular form and then baked.\n[n.] Money.\n[v.] To make into dough.","ex":"Pizza dough is very stretchy."},"DOWDY":{"p":"/ˈdaʊdi/","s":"n./adj.","e":"[n.] A plain or shabby person\n[adj.] Plain and unfashionable in style or dress.\n[adj.] Lacking stylishness or neatness; shabby.","ex":""},"DOWEL":{"p":"/ˈdaʊəl/","s":"n./v.","e":"[n.] A pin, or block, of wood or metal, fitting into holes in the abutting portions of two pieces, and being partly in one piece and partly in the other, to keep them in their proper relative position.\n[n.] A wooden rod, as one to make short pins from.\n[n.] A piece of wood or similar material fitted into a surface not suitable for fastening so that other pieces may be fastened to it.\n[v.] To fasten together with dowels.\n[v.] To furnish with dowels.","ex":"A cooper dowels pieces for the head of a cask."},"DOWN":{"p":"/daʊn/","s":"n./v./adj./adv./prep.","e":"[n.] A negative aspect; a downer.\n[n.] A grudge (on someone).\n[n.] An act of swallowing an entire drink at once.\n[v.] To knock (someone or something) down; to cause to come down, to fell.\n[v.] To lower; to put (something) down.\n[v.] To defeat; to overpower.","ex":"I love almost everything about my job. The only down is that I can't take Saturdays off."},"DOWNY":{"p":"/ˈdaʊni/","s":"adj.","e":"[adj.] Having down, covered with a soft fuzzy coating as of small feathers or hair.\n[adj.] Sharp-witted, perceptive.","ex":"The chick's downy coat of feathers formed almost immediately to keep it warm."},"DOWRY":{"p":"/ˈdaʊəɹi/","s":"n./v.","e":"[n.] Payment, such as property or money, paid by the bride's family to the groom or his family at the time of marriage.\n[n.] Payment by the groom or his family to the bride's family: bride price.\n[n.] Dower.\n[v.] To bestow a dowry upon.","ex":"1999, Judith Everard, Michael C. E. Jones, Charters Duchess Constance Br, Page xvi"},"DRAFT":{"p":"/dɹæft/","s":"n./v./adj.","e":"[n.] A current of air, usually coming into a room or vehicle.\n[n.] Draw through a flue of gasses (smoke) resulting from a combustion process.\n[n.] An act of drinking.\n[v.] To write a first version, make a preliminary sketch.\n[v.] To draw in outline; to make a draught, sketch, or plan of, as in architectural and mechanical drawing.\n[v.] To write a law.","ex":"I'd rather have a fresh, cheap draft beer."},"DRAIN":{"p":"/dɹeɪn/","s":"n./v.","e":"[n.] A conduit allowing liquid to flow out of an otherwise contained volume; a plughole (UK)\n[n.] An access point or conduit for rainwater that drains directly downstream in a (drainage) basin without going through sewers or water treatment in order to prevent or belay floods.\n[n.] Something consuming resources and providing nothing in return.\n[v.] To lose liquid.\n[v.] To flow gradually.\n[v.] To cause liquid to flow out of.","ex":"The drain in the kitchen sink is clogged."},"DRAMA":{"p":"/ˈdɹæmə/","s":"n.","e":"[n.] A composition, normally in prose, telling a story and intended to be represented by actors impersonating the characters and speaking the dialogue\n[n.] Such a work for television, radio or the cinema (usually one that is not a comedy)\n[n.] Theatrical plays in general","ex":""},"DRANK":{"p":"/dɹæŋk/","s":"n./v.","e":"[n.] Dextromethorphan\n[n.] A drink, usually alcoholic\n[v.] To consume (a liquid) through the mouth.\n[v.] (metonymic) To consume the liquid contained within (a bottle, glass, etc.).\n[v.] To consume alcoholic beverages.","ex":"He drank the water I gave him."},"DRESS":{"p":"/dɹɛs/","s":"n./v.","e":"[n.] An item of clothing (usually worn by a woman or young girl) which both covers the upper part of the body and includes skirts below the waist.\n[n.] Apparel, clothing.\n[n.] The system of furrows on the face of a millstone.\n[v.] To fit out with the necessary clothing; to clothe, put clothes on (something or someone).\n[v.] To clothe oneself; to put on clothes.\n[v.] To put on the uniform and equipment necessary to play the game.","ex":"Amy and Mary looked very pretty in their dresses."},"DRIER":{"p":"/ˈdɹaɪə/","s":"n.","e":"[n.] One who, or that which, dries; a desiccative.\n[n.] A household appliance that removes the water from clothing by accelerating evaporation, usually though heat and a tumbling motion.\n[n.] An electric hair dryer.","ex":"The sun and a northwesterly wind are great driers of the earth."},"DROLL":{"p":"/dɹəʊl/","s":"n./v./adj.","e":"[n.] A funny person; a buffoon, a wag.\n[v.] To jest, to joke.\n[adj.] Oddly humorous; whimsical, amusing in a quaint way; waggish.","ex":""},"DRONE":{"p":"/dɹəʊn/","s":"n./v.","e":"[n.] A male ant, bee or wasp, which does not work but can fertilize the queen bee.\n[n.] Someone who does not work; a lazy person, an idler.\n[n.] One who performs menial or tedious work.\n[v.] To kill with a missile fired by unmanned aircraft.","ex":""},"DROOL":{"p":"/dɹuːl/","s":"n./v.","e":"[n.] Saliva trickling from the mouth.\n[n.] Stupid talk.\n[v.] To secrete saliva, especially in anticipation of food.\n[v.] To secrete any substance in a similar way.\n[v.] To react to something with uncontrollable desire.","ex":"The alien beast drooled slime."},"DROOP":{"p":"/ˈdɹuːp/","s":"n./v.","e":"[n.] Something which is limp or sagging\n[n.] A condition or posture of drooping\n[v.] To hang downward; to sag.\n[v.] To slowly become limp; to bend gradually.\n[v.] To lose all energy, enthusiasm or happiness; to flag.","ex":"He walked with a discouraged droop."},"DROP":{"p":"/dɹɒp/","s":"n./v.","e":"[n.] A small quantity of liquid, just large enough to hold its own round shape via surface tension, especially one that falls from a source of liquid.\n[n.] A very small quantity of liquid, or (by extension) of anything.\n[n.] (now especially with \"the\") Alcoholic spirits in general.\n[v.] To fall in droplets (of a liquid).\n[v.] To drip (a liquid).\n[v.] Generally, to fall (straight down).","ex":"Put three drops of oil into the mixture."},"DROVE":{"p":"/dɹəʊv/","s":"n.","e":"[n.] A number of cattle driven to market or new pastures.\n[n.] (usually in the plural) A large number of people on the move (literally or figuratively).\n[n.] (collective) A group of hares.","ex":""},"DROWN":{"p":"/dɹaʊn/","s":"v.","e":"[v.] To die from suffocation while immersed in water or other fluid.\n[v.] To kill by suffocating in water or another liquid.\n[v.] To be flooded: to be inundated with or submerged in (literally) water or (figuratively) other things; to be overwhelmed.","ex":""},"DRUID":{"p":"/ˈdɹuː.ɪd/","s":"n.","e":"[n.] One of an order of priests among certain groups of Celts before the adoption of Abrahamic religions.","ex":""},"DRUM":{"p":"/ˈdɹʌm/","s":"n.","e":"[n.] A percussive musical instrument spanned with a thin covering on at least one end for striking, forming an acoustic chamber, affecting what materials are used to make it; a membranophone.\n[n.] Any similar hollow, cylindrical object.\n[n.] A barrel or large cylindrical container for liquid transport and storage.","ex":"Replace the drum unit of your printer."},"DRUNK":{"p":"/dɹʌŋk/","s":"v./n./adj.","e":"[v.] To consume (a liquid) through the mouth.\n[v.] (metonymic) To consume the liquid contained within (a bottle, glass, etc.).\n[v.] To consume alcoholic beverages.\n[n.] One who is intoxicated with alcohol.\n[n.] A habitual drinker, especially one who is frequently intoxicated.\n[n.] A drinking-bout; a period of drunkenness.","ex":"He drank the water I gave him."},"DRYER":{"p":"/ˈdɹaɪə/","s":"n.","e":"[n.] One who, or that which, dries; a desiccative.\n[n.] A household appliance that removes the water from clothing by accelerating evaporation, usually though heat and a tumbling motion.\n[n.] An electric hair dryer.","ex":"The sun and a northwesterly wind are great driers of the earth."},"DUAL":{"p":"/ˈdjuː.əl/","s":"n./v./adj.","e":"[n.] Of an item that is one of a pair, the other item in the pair.\n[n.] Of a regular polyhedron with V vertices and F faces, the regular polyhedron having F vertices and V faces.\n[n.] (grammar) dual number The grammatical number of a noun marking two of something (as in singular, dual, plural), sometimes referring to two of anything (a couple of, exactly two of), or a chirality-marked pair (as in left and right, as with gloves or shoes) or in some languages as a discourse marker, \"between you and me\". A few languages display trial number.\n[v.] To convert from single to dual; specifically, to convert a single-carriageway road to a dual carriageway.\n[adj.] Exhibiting duality; characterized by having two (usually equivalent) components.\n[adj.] Acting as a counterpart.","ex":"The octahedron is the dual of the cube."},"DUCAL":{"p":"/djuːkəl/","s":"adj.","e":"[adj.] Of or pertaining to a duke, a duchess, or the duchy or dukedom they hold.","ex":""},"DUCAT":{"p":"/ˈdʌkət/","s":"n.","e":"[n.] A gold coin minted by various European nations.\n[n.] A coin of the major denomination (dollar, euro, etc.); money in general.\n[n.] A ticket.","ex":""},"DUMMY":{"p":"/ˈdʌmi/","s":"n./v.","e":"[n.] A silent person; a person who does not talk.\n[n.] An unintelligent person.\n[n.] A figure of a person or animal used by a ventriloquist; a puppet.\n[v.] To make a mock-up or prototype version of something, without some or all off its intended functionality.\n[v.] To feint.","ex":"Don't be such a dummy!"},"DUMPY":{"p":"/ˈdʌmpi/","s":"n./adj.","e":"[n.] A short, stout person or animal, especially one of a breed of very short-legged chickens.\n[n.] A small bottle of beer.\n[adj.] Short and thick; stout or stocky","ex":""},"DUNCE":{"p":"/dʌns/","s":"n.","e":"[n.] An unintelligent person.","ex":""},"DUSKY":{"p":"/ˈdʌs.ki/","s":"n./adj.","e":"[n.] A dusky shark.\n[n.] A dusky dolphin.\n[n.] A dusky grouse.\n[adj.] Dimly lit, as at dusk (evening).\n[adj.] Having a shade of color that is rather dark.\n[adj.] Dark-skinned.","ex":"I like it when it is dusky, just before the street lights come on."},"DUST":{"p":"/dʌst/","s":"n./v.","e":"[n.] Fine particles\n[n.] The act of cleaning by dusting.\n[n.] The earth, as the resting place of the dead.\n[v.] To remove dust from.\n[v.] To remove dust; to clean by removing dust.\n[v.] Of a bird, to cover itself in sand or dry, dusty earth.","ex":"The cleaning lady needs a stool to dust the cupboard."},"DUTY":{"p":"/ˈdjuːti/","s":"n.","e":"[n.] That which one is morally or legally obligated to do.\n[n.] The state of being at work and responsible for or doing a particular task.\n[n.] A tax placed on imports or exports; a tariff.","ex":"We don't have a duty to keep you here."},"DUVET":{"p":"/ˈduːveɪ/","s":"n.","e":"[n.] A thick, padded quilt used instead of blankets.\n[n.] A cover for a quilt or comforter.","ex":""},"DWELL":{"p":"/dwɛl/","s":"n./v.","e":"[n.] A period of time in which a system or component remains in a given state.\n[n.] A brief pause in the motion of part of a mechanism to allow an operation to be completed.\n[n.] A planned delay in a timed control program.\n[v.] To live; to reside.\n[v.] To linger (on) a particular thought, idea etc.; to remain fixated (on).\n[v.] To be in a given state.","ex":""},"EAGLE":{"p":"/ˈiːɡəl/","s":"n./v.","e":"[n.] Any of several large carnivorous and carrion-eating birds in the family Accipitridae, having a powerful hooked bill and keen vision.\n[n.] A gold coin with a face value of ten dollars, formerly used in the United States.\n[n.] A 13th-century coin minted in Europe and circulated in England as a debased sterling silver penny, outlawed under Edward I.\n[v.] To score an eagle.","ex":""},"EARL":{"p":"/ɜːl/","s":"n.","e":"[n.] (nobility) A British or Irish nobleman next in rank above a viscount and below a marquess; equivalent to a European count. A female using the style is termed a countess.\n[n.] Any of various nymphalid butterflies of the genus Tanaecia. Other butterflies in this genus are called counts and viscounts.","ex":""},"EARN":{"p":"/ɜːn/","s":"v.","e":"[v.] To gain (success, reward, recognition) through applied effort or work.\n[v.] To receive payment for work.","ex":"You can have the s'mores: you earned them, clearing the walkway of snow so well."},"EAST":{"p":"/iːst/","s":"n./adj./adv.","e":"[n.] One of the four principal compass points, specifically 90°, conventionally directed to the right on maps; the direction of the rising sun at an equinox. Abbreviated as E.\n[adj.] Situated or lying in or towards the east; eastward.\n[adj.] Wind from the east\n[adj.] Of or pertaining to the east; eastern.\n[adv.] Towards the east; eastwards","ex":""},"ECLAT":{"p":"","s":"n.","e":"[n.] A brilliant or successful effect; brilliance of success or effort; splendor; brilliant show; striking effect; glory; renown.","ex":""},"EDIFY":{"p":"/ˈɛdɪfaɪ/","s":"v.","e":"[v.] To build, construct.\n[v.] To instruct or improve morally or intellectually.","ex":""},"EERIE":{"p":"/ˈɪəɹi/","s":"adj.","e":"[adj.] Strange, weird, fear-inspiring.\n[adj.] Frightened, timid.","ex":"The eerie sounds seemed to come from the graveyard after midnight."},"EKING":{"p":"","s":"n.","e":"[n.] The act or process of adding.\n[n.] That which is added.\n[n.] A supplementary piece of timber used to lengthen another.","ex":""},"ELATE":{"p":"/ɪˈleɪt/","s":"v./adj.","e":"[v.] To make joyful or proud.\n[v.] To lift up; raise; elevate.\n[adj.] Elated; exultant\n[adj.] Lifted up; raised; elevated.","ex":""},"ELBOW":{"p":"/ˈɛl.bəʊ/","s":"n./v.","e":"[n.] The joint between the upper arm and the forearm.\n[n.] (by extension) Any turn or bend like that of the elbow, in a wall, building, coastline, etc.; an angular or jointed part of any structure, such as the raised arm of a chair or sofa, or a short pipe fitting, turning at an angle or bent.\n[n.] A detective.\n[v.] To push with the elbow.\n[v.] (by extension) To nudge, jostle or push.","ex":"the sides of windows, where the jamb makes an elbow with the window back"},"ELEGY":{"p":"/ˈɛlɪdʒi/","s":"n.","e":"[n.] A mournful or plaintive poem; a funeral song; a poem of lamentation.\n[n.] A composition of mournful character.","ex":""},"ELFIN":{"p":"/ˈɛlfɪn/","s":"n.","e":"[n.] An elf; an inhabitant of fairy-land.\n[n.] A little urchin or child.\n[n.] Any of the butterflies in the subgenus Incisalia of the North American lycaenid genus Callophrys.","ex":""},"ELVER":{"p":"/ˈɛlvə(ɹ)/","s":"n.","e":"[n.] A young eel.","ex":""},"EMCEE":{"p":"/ˌemˈsiː/","s":"n./v.","e":"[n.] A rapper.\n[n.] Initialism of main colour.\n[n.] Initialism of matching colour.\n[n.] A medical facility, such as a hospital, especially one for the treatment and diagnosis of outpatients.\n[n.] (by extension) A hospital session to diagnose or treat patients.\n[n.] A school, or a session of a school or class, in which medicine or surgery is taught by the examination and treatment of patients in the presence of the pupils.","ex":""},"EMPTY":{"p":"/ˈɛmpti/","s":"n./v./adj.","e":"[n.] (usually plural) A container, especially a bottle, whose contents have been used up, leaving it empty.\n[v.] To make empty; to void; to remove the contents of.\n[v.] Of a river, duct, etc: to drain or flow toward an ultimate destination.\n[adj.] Devoid of content; containing nothing or nobody; vacant.\n[adj.] Containing no elements (as of a string, array, or set), opposed to being null (having no valid value).\n[adj.] Free; clear; devoid; often with of.","ex":"Put the empties out to be recycled."},"ENACT":{"p":"","s":"n./v.","e":"[n.] Purpose; determination\n[v.] To make (a bill) into law\n[v.] To act the part of; to play\n[v.] To do; to effect","ex":""},"ENDOW":{"p":"/ɛn-/","s":"v.","e":"[v.] To provide with a dower or a dowry.\n[v.] To give property to (someone) as a gift; specifically, to provide (a person or institution) with support in the form of a permanent fund of money or other benefits.\n[v.] Followed by with, or rarely by of: to enrich or furnish with some faculty or quality.","ex":""},"ENROL":{"p":"","s":"v.","e":"[v.] To enter (a name, etc.) in a register, roll or list\n[v.] To enlist (someone) or make (someone) a member of\n[v.] To enlist oneself (in something) or become a member (of something)","ex":"They were eager to enroll new recruits."},"ENTER":{"p":"/ˈɛntə(ɹ)/","s":"n./v.","e":"[n.] The \"Enter\" key on a computer keyboard.\n[n.] A stroke of the Enter key.\n[v.] To go or come into an enclosed or partially enclosed space.\n[v.] To cause to go (into), or to be received (into); to put in; to insert; to cause to be admitted.\n[v.] To go or come into (a state or profession).","ex":"You should knock before you enter, unless you want to see me naked."},"ERASE":{"p":"/ɪˈɹeɪz/","s":"n./v.","e":"[n.] The operation of deleting data.\n[v.] To remove markings or information\n[v.] To obliterate information from (a storage medium), such as to clear or (with magnetic storage) to demagnetize.\n[v.] To obliterate (information) from a storage medium, such as to clear or to overwrite.","ex":"I erased that note because it was wrong."},"ERODE":{"p":"/ɪˈɹoʊd/","s":"v.","e":"[v.] To wear away by abrasion, corrosion or chemical reaction.\n[v.] To destroy gradually by an ongoing process.","ex":"to erode a person's trust"},"ERROR":{"p":"/ˈɛɹə(ɹ)/","s":"n./v.","e":"[n.] The state, quality, or condition of being wrong.\n[n.] A mistake; an accidental wrong action or a false statement not made deliberately.\n[n.] Sin; transgression.\n[v.] To function improperly due to an error, especially accompanied by error message.\n[v.] To show or contain an error or fault.\n[v.] To err.","ex":"Remove that line of code and the script should stop erroring there."},"EVADE":{"p":"/ɪˈveɪd/","s":"v.","e":"[v.] To get away from by cunning; to avoid by dexterity, subterfuge, address, or ingenuity; to elude; to cleverly escape from\n[v.] To escape; to slip away; — sometimes with from.\n[v.] To attempt to escape; to practice artifice or sophistry, for the purpose of eluding.","ex":"He evaded his opponent's blows."},"FABLE":{"p":"/ˈfeɪbəl/","s":"n./v.","e":"[n.] A fictitious narrative intended to enforce some useful truth or precept, usually with animals, etc. as characters; an apologue. Prototypically, Aesop's Fables.\n[n.] Any story told to excite wonder; common talk; the theme of talk.\n[n.] Fiction; untruth; falsehood.\n[v.] To compose fables; hence, to write or speak fiction; to write or utter what is not true.\n[v.] To make up; to devise, and speak of, as true or real; to tell of falsely; to recount in the form of a fable.","ex":""},"FAIL":{"p":"/feɪl/","s":"n./v./adj.","e":"[n.] Poor quality; substandard workmanship.\n[n.] A failure (condition of being unsuccessful)\n[n.] A failure (something incapable of success)\n[v.] To be unsuccessful.\n[v.] Not to achieve a particular stated goal. (Usage note: The direct object of this word is usually an infinitive.)\n[v.] To neglect.","ex":"The project was full of fail."},"FAIR":{"p":"/feː(ə)/","s":"n./v./adj./adv.","e":"[n.] Something which is fair (in various senses of the adjective).\n[n.] A woman, a member of the ‘fair sex’; also as a collective singular, women.\n[n.] Fairness, beauty.\n[v.] To smoothen or even a surface (especially a connection or junction on a surface).\n[v.] To bring into perfect alignment (especially about rivet holes when connecting structural members).\n[v.] To construct or design a structure whose primary function is to produce a smooth outline or reduce air drag or water resistance.","ex":"When will we learn to distinguish between the fair and the foul?"},"FALLEN":{"p":"/ˈfɔːlən/","s":"v./n./adj.","e":"[v.] (heading) To be moved downwards.\n[v.] To move downwards.\n[v.] To happen, to change negatively.\n[n.] The dead.\n[n.] Casualties of battle or war.\n[n.] One who has fallen, as from grace.","ex":"fallen raindrops"},"FAME":{"p":"/feɪm/","s":"n./v.","e":"[n.] What is said or reported; gossip, rumour.\n[n.] One's reputation.\n[n.] The state of being famous or well-known and spoken of.\n[v.] To make (someone or something) famous","ex":""},"FATAL":{"p":"[ˈfeɪ.ɾɫ̩]","s":"n./adj.","e":"[n.] A fatality; an event that leads to death.\n[n.] A fatal error; a failure that causes a program to terminate.\n[adj.] Proceeding from, or appointed by, fate or destiny.\n[adj.] Foreboding death or great disaster.\n[adj.] Causing death or destruction.","ex":"a fatal wound; a fatal disease; that fatal day; a fatal mistake"},"FAUNA":{"p":"/ˈfɔː.nə/","s":"n.","e":"[n.] Animals considered as a group; especially those of a particular country, region, time.\n[n.] A book, cataloguing the animals of a country.","ex":"the fauna of China"},"FEED":{"p":"/ˈfiːd/","s":"n./v.","e":"[n.] Food given to (especially herbivorous) animals.\n[n.] Something supplied continuously.\n[n.] The part of a machine that supplies the material to be operated upon.\n[v.] (ditransitive) To give (someone or something) food to eat.\n[v.] To eat (usually of animals).\n[v.] To give (someone or something) to (someone or something else) as food.","ex":"They sell feed, riding helmets, and everything else for horses."},"FEEL":{"p":"/fiːl/","s":"n./v.","e":"[n.] A quality of an object experienced by touch.\n[n.] A vague mental impression.\n[n.] An act of fondling.\n[v.] (heading) To use or experience the sense of touch.\n[v.] (heading) To sense or think emotionally or judgmentally.\n[v.] To be or become aware of.","ex":"Bark has a rough feel."},"FEIGN":{"p":"/feɪn/","s":"v.","e":"[v.] To make a false show or pretence of; to counterfeit or simulate.\n[v.] To imagine; to invent; to pretend.\n[v.] To make an action as if doing one thing, but actually doing another, for example to trick an opponent.","ex":"The pupil feigned sickness on the day of his exam."},"FELL":{"p":"/fɛl/","s":"n./v.","e":"[n.] A cutting-down of timber.\n[n.] The stitching down of a fold of cloth; specifically, the portion of a kilt, from the waist to the seat, where the pleats are stitched down.\n[n.] The end of a web, formed by the last thread of the weft.\n[v.] To make something fall; especially to chop down a tree.\n[v.] To strike down, kill, destroy.\n[v.] To stitch down a protruding flap of fabric, as a seam allowance, or pleat.","ex":""},"FEMME":{"p":"/fɛm/","s":"n./adj.","e":"[n.] A woman, a wife; a young woman or girl.\n[n.] A lesbian or other queer woman whose appearance, identity etc. is seen as feminine as opposed to butch.\n[n.] A person whose gender is feminine-leaning, such as a feminine non-binary person.\n[adj.] (entertainment) Pertaining to a femme; feminine, female.\n[adj.] Effeminate (of a man).\n[adj.] Characteristic of a feminine lesbian or queer woman.","ex":"Her style was more femme than butch."},"FENCE":{"p":"/fɛns/","s":"n./v.","e":"[n.] A thin artificial barrier that separates two pieces of land or a house perimeter.\n[n.] Someone who hides or buys and sells stolen goods, a criminal middleman for transactions of stolen goods.\n[n.] Skill in oral debate.\n[v.] To enclose, contain or separate by building fence.\n[v.] To defend or guard.\n[v.] To engage in the selling or buying of stolen goods.","ex":""},"FETCH":{"p":"/fɛtʃ/","s":"n./v.","e":"[n.] An act of fetching, of bringing something from a distance.\n[n.] The object of fetching; the source of an attraction; a force, propensity, or quality which attracts.\n[n.] A stratagem or trick; an artifice.\n[v.] To retrieve; to bear towards; to go and get.\n[v.] To obtain as price or equivalent; to sell for.\n[v.] To bring or get within reach by going; to reach; to arrive at; to attain; to reach by sailing.","ex":"If you put some new tyres on it, and clean it up a bit, the car should fetch about $5,000"},"FETID":{"p":"/ˈfɛtɪd/","s":"n./adj.","e":"[n.] The foul-smelling asafoetida plant, or its extracts.\n[adj.] Foul-smelling, stinking.","ex":"I caught the fetid odor of dirty socks."},"FEVER":{"p":"/ˈfiːvə/","s":"n./v.","e":"[n.] A higher than normal body temperature of a person (or, generally, a mammal), usually caused by disease.\n[n.] (usually in combination with one or more preceding words) Any of various diseases.\n[n.] A state of excitement or anxiety.\n[v.] To put into a fever; to affect with fever.\n[v.] To become fevered.","ex":"\"I have a fever. I think I've the flu.\""},"FIBER":{"p":"/ˈfaɪ.bə/","s":"n.","e":"[n.] A single elongated piece of a given material, roughly round in cross-section, often twisted with other fibers to form thread.\n[n.] A material in the form of fibers.\n[n.] A material whose length is at least 1000 times its width.","ex":"The microscope showed a single blue fiber stuck to the sole of the shoe."},"FICUS":{"p":"/ˈfaɪkəs/","s":"n.","e":"[n.] A plant belonging to the genus Ficus, including the rubber plant.","ex":""},"FIELD":{"p":"/fiːld/","s":"n./v.","e":"[n.] A land area free of woodland, cities, and towns; open country.\n[n.] A wide, open space that is usually used to grow crops or to hold farm animals.\n[n.] A place where competitive matches are carried out.\n[v.] To intercept or catch (a ball) and play it.\n[v.] (and other batting sports) To be the team catching and throwing the ball, as opposed to hitting it.\n[v.] To place (a team, its players, etc.) in a game.","ex":"There are several species of wild flowers growing in this field."},"FIEND":{"p":"/fiːnd/","s":"n./v.","e":"[n.] A devil or demon; a malignant or diabolical being; an evil spirit.\n[n.] A very evil person.\n[n.] An enemy; a foe.\n[v.] To yearn; to be desperate (for something).","ex":"Religion teaches us to love everybody, be one fiend or friend."},"FIFTY":{"p":"/ˈfɪfti/","s":"n./num.","e":"[n.] A banknote or coin with a denomination of 50.\n[n.] A batsman's score of at least 50 runs and less than 100 runs.\n[num.] The cardinal number occurring after forty-nine and before fifty-one.","ex":"Do you want small bills or are fifties OK?"},"FILE":{"p":"/faɪl/","s":"n./v.","e":"[n.] A collection of papers collated and archived together.\n[n.] A roll or list.\n[n.] Course of thought; thread of narration.\n[v.] To commit (official papers) to some office.\n[v.] To place in an archive in a logical place and order\n[v.] To store a file (aggregation of data) on a storage medium such as a disc or another computer.","ex":""},"FILET":{"p":"/ˈfɪleɪ/","s":"n./v.","e":"[n.] A headband; a ribbon or other band used to tie the hair up, or keep a headdress in place, or for decoration.\n[n.] A fine strip of any material, in various technical uses.\n[n.] A heavy bead of waterproofing compound or sealant material generally installed at the point where vertical and horizontal surfaces meet.\n[v.] To slice, bone or make into fillets.\n[v.] To apply, create, or specify a rounded or filled corner to.","ex":""},"FILLY":{"p":"/ˈfɪli/","s":"n.","e":"[n.] A young female horse.\n[n.] A young attractive female.","ex":"Hey, Homer, get a load of the gams on that filly!"},"FILM":{"p":"[ˈfɪlm̩]","s":"n./v.","e":"[n.] A thin layer of some substance; a pellicle; a membranous covering, causing opacity.\n[n.] A medium used to capture images in a camera.\n[n.] A movie.\n[v.] To record (activity, or a motion picture) on photographic film.\n[v.] To cover or become covered with a thin skin or pellicle.","ex":"a clear plastic film for wrapping food"},"FILMY":{"p":"/ˈfɪlmi/","s":"adj.","e":"[adj.] Resembling or made of a thin film; gauzy\n[adj.] Covered by (or as if by) a film; hazy","ex":""},"FINCH":{"p":"/fɪntʃ/","s":"n./v.","e":"[n.] Any bird of the family Fringillidae, seed-eating passerine birds, native chiefly to the Northern Hemisphere and usually having a conical beak.\n[v.] To hunt for finches, to go finching.","ex":""},"FIND":{"p":"/faɪnd/","s":"n./v.","e":"[n.] Anything that is found (usually valuable), as objects on an archeological site or a person with talent.\n[n.] The act of finding.\n[v.] To encounter or discover by accident; to happen upon.\n[v.] To encounter or discover something being searched for; to locate.\n[v.] (ditransitive) To discover by study or experiment direct to an object or end.","ex":"I found my car keys. They were under the couch."},"FINE":{"p":"/fæːn/","s":"n./v./adj./adv.","e":"[n.] Fine champagne; French brandy.\n[n.] (usually in the plural) Something that is fine; fine particles.\n[v.] To make finer, purer, or cleaner; to purify or clarify.\n[v.] To become finer, purer, or cleaner.\n[v.] To make finer, or less coarse, as in bulk, texture, etc.\n[adj.] Senses referring to subjective quality.","ex":"They filtered silt and fines out of the soil."},"FINER":{"p":"/ˈfaɪnə/","s":"adj./n.","e":"[adj.] Senses referring to subjective quality.\n[adj.] Senses referring to objective quality.\n[adj.] Behind the batsman and at a small angle to the line between the wickets.\n[n.] One who fines or purifies.","ex":"[...] to nudge it through the covers (or tickle it down to fine leg) for a four [...]"},"FIRM":{"p":"/fɜːm/","s":"n.","e":"[n.] A business partnership; the name under which it trades.\n[n.] A business enterprise, however organized.\n[n.] A criminal gang, especially based around football hooliganism.","ex":""},"FISH":{"p":"/fɪʃ/","s":"n.","e":"[n.] A cold-blooded vertebrate animal that lives in water, moving with the help of fins and breathing with gills.\n[n.] Any animal (or any vertebrate) that lives exclusively in water.\n[n.] The flesh of the fish used as food.","ex":"Salmon is a fish."},"FISHY":{"p":"/ˈfɪʃi/","s":"n./adj.","e":"[n.] A cold-blooded vertebrate animal that lives in water, moving with the help of fins and breathing with gills.\n[n.] Any animal (or any vertebrate) that lives exclusively in water.\n[n.] The flesh of the fish used as food.\n[n.] A period of time spent fishing.\n[n.] An instance of seeking something.\n[n.] A counter, used in various games.","ex":"Salmon is a fish."},"FIXER":{"p":"","s":"n.","e":"[n.] Agent noun of fix; one who, or that which, fixes.\n[n.] A chemical (sodium thiosulfate) used in photographic development that fixes the image in place, preventing further chemical reactions.\n[n.] (criminal justice) A person who arranges immunity for defendants by tampering with the justice system via bribery or extortion, especially as a business endeavor for profit.","ex":""},"FIZZY":{"p":"/ˈfɪzi/","s":"n./adj.","e":"[n.] A non-alcoholic carbonated beverage.\n[adj.] (of a liquid) Containing bubbles.\n[adj.] Lively, vivacious.\n[adj.] Makes a hissing sound.","ex":""},"FJORD":{"p":"/fiˈɔːd/","s":"n.","e":"[n.] A long, narrow, deep inlet between cliffs.","ex":""},"FLACK":{"p":"/flæk/","s":"v.","e":"[v.] To flutter; palpitate.\n[v.] To hang loosely; flag.\n[v.] To beat by flapping.","ex":""},"FLAG":{"p":"/flæɡ/","s":"n./v.","e":"[n.] A piece of cloth, often decorated with an emblem, used as a visual signal or symbol.\n[n.] An exact representation of a flag (for example: a digital one used in websites).\n[n.] A flag flown by a ship to show the presence on board of the admiral; the admiral himself, or his flagship.\n[v.] To furnish or deck out with flags.\n[v.] To mark with a flag, especially to indicate the importance of something.\n[v.] (often with down) To signal to, especially to stop a passing vehicle etc.","ex":"Please flag down a taxi for me."},"FLAIL":{"p":"/fleɪl/","s":"n./v.","e":"[n.] A tool used for threshing, consisting of a long handle with a shorter stick attached with a short piece of chain, thong or similar material.\n[n.] A weapon which has the (usually spherical) striking part attached to the handle with a flexible joint such as a chain.\n[v.] To beat using a flail or similar implement.\n[v.] To wave or swing vigorously\n[v.] To thresh.","ex":""},"FLAIR":{"p":"/flɛə̯/","s":"n./v.","e":"[n.] A natural or innate talent or aptitude.\n[n.] Distinctive style or elegance.\n[n.] Smell; odor.\n[v.] To add flair.","ex":"to have a flair for art"},"FLAKY":{"p":"/ˈfleɪkiː/","s":"adj.","e":"[adj.] Consisting of flakes or of small, loose masses; lying, or cleaving off, in flakes or layers; flakelike.\n[adj.] (of a person) Unreliable; likely to make plans with others but then abandon those plans.\n[adj.] (of a thing) Unreliable; working only on an intermittent basis; likely to malfunction.","ex":"I cannot enjoy the online game because of my flaky Internet connection."},"FLAME":{"p":"/fleɪm/","s":"n./v./adj.","e":"[n.] The visible part of fire; a stream of burning vapour or gas, emitting light and heat.\n[n.] A romantic partner or lover in a usually short-lived but passionate affair.\n[n.] Intentionally insulting criticism or remark meant to incite anger.\n[v.] To produce flames; to burn with a flame or blaze.\n[v.] To burst forth like flame; to break out in violence of passion; to be kindled with zeal or ardour.\n[v.] To post a destructively critical or abusive message (to somebody).","ex":"I flamed him for spamming in my favourite newsgroup."},"FLANK":{"p":"/flæŋk/","s":"n./v./adj.","e":"[n.] The flesh between the last rib and the hip; the side.\n[n.] A cut of meat from the flank of an animal.\n[n.] The extreme left or right edge of a military formation, army etc.\n[v.] To attack the flank(s) of.\n[v.] To defend the flank(s) of.\n[v.] To place to the side(s) of.","ex":"All ahead flank!"},"FLARE":{"p":"/flɛə̯/","s":"n./v.","e":"[n.] A sudden bright light.\n[n.] A source of brightly burning light or intense heat.\n[n.] A sudden eruption or outbreak; a flare-up.\n[v.] To cause to burn.\n[v.] To cause inflammation; to inflame.\n[v.] To open outward in shape.","ex":"solar flare"},"FLAW":{"p":"/ˈflɔː/","s":"n./v.","e":"[n.] A flake, fragment, or shiver.\n[n.] A thin cake, as of ice.\n[n.] A crack or breach, a gap or fissure; a defect of continuity or cohesion.\n[v.] To add a flaw to, to make imperfect or defective.\n[v.] To become imperfect or defective; to crack or break.","ex":"That vase has a flaw."},"FLEET":{"p":"/fliːt/","s":"n.","e":"[n.] A group of vessels or vehicles.\n[n.] Any group of associated items.\n[n.] A large, coordinated group of people.","ex":""},"FLESH":{"p":"/flɛʃ/","s":"n./v.","e":"[n.] The soft tissue of the body, especially muscle and fat.\n[n.] The skin of a human or animal.\n[n.] (by extension) Bare arms, bare legs, bare torso.\n[v.] To reward (a hound, bird of prey etc.) with flesh of the animal killed, to excite it for further hunting; to train (an animal) to have an appetite for flesh.\n[v.] To bury (something, especially a weapon) in flesh.\n[v.] To inure or habituate someone in or to a given practice.","ex":""},"FLEW":{"p":"/fluː/","s":"n.","e":"[n.] (chiefly plural) The thick, dangling upper lip of certain breeds of dog, or the canine equivalent of the upper lip.","ex":"The raging hound's flews were twisted upwards in an angry snarl."},"FLIER":{"p":"","s":"n./v.","e":"[n.] That which flies, as a bird or insect.\n[n.] A machine that flies.\n[n.] An airplane pilot.\n[v.] To distribute flyers (leaflets).\n[v.] To distribute flyers in (a location) or to (recipients).","ex":""},"FLINT":{"p":"/flɪnt/","s":"n./v.","e":"[n.] A hard, fine-grained quartz that fractures conchoidally and generates sparks when struck.\n[n.] A piece of flint, such as a gunflint, used to produce a spark by striking it with a firestriker.\n[n.] A small cylinder of some other material of the same function in a cigarette lighter, etc.\n[v.] To furnish or decorate an object with flint.","ex":""},"FLORA":{"p":"/ˈflɔː.ɹə/","s":"n.","e":"[n.] Plants considered as a group, especially those of a particular country, region, time, etc.\n[n.] A book describing the plants of a country, region, time, etc.\n[n.] The microorganisms that inhabit some part of the body","ex":""},"FLOUT":{"p":"/flʌʊt/","s":"n./v.","e":"[n.] The act by which something is flouted; violation of a law.\n[n.] A mockery or insult.\n[v.] To express contempt for (laws, rules, etc.) by word or action.\n[v.] To scorn.","ex":""},"FLOWN":{"p":"/ˈfləʊn/","s":"adj./v.","e":"[adj.] Suspended in the flies.\n[v.] To travel through the air, another gas or a vacuum, without being in contact with a grounded surface.\n[v.] To flee, to escape (from).\n[v.] To cause to fly (travel or float in the air): to transport via air or the like.","ex":"flown scenery"},"FLUID":{"p":"/ˈfluːɪd/","s":"n./adj.","e":"[n.] Any substance which can flow with relative ease, tends to assume the shape of its container, and obeys Bernoulli's principle; a liquid, gas or plasma.\n[n.] A liquid (as opposed to a solid or gas).\n[n.] (specifically, typically in the plural) Intravenous fluids.\n[adj.] Of or relating to fluid.\n[adj.] In a state of flux; subject to change.\n[adj.] Moving smoothly, or giving the impression of a liquid in motion.","ex":""},"FLUKE":{"p":"/fluːk/","s":"n./v.","e":"[n.] A lucky or improbable occurrence, with the implication that the occurrence could not be repeated.\n[v.] To obtain a successful outcome by pure chance.\n[v.] To fortuitously pot a ball in an unintended way.","ex":"The first goal was just a fluke."},"FLUME":{"p":"/fluːm/","s":"n./v.","e":"[n.] A ravine or gorge, usually one with water running through.\n[n.] An open channel or trough used to direct or divert liquids.\n[v.] To transport (logs of wood) by floating them along a water-filled channel or trough.","ex":""},"FLUNG":{"p":"/ˈflʌŋ/","s":"v.","e":"[v.] To move (oneself) abruptly or violently; to rush or dash.\n[v.] To throw with violence or quick movement; to hurl.\n[v.] To throw; to wince; to flounce.","ex":""},"FLUSH":{"p":"/ˈflʌʃ/","s":"n./v.","e":"[n.] A group of birds that have suddenly started up from undergrowth, trees etc.\n[v.] To cause to take flight from concealment.\n[v.] To take suddenly to flight, especially from cover.","ex":"The hunters flushed the tiger from the canebrake."},"FLYER":{"p":"","s":"n./v.","e":"[n.] That which flies, as a bird or insect.\n[n.] A machine that flies.\n[n.] An airplane pilot.\n[v.] To distribute flyers (leaflets).\n[v.] To distribute flyers in (a location) or to (recipients).","ex":""},"FOCAL":{"p":"/ˈfəʊ.kl̩/","s":"adj.","e":"[adj.] Belonging to, concerning, or located at a focus\n[adj.] Limited to a small area","ex":""},"FOGGY":{"p":"","s":"adj.","e":"[adj.] Obscured by mist or fog; unclear; hazy\n[adj.] Confused, befuddled, etc.","ex":"He was still foggy with sleep."},"FOLD":{"p":"/fəʊld/","s":"n./v.","e":"[n.] An act of folding.\n[n.] A bend or crease.\n[n.] Any correct move in origami.\n[v.] To bend (any thin material, such as paper) over so that it comes in contact with itself.\n[v.] To make the proper arrangement (in a thin material) by bending.\n[v.] To become folded; to form folds.","ex":"After two reraises in quick succession, John realised his best option was probably a fold."},"FOLIO":{"p":"/ˈfəʊljəʊ/","s":"n./v.","e":"[n.] A leaf of a book or manuscript\n[n.] A page of a book, that is, one side of a leaf of a book.\n[n.] A page number. The even folios are on the left-hand pages and the odd folios on the right-hand pages.\n[v.] To put a serial number on each folio or page of (a book); to page","ex":""},"FOLLY":{"p":"/ˈfɒli/","s":"n.","e":"[n.] Foolishness.\n[n.] Thoughtless action resulting in tragic consequence.\n[n.] A fanciful building built for purely ornamental reasons.","ex":"It'd be folly."},"FOOL":{"p":"/fuːl/","s":"n./v./adj.","e":"[n.] A person with poor judgment or little intelligence.\n[n.] A jester; a person whose role was to entertain a sovereign and the court (or lower personages).\n[n.] Someone who derives pleasure from something specified.\n[v.] To trick; to deceive\n[v.] To act in an idiotic manner; to act foolishly\n[adj.] Foolish.","ex":"The village fool threw his own shoes down the well."},"FORAY":{"p":"/ˈfɒ.ɹeɪ/","s":"n./v.","e":"[n.] A sudden or irregular incursion in border warfare; hence, any irregular incursion for war or spoils; a raid.\n[n.] A brief excursion or attempt, especially outside one's accustomed sphere.\n[v.] To scour (an area or place) for food, treasure, booty etc.\n[v.] To pillage; to ravage.","ex":""},"FORCED":{"p":"/fɔːst/","s":"v./adj.","e":"[v.] To violate (a woman); to rape.\n[v.] To exert oneself, to do one's utmost.\n[v.] To compel (someone or something) to do something.\n[v.] To stuff; to lard; to farce.\n[adj.] Obtained forcefully, not naturally.\n[adj.] Opened or accessed using force.","ex":"Her forced smile was harder and harder to keep as her critical father kept on complaining about her."},"FORD":{"p":"/fɔːd/","s":"n./v.","e":"[n.] A location where a stream is shallow and the bottom has good footing, making it possible to cross from one side to the other with no bridge, by walking, riding, or driving through the water; a crossing.\n[n.] A stream; a current.\n[v.] To cross a stream using a ford.","ex":""},"FORE":{"p":"/fɔː/","s":"n./adj./adv./int.","e":"[n.] The front; the forward part of something; the foreground.\n[adj.] Former; occurring earlier (in some order); previous.\n[adj.] Forward; situated towards the front (of something).\n[adv.] In the part that precedes or goes first; opposed to aft, after, back, behind, etc.\n[adv.] Formerly; previously; afore.\n[adv.] In or towards the bows of a ship.","ex":"The fore was painted white."},"FORGO":{"p":"/fɔːˈɡəʊ/","s":"v.","e":"[v.] To let pass, to leave alone, to let go.\n[v.] To do without, to abandon, to renounce.\n[v.] To refrain from, to abstain from, to pass up, to withgo.","ex":"I wouldn't forgo something, unless I'm convinced that it's detrimental in some way or another."},"FORK":{"p":"/fɔːk/","s":"n./v.","e":"[n.] A pronged tool having a long straight handle, used for digging, lifting, throwing etc.\n[n.] A pronged tool for use in the garden; a smaller hand fork for weeding etc., or larger for turning over the soil.\n[n.] A gallows.\n[v.] To divide into two or more branches.\n[v.] To move with a fork (as hay or food).\n[v.] To spawn a new child process in some sense duplicating the existing process.","ex":"A road, a tree, or a stream forks."},"FORUM":{"p":"/ˈfɔːɹəm/","s":"n.","e":"[n.] A place for discussion.\n[n.] A gathering for the purpose of discussion.\n[n.] A form of discussion involving a panel of presenters and often participation by members of the audience.","ex":""},"FOYER":{"p":"/ˈfoɪɘ/","s":"n.","e":"[n.] A lobby, corridor, or waiting room, used in a hotel, theater, etc.\n[n.] The crucible or basin in a furnace which receives the molten metal.\n[n.] A hostel offering accommodation and work opportunities to homeless young people.","ex":"We had a drink in the foyer waiting for the play to start."},"FREE":{"p":"/fɹiː/","s":"n./v./adj./adv.","e":"[n.] Free transfer\n[n.] The usual means of restarting play after a foul is committed, where the non-offending team restarts from where the foul was committed.\n[v.] To make free; set at liberty; release.\n[v.] To rid of something that confines or oppresses.\n[adj.] (social) Unconstrained.\n[adj.] Obtainable without any payment.","ex":"He was given free rein to do whatever he wanted."},"FREED":{"p":"/fɹiːd/","s":"v.","e":"[v.] To make free; set at liberty; release.\n[v.] To rid of something that confines or oppresses.","ex":""},"FREER":{"p":"","s":"adj./n.","e":"[adj.] (social) Unconstrained.\n[adj.] Obtainable without any payment.\n[adj.] (abstract) Unconstrained.\n[n.] One who frees.","ex":"He was given free rein to do whatever he wanted."},"FRESH":{"p":"/fɹɛʃ/","s":"n./v./adj./adv.","e":"[n.] A rush of water, along a river or onto the land; a flood.\n[n.] A stream or spring of fresh water.\n[n.] The mingling of fresh water with salt in rivers or bays, as by means of a flood of fresh water flowing toward or into the sea.\n[v.] (commercial fishing) To pack (fish) loosely on ice.\n[v.] To flood or dilute an area of salt water with flowing fresh water.\n[v.] (of wind) To become stronger.","ex":"He followed the fresh hoofprints to find the deer."},"FRIAR":{"p":"/ˈfɹaɪə/","s":"n.","e":"[n.] A member of a mendicant Christian order such as the Augustinians, Carmelites (white friars), Franciscans (grey friars) or the Dominicans (black friars).\n[n.] A white or pale patch on a printed page.\n[n.] An American fish, the silverside.","ex":""},"FRILL":{"p":"/fɹɪl/","s":"n./v.","e":"[n.] A strip of pleated fabric or paper used as decoration or trim.\n[n.] A substance or material on the edge of something, resembling such a strip of fabric.\n[n.] A wrinkled edge to a film.\n[v.] To make into a frill.\n[v.] To become wrinkled.\n[v.] To provide or decorate with a frill or frills; to turn back in crimped plaits.","ex":""},"FRITZ":{"p":"/fɹɪts/","s":"n./v.","e":"[n.] The state of being defective.\n[n.] (chiefly South Australia) A type of processed meat sausage; devon\n[v.] To go wrong or become defective.","ex":""},"FROND":{"p":"/fɹɒnd/","s":"n.","e":"[n.] The leaf of a fern, especially a compound leaf.\n[n.] Any fern-like leaf or other object resembling a fern leaf.","ex":""},"FRONT":{"p":"/fɹʌnt/","s":"n./v./adj.","e":"[n.] The foremost side of something or the end that faces the direction it normally moves.\n[n.] The side of a building with the main entrance.\n[n.] A field of activity.\n[v.] To face (on, to); to be pointed in a given direction.\n[v.] To face, be opposite to.\n[v.] To face up to, to meet head-on, to confront.","ex":"The front runner was thirty meters ahead of her nearest competitor."},"FROST":{"p":"/fɹɑst/","s":"n./v.","e":"[n.] A cover of minute ice crystals on objects that are exposed to the air. Frost is formed by the same process as dew, except that the temperature of the frosted object is below freezing.\n[n.] The cold weather that causes these ice crystals to form.\n[n.] Coldness or insensibility; severity or rigidity of character.\n[v.] To cover with frost.\n[v.] To become covered with frost.\n[v.] To coat (something, e.g. a cake) with icing to resemble frost.","ex":""},"FROTH":{"p":"/fɹɑθ/","s":"n./v.","e":"[n.] Foam\n[n.] Unimportant events or actions; drivel\n[v.] To create froth in (a liquid).\n[v.] (of a liquid) To bubble.\n[v.] To spit, vent, or eject, as froth.","ex":"Froth is a very important feature of many types of coffee."},"FROZE":{"p":"/ˈfɹəʊz/","s":"v.","e":"[v.] Especially of a liquid, to become solid due to low temperature.\n[v.] To lower something's temperature to the point that it freezes or becomes hard.\n[v.] To drop to a temperature below zero degrees celsius, where water turns to ice.","ex":"The lake froze solid."},"FRUIT":{"p":"/fɹuːt/","s":"n./v.","e":"[n.] (often in the plural) In general, a product of plant growth useful to man or animals.\n[n.] Specifically, a sweet, edible part of a plant that resembles seed-bearing fruit (see next sense), even if it does not develop from a floral ovary; also used in a technically imprecise sense for some sweet or sweetish vegetables, such as the petioles of rhubarb, that resemble a true fruit or are used in cookery as if they were a fruit.\n[n.] A product of fertilization in a plant, specifically:\n[v.] To produce fruit, seeds, or spores.","ex":""},"FUDGE":{"p":"/fʌdʒ/","s":"n./v./int.","e":"[n.] A type of very sweet candy or confection, usually made from sugar, butter, and milk or cream. Often used in the US synonymously with chocolate fudge.\n[n.] Light or frothy nonsense.\n[n.] A deliberately misleading or vague answer.\n[v.] To try to avoid giving a direct answer.\n[v.] To alter something from its true state, as to hide a flaw or uncertainty. Always deliberate, but not necessarily dishonest or immoral.\n[v.] To botch or bungle something.","ex":"Have you tried the vanilla fudge? It's delicious!"},"FUEL":{"p":"/ˈfjuːl/","s":"n./v.","e":"[n.] Substance consumed to provide energy through combustion, or through chemical or nuclear reaction.\n[n.] Substance that provides nourishment for a living organism; food.\n[n.] Something that stimulates, encourages or maintains an action.\n[v.] To provide with fuel.\n[v.] To exacerbate, to cause to grow or become greater.","ex":"His books were fuel for the revolution."},"FUGUE":{"p":"/ˈfjuːɡ/","s":"n./v.","e":"[n.] A contrapuntal piece of music wherein a particular melody is played in a number of voices, each voice introduced in turn by playing the melody.\n[n.] Anything in literature, poetry, film, painting, etc., that resembles a fugue in structure or in its elaborate complexity and formality.\n[n.] A fugue state.\n[v.] To improvise, in singing, by introducing vocal ornamentation to fill gaps etc.","ex":""},"FULL":{"p":"/fʊl/","s":"adj./adv.","e":"[adj.] Containing the maximum possible amount that can fit in the space available.\n[adj.] Complete; with nothing omitted.\n[adj.] Total, entire.\n[adv.] Fully; quite; very; thoroughly; completely; exactly; entirely.","ex":"The jugs were full to the point of overflowing."},"FULLY":{"p":"/ˈfʊli/","s":"adv.","e":"[adv.] In a full manner; without lack or defect.\n[adv.] In a full degree; to a full extent.\n[adv.] As a minimum; at least.","ex":"He fully met his responsibilities."},"FUND":{"p":"/ˈfʌnd/","s":"n./v.","e":"[n.] A sum or source of money.\n[n.] An organization managing such money.\n[n.] A money-management operation, such as a mutual fund.\n[v.] To pay for.\n[v.] To place (money) in a fund.\n[v.] To form a debt into a stock charged with interest.","ex":"a fund for the maintenance of underprivileged students"},"FUNNY":{"p":"/ˈfʊnɪ/","s":"n./adj./adv.","e":"[n.] A joke.\n[n.] A comic strip.\n[adj.] Amusing; humorous; comical.\n[adj.] Strange or unusual, often implying unpleasant.\n[adj.] Showing unexpected resentment.\n[adv.] In an unusual manner; strangely.","ex":"When I went to the circus, I only found the clowns funny."},"FUROR":{"p":"/ˈfjɜɹə/","s":"n.","e":"[n.] A general uproar or commotion\n[n.] Violent anger or frenzy\n[n.] A state of intense excitement","ex":""},"FURRY":{"p":"/ˈfɜːɹi/","s":"n./adj.","e":"[n.] An animal character with human-like characteristics; most commonly refers to such characters created by members of the furry subculture.\n[n.] A member of the furry fandom.\n[n.] Someone who roleplays or identifies with a furry character. (Compare therianthrope.)\n[adj.] Covered with fur, or with something resembling fur.\n[adj.] Of or related to the furry subculture.","ex":"What percentage of furries are wolves?"},"FURTHER":{"p":"/fɜː(ɹ)ðə(ɹ)/","s":"v./adj./adv.","e":"[v.] To help forward; to assist.\n[v.] To encourage growth; to support progress or growth of something; to promote.\n[adj.] (comparative form of far) More distant; relatively distant.\n[adj.] More, additional.\n[adv.] (comparative form of far) To, at or over a greater distance in space, time or other extent.\n[adv.] (comparative form of far) To a greater extent or degree.","ex":"Further the economy."},"GAFFE":{"p":"/ɡæf/","s":"n.","e":"[n.] A foolish and embarrassing error, especially one made in public.","ex":""},"GAILY":{"p":"/ˈɡeɪli/","s":"adv.","e":"[adv.] Merrily.\n[adv.] Showily.","ex":""},"GAMER":{"p":"/ˈɡeɪmɚ/","s":"n.","e":"[n.] A person who plays any kind of game.\n[n.] A person whose hobby is video games.\n[n.] A person who games the system.","ex":""},"GAUDY":{"p":"/ˈɡɔː.di/","s":"n./adj.","e":"[n.] One of the large beads in the rosary at which the paternoster is recited.\n[adj.] Very showy or ornamented, now especially when excessive, or in a tasteless or vulgar manner\n[adj.] Fun; merry; festive","ex":""},"GAUZE":{"p":"/ɡɔːz/","s":"n./v.","e":"[n.] A thin fabric with a loose, open weave.\n[n.] A similar bleached cotton fabric used as a surgical dressing.\n[n.] A thin woven metal or plastic mesh.\n[v.] To apply a dressing of gauze\n[v.] To mist; to become gauze-like.","ex":""},"GENE":{"p":"/dʒiːn/","s":"n.","e":"[n.] A theoretical unit of heredity of living organisms; a gene may take several values and in principle predetermines a precise trait of an organism's form (phenotype), such as hair color.\n[n.] A segment of DNA or RNA from a cell's or an organism's genome, that may take several forms and thus parameterizes a phenomenon, in general the structure of a protein; locus.","ex":"A change in a gene is reflected in the protein or RNA molecule that it codes for."},"GHOST":{"p":"/ɡəʊst/","s":"n./v.","e":"[n.] The spirit; the soul of man.\n[n.] The disembodied soul; the soul or spirit of a deceased person; a spirit appearing after death\n[n.] Any faint shadowy semblance; an unsubstantial image\n[v.] To haunt; to appear to in the form of an apparition.\n[v.] To die; to expire.\n[v.] To ghostwrite.","ex":"Everyone believed that the ghost of an old lady haunted the crypt."},"GIANT":{"p":"/ˈdʒaɪ.ənt/","s":"n./adj.","e":"[n.] A mythical human of very great size.\n[n.] Specifically, any of the gigantes, the race of giants in the Greek mythology.\n[n.] A very tall and large person.\n[adj.] Very large.","ex":""},"GIFT":{"p":"/ɡɪft/","s":"n./v.","e":"[n.] Something given to another voluntarily, without charge.\n[n.] A talent or natural ability.\n[n.] Something gained incidentally, without effort.\n[v.] To give as a gift or donation.\n[v.] To give away, to concede easily.","ex":"She had a gift for playing the flute."},"GLOSS":{"p":"/ɡlɑs/","s":"n./v.","e":"[n.] A surface shine or luster/lustre\n[n.] A superficially or deceptively attractive appearance\n[v.] To give a gloss or sheen to.\n[v.] To make (something) attractive by deception\n[v.] To become shiny.","ex":""},"GONAD":{"p":"/ˈɡəʊ.næd/","s":"n.","e":"[n.] A sex organ that produces gametes; specifically, a testicle or ovary.\n[n.] (chiefly in the plural) The testicles.","ex":""},"GRIND":{"p":"/ˈɡɹaɪnd/","s":"n./v.","e":"[n.] The act of reducing to powder, or of sharpening, by friction.\n[n.] Something that has been reduced to powder, something that has been ground.\n[n.] A specific degree of pulverization of coffee beans.\n[v.] To reduce to smaller pieces by crushing with lateral motion.\n[v.] To shape with the force of friction.\n[v.] To remove material by rubbing with an abrasive surface.","ex":"This bag contains espresso grind."},"GROIN":{"p":"/ɡɹɔɪn/","s":"n./v.","e":"[n.] The crease or depression of the human body at the junction of the trunk and the thigh, together with the surrounding region.\n[n.] The area adjoining this fold or depression.\n[n.] The projecting solid angle formed by the meeting of two vaults\n[v.] To deliver a blow to the genitals of.\n[v.] To build with groins.\n[v.] (literary) To hollow out, to excavate.","ex":"He pulled a muscle in his groin."},"HARDY":{"p":"/ˈhɑːdi/","s":"n./adj.","e":"[n.] (usually in the plural) Anything, especially a plant, that is hardy.\n[n.] A blacksmith's fuller or chisel, having a square shank for insertion into a square hole in an anvil, called the hardy hole.\n[adj.] Having rugged physical strength; inured to fatigue or hardships.\n[adj.] Able to survive adverse growing conditions.\n[adj.] Brave and resolute.","ex":"A hardy plant is one that can withstand the extremes of climate, such as frost."},"HYENA":{"p":"/haɪˈiːnə/","s":"n.","e":"[n.] Any of the medium-sized to large feliform carnivores of the subfamily Hyaeninae (genera Hyaena and Crocuta), native to Africa and Asia and noted for the sound similar to laughter which they can make if excited.\n[n.] (Sub-Saharan Africa) A man that performs ritualized sex acts with recently widowed women and menarchal girls.","ex":""},"INERT":{"p":"/ɪnˈɝt/","s":"n./v./adj.","e":"[n.] A substance that does not react chemically.\n[v.] To fill with an inert gas to reduce the risk of explosion.\n[adj.] Unable to move or act; inanimate.\n[adj.] In chemistry, not readily reacting with other elements or compounds.\n[adj.] Having no therapeutic action.","ex":""},"INLAND":{"p":"/ˈɪnlənd/","s":"n./adj./adv.","e":"[n.] The interior part of a country.\n[adj.] Within the land; relatively remote from the ocean or from open water; interior\n[adj.] Limited to the land, or to inland routes; within the seashore boundary; not passing on, or over, the sea\n[adj.] Confined to a country or state; domestic; not foreign.\n[adv.] Into, or towards, the interior of the land, away from the coast.","ex":"an inland town"},"INTEND":{"p":"/ɪnˈtɛnd/","s":"v.","e":"[v.] (usually followed by the particle \"to\") To hope; to wish (something, or something to be accomplished); be intent upon\n[v.] To fix the mind on; attend to; take care of; superintend; regard.\n[v.] To stretch to extend; distend.","ex":"He intends to go to university."},"LEFT":{"p":"/lɛft/","s":"n./adj./adv.","e":"[n.] The left side or direction.\n[n.] The ensemble of left-wing political parties. Those holding left-wing views as a group.\n[n.] The left hand or fist.\n[adj.] The opposite of right; toward the west when one is facing north.\n[adj.] Pertaining to the political left.\n[adv.] On the left side.","ex":"The political left is holding too much power."},"LENGTH":{"p":"/lɛn(t)θ/","s":"n./v.","e":"[n.] The distance measured along the longest dimension of an object.\n[n.] Duration.\n[n.] The length of a horse, used to indicate the distance between horses at the end of a race.\n[v.] To lengthen.","ex":""},"LIBERTY":{"p":"/ˈlɪbɚti/","s":"n.","e":"[n.] The condition of being free from control or restrictions.\n[n.] The condition of being free from imprisonment, slavery or forced labour.\n[n.] The condition of being free to act, believe or express oneself as one chooses.","ex":"The army is here, your liberty is assured."},"LICENSE":{"p":"/ˈlaɪsəns/","s":"n./v.","e":"[n.] A legal document giving official permission to do something; a permit.\n[n.] The legal terms under which a person is allowed to use a product, especially software.\n[n.] Freedom to deviate deliberately from normally applicable rules or practices (especially in behaviour or speech).\n[v.] To give a formal (usually written) authorization.\n[v.] Authorize officially.","ex":"It was decided to license Wikipedia under the GFDL."},"LIEGE":{"p":"/liːdʒ/","s":"n./adj.","e":"[n.] A free and independent person; specifically, a lord paramount; a sovereign.\n[n.] (in full liege lord) A king or lord.\n[n.] The subject of a sovereign or lord; a liegeman.\n[adj.] Sovereign; independent; having authority or right to allegiance.\n[adj.] Serving an independent sovereign or master; bound by a feudal tenure; obliged to be faithful and loyal to a superior, such as a vassal to his lord; faithful.\n[adj.] Full; perfect; complete; pure.","ex":"a liege lord"},"LIFER":{"p":"","s":"n.","e":"[n.] A prisoner sentenced to life in prison.\n[n.] A prisoner sentenced to transportation for life.\n[n.] A person with a singular career path, especially in the military.","ex":""},"LIKE":{"p":"/laɪk/","s":"n./v.","e":"[n.] (usually in the plural) Something that a person likes (prefers).\n[n.] An individual vote showing support for, or approval of, something posted on the Internet.\n[v.] To enjoy, be pleased by; favor; be in favor of.\n[v.] To please.\n[v.] To derive pleasure of, by or with someone or something.","ex":"Tell me your likes and dislikes."},"LIKEN":{"p":"/ˈlaɪkən/","s":"v.","e":"[v.] (followed by to or unto) To compare; to state that (something) is like (something else).","ex":"The physics teacher likened the effect of mass on space to an indentation in a sheet of rubber."},"LIMBS":{"p":"/lɪmz/","s":"n./v.","e":"[n.] A major appendage of human or animal, used for locomotion (such as an arm, leg or wing).\n[n.] A branch of a tree.\n[n.] The part of the bow, from the handle to the tip.\n[v.] To remove the limbs from (an animal or tree).\n[v.] To supply with limbs.\n[n.] The apparent visual edge of a celestial body.","ex":"They limbed the felled trees before cutting them into logs."},"LIMITED":{"p":"/ˈlɪmɪtɪd/","s":"v./n./adj.","e":"[v.] To restrict; not to allow to go beyond a certain bound, to set boundaries.\n[v.] To have a limit in a particular set.\n[v.] To beg, or to exercise functions, within a certain limited region.\n[n.] An express train that only halts at a limited number of stops.\n[adj.] With certain (often specified) limits placed upon it.\n[adj.] Of numbers, amounts, data: poor, small, felt to be insufficient.","ex":"I'm limiting myself to two drinks tonight."},"NADIR":{"p":"/neɪˈdɪə(ɹ)/","s":"n./v.","e":"[n.] The point of the celestial sphere, directly opposite the zenith; inferior pole of the horizon; point of the celestial sphere directly under the place of observation.\n[n.] The lowest point; time of greatest depression.\n[n.] The axis of a projected conical shadow; the direction of the force of gravity at a location; down.\n[v.] To extend (a beehive) by adding an empty box at the base.","ex":"The nadir of the sun is the axis of the shadow projected by the Earth."},"NAIL":{"p":"/neɪl/","s":"n.","e":"[n.] The thin, horny plate at the ends of fingers and toes on humans and some other animals.\n[n.] The basal thickened portion of the anterior wings of certain hemiptera.\n[n.] The terminal horny plate on the beak of ducks, and other allied birds.","ex":"When I'm nervous I bite my nails."},"NAMELY":{"p":"/ˈneɪmli/","s":"adv.","e":"[adv.] Specifically; that is to say.\n[adv.] Especially, above all.","ex":"Some of the students — namely Paul, Alice and Jake — seem to have trouble with geometry."},"NARROW":{"p":"/ˈnæɹəʊ/","s":"n./adj.","e":"[n.] (chiefly in the plural) A narrow passage, especially a contracted part of a stream, lake, or sea; a strait connecting two bodies of water.\n[adj.] Having a small width; not wide; having opposite edges or sides that are close, especially by comparison to length or depth.\n[adj.] Of little extent; very limited; circumscribed.\n[adj.] Restrictive; without flexibility or latitude.","ex":"the narrows of New York harbor"},"NASAL":{"p":"/ˈneɪzəl/","s":"n./adj.","e":"[n.] A medicine that operates through the nose; an errhine.\n[n.] A vowel or consonant (such as [m] or [n]) articulated with air flowing through the nose.\n[n.] Part of a helmet projecting to protect the nose; a nose guard.\n[adj.] Of or pertaining to the nose or to the nasion\n[adj.] Having a sound imparted by means of the nose; and specifically, made by lowering the soft palate, in some cases with closure of the oral passage, the voice thus issuing (wholly or partially) through the nose, as in the consonants m, n, ng; characterized by resonance in the nasal passage","ex":"a nasal utterance."},"NASTY":{"p":"/ˈnaː.sti/","s":"n./adj.","e":"[n.] Something nasty.\n[n.] (preceded by \"the\") Sexual intercourse.\n[n.] A video nasty.\n[adj.] Dirty, filthy.\n[adj.] Contemptible, unpleasant (of a person).\n[adj.] Objectionable, unpleasant (of a thing); repellent, offensive.","ex":"Processed foods are full of aspartame and other nasties."},"NATION":{"p":"/ˈneɪ.ʃən/","s":"n.","e":"[n.] A historically constituted, stable community of people, formed on the basis of a common language, territory, economic life, ethnicity and/or psychological make-up manifested in a common culture.\n[n.] A sovereign state.\n[n.] An association of students based on its members' birthplace or ethnicity.","ex":"The Kurdish people constitute a nation in the Middle East"},"NATURE":{"p":"/ˈnæɪ̯tʃə/","s":"n./v.","e":"[n.] The natural world; that which consists of all things unaffected by or predating human technology, production, and design. (Compare ecosystem.)\n[n.] The innate characteristics of a thing. What something will tend by its own constitution, to be or do. Distinct from what might be expected or intended.\n[n.] The summary of everything that has to do with biological, chemical and physical states and events in the physical universe.\n[v.] To endow with natural qualities.","ex":"Nature never lies (i.e. tells untruths)."},"NAVY":{"p":"/ˈneɪvi/","s":"n./adj.","e":"[n.] A country's entire sea force, including ships and personnel.\n[n.] A governmental department in charge of a country's sea force.\n[n.] A dark blue colour, usually called navy blue.\n[adj.] Having the dark blue colour of navy blue.\n[adj.] Belonging to the navy; typical of the navy.","ex":""},"NEAR":{"p":"/nɪə(ɹ)/","s":"n./v./adj./adv./prep.","e":"[n.] The left side of a horse or of a team of horses pulling a carriage etc.\n[v.] To come closer to; to approach.\n[adj.] Physically close.\n[adj.] Close in time.\n[adj.] Closely connected or related.\n[adv.] At or towards a position close in space or time.","ex":"The ship nears the land."},"NEAT":{"p":"/niːt/","s":"n./adj.","e":"[n.] An artificial intelligence researcher who believes that solutions should be elegant, clear and provably correct. Compare scruffy.\n[adj.] Clean, tidy; free from dirt or impurities.\n[adj.] Free from contaminants; unadulterated, undiluted. Particularly of liquor and cocktails; see usage below.\n[adj.] Conditions with a liquid reagent or gas performed with no standard solvent or cosolvent.","ex":"My room is neat because I tidied it this morning.  She has very neat hair."},"NEEDS":{"p":"/niːdz/","s":"adv.","e":"[adv.] Of necessity; necessarily; indispensably; used with an auxiliary verb (often must), and equivalent to \"of need\".","ex":"One must needs run when the devil drives."},"NEIGH":{"p":"/neɪ/","s":"n./v.","e":"[n.] The cry of a horse.\n[v.] (of a horse) To make its cry.\n[v.] To make a sound similar to a horse's cry.\n[v.] To scoff or sneer.","ex":""},"PAIR":{"p":"/pɛə(ɹ)/","s":"n./v.","e":"[n.] Two similar or identical things taken together; often followed by of.\n[n.] Two people in a relationship, partnership or friendship.\n[n.] Used with binary nouns (often in the plural to indicate multiple instances, since such nouns are plural only, except in some technical contexts)\n[v.] To group into one or more sets of two.\n[v.] To bring two (animals, notably dogs) together for mating.\n[v.] To engage (oneself) with another of opposite opinions not to vote on a particular question or class of questions.","ex":"I couldn't decide which of the pair of designer shirts I preferred, so I bought the pair."},"PALER":{"p":"","s":"adj.","e":"[adj.] Light in color.\n[adj.] (of human skin) Having a pallor (a light color, especially due to sickness, shock, fright etc.).\n[adj.] Feeble, faint.","ex":"I have pale yellow wallpaper."},"PANIC":{"p":"/ˈpænɪk/","s":"n./v./adj.","e":"[n.] Overpowering fright, often affecting groups of people or animals.\n[n.] Rapid reduction in asset prices due to broad efforts to raise cash in anticipation of continuing decline in asset prices.\n[n.] A kernel panic or system crash.\n[v.] To feel overwhelming fear.\n[v.] To cause somebody to panic.\n[v.] (by extension) To crash.","ex":""},"PANTY":{"p":"","s":"n.","e":"[n.] (in the plural) Short trousers for men, or more usually boys.\n[n.] (usually in the plural, or in compounds) An article of clothing worn as underpants by women.\n[n.] A helmet cover.","ex":"pantyhose"},"PAPER":{"p":"/ˈpeɪpə/","s":"n./v./adj.","e":"[n.] A sheet material used for writing on or printing on (or as a non-waterproof container), usually made by draining cellulose fibres from a suspension in water.\n[n.] A newspaper or anything used as such (such as a newsletter or listing magazine).\n[n.] Wallpaper.\n[v.] To apply paper to.\n[v.] To document; to memorialize.\n[v.] To fill (a theatre or other paid event) with complimentary seats.","ex":"to paper the hallway walls"},"PARED":{"p":"","s":"v.","e":"[v.] To remove the outer covering or skin of something with a cutting device, typically a knife\n[v.] (often with down or back) to reduce, diminish or trim gradually something as if by cutting off\n[v.] To trim the hoof of a horse","ex":"Victor pared some apples in preparation to make a tart."},"PAST":{"p":"/pɑːst/","s":"v./n./adj./adv./prep.","e":"[v.] To change place.\n[v.] To change in state or status\n[v.] To move through time.\n[n.] The period of time that has already happened, in contrast to the present and the future.\n[n.] (grammar) The past tense.\n[adj.] Having already happened; in the past; finished.","ex":"a book about a time machine that can transport people back into the past"},"PASTE":{"p":"/peɪst/","s":"n./v.","e":"[n.] A soft moist mixture, in particular:\n[n.] A substance that behaves as a solid until a sufficiently large load or stress is applied, at which point it flows like a fluid\n[n.] A hard lead-containing glass, or an artificial gemstone made from this glass.\n[v.] To stick with paste; to cause to adhere by or as if by paste.\n[v.] To insert a piece of media (e.g. text, picture, audio, video) previously copied or cut from somewhere else.\n[v.] To strike or beat someone or something.","ex":""},"PASTY":{"p":"/ˈpeɪsti/","s":"n./adj.","e":"[n.] (chiefly in the plural) A small item of clothing that conceals little more than the nipple of a woman's breast, primarily worn by female exotic dancers.\n[adj.] Like paste, sticky.\n[adj.] Pale, lacking colour, having a pallor\n[adj.] White-skinned","ex":"These mashed potatoes aren’t cooked well; they are very pasty."},"PRINTER":{"p":"/ˈpɹɪntə(ɹ)/","s":"n.","e":"[n.] One who makes prints.\n[n.] The operator of a printing press, or the owner of a printing business.\n[n.] A device, usually attached to a computer, used to print text or images onto paper; an analogous device capable of producing three-dimensional objects.","ex":""},"PRISON":{"p":"/ˈpɹɪzən/","s":"n./v.","e":"[n.] A place or institution of confinement, especially of long-term confinement for those convicted of serious crimes or otherwise considered undesirable by the government.\n[n.] Confinement in prison.\n[n.] Any restrictive environment, such as a harsh academy or home.\n[v.] To imprison.","ex":"The cold stone walls of the prison had stood for over a century."},"PROFIT":{"p":"/ˈpɹɒfɪt/","s":"n./v.","e":"[n.] Total income or cash flow minus expenditures. The money or other benefit a non-governmental organization or individual receives in exchange for products and services sold at an advertised price.\n[n.] Benefit, positive result obtained.\n[n.] In property law, a nonpossessory interest in land whereby a party is entitled to enter the land of another for the purpose of taking the soil or the substance of the soil (coal, oil, minerals, and in some jurisdictions timber and game).\n[v.] To benefit (somebody), be of use to (somebody).\n[v.] (construed with from) To benefit, gain.\n[v.] (construed with from) To take advantage of, exploit, use.","ex":"Reading such an enlightening book on the subject was of much profit to his studies."},"PROGRAM":{"p":"/ˈpɹoʊˌɡɹæm/","s":"n./v.","e":"[n.] A set of structured activities.\n[n.] A leaflet listing information about a play, game or other activity.\n[n.] A performance of a show or other broadcast on radio or television.\n[v.] To enter a program or other instructions into (a computer or other electronic device) to instruct it to do a particular task.\n[v.] To develop (software) by writing program code.\n[v.] To put together the schedule of an event.","ex":"Our program for today’s exercise class includes swimming and jogging."},"PRONG":{"p":"/pɹɒŋ/","s":"n./v.","e":"[n.] A thin, pointed, projecting part, as of an antler or a fork or similar tool. A tine.\n[n.] A branch; a fork.\n[n.] The penis.\n[v.] To pierce or poke with, or as if with, a prong","ex":"a pitchfork with four prongs"},"PRUDE":{"p":"/pɹuːd/","s":"n./adj.","e":"[n.] A person who is or tries to be excessively proper, especially one who is easily offended by matters of a sexual nature.\n[adj.] Prudish.","ex":""},"PUBLIC":{"p":"/ˈpʌblɪk/","s":"n./adj.","e":"[n.] The people in general, regardless of membership of any particular group.\n[n.] A public house; an inn.\n[adj.] Able to be seen or known by everyone; open to general view, happening without concealment.\n[adj.] Pertaining to the people as a whole (as opposed to a private group); concerning the whole country, community etc.\n[adj.] Officially representing the community; carried out or funded by the state on behalf of the community.","ex":"Members of the public may not proceed beyond this point."},"PUBLISH":{"p":"/ˈpʌblɪʃ/","s":"v.","e":"[v.] To issue (something, such as printed work) for distribution and/or sale.\n[v.] To announce to the public.\n[v.] To issue the work of (an author).","ex":"Most of the sketches Faulkner published in 1925 appeared in the Sunday magazine section of the New Orleans Times-Picayune."},"PULL":{"p":"/pʊl/","s":"n./v./int.","e":"[n.] An act of pulling (applying force)\n[n.] An attractive force which causes motion towards the source\n[n.] Any device meant to be pulled, as a lever, knob, handle, or rope\n[v.] To apply a force to (an object) so that it comes toward the person or thing applying the force.\n[v.] To gather with the hand, or by drawing toward oneself; to pluck.\n[v.] To attract or net; to pull in.","ex":"He gave the hair a sharp pull and it came out."},"PUNNY":{"p":"","s":"n./adj.","e":"[n.] A punishment.\n[adj.] (of a pun) Funny.\n[adj.] Involving the use of a pun.\n[adj.] (of a person) Who makes puns.","ex":""},"RARER":{"p":"","s":"adj.","e":"[adj.] Very uncommon; scarce.\n[adj.] (of a gas) Thin; of low density.\n[adj.] Good; enjoyable.\n[adj.] (particularly meats) Cooked very lightly, so the meat is still red (in the case of steak or beef in the general sense).","ex":"Black pearls are very rare and therefore very valuable."},"RASP":{"p":"","s":"n./v.","e":"[n.] A coarse file, on which the cutting prominences are distinct points raised by the oblique stroke of a sharp punch, instead of lines raised by a chisel, as on the true file.\n[n.] The sound made by this tool when used, or any similar sound.\n[v.] To use a rasp.\n[v.] To make a noise similar to the one a rasp makes in use; to utter rasps.\n[v.] To work something with a rasp.","ex":"the rasp of her perpetual cough"},"RAVEN":{"p":"/ˈɹeɪvən/","s":"n./adj.","e":"[n.] Any of several, generally large and lustrous black species of birds in the genus Corvus, especially the common raven, Corvus corax.\n[n.] A jet-black colour.\n[adj.] Of the color of the raven; jet-black","ex":"She was a tall, sophisticated, raven-haired beauty."},"REAPS":{"p":"/ɹiːps/","s":"v.","e":"[v.] To cut (for example a grain) with a sickle, scythe, or reaping machine\n[v.] To gather (e.g. a harvest) by cutting.\n[v.] To obtain or receive as a reward, in a good or a bad sense.","ex":"to reap a benefit from exertions"},"RIVED":{"p":"/ɹaɪvd/","s":"v.","e":"[v.] To tear apart by force; to rend; to split; to cleave.\n[v.] To pierce or cleave with a weapon.","ex":""},"RODEO":{"p":"/ɹoʊ.ˈdeɪ.oʊ/","s":"n./v.","e":"[n.] A gathering of cattle to be branded.\n[n.] A North American sport involving skills with horses, cows and other livestock.\n[n.] An entertainment event associated with the sport.\n[v.] To perform in a rodeo show.","ex":""},"ROLL":{"p":"/ɹəʊl/","s":"n./v.","e":"[n.] The act or result of rolling, or state of being rolled.\n[n.] A forward or backward roll in gymnastics; going head over heels. A tumble.\n[n.] Something which rolls.\n[v.] To cause to revolve by turning over and over; to move by turning on an axis; to impel forward by causing to turn over and over on a supporting surface.\n[v.] To turn over and over.\n[v.] To tumble in gymnastics; to do a somersault.","ex":"Look at the roll of the waves."},"ROMAN":{"p":"/ˈɹəʊmən/","s":"n./adj.","e":"[n.] One of the main three types used for the Latin alphabet (the others being italics and blackletter), in which the ascenders are mostly straight.\n[n.] A novel.\n[adj.] (of type) upright, as opposed to italic\n[adj.] (of text) of or related to the Latin alphabet","ex":""},"ROOFS":{"p":"/ɹuːfs/","s":"n./v.","e":"[n.] The external covering at the top of a building.\n[n.] The top external level of a building.\n[n.] The upper part of a cavity.\n[v.] To cover or furnish with a roof.\n[v.] To traverse buildings by walking or climbing across their roofs.\n[v.] To put into prison, to bird.","ex":"The roof was blown off by the tornado."},"ROOT":{"p":"/ɹuːt/","s":"n./v.","e":"[n.] The part of a plant, generally underground, that anchors and supports the plant body, absorbs and stores water and nutrients, and in some plants is able to perform vegetative reproduction.\n[n.] A root vegetable.\n[n.] The part of a tooth extending into the bone holding the tooth in place.\n[v.] To grow roots; to enter the earth, as roots; to take root and begin to grow.\n[v.] To prepare, oversee, or otherwise cause the rooting of cuttings\n[v.] To be firmly fixed; to be established.","ex":"This tree's roots can go as deep as twenty metres underground."},"ROOTS":{"p":"/ɹuːts/","s":"n.","e":"[n.] The part of a plant, generally underground, that anchors and supports the plant body, absorbs and stores water and nutrients, and in some plants is able to perform vegetative reproduction.\n[n.] A root vegetable.\n[n.] The part of a tooth extending into the bone holding the tooth in place.\n[n.] An act of sexual intercourse.\n[n.] A sexual partner.\n[n.] Ancestry.","ex":"This tree's roots can go as deep as twenty metres underground."},"ROTOR":{"p":"/ˈɹəʊ.tə/","s":"n.","e":"[n.] A rotating part of a mechanical device, for example in an electric motor, generator, alternator or pump.\n[n.] The wing of a helicopter or similar aircraft.\n[n.] A quantity having magnitude, direction and position.","ex":""},"ROUGH":{"p":"/ɹʌf/","s":"n./v./adj./adv.","e":"[n.] The unmowed part of a golf course.\n[n.] A rude fellow; a coarse bully; a rowdy.\n[n.] A scuffed and roughened area of the pitch, where the bowler's feet fall, used as a target by spin bowlers because of its unpredictable bounce.\n[v.] To create in an approximate form.\n[v.] To commit the offense of roughing, i.e. to punch another player.\n[v.] To render rough; to roughen.","ex":"Rough in the shape first, then polish the details."},"ROUTS":{"p":"[ɹʌʊts]","s":"n./v.","e":"[n.] A noise, especially a loud one\n[n.] A disturbance; tumult.\n[n.] Snoring.\n[v.] To make a noise; roar; bellow; snort.\n[v.] To snore, especially loudly.\n[v.] To belch.","ex":""},"ROVER":{"p":"/ˈɹəʊvə(ɹ)/","s":"n.","e":"[n.] (usually in the plural) A randomly selected target.\n[n.] One who roves, a wanderer, a nomad.\n[n.] A vagabond, a tramp, an unsteady, restless person, one who by habit doesn't settle down or marry.","ex":"She is a rover and dislikes any sort of ties, physical or emotional."},"SEEM":{"p":"/siːm/","s":"v.","e":"[v.] To appear; to look outwardly; to be perceived as.\n[v.] To befit; to beseem.","ex":"He seems to be ill.   Her eyes seem blue.   It seems like it is going to rain later.   How did she seem to you?"},"SEIZE":{"p":"/siːz/","s":"v.","e":"[v.] To deliberately take hold of; to grab or capture.\n[v.] To take advantage of (an opportunity or circumstance).\n[v.] To take possession of (by force, law etc.).","ex":"to seize a ship after libeling"},"SELLER":{"p":"/ˈsɛlə/","s":"n.","e":"[n.] Someone who sells; a vendor; a clerk.\n[n.] Something which sells.","ex":"Alisha was a seller of fine books."},"SEND":{"p":"/sɛnd/","s":"n./v.","e":"[n.] The rising motion of water as a wave passes; a surge; the upward angular displacement of a vessel, opposed to pitch, the correlative downward movement.\n[n.] An operation in which data is transmitted.\n[n.] A messenger, especially one sent to fetch the bride.\n[n.] A callout or diss usually aimed at a specific person, often in the form of a diss track.\n[v.] To make something (such as an object or message) go from one place to another.\n[v.] To excite, delight, or thrill (someone).","ex":"Every day at two o'clock, he sends his secretary out to buy him a coffee."},"SICK":{"p":"/sɪk/","s":"n./v./adj.","e":"[n.] Sick people in general as a group.\n[n.] Vomit.\n[v.] To vomit.\n[v.] To fall sick; to sicken.\n[adj.] Having an urge to vomit.\n[adj.] In poor health.","ex":"We have to cure the sick."},"SILK":{"p":"/sɪlk/","s":"n./v.","e":"[n.] A fine fiber excreted by the silkworm or other arthropod (such as a spider).\n[n.] A fine, soft cloth woven from silk fibers.\n[n.] Anything which resembles silk, such as the filiform styles of the female flower of maize, or the seed covering of bombaxes.\n[v.] To remove the silk from (corn).","ex":"The thread made of silk was barely visible."},"SILKS":{"p":"","s":"n./v.","e":"[n.] A fine fiber excreted by the silkworm or other arthropod (such as a spider).\n[n.] A fine, soft cloth woven from silk fibers.\n[n.] Anything which resembles silk, such as the filiform styles of the female flower of maize, or the seed covering of bombaxes.\n[v.] To remove the silk from (corn).","ex":"The thread made of silk was barely visible."},"SILLY":{"p":"/ˈsɪli/","s":"n./adj./adv.","e":"[n.] A silly person.\n[n.] A term of address.\n[n.] A mistake.\n[adj.] Laughable or amusing through foolishness or a foolish appearance.\n[adj.] Blessed, particularly:\n[adj.] Pitiful, inspiring compassion, particularly:","ex":""},"SPACE":{"p":"/speɪs/","s":"n./v.","e":"[n.] (heading) Of time.\n[n.] (heading) Unlimited or generalized extent, physical or otherwise.\n[n.] (heading) A bounded or specific extent, physical or otherwise.\n[v.] To roam, walk, wander.\n[v.] To set some distance apart.\n[v.] To insert or utilise spaces in a written text.","ex":""},"SPELT":{"p":"/ˈspɛlt/","s":"v.","e":"[v.] To read (something) as though letter by letter; to peruse slowly or with effort.\n[v.] (sometimes with “out”) To write or say the letters that form a word or part of a word.\n[v.] To be able to write or say the letters that form words.\n[v.] To work in place of (someone).\n[v.] To rest (someone or something), to give someone or something a rest or break.\n[v.] To rest from work for a time.","ex":"I find it difficult to spell because I'm dyslexic."},"STATS":{"p":"","s":"n.","e":"[n.] A mathematical science concerned with data collection, presentation, analysis, and interpretation.\n[n.] A systematic collection of data on measurements or observations, often related to demographic information such as population counts, incomes, population counts at different ages, etc.\n[n.] Attributes of a unit in a game (e.g. health, damage output)","ex":"Statistics is the only mathematical field required for many social sciences."},"STEAK":{"p":"/steɪk/","s":"n./v.","e":"[n.] Beefsteak, a slice of beef, broiled or cut for broiling.\n[n.] (by extension) A relatively large, thick slice or slab cut from another animal, a vegetable, etc.\n[n.] (seafood) A slice of meat cut across the grain (perpendicular to the spine) from a fish.\n[v.] To cook (something, especially fish) like or as a steak.","ex":""},"SUMMER":{"p":"/ˈsʌmə(ɹ)/","s":"n./v.","e":"[n.] One of four seasons, traditionally the second, marked by the longest and typically hottest days of the year due to the inclination of the Earth and thermal lag. Typically regarded as being from June 21 to September 22 or 23 in parts of the USA, the months of June, July and August in the United Kingdom and the months of December, January and February in the Southern Hemisphere.\n[n.] Year; used to give the age of a person, usually a young one.\n[n.] Someone with light, pinkish skin that has a blue undertone, light hair and eyes, seen as best suited to certain colors of clothing.\n[v.] To spend the summer, as in a particular place on holiday.","ex":"the heat of summer"},"SWOOP":{"p":"/ˈswuːp/","s":"n./v.","e":"[n.] An instance, or the act of suddenly plunging downward.\n[n.] A sudden act of seizing.\n[n.] A quick passage from one note to the next.\n[v.] To fly or glide downwards suddenly; to plunge (in the air) or nosedive.\n[v.] To move swiftly, as if with a sweeping movement, especially to attack something.\n[v.] To fall on at once and seize; to catch while on the wing.","ex":"The quality of decision is like the well-timed swoop of a falcon which enables it to strike and destroy its victim. – Sun Tzu"},"TENOR":{"p":"/tɛnə(ɹ)/","s":"n./adj.","e":"[n.] A musical range or section higher than bass and lower than alto.\n[n.] A person, instrument or group that performs in the tenor (higher than bass and lower than alto) range.\n[n.] A musical part or section that holds or performs the main melody, as opposed to the contratenor bassus and contratenor altus, who perform countermelodies.\n[adj.] Of or pertaining to the tenor part or range.","ex":"He has a tenor voice."},"TERSE":{"p":"/tɝːs/","s":"adj.","e":"[adj.] (by extension) Of speech or style: brief, concise, to the point.\n[adj.] (by extension) Of manner or speech: abruptly or brusquely short; curt.\n[adj.] Burnished, polished; fine, smooth; neat, spruce.","ex":""},"THANK":{"p":"[θaŋk]","s":"n.","e":"[n.] An expression of appreciation; a thought.","ex":""},"TIARA":{"p":"/tiˈɑːɹə/","s":"n.","e":"[n.] The papal crown.\n[n.] An ornamental coronet.","ex":""},"TIDAL":{"p":"/ˈtaɪd(ə)l/","s":"adj.","e":"[adj.] Relating to tides","ex":""},"TRILL":{"p":"/tɹɪl/","s":"n./v.","e":"[n.] A rapid alternation between an indicated note and the one above it, in musical notation usually indicated with the letters tr written above the staff.\n[n.] A type of consonantal sound that is produced by vibrations of the tongue against the place of articulation: for example, Spanish rr.\n[n.] A tremulous high-pitched vocal sound produced by cats.\n[v.] To create a trill sound; to utter trills or a trill; to play or sing in tremulous vibrations of sound; to have a trembling sound; to quaver.\n[v.] To impart the quality of a trill to; to utter as, or with, a trill.","ex":"to trill a note, or the letter r"},"TRIM":{"p":"/tɹɪm/","s":"n./v./adj./adv.","e":"[n.] Decoration; especially, decoration placed along edges or borders.\n[n.] A haircut, especially a moderate one to touch up an existing style.\n[n.] Dress; gear; ornaments.\n[v.] To reduce slightly; to cut; especially, to remove excess.\n[v.] To decorate or adorn; especially of a Christmas tree.\n[v.] (of an aircraft) To adjust pitch using trim tabs.","ex":"Paint the house white with blue trim."},"TROPHY":{"p":"/ˈtɹəʊfi/","s":"n.","e":"[n.] Tropæum.\n[n.] An object, usually in the form of a statuette, cup, or shield, awarded for success in a competition or to mark a special achievement.\n[n.] An object taken as a prize by a hunter or conqueror, especially one that is displayed.","ex":"He won the trophy in a running competition."},"TUBE":{"p":"/tjuːb/","s":"n./v.","e":"[n.] Anything that is hollow and cylindrical in shape.\n[n.] An approximately cylindrical container, usually with a crimped end and a screw top, used to contain and dispense semiliquid substances.\n[n.] (often capitalized as Tube) The London Underground railway system, originally referred to the lower level lines that ran in tubular tunnels as opposed to the higher ones which ran in rectangular section tunnels. (Often the tube.)\n[v.] To supply with, or enclose in, a tube.\n[v.] To ride an inner tube.\n[v.] To intubate.","ex":"A tube of toothpaste."},"TUNIC":{"p":"/tjuːnɪk/","s":"n.","e":"[n.] A garment worn over the torso, with or without sleeves, and of various lengths reaching from the hips to the ankles.\n[n.] Any covering, such as seed coat or the organ that covers a membrane.","ex":""},"UPPER":{"p":"/ˈʌpə/","s":"n./adj.","e":"[n.] A stimulant, such as amphetamine, that increases energy and decreases appetite.\n[n.] The upper portion of something\n[n.] Someone with higher social standing\n[adj.] At a higher level, rank or position.\n[adj.] Situated on higher ground, further inland, or more northerly.\n[adj.] (of strata or geological time periods) younger, more recent","ex":""},"VEXES":{"p":"","s":"v.","e":"[v.] To trouble aggressively, to harass.\n[v.] To annoy, irritate.\n[v.] To cause (mental) suffering to; to distress.","ex":""},"VIALS":{"p":"","s":"n./v.","e":"[n.] A glass vessel or bottle, especially a small tube-shaped bottle used to store medicine, perfume or other chemical.\n[v.] To put or keep in, or as in, a vial.","ex":""},"VICTIM":{"p":"/ˈvɪktəm/","s":"n.","e":"[n.] One that is harmed—killed, injured, subjected to oppression, deceived, or otherwise adversely affected—by someone or something, especially another person or event, force, or condition; in particular:\n[n.] A living being which is slain and offered as a sacrifice, usually in a religious rite.","ex":"the youngest victims of the brutal war"},"VIDEO":{"p":"/ˈvɪ.di.əʊ/","s":"n./v.","e":"[n.] Television, television show, movie.\n[n.] A short film clip, with or without audio (as in a music video, or one of the plethora of user-generated short movies on sites such as YouTube).\n[n.] Motion picture stored on VHS or some other format.\n[v.] To record using a video camera, to videotape\n[v.] To record a television program","ex":""},"VIEWING":{"p":"/ˈvjuːɪŋ/","s":"v./n.","e":"[v.] To look at.\n[v.] To regard in a stated way.\n[n.] An instance of viewing something.\n[n.] A wake.","ex":"The video was viewed by millions of people."},"VIGOR":{"p":"/ˈvɪɡɚ/","s":"n.","e":"[n.] Active strength or force of body or mind; capacity for exertion, physically, intellectually, or morally; energy.\n[n.] Strength or force in animal or vegetable nature or action.\n[n.] Strength; efficacy; potency.","ex":""},"VIOLA":{"p":"/viˈoʊ.lə/","s":"n.","e":"[n.] A stringed instrument of the violin family, somewhat larger than a violin, played under the chin, and having a deeper tone.\n[n.] An organ stop having a similar tone.\n[n.] A 10-string steel-string acoustic guitar, used in Brazilian folk music.","ex":""},"VIOLENT":{"p":"/ˈvaɪ(ə)lənt/","s":"n./v./adj.","e":"[n.] An assailant.\n[v.] To urge with violence.\n[adj.] Involving extreme force or motion.\n[adj.] Involving physical conflict.\n[adj.] Likely to use physical force.","ex":"A violent wind ripped the branch from the tree."},"WHORE":{"p":"/hɔː/","s":"n./v.","e":"[n.] Any person (especially a woman) who has sexual intercourse or engages in other sexual activity for payment, especially as a means of livelihood.\n[n.] A person who does, or offers to do, a demeaning or dishonourable activity for money or personal gain; someone who acts in a dishonourable way for personal advantage.\n[n.] A person who is sexually promiscuous; a slut.\n[n.] A person who is unscrupulous, especially one who compromises their principles for gain.\n[n.] A person who will violate behavioral standards to achieve something desired.\n[v.] To prostitute oneself.","ex":""},"WIDTH":{"p":"/ˈwɪdθ/","s":"n.","e":"[n.] The state of being wide.\n[n.] The measurement of the extent of something from side to side.\n[n.] A piece of material measured along its smaller dimension, especially fabric.","ex":""},"WILDS":{"p":"","s":"n./v.","e":"[n.] A wood or forest\n[n.] An open country\n[n.] The undomesticated state of a wild animal\n[n.] (chiefly in the plural) a wilderness\n[v.] To commit random acts of assault, robbery, and rape in an urban setting, especially as a gang.","ex":"After mending the lion's leg, we returned him to the wild."},"WIND":{"p":"/ˈwaɪnd/","s":"n./v.","e":"[n.] Real or perceived movement of atmospheric air usually caused by convection or differences in air pressure.\n[n.] Air artificially put in motion by any force or action.\n[n.] The ability to breathe easily.\n[v.] To blow air through a wind instrument or horn to make a sound.\n[v.] To cause (someone) to become breathless, as by a blow to the abdomen, or by physical exertion, running, etc.\n[v.] To cause a baby to bring up wind by patting its back after being fed.","ex":"As they accelerated onto the motorway, the wind tore the plywood off the car's roof-rack."},"ZERO":{"p":"/ˈzɪəɹəʊ/","s":"n./v./adj./num.","e":"[n.] The numeric symbol that represents the cardinal number zero.\n[n.] The digit 0 in the decimal, binary, and all other base numbering systems.\n[n.] Nothing, or none.\n[v.] To set a measuring instrument to zero; to calibrate instrument scale to valid zero.\n[v.] To change a memory location or range to values of zero; to set a variable in a computer program to zero.\n[v.] To cause or set some value or amount to be zero.","ex":"In unary and k-adic notation in general, zero is the empty string."},"ZIPPY":{"p":"/ˈzɪpi/","s":"adj.","e":"[adj.] Energetic and lively.\n[adj.] Quick, speedy.","ex":""},"ZOOMS":{"p":"","s":"v./n.","e":"[v.] To communicate with someone using the Zoom videoconferencing software.\n[n.] A humming noise from something moving very fast\n[n.] A quick ascent\n[n.] A big increase\n[v.] To move fast with a humming noise\n[v.] To fly an airplane straight up","ex":""}};
